_narrator_task = None  # type: asyncio.Task | None


def _narrator_cadence_for_phase(phase: int) -> float:
    # P1+P2 stream rich real data — tighter cadence catches sub-step changes.
    # P0/3/4/5 transition in chunky deterministic steps — 20s is plenty.
    return 6.0 if phase in (1, 2) else 20.0


# Chat-thread chrome that leaks via DOM scrape into events. Strip from
# narrator inputs ONLY (scrape outputs untouched — chip/step count still
# read those raw). Patterns mirror the FE filter at
# PhaseDropdown.tsx:2034-2041 plus 'brief.md' and the partial form
# without trailing colon. Compiled once at module load.
_NARR_NOISE_PREFIX_RE = re.compile(
    # Optional leading verb-prefix (e.g. "Building: ", "Searching: ") allows
    # the JS-prepended composites at research.py:7102 to be cleaned —
    # "Building: Claude responded: I'll start by..." → "I'll start by..."
    r"^\s*(?:\w+:\s*)?(?:you|chatgpt|gemini|claude|notebooklm|gpt)\s+(?:said|responded)\b\s*[:.]?\s*",
    re.IGNORECASE,
)
_NARR_NOISE_LINE_RE = re.compile(
    r"^\s*(?:"
    r"(?:you|chatgpt|gemini|claude|notebooklm|gpt)\s+(?:said|responded)\b"
    r"|brief\.md"
    r"|skip to content"
    r"|new chat"
    r")\s*[:.]?\s*$",
    re.IGNORECASE,
)


def _scrub_for_narrator(s: str) -> str:
    """Strip chat-thread chrome from a single narrator-input string.
    Returns "" when the input is entirely chrome (caller should drop the
    field). Used only for narrator inputs — does NOT touch scrape outputs
    that drive chip/step counts."""
    if not isinstance(s, str) or not s:
        return ""
    s = s.strip()
    if not s:
        return ""
    if _NARR_NOISE_LINE_RE.match(s):
        return ""
    # Strip leading "X said:" / "X responded:" prefix (handles both
    # bare-prefix lines and verbose "Building: Claude responded: ..."
    # composites — sub() runs once at start; the JS prepends "Building: "
    # so the noise prefix still appears at start in the worst case).
    s = _NARR_NOISE_PREFIX_RE.sub("", s, count=1).strip()
    return s


# Trailing-stopword set for narrator output sanity-check. A narration
# ending with one of these as its last word is mid-sentence (e.g.
# "Reading two sources from") — emit-time fragments worth rejecting so
# the FE doesn't render a half-thought as the live agent line.
_NARR_STOPWORD_TAILS = frozenset({
    "from", "to", "of", "the", "with", "on", "in", "for", "and", "or",
    "about", "by", "into", "over", "through", "as", "at",
})

# Refusal-style substrings — when present, the model is replying as a
# chat assistant ("I don't have enough info, could you provide…") instead
# of narrating. These leaked into the FE pre-2026-05-07 (screenshots
# Narration 1/2). The SKIP escape hatch in the prompt is the primary
# defense; this list catches near-misses where the model paraphrases
# the refusal without using SKIP.
_NARR_REFUSAL_SUBSTRINGS = (
    "i don't have", "i do not have", "i cannot", "i can't",
    "i am unable", "i'm unable", "i need", "i'd need",
    "could you provide", "could you share", "please provide",
    "lacks sufficient", "structured fields", "event payload",
    "to construct a specific", "to write a precise", "to write a tight",
    "without more", "more recent event", "more concrete", "more specific",
    "the events show only", "the event log shows", "the entry shows only",
    "the log indicates", "based on the data",
)

# WH-word leading tokens. A narration that starts with one of these is
# question-shaped ("Could you provide…", "Is there…"), not declarative.
_NARR_WH_LEADING = frozenset({
    "who", "what", "why", "how", "where", "when",
    "could", "can", "would", "will", "do", "does", "did",
    "is", "are", "should", "may", "might",
})

# Hosts that should not be cited as "sources" — they ARE the agent UI
# itself or its CDN. Filtered before passing hostnames into the narrator
# prompt (otherwise narration says "scraping chatgpt.com" which is dumb).
_HOST_DENYLIST = frozenset({
    "chatgpt.com", "openai.com", "chat.openai.com", "oaiusercontent.com",
    "claude.ai", "anthropic.com",
    "gemini.google.com", "bard.google.com",
    "notebooklm.google.com",
})


def _is_acceptable_narration(s: str) -> bool:
    """Reject narration outputs that don't read as a single declarative
    sentence. Signals:
    (1) under 5 words AND under 22 chars (catches 'Twenty', 'Engaged in')
    (2) total length > 160 chars (prompt budget is 110/140 — overflow
        signals the model is composing prose, not one sentence)
    (3) `?` in the last 30 chars — declarative narrations don't end in
        a question
    (4) leading WH-word (Could/Can/Would/Is/Are/...) — question shape
    (5) refusal substrings ('I don't have', 'could you provide', ...) —
        the model is replying as a chat assistant, not narrating
    (6) trailing stopword betraying a mid-sentence cut ('Reading two
        sources from')
    (7) leading-tokenization artifact ('"d unambiguous...')

    On reject the caller should fall through to Tier-3 realistic
    fallback (or Tier-4 deterministic template) rather than just
    skipping the tick — a sustained refusal mode would otherwise leave
    the FE narration frozen on stale text for minutes."""
    if not s:
        return False
    words = s.split()
    if len(words) < 5 and len(s) < 22:
        return False
    if len(s) > 160:
        return False
    if "?" in s[-30:]:
        return False
    first = words[0].lower().rstrip(",.:;!?") if words else ""
    if first in _NARR_WH_LEADING:
        return False
    s_lower = s.lower()
    for needle in _NARR_REFUSAL_SUBSTRINGS:
        if needle in s_lower:
            return False
    last = words[-1].rstrip(".!,?:;").lower() if words else ""
    if last in _NARR_STOPWORD_TAILS:
        return False
    # Leading-tokenization artifact — Haiku occasionally returns a
    # response that begins with a fragment like "d unambiguous..." or
    # "'s research..." when the system prompt contains quoted strings.
    head = s.lstrip()[:2]
    if head in ('"d', "'d", '"s', "'s", '"t', "'t", '"r', "'r"):
        return False
    return True


def _is_skip_token(text: str) -> bool:
    """Detect the SKIP escape-hatch token Haiku/Flash emits when data is
    too thin to narrate honestly. Normalizes wrappers the model may add
    (`SKIP.`, `"SKIP"`, `Output: SKIP`)."""
    if not text:
        return False
    t = text.strip().strip('"').strip("'").strip("`").strip().lower()
    if t in {"skip", "skip.", "skip!", "skip,"}:
        return True
    if t.startswith(("output: skip", "output:skip", "skip\n", "skip ")):
        return True
    return False


def _phase_short_label(phase: int) -> str:
    """Compact human label per phase, for the deterministic phase-narration
    template that ships when Tier-2 (LLM) refuses or fails the gate. Static
    text — the FE shows elapsed time below the dropdown separately, so no
    counter suffix is needed here. Dedupe at emit site means this lands
    once per phase if Tier-2 stays in refusal mode."""
    return {
        0: "the warmup phase, verifying every agent is logged in",
        1: "brief generation, drafting a structured research brief",
        2: "parallel deep research across ChatGPT, Gemini, and Claude",
        3: "NotebookLM upload and audio overview generation",
    }.get(phase, "running through the active phase")


_NARRATION_STOPWORDS = frozenset({
    "is", "in", "of", "the", "a", "an", "and", "or", "with", "without",
    "after", "before", "over", "under", "across", "into", "onto", "from",
    "to", "as", "at", "for", "by", "on", "off", "no", "not", "yet", "so",
    "now", "still", "while", "during", "having", "been", "be", "being",
    "this", "that", "these", "those", "it", "its", "then", "than",
})


def _too_similar_to_recent(new_text: str, prev_text: str, threshold: float = 0.65) -> bool:
    """Reject a fresh narration if it's a paraphrase of the previous one.
    The exact-string dedupe at the emit site catches "ChatGPT is X" twice
    in a row but misses "ChatGPT accumulated 198 chars over 5 minutes" vs
    "ChatGPT has 198 tokens drafted after 5 minutes" — same idea, different
    wording. Word-set Jaccard over content words (>=4 chars, no stopwords)
    catches the user-reported "all five narrations say the same thing"
    pattern during ChatGPT's extended-thinking window.
    """
    if not new_text or not prev_text:
        return False
    import re as _re
    def _content(s: str) -> set[str]:
        return {
            w for w in (m.group(0).lower() for m in _re.finditer(r"[a-zA-Z]{4,}", s))
            if w not in _NARRATION_STOPWORDS
        }
    new_words = _content(new_text)
    prev_words = _content(prev_text)
    if len(new_words) < 4 or len(prev_words) < 4:
        return False
    union = new_words | prev_words
    if not union:
        return False
    return len(new_words & prev_words) / len(union) >= threshold


def _extract_top_hosts(events: list, limit: int = 2) -> list:
    """Pull deduped non-UI hostnames from agent_progress.source_urls and
    link_extracted events in the recent ring-buffer window. Used to feed
    the narrator prompt's `hosts=` field so narration can cite the actual
    sources the agents are reading instead of generic 'reading sources'.
    """
    try:
        from urllib.parse import urlparse as _urlparse
    except Exception:
        return []
    seen = []
    seen_set = set()
    for e in events:
        d = e.get("data", {}) or {}
        urls = []
        v = d.get("source_urls") or d.get("sourceUrls")
        if isinstance(v, list):
            urls.extend(v)
        if e.get("type") == "link_extracted":
            single = d.get("url")
            if single:
                urls.append(single)
        for u in urls:
            if not isinstance(u, str):
                continue
            try:
                host = (_urlparse(u).hostname or "").lower()
                if host.startswith("www."):
                    host = host[4:]
            except Exception:
                continue
            if not host or host in _HOST_DENYLIST or host in seen_set:
                continue
            seen.append(host)
            seen_set.add(host)
            if len(seen) >= limit:
                return seen
    return seen


# Tier-4 deterministic template variants — the absolute last-ditch
# fallback when both Tier-2 (Haiku/Flash on real events) AND Tier-3
# (LLM with hardcoded timeline) refuse or fail. Three phrasings per
# (akey, phase) so consecutive emits don't collide on the dedupe
# equality guard at line ~7131/~7207 (silent-emit trap).
AGENT_TIER4_VARIANTS = {
    ("chatgpt", 1): [
        "ChatGPT is reasoning through the brief in extended thinking.",
        "ChatGPT is shaping the brief outline with structured sections.",
        "ChatGPT is consolidating the brief output and validating sources.",
    ],
    ("chatgpt", 2): [
        "ChatGPT is sweeping the web for fresh sources on the topic.",
        "ChatGPT is reading retrieved articles and pulling citations.",
        "ChatGPT is synthesizing findings into the report sections.",
    ],
    ("claude", 2): [
        "Claude is loading the brief and planning the research scope.",
        "Claude is searching and reading sources into the artifact.",
        "Claude is structuring the artifact with citations and sections.",
    ],
    ("gemini", 2): [
        "Gemini is launching Deep Research from the Tools menu.",
        "Gemini is browsing fresh sources into the activity panel.",
        "Gemini is weaving findings into a structured report.",
    ],
}

_tier4_counter = {}  # type: dict[str, int]


def _tier4_template(akey: str, ph: int) -> str:
    """Round-robin pick from AGENT_TIER4_VARIANTS so consecutive Tier-4
    emits produce different strings (defeats the equality dedupe at the
    emit sites). Counter keyed by (akey, ph) so a future entry like
    ("chatgpt", 0) doesn't cross-contaminate ("chatgpt", 2)'s rotation."""
    variants = AGENT_TIER4_VARIANTS.get((akey, ph))
    if not variants:
        return f"{akey.upper()} is processing the request."
    key = (akey, ph)
    counter = _tier4_counter.get(key, 0)
    _tier4_counter[key] = counter + 1
    return variants[counter % len(variants)]


def _compact_event_for_narration(e: dict) -> str:
    """Flatten an event into one line for the narrator prompt. Skips
    high-cardinality fields and caps each value at 120 chars so a 20-event
    window stays well under the narrator input budget. Also strips
    chat-thread chrome ("You said:", "Claude responded:", "brief.md") so
    the narrator doesn't paraphrase noise back as narration."""
    t = e.get("type", "")
    ph = e.get("phase", "")
    ag = e.get("agent", "")
    d = e.get("data", {}) or {}
    parts = [f"{t} ph={ph}"]
    if ag:
        parts.append(f"agent={ag}")
    for k in ("status", "progress", "error", "message", "reason",
              "sources", "sections", "partialTextLen", "partialTextPreview",
              "elapsedSec", "searches", "sectionsDone", "sectionsTotal",
              "currentFocus", "websitesCount", "panelOpen", "artifactCount"):
        v = d.get(k)
        if v in (None, "", [], {}):
            continue
        if isinstance(v, (list, dict)):
            # Scrub each list element of chat-thread chrome before serializing.
            if k in ("sections", "steps") and isinstance(v, list):
                v = [c for c in (_scrub_for_narrator(x) for x in v
                                  if isinstance(x, str)) if c]
                if not v:
                    continue
            s = json.dumps(v)[:120]
        elif k == "partialTextPreview":
            # Last 80 chars of the streaming preview — the most-recent
            # token cluster is what the narrator should reference, not
            # the stale opening of a long synthesis.
            s = _scrub_for_narrator(str(v)[-80:])
            if not s:
                continue
        else:
            s = str(v)[:120]
            if k in ("progress", "currentFocus", "message", "reason"):
                s = _scrub_for_narrator(s)
                if not s:
                    continue
        parts.append(f"{k}={s}")
    # Surface link_extracted events with a hostname + truncated label so
    # the narrator can name the actual source ("Skimming sec.gov on
    # Tesla 10-K") instead of just "Reading sources". Hostname keeps
    # the input compact; the full URL would blow the 120-char cap.
    if t == "link_extracted":
        url = d.get("url") or ""
        label = d.get("label") or d.get("title") or ""
        if url:
            try:
                from urllib.parse import urlparse as _urlparse
                host = (_urlparse(url).hostname or "").lower()
                if host.startswith("www."):
                    host = host[4:]
            except Exception:
                host = ""
            if host and host not in _HOST_DENYLIST:
                parts.append(f"host={host}")
        if label:
            parts.append(f"label={str(label)[:40]}")
    # Surface agent_progress.source_urls as `hosts=foo.com,bar.com` (top
    # 2, deduped, agent UI hosts filtered). This is the primary signal
    # for live browsing during P2 — link_extracted does NOT fire from
    # agent browsing (it's only emitted from share-link extraction in
    # P5), so without this the prompt's "weave hostnames" instruction
    # would be no-op for the in-progress P2 narration.
    if t == "agent_progress":
        urls = d.get("source_urls") or d.get("sourceUrls")
        if isinstance(urls, list) and urls:
            try:
                from urllib.parse import urlparse as _urlparse
            except Exception:
                _urlparse = None
            if _urlparse is not None:
                _hosts = []
                _hosts_seen = set()
                for u in urls:
                    if not isinstance(u, str):
                        continue
                    try:
                        h = (_urlparse(u).hostname or "").lower()
                        if h.startswith("www."):
                            h = h[4:]
                    except Exception:
                        continue
                    if not h or h in _HOST_DENYLIST or h in _hosts_seen:
                        continue
                    _hosts.append(h)
                    _hosts_seen.add(h)
                    if len(_hosts) >= 2:
                        break
                if _hosts:
                    parts.append(f"hosts={','.join(_hosts)}")
    return " | ".join(parts)


async def _narrator_loop(phase: int):
    """Poll the ring buffer every `cadence` seconds. Synthesize one human
    sentence (phase-wide) plus, for Phase 2, one sentence per active agent.
    Emits `phase_narration` always and `agent_narration` for Phase 2.
    Back off on 429 / network blip."""
    # Resolve at loop entry, not module-load — so the user's Account-page
    # apiKeys.gemini wins. Module-load resolution would always lose: the
    # backend may pair / re-fetch keys before any pipeline starts, and the
    # narrator only spins up inside run_pipeline anyway.
    gemini_key = resolve_gemini_api_key()
    if not gemini_key:
        return
    if phase is None or phase < 0:
        return
    cadence = _narrator_cadence_for_phase(phase)
    last_narration = ""
    last_agent_lines: dict[str, str] = {}
    last_known_status_for_agent: dict[str, str] = {}
    phase_started_ts = time.time()
    backoff_ticks_left = 0
    try:
        import requests as _requests
    except Exception:
        return
    # 2026-05-28: per-agent narrator brain swapped to Gemini 3.5 Flash
    # primary with Haiku 4.5 as cross-vendor fallback. Drivers:
    #  - Cost: 3.5 Flash is ~comparable-or-cheaper at narrator volume
    #    AND the rest of the BE text-task stack (summary, title
    #    fallback, URL extractor) already runs on it — consolidating
    #    the narrator removes the lone Anthropic-text-call outlier.
    #  - Latency: Gemini single-region inference is empirically faster
    #    than the cross-vendor Anthropic hop on this hot path.
    #  - Quality: the prior parrot-input issue that pushed us off
    #    Gemini Pro 2.5 in 04-30 doesn't manifest on 3.5 Flash at
    #    temp 0.2 with the "do not echo input spans" system rule.
    #  - Vendor hedge: Haiku 4.5 stays in place as the fallback so a
    #    Google regional blip doesn't blank narration entirely.
    # Prior order (Haiku primary, Gemini fallback) was the inverse
    # of every other text-task on the BE; this swap aligns the path.
    # Backwards-compat: honor legacy DG_NARRATOR_USE_HAIKU env (renamed to
    # DG_NARRATOR_USE_GEMINI on 2026-05-28 when the primary swapped). The
    # semantic flipped — old "1" meant "use Haiku primary", new "1" means
    # "use Gemini primary" — so we invert when reading the legacy var.
    # Operators with the old name pinned in .dg-supervisor.env get one
    # release of grace before the alias is removed.
    _legacy_use_haiku = os.environ.get("DG_NARRATOR_USE_HAIKU")
    if _legacy_use_haiku is not None:
        _legacy_truthy = _legacy_use_haiku.lower() not in ("0", "false", "no")
        _USE_GEMINI = not _legacy_truthy
    else:
        _USE_GEMINI = os.environ.get("DG_NARRATOR_USE_GEMINI", "1").lower() not in ("0", "false", "no")
    _gemini_model = GEMINI_TEXT
    _haiku_model = NARRATOR_HAIKU
    url_primary = (
        "https://generativelanguage.googleapis.com/v1beta/models/"
        f"{_gemini_model}:generateContent?key={gemini_key}"
    )
    _err_logged = False  # one-shot — avoid log spam if narrator stays broken
    _gemini_err_logged = False  # one-shot — log Gemini→Haiku downgrade once

    def _call_narrator(system: str, user_msg: str, max_tokens: int = 200):
        """Call the narrator brain. Gemini 3.5 Flash first; Haiku 4.5
        fallback on ANY Gemini failure (4xx non-429, 5xx, timeout, parse
        error, empty output). Sync — wrapped in asyncio.to_thread by
        callers. Returns (text, status_code). 429 is surfaced (not
        fallback) so the outer loop can back off — Haiku fallback is
        reserved for non-rate-limit blips, not for absorbing a quota
        storm on the primary.

        Note: non-429 4xx errors fall through to Haiku (not surfaced)
        so a Gemini-project-scoped quota window doesn't blank narration
        for hours. The downgrade is logged once via _gemini_err_logged
        so operator sees when narration is running on Haiku."""
        nonlocal _gemini_err_logged
        if _USE_GEMINI:
            # Gemini Flash primary. Thinking disabled — narration needs a
            # one-line summary, not reasoning, and thinking eats the
            # token budget leaving 2-3-word stubs.
            payload = {
                "contents": [{"role": "user", "parts": [{"text": user_msg}]}],
                "systemInstruction": {"parts": [{"text": system}]},
                "generationConfig": {
                    "temperature": 0.2,
                    "maxOutputTokens": max_tokens,
                    "thinkingConfig": {"thinkingBudget": 0},
                },
            }
            try:
                resp = _requests.post(url_primary, json=payload, timeout=5)
                sc = resp.status_code
                if sc == 429:
                    return "", 429  # let outer loop back off
                try:
                    j = resp.json()
                    text = (j.get("candidates", [{}])[0]
                             .get("content", {})
                             .get("parts", [{}])[0]
                             .get("text", ""))
                    text = (text or "").strip()
                    if text and sc == 200:
                        return text, 200
                    # empty / non-200 — fall through to Haiku
                    if not _gemini_err_logged:
                        log(f"[narrator] Gemini Flash sc={sc} (empty or non-200) "
                            f"— falling back to Haiku 4.5", "WARN")
                        _gemini_err_logged = True
                except Exception:
                    if not _gemini_err_logged:
                        log(f"[narrator] Gemini Flash parse failed sc={sc} "
                            f"— falling back to Haiku 4.5", "WARN")
                        _gemini_err_logged = True
            except Exception as _gemini_e:
                if not _gemini_err_logged:
                    log(f"[narrator] Gemini Flash error ({type(_gemini_e).__name__}: "
                        f"{str(_gemini_e)[:120]}) — falling back to Haiku 4.5", "WARN")
                    _gemini_err_logged = True
            # fall through to Haiku fallback

        # Haiku 4.5 fallback — cross-vendor hedge for Google regional
        # outages. Anthropic SDK is already a BE dep (vision.py uses
        # Sonnet for ACT) so no extra footprint.
        try:
            import anthropic as _anth
            _key = resolve_api_key()
            if not _key:
                return None, 0
            _cli = _anth.Anthropic(api_key=_key, timeout=5.0)
            try:
                resp = _cli.messages.create(
                    model=_haiku_model,
                    max_tokens=max_tokens,
                    system=system,
                    messages=[{"role": "user", "content": user_msg}],
                )
                txt = "".join(
                    getattr(b, "text", "") for b in resp.content
                    if getattr(b, "type", "") == "text"
                )
                return (txt or "").strip(), 200
            except _anth.RateLimitError:
                return "", 429
            except Exception:
                return None, 0
        except Exception:
            return None, 0

    async def _realistic_fallback(akey: str, ph: int, elapsed_sec: float,
                                   last_status: str = "", *,
                                   recent_hosts=None) -> str:
        """Tier 3 fallback narration — when real data (DOM + vision) is sparse
        OR Tier-2 (LLM on real events) refused / failed the quality gate,
        ask Haiku/Flash to produce ONE realistic sentence based on phase
        + elapsed time + the typical timeline. The output cites the actual
        timeline stage (planning vs searching vs synthesizing) so it feels
        real rather than generic.

        Tier-3 OWN output is also gated through `_is_acceptable_narration`
        and `_is_skip_token` — if the model refuses again, return empty
        and the caller falls through to Tier-4 deterministic template."""
        timeline = AGENT_PHASE_FLOWS.get((akey, ph))
        if not timeline:
            return ""
        elapsed_min = elapsed_sec / 60.0
        timeline_text = "\n".join(f"- {t}" for t in timeline)
        hosts_block = ""
        hosts_hint = ""
        if recent_hosts:
            hosts_block = (
                f"Recently visited hosts: {', '.join(recent_hosts[:2])}\n\n"
            )
            hosts_hint = (
                f" If natural, mention one host — 'skimming {recent_hosts[0]}' "
                "beats 'reading sources'."
            )
        fb_system = (
            f"You narrate what the {akey.upper()} agent is likely doing right now. "
            f"Elapsed: {elapsed_min:.1f} minutes. "
            f"Last known status: {last_status or 'unknown'}.\n\n"
            f"TYPICAL TIMELINE for {akey.upper()}:\n"
            f"{timeline_text}\n\n"
            f"{hosts_block}"
            "Output ONE realistic sentence in present tense (<= 110 chars) "
            f"describing what's happening at minute {elapsed_min:.1f} of the "
            "timeline above. Reference the specific stage by what the agent "
            f"is doing (e.g. 'ChatGPT is mapping cluster overlaps across the "
            f"first 80 sources').{hosts_hint}\n\n"
            "FORBIDDEN — your output is broadcast verbatim to the user. NEVER:\n"
            "  - Questions or '?'.\n"
            "  - Refusals ('I don't have', 'I cannot', 'lacks sufficient', "
            "'Without more', 'I need').\n"
            "  - First-person ('I '). You are not in the conversation.\n"
            "  - Meta-references ('the events', 'the log', 'event payload',\n"
            "    'structured fields').\n"
            "  - 'Super Research Phase' / 'in Phase N' / 'Phase 2'.\n"
            "  - Multi-sentence answers (one period only).\n"
            "  - 'currently' as a leading word, 'Status:' prefix.\n"
            "  - Generic 'still working' / 'is still processing'.\n\n"
            "Stage references like 'in the synthesis stage' or 'in extended "
            "thinking' are FINE — only the literal 'Phase N' pipeline-meta is "
            "banned. Start with the agent name. No markdown, no em-dashes. "
            "If you cannot produce a clean sentence, output the literal token "
            "SKIP and nothing else; a deterministic template will replace it."
        )
        fb_text, fb_status = await asyncio.to_thread(
            _call_narrator, fb_system, "", 200
        )
        if fb_status >= 400 or not fb_text:
            return ""
        fb_text = fb_text.strip().strip('"').strip("`").strip()
        if _is_skip_token(fb_text):
            return ""
        if not _is_acceptable_narration(fb_text):
            return ""
        return fb_text[:140]

    try:
        while True:
            await asyncio.sleep(cadence if backoff_ticks_left == 0 else 15.0)
            if backoff_ticks_left > 0:
                backoff_ticks_left -= 1
            try:
                if _controls.is_stop() or _controls.is_pause():
                    continue
            except Exception:
                pass
            # Phase-scope filter — the ring buffer is process-global, so a
            # Phase 2 `agent_progress` from 28s ago can leak into Phase 3's
            # narrator and produce "Still working on Phase 2: generating
            # the agent reports..." emitted under phase=3 (observed in the
            # FE Phase 3 dropdown 2026-04-28). Filter to the current phase
            # only, plus any events without a phase tag (system events).
            recent_raw = _recent_events_window(30.0)
            recent = [e for e in recent_raw
                      if e.get("phase") in (phase, None)]
            phase_ctx = PHASE_FLOW_CONTEXT.get(phase, "")
            data_rich = phase in (1, 2)
            style_note = (
                "CITE the real scrape content when you can — reference specific "
                "source counts, section titles, or partialTextLen numbers you see "
                "in the events. Do not invent specifics."
                if data_rich else
                "Reason from the hardcoded phase flow + elapsed time + last status "
                "transition. Do not invent specific numbers."
            )
            system = (
                "You narrate ONE human sentence summarizing what the Super Research "
                "pipeline is doing RIGHT NOW for a user watching the phase dropdown. "
                f"Phase {phase}: {phase_ctx} {style_note}\n\n"
                "HARD CONSTRAINTS — your output is broadcast verbatim to a human "
                "user with zero post-processing. Every word ships.\n\n"
                "OUTPUT SHAPE: Exactly ONE sentence. <= 110 chars. Subject = the "
                "pipeline OR a specific agent (ChatGPT/Gemini/Claude). Verb = "
                "present-progressive (is reading, is mapping, is drafting). "
                "Object = a concrete thing from the events. Period. End.\n\n"
                "NEVER (these ship to the user as-is):\n"
                "  - Questions. No 'Could you', 'Can you', 'Would you', '?'.\n"
                "  - First-person ('I '). You are not in the conversation.\n"
                "  - Refusals or capability disclaimers ('I don't have', "
                "'lacks sufficient', 'I cannot narrate', 'Without more', "
                "'I need').\n"
                "  - Meta about the input ('the events show', 'the log "
                "indicates', 'structured fields', 'event payload', 'recent "
                "entries', 'based on the data').\n"
                "  - Multi-sentence answers (no second period followed by space).\n"
                "  - Lists, bullets, em-dashes for enumeration, prefixes like "
                "'Currently' or 'Status:'.\n"
                "  - Generic stalls: 'still working', 'still processing', "
                "'in progress'.\n\n"
                "WHEN DATA IS THIN: Output the literal token  SKIP  on its own "
                "and nothing else. A deterministic fallback will produce a "
                "sentence from the typical phase flow. Your refusal would be "
                "worse than silence.\n\n"
                "WHEN DATA IS RICH: Cite specifics — counts, section names, "
                "hostnames from `host=` or `hosts=` lines, focus areas from "
                "`currentFocus`. Weave hostnames naturally: 'pulling Tesla "
                "10-K filings from sec.gov' beats 'reading sources'. Cap at "
                "1-2 hostnames per sentence."
            )
            event_lines = "\n".join(
                f"- {_compact_event_for_narration(e)}" for e in recent[-20:]
            )
            user_msg = f"Recent events (newest last):\n{event_lines or '[none]'}"

            text, status_code = await asyncio.to_thread(_call_narrator, system, user_msg)
            if status_code == 429:
                backoff_ticks_left = 3
                continue
            if not text or status_code >= 400:
                # One-shot diagnostic — without this, a deprecated model or bad
                # API key produces a completely silent failure (the gemini-2.0
                # → 2.5 deprecation went unnoticed because every tick just
                # `continue`d). Log the first failure per phase so the operator
                # can act; subsequent failures stay quiet to avoid log spam.
                if not _err_logged:
                    log(f"[narrator] narrator call failed status={status_code} "
                        f"(use_gemini={_USE_GEMINI}, primary={_gemini_model}, "
                        f"fallback={_haiku_model}) "
                        f"— phase narration silent until resolved. Check "
                        f"GEMINI_API_KEY or ANTHROPIC_API_KEY.", "WARN")
                    _err_logged = True
                continue
            # Reset both err flags once we recover so a later regression re-logs.
            # _gemini_err_logged also resets so a transient Gemini blip doesn't
            # latch-suppress the downgrade log for the rest of the phase.
            _err_logged = False
            _gemini_err_logged = False
            text = text.strip().strip('"').strip("`").strip()
            # SKIP escape hatch — model used the designated fallback signal
            # because data was too thin to narrate honestly. Replace with
            # a deterministic phase template so the FE never goes silent.
            if _is_skip_token(text):
                text = f"Super Research is in {_phase_short_label(phase)}."
            # Quality gate — drop fragments / single-words / refusal text /
            # stopword-tail mid-sentence cuts before they hit the wire. On
            # reject, fall through to the same deterministic template (a
            # sustained Tier-2 refusal mode would otherwise leave the FE
            # narration frozen on stale text for minutes). Dedupe at emit
            # site means this template lands once per phase if Tier-2 stays
            # in refusal — subsequent ticks return clean output and resume.
            if text and not _is_acceptable_narration(text):
                text = f"Super Research is in {_phase_short_label(phase)}."
            if text and text != last_narration:
                last_narration = text
                try:
                    emit_event("phase_narration", phase=phase, text=text)
                except Exception:
                    pass

            # ── Per-agent narration (P1 + P2) ──
            # Filter the recent window per agent and emit one `agent_narration`
            # per active agent so the per-agent card carries live context.
            # Phase 1 has only ChatGPT (Pro + Extended Thinking); Phase 2 has
            # all three. When an agent has no events in the window AND we're
            # past the 60s warmup, fall back to Tier 3 realistic narration
            # (Gemini + typical timeline) so the card never goes blank during
            # long Extended-Thinking or planning windows where DOM and vision
            # both produce nothing for minutes at a stretch.
            if phase == 1:
                agent_keys = ("chatgpt",)
            elif phase == 2:
                agent_keys = ("chatgpt", "gemini", "claude")
            else:
                agent_keys = ()
            if agent_keys:
                elapsed_in_phase = time.time() - phase_started_ts
                for akey in agent_keys:
                    a_events = [e for e in recent
                                if (e.get("agent") or "").lower() == akey
                                or ((e.get("data", {}) or {}).get("agent") or "").lower() == akey]
                    if not a_events:
                        # Tier 3 fallback — only after 60s warmup so we don't
                        # produce bogus narration during the brief window where
                        # DOM scrape is settling and vision hasn't run yet.
                        # (Rejection-triggered fallback below skips this gate.)
                        if elapsed_in_phase < 60:
                            continue
                        last_status = last_known_status_for_agent.get(akey, "")
                        # Per-agent has no events; pull hosts from phase-wide
                        # window so the fallback can still cite a real source
                        # if any agent visited one in the recent ring buffer.
                        recent_hosts_phase = _extract_top_hosts(recent)
                        fb_text = await _realistic_fallback(
                            akey, phase, elapsed_in_phase, last_status,
                            recent_hosts=recent_hosts_phase,
                        )
                        # Tier-4 deterministic template if Tier-3 LLM call
                        # also refused/failed — round-robin rotation per
                        # agent so consecutive Tier-4 emits don't collide
                        # with the dedupe equality guard below.
                        if not fb_text:
                            fb_text = _tier4_template(akey, phase)
                        if fb_text and fb_text != last_agent_lines.get(akey):
                            last_agent_lines[akey] = fb_text
                            try:
                                emit_event("agent_narration", phase=phase,
                                           agent=akey, text=fb_text,
                                           fallback=True)
                            except Exception:
                                pass
                        continue
                    # Track latest status so a future fallback (after events
                    # stop arriving) can reference it for richer context.
                    for _e in reversed(a_events):
                        _d = _e.get("data", {}) or {}
                        if _d.get("status"):
                            last_known_status_for_agent[akey] = str(_d["status"])
                            break
                    a_lines = "\n".join(
                        f"- {_compact_event_for_narration(e)}" for e in a_events[-12:]
                    )
                    a_system = (
                        f"You narrate ONE human sentence about what the {akey.upper()} "
                        f"agent is doing RIGHT NOW.\n\n"
                        "HARD CONSTRAINTS — your output is broadcast verbatim to a "
                        "human user with zero post-processing. Every word ships.\n\n"
                        f"OUTPUT SHAPE: Exactly ONE sentence. <= 140 chars. Subject "
                        f"= {akey.upper()}. Verb = present-progressive (is reading, "
                        "is mapping, is drafting). Object = a concrete thing from "
                        "the events. Period. End.\n\n"
                        "NEVER (these ship to the user as-is):\n"
                        "  - Questions. No 'Could you', 'Can you', 'Would you', '?'.\n"
                        "  - First-person ('I '). You are not in the conversation.\n"
                        "  - Refusals or capability disclaimers ('I don't have', "
                        "'lacks sufficient', 'I cannot narrate', 'Without more', "
                        "'I need').\n"
                        "  - Meta about the input ('the events show', 'the log "
                        "indicates', 'structured fields', 'event payload', 'recent "
                        "entries', 'based on the data').\n"
                        "  - Multi-sentence answers (no second period followed by space).\n"
                        "  - Lists, bullets, em-dashes, prefixes ('Currently', 'Status:').\n"
                        "  - Generic stalls: 'still working', 'still processing'.\n"
                        "  - Pipeline meta: 'Super Research Phase N', 'in Phase 2', "
                        "'Phase 1 of the pipeline'. Stage names like 'in the "
                        "synthesis stage' / 'in extended thinking' / 'is now in "
                        "<stage>' are FINE — only literal 'Phase N' is banned.\n"
                        "  - Echoing input verbatim. If input contains 'research "
                        "voice mode false positives', do NOT write 'researching "
                        "voice mode false positives'. Paraphrase or output SKIP.\n"
                        "  - UI chrome: 'You said:', '<name> responded:', 'brief.md'.\n\n"
                        "WHEN DATA IS THIN: Output the literal token  SKIP  on its "
                        "own and nothing else. A deterministic fallback will "
                        "produce a sentence from the typical timeline. Your "
                        "refusal would be worse than silence.\n\n"
                        "WHEN DATA IS RICH: Weave structured fields (searches, "
                        "sectionsDone/Total, currentFocus, partialTextLen) as "
                        "paraphrased facts, not quoted strings. When events "
                        "contain `host=<domain>` or `hosts=foo.com,bar.com`, "
                        "weave 1-2 hostnames naturally — 'ChatGPT is skimming "
                        "sec.gov filings on Tesla 10-K' beats 'ChatGPT is "
                        "reading three sources'.\n\n"
                        "GOOD examples (paraphrase activity, don't quote input):\n"
                        "  - 'Gemini is mapping discrepancy patterns across the "
                        "latest test runs while pulling fresh sources.'\n"
                        "  - 'Claude has woven 380 sources into a 7-section "
                        "outline so far.'\n"
                        "  - 'ChatGPT is narrowing in on the false-positive root "
                        "cause via the docs cluster on sec.gov.'\n\n"
                        f"SCOPE: ONLY {akey.upper()}'s progress. Don't compare agents."
                    )
                    # Pass the previous narration so the model writes
                    # something MEANINGFULLY DIFFERENT instead of
                    # paraphrasing the same idea each tick — fixes the
                    # user-reported "all five narrations say 198 chars
                    # of partial output" pattern during ChatGPT's
                    # extended-thinking window where state changes
                    # little between ticks. The model emits SKIP if
                    # there's nothing new to say; the emit-site
                    # similarity gate below is a belt-and-suspenders
                    # backstop if it ignores the instruction.
                    prev_narration = last_agent_lines.get(akey, "")
                    prev_narration_clause = (
                        f"\n\nPREVIOUS NARRATION (do NOT repeat or paraphrase this — "
                        f"if the agent's state hasn't materially changed, output SKIP):\n"
                        f"\"{prev_narration}\""
                    ) if prev_narration else ""
                    a_user = (
                        f"Recent events for {akey.upper()} (newest last):\n"
                        f"{a_lines or '[none]'}"
                        f"{prev_narration_clause}"
                    )
                    a_text, a_status = await asyncio.to_thread(_call_narrator, a_system, a_user, 200)
                    if a_status == 429:
                        backoff_ticks_left = 3
                        break
                    a_text = (a_text or "").strip().strip('"').strip("`").strip()
                    # SKIP escape hatch — model used the designated fallback
                    # signal. Treat as rejected so the fallback chain runs.
                    if _is_skip_token(a_text):
                        a_text = ""
                    # Quality gate — drop refusal text / fragments / overlength.
                    elif a_text and not _is_acceptable_narration(a_text):
                        a_text = ""
                    # Empty result (Tier-2 refused, failed gate, or upstream
                    # error) → fall through to Tier-3 realistic fallback. Bypass
                    # the 60s warmup gate that applies to the no-events branch
                    # — an active refusal is worse than t<60. Tier-3 takes the
                    # recent_hosts hint so the fallback can cite real sources
                    # when the agent has visited any.
                    if not a_text:
                        last_status = last_known_status_for_agent.get(akey, "")
                        recent_hosts_for_agent = _extract_top_hosts(a_events)
                        a_text = await _realistic_fallback(
                            akey, phase, elapsed_in_phase, last_status,
                            recent_hosts=recent_hosts_for_agent,
                        )
                        # Tier-4 deterministic template — Tier-3 calls the same
                        # Haiku/Flash chain that just refused; if THAT also
                        # failed/refused, use a pure-string template that
                        # cannot be rejected. Round-robin rotation defeats
                        # the equality dedupe at the emit site below.
                        if not a_text:
                            a_text = _tier4_template(akey, phase)
                    # Two-stage dedupe at emit: exact-equality (prior
                    # behavior) + Jaccard similarity to the last emitted
                    # narration (catches paraphrases that share the same
                    # data points — "198 chars partial output" vs "198
                    # tokens drafted"). Tier-4 templates are short and
                    # phrased differently across rotations, so they pass
                    # the similarity gate naturally.
                    if a_text and a_text != last_agent_lines.get(akey) and not _too_similar_to_recent(a_text, last_agent_lines.get(akey, "")):
                        last_agent_lines[akey] = a_text
                        try:
                            emit_event("agent_narration", phase=phase,
                                       agent=akey, text=a_text)
                        except Exception:
                            pass
    except asyncio.CancelledError:
        return
    except Exception as _e:
        try:
            log(f"[narrator] loop crashed ({_e}) — narration stopped for phase {phase}", "WARN")
        except Exception:
            pass
        return


def start_narrator(phase: int):
    """Cancel any existing narrator task and start a fresh one scoped to
    this phase. Wired automatically from emit_event on `phase_start`.
    Safe to call when there's no running event loop (silently no-ops)."""
    global _narrator_task
    try:
        if _narrator_task and not _narrator_task.done():
            _narrator_task.cancel()
    except Exception:
        pass
    try:
        import narrate as _vn
        _vn.reset_phase_budget()
    except Exception:
        pass
    try:
        _narrator_task = asyncio.create_task(_narrator_loop(phase))
    except RuntimeError:
        # No running event loop (pre-startup / CLI paths). Skip.
        _narrator_task = None


def stop_narrator():
    """Cancel the narrator task. Wired automatically from emit_event on
    `phase_complete` / `phase_skipped`. Also called explicitly by
    orchestrator teardown / exception paths."""
    global _narrator_task
    try:
        if _narrator_task and not _narrator_task.done():
            _narrator_task.cancel()
    except Exception:
        pass
    _narrator_task = None


# ── Login URL negatives (shared between Phase 0 preflight + setup) ─────
# Known login-wall host fragments. When the browser lands on one of
# these after a navigation, the profile is not authenticated on that
# platform. Cheap short-circuit before spending CUA.

_LOGIN_HOST_NEGATIVES = (
    "auth.openai.com", "accounts.google.com/signin",
    "login.live.com", "claude.ai/login", "claude.ai/signup",
)

# NOTE (2026-04-24): `await_phase_login_probe` used to live here as a
# per-phase cookie-only gate called at the start of Phases 1-5. It
# turned every transient cookie blip into a mid-run `login_required`
# banner even when Phase 0 had just verified successfully. The layer
# is deleted — Phase 0 is now the single source of truth for login
# state. If a session really drifts mid-run, the phase's own driving
# code (ChatGPT navigation, NotebookLM upload, etc.) will surface a
# concrete failure through fail_phase with a specific reason, which
# the existing PhaseAlertPanel handles without the generic
# "Login required" noise.


async def scrape_progress_chatgpt(page):
    """Scrape ChatGPT's current research progress (Playwright JS — zero CUA cost).
    Returns rich data for web app: status, thinking steps, sources, sections, text length.

    Deep Research note: as of 2026, ChatGPT Deep Research renders inside a cross-origin
    iframe (connector_openai_deep_research.web-sandbox.oaiusercontent.com). Main-page
    selectors miss DR content, so we iterate `page.frames` and scrape the DR frame
    separately, then merge. Main-page signals (title, model, stop button) still come
    from the host page."""
    try:
        # ---- Main-page scrape (host page: title, model, stop button, chat-level DR indicators)
        result = await page.evaluate("""() => {
            const r = {
                status: 'unknown', phase: '', progress: '', thinking: '',
                sources: 0, source_urls: [], sections: [], steps: [],
                partial_text_len: 0, plan: '', model: '', title: '',
                dr_active: false, dr_done_text: false, has_stop_btn: false,
                panel_open: false, searches: 0
            };
            // Model info
            const modelEl = document.querySelector('[data-testid="model-selector"], .model-label');
            if (modelEl) r.model = modelEl.innerText.substring(0, 50);
            // Conversation title
            const titleEl = document.querySelector('h1, [data-testid="conversation-title"]');
            if (titleEl) r.title = titleEl.innerText.substring(0, 100);
            // Stop-button detection (aria-label + text fallback)
            r.has_stop_btn = !!document.querySelector(
                'button[aria-label="Stop generating"], button[aria-label*="Stop"], ' +
                'button[data-testid="stop-button"], button[data-testid*="stop"]'
            );
            if (!r.has_stop_btn) {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    const t = (b.textContent || '').trim().toLowerCase();
                    if (t === 'stop' || t === 'stop generating' || t === 'stop research') { r.has_stop_btn = true; break; }
                }
            }
            // Body-level DR indicators (host page shows banner/status strings even when content is in iframe)
            const bodyLower = document.body.innerText.toLowerCase();
            const drKws = ['researching', 'sources found', 'sources and counting',
                          'searching the web', 'reading sources', 'analyzing',
                          'deep research', 'looking into', 'investigating'];
            r.dr_active = drKws.some(kw => bodyLower.includes(kw));

            // 2026-04-26 v3: extract the COLLAPSED activity strip BEFORE the
            // side panel opens. Strip wording: "Looking into Hermes memory
            // system... 196 searches". Without this, FE per-platform card
            // shows empty narration for the first 3 min (gate is 180s).
            // Verb regex constrained to start-of-string + count badge so
            // stale chat text (user prompts, prior responses) won't match.
            try {
                const VERB = /^(thinking|reasoning|searching|looking|browsing|investigating|analyzing|reading|exploring|checking|visiting|researching|confirming|summari[zs]ing|synthesi[zs]ing|drafting|finali[zs]ing)\\b/i;
                const COUNT = /\\b\\d+\\s+(?:searches?|sources?|results?)\\b/i;
                let stripText = '';
                let stripTop = -1;
                const cands = document.querySelectorAll('div, button, [role="button"], li');
                for (const el of cands) {
                    const t = (el.innerText || '').trim();
                    if (!t || t.length < 6 || t.length > 220) continue;
                    if (!(VERB.test(t) && COUNT.test(t))) continue;
                    const rect = el.getBoundingClientRect();
                    if (rect.width === 0 || rect.height === 0) continue;
                    if (rect.top > stripTop) { stripText = t.slice(0, 200); stripTop = rect.top; }
                }
                if (stripText) {
                    r.progress = stripText;
                    r.steps.push(stripText);
                    // Searches count — pull the integer from the strip badge
                    // (e.g., "Summarizing X · 133 searches"). Tracked
                    // separately from r.sources (URL-derived) because a
                    // single search yields many sources and the user cares
                    // about both: how many web queries were issued vs how
                    // many citations made it into the report.
                    const sm = stripText.match(/(\\d+)\\s+searches?/i);
                    if (sm) r.searches = parseInt(sm[1], 10) || 0;
                }
            } catch(e) {}
            // Completion indicators
            const doneKws = ['research completed', 'research complete',
                             'finished research', 'deep research completed'];
            r.dr_done_text = doneKws.some(kw => bodyLower.includes(kw));
            // Thinking/research progress (host page, rare in iframe DR but kept for chat mode)
            const thinking = document.querySelector('.thinking-text, [data-thinking], .research-progress, .step-text');
            if (thinking) r.thinking = thinking.innerText.substring(0, 500);
            // Sources/citations (host page — kept for non-DR chat)
            const srcSet = new Set();
            document.querySelectorAll(
                '.citation, .source-link, [data-citation], ' +
                '[data-message-author-role="assistant"] a[href*="http"], ' +
                '[data-testid="canvas"] a[href*="http"], .canvas-container a[href*="http"]'
            ).forEach(s => {
                const href = s.href || '';
                if (href.startsWith('http') && !href.includes('chatgpt.com') && !href.includes('openai.com') && !href.includes('chat.openai') && !href.includes('oaiusercontent') && href.length < 500)
                    srcSet.add(href);
            });
            r.source_urls = Array.from(srcSet).slice(0, 50);
            r.sources = r.source_urls.length;
            // Response sections (host page headings)
            const headings = document.querySelectorAll('[data-message-author-role="assistant"] h1, [data-message-author-role="assistant"] h2, [data-message-author-role="assistant"] h3');
            r.sections = Array.from(headings).map(h => h.innerText.substring(0, 80));
            // Partial response length (host page)
            const msgs = document.querySelectorAll('[data-message-author-role="assistant"]');
            if (msgs.length > 0) r.partial_text_len = msgs[msgs.length-1].innerText.length;
            // Canvas/artifact content
            const canvas = document.querySelector('[data-testid="canvas"], .canvas-container, .canvas-content');
            if (canvas && canvas.innerText.length > r.partial_text_len) r.partial_text_len = canvas.innerText.length;
            return r;
        }""")

        # ---- Host-page side-panel scrape (P1 Pro+ET, also catches P2 host-side panel)
        # P1 mode renders the activity panel inline on the host page (no DR
        # sandbox iframe). After _open_chatgpt_activity_panel clicks the strip,
        # the side panel mounts as <aside>/[role=complementary]/panel-class div
        # on the right ~30-40% of viewport. The iframe block below only matches
        # P2 DR; this block fills the P1 gap with a Gemini-style wide-net sweep
        # of the panel root: VERB-prefixed step rows, generic a[href] sources
        # with chatgpt.com redirector unwrap + chrome filter, h1/h2/h3 sections.
        # Returns panel_found:false when no host-side panel exists (e.g. P2 DR
        # where panel is iframe-rooted) → no-op merge, iframe block runs next.
        try:
            hp = await page.evaluate("""() => {
                const out = { steps: [], source_urls: [], sections: [], progress: '', panel_found: false };
                const sels = [
                    'aside', '[role="complementary"]', '[role="region"]',
                    '[aria-label*="source" i]', '[aria-label*="research" i]',
                    '[aria-label*="activity" i]',
                    '[class*="panel" i][class*="side" i]',
                    '[class*="research" i][class*="panel" i]',
                    '[class*="activity" i][class*="panel" i]'
                ];
                let root = null;
                for (const sel of sels) {
                    for (const el of document.querySelectorAll(sel)) {
                        const rc = el.getBoundingClientRect();
                        if (rc.width < 280 || rc.height < 200) continue;
                        if (rc.right < window.innerWidth * 0.55) continue;
                        const inner = (el.innerText || '').trim();
                        if (inner.length < 50) continue;
                        root = el; break;
                    }
                    if (root) break;
                }
                if (!root) return out;
                out.panel_found = true;
                // 2026-04-26 v5: structure-only gate. Old VERB+check+spin
                // gate dropped Extended Thinking reasoning paragraphs and
                // Deep Research source-title rows because they often have
                // no spin/check icon AND no verb prefix. New gate accepts
                // any leaf-row (no nested listitems) with substantial text.
                const VERB = /^(checking|searching|looking|browsing|investigating|analyzing|reading|exploring|visiting|researching|thinking|reasoning|gathering|reviewing|consulting|comparing|evaluating|considering|drafting|writing|finalizing|finalising|summari[zs]ing|confirming|synthesi[zs]ing)\\b/i;
                const rowEls = Array.from(root.querySelectorAll('li, [role="listitem"], div, p, button, [role="button"]'));
                const seenKey = new Set();
                const rows = [];
                for (const el of rowEls) {
                    const t = (el.innerText || '').trim();
                    if (!t || t.length < 12 || t.length > 240) continue;
                    if (el.querySelector('li, [role="listitem"]')) continue;
                    if (t === t.toUpperCase() && t.length < 30) continue;
                    const wordChars = t.replace(/[^A-Za-z]/g, '').length;
                    if (wordChars < 8) continue;
                    if ((t.match(/\\n/g) || []).length > 3) continue;
                    const hasCheck = !!el.querySelector('svg[class*="check"], svg[data-icon*="check"], [aria-label*="completed" i]');
                    const hasSpin  = !!el.querySelector('svg[class*="spin"], svg[class*="loader"], [class*="animate-spin"], [aria-busy="true"]');
                    const verbHit  = VERB.test(t);
                    const key = t.slice(0, 80);
                    if (seenKey.has(key)) continue;
                    seenKey.add(key);
                    rows.push({ t: t.slice(0, 220), hasSpin, hasCheck, verbHit });
                }
                out.steps = rows.map(r => r.t).slice(-15);
                const live = rows.find(r => r.hasSpin)
                           || rows.find(r => r.verbHit && !r.hasCheck)
                           || (rows.length ? rows[rows.length - 1] : null);
                if (live) out.progress = live.t.slice(0, 160);
                else if (out.steps.length) out.progress = out.steps[out.steps.length - 1];
                const srcSet = new Set();
                root.querySelectorAll('a[href^="http"]').forEach(a => {
                    let h = a.href || '';
                    if (!h || h.length >= 500) return;
                    try {
                        if (h.includes('chatgpt.com/') && h.includes('url=')) {
                            const u = new URL(h);
                            const real = u.searchParams.get('url');
                            if (real && real.startsWith('http')) h = decodeURIComponent(real);
                        }
                    } catch(e) {}
                    if (h.includes('chatgpt.com') || h.includes('openai.com') ||
                        h.includes('oaiusercontent') || h.includes('chat.openai')) return;
                    srcSet.add(h);
                });
                out.source_urls = Array.from(srcSet).slice(0, 50);
                out.sections = Array.from(root.querySelectorAll('h1, h2, h3'))
                    .map(h => (h.innerText || '').trim().slice(0, 80))
                    .filter(s => s.length > 1);
                return out;
            }""")
            if hp and hp.get("panel_found"):
                result["panel_open"] = True
                if hp.get("source_urls"):
                    seen_h = set(result.get("source_urls") or [])
                    unioned_h = list(result.get("source_urls") or [])
                    for u in hp["source_urls"]:
                        if u not in seen_h:
                            seen_h.add(u); unioned_h.append(u)
                    if len(unioned_h) > result.get("sources", 0):
                        result["source_urls"] = unioned_h[:50]
                        result["sources"] = len(result["source_urls"])
                if hp.get("steps") and len(hp["steps"]) > len(result.get("steps") or []):
                    result["steps"] = hp["steps"]
                if hp.get("progress"):
                    result["progress"] = hp["progress"]
                if hp.get("sections") and len(hp["sections"]) > len(result.get("sections") or []):
                    result["sections"] = hp["sections"]
        except Exception as _hpe:
            log(f"ChatGPT host-panel scrape skipped: {_hpe}", "DEBUG")

        # ---- Iframe scrape (Deep Research content lives here as of 2026)
        try:
            for frame in page.frames:
                try:
                    src = (frame.url or "").lower()
                except Exception:
                    continue
                if not src:
                    continue
                # Match any OpenAI DR sandbox iframe (URL substring varies)
                if ("deep_research" in src or "oaiusercontent" in src or "web-sandbox.oaiusercontent" in src):
                    try:
                        dr = await frame.evaluate("""() => {
                            const d = {
                                steps: [], source_urls: [], sections: [],
                                partial_text_len: 0, progress: '', thinking: '',
                                is_active: false, is_done: false
                            };
                            // 1. Steps: DR shows an activity/timeline panel
                            const stepEls = document.querySelectorAll(
                                '[class*="step"], [class*="activity"], [class*="timeline"] li, ' +
                                '[data-step], [class*="research-step"], ' +
                                'li[class*="activity"], [role="listitem"]'
                            );
                            d.steps = Array.from(stepEls).map(e => (e.innerText || '').trim().substring(0, 180))
                                                         .filter(s => s.length > 3).slice(-12);
                            // 2. Sources: DR shows a source list — collect http links inside iframe
                            const srcSet = new Set();
                            document.querySelectorAll('a[href^="http"]').forEach(a => {
                                const h = a.href || '';
                                if (h.length < 500 &&
                                    !h.includes('chatgpt.com') && !h.includes('openai.com') &&
                                    !h.includes('oaiusercontent')) srcSet.add(h);
                            });
                            d.source_urls = Array.from(srcSet).slice(0, 50);
                            // 3. Headings in the DR report
                            const hs = document.querySelectorAll('h1, h2, h3');
                            d.sections = Array.from(hs).map(h => (h.innerText || '').trim().substring(0, 80))
                                                       .filter(s => s.length > 1);
                            // 4. Partial text — use body text as proxy
                            d.partial_text_len = (document.body?.innerText || '').length;
                            // 5. Activity detection inside iframe
                            const bodyLower = (document.body?.innerText || '').toLowerCase();
                            const activeKws = ['researching', 'searching', 'reading', 'analyzing',
                                               'sources found', 'sources and counting', 'browsing'];
                            d.is_active = activeKws.some(kw => bodyLower.includes(kw));
                            // 6. Completion indicators inside iframe
                            const doneKws = ['research completed', 'finished research',
                                             'deep research completed'];
                            d.is_done = doneKws.some(kw => bodyLower.includes(kw));
                            // 7. Latest step as progress
                            if (d.steps.length > 0) d.progress = d.steps[d.steps.length - 1];
                            return d;
                        }""")
                        if dr:
                            # Additive merge: iframe data is rich for DR content,
                            # but host-panel sweep above already collected steps/
                            # sources from the host page side. Last-write-wins
                            # would clobber 12 host-panel rows with 8 iframe rows.
                            if dr.get("partial_text_len", 0) > result.get("partial_text_len", 0):
                                result["partial_text_len"] = dr["partial_text_len"]
                            # Sources: union (preserve order, cap 50)
                            iframe_srcs = dr.get("source_urls") or []
                            if iframe_srcs:
                                seen_i = set(result.get("source_urls") or [])
                                unioned_i = list(result.get("source_urls") or [])
                                for u in iframe_srcs:
                                    if u not in seen_i:
                                        seen_i.add(u); unioned_i.append(u)
                                if len(unioned_i) > len(result.get("source_urls") or []):
                                    result["source_urls"] = unioned_i[:50]
                                    result["sources"] = len(result["source_urls"])
                            # Steps: union by [:80] dedupe key (keep last 15)
                            if dr.get("steps"):
                                existing_steps = result.get("steps") or []
                                seen_s = set(s[:80] for s in existing_steps)
                                merged_steps = list(existing_steps)
                                for s in dr["steps"]:
                                    k = s[:80]
                                    if k not in seen_s:
                                        seen_s.add(k); merged_steps.append(s)
                                result["steps"] = merged_steps[-15:]
                                if dr.get("progress"):
                                    # 2026-04-29: keep host-panel progress when
                                    # present — the host strip's "Focusing on X"
                                    # / "224 searches" line is canonical for FE
                                    # narration. Only fall through to iframe
                                    # progress when host produced nothing.
                                    cur = result.get("progress") or ""
                                    if not cur:
                                        result["progress"] = dr["progress"]
                            # Sections: union (exact-string dedup since headings)
                            if dr.get("sections"):
                                existing_sec = result.get("sections") or []
                                seen_sec = set(existing_sec)
                                merged_sec = list(existing_sec)
                                for s in dr["sections"]:
                                    if s not in seen_sec:
                                        seen_sec.add(s); merged_sec.append(s)
                                if len(merged_sec) > len(existing_sec):
                                    result["sections"] = merged_sec
                            # Status override from iframe signals
                            if dr.get("is_active"):
                                result["dr_active"] = True
                            if dr.get("is_done"):
                                result["dr_done_text"] = True
                    except Exception as _ie:
                        log(f"ChatGPT DR iframe evaluate skipped: {_ie}", "DEBUG")
                    # ── Actively expand the "Cited sources" panel ──
                    # ChatGPT DR collapses the sources list by default — the
                    # `<a href>` nodes inside it are NOT rendered until the
                    # user clicks the panel. The default scrape above misses
                    # those links and undercounts sources (often 0–3 instead
                    # of 10–20). On by default — opt out via
                    # DG_SOURCE_PANEL_EXPAND=0/false/no. Wrapped in try/except
                    # so any failure silently keeps the partial result we
                    # already collected.
                    if os.environ.get("DG_SOURCE_PANEL_EXPAND", "1").lower() not in ("0", "false", "no"):
                        try:
                            click_res = await frame.evaluate("""() => {
                                const candidates = document.querySelectorAll('button, [role="button"]');
                                for (const b of candidates) {
                                    const t = (b.textContent || '').trim().toLowerCase();
                                    const al = (b.getAttribute('aria-label') || '').toLowerCase();
                                    const isSourcesLabel =
                                        t === 'sources' || t === 'cited sources' ||
                                        /^\\d+\\s+sources?$/.test(t) ||
                                        al.includes('cited source') || al === 'sources';
                                    if (!isSourcesLabel) continue;
                                    const expanded = b.getAttribute('aria-expanded');
                                    if (expanded === 'true') {
                                        return { clicked: false, alreadyExpanded: true, label: t || al };
                                    }
                                    b.click();
                                    return { clicked: true, label: t || al };
                                }
                                return { clicked: false, found: false };
                            }""")
                            if click_res and click_res.get("clicked"):
                                # Lazy render needs a beat. 1.0s is generous —
                                # the list either appears immediately or the
                                # panel was already populated.
                                await asyncio.sleep(1.0)
                                try:
                                    dr2 = await frame.evaluate("""() => {
                                        const srcSet = new Set();
                                        document.querySelectorAll('a[href^="http"]').forEach(a => {
                                            const h = a.href || '';
                                            if (h.length < 500 &&
                                                !h.includes('chatgpt.com') && !h.includes('openai.com') &&
                                                !h.includes('oaiusercontent')) srcSet.add(h);
                                        });
                                        return { source_urls: Array.from(srcSet).slice(0, 50) };
                                    }""")
                                    if dr2 and dr2.get("source_urls"):
                                        # Union (preserve order) instead of replace —
                                        # the panel may render different URLs than the
                                        # pre-click DOM scrape (different ordering or
                                        # subset). Strict `>` would skip cases where
                                        # post-click count ties pre-click but the URLs
                                        # are objectively different.
                                        seen_u = set(result.get("source_urls") or [])
                                        unioned = list(result.get("source_urls") or [])
                                        for u in dr2["source_urls"]:
                                            if u not in seen_u:
                                                seen_u.add(u)
                                                unioned.append(u)
                                        if len(unioned) > result.get("sources", 0):
                                            result["source_urls"] = unioned[:50]
                                            result["sources"] = len(result["source_urls"])
                                except Exception as _re2:
                                    log(f"ChatGPT sources-panel re-scrape skipped: {_re2}", "DEBUG")
                        except Exception as _se:
                            log(f"ChatGPT sources-panel expand skipped: {_se}", "DEBUG")
                    # ── 2026-04-26 (v2): plan-checklist DOM walker + live-row click ──
                    # ChatGPT DR's plan checklist uses Tailwind <div>s (not role=checkbox /
                    # data-testid=task / bare <li>) so the v1 selectors missed iteration 1.
                    # v2: walk the checklist via verb-prefix + svg[class*=check|spin] heuristic,
                    # populate result.steps[] (full plan list, last 15) and result.progress
                    # (active-row label) directly. Click the live row IF NOT already
                    # aria-expanded, then re-scrape URLs scoped to the expanded subtree
                    # (no global host-page sweep). Opt out via DG_PLAN_ITEM_EXPAND=0.
                    if os.environ.get("DG_PLAN_ITEM_EXPAND", "1").lower() not in ("0", "false", "no"):
                        try:
                            walk = await frame.evaluate("""() => {
                                const out = { steps: [], live_label: '', clicked: false, already_expanded: false };
                                const VERB = /^(thinking|reasoning|searching|looking|browsing|investigating|analyzing|reading|exploring|checking|visiting|researching|confirming|summari[zs]ing|synthesi[zs]ing|drafting|finali[zs]ing)\\b/i;
                                const all = Array.from(document.querySelectorAll('div, li, [role="listitem"], button, [role="button"]'));
                                const rows = [];
                                for (const el of all) {
                                    const t = (el.innerText || '').trim();
                                    if (!t || t.length < 4 || t.length > 220) continue;
                                    const hasCheck = !!el.querySelector('svg[class*="check"], svg[data-icon*="check"]');
                                    const hasSpin  = !!el.querySelector('svg[class*="spin"], svg[class*="loader"], [class*="animate-spin"]');
                                    const verbHit  = VERB.test(t);
                                    if (!verbHit && !hasCheck && !hasSpin) continue;
                                    const key = t.slice(0, 60);
                                    if (rows.find(r => r.key === key)) continue;
                                    rows.push({ el, t, hasCheck, hasSpin, verbHit, key });
                                }
                                out.steps = rows.map(r => r.t.slice(0, 200)).slice(-15);
                                const live = rows.find(r => r.hasSpin) ||
                                             rows.find(r => r.verbHit && !r.hasCheck);
                                if (live) {
                                    out.live_label = live.t.slice(0, 160);
                                    const expanded = live.el.getAttribute('aria-expanded');
                                    if (expanded === 'true') {
                                        out.already_expanded = true;
                                    } else {
                                        live.el.click();
                                        out.clicked = true;
                                    }
                                }
                                return out;
                            }""")
                            if walk:
                                # Additive: union plan-item steps with whatever
                                # the iframe walker + host-panel sweep already
                                # collected. live_label is the active row, so
                                # it typically wins for `progress` but only if
                                # richer than what's there.
                                if walk.get("steps"):
                                    existing_steps = result.get("steps") or []
                                    seen_s = set(s[:80] for s in existing_steps)
                                    merged_steps = list(existing_steps)
                                    for s in walk["steps"]:
                                        k = s[:80]
                                        if k not in seen_s:
                                            seen_s.add(k); merged_steps.append(s)
                                    result["steps"] = merged_steps[-15:]
                                if walk.get("live_label"):
                                    cur = result.get("progress") or ""
                                    if not cur or len(walk["live_label"]) > len(cur) * 0.5:
                                        result["progress"] = walk["live_label"]
                                if walk.get("clicked"):
                                    log(f'[ChatGPT] plan-item live-row clicked: "{walk.get("live_label","")}"')
                                    await asyncio.sleep(1.0)
                                if walk.get("clicked") or walk.get("already_expanded"):
                                    try:
                                        dr3 = await frame.evaluate("""() => {
                                            const expanded = document.querySelector('[aria-expanded="true"]');
                                            const root = expanded || document;
                                            const srcSet = new Set();
                                            root.querySelectorAll('a[href^="http"]').forEach(a => {
                                                const h = a.href || '';
                                                if (h.length < 500 &&
                                                    !h.includes('chatgpt.com') && !h.includes('openai.com') &&
                                                    !h.includes('oaiusercontent')) srcSet.add(h);
                                            });
                                            return { source_urls: Array.from(srcSet).slice(0, 50) };
                                        }""")
                                        if dr3 and dr3.get("source_urls"):
                                            seen3 = set(result.get("source_urls") or [])
                                            unioned3 = list(result.get("source_urls") or [])
                                            for u in dr3["source_urls"]:
                                                if u not in seen3:
                                                    seen3.add(u)
                                                    unioned3.append(u)
                                            if len(unioned3) > len(result.get("source_urls") or []):
                                                result["source_urls"] = unioned3[:50]
                                                result["sources"] = len(result["source_urls"])
                                    except Exception as _re3:
                                        log(f"ChatGPT plan-item re-scrape skipped: {_re3}", "DEBUG")
                        except Exception as _pe:
                            log(f"ChatGPT plan-item walker skipped: {_pe}", "DEBUG")
                    break
        except Exception as _fe:
            log(f"ChatGPT frames iteration skipped: {_fe}", "DEBUG")

        # ---- Synthesize steps if iframe didn't provide any
        if not result.get("steps"):
            synth = []
            if result.get("thinking"):
                synth.append("Extended Thinking: " + result["thinking"][:100])
            hosts = set()
            for u in result.get("source_urls", []):
                try:
                    from urllib.parse import urlparse
                    h = urlparse(u).hostname or ""
                    if h.startswith("www."):
                        h = h[4:]
                    if h:
                        hosts.add(h)
                except Exception:
                    pass
            for h in list(hosts)[:5]:
                synth.append(f"Researching {h}")
            if result.get("sections"):
                synth.append(f"Writing: {result['sections'][-1]}")
            if result.get("partial_text_len", 0) > 3000:
                synth.append(f"Generating brief: {round(result['partial_text_len']/1000)}k chars")
            result["steps"] = synth

        if result.get("steps") and not result.get("progress"):
            result["progress"] = result["steps"][-1]

        # Plan line (sections as outline)
        if len(result.get("sections", [])) >= 2 and not result.get("plan"):
            result["plan"] = "Research outline: " + " \u2192 ".join(result["sections"][:5])

        # ---- Final status resolution
        has_stop = result.pop("has_stop_btn", False)
        dr_active = result.pop("dr_active", False)
        dr_done_text = result.pop("dr_done_text", False)
        partial = result.get("partial_text_len", 0)
        if has_stop or dr_active:
            result["status"] = "generating"
            result["phase"] = "deep_research" if dr_active else "researching"
            if not result.get("progress"):
                result["progress"] = "Deep Research in progress"
        elif dr_done_text and partial > 100:
            result["status"] = "complete"
            result["phase"] = "done"
        elif partial > 100:
            # Partial content but no active/done signal — call it complete (historical behavior)
            result["status"] = "complete"
            result["phase"] = "done"
        else:
            result["status"] = "idle"
            result["phase"] = "waiting"

        return result
    except Exception as e:
        log(f"ChatGPT scrape failed (selectors may need update): {e}", "WARN")
        return {"status": "scrape_error", "progress": "Selector mismatch — ChatGPT UI may have changed", "sources": 0, "partial_text_len": 0}


async def _open_chatgpt_activity_panel(page):
    """Click the collapsed activity strip (e.g. 'Looking into Hermes... 196 searches')
    in ChatGPT Deep Research so the side panel with full step list + source URLs
    slides out.

    Robust selector (2026-04-26 v2): walks ALL elements (not just buttons —
    ChatGPT renders the strip as a styled <div> with imperatively-bound click
    handlers, so the v1 narrow `button, [role="button"]` selector matched 0
    candidates and silently no-op'd across 3 user runs). Recurses into Shadow
    DOM. Dispatches the full pointer/mouse event chain (pointerdown → mousedown
    → pointerup → mouseup → click) instead of bare `.click()` so React's
    synthetic listeners fire. Tries the leaf element then 5 ancestors.

    Returns dict with `found`, `candidates` (count of text-matched nodes),
    `clicked`, `alreadyExpanded`, `label`, `clickedTag`. Caller uses
    `_verify_chatgpt_panel_open(page)` 2s post-click to confirm side panel
    actually rendered (mitigates silent click failures)."""
    JS = """() => {
        // searches | sources | results — covers all observed badge wordings
        const COUNT = /\\b\\d+\\s+(?:searches?|sources?|results?)\\b/i;
        // Verb-only fallback for P1 Pro+ET strips that haven't materialized a
        // count yet. Includes "thinking"/"reasoning" because Pro+ET shows
        // those before swapping to site-fetch verbs ("Reading <site>",
        // "Visiting <url>") mid-stream. Reverted 2026-05-03 to the pre-c06a60e
        // P1-only list — the P2 synthesis-stage verbs (confirming, summarizing,
        // synthesizing, drafting, finalizing) added across commits c06a60e..
        // 9f4117c chased a moving target and never opened the P2 source panel
        // reliably anyway. The new ELLIPSIS structural anchor handles all P2
        // wording (live narration always ends in "..."); P1 verb wording is
        // stable so this list stays.
        const VERB_ONLY = /^(thinking|reasoning|searching|looking|browsing|investigating|analyzing|reading|exploring|checking|visiting|researching)\\b/i;
        // 2026-05-03 STRUCTURAL ANCHOR: the live in-tile glow line ALWAYS
        // ends with ellipsis ("..." or U+2026 normalized) while the run is
        // streaming. Verb wording mutates per stream (5 prior commits keep
        // expanding the verb regex with no end in sight); the ellipsis
        // suffix does not. Match BOTH ASCII three-dot and Unicode \\u2026.
        const ELLIPSIS = /(?:\\.{3}|\\u2026)\\s*$/;

        // Specificity score for hit ranking. Layered to keep the 32c2957
        // "parent strip > badge child" guarantee while putting the live
        // ellipsis-bearing leaf above everything (it's the actual click
        // target with the React handler attached, not a presentational
        // wrapper). Tiers: 5 ellipsis+verb > 4 ellipsis+count > 3.5 bare
        // ellipsis > 3 verb+count > 2 verb-only > 1 count-only > 0 (none —
        // unreachable; findHitsIn filters).
        const hitScore = (h) => {
            if (h.hasEllipsis && h.hasVerb)  return 5;
            if (h.hasEllipsis && h.hasCount) return 4;
            if (h.hasEllipsis)               return 3.5;
            if (h.hasVerb && h.hasCount)     return 3;
            if (h.hasVerb)                   return 2;
            if (h.hasCount)                  return 1;
            return 0;
        };

        function findHitsIn(root) {
            // Local accumulator — kept narrow so caller can priority-rank
            // dialog hits ahead of host-page hits.
            const out = [];
            if (!root) return out;
            let nodes;
            try { nodes = root.querySelectorAll('*'); } catch (e) { return out; }
            if (nodes.length > 8000) return out;
            for (const el of nodes) {
                const t = (el.innerText || el.textContent || '').trim();
                if (!t || t.length < 4 || t.length > 300) continue;
                const matchesCount    = COUNT.test(t);
                const matchesVerb     = VERB_ONLY.test(t);
                // Ellipsis match limited to 12–240 char leaves — the live
                // narration sentences land in this window. Mid-sentence
                // "..." in streamed prose paragraphs typically run >240
                // chars (filtered out) or <12 chars (placeholder spans).
                const matchesEllipsis = ELLIPSIS.test(t) && t.length >= 12 && t.length <= 240;
                if (!matchesCount && !matchesVerb && !matchesEllipsis) continue;
                const r = el.getBoundingClientRect();
                if (r.width === 0 || r.height === 0) continue;
                out.push({ el, top: r.top, len: t.length,
                           hasCount: matchesCount, hasVerb: matchesVerb,
                           hasEllipsis: matchesEllipsis });
            }
            return out;
        }

        function clickAndReturn(target, candidatesCount, scope) {
            const label = (target.innerText || target.textContent || '').trim().slice(0, 160);
            // aria-expanded check up the chain — skip re-click if already open
            let probe = target;
            for (let i = 0; i < 6 && probe; i++) {
                if (probe.getAttribute && probe.getAttribute('aria-expanded') === 'true') {
                    return { found: true, alreadyExpanded: true, label,
                             candidates: candidatesCount, scope };
                }
                probe = probe.parentElement;
            }
            // parent-chain dispatch loop — try leaf, then up to 5 ancestors
            const tries = [];
            let node = target;
            for (let i = 0; i < 6 && node; i++) { tries.push(node); node = node.parentElement; }
            let clickedTag = '';
            let lastErr = '';
            for (const n of tries) {
                try {
                    const r = n.getBoundingClientRect();
                    const x = r.left + r.width / 2, y = r.top + r.height / 2;
                    const opts = { bubbles: true, cancelable: true, view: window,
                                   clientX: x, clientY: y, button: 0 };
                    // Full event chain — covers React onPointerDown/onMouseDown/onClick
                    n.dispatchEvent(new MouseEvent('pointerdown', opts));
                    n.dispatchEvent(new MouseEvent('mousedown',  opts));
                    n.dispatchEvent(new MouseEvent('pointerup',  opts));
                    n.dispatchEvent(new MouseEvent('mouseup',    opts));
                    n.dispatchEvent(new MouseEvent('click',      opts));
                    clickedTag = (n.tagName || '') +
                                 (n.getAttribute && n.getAttribute('role')
                                     ? `[${n.getAttribute('role')}]` : '');
                    break;
                } catch (e) { lastErr = String(e); continue; }
            }
            return { found: true, clicked: !!clickedTag, label,
                     candidates: candidatesCount, clickedTag, scope, error: lastErr };
        }

        // 2026-04-28: PASS 1 — dialog-scoped search FIRST. The DR plan
        // dialog (role="dialog" / aria-modal / report-plan class) renders
        // the activity-strip pill ("Summarizing X · 133 searches") pinned
        // at its bottom — clicking THAT is what mounts the sources sub-
        // panel. The host page ALSO renders a presentational footer with
        // the same wording, and clicking that does nothing. Without
        // searching dialog-scoped first, the global walker found the
        // host-page footer, scored it, clicked it, and silently no-op'd
        // — leaving narration stuck at "0 sources, 0 chars".
        const dialogs = document.querySelectorAll(
            '[role="dialog"], [aria-modal="true"], ' +
            '[class*="report-plan" i], [class*="research-plan" i]'
        );
        let dialogHits = [];
        for (const d of dialogs) {
            const r = d.getBoundingClientRect();
            if (r.width < 200 || r.height < 100) continue;
            const found = findHitsIn(d);
            for (const h of found) dialogHits.push(h);
        }
        if (dialogHits.length > 0) {
            dialogHits.sort((a, b) => (hitScore(b) - hitScore(a)) || (b.top - a.top) || (a.len - b.len));
            return clickAndReturn(dialogHits[0].el, dialogHits.length, 'dialog');
        }

        // PASS 2 — global walk (existing logic). Recurses into Shadow DOM.
        const seen = new WeakSet();
        const hits = [];
        function walk(root) {
            if (!root || seen.has(root)) return;
            seen.add(root);
            const found = findHitsIn(root);
            for (const h of found) hits.push(h);
            // Recurse into shadow roots.
            try {
                for (const el of root.querySelectorAll('*')) {
                    if (el.shadowRoot) walk(el.shadowRoot);
                }
            } catch (e) {}
        }
        walk(document);
        if (!hits.length) return { found: false, candidates: 0 };
        // Parent strip (verb+count) wins over badge child (count-only) via
        // hitScore; ties broken by lowest-on-page, then shortest text.
        hits.sort((a, b) => (hitScore(b) - hitScore(a)) || (b.top - a.top) || (a.len - b.len));
        return clickAndReturn(hits[0].el, hits.length, 'global');
    }"""
    try:
        res = await page.evaluate(JS)
        if res and res.get("found"):
            return res
    except Exception:
        pass
    try:
        for frame in page.frames:
            try:
                src = (frame.url or "").lower()
            except Exception:
                continue
            if not src:
                continue
            if ("deep_research" in src or "oaiusercontent" in src or
                    "web-sandbox.oaiusercontent" in src):
                try:
                    res = await frame.evaluate(JS)
                    if res and res.get("found"):
                        return res
                except Exception:
                    continue
    except Exception:
        pass
    return {"found": False, "candidates": 0}


async def _verify_chatgpt_panel_open(page):
    """Returns True if a wide side panel is now visible on the right side of
    the ChatGPT DR viewport. Used post-click to detect silent click failures.

    Heuristic: an <aside> / [role="complementary"] / [aria-label*="source"i]
    / [class*="panel"] element with width >= 280px and at least one URL or
    numbered step row inside."""
    JS = """() => {
        const sels = [
            'aside', '[role="complementary"]', '[role="region"]',
            '[aria-label*="source" i]', '[aria-label*="research" i]',
            '[class*="panel" i][class*="side" i]',
            '[class*="research" i][class*="panel" i]'
        ];
        for (const sel of sels) {
            try {
                for (const el of document.querySelectorAll(sel)) {
                    const r = el.getBoundingClientRect();
                    if (r.width < 280 || r.height < 200) continue;
                    if (r.right < window.innerWidth * 0.55) continue;  // must be on right side
                    const inner = (el.innerText || '').trim();
                    if (inner.length < 50) continue;
                    const hasUrl = !!el.querySelector('a[href*="http"]');
                    const hasList = !!el.querySelector('ol > li, ul > li');
                    if (hasUrl || hasList) return true;
                }
            } catch (e) {}
        }
        return false;
    }"""
    try:
        ok = await page.evaluate(JS)
        if ok:
            return True
    except Exception:
        pass
    try:
        for frame in page.frames:
            try:
                src = (frame.url or "").lower()
            except Exception:
                continue
            if "oaiusercontent" in src or "deep_research" in src:
                try:
                    ok = await frame.evaluate(JS)
                    if ok:
                        return True
                except Exception:
                    continue
    except Exception:
        pass
    return False


async def scrape_progress_gemini(page):
    """Scrape Gemini's current research progress — rich data for web app.
    Selectors use multiple fallbacks — degrades gracefully on UI changes."""
    try:
        return await page.evaluate("""() => {
            const r = {
                status: 'unknown', phase: '', progress: '', thinking: '',
                sources: 0, source_urls: [], sections: [], steps: [],
                partial_text_len: 0, plan: '', title: '', model: '',
                panel_open: false, observed_sources: 0, searches: 0
            };
            // Conversation title (Gemini sets it once the chat has a topic)
            const gtitle = document.querySelector('[data-conversation-title], .conversation-title, bard-sidenav-mini-content [aria-current="true"]');
            if (gtitle) r.title = gtitle.innerText.substring(0, 100);
            else if (document.title) r.title = document.title.replace(/ - Gemini$/, '').substring(0, 100);
            // Research steps (Gemini shows a progress panel during Deep Research)
            const steps = document.querySelectorAll('.research-step, .step-content, [data-research-step], .activity-item');
            r.steps = Array.from(steps).map(s => s.innerText.substring(0, 150));
            if (r.steps.length > 0) r.progress = r.steps[r.steps.length - 1];

            // 2026-04-28 v6: structure-only panel walker — when Gemini's
            // Deep Research activity panel opens, the canonical class
            // selectors (.research-step, .activity-item) may not match the
            // current build. This walker mirrors Claude's panel walker:
            // any aside/role=complementary/role=region container > 220px
            // wide with substantial text content gets walked for leaf
            // rows with VERB-prefix or check/spin icons. Always runs as
            // an additive merge so brittle class-based scrape above keeps
            // working when it does.
            try {
                const VERBG = /^(checking|searching|looking|browsing|investigating|analyzing|reading|exploring|visiting|researching|thinking|reasoning|gathering|reviewing|consulting|comparing|evaluating|considering|drafting|writing|finalizing|finalising|summari[zs]ing)\\b/i;
                const panelRoots = document.querySelectorAll(
                    'aside, [role="complementary"], [role="region"], ' +
                    '[aria-label*="research" i], [aria-label*="sources" i], ' +
                    '[aria-label*="activity" i], [class*="research-panel" i], ' +
                    '[class*="side-panel" i], [class*="drawer" i]'
                );
                const seenRow = new Set();
                const rows = [];
                let live = '';
                let panelMatched = null;
                for (const root of panelRoots) {
                    const pr = root.getBoundingClientRect();
                    if (pr.width < 220 || pr.height < 150) continue;
                    if (pr.right < window.innerWidth * 0.45) continue;
                    panelMatched = root;
                    const rowEls = Array.from(root.querySelectorAll('li, [role="listitem"], div, p, button, [role="button"]'));
                    for (const el of rowEls) {
                        const t = (el.innerText || '').trim();
                        if (!t || t.length < 12 || t.length > 240) continue;
                        if (el.querySelector('li, [role="listitem"]')) continue;
                        if (t === t.toUpperCase() && t.length < 30) continue;
                        const wordChars = t.replace(/[^A-Za-z]/g, '').length;
                        if (wordChars < 8) continue;
                        if ((t.match(/\\n/g) || []).length > 3) continue;
                        const hasCheck = !!el.querySelector('svg[class*="check"], svg[data-icon*="check"], [aria-label*="completed" i]');
                        const hasSpin  = !!el.querySelector('svg[class*="spin"], svg[class*="loader"], [class*="animate-spin"], [aria-busy="true"]');
                        const verbHit  = VERBG.test(t);
                        const key = t.slice(0, 80);
                        if (seenRow.has(key)) continue;
                        seenRow.add(key);
                        rows.push({ t: t.slice(0, 220), hasSpin, hasCheck, verbHit });
                        if (hasSpin && !live) live = t.slice(0, 160);
                    }
                }
                if (rows.length > 0) {
                    // NOTE: this generic panel-walker tier does NOT set
                    // panel_open (Gemini's research is INLINE in the chat
                    // for the structural walker; treating those rows as
                    // a "side panel open" would mis-trigger panel-aware
                    // vision crops). The Show-thinking branch lower in
                    // the function sets r.thinking_visible (NOT panel_open)
                    // for the same reason — Gemini's thinking expander is
                    // inline below the response, full-width, not a side
                    // panel. The vision crop targets the right viewport
                    // edge; firing it on inline thinking would scrape the
                    // wrong region.
                    const panelSteps = rows.map(x => x.t).slice(-15);
                    r.steps = r.steps.concat(panelSteps).slice(-15);
                    if (live) r.progress = live;
                    else {
                        const verbLive = rows.find(x => x.verbHit && !x.hasCheck);
                        if (verbLive) r.progress = verbLive.t.slice(0, 160);
                        else if (rows.length) r.progress = rows[rows.length - 1].t.slice(0, 160);
                    }
                }
                // Also pull source URLs from the matched panel — Gemini's
                // panel includes sourced citations as a[href] entries.
                if (panelMatched) {
                    const panelSrcSet = new Set();
                    panelMatched.querySelectorAll('a[href^="http"]').forEach(a => {
                        const h = a.href || '';
                        if (h.length < 500 &&
                            !h.includes('google.com/gemini') &&
                            !h.includes('accounts.google') &&
                            !h.includes('gemini.google')) panelSrcSet.add(h);
                    });
                    if (panelSrcSet.size > 0) {
                        // We'll union with the global srcSet below.
                        r._panel_sources = Array.from(panelSrcSet);
                    }
                    // Searches count — Gemini DR's activity panel typically
                    // surfaces an aggregate "Searched N websites" / "N sites"
                    // line. Pick the largest number across the four common
                    // wordings so a transient lower count doesn't shrink the
                    // chip mid-run. Tracked separately from r.sources
                    // (URL-derived) for the unified FE chip.
                    try {
                        const panelText = (panelMatched.innerText || '');
                        const re = /(\\d+)\\s+(?:websites?|sources?|searches?|sites?)\\b/gi;
                        let mm; let best = 0;
                        while ((mm = re.exec(panelText)) !== null) {
                            const n = parseInt(mm[1], 10) || 0;
                            if (n > best) best = n;
                        }
                        if (best > 0) r.searches = best;
                    } catch(e) {}
                }
            } catch(e) {}
            // Research plan (shown before "Start research")
            const plan = document.querySelector('.research-plan, .plan-content');
            if (plan) r.plan = plan.innerText.substring(0, 1000);
            // Sources — Gemini Deep Research shows sources in research panel + response
            const srcSet = new Set();
            document.querySelectorAll(
                '.source-card, .citation, [data-source], .web-result, ' +
                '.research-source, [class*="source"], [class*="citation"], ' +
                'a[href*="http"]:not([href*="google.com/gemini"]):not([href*="accounts.google"])'
            ).forEach(s => {
                const a = s.querySelector ? s.querySelector('a') : s;
                const href = a?.href || '';
                if (href.startsWith('http') && href.length < 500) srcSet.add(href);
                // No innerText fallback: titles like "Read on Bloomberg" can't
                // be clicked and would inflate r.sources beyond what the FE
                // filtered URL list shows.
            });
            // Union with the panel-walker's URL haul (above) so URLs found
            // only inside the right-side research panel still flow through.
            if (r._panel_sources) {
                for (const u of r._panel_sources) srcSet.add(u);
                delete r._panel_sources;
            }
            r.source_urls = Array.from(srcSet).slice(0, 50);
            r.sources = r.source_urls.length;
            // Response sections
            const headings = document.querySelectorAll(
                'message-content h1, message-content h2, message-content h3, ' +
                '.model-response-text h1, .model-response-text h2, .model-response-text h3, ' +
                '[class*="response"] h1, [class*="response"] h2'
            );
            r.sections = Array.from(headings).map(h => h.innerText.substring(0, 80)).filter(s => s.length > 1);
            // Per-section status — Gemini renders ✓ / spinner / pending icons
            // next to section headings in the Show-thinking panel. Capture
            // counts so FE narration can say "drafted 4/8 sections".
            try {
                let doneCount = 0;
                Array.from(headings).forEach(h => {
                    const parent = h.parentElement;
                    if (!parent) return;
                    const checkLike = parent.querySelector(
                        'svg[class*="check"], [aria-label*="complete" i], ' +
                        '[aria-label*="done" i], [class*="completed"]'
                    );
                    if (checkLike) doneCount++;
                });
                r.sections_done = doneCount;
                r.sections_total = r.sections.length;
            } catch(e) { r.sections_done = 0; r.sections_total = r.sections.length; }
            // Show-thinking expander detection — capture state in
            // r.thinking_visible (not panel_open) since Gemini's thinking
            // is INLINE below the response, not a right-side panel. The
            // narrate vision crop targets the right edge of the
            // viewport, which would be the wrong region here. Setting
            // panel_open=true would mis-trigger that crop. Use this flag
            // for FE narration context without invoking vision.
            try {
                const showThinkingBtn = Array.from(document.querySelectorAll('button'))
                    .find(b => /show thinking|hide thinking/i.test(b.textContent || ''));
                if (showThinkingBtn && /hide thinking/i.test(showThinkingBtn.textContent || '')) {
                    r.thinking_visible = true;
                }
            } catch(e) {}
            // Composite progress line — cite section progress + website
            // count when both are present. Mirrors Claude's artifact tracker
            // narration ("Tracking N sources from artifact") with Gemini's
            // data shape. Boosts narration quality on iter-#3+ when the
            // raw `r.progress` (live row) is short or missing.
            if (r.searches > 0 && r.sections.length > 0) {
                const liveSection = r.sections[r.sections.length - 1];
                const composite = `Researching ${r.searches} websites — currently on "${liveSection}"`;
                if (composite.length > (r.progress || '').length) r.progress = composite;
            } else if (r.searches > 0 && !r.progress) {
                r.progress = `Researching ${r.searches} websites`;
            }
            // Partial text
            const responses = document.querySelectorAll('message-content, .model-response-text');
            if (responses.length > 0) r.partial_text_len = responses[responses.length-1].innerText.length;
            // Status — robust stop button detection (multiple strategies)
            let isActive = false;
            // 1. aria-label selectors (multiple patterns)
            const stopSels = 'button[aria-label="Stop"], button[aria-label*="stop"], button[aria-label="Cancel"], button[title*="Stop"]';
            if (document.querySelector(stopSels)) isActive = true;
            // 2. Text-based: any button with "Stop" text
            if (!isActive) {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    const txt = (b.textContent || '').trim().toLowerCase();
                    if (txt === 'stop' || txt === 'stop generating' || txt === 'cancel') { isActive = true; break; }
                }
            }
            // 3. Streaming attribute (Gemini marks actively streaming content)
            if (!isActive && document.querySelector('[data-is-streaming="true"], .loading-indicator, .streaming')) isActive = true;
            // 4. Animation detection (spinning/pulsing elements indicate active work)
            // Use getAnimations() + playState === 'running' instead of CSS
            // animationName !== 'none'. CSS animationName remains set on
            // elements whose animations finished or never started, causing
            // persistent UI chrome (avatars, fade-ins) to read as active long
            // after generation completed.
            if (!isActive) {
                const animated = document.querySelectorAll('[class*="animate"], [class*="spin"], [class*="pulse"], [class*="loading"]');
                for (const el of animated) {
                    if (el.offsetParent === null) continue;
                    if (typeof el.getAnimations !== 'function') continue;
                    const anims = el.getAnimations();
                    if (anims.some(a => a.playState === 'running')) { isActive = true; break; }
                }
            }
            // 5. Research progress panel still showing active steps
            if (!isActive && r.steps.length > 0) {
                const lastStep = r.steps[r.steps.length - 1].toLowerCase();
                if (lastStep.includes('searching') || lastStep.includes('reading') || lastStep.includes('analyzing') || lastStep.includes('browsing')) isActive = true;
            }
            // Planning-gate: if "Start research" button is visible, Gemini has
            // produced a plan but research hasn't started — do NOT mark complete
            // even if r.partial_text_len > 0 (that text is the plan, not output).
            let hasStartBtn = false;
            const allBtns = document.querySelectorAll('button');
            for (const b of allBtns) {
                const txt = (b.textContent || '').trim().toLowerCase();
                if (txt === 'start research' || txt.includes('start research')) { hasStartBtn = true; break; }
            }
            if (hasStartBtn) {
                r.status = 'generating';
                r.phase = 'planning';
                if (!r.progress) r.progress = 'Research plan ready — awaiting Start';
            } else {
                r.status = isActive ? 'generating' : (r.partial_text_len > 0 ? 'complete' : 'idle');
                r.phase = isActive ? 'researching' : (r.steps.length > 0 ? 'researching' : (r.plan ? 'planning' : (r.partial_text_len > 0 ? 'done' : 'waiting')));
            }
            return r;
        }""")
    except Exception as e:
        log(f"Gemini scrape failed (selectors may need update): {e}", "WARN")
        return {"status": "scrape_error", "progress": "Selector mismatch — Gemini UI may have changed", "sources": 0, "partial_text_len": 0}


async def scrape_progress_claude(page):
    """Scrape Claude's current research progress — rich data for web app.

    Claude Research (2026) shows:
      - "Stop research" button (not "Stop Response") while active
      - "N sources and counting" text while gathering sources
      - "Research completed in Xm" card header when done
      - Research renders inside a card/artifact panel, not main chat stream
    We detect these text markers as primary activity signals."""
    try:
        return await page.evaluate("""() => {
            const r = {
                status: 'unknown', phase: '', progress: '', thinking: '',
                sources: 0, source_urls: [], sections: [], steps: [],
                tool_uses: [], partial_text_len: 0, plan: '', model: '', title: '',
                panel_open: false, searches: 0
            };
            // Conversation title
            const ctitle = document.querySelector('[data-conversation-title], .conversation-title, header h1, h1.truncate, [data-testid="conversation-title"]');
            if (ctitle) r.title = ctitle.innerText.substring(0, 100);
            else if (document.title) r.title = document.title.replace(/ - Claude$/, '').replace(/^Claude$/, '').substring(0, 100);
            // Model info
            const modelEl = document.querySelector('.model-selector, [data-testid="model-name"]');
            if (modelEl) r.model = modelEl.innerText.substring(0, 50);
            // Thinking content
            const thinking = document.querySelector('[data-is-thinking="true"], .thinking-content, .thinking-block');
            if (thinking) r.thinking = thinking.innerText.substring(0, 500);

            // ---- Text-based markers (Claude Research surfaces activity as text, not attributes)
            const bodyText = document.body?.innerText || '';
            const bodyLower = bodyText.toLowerCase();
            // "N sources and counting" → research actively gathering
            const srcCountM = bodyText.match(/(\\d[\\d,]*)\\s+sources?\\s+and\\s+counting/i);
            const liveSrcCount = srcCountM ? parseInt(srcCountM[1].replace(/,/g, ''), 10) : 0;
            // "Research completed in Xm" → research done
            // 2026-04-26: matches BOTH "research completed in 5m" (legacy)
            // AND "Research complete · 553 sources · 24m 41s" (modern 2026).
            // 2026-05-04: also Claude's 2026-05+ "Boom! Research report is
            // ready" callout — long DR runs ship this instead of the prefix.
            const doneM = bodyText.match(/research\\s+complete(?:d)?(?:\\s+in)?(?:[\\s·•—\\-]+\\d[\\d,]*\\s+sources?)?(?:[\\s·•—\\-]+\\d+(?:[hms]|\\s*(?:hour|min|sec)))?/i);
            const boomM = bodyText.match(/\\bBoom!\\s+(?:Your\\s+)?[Rr]esearch\\s+report\\s+is\\s+ready\\b/);
            const researchDone = !!(doneM || boomM);

            // ---- Tool uses (Research tool, web_search, browse, etc.)
            const tools = document.querySelectorAll(
                '.tool-use-content, [data-tool-name], .tool-result, ' +
                '[class*="tool-use"], [class*="tool_use"], [data-testid*="tool"], ' +
                '.font-claude-message [class*="border"][class*="rounded"]'
            );
            r.tool_uses = Array.from(tools).map(t => {
                const name = t.getAttribute('data-tool-name') || '';
                const txt = (t.innerText || '').substring(0, 200);
                return name ? `${name}: ${txt}` : txt;
            }).filter(t => t.length > 3);

            // ---- Sources — citations, tool-result links, artifact links
            const srcSet = new Set();
            document.querySelectorAll('.font-claude-message a[href*="http"], .contents a[href*="http"]').forEach(a => {
                const href = a.href || '';
                if (href.startsWith('http') && !href.includes('claude.ai') && !href.includes('anthropic.com'))
                    srcSet.add(href);
            });
            document.querySelectorAll('[class*="tool"] a[href], .tool-result a[href]').forEach(a => {
                if (a.href?.startsWith('http') && !a.href.includes('claude.')) srcSet.add(a.href);
            });
            document.querySelectorAll('aside a[href*="http"], [class*="artifact"] a[href*="http"]').forEach(a => {
                if (a.href?.startsWith('http') && !a.href.includes('claude.')) srcSet.add(a.href);
            });
            // Broad research-card link sweep: any http link inside an element whose class/text
            // mentions "research" (research report lives inside card wrappers with dynamic classes)
            document.querySelectorAll('[class*="research"] a[href*="http"], [data-testid*="research"] a[href*="http"]').forEach(a => {
                if (a.href?.startsWith('http') && !a.href.includes('claude.')) srcSet.add(a.href);
            });
            r.source_urls = Array.from(srcSet).slice(0, 50);
            r.sources = r.source_urls.length;
            // Text-derived count from "N sources and counting" — kept SEPARATE
            // from r.sources because there are no URLs to attribute. Without
            // this split, the chip "5 src" disagreed with the empty URL list.
            // The watchdog can still consume r.observed_sources for liveness.
            r.observed_sources = liveSrcCount;
            // Mirror onto the unified `searches` field so the FE has one
            // consistent name across all three agents. Claude's UI conflates
            // searches and sources ("N sources and counting") but the FE
            // chip still reads from r.searches for visual consistency.
            r.searches = liveSrcCount;

            // ---- Sections — headings restricted to artifact / aside /
            // research-panel scope. The .font-claude-message + .contents
            // selectors used to be here (2026-04-30 removed) but they
            // grabbed conversation-thread chrome ("# You said:", "# Claude
            // responded:") which got prepended with "Building: " at line
            // 7102 and contaminated r.steps[] / r.progress, then leaked
            // into narrator inputs as parroted "Claude responded: I'll
            // start by..." narration. Belt-and-suspenders chrome filter
            // on the .filter() line defends against any future selector
            // that re-introduces chat-thread headings.
            const headings = document.querySelectorAll(
                'aside h1, aside h2, aside h3, ' +
                '[class*="artifact"] h1, [class*="artifact"] h2, ' +
                '[class*="research"] h1, [class*="research"] h2, [class*="research"] h3'
            );
            r.sections = Array.from(headings)
                .map(h => (h.innerText || '').substring(0, 80))
                .filter(s => s.length > 1 &&
                             !/^(?:you|claude|chatgpt|gemini|notebooklm|gpt)\\s+(?:said|responded)\\b/i.test(s));

            // ---- Partial text — conversation + artifact + research card
            let textLen = 0;
            const msgs = document.querySelectorAll('.font-claude-message, .contents .prose');
            if (msgs.length > 0) textLen = msgs[msgs.length-1].innerText.length;
            const artifact = document.querySelector('aside .prose, aside [class*="content"], [class*="artifact-panel"] .prose');
            if (artifact) textLen = Math.max(textLen, artifact.innerText.length);
            // Research card container text (major content host when "Research" tool is used)
            const researchCard = document.querySelector('[class*="research-card"], [data-testid*="research"], [class*="research-report"]');
            if (researchCard) textLen = Math.max(textLen, (researchCard.innerText || '').length);
            r.partial_text_len = textLen;

            // ---- 2026-04-26 v3: extract artifact-1 CARD preview text BEFORE
            // the side panel opens. The card sits in the assistant message in
            // the conversation column with class containing "artifact" — title
            // + first ~5 visible checklist rows are visible here. Currently the
            // existing scrape only reads <a href> links from these wrappers;
            // we now also extract the card body text so steps[] / progress
            // populate from the first poll, not just after iter-#3 panel-open.
            try {
                const artifactCards = document.querySelectorAll(
                    '.font-claude-message [class*="artifact"]'
                );
                const cardLines = [];
                let cardTitle = '';
                for (const c of artifactCards) {
                    const t = (c.innerText || '').trim();
                    if (!t || t.length < 10) continue;
                    const lines = t.split('\\n').map(s => s.trim())
                                   .filter(s => s.length > 3 && s.length < 200);
                    if (!cardTitle && lines.length) cardTitle = lines[0];
                    for (const ln of lines.slice(1, 8)) cardLines.push(ln);
                }
                if (cardTitle && !r.title) r.title = cardTitle.slice(0, 100);
                cardLines.slice(0, 6).forEach(ln => r.steps.push(ln));
                if (cardLines.length > 0 && !r.progress) {
                    r.progress = cardLines[cardLines.length - 1];
                }
            } catch(e) {}

            // ---- 2026-04-26 v5: live panel walker — after the artifact panel
            // opens (aside / artifact-panel / research-panel mount), the panel
            // root contains the full live checklist. Structure-only gate
            // (no VERB/icon requirement) matches the ChatGPT P1 walker so
            // Reading-source rows and Searched-the-web rows both register.
            try {
                const VERB2 = /^(checking|searching|looking|browsing|investigating|analyzing|reading|exploring|visiting|researching|thinking|reasoning|gathering|reviewing|consulting|comparing|evaluating|considering|drafting|writing|finalizing|finalising|summari[zs]ing)\\b/i;
                const panelRoots = document.querySelectorAll('aside, [role="complementary"], [role="dialog"], [data-state="open"], [class*="artifact-panel"], [class*="research-panel"], [class*="side-panel" i], [class*="sidebar" i], [class*="drawer" i], [aria-label*="research" i], [aria-label*="sources" i], [aria-label*="activity" i]');
                const panelSeen = new Set();
                const panelRows = [];
                let panelLive = '';
                for (const root of panelRoots) {
                    const pr = root.getBoundingClientRect();
                    if (pr.width < 220 || pr.height < 150) continue;
                    const rowEls = Array.from(root.querySelectorAll('li, [role="listitem"], div, p, button, [role="button"]'));
                    for (const el of rowEls) {
                        const t = (el.innerText || '').trim();
                        if (!t || t.length < 12 || t.length > 240) continue;
                        if (el.querySelector('li, [role="listitem"]')) continue;
                        if (t === t.toUpperCase() && t.length < 30) continue;
                        const wordChars = t.replace(/[^A-Za-z]/g, '').length;
                        if (wordChars < 8) continue;
                        if ((t.match(/\\n/g) || []).length > 3) continue;
                        const hasCheck = !!el.querySelector('svg[class*="check"], svg[data-icon*="check"], [aria-label*="completed" i]');
                        const hasSpin  = !!el.querySelector('svg[class*="spin"], svg[class*="loader"], [class*="animate-spin"], [aria-busy="true"]');
                        const verbHit  = VERB2.test(t);
                        const key = t.slice(0, 80);
                        if (panelSeen.has(key)) continue;
                        panelSeen.add(key);
                        panelRows.push({ t: t.slice(0, 220), hasSpin, hasCheck, verbHit });
                        if (hasSpin && !panelLive) panelLive = t.slice(0, 160);
                    }
                }
                if (panelRows.length > 0) {
                    r.panel_open = true;
                    const panelSteps = panelRows.map(x => x.t).slice(-15);
                    r.steps = panelSteps.concat(r.steps);
                    if (panelLive) r.progress = panelLive;
                    else {
                        const verbLive = panelRows.find(x => x.verbHit && !x.hasCheck);
                        r.progress = verbLive ? verbLive.t.slice(0, 160)
                                              : panelRows[panelRows.length - 1].t.slice(0, 160);
                    }
                }
            } catch(e) {}

            // ---- Steps: synthesize from tool_uses + live markers + sources
            if (r.thinking) r.steps.push('Extended Thinking: ' + r.thinking.substring(0, 100));
            r.tool_uses.slice(-5).forEach(t => {
                const brief = t.substring(0, 120);
                r.steps.push(brief.toLowerCase().includes('earch') ? 'Searching: ' + brief : brief);
            });
            if (liveSrcCount > 0) r.steps.push(`Gathering sources (${liveSrcCount} and counting)`);
            const cHosts = new Set();
            r.source_urls.forEach(u => { try { cHosts.add(new URL(u).hostname.replace('www.', '')); } catch(e) {} });
            Array.from(cHosts).slice(0, 5).forEach(h => r.steps.push('Browsing ' + h));
            if (r.sections.length > 0) r.steps.push('Building: ' + r.sections[r.sections.length - 1]);
            if (r.partial_text_len > 3000) r.steps.push('Artifact: ' + Math.round(r.partial_text_len / 1000) + 'k chars');
            if (researchDone) r.steps.push('Research completed');

            if (r.tool_uses.length > 0) r.progress = r.tool_uses[r.tool_uses.length - 1].substring(0, 200);
            else if (r.steps.length > 0) r.progress = r.steps[r.steps.length - 1];
            else if (liveSrcCount > 0) r.progress = `${liveSrcCount} sources and counting`;

            // Plan
            if (r.sections.length >= 2) r.plan = 'Research structure: ' + r.sections.slice(0, 5).join(' \\u2192 ');

            // ---- Status resolution (multi-strategy)
            // 1. "Stop research" / "Stop" button — primary active signal
            let hasStop = false;
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const txt = (b.textContent || '').trim().toLowerCase();
                const al  = (b.getAttribute('aria-label') || '').toLowerCase();
                if (txt === 'stop' || txt === 'stop generating' || txt === 'stop research' ||
                    txt === 'stop researching' ||
                    al.includes('stop response') || al.includes('stop research') ||
                    al.includes('stop generating')) { hasStop = true; break; }
            }
            // 2. Streaming DOM markers
            if (!hasStop && document.querySelector('[data-is-streaming="true"], .streaming, [class*="animate-pulse"]')) hasStop = true;
            // 3. "sources and counting" → still gathering (active)
            if (!hasStop && liveSrcCount > 0) hasStop = true;
            // 4. Body keyword sweep for active research verbs
            if (!hasStop) {
                const activeKws = ['searching the web', 'analyzing sources', 'reading sources',
                                   'browsing', 'conducting research', 'gathering information'];
                if (activeKws.some(kw => bodyLower.includes(kw))) hasStop = true;
            }

            // Resolve status — completion text trumps stale "active" signals
            if (researchDone && !hasStop) {
                r.status = 'complete'; r.phase = 'done';
            } else if (hasStop) {
                r.status = 'generating';
                r.phase = r.thinking ? 'thinking' : (r.tool_uses.length > 0 || liveSrcCount > 0 ? 'researching' : 'generating');
            } else if (r.partial_text_len > 0 || r.sources > 0) {
                r.status = 'complete'; r.phase = 'done';
            } else {
                r.status = 'idle'; r.phase = 'waiting';
            }
            return r;
        }""")
    except Exception as e:
        log(f"Claude scrape failed (selectors may need update): {e}", "WARN")
        return {"status": "scrape_error", "progress": "Selector mismatch — Claude UI may have changed", "sources": 0, "partial_text_len": 0}


SCRAPE_FNS = {
    "ChatGPT": scrape_progress_chatgpt,
    "Gemini": scrape_progress_gemini,
    "Claude": scrape_progress_claude,
    "Phase1": scrape_progress_chatgpt,  # Phase 1 runs on ChatGPT
}


# ── Per-Agent Completion Detectors (Playwright-only) ──────────────────────────
# Atomic single-shot detectors for the round-robin loop. Each returns
# (done: bool, reason: str). Reason is a short string for logging/telemetry.
# The caller tracks "2 consecutive polls" semantics where required — detectors
# just report the current signal snapshot from a single poll.
#
# Rules (locked 2026-04 with Phase 2 orchestration overhaul):
#   ChatGPT: no Stop (host + iframe) AND ("Research completed" text OR partial>5000)
#   Claude : no Stop/"sources and counting" AND
#            (artifacts>=2 OR done-text OR (partial>8000 AND summary/conclusion heading))
#   Gemini : no Start-research AND no Stop AND
#            (Share/Export visible OR (partial>5000 AND no active keywords))

async def detect_completion_chatgpt(page):
    """ChatGPT Deep Research completion detector. Playwright-only.
    Returns (done, reason, snap) where snap = {text_len, sources, steps}.

    2026-04-25 strictness rewrite: detector returns done=True ONLY when:
      • Stop button is gone (host AND iframe)
      • "Thought for X seconds" badge present (definitive done marker)
    The previous `partial_len > 5000` fallback was a known false-positive
    path (fired mid-stream during long research). Removed entirely. The
    caller is responsible for the 2-cycle flatness gate (text/sources/steps
    all flat across 2 polling cycles) before extracting — we only report
    the snapshot here, never decide on flatness."""
    try:
        host = await page.evaluate("""() => {
            let hasStop = !!document.querySelector(
                'button[aria-label="Stop generating"], button[aria-label*="Stop"], ' +
                'button[data-testid="stop-button"], button[data-testid*="stop"]'
            );
            if (!hasStop) {
                for (const b of document.querySelectorAll('button')) {
                    const t = (b.textContent || '').trim().toLowerCase();
                    if (t === 'stop' || t === 'stop generating' || t === 'stop research') {
                        hasStop = true; break;
                    }
                }
            }
            const bl = (document.body?.innerText || '');
            // "Thought for X seconds" badge — renders only AFTER thinking
            // phase completes. With Stop button gone + this badge present,
            // we're as confident as we can be that DR is fully settled.
            const thoughtFor = /thought for\\s+\\d/i.test(bl);
            // 2026-04-26 backup: same modern marker Claude uses. Covers the case
            // where ChatGPT renames the badge or runs a non-thinking-mode DR
            // variant where "Thought for X" never appears. Either signal counts.
            const researchDone = /research\\s+complete(?:d)?(?:[\\s·•—\\-]+\\d[\\d,]*\\s+sources?)?/i.test(bl);
            const doneMarker = thoughtFor || researchDone;
            const msgs = document.querySelectorAll('[data-message-author-role="assistant"]');
            const hostLen = msgs.length ? msgs[msgs.length-1].innerText.length : 0;
            // Sources count: external citation links anywhere on the page
            const sources = document.querySelectorAll('a[href^="http"][target="_blank"]').length;
            // Steps: research card list items (the rotating step list)
            const steps = document.querySelectorAll(
                '[class*="research"] li, [class*="step"], [class*="task"]'
            ).length;
            return { hasStop, thoughtFor, researchDone, doneMarker, hostLen, sources, steps };
        }""")

        iframe_stop = False
        iframe_thought = False
        iframe_len = 0
        iframe_sources = 0
        iframe_steps = 0
        try:
            for frame in page.frames:
                try:
                    src = (frame.url or "").lower()
                except Exception:
                    continue
                if not src:
                    continue
                if ("deep_research" in src or "oaiusercontent" in src):
                    try:
                        data = await frame.evaluate("""() => {
                            let hasStop = false;
                            for (const b of document.querySelectorAll('button')) {
                                const t = (b.textContent || '').trim().toLowerCase();
                                const al = (b.getAttribute('aria-label') || '').toLowerCase();
                                if (t === 'stop' || t === 'stop research' ||
                                    al.includes('stop')) { hasStop = true; break; }
                            }
                            const bl = (document.body?.innerText || '');
                            const thoughtFor = /thought for\\s+\\d/i.test(bl);
                            const researchDone = /research\\s+complete(?:d)?(?:[\\s·•—\\-]+\\d[\\d,]*\\s+sources?)?/i.test(bl);
                            const doneMarker = thoughtFor || researchDone;
                            const sources = document.querySelectorAll(
                                'a[href^="http"][target="_blank"]'
                            ).length;
                            const steps = document.querySelectorAll(
                                '[class*="research"] li, [class*="step"], [class*="task"]'
                            ).length;
                            return { hasStop, thoughtFor, researchDone, doneMarker, len: bl.length, sources, steps };
                        }""")
                        if data:
                            iframe_stop = bool(data.get("hasStop"))
                            iframe_thought = bool(data.get("doneMarker"))
                            iframe_len = int(data.get("len") or 0)
                            iframe_sources = int(data.get("sources") or 0)
                            iframe_steps = int(data.get("steps") or 0)
                    except Exception:
                        pass
                    break
        except Exception:
            pass

        has_stop = host["hasStop"] or iframe_stop
        # done_marker = ("Thought for X seconds" badge OR "Research complete · N sources" text).
        # Either is enough — non-thinking DR variants don't produce the badge,
        # and renamed-badge variants don't match /thought for \d+/.
        has_done_marker = bool(host.get("doneMarker")) or iframe_thought
        which_marker = ("thought_for" if host.get("thoughtFor") or iframe_thought
                        else "research_complete" if host.get("researchDone") else "")
        partial_len = max(int(host.get("hostLen") or 0), iframe_len)
        sources = max(int(host.get("sources") or 0), iframe_sources)
        steps = max(int(host.get("steps") or 0), iframe_steps)
        snap = {"text_len": partial_len, "sources": sources, "steps": steps}

        if has_stop:
            return (False, f"stop_btn_present (text={partial_len}, src={sources}, st={steps})", snap)
        if not has_done_marker:
            return (False, f"no_done_marker (Thought-for badge AND Research-complete text both missing)", snap)
        return (True, f"no_stop + done_marker={which_marker}", snap)
    except Exception as e:
        return (False, f"detect_error: {e}", {})


async def detect_completion_claude(page):
    """Claude Research completion detector. Playwright-only.
    Returns (done, reason, snap) where snap = {text_len, sources, steps}.

    2026-04-25 strictness rewrite: detector returns done=True ONLY when:
      • Stop button gone + no live "sources and counting" indicator
      • "research completed" text present OR research-card status='complete'
    Removed: artifacts>=2 fallback (Claude legitimately produces 2 artifacts
    pre-final), text_len>8000+heading fallback (mid-stream summary headings
    can match). Caller handles 2-cycle flatness."""
    try:
        data = await page.evaluate("""() => {
            let hasStop = false;
            for (const b of document.querySelectorAll('button')) {
                const txt = (b.textContent || '').trim().toLowerCase();
                const al  = (b.getAttribute('aria-label') || '').toLowerCase();
                if (txt === 'stop' || txt === 'stop generating' || txt === 'stop research' ||
                    txt === 'stop researching' ||
                    al.includes('stop response') || al.includes('stop research') ||
                    al.includes('stop generating')) { hasStop = true; break; }
            }
            if (!hasStop && document.querySelector(
                '[data-is-streaming="true"], .streaming, [class*="animate-pulse"]'
            )) hasStop = true;

            const bodyText = document.body?.innerText || '';
            // 2026-04-26: regex matches BOTH "research completed in 5m"
            // (legacy) AND "Research complete · 553 sources · 24m 41s" (modern
            // 2026 layout). 2026-05-04: also "Boom! Research report is ready"
            // — Claude's 2026-05+ ready callout for long DR runs (the artifact
            // card title alone, "<Title> · N sources · Xh Ym", is matched by
            // the scoped fallback below to avoid mid-stream false positives).
            const researchDone = /research\\s+complete(?:d)?(?:\\s+in)?(?:[\\s·•—\\-]+\\d[\\d,]*\\s+sources?)?(?:[\\s·•—\\-]+\\d+(?:[hms]|\\s*(?:hour|min|sec)))?/i.test(bodyText)
                              || /\\bBoom!\\s+(?:Your\\s+)?[Rr]esearch\\s+report\\s+is\\s+ready\\b/.test(bodyText);
            const liveActive = /\\d[\\d,]*\\s+sources?\\s+and\\s+counting/i.test(bodyText);
            // Claude's research card flips status when streaming ends.
            // 2026-04-26: also accept TEXT-CONTENT match — Claude's modern
            // layout doesn't use [data-research-status]; the artifact card
            // shows "Research complete · N sources · Xm Ys" as visible text.
            let researchCardDone = !!document.querySelector(
                '[data-research-status="complete"], [data-research-state="done"]'
            );
            if (!researchCardDone) {
                researchCardDone = !!Array.from(
                    document.querySelectorAll('[class*="card"], [class*="artifact"], button, div[role="button"]')
                ).find(el => /research\\s+complete(?:d)?\\s*[\\s·•—\\-]/i.test(el.textContent || ''));
            }
            // 2026-05-04: Claude's 2026-05+ artifact card drops the "complete"
            // prefix and shows just "<Title> · N sources · Xh Ym". Body-text
            // matching that pattern is too greedy (mid-stream pages can render
            // separate elapsed-timer + source-count elements that look the
            // same when flattened to innerText). Scope to artifact/aside
            // containers — those only render this title post-completion.
            if (!researchCardDone) {
                researchCardDone = !!Array.from(document.querySelectorAll(
                    '.font-claude-message [class*="artifact"], aside [class*="artifact"], aside [class*="card"]'
                )).find(el => /[\\s·•—\\-]+\\d[\\d,]*\\s+sources?\\s*[\\s·•—\\-]+\\d+\\s*[hms]/i.test(el.innerText || ''));
            }

            let textLen = 0;
            const msgs = document.querySelectorAll('.font-claude-message, .contents .prose');
            if (msgs.length > 0) textLen = msgs[msgs.length-1].innerText.length;
            const artifact = document.querySelector(
                'aside .prose, aside [class*="content"], [class*="artifact-panel"] .prose'
            );
            if (artifact) textLen = Math.max(textLen, artifact.innerText.length);
            const researchCard = document.querySelector(
                '[class*="research-card"], [data-testid*="research"], [class*="research-report"]'
            );
            if (researchCard) textLen = Math.max(textLen, (researchCard.innerText || '').length);

            const sources = document.querySelectorAll(
                '.font-claude-message a[href^="http"], aside a[href^="http"]'
            ).length;
            const steps = document.querySelectorAll(
                '[class*="research"] li, [class*="step"]'
            ).length;
            return { hasStop, researchDone, researchCardDone, liveActive,
                     textLen, sources, steps };
        }""")

        text_len = int(data.get("textLen") or 0)
        sources = int(data.get("sources") or 0)
        steps = int(data.get("steps") or 0)
        snap = {"text_len": text_len, "sources": sources, "steps": steps}

        if data.get("liveActive"):
            return (False, f"live_sources_counting", snap)
        if data.get("hasStop"):
            return (False, f"stop_btn_present (text={text_len})", snap)
        if not (data.get("researchDone") or data.get("researchCardDone")):
            return (False, f"no_done_marker (no research_complete text/card)", snap)
        return (True, f"no_stop + research_complete_marker", snap)
    except Exception as e:
        return (False, f"detect_error: {e}", {})


async def detect_completion_gemini(page):
    """Gemini Deep Research completion detector. Playwright-only.
    Returns (done, reason, snap) where snap = {text_len, sources, steps}.

    2026-04-25 strictness rewrite: done=True ONLY when:
      • Stop button gone + Start-research button gone (post-planning)
      • Share & Export button visible (definitive done — only renders
        after research finishes)
    Removed: text_len>5000+!active_kw fallback (transient no-active-keyword
    windows mid-stream caused false positives). Caller handles 2-cycle flat."""
    try:
        data = await page.evaluate("""() => {
            let hasStop = false;
            const stopSels = 'button[aria-label="Stop"], button[aria-label*="stop"], ' +
                             'button[aria-label="Cancel"], button[title*="Stop"]';
            if (document.querySelector(stopSels)) hasStop = true;
            if (!hasStop) {
                for (const b of document.querySelectorAll('button')) {
                    const txt = (b.textContent || '').trim().toLowerCase();
                    if (txt === 'stop' || txt === 'stop generating' || txt === 'cancel') {
                        hasStop = true; break;
                    }
                }
            }
            if (!hasStop && document.querySelector(
                '[data-is-streaming="true"], .loading-indicator, .streaming'
            )) hasStop = true;

            let hasStartBtn = false;
            for (const b of document.querySelectorAll('button')) {
                const txt = (b.textContent || '').trim().toLowerCase();
                if (txt === 'start research' || txt.includes('start research')) {
                    hasStartBtn = true; break;
                }
            }

            let hasShareExport = false;
            const shareKws = ['share & export', 'share and export'];
            for (const b of document.querySelectorAll('button, [role="button"]')) {
                const txt = (b.textContent || '').trim().toLowerCase();
                const al  = (b.getAttribute('aria-label') || '').toLowerCase();
                if (shareKws.some(k => txt === k || al.includes(k))) {
                    hasShareExport = true; break;
                }
                if (txt === 'share' || txt === 'export' ||
                    al === 'share' || al === 'export') {
                    hasShareExport = true; break;
                }
            }

            let textLen = 0;
            const responses = document.querySelectorAll('message-content, .model-response-text');
            if (responses.length > 0) textLen = responses[responses.length-1].innerText.length;

            const sources = document.querySelectorAll(
                'message-content a[href^="http"]'
            ).length;
            const steps = document.querySelectorAll(
                '[class*="research-step"], [class*="thought"]'
            ).length;
            return { hasStop, hasStartBtn, hasShareExport, textLen, sources, steps };
        }""")

        text_len = int(data.get("textLen") or 0)
        sources = int(data.get("sources") or 0)
        steps = int(data.get("steps") or 0)
        snap = {"text_len": text_len, "sources": sources, "steps": steps}

        if data.get("hasStartBtn"):
            return (False, "start_research_btn_visible (pre-research)", snap)
        if data.get("hasStop"):
            return (False, f"stop_btn_present (text={text_len})", snap)
        if not data.get("hasShareExport"):
            return (False, f"no_done_marker (Share/Export button missing)", snap)
        return (True, f"no_stop + share_export_visible", snap)
    except Exception as e:
        return (False, f"detect_error: {e}", {})


DETECT_FNS = {
    "ChatGPT": detect_completion_chatgpt,
    "Gemini":  detect_completion_gemini,
    "Claude":  detect_completion_claude,
}


# ── Claude Artifact DOM Helpers ──────────────────────────────────────────────

async def _count_claude_artifacts(page):
    """Count artifact preview cards in Claude conversation. Returns int.
    2026-04-26: extended selectors for the modern Research card layout —
    aria-label="Open the artifact", a[href*="/artifacts/"] direct links,
    role=button rounded card divs, plus a TEXT-content fallback that
    finds buttons whose text contains "Research complete" or starts with
    a research-card-style prefix (e.g. "OpenClaw and OpenShell research").
    2026-05-04: scope to assistant-message containers + strip user-message
    and attachment chips. Claude renders user-attached .md files (e.g.
    brief.md) as artifact-style preview cards inside the user-message
    bubble — same DOM shape as assistant artifacts — so the broad
    selectors would inflate the count by 1 and make _click_claude_artifact
    land on the brief instead of the assistant's report.
    """
    try:
        return await page.evaluate("""() => {
            const selectors = [
                'button[data-testid*="artifact"]',
                '[data-testid*="artifact-preview"]',
                '.artifact-card', '.artifact-preview',
                'button[data-artifact-id]',
                '[class*="artifact"][role="button"]',
                'button[aria-label*="Open the artifact"]',
                'button[aria-label*="research"]',
                'a[href*="/artifacts/"]',
                // 2026-05-13: dropped `div[role="button"][class*="rounded"][class*="border"]`
                // from both _count_claude_artifacts and _click_claude_artifact —
                // matched chat-row context-menu triggers in Run 1 (image:
                // Star/Rename/Add to project/Delete popup) and grabbed the
                // wrong target. The remaining selectors cover every artifact-
                // card variant we have logs for; this fallback was a
                // 2026-04-26 belt-and-suspenders that turned into a misclick
                // magnet. Must drop from BOTH locations so count + click agree.
            ];
            // 2026-05-12: self-strip helper. Flow B attached .md/.pdf/.docx
            // files render in Claude as preview cards with the same artifact-
            // card DOM shape (rounded div role=button) — the ancestor-based
            // attachment exclusion missed these when Claude didn't tag any
            // parent with attachment/file/upload markers. Match on the
            // element's own text + aria to catch them.
            const _fileExtRe = /\\.(?:md|pdf|docx?|txt|csv|json|html?|rtf|odt|markdown)\\b/i;
            const _looksLikeFile = (el) => {
                const t = (el.textContent || '').trim().toLowerCase();
                const a = (el.getAttribute('aria-label') || '').toLowerCase();
                if (_fileExtRe.test(t) || _fileExtRe.test(a)) return true;
                if (/^(open|view)\\s+(?:file|attachment|document)\\b/i.test(a)) return true;
                return false;
            };
            const isUserOrAttachment = (el) => !!el.closest(
                '[data-testid="user-message"], [data-message-author-role="user"], ' +
                '[data-testid*="attachment"], [data-testid*="file"], [class*="attachment" i], ' +
                '[class*="upload" i], [data-testid*="upload"], ' +
                '[class*="file-preview" i], [class*="file-card" i], ' +
                '[aria-label*="attachment" i], [aria-label*="file " i]'
            ) || _looksLikeFile(el);
            const isInAssistant = (el) => !!el.closest('.font-claude-message');
            let total = 0;
            // Pass 1: prefer matches inside assistant message scope.
            for (const sel of selectors) {
                const found = Array.from(document.querySelectorAll(sel))
                    .filter(el => isInAssistant(el) && !isUserOrAttachment(el));
                if (found.length > 0) { total = Math.max(total, found.length); }
            }
            // Pass 2: only run when assistant-scoped lookup returned nothing
            // (covers Claude UI variants without .font-claude-message
            // wrappers). Still strips user-message + attachment matches.
            if (total === 0) {
                for (const sel of selectors) {
                    const found = Array.from(document.querySelectorAll(sel))
                        .filter(el => !isUserOrAttachment(el));
                    if (found.length > 0) { total = Math.max(total, found.length); }
                }
            }
            // Text-content fallback: any clickable element matching the
            // legacy "Research complete · N sources · Xm Ys" marker OR the
            // 2026-05+ Boom! ready callout. Scope to .font-claude-message
            // and strip user/attachment matches.
            const textHits = Array.from(document.querySelectorAll(
                '.font-claude-message button, .font-claude-message [role="button"]'
            )).filter(el => !isUserOrAttachment(el))
              .filter(el => /research\\s+complete(?:d)?\\s*[\\s·•—\\-]/i.test(el.textContent || '')
                         || /\\bBoom!\\s+(?:Your\\s+)?[Rr]esearch\\s+report\\s+is\\s+ready\\b/.test(el.textContent || ''));
            total = Math.max(total, textHits.length);
            // Legacy fallback: document-like inline cards in assistant messages.
            if (total === 0) {
                const cards = Array.from(document.querySelectorAll(
                    '.font-claude-message button[class*="block"], ' +
                    '.font-claude-message [class*="artifact"], ' +
                    '[data-is-streaming] button[class*="w-full"]'
                )).filter(el => !isUserOrAttachment(el));
                total = cards.length;
            }
            return total;
        }""")
    except Exception as e:
        log(f"Artifact count failed: {e}", "WARN")
        return 0


async def _click_claude_artifact(page, index=0):
    """Click the Nth artifact card (0-indexed). Returns True if clicked.
    2026-04-26: same modernized selectors as _count_claude_artifacts.
    2026-05-04: same assistant-scope + user/attachment strip as
    _count_claude_artifacts so the brief.md attachment chip in the
    user-message bubble can't be the click target."""
    try:
        return await page.evaluate(f"""(idx) => {{
            const selectors = [
                'button[data-testid*="artifact"]',
                '[data-testid*="artifact-preview"]',
                '.artifact-card', '.artifact-preview',
                'button[data-artifact-id]',
                '[class*="artifact"][role="button"]',
                'button[aria-label*="Open the artifact"]',
                'button[aria-label*="research"]',
                'a[href*="/artifacts/"]',
                // 2026-05-13: dropped `div[role="button"][class*="rounded"][class*="border"]`
                // from both _count_claude_artifacts and _click_claude_artifact —
                // matched chat-row context-menu triggers in Run 1 (image:
                // Star/Rename/Add to project/Delete popup) and grabbed the
                // wrong target. The remaining selectors cover every artifact-
                // card variant we have logs for; this fallback was a
                // 2026-04-26 belt-and-suspenders that turned into a misclick
                // magnet. Must drop from BOTH locations so count + click agree.
            ];
            // 2026-05-12: self-strip helper for Flow B attached files.
            // See _count_claude_artifacts for full rationale. f-string
            // braces doubled (`{{`/`}}`) per the surrounding pattern.
            const _fileExtRe = /\\.(?:md|pdf|docx?|txt|csv|json|html?|rtf|odt|markdown)\\b/i;
            const _looksLikeFile = (el) => {{
                const t = (el.textContent || '').trim().toLowerCase();
                const a = (el.getAttribute('aria-label') || '').toLowerCase();
                if (_fileExtRe.test(t) || _fileExtRe.test(a)) return true;
                if (/^(open|view)\\s+(?:file|attachment|document)\\b/i.test(a)) return true;
                return false;
            }};
            const isUserOrAttachment = (el) => !!el.closest(
                '[data-testid="user-message"], [data-message-author-role="user"], ' +
                '[data-testid*="attachment"], [data-testid*="file"], [class*="attachment" i], ' +
                '[class*="upload" i], [data-testid*="upload"], ' +
                '[class*="file-preview" i], [class*="file-card" i], ' +
                '[aria-label*="attachment" i], [aria-label*="file " i]'
            ) || _looksLikeFile(el);
            const isInAssistant = (el) => !!el.closest('.font-claude-message');
            let cards = [];
            // Pass 1: prefer matches inside assistant message scope.
            for (const sel of selectors) {{
                const found = Array.from(document.querySelectorAll(sel))
                    .filter(el => isInAssistant(el) && !isUserOrAttachment(el));
                if (found.length > 0) {{ cards = found; break; }}
            }}
            // Pass 2: fallback to broad scan if assistant scope returned
            // nothing — still strips user-message + attachment matches.
            if (!cards.length) {{
                for (const sel of selectors) {{
                    const found = Array.from(document.querySelectorAll(sel))
                        .filter(el => !isUserOrAttachment(el));
                    if (found.length > 0) {{ cards = found; break; }}
                }}
            }}
            if (!cards.length) {{
                // Text-content fallback: legacy "Research complete · …" or
                // 2026-05+ Boom! marker. Scoped + user/attachment-stripped.
                const textHits = Array.from(document.querySelectorAll(
                    '.font-claude-message button, .font-claude-message [role="button"]'
                )).filter(el => !isUserOrAttachment(el))
                  .filter(el => /research\\s+complete(?:d)?\\s*[\\s·•—\\-]/i.test(el.textContent || '')
                             || /\\bBoom!\\s+(?:Your\\s+)?[Rr]esearch\\s+report\\s+is\\s+ready\\b/.test(el.textContent || ''));
                if (textHits.length > 0) cards = textHits;
            }}
            if (!cards.length) {{
                const fallback = Array.from(document.querySelectorAll(
                    '.font-claude-message button[class*="block"], ' +
                    '.font-claude-message [class*="artifact"]'
                )).filter(el => !isUserOrAttachment(el));
                cards = fallback;
            }}
            // 2026-04-26: visibility + dialog-modal filter — a publish/share
            // dialog left over from a prior turn can match the same selectors;
            // skip zero-bbox elements and anything inside [role="dialog"].
            cards = cards.filter(c => {{
                const r = c.getBoundingClientRect();
                if (r.width < 20 || r.height < 20) return false;
                if (c.closest('[role="dialog"], [aria-modal="true"]')) return false;
                return true;
            }});
            const targetIdx = idx < 0 ? cards.length + idx : idx;
            if (cards.length > 0 && targetIdx >= 0 && targetIdx < cards.length) {{
                cards[targetIdx].click();
                return true;
            }}
            return false;
        }}""", index)
    except Exception as e:
        log(f"Artifact click failed: {e}", "WARN")
        return False


def _claude_artifact_frame_targets(page):
    """Return frame targets worth scraping for Claude artifact content.

    Always starts with the main page. Appends any iframe whose URL is
    claude.ai / claude.site / about:blank (srcdoc-mounted sandboxes), plus
    any frame whose URL is empty/unknown — Claude has historically used
    blank-src iframes for some Document artifact variants and may again.

    Mirrors `_chatgpt_dr_frame_targets` (DGOPS-7366) but for Claude
    artifacts. Pre-fix, Run B 2026-05-12 had Claude Tier 2/3 both return
    empty while CUA later copied 127k chars — strong signal that the
    content was iframe-mounted and parent-document queries couldn't see
    it. This helper restores Tier 2/3 reach into the artifact iframe."""
    targets = [page]
    try:
        for frame in page.frames:
            try:
                src = (frame.url or "").lower()
            except Exception:
                continue
            if frame is page.main_frame:
                continue
            # Claude artifact iframe variants we've seen + the about:blank
            # srcdoc case (sandboxed inline HTML). The empty-URL case is a
            # belt-and-suspenders catch for any future scheme.
            if ("claude.ai" in src
                    or "claude.site" in src
                    or "anthropic" in src
                    or src.startswith("about:")
                    or src.startswith("blob:")
                    or src == ""):
                targets.append(frame)
    except Exception:
        pass
    return targets


_CLAUDE_PANEL_SELECTORS_JS = """[
    '[data-testid="artifact-content"]',
    '.artifact-content',
    '.artifact-panel .contents',
    // 2026-05-13: dropped `aside .prose`, `aside .markdown`,
    // `aside [contenteditable="true"]`, `aside .tiptap`,
    // `aside article`, `aside main` — bare-`aside` prefixes matched the
    // LEFT navigation <aside> on claude.ai (Run 1 returned 5906 chars of
    // "New chat / Search / Chats / Projects / Recents" nav text). The
    // artifact panel uses [class*="artifact-panel"] / similar markers, NOT
    // <aside>. Right-pane positioning is enforced at the panel-candidate
    // gate below; here we just list the artifact-class-anchored selectors.
    '[class*="artifact-panel"] .prose',
    '[class*="artifact-panel"] .markdown',
    '[class*="artifact-panel"] [contenteditable="true"]',
    '[class*="artifact-panel"] .tiptap',
    '[class*="artifact-panel"] article',
    '[class*="artifact-panel"] main',
    '[class*="artifact-panel"] [class*="content"]',
    '[class*="artifact"] .ProseMirror',
    '[class*="artifact"] [class*="rendered"]',
    '.markdown-body',
    '.prose-message',
    // iframe-side (when target is a Claude artifact frame): the
    // artifact body mounts directly on common containers.
    'main',
    'article',
    'body > div > article',
    'body main',
    '#root main',
    '#root article',
]"""


async def _read_claude_artifact_panel(page):
    """Read content from the currently open artifact panel (right side).

    Returns clean markdown when possible (innerHTML → markdownify) so the
    saved Claude report keeps its headings, lists, bold/italic, code blocks,
    and links. Falls back to innerText only when HTML extraction fails — the
    fallback flattens markdown structure to plain text, so a sentinel log is
    emitted to make the degradation visible (the FE would otherwise render
    a wall-of-text and we'd never know which extraction path produced it).

    2026-05-13 (DGOPS-7367 advisor): iframe-aware + retry-on-empty. Pre-fix,
    this function read only `document` and gave up on first miss. Run B
    2026-05-12 had Claude content reachable to CUA's pixel-level Ctrl+A but
    invisible to `document.querySelector` — almost certainly iframe-mounted.
    Now walks `_claude_artifact_frame_targets` for innerHTML across page +
    iframes, and retries once after 1.5s on the first empty pass to cover
    slow mounts. Falls through to innerText only after both passes miss.
    """
    targets = _claude_artifact_frame_targets(page)
    panel_selectors_arg = _CLAUDE_PANEL_SELECTORS_JS

    # 2026-05-13: shared right-pane position-gated panel finder. Run 1
    # had this function return 5906 chars of LEFT-nav text because the
    # old fallback `aside, [class*="side-panel"], [class*="right-panel"]`
    # matched claude.ai's navigation <aside>. The replacement requires
    # (a) wider than 400px, (b) right edge past viewport-center, (c)
    # innerText doesn't look like nav chrome (no "New chat / Recents /
    # Topic Generator" markers in the first 500 chars).
    _PANEL_GATE_JS = r"""
        const NAV_MARKERS = /\b(new chat|recents?|projects|search|topic generator|starred|home|chats?\b)\b/i;
        const _vw = window.innerWidth || document.documentElement.clientWidth;
        const _candidates = Array.from(document.querySelectorAll(
            '[class*="artifact-panel"], ' +
            '[data-testid*="artifact-panel"], ' +
            '[role="complementary"][class*="artifact" i], ' +
            '[class*="right-panel"][class*="artifact" i], ' +
            '[class*="side-panel"][class*="artifact" i], ' +
            'div[class*="artifact"][class*="open" i]'
        ));
        function _isLikelyPanel(el) {
            const r = el.getBoundingClientRect();
            if (r.width < 400) return false;
            if (r.right < _vw * 0.5) return false;
            const head = (el.innerText || '').slice(0, 500);
            if (NAV_MARKERS.test(head)) {
                let _matches = 0;
                const re = new RegExp(NAV_MARKERS.source, 'gi');
                while (re.exec(head) !== null) _matches++;
                if (_matches >= 2) return false;
            }
            return true;
        }
    """

    async def _try_html(target):
        try:
            return await target.evaluate(f"""() => {{
                {_PANEL_GATE_JS}
                const panelSelectors = {panel_selectors_arg};
                for (const sel of panelSelectors) {{
                    let el;
                    try {{ el = document.querySelector(sel); }} catch (e) {{ continue; }}
                    if (el && el.innerText.length > 50) return el.innerHTML;
                }}
                // Right-pane-positioned fallback — only matches if a real
                // artifact panel is on the right half of the viewport AND
                // doesn't read like nav-chrome. Bare-`aside` fallback was
                // removed 2026-05-13.
                for (const el of _candidates) {{
                    if (_isLikelyPanel(el) && el.innerText.length > 200) return el.innerHTML;
                }}
                return '';
            }}""")
        except Exception:
            return ""

    async def _try_text(target):
        try:
            return await target.evaluate(f"""() => {{
                {_PANEL_GATE_JS}
                const panelSelectors = {panel_selectors_arg};
                for (const sel of panelSelectors) {{
                    let el;
                    try {{ el = document.querySelector(sel); }} catch (e) {{ continue; }}
                    if (el && el.innerText.length > 50) return el.innerText;
                }}
                for (const el of _candidates) {{
                    if (_isLikelyPanel(el) && el.innerText.length > 200) return el.innerText;
                }}
                return '';
            }}""")
        except Exception:
            return ""

    try:
        # Pass 1 — HTML across all targets.
        for target in targets:
            html_blob = await _try_html(target)
            if html_blob and len(html_blob) > 200:
                md = html_to_markdown(html_blob)
                if md and len(md) > 100:
                    return md
        # Pass 2 — wait 1.5s then HTML retry. Covers slow artifact mounts
        # where the wait_for_selector at the extractor entry timed out
        # against a narrower selector than what we query here.
        await asyncio.sleep(1.5)
        for target in targets:
            html_blob = await _try_html(target)
            if html_blob and len(html_blob) > 200:
                md = html_to_markdown(html_blob)
                if md and len(md) > 100:
                    return md
        # Pass 3 — innerText fallback (preserves prior behavior). Markdown
        # structure is lost here — log a sentinel so the operator knows
        # the saved doc is plain text rather than properly formatted MD.
        for target in targets:
            text = await _try_text(target)
            if text:
                log("[Claude] Artifact panel innerText fallback fired — markdown "
                    "structure lost. Saved doc will render as plain text.", "WARN")
                return text
        return ""
    except Exception as e:
        log(f"Artifact panel read failed: {e}", "WARN")
        return ""


async def _extract_claude_via_published_page(page, browser, cua_client, label, verbose=False):
    """Claude T2 (2026-05-13 enhancement): publish the artifact, open
    the resulting claude.site URL in a new tab, HTML→MD scrape from the
    clean full-page DOM, close the tab.

    Why this beats every other in-chat path: the published page renders
    JUST the report — no left-nav, no chat history, no artifact-panel
    chrome, no iframe sandbox, no React component slots competing for
    DOM space. Most drift-resistant scrape surface Claude offers.

    Idempotency: publish_open_claude_artifact is idempotent for already-
    published artifacts (clicking Publish on a published artifact just
    retrieves the existing URL). The orchestrator's separate publish-
    for-link-metadata call downstream stays safe — it'll find the
    already-published state and return the same URL.

    Failure modes (each falls through to ""):
    - Publish path fails (CUA loop exhausted, no Publish button) →
      no URL → tier skipped silently
    - new_page() / goto() raises → tab cleanup in finally
    - Scrape returns empty → falls through to Tier 3 (Copy hijack)

    Returns markdown or "" on any failure. Caller decides whether to
    accept it (length + junk gates).
    """
    if not browser:
        return ""
    try:
        # Step 1: publish + grab the public URL. Reuses the existing
        # helper so we don't duplicate publish DOM/CUA logic.
        published_url = await publish_open_claude_artifact(
            page, browser, cua_client, verbose=verbose,
        )
        if not published_url or "claude.site" not in published_url.lower():
            log(f"[{label}] T2 publish didn't produce claude.site URL — fall through to Tier 3", "DEBUG")
            return ""
        log(f"[{label}] T2 published-page: navigating new tab to {published_url[:80]}")

        # Step 2: open new tab, navigate, scrape. New tab keeps the
        # main page state untouched so subsequent tiers (or the
        # orchestrator's publish-for-link call) don't have to navigate
        # back.
        new_page = None
        try:
            new_page = await browser.context.new_page()
            await new_page.goto(published_url, wait_until="domcontentloaded", timeout=20000)
            # Claude's published page hydrates client-side — 2.5s settle.
            await asyncio.sleep(2.5)
            # Step 3: HTML→MD on the clean DOM. The published page mounts
            # the report directly in <article> / <main> with no chrome,
            # so the selector list is short and robust.
            md = await _extract_html_to_md(new_page, [
                'article',
                'main article',
                'main',
                '[class*="artifact"] [class*="content"]',
                '[class*="content"] article',
                '.prose',
                '.markdown',
                'body main',
                'body article',
            ], label)
            return md or ""
        finally:
            if new_page is not None:
                try:
                    await new_page.close()
                except Exception:
                    pass
    except Exception as e:
        log(f"[{label}] T2 published-page extraction failed: {e}", "WARN")
        return ""


def _looks_like_nav_sidebar(text: str) -> bool:
    """Reject heuristic for extraction returning navigation-sidebar text
    (e.g. claude.ai's left nav: New chat / Search / Chats / Projects /
    Recents / Topic Generator…). Run 1 (2026-05-12 chat_1778684431400_1)
    had `_read_claude_artifact_panel` fall back to a bare-`<aside>`
    selector that matched the left nav and returned 5906 chars of
    `New chat\\nSearch\\nChats\\nProjects\\nRecents\\nTopic Generator…`
    text — passed all downstream guards because it had no checklist /
    sources / wrong-artifact markers. This guard catches that shape.

    Heuristics (must trip ALL to be considered nav):
      - >=3 distinct nav markers in the first 500 chars
      - <3 prose paragraphs (lines >100 chars)
      - Total length < 8000 chars
    """
    if not text:
        return False
    head = text[:500]
    nav_markers_re = re.compile(
        r'\b(new\s+chat|recents?|projects|search|topic\s+generator|starred|chats?\b)\b',
        re.IGNORECASE,
    )
    nav_hits = set(m.group(0).lower() for m in nav_markers_re.finditer(head))
    if len(nav_hits) < 3:
        return False
    # Count prose paragraphs in full body (lines or blocks of >100 chars).
    long_lines = sum(1 for ln in text.split('\n') if len(ln.strip()) > 100)
    if long_lines >= 3:
        return False
    if len(text) >= 8000:
        return False
    return True


def _is_sources_not_document(text, *, platform="generic"):
    """Strict invariant guard for Phase 2 finalize extraction:
    extract_*_response must return the DOCUMENT (final report markdown),
    NEVER the SOURCES tracking checklist or right-side source-panel URL list.
    Errs toward LETTING DOCUMENTS THROUGH — a wrongly rejected report would
    force a retry on a correct extract.

    Heuristics (a doc passes if prose check holds; a source artifact must
    trip checklist OR url-list signals AND lack prose):
      STRONG-DOC    : >=4000 chars AND >=2 headings AND any paragraph
                      >=200 chars  → False (always accept long prose docs)
      DOC POSITIVE  : >=3 markdown headings AND >=5 paragraphs >100 chars
      MODERN MARKER : "Research complete · N sources" in text AND >=2
                      headings → False (Claude's 1-artifact layout)
      CHECKLIST NEG : >=4 [x]/[ ] OR >=4 "Reading source N" lines AND
                      heading count <2 AND length < 5000 AND
                      checkbox/total-lines ratio > 15% → True
      URL-LIST NEG  : >=8 numbered-URL/bare-hostname lines AND headings <2
                      AND length 800-3000

    A1 (2026-05-01): added STRONG-DOC override + MODERN MARKER sentinel +
    checklist-ratio gate. Final research reports may include a methodology
    section with a few checkboxes; the old length-only rejection rule
    (len<5000 + checkbox>=4 + headings<2) could mis-fire on dense reports
    that happened to land below 5000 chars during a partial render. The
    new ratio gate blocks rejection unless checkboxes dominate the body.
    """
    if not text or len(text) < 200:
        return False
    # CHAT-TRANSCRIPT NEG (2026-05-02): chat-transcript meta-summary
    # artifacts (e.g. "Claude Deep Research" tile with body containing
    # "You said: …" / "Claude responded: …") would otherwise pass the
    # STRONG-DOC override below — they have prose + headings but are
    # fundamentally a recorded conversation, not the report. Reject when
    # ≥2 chat-chrome lines are present anywhere.
    chat_chrome_lines = sum(
        1 for _l in text.splitlines()
        if re.match(r'^\s*(?:you|chatgpt|gemini|claude|notebooklm|gpt)\s+(?:said|responded)\b',
                    _l, re.I)
    )
    if chat_chrome_lines >= 2:
        return True
    headings = len(re.findall(r'(?m)^#{1,3}\s+\S', text))
    paragraphs = [p for p in text.split('\n\n') if len(p) > 100]
    # STRONG-DOC: clearly long-form prose with at least minimal structure.
    if len(text) >= 4000 and headings >= 2 and any(len(p) >= 200 for p in paragraphs):
        return False
    if headings >= 3 and len(paragraphs) >= 5:
        return False
    # MODERN MARKER: Claude's 1-artifact "Research complete · N sources"
    # layout — if the marker is present alongside any meaningful structure,
    # the artifact is definitely the final report (the tracking checklist
    # never carries this exact marker phrase).
    if re.search(r'research\s+complete(?:d)?\s*[·•—\-\s]+\d[\d,]*\s+sources?', text, re.I) \
            and headings >= 2:
        return False
    checkbox_lines = len(re.findall(r'(?m)^\s*[-*]?\s*\[[ xX]\]\s+\S', text))
    reading_lines = len(re.findall(
        r'(?im)^\s*(?:reading|checking|analyzing|searching)\s+(?:source\s+)?\d+', text))
    total_nonempty = max(1, len([l for l in text.splitlines() if l.strip()]))
    checklist_ratio = checkbox_lines / total_nonempty
    if (checkbox_lines >= 4 or reading_lines >= 4) and headings < 2 and len(text) < 5000 \
            and (checkbox_lines < 4 or checklist_ratio > 0.15 or reading_lines >= 4):
        return True
    lines = [l.strip() for l in text.splitlines() if l.strip()]
    url_only = sum(
        1 for l in lines
        if re.match(r'^\d+[\.\)]?\s*(?:https?://|[a-z0-9.-]+\.[a-z]{2,}/)', l, re.I))
    if url_only >= 8 and headings < 2 and 800 <= len(text) <= 3000:
        return True
    return False


def _strip_gemini_panel_noise(md: str) -> str:
    """Trim Gemini's research-panel chrome + post-report noise from the
    raw HTML→MD (T2) or select-all (T3) extraction.

    Gemini's `<immersive-panel>` legitimately contains, after the formal
    report body, a "Sources used in the report" section followed by
    hundreds of citation chips interleaved with Gemini's own thinking-
    trace narration ("Researching websites…", planning-header runs
    without `##` markers). All of that lives inside the same DOM scope
    our selectors match — tighter selectors can't exclude it, strip
    after the html2text pass instead.

    Strips:
      1. Leading toolbar chrome (`Contents` / `Share & Export` / `Create`)
         that Gemini's app shell renders inside the panel root.
      2. Everything at and after `Sources used in the report` — the
         marker is Gemini's UI label, never an author-written heading;
         additionally require a URL-shaped token within ~200 chars
         after the marker to guard against a hypothetical user-prompt
         phrasing collision.
      3. Collapses runs of 3+ blank lines left by the strips.

    Idempotent — safe to call twice."""
    if not md:
        return md
    # Toolbar chrome. Gemini renders this as a single line
    # "ContentsShare & Export" (no separator between the section
    # heading text and the menu label after html_to_markdown collapses
    # the nested elements) followed by "Create" on its own line. Both
    # sit near the top of the panel but AFTER the Gemini Deep Research
    # header + prompt-echo, so MULTILINE not start-anchored.
    md = re.sub(
        r'(?m)^\s*ContentsShare & Export\s*$\n+\s*Create\s*$\n+',
        '',
        md,
    )
    # Strip from "Sources used in the report" to EOF iff a URL appears
    # in the next ~200 chars (confirms Gemini citation panel, not a
    # collision with author phrasing).
    m = re.search(r'^\s*Sources used in the report\s*$', md, re.MULTILINE)
    if m:
        lookahead = md[m.end(): m.end() + 200]
        if re.search(r'https?://', lookahead):
            md = md[:m.start()].rstrip()
    # Collapse 3+ blank lines (the strips can leave awkward gaps).
    md = re.sub(r'\n{3,}', '\n\n', md)
    return md


async def _close_claude_artifact_panel(page):
    """Close the artifact panel by pressing Escape or clicking close."""
    try:
        # Try Escape first (most reliable)
        await page.keyboard.press("Escape")
        await asyncio.sleep(0.3)
        # Verify panel closed by checking if aside/panel shrank
        still_open = await page.evaluate("""() => {
            const panel = document.querySelector('aside, [class*="artifact-panel"], [class*="side-panel"]');
            return panel && panel.offsetWidth > 100;
        }""")
        if still_open:
            # Try clicking close button
            await page.evaluate("""() => {
                const close = document.querySelector(
                    'aside button[aria-label="Close"], ' +
                    '[class*="artifact-panel"] button[aria-label="Close"], ' +
                    'aside button:has(svg[class*="close"]), ' +
                    'button[data-testid="close-artifact"]'
                );
                if (close) close.click();
            }""")
    except Exception:
        pass


async def scrape_claude_artifact_tracking(page, browser=None, cua_client=None,
                                          verbose=False, keep_open=False,
                                          already_open=False):
    """Scrape Claude's FIRST artifact for tracking/progress data during active research.
    DOM-first with CUA fallback. Returns enriched progress dict or None.
    keep_open=True: don't close the panel after read (re-used across polls).
    already_open=True: skip the click step (panel already open from prior poll)."""
    artifact_count = await _count_claude_artifacts(page)
    if artifact_count == 0:
        return None

    content = ""
    walker = {"steps": [], "sections": [], "source_urls": []}

    # Layer 1: DOM probe — open panel (if not already), read panel + DOM walker
    try:
        if not already_open:
            clicked = await _click_claude_artifact(page, index=0)
            if clicked:
                await asyncio.sleep(1.5)  # Wait for panel to render
        content = await _read_claude_artifact_panel(page)
        # Structured DOM walker — cheaper + more accurate than regex on plain text.
        # Reads the live artifact's checklist headings + section list + URL anchors
        # so steps[]/sections[]/source_urls[] reflect Claude's running outline.
        try:
            walker = await page.evaluate("""() => {
                const out = { steps: [], sections: [], source_urls: [] };
                const root = document.querySelector(
                    '[data-testid="artifact-content"], aside, [class*="artifact-panel"]'
                ) || document;
                root.querySelectorAll(
                    'li, [role="listitem"], [class*="step"], [class*="checklist"] > div, ' +
                    '[class*="task"] > div, [class*="activity"]'
                ).forEach(e => {
                    const t = (e.innerText || '').trim();
                    if (t && t.length > 4 && t.length < 240) out.steps.push(t.slice(0, 220));
                });
                root.querySelectorAll('h1, h2, h3').forEach(h => {
                    const t = (h.innerText || '').trim();
                    if (t && t.length > 1 && t.length < 120) out.sections.push(t);
                });
                const seen = new Set();
                root.querySelectorAll('a[href^="http"]').forEach(a => {
                    const h = a.href || '';
                    if (h && h.length < 500 && !h.includes('claude.ai') &&
                        !h.includes('anthropic.com') && !seen.has(h)) {
                        seen.add(h); out.source_urls.push(h);
                    }
                });
                out.steps = out.steps.slice(-15);
                out.sections = out.sections.slice(0, 20);
                out.source_urls = out.source_urls.slice(0, 50);
                return out;
            }""")
        except Exception as _we:
            log(f"[Claude] artifact DOM walker skipped: {_we}", "DEBUG")
        if not keep_open:
            await _close_claude_artifact_panel(page)
    except Exception as e:
        log(f"[Claude] Artifact DOM tracking failed: {e}", "WARN")

    # Layer 2: CUA fallback if DOM yielded nothing
    if not content and not walker.get("source_urls") and browser and cua_client:
        try:
            result = await agent_loop(cua_client, browser,
                PROMPT_SCRAPE_CLAUDE_ARTIFACT_TRACKING,
                "Open the first artifact in the conversation and read its content. "
                "Report URLs, steps, sections, and sources found. Then close the artifact panel.",
                model=CUA_MODEL, max_iterations=6, verbose=verbose)
            content = result.get("text", "")
        except Exception as e:
            log(f"[Claude] Artifact CUA tracking failed: {e}", "WARN")

    # Lowered gate: 5 chars (was 30) — accept partials. Walker URLs alone count.
    if (not content or len(content) < 5) and not walker.get("source_urls"):
        return None

    # Prefer DOM-walker output; fall back to regex on plain text only when walker empty.
    urls = walker["source_urls"] or list(dict.fromkeys(re.findall(r'https?://[^\s)>\]"]+', content or "")))[:50]
    steps = walker["steps"] or re.findall(r'(?:^|\n)\s*(?:\d+[\.\)]\s*|[-•]\s+)(.{10,200})', content or "")
    sections = walker["sections"] or re.findall(r'(?:^|\n)#{1,3}\s+(.{3,80})', content or "")
    if not sections:
        sections = re.findall(r'(?:^|\n)([A-Z][A-Z\s&]{5,60})(?:\n|$)', content or "")

    domains = set()
    for u in urls:
        try:
            from urllib.parse import urlparse
            domains.add(urlparse(u).netloc)
        except Exception:
            pass

    return {
        "status": "generating",
        "phase": "researching",
        "progress": (steps[-1] if steps else f"Tracking {len(urls)} sources from artifact"),
        "sources": max(len(domains), len(urls)),
        "source_urls": urls[:50],
        "sections": sections[:15],
        "steps": steps[:15],
        "tool_uses": [f"Analyzing: {s[:80]}" for s in sections[:5]],
        "partial_text_len": len(content or ""),
        "artifact_tracking": True,
        "artifact_count": artifact_count,
    }


async def scrape_chatgpt_activity_panel_tracking(page):
    """Walk ChatGPT Deep Research's *open* activity side panel for live
    progress data — steps checklist, section headings, source URLs,
    aggregate search count.

    Mirrors `scrape_claude_artifact_tracking` (Claude's gold-standard
    rich-narration path). The panel must already be open — caller is
    responsible for invoking `_open_chatgpt_activity_panel` first and
    keeping it open across polls (`chatgpt_activity_panel_open` flag).

    DOM-only: no CUA fallback. Reading from an already-mounted panel is a
    cheap structural walk; if DOM yields nothing the caller can fall
    through to vision narration (which already runs alongside this in the
    round-robin loop). Returns None when the panel isn't mounted /
    mounted-but-empty so the caller can skip merging.

    Returns dict with keys:
        steps, sections, source_urls, searches, partial_text_len, progress
    """
    JS = """() => {
        const out = {
            steps: [], sections: [], source_urls: [],
            searches: 0, partial_text_len: 0, progress: ""
        };
        // Panel root — ChatGPT renders the side panel as <aside> /
        // [role="complementary"] / [aria-label~=source] in the DR
        // sandbox iframe OR host page (post-2025 redesign). Match either.
        // Width gate prevents matching narrow chrome (sidebar nav, etc.).
        const PANEL_SELS = [
            'aside', '[role="complementary"]', '[role="region"]',
            '[aria-label*="source" i]', '[aria-label*="activity" i]',
            '[aria-label*="research" i]',
            '[class*="panel" i][class*="side" i]'
        ].join(', ');
        const panels = Array.from(document.querySelectorAll(PANEL_SELS))
            .filter(el => {
                const r = el.getBoundingClientRect();
                return r.width >= 280 && r.height >= 200 &&
                       r.right > window.innerWidth * 0.45;
            });
        if (panels.length === 0) return out;
        // Prefer the rightmost-and-tallest — ChatGPT mounts a single
        // dominant side panel; smaller candidates are usually unrelated
        // chrome that happens to match the selector.
        panels.sort((a, b) => {
            const ra = a.getBoundingClientRect();
            const rb = b.getBoundingClientRect();
            return (rb.height * (rb.right > window.innerWidth * 0.5 ? 1.5 : 1))
                 - (ra.height * (ra.right > window.innerWidth * 0.5 ? 1.5 : 1));
        });
        const panel = panels[0];
        const panelText = (panel.innerText || '').trim();
        out.partial_text_len = panelText.length;

        // Step rows — walk listitems and styled <div>s. Same shape as
        // Claude's walker. Skip rows with nested children (we want leaf
        // text only, not the parent that contains many siblings).
        // 2026-04-30: dropped [class*="row" i] — too loose; matched
        // sidebar nav / model-switcher rows and bled UI chrome into
        // out.steps[]. Min length raised 4→12 to drop "OK"/"Done"
        // single-word noise. Activity-verb gate mirrors Claude's panel
        // walker at research.py:7052 — without it the walker grabs any
        // 4-240-char text inside a panel-shaped div.
        const STEP_SELS = [
            'li', '[role="listitem"]',
            '[class*="step" i]', '[class*="checklist" i] > div',
            '[class*="task" i] > div', '[class*="activity" i]'
        ].join(', ');
        const VERB_GATE = /^(?:checking|searching|looking|browsing|investigating|analyzing|reading|exploring|visiting|researching|thinking|reasoning|gathering|reviewing|consulting|comparing|evaluating|considering|drafting|writing|finalizing|finalising|summari[zs]ing|confirming|synthesi[zs]ing)\b/i;
        const seenStep = new Set();
        panel.querySelectorAll(STEP_SELS).forEach(e => {
            const t = (e.innerText || '').trim();
            if (!t || t.length < 12 || t.length > 240) return;
            if (e.querySelector('li, [role="listitem"]')) return;
            if (!VERB_GATE.test(t)) return;
            const k = t.slice(0, 80);
            if (seenStep.has(k)) return;
            seenStep.add(k);
            out.steps.push(t.slice(0, 220));
        });
        out.steps = out.steps.slice(-15);
        if (out.steps.length > 0) out.progress = out.steps[out.steps.length - 1];

        // Section headings — ChatGPT uses h1/h2/h3 inside the panel for
        // top-level outline (Deep Research's running report skeleton).
        panel.querySelectorAll('h1, h2, h3').forEach(h => {
            const t = (h.innerText || '').trim();
            if (t && t.length > 1 && t.length < 120) out.sections.push(t);
        });
        out.sections = out.sections.slice(0, 20);

        // URL list — every external <a>. Exclude ChatGPT/OpenAI internal
        // anchors (sign-in, settings, share endpoint) since those aren't
        // research sources. Cap at 50 to bound payload size.
        const seenUrl = new Set();
        panel.querySelectorAll('a[href^="http"]').forEach(a => {
            const h = a.href || '';
            if (!h || h.length > 500) return;
            if (h.includes('chatgpt.com') || h.includes('openai.com')) return;
            if (seenUrl.has(h)) return;
            seenUrl.add(h);
            out.source_urls.push(h);
        });
        out.source_urls = out.source_urls.slice(0, 50);

        // Aggregate search count — ChatGPT renders strings like
        // "193 searches" / "33 sources" in the panel header or near the
        // step list. Pick the largest match so a transient lower count
        // doesn't shrink the chip mid-run. Same heuristic as Gemini's
        // panel walker.
        try {
            const re = /(\\d+)\\s+(?:websites?|sources?|searches?|sites?|results?)\\b/gi;
            let mm; let best = 0;
            while ((mm = re.exec(panelText)) !== null) {
                const n = parseInt(mm[1], 10) || 0;
                if (n > best) best = n;
            }
            out.searches = best;
        } catch (e) {}

        return out;
    }"""
    try:
        res = await page.evaluate(JS)
    except Exception as _e:
        log(f"[ChatGPT] activity panel walker failed: {_e}", "DEBUG")
        return None
    # Also try the Deep Research sandbox iframe — the panel often mounts
    # there when the conversation runs in DR mode (cross-origin iframe
    # at oaiusercontent / web-sandbox.oaiusercontent).
    if not res or (not res.get("steps") and not res.get("source_urls")):
        try:
            for frame in page.frames:
                try:
                    src = (frame.url or "").lower()
                except Exception:
                    continue
                if not src:
                    continue
                if ("deep_research" in src or "oaiusercontent" in src):
                    try:
                        f_res = await frame.evaluate(JS)
                        if f_res and (f_res.get("steps") or f_res.get("source_urls")):
                            res = f_res
                            break
                    except Exception:
                        continue
        except Exception:
            pass
    if not res:
        return None
    has_data = (
        bool(res.get("steps"))
        or bool(res.get("source_urls"))
        or bool(res.get("sections"))
        or int(res.get("searches", 0) or 0) > 0
    )
    if not has_data:
        return None
    return res


# ── Browser ────────────────────────────────────────────────────────────────────

class Browser:
    """Playwright persistent Chrome context — proven from original research.py."""

    # Hosts where popups are allowed to live. Anything else opened during a
    # run (linkedin/x/reddit/facebook from Gemini's share dialog social
    # icons, ads, third-party redirects we don't drive) gets auto-closed
    # by _guard_popup. Subdomain match: host == ALLOWED or host endswith
    # "." + ALLOWED. `google.com` covers the OAuth/sign-in chain.
    _POPUP_ALLOWED_HOSTS = frozenset({
        "chatgpt.com", "openai.com", "auth.openai.com",
        "claude.ai", "claude.site", "anthropic.com",
        "gemini.google.com", "g.co",
        "docs.google.com", "drive.google.com",
        "accounts.google.com", "myaccount.google.com",
        "mail.google.com",
        "notebooklm.google.com",
        "studio.youtube.com", "youtube.com",
        "google.com",
    })

    def __init__(self, profile_dir, headless=False):
        self.profile_dir = str(profile_dir)
        self.headless = headless
        self.playwright = None
        self.context = None
        self.page = None
        self._upload_queue = []
        # Tabs opened by us via new_tab() get registered here. Anything
        # NOT here AND not on _POPUP_ALLOWED_HOSTS is auto-closed.
        self._known_pages: set = set()

    async def start(self):
        # Kill only orphaned Playwright Chrome from OUR profile directory.
        # NEVER kill all chrome.exe — that nukes the user's personal browser.
        # Q8 (2026-04-30): match by profile path AND only kill chromes whose
        # create_time predates this --serve process. A chrome younger than us
        # was spawned by this same --serve (sibling pipeline restart, parallel
        # phase relaunch, etc.) and killing it surfaces as "Page.bring_to_front:
        # Target page, context or browser has been closed" on the sibling run.
        # Pre-fix the killer was indiscriminate — every Browser.start() in the
        # process lifetime would chew live sibling chromes.
        try:
            import psutil
            our_profile = str(Path(self.profile_dir).resolve()).lower().replace("\\", "/")
            try:
                serve_start_ts = psutil.Process(os.getpid()).create_time()
            except Exception:
                serve_start_ts = 0.0
            for proc in psutil.process_iter(["pid", "name", "cmdline"]):
                try:
                    if proc.info["name"] and "chrome" in proc.info["name"].lower():
                        cmdline = " ".join(proc.info["cmdline"] or []).lower().replace("\\", "/")
                        if _profile_matches_cmdline(our_profile, cmdline):
                            try:
                                chrome_start_ts = proc.create_time()
                            except (psutil.NoSuchProcess, psutil.AccessDenied):
                                chrome_start_ts = 0.0
                            if serve_start_ts > 0 and chrome_start_ts >= serve_start_ts:
                                log(f"Sparing sibling Chrome PID {proc.info['pid']} (younger than --serve, our profile)")
                                continue
                            log(f"Killing orphaned Chrome PID {proc.info['pid']} (our profile)")
                            proc.kill()
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
            await asyncio.sleep(1)
        except ImportError:
            pass
        except Exception:
            pass

        # Remove stale Chrome lock files from unclean shutdown — these prevent
        # Playwright from reusing the persistent profile directory.
        profile_path = Path(self.profile_dir)
        for lock_name in ("SingletonLock", "SingletonSocket", "SingletonCookie"):
            lock_file = profile_path / lock_name
            if lock_file.exists():
                try:
                    lock_file.unlink()
                    log(f"Removed stale Chrome lock: {lock_name}")
                except Exception:
                    pass

        # Clean version-specific cache dirs that cause downgrade errors when
        # switching between system Chrome and Playwright's bundled Chromium.
        # These are regeneratable caches — login sessions live in Default/.
        import shutil
        for cache_dir in ("ShaderCache", "GrShaderCache", "GraphiteDawnCache",
                          "component_crx_cache", "extensions_crx_cache",
                          "BrowserMetrics", "Crashpad"):
            p = profile_path / cache_dir
            if p.is_dir():
                try:
                    shutil.rmtree(p, ignore_errors=True)
                except Exception:
                    pass
        # Also remove the downgrade sentinel that triggers cleanup attempts
        for sentinel in profile_path.glob("*.CHROME_DELETE"):
            try:
                shutil.rmtree(sentinel, ignore_errors=True)
            except Exception:
                pass

        # STEALTH-2026-04-19: Escalated from playwright + UA/UACH spoof to
        # patchright + real Chrome binary. Prior stack (playwright's bundled
        # Chromium, manual UA/UACH overrides, --disable-blink-features, init
        # scripts) still got blocked by ChatGPT and Claude login — bot-score
        # too high even with all the shims. patchright is a drop-in async
        # replacement that patches the deeper CDP / runtime.enable / chrome
        # object / headless-mode detection vectors internally, and pairs
        # with channel="chrome" to run the user's installed Chrome binary
        # instead of the bundled Chromium.
        #
        # channel="chrome" was previously avoided because we feared the
        # Windows singleton broker would delegate to the user's personal
        # Chrome and exit. That only happens when sharing a user-data-dir;
        # we now use a DEDICATED profile at ~/.super-research/browser-profile
        # so Chrome launches a separate process independent of the user's
        # daily browsing instance.
        #
        # Per patchright docs, we MUST NOT set user_agent, extra_http_headers,
        # or automation-disabling args — patchright handles those internally,
        # and adding them back produces inconsistencies that detection
        # scripts flag. Keep the init_script below as a belt-and-suspenders
        # layer; it's additive and patchright tolerates it.
        from patchright.async_api import async_playwright
        self.playwright = await async_playwright().start()
        self.context = await self.playwright.chromium.launch_persistent_context(
            user_data_dir=self.profile_dir,
            channel="chrome",
            headless=self.headless,
            viewport={"width": API_WIDTH, "height": API_HEIGHT},
            no_viewport=False,
        )
        # patchright owns the stealth layer from here. The prior hand-rolled
        # add_init_script (webdriver/plugins/languages/vendor/platform/
        # hardwareConcurrency/deviceMemory/chrome.runtime/permissions/WebGL)
        # ran AFTER patchright's own patches and overwrote them with values
        # that don't match what real Chrome actually exposes, producing
        # fingerprints worse than either layer alone. Keep the file-chooser
        # wiring; that's unrelated to stealth.
        if self.context.pages:
            self.page = self.context.pages[0]
        else:
            self.page = await self.context.new_page()
        self._known_pages.add(self.page)
        self.context.on("page", self._attach_file_handler)
        self.context.on("page", self._guard_popup)
        self._attach_file_handler(self.page)

        # Clipboard read/write — granted ONCE here at browser bootstrap.
        # Browser.grantPermissions (CDP, no origin) applies to the persistent
        # context and persists for the session, so this single grant covers
        # every agent tab in every phase (new_tab + open_isolated_tab both
        # reuse this same context). Without it, navigator.clipboard.writeText/
        # readText are denied in the automated context, which SILENTLY breaks
        # both P1/P2 brief-paste (Strategy A: clipboard + Ctrl+V) AND P2
        # response extraction (Gemini "Copy contents" → clipboard, ChatGPT/
        # Claude copy). verified_paste_brief still grants per-paste as a
        # defensive fallback in case this bootstrap grant ever fails.
        if await _grant_clipboard_permission(self.page):
            log("[browser] clipboard read/write permission granted browser-wide")
        else:
            log("[browser] clipboard permission grant failed — paste/extraction may degrade", "WARN")

        # F4 / DGOPS-7451 — security deny-list at the Playwright route layer.
        # Blocks ANY navigation, sub-frame request, fetch, or XHR to internal
        # infrastructure hostnames (web.app / firebaseapp.com /
        # distributedglobal.com / dg-eng.com). Catches the "agent wanders into
        # internal infra and rides a persisted Workspace session" class of
        # leak at the network layer — which is exactly what happened on
        # 2026-05-05 when Gemini Deep Research scraped dg-security-monitor.
        async def _security_deny_route(route, request):
            try:
                from urllib.parse import urlparse
                host = (urlparse(request.url).hostname or "").lower()
                pattern = _matches_security_deny_host(host)
                if pattern:
                    # Capture referrer for audit-log payload (PR review J1).
                    # Answers "which page tried to navigate to the blocked
                    # host?" — critical early-warning when the deny-list
                    # has a gap (next internal app deployed to *.appspot.com
                    # / *.run.app / custom DG domain). Best-effort: header
                    # read can fail on some request types — fall through to
                    # empty referrer rather than block the audit emit.
                    referrer = ""
                    try:
                        hdrs = await request.all_headers()
                        referrer = (hdrs.get("referer", "") or
                                    hdrs.get("referrer", "") or "")
                    except Exception:
                        pass
                    log(f"[security] BLOCKED agent navigation to {host} "
                        f"(matches deny-list pattern={pattern}, "
                        f"url={request.url[:200]}, "
                        f"referrer={referrer[:120]})", "WARN")
                    try:
                        emit_event("security_blocked_navigation",
                                   host=host, pattern=pattern,
                                   url=request.url[:300],
                                   resourceType=request.resource_type,
                                   referrer=referrer[:300])
                    except Exception:
                        pass
                    await route.abort("blockedbyclient")
                    return
            except Exception as _e:
                # Never let route handler exceptions leak — it would block
                # all navigation. Fall through to continue_ on any error.
                log(f"[security] route handler error (continuing): {_e}", "DEBUG")
            try:
                await route.continue_()
            except Exception:
                pass

        # PR review J2 principle preserved via emergency env-gate. Default
        # active. When DG_SECURITY_DENY_LIST_ENABLED=0, the deny-list is
        # bypassed entirely (no install, no per-request overhead). The
        # route deny-list is now the only load-bearing F4 defense (after
        # storage scrub was removed in DGOPS-7451), so this gate matters
        # for operators who need to disable it during incident response.
        if DG_SECURITY_DENY_LIST_ENABLED:
            try:
                await self.context.route("**/*", _security_deny_route)
            except Exception as _re:
                log(f"[security] failed to install route deny-list: {_re}", "WARN")
        else:
            log("[security] route deny-list DISABLED via "
                "DG_SECURITY_DENY_LIST_ENABLED=0 — M4 F4 defense is OFF",
                "WARN")

        log("Browser started (stealth: patchright + channel=chrome)")

    def _attach_file_handler(self, page):
        page.on("filechooser", self._on_file_chooser)

    async def _guard_popup(self, page):
        """Auto-close popup tabs that aren't on the agent host allow-list.

        Fires for BOTH our own new_tab() calls AND spontaneous popups
        (social-share window.open, target=_blank). Polls page.url for up to
        ~4s waiting for the URL to settle past about:blank — then matches
        the host against the allow-list. Tabs explicitly registered in
        _known_pages by new_tab() are never closed (belt-and-suspenders for
        race cases).

        Allow-list covers every host we drive a flow through (chatgpt/
        claude/gemini/notebooklm/youtube/gmail/gdocs/google-auth). Anything
        else (linkedin/facebook/x/reddit etc. from Gemini's share dialog
        social icons, ads, OAuth redirects we don't drive) gets closed.
        """
        try:
            if page in self._known_pages:
                return
            url = ""
            for _ in range(8):  # ~4s window for URL to settle
                try:
                    url = page.url or ""
                except Exception:
                    return
                if url and url != "about:blank":
                    break
                await asyncio.sleep(0.5)
            if not url or url == "about:blank":
                # Stayed at about:blank — likely a still-loading agent tab.
                # Don't close; the caller's flow will manage it.
                return
            try:
                from urllib.parse import urlparse
                host = (urlparse(url).hostname or "").lower()
            except Exception:
                return
            host_norm = host[4:] if host.startswith("www.") else host
            if host_norm and any(host_norm == a or host_norm.endswith("." + a)
                                  for a in self._POPUP_ALLOWED_HOSTS):
                # Treat as legitimate — register so a subsequent event won't
                # re-evaluate it, and exit.
                self._known_pages.add(page)
                return
            log(f"[popup-guard] Closing off-allowlist popup: {host} ({url[:80]})", "INFO")
            try:
                await page.close()
            except Exception as e:
                log(f"[popup-guard] close failed: {e}", "WARN")
        except Exception as e:
            log(f"[popup-guard] error: {e}", "WARN")

    async def _on_file_chooser(self, file_chooser):
        if not self._upload_queue:
            log("File dialog opened but upload queue is empty", "WARN")
            return
        # 2026-04-30: type-aware routing. Pre-fix the queue was strict FIFO,
        # so YouTube uploads broke whenever the thumbnail file dialog opened
        # before the video dialog (or CUA misclicked into thumbnail first):
        # the PNG fed into the video picker → "Invalid file format" banner.
        # Now we read the input element's `accept` attribute and pop the
        # queued file whose extension matches. Falls back to FIFO when the
        # accept attribute is unset / ambiguous.
        accept = ""
        try:
            handle = await file_chooser.element_handle()
            if handle is not None:
                accept = (await handle.get_attribute("accept")) or ""
        except Exception:
            accept = ""
        accept_lower = accept.lower()
        VIDEO_EXTS = {".mp4", ".mov", ".webm", ".mkv", ".avi", ".m4v"}
        IMAGE_EXTS = {".png", ".jpg", ".jpeg", ".gif", ".webp"}
        wants_image = ("image" in accept_lower) or any(ext in accept_lower for ext in IMAGE_EXTS)
        wants_video = ("video" in accept_lower) or any(ext in accept_lower for ext in VIDEO_EXTS)
        chosen_idx = 0  # default FIFO
        if wants_image and not wants_video:
            for i, p in enumerate(self._upload_queue):
                if Path(p).suffix.lower() in IMAGE_EXTS:
                    chosen_idx = i
                    break
        elif wants_video and not wants_image:
            for i, p in enumerate(self._upload_queue):
                if Path(p).suffix.lower() in VIDEO_EXTS:
                    chosen_idx = i
                    break
        path = self._upload_queue.pop(chosen_idx)
        if Path(path).exists():
            log(f"File dialog intercepted — uploading: {Path(path).name} (accept={accept[:60] or 'unset'})")
            # Wrap in try/except — pyee's AsyncIOEventEmitter turns any
            # unhandled exception in this `page.on("filechooser", ...)`
            # callback into a process-killing `raise error` (pyee/base.py
            # _emit_handle_potential_error). Pre-fix, a TargetClosedError
            # raised here when the page closed mid-upload (popup-guard
            # racing the dialog, EPIPE from the Patchright Node driver
            # during HV recovery, etc.) escalated the whole BE process
            # to exit code 0xFFFFFFFF and the daemon-loop respawned —
            # losing the in-flight pipeline and leaving the queue-gate
            # wedged on a stale prior-run pointer. The page is gone; we
            # have nothing useful to do with the file. Drop a WARN and
            # let the caller's own retry / timeout path handle it.
            try:
                await file_chooser.set_files(path)
            except Exception as _set_err:
                log(
                    f"File dialog set_files failed ({type(_set_err).__name__}): {_set_err} "
                    f"— page may have closed mid-upload; swallowing to keep BE alive",
                    "WARN",
                )
        else:
            log(f"File dialog — queued file not found: {path}", "WARN")

    def set_upload_file(self, path):
        """Set the file for the next file dialog (replaces any queued files)."""
        self._upload_queue = [str(path)]

    def queue_upload_file(self, path):
        """Add a file to the upload queue (for sequential file dialogs like video + thumbnail)."""
        self._upload_queue.append(str(path))

    def clear_upload_file(self):
        self._upload_queue = []

    async def screenshot(self) -> str:
        try:
            buf = await self.page.screenshot(type="png", timeout=10000)
            return base64.b64encode(buf).decode("ascii")
        except Exception as e:
            log(f"Screenshot failed: {e}", "WARN")
            await asyncio.sleep(2)
            try:
                buf = await self.page.screenshot(type="png", timeout=15000)
                return base64.b64encode(buf).decode("ascii")
            except Exception:
                return ""

    async def left_click(self, x, y):
        await self.page.mouse.click(x, y)

    async def right_click(self, x, y):
        await self.page.mouse.click(x, y, button="right")

    async def double_click(self, x, y):
        await self.page.mouse.dblclick(x, y)

    async def triple_click(self, x, y):
        await self.page.mouse.click(x, y, click_count=3)

    async def middle_click(self, x, y):
        await self.page.mouse.click(x, y, button="middle")

    async def type_text(self, text):
        await self.page.keyboard.type(text, delay=20)

    async def key(self, combo):
        mapping = {
            "ctrl": "Control", "alt": "Alt", "shift": "Shift",
            "meta": "Meta", "super": "Meta", "cmd": "Meta",
            "return": "Enter", "enter": "Enter",
            "backspace": "Backspace", "delete": "Delete",
            "tab": "Tab", "escape": "Escape", "esc": "Escape",
            "space": " ", "up": "ArrowUp", "down": "ArrowDown",
            "left": "ArrowLeft", "right": "ArrowRight",
            "pageup": "PageUp", "pagedown": "PageDown",
            "home": "Home", "end": "End",
        }
        parts = combo.split("+")
        translated = [mapping.get(p.strip().lower(), p.strip()) for p in parts]
        await self.page.keyboard.press("+".join(translated))

    async def mouse_move(self, x, y):
        await self.page.mouse.move(x, y)

    async def scroll(self, x, y, direction, amount=3):
        await self.page.mouse.move(x, y)
        delta_map = {"up": (0, -100*amount), "down": (0, 100*amount),
                     "left": (-100*amount, 0), "right": (100*amount, 0)}
        dx, dy = delta_map.get(direction, (0, 100*amount))
        await self.page.mouse.wheel(dx, dy)

    async def left_click_drag(self, sx, sy, ex, ey):
        await self.page.mouse.move(sx, sy)
        await self.page.mouse.down()
        await self.page.mouse.move(ex, ey)
        await self.page.mouse.up()

    async def navigate(self, url):
        log(f"Navigating: {url}")
        # Self-heal if self.page was closed out from under us. Common
        # trigger: a throwaway tab opened via new_tab() (which reassigns
        # self.page) and then close()'d by the caller — e.g. the verify-
        # at-phase-time flow at :7718 / :7851. Pre-fix, run_phase1's
        # first navigate hit TargetClosedError on the stale self.page
        # because nothing restored it post-verify. context.new_page()
        # gives us a live page on the same persistent profile (logins
        # survive) so the goto below lands somewhere alive.
        if self.page is None or self.page.is_closed():
            log("navigate: self.page closed — opening fresh page", "WARN")
            self.page = await self.context.new_page()
            self._known_pages.add(self.page)
            try:
                self.page.on("close", lambda p: self._known_pages.discard(p))
            except Exception:
                pass
            self._attach_file_handler(self.page)
        try:
            await self.page.goto(url, wait_until="domcontentloaded", timeout=30000)
        except Exception as e:
            # One retry on page-death-class failures (TargetClosedError
            # surfaces as "Target page, context or browser has been closed").
            # Bounded to one retry so context-level death (driver EPIPE,
            # network) still surfaces to the caller's snag handler instead
            # of looping forever.
            msg = str(e).lower()
            if ("target page" in msg or "browser has been closed" in msg
                    or "page, context" in msg):
                log(f"navigate: page died mid-goto ({type(e).__name__}) — recreating + retry once", "WARN")
                try: await self.page.close()
                except Exception: pass
                self.page = await self.context.new_page()
                self._known_pages.add(self.page)
                try:
                    self.page.on("close", lambda p: self._known_pages.discard(p))
                except Exception:
                    pass
                self._attach_file_handler(self.page)
                await self.page.goto(url, wait_until="domcontentloaded", timeout=30000)
            else:
                raise

    async def new_tab(self, url=None):
        """Open new tab. Sets self.page to the new tab."""
        self.page = await self.context.new_page()
        # Register BEFORE goto so the popup guard's race window (between
        # context "page" event firing and goto completing) sees this as
        # a known agent tab and skips closing it.
        self._known_pages.add(self.page)
        # Discard from set on close so _known_pages doesn't grow unbounded
        # across hard-retries that close+reopen agent tabs.
        try:
            self.page.on("close", lambda p: self._known_pages.discard(p))
        except Exception:
            pass
        if url:
            log(f"New tab: {url}")
            await self.page.goto(url, wait_until="domcontentloaded", timeout=30000)
        self._attach_file_handler(self.page)
        return self.page

    async def open_isolated_tab(self, url=None):
        """Open a throwaway tab WITHOUT touching self.page. Use for
        verify/probe tabs the caller will close in a finally. Critical
        because new_tab() reassigns self.page — closing the returned
        page would leave self.page pointing at a dead page and break
        the next Browser-level navigate. See verify_at_phase_time
        (:7718) — pre-fix, that flow used new_tab + tab.close() and
        crashed P1's first navigate with TargetClosedError every time
        skipInitVerify was on."""
        page = await self.context.new_page()
        self._known_pages.add(page)
        try:
            page.on("close", lambda p: self._known_pages.discard(p))
        except Exception:
            pass
        if url:
            log(f"New tab: {url}")
            await page.goto(url, wait_until="domcontentloaded", timeout=30000)
        self._attach_file_handler(page)
        return page

    async def switch_to_page(self, page):
        self.page = page
        await page.bring_to_front()

    async def current_url(self):
        return self.page.url

    async def close(self):
        try:
            if self.context: await self.context.close()
            if self.playwright: await self.playwright.stop()
            log("Browser closed")
        except Exception as e:
            log(f"Browser close error: {e}", "WARN")
            # Kill only OUR profile's chromium — never nuke all chrome.exe
            try:
                import psutil
                our_profile = str(Path(self.profile_dir).resolve()).lower().replace("\\", "/")
                for proc in psutil.process_iter(["pid", "name", "cmdline"]):
                    try:
                        if proc.info["name"] and "chrom" in proc.info["name"].lower():
                            cmdline = " ".join(proc.info["cmdline"] or []).lower().replace("\\", "/")
                            if _profile_matches_cmdline(our_profile, cmdline):
                                proc.kill()
                    except (psutil.NoSuchProcess, psutil.AccessDenied):
                        pass
            except Exception:
                pass


# ── Action Executor ────────────────────────────────────────────────────────────

async def execute_action(browser, action, params):
    """Execute a CUA action. Returns screenshot base64."""
    if action == "screenshot":
        return None
    try:
        if action == "left_click":
            x, y = params["coordinate"]; log_action("left_click", f"({x}, {y})"); await browser.left_click(x, y)
        elif action == "right_click":
            x, y = params["coordinate"]; log_action("right_click", f"({x}, {y})"); await browser.right_click(x, y)
        elif action == "double_click":
            x, y = params["coordinate"]; log_action("double_click", f"({x}, {y})"); await browser.double_click(x, y)
        elif action == "triple_click":
            x, y = params["coordinate"]; log_action("triple_click", f"({x}, {y})"); await browser.triple_click(x, y)
        elif action == "middle_click":
            x, y = params["coordinate"]; log_action("middle_click", f"({x}, {y})"); await browser.middle_click(x, y)
        elif action == "type":
            text = params["text"]; log_action("type", f"{len(text)} chars")
            if len(text) > 200:
                # insertText for long text — avoids clipboard file-paste issue
                try:
                    await browser.page.keyboard.insert_text(text)
                except Exception:
                    await browser.type_text(text[:2000])
            else:
                await browser.type_text(text)
        elif action == "key":
            combo = params.get("key") or params.get("text", "")
            if not combo:
                log("Empty key — skipping", "WARN"); return await browser.screenshot()
            log_action("key", combo); await browser.key(combo)
        elif action == "mouse_move":
            x, y = params["coordinate"]; log_action("mouse_move", f"({x}, {y})"); await browser.mouse_move(x, y)
        elif action == "scroll":
            x, y = params.get("coordinate", (640, 400))
            d = params.get("direction", "down")
            a = params.get("amount", 3)
            log_action("scroll", f"({x},{y}) {d}"); await browser.scroll(x, y, d, a)
        elif action == "left_click_drag":
            sx, sy = params.get("start_coordinate", (0, 0))
            ex, ey = params.get("end_coordinate", (0, 0))
            log_action("drag", f"({sx},{sy})->({ex},{ey})"); await browser.left_click_drag(sx, sy, ex, ey)
        elif action == "wait":
            d = params.get("duration", 1); log_action("wait", f"{d}s"); await asyncio.sleep(d)
        else:
            log(f"Unknown action: {action}", "WARN")
    except Exception as e:
        log(f"Action '{action}' failed: {e} — continuing", "WARN")
    await asyncio.sleep(0.5)
    return await browser.screenshot()


# ── Agent Loop ─────────────────────────────────────────────────────────────────

async def agent_loop(client, browser, system_prompt, user_message,
                     model=CUA_MODEL, max_iterations=30, verbose=False,
                     phase=None, agent_name=None, target_page=None):
    """CUA agent loop — proven from original research.py.

    target_page (optional): Playwright Page reference. When provided, every
    screenshot re-anchors to this tab via bring_to_front. Prevents the
    "Claude polls screenshotted Gemini's tab" race when another async path
    swaps browser.page between iterations.
    """
    async def _anchored_screenshot():
        if target_page is not None:
            try:
                await browser.switch_to_page(target_page)
            except Exception:
                pass
        return await browser.screenshot()

    initial_ss = await _anchored_screenshot()
    if not initial_ss:
        return {"status": "error", "text": "Could not take initial screenshot"}

    messages = [{"role": "user", "content": [
        {"type": "text", "text": user_message},
        {"type": "image", "source": {"type": "base64", "media_type": "image/png", "data": initial_ss}},
    ]}]
    tools = [{"type": "computer_20251124", "name": "computer",
              "display_width_px": API_WIDTH, "display_height_px": API_HEIGHT}]

    last_text = ""
    recent_actions = []

    for iteration in range(1, max_iterations + 1):
        # ── Check stop/pause before each CUA API call ──
        if _controls.is_stop():
            return {"status": "stopped", "text": last_text}
        if _controls.is_pause():
            await _controls.wait_if_paused()
            if _controls.is_stop():
                return {"status": "stopped", "text": last_text}

        if verbose: log(f"Iteration {iteration}/{max_iterations}")
        try:
            response = client.beta.messages.create(
                model=model, max_tokens=4096, system=system_prompt,
                tools=tools, messages=messages, betas=[BETA_FLAG],
            )
        except Exception as e:
            err = str(e)
            # Resolve which phase/agent this CUA call is serving so the
            # frontend can route the warning to the correct per-agent
            # badge inside Phase 2 instead of collapsing into a phase-wide
            # banner. Fall back to _runtime.phase when caller omitted it.
            _phase = phase if phase is not None else _runtime.phase
            _agent = agent_name or None
            low = err.lower()
            if "rate_limit" in low or "429" in err:
                # #705: a 429 is a key/quota problem the user must act on —
                # switching to another key clears it. Don't silent-retry (that
                # hid a persistent rate limit and made the alert appear-then-
                # vanish); pause immediately with a Retry-only 'load or switch
                # your key' card, same as the cap / key-rejected branches below.
                log(f"Claude API rate limited (429) — pausing for key action: {err[:160]}", "ERROR")
                _rl_msg = ("Rate-limited (429) on the current Anthropic key. Load or "
                           "switch to another key in Account → API Config, then Retry.")
                if _phase == 2 and _agent:
                    fail_agent(_agent, "Claude API rate limit", _rl_msg)
                else:
                    fail_phase(_phase, "Claude API rate limit", _rl_msg)
                return {"status": "error", "text": str(e)}
            elif "overloaded" in low or "529" in err:
                log("API overloaded — waiting 60s", "WARN")
                await asyncio.sleep(60); continue
            elif "workspace api usage limits" in low or ("400" in err and "usage limit" in low):
                log(f"Workspace API cap hit — aborting CUA loop: {err[:200]}", "ERROR")
                _cap_detail = err[:200] or "Workspace cap hit on the current Anthropic key."
                _cap_hint = "Paste a different key in Account → API Config (preferred), raise the cap in the Anthropic Console, or wait for reset."
                if _phase == 2 and _agent:
                    fail_agent(_agent, "Claude API workspace cap hit", f"{_cap_detail} {_cap_hint}")
                else:
                    fail_phase(_phase, "Claude API workspace cap hit", f"{_cap_detail} {_cap_hint}")
                return {"status": "error", "text": str(e)}
            elif "401" in err and ("unauthorized" in low or "invalid" in low or "api_key" in low):
                log(f"Claude API key rejected — aborting CUA loop: {err[:200]}", "ERROR")
                _bad_key_hint = "Paste a fresh key in Account → API Config (preferred, no restart), or update ANTHROPIC_API_KEY on the BE machine and restart."
                if _phase == 2 and _agent:
                    fail_agent(_agent, "Claude API key rejected", _bad_key_hint)
                else:
                    fail_phase(_phase, "Claude API key rejected", _bad_key_hint)
                return {"status": "error", "text": str(e)}
            else:
                log(f"API error: {e}", "ERROR")
                return {"status": "error", "text": str(e)}

        assistant_content = response.content
        messages.append({"role": "assistant", "content": assistant_content})

        tool_uses = []
        for block in assistant_content:
            if hasattr(block, "text"):
                last_text = block.text
                if verbose: log(f"Claude: {last_text[:200]}")
            if block.type == "tool_use":
                tool_uses.append(block)

        if not tool_uses:
            return {"status": "done", "text": last_text}

        tool_results = []
        for tb in tool_uses:
            act = tb.input.get("action", "")
            # Stuck detection
            sig = f"{act}:{tb.input.get('coordinate', '')}"
            recent_actions.append(sig)
            if len(recent_actions) > 5: recent_actions.pop(0)
            if len(recent_actions) == 5 and len(set(recent_actions)) == 1:
                log("Stuck — same action 5x. Injecting hint.", "WARN")
                tool_results.append({"type": "tool_result", "tool_use_id": tb.id, "content": [
                    {"type": "text", "text": "You seem stuck. Try a different approach."},
                    {"type": "image", "source": {"type": "base64", "media_type": "image/png", "data": await _anchored_screenshot()}},
                ]})
                recent_actions.clear()
                continue

            if act == "screenshot":
                ss = await _anchored_screenshot()
                tool_results.append({"type": "tool_result", "tool_use_id": tb.id,
                    "content": [{"type": "image", "source": {"type": "base64", "media_type": "image/png", "data": ss}}]})
            else:
                ss = await execute_action(browser, act, tb.input)
                # Re-anchor after action — execute_action may have navigated,
                # opened a new tab, or the OS swapped focus during the click.
                if target_page is not None:
                    try:
                        await browser.switch_to_page(target_page)
                    except Exception:
                        pass
                tool_results.append({"type": "tool_result", "tool_use_id": tb.id, "content": [
                    {"type": "text", "text": f"Action '{act}' executed."},
                    {"type": "image", "source": {"type": "base64", "media_type": "image/png", "data": ss}},
                ]})
            # Emit CUA action event for frontend visibility
            if agent_name and act != "screenshot":
                emit_event("cua_action", phase=phase, agent=agent_name,
                    action=act, description=last_text[:200] if last_text else f"Action: {act}",
                    iteration=iteration)
        messages.append({"role": "user", "content": tool_results})

    return {"status": "max_iterations", "text": last_text}


# ── Verification Helpers ───────────────────────────────────────────────────────

async def verify_chatgpt_generating(page) -> bool:
    """Check if ChatGPT is actively generating (stop button visible).
    Scrolls both page body AND chat container — DR stop button is in chat UI, not input area.

    2026-04 iframe fix: ChatGPT Deep Research renders inside a cross-origin
    sandbox iframe (connector_openai_deep_research.web-sandbox.oaiusercontent.com).
    Host-page selectors miss the DR stop button + progress entirely, so we
    walk `page.frames` and check inside the DR iframe for any "researching"/
    "sources"/"stop" signal. Matches the detect_completion_chatgpt pattern."""
    try:
        await page.evaluate("""() => {
            // Scroll the page body
            window.scrollTo(0, document.body.scrollHeight);
            // Also scroll common chat containers (DR stop button is inside the chat, not input)
            const containers = document.querySelectorAll(
                '[class*="react-scroll"], [class*="chat-messages"], main, [role="presentation"]');
            containers.forEach(c => c.scrollTop = c.scrollHeight);
        }""")
        await asyncio.sleep(0.3)
        host_hit = await page.evaluate("""() => {
            // Check standard composer stop buttons
            const stop = document.querySelector('button[aria-label="Stop generating"]')
                || document.querySelector('button[data-testid="stop-button"]')
                || document.querySelector('button[aria-label="Stop streaming"]')
                || document.querySelector('button[aria-label="Stop"]');
            if (stop) return true;
            // ChatGPT Deep Research: stop button lives INSIDE the research card/dialog
            // (not in the composer). Look for buttons inside research/canvas containers.
            const cards = document.querySelectorAll(
                '[data-testid*="research"], [data-testid*="canvas"], [class*="research"], ' +
                '[aria-label*="Deep research"], [aria-label*="deep research"]'
            );
            for (const c of cards) {
                const cBtns = c.querySelectorAll('button');
                for (const b of cBtns) {
                    const lbl = (b.getAttribute('aria-label') || '').toLowerCase();
                    const t = (b.textContent || '').trim().toLowerCase();
                    if (lbl.includes('stop') || lbl.includes('cancel') || t === 'stop') return true;
                }
                // Progress/loading indicator inside the card
                if (c.querySelector('[role="progressbar"], [class*="progress"], [class*="spinner"]')) return true;
            }
            // Check by button content (square icon = stop)
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const svg = b.querySelector('svg rect, svg path');
                const label = (b.getAttribute('aria-label') || '').toLowerCase();
                if (label.includes('stop')) return true;
            }
            // 2026-05-14: CSS-animation fallback (mirrors verify_gemini_generating /
            // verify_claude_generating). Catches the gap between "Thought for X
            // seconds" badge appearing and the iframe-scoped stop button rendering
            // — the previous code's 'thought for ' short-circuit was firing as a
            // false done-signal during that window. E2E hit this: CUA clicked
            // Start research on the clarification panel, research went to
            // "Researching..." state, but no host-level stop button + a stale
            // "Thought for" badge made the host check return false 15× and the
            // outer loop spawned a 2nd ChatGPT tab.
            // 2026-05-14 (refined): use getAnimations() + playState === 'running'.
            // CSS animationName remains set on elements with completed/never-
            // run animations, so the prior check returned true forever on
            // persistent UI chrome (avatars, fade-ins) and caused Phase 1
            // brief verify to read as "generating" for 27 min after the brief
            // actually completed, leading the multi-signal stall watchdog to
            // fire as a false alarm. Visibility gate added to skip hidden
            // animated nodes that some component libraries keep mounted.
            const animated = document.querySelectorAll(
                '[class*="animate"], [class*="spin"], [class*="pulse"], [class*="loading"], [class*="streaming"]'
            );
            for (const el of animated) {
                if (el.offsetParent === null) continue;
                if (typeof el.getAnimations !== 'function') continue;
                const anims = el.getAnimations();
                if (anims.some(a => a.playState === 'running')) return true;
            }
            // 2026-05-24 P1-stall fix: gate body-text keyword checks on the
            // presence of DR-mode UI. hostKws ('searching the web' / 'reading
            // sources' / 'sources and counting') and 'researching...' literal
            // were added (2026-05-14, commit 4003d38) to catch P2 DR active
            // state when the clarification card transitions post-Start-click.
            // For P1 Pro + Extended Thinking, no DR card exists — and the
            // brief response for research-themed prompts (e.g. movie research
            // briefs) naturally writes literal phrases like "searching the
            // web" / "reading sources" / "researching..." in its narrative
            // content. That made the body-text sweep return true forever
            // after a P1 brief completed, stalling verify for 27+ minutes
            // (Salaar/Kalki E2E 2026-05-24). The fix: only run keyword sweep
            // when a DR-mode marker is actually mounted; for non-DR pages,
            // rely on CSS-animation + .result-streaming structural signals.
            // Gate selectors are narrow on purpose: [class*="research"] from
            // the cards loop above is too broad (response containers can have
            // research-themed class names); data-testid + aria-label are
            // DR-specific affordances that don't appear in P1.
            const bl = (document.body?.innerText || '').toLowerCase();
            const drModePresent = document.querySelector(
                '[data-testid*="research"], [data-testid*="canvas"], '
                + '[aria-label*="Deep research"], [aria-label*="deep research"]'
            ) !== null;
            if (drModePresent) {
                const hostKws = ['sources and counting', 'searching the web', 'reading sources'];
                if (hostKws.some(k => bl.includes(k))) return true;
                // post-Start "Researching..." status lives inside the DR
                // clarification card affordance. Gated on drModePresent so it
                // can't false-positive on P1 brief narrative that writes
                // "researching..." in prose.
                if (bl.includes('researching...')) return true;
            }
            // "Thought for X seconds" badge persists during Extended Thinking
            // (P1 Pro) and DR (P2). With stop button + cards + CSS-animation
            // all negative above, this confirms the page is settled. Kept
            // outside the DR gate — it's a NEGATIVE (done) signal.
            // 2026-05-24: tightened from `includes('thought for ')` to the
            // canonical "thought for + whitespace + digit" regex used by
            // detect_completion_chatgpt (research.py:12505/12546). The
            // substring match could false-fire on assistant narrative like
            // "I thought for a moment about Salaar..." and declare done
            // prematurely if the earlier stop/animation checks happened to
            // be momentarily negative between token batches. Requiring a
            // digit immediately after "thought for " locks the match to
            // the actual badge format ("Thought for 23 seconds", "Thought
            // for 2 minutes"), not prose.
            if (/thought for\\s+\\d/i.test(bl)) return false;
            return !!document.querySelector('.result-streaming, [data-is-streaming="true"]');
        }""")
        if host_hit:
            return True

        # ── DR iframe walk ──
        # Deep Research renders inside cross-origin oaiusercontent sandbox.
        # Walk frames, look for deep_research/oaiusercontent URL match, then
        # check for stop button / active keywords / partial content inside.
        try:
            for frame in page.frames:
                try:
                    src = (frame.url or "").lower()
                except Exception:
                    continue
                if not src:
                    continue
                if ("deep_research" in src or "oaiusercontent" in src):
                    try:
                        active = await frame.evaluate("""() => {
                            // Any stop button
                            for (const b of document.querySelectorAll('button')) {
                                const t = (b.textContent || '').trim().toLowerCase();
                                const al = (b.getAttribute('aria-label') || '').toLowerCase();
                                if (t === 'stop' || t === 'stop research' ||
                                    al.includes('stop')) return true;
                            }
                            // Spinner / progress
                            if (document.querySelector(
                                '[role="progressbar"], [class*="progress"], [class*="spinner"], ' +
                                '[class*="loading"], [data-is-streaming="true"]'
                            )) return true;
                            // 2026-05-14: CSS-animation fallback (mirrors verify_gemini /
                            // verify_claude). ChatGPT DR's "Researching..." state has
                            // animated text-shimmer + dot-flashing inside the iframe
                            // that don't always have a [class*="spinner"] marker at
                            // the exact poll moment — without this fallback the
                            // iframe walk returned false during legitimate research
                            // and the outer loop spawned a 2nd tab. E2E 2026-05-14:
                            // CUA had clicked Start research and the iframe was
                            // visibly rendering when this returned false 15×.
                            // 2026-05-14 (refined): use getAnimations() + playState ===
                            // 'running' to avoid false-positives from completed
                            // animations whose CSS animationName remains set.
                            const animated = document.querySelectorAll(
                                '[class*="animate"], [class*="spin"], [class*="pulse"], [class*="loading"], [class*="streaming"]'
                            );
                            for (const el of animated) {
                                if (el.offsetParent === null) continue;
                                if (typeof el.getAnimations !== 'function') continue;
                                const anims = el.getAnimations();
                                if (anims.some(a => a.playState === 'running')) return true;
                            }
                            const bl = (document.body?.innerText || '').toLowerCase();
                            // 2026-05-14 (post-E2E): the post-Start status bar inside
                            // the DR iframe shows literal "Researching..." (with
                            // ellipsis) while research is active. The ellipsis is
                            // what makes this safe — bare "researching" would
                            // false-positive on narrative prose, but the ellipsis
                            // pattern is the live status indicator, not story text.
                            // Must beat the 'thought for ' short-circuit below.
                            if (bl.includes('researching...')) return true;
                            // "Thought for X seconds" badge persists while DR
                            // continues — it's NOT a definitive done signal. With
                            // stop button + spinner + CSS animation all negative
                            // above, treat the iframe as settled. Keyword fallthrough
                            // intentionally not re-added: inside the DR iframe, body
                            // text IS the rendered brief itself (could legitimately
                            // contain "after reading sources" / "searching the web"),
                            // and any keyword match would re-introduce the same
                            // false-positive class as the deleted length>200 fallback.
                            // 2026-05-24: same regex tightening as host path —
                            // require a digit after "thought for " to lock to badge
                            // format and not match narrative prose.
                            if (/thought for\\s+\\d/i.test(bl)) return false;
                            return false;
                        }""")
                        if active:
                            return True
                    except Exception:
                        pass
                    break
        except Exception:
            pass
        return False
    except Exception:
        return False


async def _verify_chatgpt_generating_diag(page) -> str:
    """Diagnostic twin of verify_chatgpt_generating's host_hit JS — returns
    the reason string for "still generating" instead of just a bool. Used
    by poll_until_done's safety-net CUA escalation so the log shows
    WHICH path inside the verify function is the false-positive when DOM
    keeps reporting generating but content is flat.

    Returns empty string when the verify would have returned False (done).
    Returns one of: "stop_composer:<aria-label>", "card_stop:<class>",
    "card_progress:<class>", "generic_stop_label:<label>",
    "css_animation:<class>", "host_kw:<phrase>", "researching_ellipsis",
    "data_streaming_attr", or "no_hit" (which should round-trip to False
    in the real verify too).

    NOTE: kept in sync MANUALLY with verify_chatgpt_generating's host_hit
    block (research.py:~14495-14597). If you touch one, touch the other.
    Drift only affects diagnostic accuracy — the real verify path is
    unaffected and the safety-net CUA escalation still works."""
    try:
        return await page.evaluate("""() => {
            const stop = document.querySelector('button[aria-label="Stop generating"]')
                || document.querySelector('button[data-testid="stop-button"]')
                || document.querySelector('button[aria-label="Stop streaming"]')
                || document.querySelector('button[aria-label="Stop"]');
            if (stop) return "stop_composer:" + (stop.getAttribute('aria-label') || stop.getAttribute('data-testid') || '?');

            const cards = document.querySelectorAll(
                '[data-testid*="research"], [data-testid*="canvas"], [class*="research"], ' +
                '[aria-label*="Deep research"], [aria-label*="deep research"]'
            );
            for (const c of cards) {
                const cBtns = c.querySelectorAll('button');
                for (const b of cBtns) {
                    const lbl = (b.getAttribute('aria-label') || '').toLowerCase();
                    const t = (b.textContent || '').trim().toLowerCase();
                    if (lbl.includes('stop') || lbl.includes('cancel') || t === 'stop')
                        return "card_stop:" + ((c.className || c.getAttribute('data-testid') || '?') + '').slice(0, 60);
                }
                if (c.querySelector('[role="progressbar"], [class*="progress"], [class*="spinner"]'))
                    return "card_progress:" + ((c.className || c.getAttribute('data-testid') || '?') + '').slice(0, 60);
            }

            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const label = (b.getAttribute('aria-label') || '').toLowerCase();
                if (label.includes('stop'))
                    return "generic_stop_label:" + label.slice(0, 60);
            }

            const animated = document.querySelectorAll(
                '[class*="animate"], [class*="spin"], [class*="pulse"], [class*="loading"], [class*="streaming"]'
            );
            for (const el of animated) {
                if (el.offsetParent === null) continue;
                if (typeof el.getAnimations !== 'function') continue;
                const anims = el.getAnimations();
                if (anims.some(a => a.playState === 'running'))
                    return "css_animation:" + ((el.className || el.tagName) + '').slice(0, 80);
            }

            const bl = (document.body?.innerText || '').toLowerCase();
            const drModePresent = document.querySelector(
                '[data-testid*="research"], [data-testid*="canvas"], '
                + '[aria-label*="Deep research"], [aria-label*="deep research"]'
            ) !== null;
            if (drModePresent) {
                const hostKws = ['sources and counting', 'searching the web', 'reading sources'];
                const hit = hostKws.find(k => bl.includes(k));
                if (hit) return "host_kw:" + hit;
                if (bl.includes('researching...')) return "researching_ellipsis";
            }

            if (/thought for\\s+\\d/i.test(bl)) return "";
            return document.querySelector('.result-streaming, [data-is-streaming="true"]') ? "data_streaming_attr" : "";
        }""") or "no_hit"
    except Exception as e:
        return f"diag_error:{type(e).__name__}"


async def verify_gemini_generating(page) -> bool:
    """Check if Gemini is actively generating — broad stop button + animation detection."""
    try:
        await page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
        await asyncio.sleep(0.3)
        return await page.evaluate("""() => {
            // Broad button scan — any button with stop-related text/label
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const a = (b.getAttribute('aria-label') || '').toLowerCase();
                const t = (b.getAttribute('title') || '').toLowerCase();
                const txt = (b.textContent || '').trim().toLowerCase();
                if (a.includes('stop') || t.includes('stop') || txt === 'stop') return true;
            }
            // Animation/streaming indicators
            if (document.querySelector('[data-is-streaming="true"], .loading-indicator')) return true;
            // CSS animation on any element (spinning, pulsing).
            // 2026-05-14: use getAnimations() + playState === 'running' so
            // persisted-but-completed CSS animations on UI chrome don't
            // false-positive (see verify_chatgpt_generating note).
            const animated = document.querySelectorAll('[class*="animate"], [class*="spin"], [class*="pulse"], [class*="loading"]');
            for (const el of animated) {
                if (el.offsetParent === null) continue;
                if (typeof el.getAnimations !== 'function') continue;
                const anims = el.getAnimations();
                if (anims.some(a => a.playState === 'running')) return true;
            }
            return false;
        }""")
    except Exception:
        return False


async def verify_claude_generating(page) -> bool:
    """Check if Claude is actively generating — broad stop button + animation detection."""
    try:
        await page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
        await asyncio.sleep(0.3)
        return await page.evaluate("""() => {
            // Broad button scan — any button with stop-related text/label/icon
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const a = (b.getAttribute('aria-label') || '').toLowerCase();
                const t = (b.getAttribute('title') || '').toLowerCase();
                const txt = (b.textContent || '').trim().toLowerCase();
                if (a.includes('stop') || t.includes('stop') || txt === 'stop'
                    || a.includes('cancel gen') || a.includes('stop gen')) return true;
            }
            // Streaming/animation indicators
            if (document.querySelector('[data-is-streaming="true"]')) return true;
            // CSS animation check (Claude uses spinning asterisk, pulsing indicators).
            // 2026-05-14: use getAnimations() + playState === 'running' so
            // persisted-but-completed CSS animations on UI chrome don't
            // false-positive (see verify_chatgpt_generating note).
            const animated = document.querySelectorAll('[class*="animate"], [class*="spin"], [class*="pulse"], [class*="loading"], [class*="streaming"]');
            for (const el of animated) {
                if (el.offsetParent === null) continue;
                if (typeof el.getAnimations !== 'function') continue;
                const anims = el.getAnimations();
                if (anims.some(a => a.playState === 'running')) return true;
            }
            return false;
        }""")
    except Exception:
        return False


async def wait_until_verified(verify_fn, page, label, browser=None, cua_client=None,
                              max_retries=20, interval=3, verbose=False, phase=None):
    """Smart verification: DOM check first, then CUA diagnosis if failing.

    Phase 1 (retries 1-5): Quick DOM checks — maybe it just needs a moment.
    Phase 2 (retry 6): CUA diagnoses what's on screen.
    Phase 3 (retry 7): CUA tries to fix the issue (click buttons, dismiss dialogs).
    Phase 4 (retries 8-20): Continue DOM checks after CUA fix.
    """
    for i in range(max_retries):
        if await verify_fn(page):
            log(f"[{label}] ✓ Verified — actively generating")
            agent_key = normalize_agent_key(label)
            emit_event("agent_verified", phase=phase, agent=agent_key,
                verified=True, method="dom",
                message=f"{label} confirmed actively generating",
                attempts=i + 1)
            return True

        # Phase 1: Quick DOM checks
        if i < 5:
            log(f"[{label}] Not yet generating... check {i+1}/5")
            await asyncio.sleep(interval)
            continue

        # Phase 2: CUA diagnosis (once, at retry 6)
        if i == 5 and browser and cua_client:
            log(f"[{label}] DOM checks failed 5x — scrolling to bottom, asking CUA to diagnose...")
            await browser.switch_to_page(page)
            try:
                await page.evaluate("""() => {
                    window.scrollTo(0, document.body.scrollHeight);
                    document.querySelectorAll('[class*="react-scroll"], [class*="chat-messages"], main, [role="presentation"]')
                        .forEach(c => { try { c.scrollTop = c.scrollHeight; } catch(e){} });
                }""")
                await asyncio.sleep(0.4)
            except Exception:
                pass
            diag = await agent_loop(cua_client, browser, PROMPT_DIAGNOSE,
                "Look at the BOTTOM of the chat. Is there a Stop button visible? "
                "Is there a loading animation or spinner? Is the AI actively generating?",
                model=CUA_MODEL, max_iterations=3, verbose=verbose)
            diag_text = (diag.get("text") or "").lower()
            log(f"[{label}] CUA diagnosis: {diag.get('text', '')[:200]}")

            # Parse carefully — avoid false positives from "not still generating"
            has_stop = ("stop" in diag_text and "yes" in diag_text)
            # 2026-05-14: "progress bar" added as an alternate positive
            # signal. The post-Start DR card consistently surfaces a
            # progress bar in CUA's screenshot description, and unlike
            # "loading"/"spinning"/"animation" it doesn't require the
            # CUA's prompt to have answered "yes" — the phrase only
            # appears when the bar is actually present. Belt for the
            # case where DOM verify is still buggy.
            has_loading = (
                ("loading" in diag_text or "spinning" in diag_text or "animation" in diag_text)
                and "yes" in diag_text
            ) or "progress bar" in diag_text
            says_generating = "still generating" in diag_text and "not still generating" not in diag_text and "no" not in diag_text.split("still generating")[0][-20:]
            if has_stop or has_loading or says_generating:
                log(f"[{label}] ✓ CUA confirms generating")
                return True
            if "needs click" in diag_text or "start research" in diag_text:
                log(f"[{label}] CUA says button needs clicking")
                # Will be handled in Phase 3 (CUA fix)

            continue

        # Phase 3: CUA fix attempt (once, at retry 7)
        if i == 6 and browser and cua_client:
            log(f"[{label}] CUA attempting to fix the issue...")
            await browser.switch_to_page(page)
            fix = await agent_loop(cua_client, browser, PROMPT_FIX_ISSUE,
                "Fix whatever is blocking the research from starting. Click any needed buttons.",
                model=CUA_MODEL, max_iterations=10, verbose=verbose)
            log(f"[{label}] CUA fix attempt: {fix.get('text', '')[:200]}")
            await asyncio.sleep(5)
            continue

        # Phase 4: Continue DOM checks after CUA intervention
        log(f"[{label}] Post-fix check {i-6}/{max_retries-7}")
        await asyncio.sleep(interval)

    log(f"[{label}] ✗ Could not verify after {max_retries} attempts (including CUA)", "WARN")
    return False


# ── DOM Polling (zero CUA cost) ───────────────────────────────────────────────

_last_progress: dict = {}  # Deduplication cache for agent_progress events


# ── MutationObserver streaming (real-time partial text per agent page) ───
#
# We inject a throttled MutationObserver into each agent page that watches
# the assistant's response container. It fires `window.onStream({len,text})`
# every ~500ms while the response grows. The callback here updates a shared
# dict keyed by page id, so the poll loop (Phase 1 or Phase 2) can read the
# latest `observer_text_len` + `observer_preview` when it emits agent_progress.
#
# This gives the frontend true token-level streaming while the 30s DOM poll
# keeps structured fields (sources/sections/steps) fresh. No polling wasted
# on just-a-few-more-chars-every-second — the observer handles that slice.

_OBSERVER_SELECTORS = {
    "chatgpt": ['[data-message-author-role="assistant"]:last-of-type',
                'main [data-message-id]:last-of-type',
                'article.text-token-text-primary:last-of-type'],
    "gemini":  ['message-content:last-of-type',
                '.model-response-text:last-of-type',
                '.response-container:last-of-type'],
    "claude":  ['[data-testid="assistant-message"]:last-of-type',
                '.font-claude-message:last-of-type',
                '[data-is-streaming]:last-of-type'],
}

# Keyed by id(page) — each page gets its own stream state
_agent_streams: dict[int, dict] = {}


def _make_stream_callback(page_id: int):
    """Return a callback for page.expose_function('onStream', ...)"""
    def cb(data):
        try:
            st = _agent_streams.setdefault(page_id, {})
            st["observer_text_len"] = int(data.get("len", 0) or 0)
            # 2026-05-25: strip ChatGPT's PUA-delimited citation runs from
            # the streamed preview. Without this, ChatGPT DR's mid-flight
            # observer text gets emitted into `partialTextPreview` via
            # agent_progress events, and the FE wraps the unbreakable
            # citation blobs as a wall of low-information noise — exact
            # symptom in the user's 2026-05-25 P2 ChatGPT MD screenshot.
            # No-op for Gemini/Claude (no PUA sentinels in their DOM).
            st["observer_preview"] = _strip_chatgpt_citation_tokens(
                str(data.get("text", "") or "")
            )[:500]
            st["last_update"] = time.time()
        except Exception:
            pass
    return cb


async def inject_agent_observer(page, agent_key: str):
    """Inject a throttled MutationObserver on `page` that streams the assistant
    response's partial text length + last 500 chars to Python.

    Idempotent: re-call after navigations to re-attach. The exposed function
    `onStream` is registered once per page (Playwright will raise on
    re-expose — we catch that).
    """
    page_id = id(page)
    _agent_streams.setdefault(page_id, {
        "observer_text_len": 0, "observer_preview": "", "last_update": 0.0,
    })
    try:
        await page.expose_function("onStream", _make_stream_callback(page_id))
    except Exception:
        # Already exposed — safe to ignore, callback is already bound
        pass

    selectors = _OBSERVER_SELECTORS.get(agent_key, [])
    if not selectors:
        return False

    script = """
    (selectors) => {
        if (window.__agentObserver) {
            try { window.__agentObserver.disconnect(); } catch(e) {}
        }
        let container = null;
        for (const sel of selectors) {
            try { container = document.querySelector(sel); } catch(e) {}
            if (container) break;
        }
        if (!container) {
            window.__agentObserverActive = false;
            return false;
        }
        let lastLen = 0;
        let timer = null;
        const mo = new MutationObserver(() => {
            clearTimeout(timer);
            timer = setTimeout(() => {
                const text = container.innerText || '';
                if (text.length === lastLen) return;
                lastLen = text.length;
                try {
                    window.onStream({ text: text.slice(-500), len: text.length, ts: Date.now() });
                } catch(e) {}
            }, 500);
        });
        mo.observe(container, {childList: true, subtree: true, characterData: true});
        window.__agentObserver = mo;
        window.__agentObserverActive = true;
        return true;
    }
    """
    try:
        ok = await page.evaluate(script, selectors)
        return bool(ok)
    except Exception as e:
        log(f"[observer-{agent_key}] inject failed: {e}", "WARN")
        return False


async def inject_chatgpt_dr_iframe_observer(page) -> bool:
    """Inject MutationObserver INSIDE the cross-origin DR iframe (Block 1b).

    The host-page observer (inject_agent_observer) cannot see iframe content
    because the iframe is cross-origin. Without this, partial_text_len
    flatlines while the DR iframe is actively streaming the report.

    Mirrors host-page observer state into the same _agent_streams[id(page)]
    entry by taking max(host_len, iframe_len), so get_observer_state(page)
    naturally reads the combined value.

    Gated by DG_CHATGPT_IFRAME_OBSERVER=1 (off by default — opt-in).
    Returns True if injected, False if no DR iframe found / inject failed.
    """
    target_frame = None
    for frame in page.frames:
        try:
            src = (frame.url or "").lower()
        except Exception:
            continue
        if not src:
            continue
        if ("deep_research" in src or "oaiusercontent" in src
                or "web-sandbox.oaiusercontent" in src):
            target_frame = frame
            break
    if not target_frame:
        return False

    page_id = id(page)
    _agent_streams.setdefault(page_id, {
        "observer_text_len": 0, "observer_preview": "", "last_update": 0.0,
    })

    def _iframe_cb(data):
        try:
            iframe_len = int(data.get("len", 0) or 0)
            # 2026-05-25: strip ChatGPT's PUA-delimited citation runs from
            # iframe-side observer preview. This callback fires for the DR
            # sandbox iframe specifically — the same noise source as the
            # host-page callback above (citation tokens render to the DR
            # canvas DOM). Mirror the host-side strip so both observer
            # paths emit clean text.
            iframe_preview = _strip_chatgpt_citation_tokens(
                str(data.get("text", "") or "")
            )[:500]
            st = _agent_streams.setdefault(page_id, {})
            # Take max — host and iframe observers may both fire
            if iframe_len > int(st.get("observer_text_len", 0) or 0):
                st["observer_text_len"] = iframe_len
                st["observer_preview"] = iframe_preview
                st["last_update"] = time.time()
        except Exception:
            pass

    try:
        await target_frame.expose_function("onStreamIframe", _iframe_cb)
    except Exception:
        # Already exposed — safe to ignore
        pass

    iframe_selectors = ['main', 'article', '[class*="report"]', 'body']
    script = """
    (selectors) => {
        if (window.__agentObserverIframe) {
            try { window.__agentObserverIframe.disconnect(); } catch(e) {}
        }
        let container = null;
        for (const sel of selectors) {
            try { container = document.querySelector(sel); } catch(e) {}
            if (container) break;
        }
        if (!container) {
            window.__agentObserverIframeActive = false;
            return false;
        }
        let lastLen = 0;
        let timer = null;
        const mo = new MutationObserver(() => {
            clearTimeout(timer);
            timer = setTimeout(() => {
                const text = container.innerText || '';
                if (text.length === lastLen) return;
                lastLen = text.length;
                try {
                    window.onStreamIframe({ text: text.slice(-500), len: text.length, ts: Date.now() });
                } catch(e) {}
            }, 500);
        });
        mo.observe(container, {childList: true, subtree: true, characterData: true});
        window.__agentObserverIframe = mo;
        window.__agentObserverIframeActive = true;
        return true;
    }
    """
    try:
        ok = await target_frame.evaluate(script, iframe_selectors)
        if ok:
            log("[observer-chatgpt-iframe] injected into DR iframe", "INFO")
        return bool(ok)
    except Exception as e:
        log(f"[observer-chatgpt-iframe] inject failed: {e}", "WARN")
        return False


def get_observer_state(page) -> dict:
    """Read the latest MutationObserver snapshot for this page.
    Returns {} if observer hasn't been injected or hasn't fired yet."""
    try:
        return _agent_streams.get(id(page), {}) or {}
    except Exception:
        return {}


_VISION_URL_SCHEMA = {
    "type": "OBJECT",
    "properties": {
        "urls": {"type": "ARRAY", "items": {"type": "STRING"}},
        "confidence": {"type": "NUMBER"},
    },
    "required": ["urls", "confidence"],
}

_VISION_URL_PROMPT = (
    "Extract every source URL visible in this screenshot of an AI research "
    "panel (ChatGPT/Claude/Gemini side panel showing cited sources).\n"
    "RULES:\n"
    "1. Output only http:// or https:// URLs, verbatim.\n"
    "2. Skip platform chrome: chatgpt.com, openai.com, oaiusercontent, "
    "claude.ai, anthropic.com, gemini.google.com, accounts.google.com.\n"
    "3. If a URL is truncated with '...', skip it entirely. Never invent.\n"
    "4. confidence: 0.7+ if URLs read clearly, 0.4-0.7 partial, <0.4 if "
    "no URLs visible (return empty list)."
)

_VISION_URL_SKIP_DOMAINS = (
    "chatgpt.com", "openai.com", "oaiusercontent",
    "claude.ai", "anthropic.com",
    "gemini.google.com", "accounts.google.com",
)


async def extract_source_urls_via_vision(page, agent_key: str,
                                          last_dom_count: int = 0) -> list:
    """Vision-extract source URLs from the agent's side panel (Block 3).

    Used as a supplementary signal when DOM scraping misses URLs (collapsed
    rows, popovers, lazy-loaded content, anchor-less click targets). Returns
    list of validated http(s) URLs (deduped, length-capped, platform-chrome
    filtered). Empty list on any failure — caller treats as no-op union.

    Disabled by setting DG_VISION_URL_EXTRACT=0.
    """
    api_key = resolve_gemini_api_key()
    if not api_key:
        return []

    try:
        png = await page.screenshot(type="png", full_page=False)
    except Exception as e:
        log(f"[{agent_key}] vision-urls screenshot failed: {e}", "DEBUG")
        return []

    # Crop heuristic: ChatGPT/Gemini panels are right ~45%; Claude artifact
    # panel can be center/right depending on layout — keep full frame.
    try:
        from narrate import _crop_right_fraction
        if agent_key in ("chatgpt", "gemini"):
            png = _crop_right_fraction(png, 0.45)
    except Exception:
        pass

    user_msg = (
        f"Agent: {agent_key}. DOM scrape found {last_dom_count} URLs. "
        "Extract every additional source URL visible in the side panel."
    )

    # Model resolved from models.GEMINI_NARRATE (env override:
    # GEMINI_NARRATE_MODEL). Default GA target 2026-05: gemini-3.5-flash.
    model = GEMINI_NARRATE
    url = (f"https://generativelanguage.googleapis.com/v1beta/models/"
           f"{model}:generateContent?key={api_key}")
    payload = {
        "contents": [{
            "role": "user",
            "parts": [
                {"inlineData": {
                    "mimeType": "image/png",
                    "data": base64.standard_b64encode(png).decode("ascii"),
                }},
                {"text": user_msg},
            ],
        }],
        "systemInstruction": {"parts": [{"text": _VISION_URL_PROMPT}]},
        "generationConfig": {
            "temperature": 0.0,
            "maxOutputTokens": 800,
            "responseMimeType": "application/json",
            "responseSchema": _VISION_URL_SCHEMA,
        },
    }

    def _sync_call():
        try:
            import requests as _req
            resp = _req.post(url, json=payload, timeout=10.0)
            if resp.status_code != 200:
                log(f"[{agent_key}] vision-urls http {resp.status_code}: "
                    f"{resp.text[:140]}", "WARN")
                return [], 0.0
            j = resp.json()
            text = (j.get("candidates", [{}])[0]
                      .get("content", {}).get("parts", [{}])[0]
                      .get("text", ""))
            data = json.loads(text)
            return (data.get("urls") or []), float(data.get("confidence", 0) or 0)
        except Exception as e:
            log(f"[{agent_key}] vision-urls call/parse error: {e}", "WARN")
            return [], 0.0

    try:
        raw_urls, conf = await asyncio.to_thread(_sync_call)
    except Exception as e:
        log(f"[{agent_key}] vision-urls call failed: {e}", "WARN")
        return []

    if conf < 0.4 or not raw_urls:
        return []

    # Validate + filter — drop anything that isn't a real http(s) URL or
    # references platform chrome.
    filtered = []
    seen = set()
    for u in raw_urls:
        if not isinstance(u, str):
            continue
        u = u.strip()
        if not (u.startswith("http://") or u.startswith("https://")):
            continue
        if len(u) > 500:
            continue
        if u in seen:
            continue
        if any(d in u.lower() for d in _VISION_URL_SKIP_DOMAINS):
            continue
        seen.add(u)
        filtered.append(u)
    return filtered[:50]


class _BriefStreamStalled(Exception):
    """Raised by poll_until_done when ChatGPT's brief stream goes flat on
    text + sources + steps for STALL_THRESHOLD_SEC. Distinct from a wall-
    clock timeout so the P1 caller can show stall-specific copy
    ('ChatGPT stream stalled — text + sources flat for 20 min') instead
    of the legacy 'Brief generation timed out after 45 min' message."""
    pass


async def poll_until_done(page, verify_fn, label, poll_interval, max_wait_min,
                          browser=None, cua_client=None, verbose=False, phase=2):
    """Poll page until response is complete. Smart: uses CUA to check if DOM selectors fail."""
    wait_start = time.time()
    max_wait = max_wait_min * 60
    paused_total = 0.0  # accumulator: time spent in wait_if_paused (pause-aware)
    consecutive_not_generating = 0
    cua_checked = False
    last_heartbeat = time.time()
    # ── ChatGPT activity-strip open state (P1 only — Phase1 / Phase1-followup) ──
    # Mirrors the per-agent dict P2 round-robin uses, scoped to this single
    # poll call. Flips _panel_open_done True on first verified open. DOM
    # misses count both "found:false" AND "clicked but verify:false". CUA
    # tier-3 capped at 1/call. The same robust helper (research.py:5048)
    # works regardless of phase — Pro+ET in P1 produces the same React-
    # rendered styled <div> strip that DR in P2 does.
    _panel_open_done = False
    _panel_dom_misses = 0
    _panel_cua_attempts = 0
    _panel_poll_cycles = 0  # ticks once per ChatGPT P1 poll while panel still closed
    # Stall detector — multi-signal (2026-04-25 strictness rewrite):
    # tracks text + sources + steps. ChatGPT DR's "researching" phase
    # legitimately produces zero text growth for 5-15 min while sources
    # and steps accumulate, so a text-only stall detector false-fired
    # during normal in-progress work. Now stall fires only when ALL
    # THREE signals flatline for 20 min (was 10 min text-only) AND the
    # detector still says "generating" — a genuinely-done response is
    # caught earlier by the verify_fn=False completion path.
    last_seen_len = 0
    last_seen_sources = 0
    last_seen_steps_sig = 0
    stall_window_start = None  # time.time() when ALL signals stopped growing
    STALL_THRESHOLD_SEC = 1200  # 20 min of multi-signal flatness → likely stuck
    # 2026-05-25: secondary safety-net CUA escalation at 5 min of flatness
    # (well before the 20 min stall-surface). The polling loop's existing
    # CUA path only fires when verify_fn returns False — if DOM detection
    # has a false-positive that keeps verify returning True forever, CUA
    # never gets asked. This safety-net triggers a visual CUA confirm
    # solely on content-flat-while-detector-says-generating. CUA can
    # override the stuck DOM read and let us extract early. Per-agent
    # gated so verify_fn != verify_chatgpt_generating skips the diagnostic
    # (other verify functions don't have a matching diag helper yet) but
    # the CUA escalation still fires. Tracked separately from cua_checked
    # so it doesn't collide with the verify-False path.
    SAFETY_NET_CUA_SEC = 300
    safety_net_cua_asked = False

    # 2026-05-06 (Stream 2 D2): no inner wall-clock cap. The outer
    # _await_phase_with_active_deadline at the call site is the sole
    # ceiling (P1: 60m advisory soft-warn). paused_total / max_wait
    # accumulators kept as harmless dead state to preserve the function
    # signature; only the multi-signal stall detector below raises
    # _BriefStreamStalled.
    while True:
        # ── Browser-crash detection ──
        # If the underlying tab closed unexpectedly (Chromium crash, OOM,
        # user closed it, profile lock fight) every page op below will
        # raise. Emit Template A/B alert and return False so the caller
        # advances to the await_*_decision path.
        try:
            if page.is_closed():
                log(f"[{label}] Browser tab closed unexpectedly", "WARN")
                _ag_norm_crash = normalize_agent_key(label)
                # Browser crashes are always-auto: human can't do anything
                # useful here, so emit passive banner and let the outer
                # auto-retry rebuild the session. last_failure_kind tells
                # run_pipeline.finally to bypass the not-resume_dir gate.
                _runtime.last_failure_kind = "browser_crash"
                emit_browser_recovery_status(
                    phase, agent=_ag_norm_crash if (phase == 2 and _ag_norm_crash) else None)
                return False
        except Exception:
            # is_closed() itself can throw if the page handle is already
            # garbage; treat that as a crash too.
            log(f"[{label}] Page handle invalid — treating as crash", "WARN")
            _ag_norm_crash = normalize_agent_key(label)
            _runtime.last_failure_kind = "browser_crash"
            emit_browser_recovery_status(
                phase, agent=_ag_norm_crash if (phase == 2 and _ag_norm_crash) else None)
            return False
        # ── Stop/Pause check ──
        if _controls.is_stop():
            log(f"[{label}] STOP requested — aborting poll")
            return False
        # ── Skip checks (agent-level + phase-level) ──
        # Honor the same skip set the round-robin uses, so a user "Skip"
        # tap inside a P1 brief poll exits cleanly (poll loops historically
        # ignored skipped_agents and ran until the wall-clock cap).
        _ag_norm = normalize_agent_key(label)
        if _ag_norm and _ag_norm in (_controls.skipped_agents or set()):
            log(f"[{label}] SKIP requested for agent — aborting poll")
            return False
        if _controls.consume_phase_skip(phase):
            log(f"[{label}] SKIP requested for phase {phase} — aborting poll")
            return False
        if _controls.is_pause():
            emit_event("pipeline_paused", phase=phase)
            _pause_t0 = time.monotonic()
            await _controls.wait_if_paused()
            _this_pause = time.monotonic() - _pause_t0
            paused_total += _this_pause
            # Don't count user pause time toward stall — push the stall
            # window forward so a long pause doesn't false-fire on the
            # next post-resume tick.
            if stall_window_start is not None:
                stall_window_start += _this_pause
            if _controls.is_stop():
                log(f"[{label}] STOP after pause — aborting poll")
                return False
            # Pause+input+resume = rerun the phase from the start. Bail out so
            # the orchestrator can detect `_runtime.restart_requested` and loop.
            if _controls.peek_extra_context():
                _runtime.restart_requested = True
                log(f"[{label}] Extra context during pause — signalling phase restart")
                return False

        # ── Heartbeat every 60s so frontend knows we're alive ──
        if time.time() - last_heartbeat >= 60:
            emit_event("heartbeat", phase=phase, agent=normalize_agent_key(label))
            last_heartbeat = time.time()

        # Scrape progress FIRST — every cycle, regardless of state
        scrape_fn = SCRAPE_FNS.get(label)
        if scrape_fn:
            try:
                progress = await scrape_fn(page)
                # Hoisted from dedupe block — needed by panel-open gate below.
                elapsed_sec = int(time.time() - wait_start)

                # ── ChatGPT activity-strip open (P1 mirror of P2 round-robin) ──
                # Pro+ET sometimes does mid-thinking web searches → "Looking
                # into X… N searches" strip at bottom of chat. Same robust
                # DOM helper (walks * + dispatches full event chain — v1
                # narrow selector matched 0 candidates because the strip is
                # a styled <div>). Gate: 180s wall-clock. After 2 DOM misses
                # → CUA tier-3 (capped 1/call). Only fires for ChatGPT P1
                # entry points; Gemini/Claude have own paths.
                if label in ("Phase1", "Phase1-followup") and not _panel_open_done:
                    _panel_poll_cycles += 1
                if (label in ("Phase1", "Phase1-followup")
                        and (_panel_poll_cycles >= 2 or elapsed_sec >= 60)
                        and not _panel_open_done):
                    try:
                        res = await _open_chatgpt_activity_panel(page)
                        cands = (res or {}).get("candidates", 0)
                        if not res or not res.get("found"):
                            _panel_dom_misses += 1
                            log(f"[{label}] panel DOM miss #{_panel_dom_misses} "
                                f"(elapsed={elapsed_sec}s, walked_hits={cands}) — "
                                f"strip not yet rendered or wording changed", "DEBUG")
                        elif res.get("alreadyExpanded"):
                            _panel_open_done = True
                            log(f"[{label}] activity panel already expanded at "
                                f"elapsed={elapsed_sec}s — label: \"{res.get('label','')[:80]}\"")
                        elif res.get("clicked"):
                            await asyncio.sleep(2.0)
                            verified = await _verify_chatgpt_panel_open(page)
                            if verified:
                                _panel_open_done = True
                                log(f"[{label}] activity panel opened via DOM at "
                                    f"elapsed={elapsed_sec}s — clickedTag={res.get('clickedTag','?')}")
                            else:
                                _panel_dom_misses += 1
                                log(f"[{label}] DOM clicked but panel didn't render — "
                                    f"miss #{_panel_dom_misses}", "WARN")
                        else:
                            _panel_dom_misses += 1
                            log(f"[{label}] panel found but click failed — "
                                f"err={res.get('error','?')}", "WARN")
                    except Exception as _pe:
                        log(f"[{label}] activity panel open failed: {_pe}", "WARN")
                        _panel_dom_misses += 1

                    # CUA tier-3 escalation after 2 DOM misses (capped at 1/call).
                    if (not _panel_open_done
                            and _panel_dom_misses >= 2
                            and _panel_cua_attempts == 0
                            and cua_client and browser):
                        log(f"[{label}] DOM missed strip 2x — escalating to CUA tier-3 "
                            f"(elapsed={elapsed_sec}s)")
                        emit_tier_transition(phase=phase, agent="chatgpt",
                            op="open_activity_panel_p1", from_tier="dom",
                            to_tier="cua", reason="dom_2_misses")
                        _panel_cua_attempts = 1
                        async def _cgpt_p1_cua():
                            return await asyncio.wait_for(
                                agent_loop(cua_client, browser,
                                    PROMPT_OPEN_CHATGPT_SOURCE_PANEL,
                                    "Open the activity strip at the bottom of this ChatGPT "
                                    "Pro/Thinking conversation. ONE click only. Verify the "
                                    "side panel slides out before reporting.",
                                    model=CUA_MODEL, max_iterations=5,
                                    verbose=verbose, target_page=page),
                                timeout=120.0)
                        try:
                            cua_res = await _shadow_observed_cua(
                                page, hotspot_id="7c-p1", phase=phase, platform="chatgpt",
                                current_step="open_activity_panel_p1",
                                context_hint=f"P1 brief poll DOM 2-miss at elapsed={elapsed_sec}s",
                                expected_outcome="side panel mounts on right with step list",
                                cua_coro_factory=_cgpt_p1_cua)
                            out = ((cua_res or {}).get("text") or "").lower()
                            if "panel: open" in out or "panel: already_open" in out:
                                _panel_open_done = True
                                log(f"[{label}] activity panel opened via CUA tier-3")
                            else:
                                log(f"[{label}] CUA tier-3 didn't confirm panel: {out[:120]}", "WARN")
                        except asyncio.TimeoutError:
                            log(f"[{label}] CUA tier-3 timed out after 120s", "WARN")
                        except Exception as _ce:
                            log(f"[{label}] CUA tier-3 failed: {_ce}", "WARN")

                # Enrich with MutationObserver data (token-level stream)
                _obs = get_observer_state(page)
                _obs_len = _obs.get("observer_text_len", 0) or 0
                _obs_preview = _obs.get("observer_preview", "") or ""
                # partialTextLen is max of DOM scrape + observer (observer is usually fresher)
                _merged_partial_len = max(progress.get("partial_text_len", 0) or 0, _obs_len)
                # Multi-signal stall tracking (2026-04-25): stamp time when
                # ALL signals stop growing; reset on any growth in any
                # signal. ChatGPT DR's researching phase produces no text
                # growth but sources and steps continue — text-only stall
                # detection false-fired during legit in-progress work.
                # observed_sources (Claude text count, ChatGPT vision count)
                # captures growth that URL extraction can't see. Treat as
                # liveness signal so the stall window doesn't open during
                # legit URL-light progress.
                _p1_sources = max(
                    int(progress.get("sources", 0) or 0),
                    int(progress.get("observed_sources", 0) or 0),
                )
                _p1_steps_sig = len(progress.get("steps", []) or [])
                _grew = (_merged_partial_len > last_seen_len
                         or _p1_sources > last_seen_sources
                         or _p1_steps_sig > last_seen_steps_sig)
                if _grew:
                    last_seen_len = max(last_seen_len, _merged_partial_len)
                    last_seen_sources = max(last_seen_sources, _p1_sources)
                    last_seen_steps_sig = max(last_seen_steps_sig, _p1_steps_sig)
                    stall_window_start = None
                    # Content actively growing → arm safety-net for the
                    # next flat window. Without this reset, a single CUA
                    # safety-net trigger early in the run would suppress
                    # re-checks even if a real stall hits later.
                    safety_net_cua_asked = False
                elif (_merged_partial_len > 0 or _p1_sources > 0) and stall_window_start is None:
                    stall_window_start = time.time()
                # Vision fallback merge (Gemini Flash) — fills gaps when the
                # DOM walker returns empty + provides richer narration. Cooldown
                # / budget enforced inside narrate.narrate_panel. Two
                # triggers: (a) walker is empty/ET-state past the 60s warmup,
                # or (b) every Nth poll for a fresh narration sentence even
                # when the walker IS producing data.
                _vn_steps_n = len(progress.get("steps", []) or [])
                _vn_progress_str = (progress.get("progress") or "").strip()
                _vn_sources = int(progress.get("sources", 0) or 0)
                _vn_panel_open = bool(progress.get("panel_open", False))
                # 2026-04-29: aggressive vision narration cadence. With a
                # working GEMINI_API_KEY the narrator should fire often
                # enough that the FE always has a fresh sentence. Lowered
                # the DOM-empty warmup from 60s → 20s and the panel-open
                # gate from 90s → 30s. The narrator's own MIN_GAP_S
                # (30s default) bounds the actual call frequency, so
                # these warmups just decide WHEN the first call happens.
                _vn_should_call = (
                    elapsed_sec > 20
                    and _vn_steps_n < 2
                    and _vn_sources == 0
                ) or (
                    elapsed_sec > 30 and _vn_panel_open
                )
                # Force every Nth poll so the narrator fires even when
                # DOM is producing data (keeps FE narration fresh during
                # rich-DOM windows). Default 2 (every other poll).
                _vn_force_every_n = int(os.environ.get("GEMINI_NARRATE_FORCE_EVERY_N", "2"))
                if _vn_force_every_n > 0 and elapsed_sec > 0:
                    try:
                        _poll_interval = max(int(POLL_PRO if phase == 1 else POLL_DEEP_RESEARCH), 1)
                    except Exception:
                        _poll_interval = 30
                    _poll_tick = elapsed_sec // _poll_interval
                    if _poll_tick > 0 and _poll_tick % _vn_force_every_n == 0:
                        _vn_should_call = True
                _vision_data = None
                _scrape_source = "dom"
                _vision_narration = ""
                _vision_phase_signal = ""
                if _vn_should_call:
                    try:
                        import narrate as _vn
                        _vision_data = await _vn.narrate_panel(
                            page,
                            agent=normalize_agent_key(label),
                            phase=phase,
                            workflow_name=label,
                            last_dom_progress=_vn_progress_str,
                            last_dom_sources=_vn_sources,
                            last_dom_steps_n=_vn_steps_n,
                        )
                    except Exception as _vne:
                        log(f"[{label}] narrate failed: {_vne}", "DEBUG")
                        _vision_data = None
                # Confidence floor lowered 0.4 → 0.3 (2026-04-29). The
                # narrator self-tags low-confidence reads as < 0.4 when
                # the panel is closed/empty, so 0.3 still filters the
                # totally-blank cases while accepting "partial-but-real"
                # narration the user benefits from seeing.
                if _vision_data and float(_vision_data.get("confidence", 0)) >= 0.3:
                    _scrape_source = "vision"
                    _vision_narration = _vision_data.get("narration", "")
                    _vision_phase_signal = _vision_data.get("phase_signal", "") or ""
                    _v_progress = _vision_data.get("progress", "")
                    if _v_progress and len(_v_progress) > len(_vn_progress_str):
                        progress["progress"] = _v_progress
                    _v_steps = _vision_data.get("steps") or []
                    if _v_steps:
                        _seen = set(s[:80] for s in (progress.get("steps") or []))
                        _merged = list(progress.get("steps") or [])
                        for s in _v_steps:
                            k = s[:80]
                            if k not in _seen:
                                _seen.add(k); _merged.append(s)
                        progress["steps"] = _merged[-15:]
                    if (not progress.get("sections")) and _vision_data.get("sections"):
                        progress["sections"] = _vision_data["sections"]
                    # Vision-derived source-count estimate. Kept SEPARATE from
                    # progress["sources"] (URL-derived) so the chip count and
                    # the expanded URL list never disagree. Watchdog can still
                    # see this signal via observed_sources.
                    _so = int(_vision_data.get("sources_observed") or 0)
                    if _so > 0:
                        progress["observed_sources"] = _so
                    log(f"[{label}] narrate hit: phase_signal={_vision_data.get('phase_signal')} "
                        f"conf={_vision_data.get('confidence',0):.2f} steps+={len(_v_steps)} "
                        f"narration=\"{_vision_narration[:80]}\"", "INFO")

                # Deduplicate: emit if data changed OR every 30s (elapsed_bucket).
                # Without elapsed_bucket, P1's Extended Thinking window (5-15 min
                # of zero text/source growth) would suppress every emit for the
                # whole window, leaving the FE stuck on "Opening ChatGPT…". The
                # 30s tick guarantees the dropdown narration stays alive — same
                # pattern P2's round-robin polling uses.
                # elapsed_sec hoisted to top of try block for panel-open gate.
                progress_key = json.dumps({
                    "status": progress.get("status", ""),
                    "sources": progress.get("sources", 0),
                    "partialTextLen": _merged_partial_len,
                    "sections_len": len(progress.get("sections", [])),
                    "steps_len": len(progress.get("steps", []) or []),
                    # Coarse-bucket the observer length so small bumps don't spam Firestore
                    "obs_bucket": _merged_partial_len // 200,
                    # 30s tick keeps narration live during long ET windows
                    "elapsed_bucket": elapsed_sec // 30,
                    # Vision narration changes should also break the dedupe
                    "vision_n": _vision_narration[:60] if _vision_narration else "",
                    # Without progress_label + tool_uses, transitions like
                    # "Reading source 3" → "Reading source 4" with no text-len /
                    # source delta get suppressed and starve the watchdog.
                    "progress_label": (progress.get("progress", "") or "")[:80],
                    "tool_uses_len": len(progress.get("tool_uses", []) or []),
                    # Without these, a search-count change alone (or a
                    # sectionsDone tick) gets suppressed by every other
                    # field staying constant — leaving the FE chart
                    # series flat through whole search bursts. The
                    # graphs need these deltas to draw real curves.
                    "searches": int(progress.get("searches", 0) or 0),
                    "sections_done": int(progress.get("sections_done", 0) or 0),
                    "sections_total": int(progress.get("sections_total", 0) or 0),
                    "observed_sources": int(progress.get("observed_sources", 0) or 0),
                }, sort_keys=True)
                # Phase prefix: _last_progress is process-global, so without
                # it a P1 entry could dedupe a P2 emit with the same key.
                _dedupe_key = f"p{phase}:{label}"
                if _last_progress.get(_dedupe_key) != progress_key:
                    _last_progress[_dedupe_key] = progress_key
                    expected_min = get_expected_minutes(phase)
                    # Loosen ET gate: P1 brief mode (Pro + Extended Thinking, NOT
                    # Deep Research) returns status="idle" pre-stream because
                    # scrape_progress_chatgpt has no DR signals + zero tokens.
                    # We're inside poll_until_done so by definition the agent
                    # IS working — show "Extended Thinking active" rather than
                    # the stale pre-poll string ("Opening ChatGPT…").
                    is_et = (progress.get("status") in ("generating", "idle")
                             and progress.get("sources", 0) == 0
                             and _merged_partial_len < 500)
                    if is_et:
                        # Agent-specific label: ChatGPT kept "Extended Thinking",
                        # Claude renamed to "Adaptive Thinking", Gemini uses
                        # "Planning" (pre-research planning step). Emitting the
                        # wrong label on Claude misleads users into thinking a
                        # deprecated setting is on.
                        _nk = normalize_agent_key(label)
                        _think_label = (
                            "Adaptive Thinking" if _nk == "claude" else
                            "Planning" if _nk == "gemini" else
                            "Extended Thinking"
                        )
                        progress["status"] = "extended_thinking"
                        # Prefer vision's rich narration over the generic
                        # "<X> active" fallback when vision gave us a
                        # confident reading. Otherwise build a dynamic
                        # fallback from whatever DOM data we have so the
                        # dropdown isn't a static "Extended Thinking
                        # active" string for the entire 10-20 min ET
                        # window. Includes elapsed minutes + drafted
                        # chars when those grow — gives the user
                        # something to watch even when vision is between
                        # cooldown ticks.
                        if _vision_narration:
                            progress["progress"] = _vision_narration
                        else:
                            # Elapsed time deliberately omitted — the parent
                            # phase card already shows "N.N min elapsed" at the
                            # top of the progress bar; duplicating it on the
                            # agent narration line is just visual noise.
                            _et_parts = [f"{_think_label} active"]
                            if _merged_partial_len >= 200:
                                _et_parts.append(f"{_merged_partial_len:,} chars drafted")
                            progress["progress"] = " · ".join(_et_parts)
                    agent_key = normalize_agent_key(label)
                    emit_event("agent_progress", phase=phase, agent=agent_key,
                        status=progress.get("status", ""),
                        progress=progress.get("progress", ""),
                        sources=progress.get("sources", 0),
                        sourceUrls=progress.get("source_urls", []),
                        sections=progress.get("sections", []),
                        partialTextLen=_merged_partial_len,
                        partialTextPreview=_obs_preview,
                        model=progress.get("model", ""),
                        thinking=progress.get("thinking", ""),
                        steps=progress.get("steps", []),
                        plan=progress.get("plan", ""),
                        toolUses=progress.get("tool_uses", []),
                        title=progress.get("title", ""),
                        scrapeHealth="limited" if is_et else "full",
                        scrapeSource=_scrape_source,
                        visionNarration=_vision_narration,
                        phaseSignal=_vision_phase_signal,
                        panelOpen=bool(progress.get("panel_open", False)),
                        observedSources=int(progress.get("observed_sources", 0) or 0),
                        searches=int(progress.get("searches", 0) or 0),
                        elapsedSec=elapsed_sec,
                        expectedMinutes=expected_min,
                    )
                    # Append a snapshot to the per-agent history ring so
                    # post-completion graphs / sparklines have a real time
                    # series, not just end-state scalars. Capped at 240 raw
                    # entries; downsampled to 60 at finalize time.
                    try:
                        _hist = _runtime.agent_progress_history.setdefault(agent_key, [])
                        _hist.append({
                            "t": int(elapsed_sec * 1000),
                            "sources": int(progress.get("sources", 0) or 0),
                            "chars": int(_merged_partial_len or 0),
                            "sections": int(len(progress.get("sections", []) or [])),
                            "searches": int(progress.get("searches", 0) or 0),
                            "sectionsDone": int(progress.get("sections_done", 0) or 0),
                            "sectionsTotal": int(progress.get("sections_total", 0) or 0),
                        })
                        if len(_hist) > 240:
                            del _hist[:len(_hist) - 240]
                    except Exception:
                        pass
            except Exception:
                pass

        generating = await verify_fn(page)

        if not generating:
            consecutive_not_generating += 1

            # First "not generating" could be a DOM selector issue or a
            # split-second between tokens. Drop to 2-consecutive (was 3)
            # — saves 30s of slack per phase. The DOM selectors are tight
            # post-2026-04 overhaul; false-positive risk is low. CUA is
            # still the visual fallback after 2 consecutive.
            if consecutive_not_generating <= 1:
                await asyncio.sleep(5)
                continue

            # After 2 consecutive "not generating" — ask CUA to verify
            if not cua_checked and browser and cua_client:
                agent_key = normalize_agent_key(label)
                log(f"[{label}] DOM says not generating after {int(time.time() - wait_start)}s — scrolling + CUA visual confirm...")
                await browser.switch_to_page(page)
                try:
                    await page.evaluate("""() => {
                        window.scrollTo(0, document.body.scrollHeight);
                        document.querySelectorAll('[class*="react-scroll"], [class*="chat-messages"], main, [role="presentation"]')
                            .forEach(c => { try { c.scrollTop = c.scrollHeight; } catch(e){} });
                    }""")
                    await asyncio.sleep(0.4)
                except Exception:
                    pass
                diag = await agent_loop(cua_client, browser, PROMPT_DIAGNOSE,
                    "Look at the BOTTOM of the chat (composer / end of response). "
                    "Is there a Stop button visible? Is there a loading animation or 'Researching...' indicator? "
                    "If a Stop button is visible anywhere, say 'still generating'. "
                    "Only say 'response complete' if there is NO stop button AND the final paragraph of the response is visible.",
                    model=CUA_MODEL, max_iterations=3, verbose=verbose)
                # CRITICAL: A structural CUA failure (workspace cap, 401, 529,
                # etc.) returns {"status": "error", "text": str(exception)}.
                # Previously that error text fell through the heuristic parse
                # below and hit the "assume complete" default, silently
                # advancing the phase on a dead CUA call. Now: skip CUA this
                # tick, trust the DOM check on the next poll. The underlying
                # Anthropic error has already been surfaced to the frontend
                # via pipeline_error by agent_loop's own error handler.
                if diag.get("status") == "error":
                    log(f"[{label}] CUA diagnostic unavailable ({(diag.get('text') or '')[:80]}) — "
                        f"falling back to DOM for this poll tick", "WARN")
                    cua_checked = False
                    await asyncio.sleep(poll_interval)
                    continue
                diag_text = (diag.get("text") or "").lower()
                cua_checked = True

                # Parse CUA response: look for the deterministic conclusion phrase
                is_generating = False
                is_complete = False
                if "response complete" in diag_text:
                    is_complete = True
                elif "still generating" in diag_text:
                    is_generating = True
                elif "needs click" in diag_text:
                    is_generating = True  # Needs intervention, not done yet
                else:
                    # Fallback: count YES/NO answers about stop button and loading
                    has_stop = ("stop" in diag_text and "yes" in diag_text.split("stop")[0][-30:])
                    has_loading = ("loading" in diag_text and "yes" in diag_text.split("loading")[0][-30:])
                    has_response = ("completed" in diag_text or "response visible" in diag_text) and "yes" in diag_text
                    if has_stop or has_loading:
                        is_generating = True
                    elif has_response:
                        is_complete = True
                    else:
                        is_complete = True  # Default: if unclear, assume complete (don't get stuck)

                if is_generating:
                    log(f"[{label}] CUA says still generating — continuing poll")
                    consecutive_not_generating = 0
                    cua_checked = False
                    if "needs click" in diag_text:
                        await agent_loop(cua_client, browser, PROMPT_FIX_ISSUE,
                            "Click whatever button needs clicking.", model=CUA_MODEL, max_iterations=5, verbose=verbose)
                        await asyncio.sleep(5)
                    else:
                        await asyncio.sleep(poll_interval)
                    continue
                else:
                    log(f"[{label}] CUA confirms response complete ✓")

            # Double-check DOM
            await asyncio.sleep(3)
            still = await verify_fn(page)
            if not still:
                elapsed = int(time.time() - wait_start)
                log(f"[{label}] Response complete ({elapsed}s)")
                return True
        else:
            consecutive_not_generating = 0
            cua_checked = False  # Reset so CUA can check again if needed

            # 2026-05-25 safety-net CUA escalation: content flat 5+ min
            # while detector says generating → most likely a DOM-detector
            # false-positive (Salaar/Kalki movie briefs hit this when
            # CSS-animation / card-progress / data-streaming-attr checks
            # match persistent post-stream-end UI chrome). Without this
            # path the loop would wait the full 20 min STALL_THRESHOLD_SEC
            # before surfacing Retry/Skip to the user — way too slow.
            # Diagnostic log captures WHICH verify check is firing so a
            # follow-up commit can fix the root cause; CUA visual confirm
            # is the immediate mitigation.
            if (browser and cua_client
                    and stall_window_start is not None
                    and (time.time() - stall_window_start) > SAFETY_NET_CUA_SEC
                    and not safety_net_cua_asked):
                safety_net_cua_asked = True
                _flat_sec = int(time.time() - stall_window_start)
                # Diagnostic: log which verify path is producing the
                # false-positive. ChatGPT-only for now — other verify
                # functions don't have a matching diag helper. Doesn't
                # block the CUA call if the diag eval fails.
                _verify_fn_name = getattr(verify_fn, "__name__", "")
                if _verify_fn_name == "verify_chatgpt_generating":
                    try:
                        _diag_reason = await _verify_chatgpt_generating_diag(page)
                        log(f"[{label}] Safety-net diag: verify_chatgpt_generating "
                            f"true via [{_diag_reason}] "
                            f"(text={last_seen_len}, sources={last_seen_sources}, "
                            f"steps={last_seen_steps_sig}, flat={_flat_sec}s)", "INFO")
                    except Exception as _sde:
                        log(f"[{label}] Safety-net diag failed: {_sde}", "DEBUG")
                log(f"[{label}] Safety-net: content flat for {_flat_sec}s while "
                    f"detector says generating — CUA visual confirm "
                    f"(threshold={SAFETY_NET_CUA_SEC}s)", "INFO")
                await browser.switch_to_page(page)
                try:
                    await page.evaluate("""() => {
                        window.scrollTo(0, document.body.scrollHeight);
                        document.querySelectorAll('[class*="react-scroll"], [class*="chat-messages"], main, [role="presentation"]')
                            .forEach(c => { try { c.scrollTop = c.scrollHeight; } catch(e){} });
                    }""")
                    await asyncio.sleep(0.4)
                except Exception:
                    pass
                _sn_diag = await agent_loop(cua_client, browser, PROMPT_DIAGNOSE,
                    "Look at the BOTTOM of the chat (composer / end of response). "
                    "Is there a Stop button visible? Is there a loading animation or 'Researching...' indicator? "
                    "If a Stop button is visible anywhere, say 'still generating'. "
                    "Only say 'response complete' if there is NO stop button AND the final paragraph of the response is visible.",
                    model=CUA_MODEL, max_iterations=3, verbose=verbose)
                if _sn_diag.get("status") == "error":
                    log(f"[{label}] Safety-net CUA unavailable "
                        f"({(_sn_diag.get('text') or '')[:80]}) — "
                        f"falling back to existing 20m stall surface", "WARN")
                    # Don't reset stall_window_start; existing stall path fires
                else:
                    _sn_text = (_sn_diag.get("text") or "").lower()
                    # Parse mirrors the existing CUA-after-verify-fail block
                    # (research.py:~15698-15717). Default to "still generating"
                    # on ambiguous reads so we DON'T early-exit on a false-done.
                    # (The verify-False CUA path defaults to "complete" because
                    # DOM already says done; here DOM says generating + content
                    # flat — keeping it open is safer.)
                    _sn_is_generating = False
                    _sn_is_complete = False
                    if "response complete" in _sn_text:
                        _sn_is_complete = True
                    elif "still generating" in _sn_text:
                        _sn_is_generating = True
                    elif "needs click" in _sn_text:
                        _sn_is_generating = True
                    else:
                        _sn_has_stop = ("stop" in _sn_text and "yes" in _sn_text.split("stop")[0][-30:])
                        _sn_has_loading = ("loading" in _sn_text and "yes" in _sn_text.split("loading")[0][-30:])
                        _sn_has_response = (("completed" in _sn_text or "response visible" in _sn_text)
                                            and "yes" in _sn_text)
                        if _sn_has_stop or _sn_has_loading:
                            _sn_is_generating = True
                        elif _sn_has_response:
                            _sn_is_complete = True
                        else:
                            # AMBIGUOUS — keep waiting (opposite of verify-False
                            # path's default). Content was flat but CUA didn't
                            # give a clear read; better to fall to the 20m
                            # stall surface than risk extracting an in-flight
                            # response.
                            _sn_is_generating = True
                    if _sn_is_complete:
                        _elapsed = int(time.time() - wait_start)
                        log(f"[{label}] Safety-net CUA confirms response complete ✓ "
                            f"({_elapsed}s) — DOM detector was the false-positive")
                        return True
                    if _sn_is_generating:
                        log(f"[{label}] Safety-net CUA confirms still generating — "
                            f"reset stall window, continue poll")
                        # Reset flat-window so the safety-net doesn't loop-fire
                        # every poll. The next 5 min of true flatness will
                        # re-arm it; if content actually grows in the
                        # meantime the regular stall_window_start gets
                        # cleared by the growth-detection branch above.
                        stall_window_start = time.time()
                        safety_net_cua_asked = False

            # Stall surface: detector still says "running" but ALL three
            # signals (text + sources + steps) stopped growing for
            # STALL_THRESHOLD_SEC. Catches the "ChatGPT alive but frozen
            # mid-stream" case proactively — raises _BriefStreamStalled
            # (Stream 2 D3) so the P1 caller can show stall-specific copy
            # distinct from a wall-clock timeout. Multi-signal makes false
            # alarms vanishingly rare: ChatGPT DR's researching phase
            # always grows sources/steps even when text doesn't.
            # (Now serves as final fallback — safety-net above should
            # catch DOM false-positives at the 5m mark.)
            if (stall_window_start is not None
                    and (time.time() - stall_window_start) > STALL_THRESHOLD_SEC):
                _stall = int(time.time() - stall_window_start)
                log(f"[{label}] Stall detected: text={last_seen_len}, "
                    f"sources={last_seen_sources}, steps={last_seen_steps_sig} — "
                    f"all flat for {_stall}s while detector says generating "
                    f"→ surfacing for user decision (Retry/Skip)", "WARN")
                raise _BriefStreamStalled(
                    f"phase {phase} response stalled "
                    f"(text={last_seen_len}, sources={last_seen_sources}, "
                    f"steps={last_seen_steps_sig}; flat for {_stall}s)"
                )

        elapsed_min = int(time.time() - wait_start) // 60
        log(f"[{label}] Still generating... ({elapsed_min}m elapsed)")
        await asyncio.sleep(poll_interval)


# ── Round-Robin Polling (Phase 2) ─────────────────────────────────────────────

async def _restart_phase2_agent(name: str, browser, cua_client, brief_text: str,
                                 brief_path, verbose: bool):
    """Hard-retry helper: re-run the per-agent setup for a Phase 2 agent from
    scratch (fresh tab, Pro/DR mode selection, brief paste, submit, verify).

    Mirrors the per-agent setup blocks inside `run_phase2` — kept in sync
    manually because run_phase2's setup is entangled with agent startup
    ordering (Gemini waits for Start-research button AFTER ChatGPT/Claude
    submit). For a single-agent restart, ordering doesn't matter: run the
    agent's own setup in isolation.

    Returns `(new_page, verified_bool)` or `None` on hard failure (including
    paste/setup failure where start_agent_no_gemini_wait returned ok=False)."""
    # Re-deliver user source docs on hard-retry too (read from disk so the
    # retried agent gets the same attachments the original run did).
    source_paths = _read_p2_source_paths()
    if name == "ChatGPT":
        new_page, _setup_ok = await start_agent_no_gemini_wait(
            browser, cua_client, "https://chatgpt.com",
            PROMPT_CHATGPT_DEEP_RESEARCH,
            "Enable Deep Research mode in ChatGPT. Do NOT type — just set up and focus input. Say 'ready for paste'.",
            brief_text, "2A-retry", "ChatGPT", verbose, brief_path=brief_path,
            source_paths=source_paths)
        if not _setup_ok:
            return (new_page, False)
        verified = await wait_until_verified(
            verify_chatgpt_generating, new_page, "2A-retry",
            browser=browser, cua_client=cua_client,
            max_retries=15, interval=3, verbose=verbose)
        return (new_page, verified)

    if name == "Claude":
        new_page, _setup_ok = await start_agent_no_gemini_wait(
            browser, cua_client, "https://claude.ai/new",
            PROMPT_CLAUDE_DEEP_RESEARCH,
            "Select Opus 4.8 + Max effort + Adaptive Thinking + Research tool (if Opus 4.8 isn't offered, pick the highest Opus available — never downgrade to 4.7 when 4.8 exists). Do NOT type — just set up and focus input. Say 'ready for paste'.",
            brief_text, "2C-retry", "Claude", verbose, brief_path=brief_path,
            source_paths=source_paths)
        if not _setup_ok:
            return (new_page, False)
        verified = await wait_until_verified(
            verify_claude_generating, new_page, "2C-retry",
            browser=browser, cua_client=cua_client,
            max_retries=15, interval=3, verbose=verbose)
        return (new_page, verified)

    if name == "Gemini":
        new_page, _setup_ok = await start_agent_no_gemini_wait(
            browser, cua_client, "https://gemini.google.com",
            PROMPT_GEMINI_DEEP_RESEARCH,
            "Enable Deep Research mode in Gemini. Do NOT type — just set up and focus input. Say 'ready for paste'.",
            brief_text, "2B-retry", "Gemini", verbose, brief_path=brief_path,
            source_paths=source_paths)
        if not _setup_ok:
            return (new_page, False)
        await browser.switch_to_page(new_page)
        await asyncio.sleep(2)

        # Gemini needs an extra click: wait up to 90s for "Start research"
        # button, click via JS, fall back to CUA if JS can't find it.
        start_clicked = False
        for attempt in range(45):
            try:
                clicked = await new_page.evaluate("""() => {
                    const btns = document.querySelectorAll('button');
                    for (const b of btns) {
                        const txt = b.textContent.trim().toLowerCase();
                        if (txt.includes('start research')) { b.click(); return true; }
                    }
                    return false;
                }""")
                if clicked:
                    start_clicked = True
                    await asyncio.sleep(5)
                    break
            except Exception:
                pass
            await asyncio.sleep(2)
        if not start_clicked and cua_client:
            await browser.switch_to_page(new_page)
            fix = await agent_loop(cua_client, browser,
                PROMPT_GEMINI_START_RESEARCH,
                "Click the 'Start research' button to begin the deep research.",
                model=CUA_MODEL, max_iterations=10, verbose=verbose)
            if "click" in (fix.get("text") or "").lower():
                start_clicked = True
                await asyncio.sleep(5)

        verified = await wait_until_verified(
            verify_gemini_generating, new_page, "2B-retry",
            browser=browser, cua_client=cua_client,
            max_retries=15, interval=3, verbose=verbose)
        return (new_page, verified)

    return None


# ── Per-Agent Extract + Record (content-first, link-second) ──────────────────
# Called by poll_all_agents_round_robin the moment detect_completion_* flips
# True for an agent. Runs the locked 2026-04 emission ladder end-to-end so the
# frontend gets the MD, the public link (or chat-URL fallback), and the
# `complete` status all together — backend and frontend stay in sync, and the
# frontend tick mark appears at the same moment the backend marks completed_set.
#
# Emission order (user-locked):
#   1. agent_progress status=extracting          (before we touch anything)
#   2. extract content → save documents/<agent>.md + Firestore mirror
#   3. attempt public Share/Publish link (short-circuited for ChatGPT iframe)
#   4. emit link_extracted { url, verified, fallback? }
#      (public if verified, else chat-URL fallback with verified=False)
#   5. agent_progress status=complete
#   Caller then does completed_set.add(agent) and clears extraction_in_progress.

async def extract_and_record_agent(name, page, browser, cua_client, queue_dir,
                                    elapsed_sec=0, verbose=False,
                                    expected_text_len=0):
    """Per-agent extract + save + emit ladder. Returns a result dict
    the caller drops into results[]. Never raises — on any internal failure
    returns status='failed' so the poll loop can decide whether to retry.

    2026-04-25: Markdown-as-primary architecture (mirrors P1).
    The moment markdown lands in Firestore, the function emits link_extracted
    (in-app /documents URL, primary=True, verified=True) + agent_progress
    complete. Share-link extraction is REMOVED from P2 entirely — Phase 5's
    Google Doc creation uses Phase 3's link extraction instead. The in-app
    /documents?open=… link is the only link FE renders in PhaseDropdown.

    Result dict semantics:
      url          — conversation URL (page.url) for downstream resume
      _in_app_url  — /documents?open=… for the FE primary link
      verified     — True if MD text > 0 (the in-app primary IS verified)
    """
    agent_key = name.lower().replace(" ", "")

    # Step 1 — Emit extracting so the frontend can show "Extracting…" spinner
    try:
        emit_event("agent_progress", phase=2, agent=agent_key,
                   status="extracting",
                   progress=f"Extracting {name} research content…")
    except Exception:
        pass

    # Pull the agent's tab to the foreground so extract_*_response can operate
    try:
        await browser.switch_to_page(page)
        await asyncio.sleep(1)
    except Exception as e:
        log(f"[{name}] switch_to_page failed: {e}", "WARN")

    # Step 2 — Content extraction (HTML→MD → copy button → JS → clipboard)
    extract_fn_map = {
        "ChatGPT": extract_chatgpt_response,
        "Gemini":  extract_gemini_response,
        "Claude":  extract_claude_response,
    }
    extract_fn = extract_fn_map.get(name)
    text = ""
    if extract_fn:
        try:
            # Claude: poll-loop kept artifact-1 panel open via scrape_claude_artifact_tracking
            # (commit d45807f). Pass that signal so the extractor closes-1 before clicking
            # the LAST card (which opens artifact-2, the final report). Without this hand-off,
            # the LAST-card click can no-op (artifact_count==1) or race the panel swap.
            extra_kw = {}
            if name == "Claude":
                extra_kw["artifact_panel_open"] = bool(getattr(_runtime, "claude_artifact_panel_open", False))
            text = await extract_fn(page, browser=browser, cua_client=cua_client,
                                     label=name, verbose=verbose, **extra_kw) or ""
        except Exception as e:
            log(f"[{name}] Content extraction error: {e}", "WARN")
            text = ""
        # Panel state mutated: extract_claude_response (when it ran) opened artifact-2,
        # so the polling-loop's "panel 1 is open" signal is no longer accurate. Clear
        # it so a subsequent retry/poke doesn't make scrape_claude_artifact_tracking
        # skip the click (already_open=True) and read artifact-2 into the running tracker.
        if name == "Claude":
            try:
                _runtime.claude_artifact_panel_open = False
            except Exception:
                pass
            # Length-sanity (2026-05-02): if streamed partial text accumulated
            # during round-robin was substantial AND the extracted text is
            # <30% of it, the extractor likely grabbed the wrong artifact
            # (e.g. an early summary tile). Reject and let the failed-status
            # branch fire so the caller's retry budget kicks in.
            if (text and expected_text_len >= 1000
                    and len(text) < int(0.3 * expected_text_len)):
                log(f"[{name}] Length-sanity rejection: {len(text)} chars < 30% of "
                    f"streamed {expected_text_len} chars — likely wrong artifact", "WARN")
                try:
                    emit_event("wrong_artifact_rejected", phase=2, agent="claude",
                               op="finalize_length_sanity",
                               length=len(text),
                               expected=expected_text_len,
                               tier="length_sanity")
                except Exception:
                    pass
                text = ""
    n_chars = len(text)

    # Step 2b — Save MD to disk (Phase 3 input) + Firestore mirror (FE doc).
    # md_saved tracks the FIRESTORE write because that's what gates the FE's
    # `docReachable` accordion check. A successful local-only save is not
    # enough — without the subcollection write, the FE accordion would sit
    # in `isAgentSyncing` until the run ends. Retry once (transient quota /
    # network blips) before accepting the failure.
    local_saved = False
    md_saved = False
    md_content = ""
    if text and queue_dir:
        try:
            documents_dir = queue_dir / "documents"
            documents_dir.mkdir(parents=True, exist_ok=True)
            fname = agent_key + ".md"
            md_content = f"# {name} Deep Research\n\n{text}"
            (documents_dir / fname).write_text(md_content, encoding="utf-8")
            local_saved = True
            log(f"[{name}] Saved {n_chars} chars to documents/{fname}")
            # Extract real cited-source findings from the just-written
            # markdown so the FE GraphAnalysis Findings tab can render
            # rich {url, snippet, sourceTitle} cards instead of just
            # section headings. Persisted by save_meta's agents map
            # writer (research.py:~17686). Source URLs come from the
            # in-memory progress snapshot (already deduped).
            try:
                _src_urls = list(getattr(_runtime, "agent_progress_snapshots", {}).get(agent_key, {}).get("source_urls", []) or [])
                if _src_urls:
                    _findings = _extract_findings(md_content, _src_urls)
                    if _findings:
                        _runtime.agent_findings[agent_key] = _findings
                        log(f"[{name}] Extracted {len(_findings)} cited-source findings")
            except Exception as _ef:
                log(f"[{name}] findings extraction failed: {_ef}", "DEBUG")
        except Exception as e:
            log(f"[{name}] Local MD save failed: {e}", "WARN")
        if local_saved:
            if _firebase_db and _fb_uid and _fb_research_id:
                # F5 (2026-05-13): 4 attempts (1s/4s/16s backoff) replaces the
                # prior 2-attempt/2s loop. Most transient Firestore blips
                # (429 / Unavailable / network flap) resolve well inside 21s.
                # Persistent failures (auth/quota/schema) still get caught and
                # the agent flips to "errored" via the failed branch below.
                md_saved = await save_document_to_firestore_with_retry(
                    agent_key, md_content, f"{name} Deep Research", label=name)
            else:
                # Unpaired / local-only run — no Firestore configured, so the
                # FE doc-reachable gate doesn't apply. Treat the local-disk
                # save as authoritative success so downstream status="done"
                # holds (preserves pre-F5 behaviour for headless runs).
                md_saved = True

    # Conversation URL — captured NOW because the page may navigate during the
    # parallel share-link worker (Gemini's Share & Export modal can redirect).
    conversation_url = ""
    try:
        conversation_url = (page.url or "") if page else ""
    except Exception:
        conversation_url = ""

    # Step 3 — Markdown-as-primary emit (P1 mirror), STRICT gate.
    # The FE flips an agent to ✓ only when it sees:
    #   (a) link_extracted with primary=true + verified=true, AND
    #   (b) the doc reachable via useResearches (subcollection sync).
    # Therefore we must NOT emit `complete` unless both _fb_research_id (so the
    # in-app URL has an anchor) AND n_chars > 0 (so a doc actually exists in
    # Firestore for the FE to find). A bare /documents URL without anchor is
    # not enough — it would let the FE flip ✓ without a real target.
    has_anchor = bool(_fb_research_id)
    _in_app_url = (f"/documents?open={_fb_research_id}:{agent_key}"
                   if has_anchor else "/documents")
    _in_app_label = f"Read {name} report"
    if n_chars > 0 and has_anchor and md_saved:
        try:
            emit_event("link_extracted", phase=2, agent=agent_key,
                       url=_in_app_url, label=_in_app_label,
                       verified=True, primary=True)
        except Exception:
            pass
        # 2026-05-03: pull the latest rich progress snapshot so the
        # completion emit carries sourceUrls / sections / steps / searches
        # alongside partialTextLen + links. Without this enrichment, the
        # FE persistence in usePipeline at phase_complete only had
        # partialTextLen to write — agents[key].sourceUrls landed empty
        # and the post-completion dropdown card showed the bare stub.
        _snap = {}
        try:
            _snap = dict(getattr(_runtime, "agent_progress_snapshots", {}).get(agent_key, {}) or {})
        except Exception:
            _snap = {}
        try:
            emit_event("agent_progress", phase=2, agent=agent_key,
                       status="complete",
                       progress=f"Content extracted: {n_chars} chars ({elapsed_sec}s)",
                       partialTextLen=n_chars,
                       elapsedSec=int(elapsed_sec or 0),
                       sourceUrls=_snap.get("source_urls", []),
                       sections=_snap.get("sections", []),
                       steps=_snap.get("steps", []),
                       searches=int(_snap.get("searches", 0) or 0),
                       observedSources=int(_snap.get("observed_sources", 0) or 0),
                       sources=max(int(_snap.get("sources", 0) or 0),
                                   len(_snap.get("source_urls", []) or [])),
                       links=[{"label": _in_app_label, "url": _in_app_url,
                               "verified": True, "primary": True}])
        except Exception:
            pass
        # F4 (2026-05-06): persist agent terminal status to root doc on
        # the individual complete-emit instead of waiting for the bulk
        # phase_complete write at :19641. On chat reopen mid-Phase-2,
        # an agent that finished early (e.g. ChatGPT done while Claude
        # is still researching) should already show as 100% complete in
        # research.agents[k].status — pre-fix, only the message bucket
        # carried the done state, and reopen rebuilt the bucket from
        # Firestore which lacked the runtime status until phase_complete
        # bulk-flushed all three. Idempotent with the bulk write — same
        # field, same value. FE companion at usePipeline.ts agent_progress
        # handler also writes this client-side for redundancy.
        try:
            _write_agent_terminal_status(agent_key, "complete")
        except Exception:
            pass
    else:
        # No content extracted OR no anchor OR Firestore write failed — emit
        # failed (FE keeps spinner, never flips ✓ without a reachable doc).
        _why = ("0 chars" if n_chars <= 0
                else "no research anchor (_fb_research_id missing)" if not has_anchor
                else "Firestore document sync failed after retry — FE doc-reachable would never flip")
        try:
            emit_event("agent_progress", phase=2, agent=agent_key,
                       status="failed",
                       progress=f"Content extraction failed — {_why} ({elapsed_sec}s)",
                       partialTextLen=max(int(n_chars), 0),
                       elapsedSec=int(elapsed_sec or 0))
        except Exception:
            pass
        # F5 (2026-05-13): persist terminal "errored" on the root doc so
        # post-reload tile/icon state shows the red badge instead of the
        # last running snapshot. Mirrors fail_agent's behaviour at 7403.
        # Idempotent with any user-initiated Retry path (retry writes
        # "running"; subsequent success/failure overwrites this).
        try:
            _write_agent_terminal_status(agent_key, "errored")
        except Exception:
            pass

    # ── Step 4 — Inline share-link extraction (Option A, 2026-04-25) ──
    # Best-effort, **NOT streamed to FE**. We call the extractor functions
    # directly (no extract_with_retry) so we don't emit `link_extracting` /
    # `link_extracted` / `link_extraction_failed` events into the FE event
    # stream. The FE already showed `link_extracted primary=true` for the
    # in-app /documents URL above; a second link_extracted for the share
    # URL would land as a non-primary record (filtered out by P1+P2 strict
    # rule) but would still bloat steps[] and dirty agentAlerts via the
    # usePipeline link_extracted handler. Direct call keeps the FE clean.
    #
    # 90 s outer budget per agent. Public success → kind="public",
    # verified=True. Public failure (timeout, error, unverified URL) →
    # conversation URL, kind="conversation", verified=False. The run
    # always advances; Phase 5 always has *some* URL.
    if n_chars > 0:
        share_extractor_map = {
            "ChatGPT": extract_share_link_chatgpt,
            "Gemini":  extract_share_link_gemini,
            "Claude":  extract_share_link_claude,
        }
        share_extractor = share_extractor_map.get(name)
        share_url = conversation_url
        share_kind = "conversation"
        share_verified = False
        share_label = f"{name} conversation"
        inner_cua_attempted = False
        if share_extractor:
            _share_t0 = time.time()
            try:
                link_res = await asyncio.wait_for(
                    share_extractor(browser, cua_client=cua_client,
                                    label=f"{name} public share", verbose=verbose),
                    timeout=90.0,
                )
                _elapsed_share = time.time() - _share_t0
                # Validate against the same rules extract_with_retry uses, so
                # we don't pin a junk URL onto _runtime.agent_share_urls.
                if (link_res and link_res.url and
                        validate_link(agent_key, link_res.url)):
                    share_url = link_res.url
                    share_kind = "public"
                    share_verified = True
                    share_label = link_res.label or f"{name} public share"
                    log(f"[{name}] Inline share-link extracted ({_elapsed_share:.1f}s): {share_url}")
                    # F4 / DGOPS-7451 — public share is anyone-with-link viewable.
                    # On 2026-05-05 Gemini auto-created a share at
                    # gemini.google.com/share/8e52f021efe3 that had to be
                    # manually revoked. Surface a HIGH-severity event so the
                    # operator sees the URL prominently in run output and
                    # can revoke before propagation. (Auto-revoke is the
                    # bonus follow-up — see DGOPS-7451 ticket.)
                    log(f"[security] PUBLIC SHARE LINK EMITTED for {name}: {share_url}", "WARN")
                    try:
                        emit_event("public_share_detected",
                                   phase=2, agent=agent_key,
                                   url=share_url, label=share_label,
                                   severity="HIGH",
                                   message=(f"{name} emitted a public share URL — "
                                            "anyone with this link can view the "
                                            "research. Revoke from the agent's UI "
                                            "if the run output shouldn't be public."))
                    except Exception:
                        pass
                else:
                    err = (link_res.error if link_res else "no result")
                    log(f"[{name}] Inline share-link unverified ({err}, {_elapsed_share:.1f}s) "
                        f"— falling back to conversation URL silently", "INFO")
                # Capture whether the inner extractor's CUA fallback already
                # ran — Step 4b below skips when True to avoid a wonky-modal
                # double-CUA pass (was a tab-spam contributor on Gemini's
                # share dialog, where the dialog renders social-share icons
                # that CUA misclicks open as new tabs).
                if link_res and getattr(link_res, "cua_attempted", False):
                    inner_cua_attempted = True
            except asyncio.TimeoutError:
                log(f"[{name}] Inline share-link timed out (90s) "
                    f"— falling back to conversation URL silently", "INFO")
            except Exception as _e:
                log(f"[{name}] Inline share-link errored ({_e}) "
                    f"— falling back to conversation URL silently", "INFO")
        # ── Step 4b — Inline CUA share fallback (Gemini/Claude only) ──
        # If the DOM-tier extractor didn't return a verified public URL AND
        # its inner CUA fallback hasn't already run, try CUA here on the
        # same page (no tab switch, no revisit). Wrapped in
        # _shadow_observed_cua so Vision (tier-2 shadow) observes in
        # parallel and Track A telemetry accumulates on the new "p2-share"
        # hotspot. ChatGPT is excluded here — extract_share_link_chatgpt
        # already runs its own CUA pass internally (research.py:3340-3379)
        # and is wrapped in shadow at that site, so a second pass would
        # double the budget without new information. Same logic now applies
        # to Gemini/Claude via inner_cua_attempted.
        if ((not share_verified) and (not inner_cua_attempted) and
                cua_client and n_chars > 0 and name != "ChatGPT"):
            cua_share_prompt = {
                "Gemini": PROMPT_SHARE_GEMINI,
                "Claude": PROMPT_PUBLISH_CLAUDE,
            }.get(name)
            if cua_share_prompt:
                emit_tier_transition(phase=2, agent=agent_key,
                    op="p2_share_extract", from_tier="dom", to_tier="cua",
                    reason="dom_share_extractor_unverified")
                _cua_t0 = time.time()
                async def _p2_share_cua():
                    return await asyncio.wait_for(
                        agent_loop(cua_client, browser, cua_share_prompt,
                            f"Make this {name} conversation shareable and get the link.",
                            model=CUA_MODEL, max_iterations=10, verbose=verbose,
                            target_page=page),
                        timeout=75.0)
                try:
                    await _shadow_observed_cua(
                        page, hotspot_id="p2-share", phase=2, platform=agent_key,
                        current_step="open_share_menu_and_create_link",
                        context_hint=f"P2 inline share fallback for {name}",
                        expected_outcome="public-share URL on clipboard or visible in modal",
                        cua_coro_factory=_p2_share_cua)
                    # After CUA acted, recover the URL from clipboard / current URL.
                    cand = ""
                    try:
                        cand = await asyncio.wait_for(
                            page.evaluate("navigator.clipboard.readText()"),
                            timeout=2.0)
                    except (asyncio.TimeoutError, Exception):
                        cand = ""
                    if not (cand and "http" in cand and len(cand) < 500
                            and validate_link(agent_key, cand)):
                        try:
                            cand2 = await asyncio.wait_for(
                                asyncio.to_thread(get_clipboard),
                                timeout=3.0)
                            if cand2 and validate_link(agent_key, cand2):
                                cand = cand2
                        except (asyncio.TimeoutError, Exception):
                            pass
                    if not (cand and validate_link(agent_key, cand)):
                        try:
                            cand3 = await browser.current_url() or ""
                            if cand3 and validate_link(agent_key, cand3):
                                cand = cand3
                        except Exception:
                            pass
                    if cand and validate_link(agent_key, cand):
                        share_url = cand
                        share_kind = "public"
                        share_verified = True
                        share_label = f"{name} public share"
                        log(f"[{name}] CUA share-link extracted "
                            f"({time.time() - _cua_t0:.1f}s): {share_url[:80]}")
                    else:
                        log(f"[{name}] CUA share-link unverified "
                            f"({time.time() - _cua_t0:.1f}s) — keeping "
                            f"conversation URL", "INFO")
                except asyncio.TimeoutError:
                    log(f"[{name}] CUA share-link timed out (75s) — "
                        f"keeping conversation URL", "INFO")
                except Exception as _ce:
                    log(f"[{name}] CUA share-link errored ({_ce}) — "
                        f"keeping conversation URL", "INFO")
        # Stash for Phase 5 — agent_chat_urls already has the conversation URL,
        # but agent_share_urls carries kind/verified so the Doc builder can
        # decide whether to label "Public share" or "Conversation".
        try:
            _runtime.agent_share_urls[name] = {
                "url": share_url,
                "kind": share_kind,
                "label": share_label,
                "verified": share_verified,
            }
        except Exception:
            # _runtime is a process-level singleton — should always exist.
            # If it doesn't, Phase 5's fallback (agent_chat_urls) still works.
            pass
        # Also propagate to the Firestore aggregate links map so P5's Doc
        # body composition can read it from the single source of truth.
        # Key by lowercase platform name to match the rest of the map
        # (chatgpt / gemini / claude).
        try:
            if share_url:
                # link_kind (not kind) — `kind` is already the positional arg
                # carrying the agent name ("chatgpt" / "gemini" / "claude"),
                # and Python won't tolerate the same parameter passed twice.
                # The earlier `kind=share_kind` collision swallowed silently
                # in the broad except below, so per-agent links never made
                # it to Firestore and the FE-P5 Doc was missing P2 sections.
                update_link_in_firestore(
                    name.lower(),
                    share_url,
                    label=share_label or name,
                    phase=2,
                    verified=share_verified,
                    link_kind=share_kind,
                )
        except Exception as _ufe:
            log(f"[{name}] Firestore link update failed (non-fatal): {_ufe}", "WARN")

    # F5 (2026-05-13): status="done" now requires `md_saved=True`. Prior
    # gate was `n_chars > 0` alone, which let Firestore-sync-failed agents
    # report status="done" in the Phase 2 summary log while the FE
    # doc-reachable gate sat unflipped (because the subcollection write
    # never landed). Phase 2 finalize consumers (done_count, terminal-status
    # backstop, _p2_links builder) all read this status — keeping them in
    # sync with what the FE actually sees prevents the worst-of-both-worlds
    # "log says done, FE says spinner" state inconsistency.
    return {
        "status": "done" if (n_chars > 0 and md_saved) else "failed",
        "text": text,
        "url": conversation_url,        # conversation URL — for resume reconnect
        "_in_app_url": _in_app_url,     # in-app /documents primary — FE link
        "verified": (n_chars > 0 and md_saved),
        "page": page,
        "elapsed_sec": int(elapsed_sec or 0),
        "md_saved": md_saved,
    }


async def _spotlight_latest_response(page, agent_name: str):
    """A4 (2026-05-01): briefly select the latest response paragraph via
    DOM Range API so the user can SEE which agent the round-robin is
    currently polling. Symmetric across ChatGPT/Gemini/Claude — no CUA
    cost, no screenshot, no click. Auto-clears after 900ms so the user's
    own selection isn't held hostage. Failures are silent (visual cue
    is non-essential — polling/scraping is what actually matters).
    """
    if not page:
        return
    # Per-platform selectors for the response container. Walk last→first
    # and pick the first on-screen match. Fallback: any visible <article>
    # or <p> chunk so the spotlight still flashes if selectors drift.
    sel_map = {
        "ChatGPT": (
            '[data-message-author-role="assistant"] .markdown, '
            '[data-message-author-role="assistant"], '
            '[data-testid^="conversation-turn"] .markdown, '
            'main article'
        ),
        "Gemini": (
            'message-content, '
            '.response-content, '
            '.markdown-main-panel, '
            'model-response, '
            'main .markdown'
        ),
        "Claude": (
            '[data-test-render-count] .font-claude-message, '
            '.font-claude-message, '
            '[data-testid="user-message"] ~ * .prose, '
            '.prose, '
            'main article'
        ),
    }
    css = sel_map.get(agent_name, "main article, main .markdown, p")
    try:
        await page.evaluate(
            """(css) => {
                try {
                    const els = Array.from(document.querySelectorAll(css));
                    if (!els.length) return false;
                    // pick the LAST visible-on-screen element so we spotlight
                    // the freshest paragraph, not the user's prompt at top.
                    let target = null;
                    for (let i = els.length - 1; i >= 0; i--) {
                        const r = els[i].getBoundingClientRect();
                        if (r.height > 18 && r.bottom > 0
                                && r.top < (window.innerHeight + 200)) {
                            target = els[i]; break;
                        }
                    }
                    target = target || els[els.length - 1];
                    const range = document.createRange();
                    range.selectNodeContents(target);
                    const s = window.getSelection();
                    if (!s) return false;
                    s.removeAllRanges();
                    s.addRange(range);
                    setTimeout(() => {
                        try { window.getSelection()?.removeAllRanges(); }
                        catch (_) {}
                    }, 900);
                    return true;
                } catch (_) { return false; }
            }""",
            css,
        )
    except Exception:
        pass


# ── Claude clarification-question detector (2026-05-18) ──────────────────────
# When the user submits a vague / template brief, Claude responds with a chat
# message asking clarifying questions INSTEAD of starting Deep Research.
# Without the auto-reply below, the BE waits for an artifact that never
# appears and surfaces a generic "Hit a snag" alert at the wall-clock cap,
# requiring the operator to manually type a defer message into the Claude tab.
#
# Sign-off pattern: Claude's clarification responses consistently end with a
# variant of "Once you {clarify|confirm|...}, I'll {launch|start|...} the
# research" — that exact structure is the gating signal here (5th condition
# alongside elapsed window, not-generating, no-artifact, short-text-with-?s).
# Mid-research statements like "I'll start with the analysis of X" don't
# match because they lack the "once you" / "let me know" / "with those"
# clarification-pending opener.
_CLAUDE_CLARIFICATION_SIGNOFF_RE = re.compile(
    r"(?:once\s+(?:you\s+)?(?:clarify|confirm|share|provide|specify|tell\s+me|answer)|"
    r"let\s+me\s+know|"
    r"with\s+(?:those|that|these)\s+(?:answers|details|specifics|clarifications))"
    r"[^.!?]{0,180}"
    r"(?:I[''’]?ll|I\s+will)\s+(?:launch|start|begin|dive|jump|kick\s+off|get\s+started)"
    r"[^.!?]{0,80}"
    r"research",
    re.IGNORECASE | re.DOTALL,
)


async def _claude_asking_clarification(page):
    """Lightweight DOM read of the last assistant message + sign-off regex
    match. Does NOT touch clipboard or open artifact panels (cheaper than
    extract_claude_response — safe to call every round-robin tick).

    Returns (matched: bool, last_text: str, q_count: int)."""
    try:
        last_text = await page.evaluate("""() => {
            const candidates = [
                '.font-claude-message',
                '[data-message-author-role="assistant"]',
                '.contents .prose',
            ];
            for (const sel of candidates) {
                const all = document.querySelectorAll(sel);
                if (all.length > 0) {
                    const last = all[all.length - 1];
                    const t = (last.innerText || last.textContent || "").trim();
                    if (t.length > 30) return t;
                }
            }
            return "";
        }""")
    except Exception:
        return False, "", 0
    if not last_text:
        return False, "", 0
    q_count = last_text.count("?")
    # Sign-off lives in the tail — match on last 600 chars so a mid-message
    # "I'll start with..." aside doesn't false-positive.
    tail = last_text[-600:] if len(last_text) > 600 else last_text
    matched = bool(_CLAUDE_CLARIFICATION_SIGNOFF_RE.search(tail))
    return matched, last_text, q_count


async def _claude_send_clarification_reply(page, label):
    """Type the defer-to-Claude reply into the chat input, then submit.

    Submit strategy: try the Send button first (matches paste_followup at
    research.py:5170), fall back to Enter if no enabled button is found.
    Send-button-first protects against future Claude composer A/B tests
    that might bind Enter to newline (Shift+Enter→Enter swap pattern).

    Returns True on send, False if no composer was reachable."""
    reply = "Up to Claude to decide for the best output."
    typed_into = None
    for sel in ('div[contenteditable="true"]', '.ProseMirror', 'textarea', '[role="textbox"]'):
        try:
            inp = await page.query_selector(sel)
            if not inp:
                continue
            await inp.click()
            await asyncio.sleep(0.3)
            await page.keyboard.type(reply, delay=10)
            await asyncio.sleep(0.4)
            typed_into = sel
            break
        except Exception as _te:
            log(f"[{label}] Clarification type attempt on {sel} failed: {_te}", "DEBUG")
            continue
    if typed_into is None:
        log(f"[{label}] No composer found for clarification reply", "WARN")
        return False
    # Send-button-first (mirror paste_followup pattern at research.py:5170).
    for sel in (
        'button[data-testid="send-button"]',
        'button[aria-label="Send prompt"]',
        'button[aria-label="Send"]',
        'button[aria-label="Send message"]',
        'button[aria-label="Submit"]',
    ):
        try:
            btn = await page.query_selector(sel)
            if btn and await btn.is_enabled():
                await btn.click()
                log(f"[{label}] Sent clarification-defer reply via {sel}: {reply!r}", "INFO")
                return True
        except Exception:
            continue
    # Enter fallback.
    try:
        await page.keyboard.press("Enter")
        log(f"[{label}] Sent clarification-defer reply via Enter: {reply!r}", "INFO")
        return True
    except Exception as _ee:
        log(f"[{label}] Clarification reply Enter-fallback failed: {_ee}", "WARN")
        return False


# ─────────────────────────────────────────────────────────────────────
# Gemini Deep Research — kickoff-stall detection
# ─────────────────────────────────────────────────────────────────────
#
# Failure mode (observed in production 2026-05-22 — user screenshot):
# After "Start research" is sent, Gemini sometimes ACKs with "OK,
# starting now. As soon as your report is ready, I'll let you know"
# but never actually kicks off — the canonical "Researching N sources"
# card never appears and the run silently stalls. A single polite
# follow-up nudge reliably re-triggers the kickoff (the user
# previously unblocked these stalls by typing "Done?" which produced
# the same "I'm on it" → card-appears sequence).
#
# Mirrors the Claude clarification block above (research.py:16179):
# regex + lightweight DOM probe + one-shot nudge + state reset.

# ACK patterns Gemini emits after "Start research" — confirm Gemini
# DID respond. Anchored on phrases unique to the start-ack UX
# ("starting now", "let you know when", "feel free to leave this
# chat", "I'm on it"). Permissive — any ACK variant should match.
_GEMINI_KICKOFF_ACK_RE = re.compile(
    r"(starting\s+now|"
    r"let\s+you\s+know\s+when|"
    r"feel\s+free\s+to\s+leave\s+this\s+chat|"
    r"i[''’]?m\s+on\s+it)",
    re.IGNORECASE,
)

# Canonical "research is actually running" card text. Gemini Deep
# Research renders varying card text while the worker scrapes:
#   - "Researching 25 sources..." (numbered count — Golden Retrievers run)
#   - "Researching websites..." (no number — Salaar Part 2 run 2026-05-24)
#   - "Researching N searches..." / "Researching N sites..." (variants)
# Match any of these to suppress the nudge once kickoff succeeded.
# Mirrors the noun list in scrape_progress_gemini at research.py:~12054
# (`websites?|sources?|searches?|sites?`).
_GEMINI_RESEARCH_CARD_RE = re.compile(
    r"researching\s+(?:\d+\s+)?(?:websites?|sources?|searches?|sites?)",
    re.IGNORECASE,
)

# Completion message Gemini emits when the report is ready — same
# pattern as the in-app "research complete" banner. Suppresses the
# nudge if the report already arrived between ticks.
_GEMINI_COMPLETION_RE = re.compile(
    r"(completed\s+your\s+research|"
    r"feel\s+free\s+to\s+ask\s+me\s+follow[\s-]?up)",
    re.IGNORECASE,
)


async def _gemini_kickoff_pending(page):
    """Lightweight DOM probe: did Gemini ACK without actually starting?

    Returns (pending: bool, reason: str). pending=True iff:
      - ACK pattern matches somewhere in page innerText (Gemini DID respond)
      - "Researching N sources" card is NOT visible (research has NOT started)
      - Completion pattern is NOT visible (research is not already done)

    Safe to call every round-robin tick — reads first 8000 chars of
    body innerText only.
    """
    try:
        body = await page.evaluate("""() => (document.body.innerText || "").slice(0, 8000)""")
    except Exception:
        return False, "evaluate-failed"
    if not body:
        return False, "empty-body"
    if _GEMINI_COMPLETION_RE.search(body):
        return False, "completion-present"
    if _GEMINI_RESEARCH_CARD_RE.search(body):
        return False, "card-present"
    if not _GEMINI_KICKOFF_ACK_RE.search(body):
        return False, "no-ack-yet"
    return True, "ack-no-card"


# Escalating nudge wording — attempt 0 is a polite directive, attempt 1
# is a yes/no check-in question, attempt 2 mirrors the terse "Done?" that
# empirically jolted Gemini in the user's manual intervention (2026-05-24).
# Each wording targets a different parser path; if Gemini ignores the
# polite directive, the question may engage it, and if both ignored, the
# terse one-word check is the empirical last resort.
_GEMINI_KICKOFF_NUDGES = (
    "Please proceed with the deep research now.",
    "Are you researching?",
    "Done?",
)


async def _gemini_send_kickoff_nudge(page, label, attempt_idx=0):
    """Send a kickoff nudge to re-trigger Gemini's research with escalating
    wording across attempts (0-indexed). Clamps to the final wording for
    any attempt_idx beyond the list length.

    Reuses paste_followup so the nudge picks up _PASTE_SELECTORS["gemini"]
    composer selectors + the unified Send-button fallback chain — same
    machinery as the existing user-poke follow-up at research.py:~17498.
    Returns True on send, False if the composer was unreachable."""
    idx = max(0, min(attempt_idx, len(_GEMINI_KICKOFF_NUDGES) - 1))
    nudge = _GEMINI_KICKOFF_NUDGES[idx]
    ok = await paste_followup(
        page, nudge, "gemini",
        label=f"{label}-kickoff-nudge-{idx + 1}",
    )
    if ok:
        log(f"[{label}] Sent Gemini kickoff nudge #{idx + 1}/{len(_GEMINI_KICKOFF_NUDGES)}: {nudge!r}", "INFO")
    else:
        log(f"[{label}] Gemini kickoff nudge #{idx + 1} failed to send", "WARN")
    return ok


async def poll_all_agents_round_robin(agents, browser, cua_client,
                                       max_wait_min=90, poll_interval=30, verbose=False):
    """Round-robin poll all verified agents until each completes or times out.

    ChatGPT DR: polls for document card/canvas appearance (no stop button).
    Gemini/Claude: polls for stop button disappearance.
    Minimum wait enforced per agent to prevent false-positive early completion.
    """
    extract_fns = {
        "ChatGPT": extract_chatgpt_response,
        "Gemini": extract_gemini_response,
        "Claude": extract_claude_response,
    }
    # CUA completion check: first at 5 min (MIN_WAIT), then every 5 min.
    # 2026-04-25: dropped from 20→5 to mirror P1 cadence (catches fast finishers).
    _min_agent_wait = int(os.environ.get("MIN_AGENT_WAIT_MIN", "5")) * 60
    MIN_WAIT = {"ChatGPT": _min_agent_wait, "Gemini": _min_agent_wait, "Claude": _min_agent_wait}
    CUA_CHECK_INTERVAL = 300   # 5 min between CUA completion checks
    # Gemini-only periodic refresh. Post-2026-05 Gemini does NOT push the
    # completed Deep-Research panel into the live DOM — the done-state
    # ("Share & Export" button + completion text) only renders after a page
    # reload. Reload every ~10 min so detect_completion_gemini can see the
    # done-marker on its own. Replaces the old one-shot 10-min reload +
    # 15-min "Is the Research completed?" paste crutch (removed 2026-05-26).
    GEMINI_REFRESH_INTERVAL = int(os.environ.get("GEMINI_REFRESH_INTERVAL_SEC", str(10 * 60)))
    ARTIFACT_SCRAPE_INTERVAL = 60   # 1 min between Claude artifact-tracking scrapes (was 180; iteration #1 must pass — see init at last_artifact_scrape=0 below)

    pending = {}
    results = {}

    for name, agent in agents.items():
        # 2026-04 fix: don't drop an agent just because verify_*_generating
        # returned False. Verifiers can miss real activity (e.g. ChatGPT DR
        # lives in a cross-origin iframe that host-side selectors can't see).
        # As long as the tab exists we keep it in the round-robin — the
        # Playwright detectors + CUA fallback decide completion. If the tab
        # is truly dead, the 90-min per-agent timeout fires eventually.
        # Only skip when there's no page handle at all (tab never opened).
        if not agent.get("page"):
            results[name] = {"status": "not_verified", "text": "", "url": agent.get("url", "")}
            continue
        if not agent["verified"]:
            log(f"[{name}] verify_{name.lower()}_generating returned False but page exists — "
                f"keeping in round-robin (detectors will decide).", "WARN")
            # No alert: the round-robin keeps polling and the wall-clock
            # cap is what eventually surfaces fail_agent if no output.
        # Use research_started_at if available (e.g., Gemini waits for "Start research")
        # so elapsed/MIN_WAIT are computed from actual research start, not submission.
        _research_t = agent.get("research_started_at", time.time())
        pending[name] = {
            "page": agent["page"],
            "url": agent["url"],
            "start_time": _research_t,
            "done_count": 0,
            "cua_confirmed": False,
            "last_heartbeat": _research_t,
            "last_cua_check": _research_t,       # CUA check gate — MIN_WAIT from research start
            "last_artifact_scrape": 0,           # 0 → iteration #1 always passes the gate (Claude opens artifact ASAP)
            "chatgpt_activity_panel_open": False,  # ChatGPT activity-strip click flag — mirror Claude pattern
            "poll_cycles": 0,                    # increments once per round-robin tick — gates iter-#3 panel-open
            "chatgpt_panel_dom_misses": 0,       # consecutive DOM "found:false" — escalates to CUA after 2
            "chatgpt_panel_cua_attempts": 0,     # capped at 1/agent/phase
            "claude_artifact_dom_misses": 0,
            "claude_artifact_cua_attempts": 0,
            "observer_text_len": 0,              # MutationObserver sets this (see B2)
            "claude_clarification_replied": False,  # one-shot flag for clarification-defer reply
            "gemini_kickoff_nudge_count": 0,        # multi-shot nudge counter (max 3, 3min apart) for Gemini kickoff-stall
            "gemini_last_kickoff_nudge_at": 0.0,    # timestamp gate enforcing 3min spacing between Gemini kickoff nudges
            # 2026-05-26 Gemini periodic refresh. Post-2026-05 Gemini does
            # NOT push the completed Deep-Research panel into the live DOM —
            # the done-state only renders after a reload. We reload every
            # GEMINI_REFRESH_INTERVAL (~10 min) so detect_completion_gemini
            # can see the done-marker on its own. Seeded to research start so
            # the first refresh fires ~10 min in (matches the old one-shot
            # 10-min reload). Replaces the prior one-shot reload + 15-min
            # "Is the Research completed?" paste crutch — Flash 3.5 completes
            # cleanly and needs no nudge (user-validated 2026-05-26).
            "last_refresh": _research_t,
        }
        # Register for mid-run input dispatcher
        platform_key = name.lower().replace(" ", "")
        _runtime.register_page(platform_key, agent["page"], agent["url"])

    if not pending:
        return results

    _runtime.phase = 2
    _runtime.sub_state = "2_parallel_polling"
    log(f"\n--- Round-robin polling {len(pending)} agents (max {max_wait_min}min each) ---")

    # ── C1: tick counter drives strict-rotation cursor ──
    # Every tick shifts the per-agent iteration order by one, so after a
    # full rotation every agent has had its turn at being processed first.
    # Fixes the "only one agent gets polled" starvation that appears when
    # an earlier agent's await_agent_decision or long CUA check eats the
    # tick's budget before later agents are reached.
    _tick_counter = 0
    # Target 5 min of cursor dwell per agent — at the default 30s poll
    # interval that's 10 ticks between full rotations, still giving each
    # agent a shot at foreground focus every single tick via the shift.
    _tick_counter_initial = 0

    while pending:
        _tick_counter += 1
        # ── Browser-crash sweep (per-tick, before any per-agent work) ──
        # If any pending agent's tab crashed since the last tick, fail it
        # via Template B and drop it from pending so the rotation isn't
        # starved waiting on a dead handle.
        for _crash_name in list(pending.keys()):
            _crash_p = pending.get(_crash_name) or {}
            _crash_page = _crash_p.get("page")
            try:
                _crashed = bool(_crash_page is None or _crash_page.is_closed())
            except Exception:
                _crashed = True
            if _crashed:
                _crash_key = normalize_agent_key(_crash_name)
                log(f"[{_crash_name}] Browser tab crashed — failing agent", "WARN")
                # Always-auto: passive banner, outer run_pipeline.finally
                # rebuilds the browser session and resumes from checkpoint.
                _runtime.last_failure_kind = "browser_crash"
                emit_browser_recovery_status(2, agent=_crash_key)
                results[_crash_name] = {"status": "browser_crashed", "text": "",
                                        "url": _crash_p.get("url", ""),
                                        "page": None,
                                        "elapsed_sec": int(time.time() - _crash_p.get("start_time", time.time()))}
                del pending[_crash_name]
                continue
        # ── Stop/Pause check via asyncio Events ──
        if _controls.is_stop() or _controls.is_pause():
            is_stop = _controls.is_stop()
            signal = "STOP" if is_stop else "PAUSE"
            log(f"[Round-robin] {signal} requested — collecting partial results from completed agents")
            if is_stop:
                for name in list(pending.keys()):
                    p = pending[name]
                    try:
                        await browser.switch_to_page(p["page"])
                        text = await extract_fns[name](p["page"], browser=browser,
                            cua_client=cua_client, label=name, verbose=verbose)
                        elapsed = time.time() - p["start_time"]
                        status = "partial" if text and len(text) > 100 else "interrupted"
                        results[name] = {"status": status, "text": text or "",
                                         "url": p["page"].url, "page": p["page"],
                                         "elapsed_sec": int(elapsed)}
                        log(f"  [{name}] {status} — {len(text or '')} chars")
                    except Exception as e:
                        results[name] = {"status": "interrupted", "text": "",
                                         "url": p.get("url", ""), "page": p["page"]}
                        log(f"  [{name}] extraction failed: {e}", "WARN")
            else:
                # On PAUSE: snapshot current agent URLs, close browser, block, then relaunch+reopen
                for name in list(pending.keys()):
                    p = pending[name]
                    plat = name.lower().replace(" ", "")
                    url = ""
                    try:
                        url = p["page"].url
                    except Exception:
                        url = p.get("url", "")
                    _runtime.agent_chat_urls[plat] = url
                    _runtime.agent_statuses[plat] = "generating"
                    results[name] = {"status": "paused", "text": "",
                                     "url": url, "page": None,  # Page dies on close
                                     "elapsed_sec": int(time.time() - p["start_time"])}
                _runtime.phase = 2
                _runtime.sub_state = "2_parallel_polling"
                # Pause/resume helpers expect the actual queue dir (where
                # `checkpoint_pause.json` lives). Passing `_tracks_dir`
                # here was a silent bug — the variable now just holds the
                # run name, so the write would land at `<run_name>/`
                # relative to cwd and almost always fail. Resolve to the
                # real queue dir before calling.
                _qd = (Path(__file__).parent / "queues" / _tracks_dir.name) if _tracks_dir else None
                stopped = await pause_and_close_browser(browser, _qd, phase=2)
                if stopped:
                    return results
                # If user added input during the pause, bail out of the
                # round-robin so the orchestrator can rerun Phase 2 with the
                # combined brief (matches "pause + input + resume = rerun").
                if _controls.peek_extra_context():
                    _runtime.restart_requested = True
                    log("[Round-robin] Extra context during pause — signalling Phase 2 restart")
                    return results
                # Relaunch browser + reopen agent tabs
                await browser.start()
                restored = await resume_browser_from_checkpoint(browser, _qd)
                # Reconstruct pending from restored pages
                for name in list(results.keys()):
                    if results[name]["status"] != "paused":
                        continue
                    plat = name.lower().replace(" ", "")
                    if plat in restored:
                        results[name]["page"] = restored[plat]
                        results[name]["url"] = restored[plat].url
                # Resumed — re-read config and only restore agents that are still enabled
                updated_cfg = _controls.pop_config_updates()
                # Also check disk config
                _cfg_path = Path(__file__).parent / "queues"
                if _tracks_dir:
                    _cfg_disk = _cfg_path / _tracks_dir.name / "config.json"
                    if _cfg_disk.exists():
                        try:
                            _disk_cfg = json.loads(_cfg_disk.read_text(encoding="utf-8"))
                            updated_cfg = {**_disk_cfg, **updated_cfg}  # in-memory overrides disk
                        except Exception:
                            pass
                _resume_agents = updated_cfg.get("agents", {"chatgpt": True, "gemini": True, "claude": True})
                _agent_name_map = {"ChatGPT": "chatgpt", "Gemini": "gemini", "Claude": "claude"}
                for name in list(results.keys()):
                    if results[name]["status"] == "paused":
                        agent_key = _agent_name_map.get(name, name.lower())
                        if _resume_agents.get(agent_key, True):
                            # Agent still enabled — restore to polling
                            pending[name] = {"page": results[name]["page"], "url": results[name]["url"],
                                             "start_time": time.time() - results[name]["elapsed_sec"],
                                             "done_count": 0, "cua_confirmed": False,
                                             "last_heartbeat": time.time(),
                                             "last_cua_check": time.time(),
                                             "last_artifact_scrape": 0,
                                             "chatgpt_activity_panel_open": False,
                                             "poll_cycles": 0,
                                             "chatgpt_panel_dom_misses": 0,
                                             "chatgpt_panel_cua_attempts": 0,
                                             "claude_artifact_dom_misses": 0,
                                             "claude_artifact_cua_attempts": 0,
                                             "observer_text_len": 0,
                                             "claude_clarification_replied": False,
                                             # Periodic-refresh gate — a post-resume Gemini
                                             # run gets a fresh refresh clock relative to its
                                             # reconstructed start_time.
                                             "last_refresh": time.time() - results[name]["elapsed_sec"]}
                            del results[name]
                            log(f"  [{name}] Restored to polling")
                        else:
                            # Agent disabled during pause — extract what we have and skip
                            log(f"  [{name}] Disabled during pause — extracting partial results")
                            try:
                                await browser.switch_to_page(results[name]["page"])
                                text = await extract_fns[name](results[name]["page"], browser=browser,
                                    cua_client=cua_client, label=name, verbose=verbose)
                                results[name] = {"status": "disabled_during_pause", "text": text or "",
                                                 "url": results[name]["url"], "page": results[name]["page"],
                                                 "elapsed_sec": results[name]["elapsed_sec"]}
                            except Exception:
                                results[name] = {"status": "disabled_during_pause", "text": "",
                                                 "url": results[name]["url"], "page": results[name]["page"],
                                                 "elapsed_sec": results[name]["elapsed_sec"]}
                            emit_event("agent_skipped", phase=2, agent=agent_key)
                            _write_agent_terminal_status(agent_key, "skipped")
                emit_event("pipeline_resumed", phase=2)
                continue
            return results

        # ── Mid-run skip (from BackendSilentBanner or HumanVerifyBanner) ──
        # User hit "Skip [agent]" in the UI → _controls.skipped_agents has
        # the lowercase name. Extract whatever partial output exists from
        # that tab and drop it from `pending` so the rest of Phase 2 keeps
        # going with the remaining agents.
        _skip_name_map = {"chatgpt": "ChatGPT", "gemini": "Gemini", "claude": "Claude"}
        for _ag_key in list(_controls.skipped_agents):
            _agent_name = _skip_name_map.get(_ag_key)
            if _agent_name and _agent_name in pending:
                p = pending[_agent_name]
                log(f"[{_agent_name}] Skipped by user — extracting partial output", "WARN")
                try:
                    await browser.switch_to_page(p["page"])
                    _partial = await extract_fns[_agent_name](
                        p["page"], browser=browser, cua_client=cua_client,
                        label=_agent_name, verbose=verbose)
                except Exception as _e:
                    log(f"[{_agent_name}] Skip-extract failed: {_e}", "WARN")
                    _partial = ""
                results[_agent_name] = {
                    "status": "skipped_by_user",
                    "text": _partial or "",
                    "url": p.get("url", ""),
                    "page": p["page"],
                    "elapsed_sec": int(time.time() - p["start_time"]),
                }
                del pending[_agent_name]
                emit_event("agent_skipped", phase=2, agent=_ag_key,
                           reason="user_skip",
                           partial_chars=len(_partial or ""))
                # status="skipped" auto-persisted by emit_event hook (runtime reason set).
            # Whether or not the agent was actually in pending, clear it from
            # the skip set so we don't keep firing agent_skipped every tick.
            _controls.skipped_agents.discard(_ag_key)

        # ── Hard retry (close tab + re-run setup from scratch) ──
        # Unlike the soft retry (pastes a follow-up into the same tab and
        # extends the budget — handled per-agent in the timeout branch
        # below), hard retry throws away the tab and starts the agent
        # fresh. Use when the session died or the tab is otherwise
        # unrecoverable. Other agents keep running untouched.
        _hard_name_map = {"chatgpt": "ChatGPT", "gemini": "Gemini", "claude": "Claude"}
        for _agent_key in ("chatgpt", "gemini", "claude"):
            if not _controls.consume_retry_agent_hard(_agent_key):
                continue
            _agent_name = _hard_name_map.get(_agent_key)
            if not _agent_name:
                continue
            # 2026-04-25: when an agent failed pre-pending (setup/paste
            # failed during initial Phase 2 startup), `pending` won't have
            # an entry for it. Seed a stub so the hard-retry codepath below
            # can run from scratch. hard_retry_count starts at 0 since
            # there was no prior attempt counted.
            if _agent_name not in pending:
                log(f"[{_agent_name}] Hard retry requested for agent that failed pre-pending — seeding pending stub", "INFO")
                pending[_agent_name] = {
                    "page": None,
                    "url": "",
                    "start_time": time.time(),
                    "done_count": 0,
                    "cua_confirmed": False,
                    "last_heartbeat": time.time(),
                    "last_cua_check": time.time(),
                    "last_artifact_scrape": 0,
                    "chatgpt_activity_panel_open": False,
                    "poll_cycles": 0,
                    "chatgpt_panel_dom_misses": 0,
                    "chatgpt_panel_cua_attempts": 0,
                    "claude_artifact_dom_misses": 0,
                    "claude_artifact_cua_attempts": 0,
                    "observer_text_len": 0,
                    "empty_retries": 0,
                    "hard_retry_count": 0,
                    "claude_clarification_replied": False,
                    "last_refresh": time.time(),
                }
            p = pending[_agent_name]
            _hard_count = int(p.get("hard_retry_count", 0)) + 1
            # Cap: 2 hard retries per agent per phase. Above the cap we
            # used to fall through to soft retry (follow-up in same tab),
            # but: (a) if the tab is dead, soft retry is a silent no-op
            # because there's no live page to paste into, and (b) the
            # retry_agents set has no consumer in the P2 main loop, so
            # even with a live tab the soft-retry path was effectively
            # dead. Dead-tab guard surfaces fail_agent so the agent
            # doesn't sit in pending forever.
            if _hard_count > 2:
                _tab_dead = False
                try:
                    _old_p = p.get("page")
                    _tab_dead = (_old_p is None or _old_p.is_closed())
                except Exception:
                    _tab_dead = True
                if _tab_dead:
                    log(f"[{_agent_name}] Hard retry cap + dead tab — failing agent", "WARN")
                    fail_agent(_agent_key,
                               f"{_agent_name} hard retries exhausted, tab gone",
                               "All hard-retry attempts have been used and the "
                               "agent's browser tab is no longer alive. Skip drops "
                               "this agent; the others continue.")
                    del pending[_agent_name]
                    results[_agent_name] = {
                        "status": "hard_retry_exhausted_dead_tab",
                        "text": "", "url": "", "page": None, "elapsed_sec": 0}
                    continue
                log(f"[{_agent_name}] Hard retry cap hit (tab still alive) — queuing soft retry", "WARN")
                _controls.retry_agents.add(_agent_key)
                continue
            log(f"[{_agent_name}] Hard retry #{_hard_count} — closing tab, re-running setup", "WARN")
            # Resolve the brief from runtime state (populated before Phase 2 kicks
            # off at line ~10050: `_runtime.original_inputs = {..., 'brief': ...}`).
            _brief_text_hr = _runtime.original_inputs.get("brief") or ""
            _brief_path_hr = None
            if _tracks_dir:
                _bp = Path(__file__).parent / "queues" / _tracks_dir.name / "documents" / "brief.md"
                if _bp.exists():
                    _brief_path_hr = str(_bp)
            # Close old tab — non-fatal if it's already gone.
            try:
                old_page = p.get("page")
                if old_page is not None:
                    await old_page.close()
            except Exception:
                pass
            # Re-run agent setup. On crash, drop the agent from pending so
            # the phase can proceed with whoever else is still healthy.
            try:
                restart = await _restart_phase2_agent(
                    _agent_name, browser, cua_client,
                    _brief_text_hr, _brief_path_hr, verbose)
            except Exception as _e:
                log(f"[{_agent_name}] Hard retry setup crashed: {_e}", "ERROR")
                fail_agent(_agent_key, "Hard retry failed", str(_e)[:200])
                del pending[_agent_name]
                results[_agent_name] = {"status": "hard_retry_failed", "text": "",
                                         "url": "", "page": None, "elapsed_sec": 0}
                continue
            if restart is None:
                log(f"[{_agent_name}] Hard retry returned None — dropping agent", "WARN")
                del pending[_agent_name]
                results[_agent_name] = {"status": "hard_retry_failed", "text": "",
                                         "url": "", "page": None, "elapsed_sec": 0}
                continue
            new_page, verified_h = restart
            # If the restart's setup/paste failed (verified_h False AND we
            # got a non-verified page back from start_agent_no_gemini_wait
            # ok=False), the helper already emitted pipeline_error with
            # Retry/Skip actions. Drop the agent from pending so the user's
            # next Retry click cleanly re-seeds via the pre-pending path
            # above.
            if not verified_h:
                # verified_h could legitimately be False if generation
                # verification didn't land within the window — that's the
                # benign case the WARN below handles. But if start_agent
                # itself returned ok=False, the page was set up but paste
                # failed — `_restart_phase2_agent` would have returned
                # (page, False) and emitted pipeline_error already. Either
                # way, we keep `pending` populated so polling can retry,
                # but emit a clear status.
                pass
            _now = time.time()
            pending[_agent_name] = {
                "page": new_page,
                "url": new_page.url if new_page else "",
                "start_time": _now,
                "done_count": 0,
                "cua_confirmed": False,
                "last_heartbeat": _now,
                "last_cua_check": _now,
                "last_artifact_scrape": 0,
                "chatgpt_activity_panel_open": False,
                "poll_cycles": 0,
                "chatgpt_panel_dom_misses": 0,
                "chatgpt_panel_cua_attempts": 0,
                "claude_artifact_dom_misses": 0,
                "claude_artifact_cua_attempts": 0,
                "observer_text_len": 0,
                "empty_retries": 0,
                "hard_retry_count": _hard_count,
                "claude_clarification_replied": False,
                # Periodic-refresh gate — a hard-retried Gemini run gets a
                # fresh refresh clock relative to its new start_time.
                "last_refresh": _now,
            }
            _runtime.register_page(_agent_key, new_page,
                                    new_page.url if new_page else "")
            if verified_h:
                try:
                    await inject_agent_observer(new_page, _agent_key)
                except Exception:
                    pass
                try:
                    emit_event("agent_progress", phase=2, agent=_agent_key,
                               status="generating",
                               progress=f"{_agent_name} restarted (hard retry #{_hard_count}) — running")
                except Exception:
                    pass
                log(f"[{_agent_name}] Hard retry successful ✓")
            else:
                log(f"[{_agent_name}] Hard retry tab opened but not verified yet — polling will re-check", "WARN")

        # Rotate iteration order so no agent is always "first". With 3
        # agents, the order cycles A→B→C, B→C→A, C→A→B, A→B→C, ensuring
        # that over 3 ticks every agent has been processed first.
        _pending_keys = list(pending.keys())
        if _pending_keys:
            _shift = _tick_counter % len(_pending_keys)
            _pending_keys = _pending_keys[_shift:] + _pending_keys[:_shift]

        for name in _pending_keys:
            p = pending[name]
            elapsed = time.time() - p["start_time"]
            # Per-agent cycle counter (used for "give research time to settle"
            # gate before opening Claude/ChatGPT panels — see iter-#3 logic
            # below). Increment ONCE per round-robin tick per agent.
            p["poll_cycles"] = p.get("poll_cycles", 0) + 1

            # DGOPS-7367 (2026-05-13) — deferred DNS retry tick. State-
            # machine lives in `_advance_dns_backoff` (research.py:~7494),
            # extracted from this inline block on 2026-05-18 for unit-test
            # coverage. Runs BEFORE the spotlight + scrape body so a
            # successful retry's fresh DOM is what this tick reads from.
            if await _advance_dns_backoff(p, name, time.time(), elapsed):
                continue

            # ── C6: cursor foreground + partial-content refresh ──
            # Bring this agent's tab to the front before any scrape/check so
            # its MutationObserver has the freshest token stream (Chromium
            # throttles background tabs less under Playwright than a normal
            # browser, but foregrounding still produces materially fresher
            # data — especially after a long blocking await on another agent).
            try:
                await browser.switch_to_page(p["page"])
            except Exception as _sw_err:
                log(f"[{name}] switch_to_page at cursor start failed: {_sw_err}", "WARN")

            # A4 (2026-05-01): visible spotlight — DOM Range select on the
            # latest response paragraph so the user can SEE the round-robin
            # land on this agent. Symmetric across all 3 (Claude already
            # had a CUA-side-effect "highlight" via artifact panel open;
            # this gives ChatGPT/Gemini matching visibility without the
            # ~$0.05/round CUA cost). Throttled to once per 30s/agent so
            # it doesn't fight rapidly with the user's manual selection.
            _last_spotlight = p.get("last_spotlight_at", 0)
            if (time.time() - _last_spotlight) > 30:
                p["last_spotlight_at"] = time.time()
                try:
                    await _spotlight_latest_response(p["page"], name)
                except Exception:
                    pass

            # ── Claude clarification auto-reply (2026-05-18) ──
            # When the brief is vague/template, Claude responds with chat
            # text asking clarifying questions INSTEAD of starting Deep
            # Research. Without this block the BE would wait for an
            # artifact that never appears and eventually surface a generic
            # "Hit a snag" alert at the wall-clock cap.
            #
            # 5 conjoint conditions (all must hold) — tight enough that a
            # real research-in-progress response can't false-fire:
            #   (1) name == "Claude" and not already replied for this agent
            #   (2) 180s ≤ elapsed ≤ 900s (clarifications come fast; if
            #       research already started by 15min we shouldn't intervene)
            #   (3) verify_claude_generating == False (Claude finished its
            #       chat reply and is idle, not mid-stream)
            #   (4) No artifact / side-panel visible in DOM (research
            #       artifact has NOT appeared yet)
            #   (5) Last assistant message contains ≥2 '?' chars AND its
            #       tail matches _CLAUDE_CLARIFICATION_SIGNOFF_RE (the
            #       "Once you ... I'll launch the research" signature)
            # On match: type "Up to Claude to decide for the best output."
            # + Enter, reset start_time + last_heartbeat so the wall-clock
            # doesn't fire mid-recompose, set one-shot flag, skip rest of
            # tick.
            if (
                name == "Claude"
                and not p.get("claude_clarification_replied")
                and 180 <= elapsed <= 900
            ):
                try:
                    if not await verify_claude_generating(p["page"]):
                        # Cheap artifact-panel probe — if a right-side
                        # artifact panel is already open, this isn't a
                        # clarification scenario.
                        #
                        # Bare-aside REMOVED 2026-05-18: Claude.ai's LEFT
                        # navigation ("New chat / Recents / Projects") is
                        # rendered as <aside> and exceeds any reasonable
                        # bbox lower bound, so a bare-aside check would
                        # always match and the no-panel gate would never
                        # be true. Tightened gate ports _PANEL_GATE_JS at
                        # research.py:10639 — must be right-half-of-
                        # viewport, ≥400px wide, and innerText must not
                        # read like nav chrome (≥2 nav markers).
                        try:
                            _has_panel = await p["page"].evaluate(r"""() => {
                                const NAV_MARKERS = /\b(new chat|recents?|projects|search|topic generator|starred|home|chats?\b)\b/i;
                                const _vw = window.innerWidth || document.documentElement.clientWidth;
                                const sels = [
                                    '[class*="artifact-panel" i]',
                                    '[data-testid*="artifact-panel"]',
                                    '[role="complementary"][class*="artifact" i]',
                                    '[class*="right-panel"][class*="artifact" i]',
                                    '[class*="side-panel"][class*="artifact" i]',
                                    'div[class*="artifact"][class*="open" i]'
                                ];
                                const seen = new Set();
                                const candidates = [];
                                for (const s of sels) {
                                    for (const el of document.querySelectorAll(s)) {
                                        if (seen.has(el)) continue;
                                        seen.add(el);
                                        candidates.push(el);
                                    }
                                }
                                for (const el of candidates) {
                                    const r = el.getBoundingClientRect();
                                    if (r.width < 400) continue;
                                    if (r.right < _vw * 0.5) continue;
                                    const head = (el.innerText || '').slice(0, 500);
                                    if (NAV_MARKERS.test(head)) {
                                        let n = 0;
                                        const re = new RegExp(NAV_MARKERS.source, 'gi');
                                        while (re.exec(head) !== null) n++;
                                        if (n >= 2) continue;
                                    }
                                    return true;
                                }
                                return false;
                            }""")
                        except Exception:
                            _has_panel = False
                        if not _has_panel:
                            matched, last_text, q_count = await _claude_asking_clarification(p["page"])
                            if matched and q_count >= 2 and 0 < len(last_text) < 3000:
                                log(f"[{name}] Clarification scenario detected — "
                                    f"sign-off matched, {q_count} '?'s, {len(last_text)} chars. "
                                    f"Auto-sending defer reply.", "INFO")
                                emit_event(
                                    "agent_progress", phase=2, agent="claude",
                                    status="generating",
                                    progress="Claude was asking for clarification — auto-replied to continue research.",
                                )
                                sent = await _claude_send_clarification_reply(p["page"], name)
                                p["claude_clarification_replied"] = True
                                if sent:
                                    # Reset all wall-clock / growth baselines
                                    # so neither the wall-clock nor the no-
                                    # growth watchdog (research.py:~14987,
                                    # requires elapsed>1200 AND no_growth>1200)
                                    # fires a false-positive snag while Claude
                                    # composes the new response. Without
                                    # last_growth_time reset, no_growth_secs
                                    # would carry the clarification-window's
                                    # ~200-900s into the new run and trigger
                                    # the watchdog ~1000s sooner than designed.
                                    _now = time.time()
                                    p["start_time"] = _now
                                    p["last_heartbeat"] = _now
                                    p["last_growth_time"] = _now
                                    p["stuck_warned_at"] = 0
                                    p["last_artifact_scrape"] = 0  # let next tick re-probe
                                    continue
                except Exception as _cer:
                    log(f"[{name}] Clarification-check failed (non-fatal): {_cer}", "DEBUG")

            # ── Gemini kickoff-stall auto-nudge (multi-shot) ──
            # User-observed (2026-05-22 + 2026-05-24): Gemini ACKs "Great,
            # I'm on it" but the "Researching N sources" / "Researching
            # websites..." card never appears — silently stalls. A single
            # polite nudge ("Please proceed with the deep research now.")
            # sometimes works but Gemini also sometimes ignores it
            # (observed in the 2026-05-24 E2E), and the user had to
            # manually type "Done?" to unstick. Multi-shot with escalating
            # wording across attempts hardens against this:
            #   - Nudge 1 (polite directive)       at ~45s
            #   - Nudge 2 (yes/no check-in)        at ~225s (180s spacing)
            #   - Nudge 3 (terse, "Done?")         at ~405s (180s spacing)
            # All three fit inside the 600s outer cap, well before the
            # 20-min general no-growth watchdog at research.py:~17441
            # takes over.
            #
            # Gates (all must hold):
            #   - name == Gemini
            #   - nudge count < 3
            #   - 45s ≤ elapsed ≤ 600s (since last reset)
            #   - either no prior nudge OR ≥180s since the last one
            if (
                name == "Gemini"
                and p.get("gemini_kickoff_nudge_count", 0) < len(_GEMINI_KICKOFF_NUDGES)
                and 45 <= elapsed <= 600
                and (
                    p.get("gemini_last_kickoff_nudge_at", 0.0) == 0.0
                    or (time.time() - p.get("gemini_last_kickoff_nudge_at", 0.0)) >= 180
                )
            ):
                try:
                    pending_kickoff, reason = await _gemini_kickoff_pending(p["page"])
                    if pending_kickoff:
                        attempt_idx = p.get("gemini_kickoff_nudge_count", 0)
                        total = len(_GEMINI_KICKOFF_NUDGES)
                        log(f"[{name}] Kickoff-stall detected ({reason}) — "
                            f"sending nudge #{attempt_idx + 1}/{total}.", "INFO")
                        emit_event(
                            "agent_progress", phase=2, agent="gemini",
                            status="generating",
                            progress=(
                                f"Gemini stalled after ACK — auto-nudge "
                                f"#{attempt_idx + 1}/{total} to start research."
                            ),
                        )
                        sent = await _gemini_send_kickoff_nudge(
                            p["page"], name, attempt_idx=attempt_idx,
                        )
                        p["gemini_kickoff_nudge_count"] = attempt_idx + 1
                        p["gemini_last_kickoff_nudge_at"] = time.time()
                        if sent:
                            # Reset baselines so the no-growth + wall-
                            # clock watchdogs don't fire from the pre-
                            # nudge stall window (same rationale as the
                            # Claude reset above at research.py:~16863).
                            # Reset per-nudge — gives Gemini a fresh
                            # window after each attempt.
                            _now = time.time()
                            p["start_time"] = _now
                            p["last_heartbeat"] = _now
                            p["last_growth_time"] = _now
                            p["stuck_warned_at"] = 0
                            continue
                except Exception as _gke:
                    log(f"[{name}] Gemini-kickoff-check failed (non-fatal): {_gke}", "DEBUG")

            # 2026-05-04: per-agent wall-clock timeout REMOVED entirely.
            # Phase-level soft warn from _await_phase_with_active_deadline
            # already covers the slow-agent case (the only practical way
            # for P2 phase wall-clock to fire is one slow agent in
            # pending), and the dual phase+agent alert UX required two
            # Wait clicks to clear. Single phase-level alert is enough.
            #
            # Other safety nets remain INSIDE this loop and are unaffected:
            #   • Browser-crash sweep (line ~11305): page.is_closed → fail_agent
            #   • Skipped_agents handler (line ~11452): user explicit skip
            #   • Hard retry (line ~11488): user-driven, capped at 2/agent
            #   • Session-expiry mid-run (line ~11726): /login redirect detection
            #   • No-growth stuck watchdog (line ~12279): elapsed>1200 + no_growth>1200
            #   • Stop button: 5s short-circuit at the helper level
            # An agent that is genuinely stuck (not just slow) is caught by
            # the no-growth watchdog within ~20 min — far sooner than 90 min.
            # An agent that's genuinely working but slow gets the phase-
            # level soft warn at the user's max_wait_min budget.

            # ── Mid-run session expiry check ──
            # Agent tabs sometimes get logged out silently (cookie expiry,
            # background re-auth failure). Catch it here so the user gets a
            # clear banner instead of the polling loop churning indefinitely
            # against a login page. Throttled — one check every 2 min per agent.
            # Require 2 consecutive detections before firing the alert to avoid
            # false alarms from transient modals / loading states.
            _last_auth_check = p.get("last_auth_check", 0)
            if (time.time() - _last_auth_check) > 120:
                p["last_auth_check"] = time.time()
                agent_key_auth = normalize_agent_key(name)
                platform_key = name.lower().replace(" ", "")
                expired, reason = await detect_session_expiry(p["page"], platform_key, name)
                if not expired:
                    p["session_expiry_hits"] = 0
                else:
                    p.setdefault("session_expiry_hits", 0)
                    p["session_expiry_hits"] += 1
                if expired and p.get("session_expiry_hits", 0) < 2:
                    log(f"[{name}] Possible session expiry ({reason}) — waiting for 2nd confirmation before alerting", "WARN")
                    expired = False  # Suppress alert this tick
                if expired:
                    log(f"[{name}] Session expired mid-run ({reason}) — confirmed by 2 consecutive checks", "WARN")
                    p["session_expiry_hits"] = 0  # reset for next time
                    fail_agent(agent_key_auth,
                               f"{name} session expired mid-run",
                               (f"The {name} tab drifted to a login page ({reason}). "
                                "Log in again in the browser, then Retry. Skip drops this agent."))
                    # Block this agent's polling until user decides. Other
                    # agents keep polling (they don't hit this await).
                    auth_decision = await _controls.await_agent_decision(agent_key_auth, timeout=1800.0)
                    log(f"[{name}] Session-expiry decision: {auth_decision}")
                    if auth_decision == "stop":
                        break
                    if auth_decision == "skip":
                        # Existing skipped_agents handler will finalize on next tick
                        continue
                    if auth_decision == "retry":
                        # Refresh the tab so the agent's (now logged-in) session cookie
                        # lands, then reset polling state. Don't extend budget — this
                        # is the user's re-auth, not a new research run.
                        try:
                            await p["page"].reload(wait_until="domcontentloaded", timeout=15000)
                            await asyncio.sleep(3)
                        except Exception as _e:
                            log(f"[{name}] Reload after re-auth failed: {_e}", "WARN")
                        p["last_auth_check"] = time.time()
                        continue
                    # 'continue_partial' / 'timeout' — user idle; keep polling
                    # with the stale session (likely 30min re-grace from platforms)
                    continue

            # ── Gemini periodic refresh (every GEMINI_REFRESH_INTERVAL) ──
            # Post-2026-05 Gemini does NOT push the completed Deep-Research
            # panel into the live DOM — the "Share & Export" done-marker +
            # completion text only render after a page reload (verified in
            # backend-2.log: a 123-min Golden Retriever run sat on 20 straight
            # CUA "still generating" reads until a manual refresh surfaced the
            # finished report). So we reload every GEMINI_REFRESH_INTERVAL
            # (~10 min); detect_completion_gemini then sees the done-state on
            # its own and extracts, instead of leaning on the CUA visual check.
            #
            # Replaces the prior one-shot 10-min reload + 15-min
            # paste_followup("Is the Research completed?") crutch: on 3.1 Pro
            # the DOM froze for the whole 1-2h run and needed a manual nudge,
            # but Flash 3.5 completes cleanly and the periodic reload alone
            # surfaces the done-state (user-validated 2026-05-26).
            #
            # Race-safe: if completion text is already on page we skip the
            # reload and let the detector extract on the next tick. Gated to
            # Gemini, never during a DNS retry. Orthogonal to the kickoff-stall
            # multi-shot nudge (~17421-17485, elapsed ≤ 600s only).
            if (
                name == "Gemini"
                and (time.time() - p.get("last_refresh", p["start_time"])) >= GEMINI_REFRESH_INTERVAL
                and not p.get("dns_retry_at")
            ):
                p["last_refresh"] = time.time()
                try:
                    _body_text_10 = await p["page"].evaluate(
                        "() => (document.body.innerText || '').slice(0, 8000)"
                    )
                    if _GEMINI_COMPLETION_RE.search(_body_text_10 or ""):
                        # Completion text already on page — skip this reload;
                        # detect_completion_gemini extracts on the next tick.
                        log(
                            "[Gemini] periodic refresh: completion text "
                            "already on page — skipping reload"
                        )
                    else:
                        _url_pre_reload = ""
                        try:
                            _url_pre_reload = p["page"].url or ""
                        except Exception:
                            _url_pre_reload = ""
                        log(
                            "[Gemini] periodic refresh firing — "
                            f"page.reload() so the completed DR panel + "
                            f"done-marker can render. URL pre-reload={_url_pre_reload}"
                        )
                        try:
                            emit_event(
                                "agent_progress", phase=2, agent="gemini",
                                status="generating",
                                progress=(
                                    "Refreshing Gemini so the finished "
                                    "research panel can load."
                                ),
                            )
                        except Exception:
                            pass
                        try:
                            await p["page"].reload(
                                wait_until="domcontentloaded", timeout=20000
                            )
                        except Exception as _re:
                            log(
                                f"[Gemini] periodic reload raised "
                                f"(non-fatal): {_re}",
                                "WARN",
                            )
                        await asyncio.sleep(5.0)
                        # If the reload drifted us off the conversation
                        # URL, navigate back. Only attempt if the
                        # pre-reload URL had a path component beyond
                        # the bare app root.
                        try:
                            _url_post_reload = p["page"].url or ""
                            _pre_meaningful = (
                                _url_pre_reload
                                and _url_pre_reload != _url_post_reload
                                and ("/app/" in _url_pre_reload
                                     or "/chat/" in _url_pre_reload)
                                and _url_pre_reload.rstrip("/").split("/")[-1] != "app"
                            )
                            if _pre_meaningful:
                                log(
                                    f"[Gemini] post-reload URL drifted: "
                                    f"{_url_pre_reload} → {_url_post_reload} "
                                    f"— navigating back to preserve conversation",
                                    "WARN",
                                )
                                try:
                                    await p["page"].goto(
                                        _url_pre_reload,
                                        wait_until="domcontentloaded",
                                        timeout=20000,
                                    )
                                    await asyncio.sleep(3.0)
                                except Exception as _gge:
                                    log(
                                        f"[Gemini] safety-net goto back "
                                        f"raised (non-fatal): {_gge}",
                                        "WARN",
                                    )
                        except Exception:
                            pass
                        try:
                            await inject_agent_observer(p["page"], "gemini")
                        except Exception as _inj_err:
                            log(
                                f"[Gemini] post-reload observer re-inject "
                                f"failed (non-fatal): {_inj_err}",
                                "DEBUG",
                            )
                        # Reset baselines so the no-growth + stuck
                        # watchdog don't fire from the reload window.
                        _now = time.time()
                        p["last_growth_time"] = _now
                        p["last_heartbeat"] = _now
                        p["stuck_warned_at"] = 0
                        p["last_cua_check"] = _now
                except Exception as _gre:
                    log(
                        f"[Gemini] periodic refresh raised "
                        f"(non-fatal): {_gre}",
                        "WARN",
                    )
                continue

            # DOM scrape (primary); MutationObserver handles token-level stream separately.
            scrape_fn = SCRAPE_FNS.get(name)
            progress = {}
            scrape_ok = False
            if scrape_fn:
                try:
                    progress = await scrape_fn(p["page"]) or {}
                    scrape_ok = True
                except Exception as _scrape_err:
                    # Don't mask scrape failures — tell frontend the scrape degraded
                    log(f"[{name}] DOM scrape failed: {_scrape_err}", "WARN")

            # Claude artifact tracking — open the FIRST artifact and keep it open
            # so subsequent polls re-read live (URLs / steps / sections) without
            # re-clicking. Auto-close removed: the second artifact (final report) is
            # detected/opened separately by extract_claude_response at completion.
            #
            # 2026-04-26 (v3): iter-#3 settle gate — wait until ≥3 polling cycles
            # OR ≥180s wall-clock (whichever first) so research is actually
            # ongoing and the artifact card has spawned. Same gate applied to
            # ChatGPT below for symmetry. After 2 consecutive DOM "no artifact"
            # readings (after the gate clears), escalate to CUA tier-3 once.
            # One-shot Claude page refresh at cycle 2 — unstick prophylaxis.
            # Claude.ai sometimes hangs DOM mid-research even though server-side
            # generation continues. A single reload mid-research re-mounts the
            # conversation + artifact card from server state without losing any
            # research progress (research is server-side; refresh is DOM-only).
            # Runs BEFORE the artifact-open gate clears at cycle 3, so iter 3's
            # first DOM probe meets a fresh DOM.
            if (name == "Claude"
                    and p.get("poll_cycles", 0) == 2
                    and not p.get("claude_refreshed_once")
                    and not p.get("dns_retry_at")):
                try:
                    log("[Claude] one-shot page refresh at cycle=2 (unstick prophylaxis)")
                    await p["page"].reload(wait_until="domcontentloaded", timeout=20000)
                    await asyncio.sleep(3.0)
                    p["claude_refreshed_once"] = True
                except Exception as _re:
                    # DGOPS-7367 (2026-05-13): if the reload tripped a
                    # transient network error (DNS / connection hiccup),
                    # don't write claude_refreshed_once and don't fall
                    # through to the CUA-error-drop path. Schedule an
                    # exponential-backoff retry instead — most residential
                    # DNS blips self-heal in < 10min, well inside Phase 2's
                    # budget. Non-transient errors (SSL, blocked, etc.)
                    # keep today's behavior: mark refreshed-once, let CUA
                    # diagnose, drop on `is_error` verdict.
                    if _is_transient_net_error(_re):
                        p["error_source"] = "network"
                        p["dns_last_error"] = str(_re)[:200]
                        p["dns_retry_attempts"] = 1
                        p["dns_retry_at"] = time.time() + _DNS_BACKOFF_SECS[0]
                        log(f"[Claude] transient network error during refresh "
                            f"({str(_re)[:80]}) — scheduling retry in "
                            f"{_DNS_BACKOFF_SECS[0]}s (attempt 1/{len(_DNS_BACKOFF_SECS)})", "WARN")
                        # DGOPS-7367 hardening (2026-05-13): keep the
                        # silence watchdogs satisfied during the initial
                        # 30s wait + any future retry waits.
                        try:
                            emit_event("agent_progress", phase=2, agent="claude",
                                       status="generating",
                                       progress=f"Network blip during prophylaxis refresh — "
                                                f"retrying in {_DNS_BACKOFF_SECS[0]}s "
                                                f"(1/{len(_DNS_BACKOFF_SECS)})",
                                       elapsedSec=int(elapsed))
                        except Exception:
                            pass
                    else:
                        log(f"[Claude] refresh failed (non-transient): {_re}", "WARN")
                        p["claude_refreshed_once"] = True

            # 2026-05-03: lowered cycle gate 3→2 and elapsed 180s→90s for
            # parity with ChatGPT's panel-open gate at line ~11689.
            # Claude's artifact panel is the only path that ships
            # source_urls into progress["source_urls"]; the prior 180s gate
            # left the dropdown showing 0 source chips for the first 3
            # minutes of every Claude P2 run. ChatGPT proved the 90s gate
            # is safe (artifact strip is rendered by ~30s on a healthy run).
            _claude_gate_ok = (p.get("poll_cycles", 0) >= 2 or elapsed >= 90)
            if (name == "Claude" and _claude_gate_ok and
                    (time.time() - p.get("last_artifact_scrape", 0)) > ARTIFACT_SCRAPE_INTERVAL):
                try:
                    artifact_data = await scrape_claude_artifact_tracking(
                        p["page"], browser=browser, cua_client=cua_client,
                        verbose=verbose, keep_open=True,
                        already_open=p.get("artifact_panel_open", False))
                    if artifact_data:
                        if not p.get("artifact_panel_open"):
                            log(f"[Claude] artifact panel opened (first time) at "
                                f"elapsed={int(elapsed)}s, cycle={p.get('poll_cycles')}")
                        p["artifact_panel_open"] = True
                        p["claude_artifact_dom_misses"] = 0  # reset on success
                        # Mirror onto runtime singleton so extract_and_record_agent
                        # (which has no `p` handle) can close-1 before clicking the
                        # final artifact card. See extract_claude_response signature.
                        try:
                            _runtime.claude_artifact_panel_open = True
                        except Exception:
                            pass
                        if artifact_data.get("source_urls"):
                            for key in ("source_urls", "steps", "sections", "tool_uses"):
                                if artifact_data.get(key):
                                    existing = progress.get(key, []) or []
                                    merged = list(dict.fromkeys(existing + artifact_data[key]))
                                    progress[key] = merged
                            # Invariant: progress["sources"] == len(progress["source_urls"]).
                            # Without this, the merge can grow source_urls past
                            # artifact_data's count, leaving the chip stuck at
                            # the smaller number while the URL list is longer.
                            progress["sources"] = len(progress.get("source_urls", []) or [])
                            if artifact_data.get("partial_text_len", 0) > progress.get("partial_text_len", 0):
                                progress["partial_text_len"] = artifact_data["partial_text_len"]
                            progress["artifact_count"] = artifact_data.get("artifact_count", 0)
                            scrape_ok = True
                            log(f"[Claude] Artifact tracking: {len(artifact_data.get('source_urls', []))} URLs, "
                                f"{len(artifact_data.get('steps', []))} steps, "
                                f"{len(artifact_data.get('sections', []))} sections")
                    else:
                        # No artifact detected — count as DOM miss for CUA escalation.
                        if not p.get("artifact_panel_open"):
                            p["claude_artifact_dom_misses"] = p.get("claude_artifact_dom_misses", 0) + 1
                            log(f"[Claude] artifact DOM miss "
                                f"#{p['claude_artifact_dom_misses']} at cycle={p.get('poll_cycles')}",
                                "DEBUG")
                    p["last_artifact_scrape"] = time.time()
                except Exception as e:
                    log(f"[Claude] Artifact tracking scrape failed: {e}", "WARN")
                    p["last_artifact_scrape"] = time.time()

                # CUA tier-3 escalation — fires after 2 consecutive DOM misses,
                # capped at 1/agent/phase. Tries to find + click the FIRST
                # artifact card visually.
                if (not p.get("artifact_panel_open")
                        and p.get("claude_artifact_dom_misses", 0) >= 2
                        and p.get("claude_artifact_cua_attempts", 0) == 0
                        and cua_client):
                    log(f"[Claude] DOM missed artifact 2x — escalating to CUA tier-3 "
                        f"(cycle={p.get('poll_cycles')})")
                    emit_tier_transition(phase=2, agent="claude",
                        op="open_artifact_1", from_tier="dom", to_tier="cua",
                        reason="dom_2_misses")
                    p["claude_artifact_cua_attempts"] = 1
                    async def _claude_p2_cua():
                        return await asyncio.wait_for(
                            agent_loop(cua_client, browser,
                                PROMPT_OPEN_CLAUDE_SOURCE_ARTIFACT,
                                "Open the FIRST artifact card (research/sources tracking) "
                                "in the Claude conversation. NEVER click the last artifact.",
                                model=CUA_MODEL, max_iterations=5,
                                verbose=verbose, target_page=p["page"]),
                            timeout=120.0)
                    try:
                        cua_res = await _shadow_observed_cua(
                            p["page"], hotspot_id="7d", phase=2, platform="claude",
                            current_step="open_artifact_1",
                            context_hint=f"DOM 2-miss at cycle={p.get('poll_cycles')}",
                            expected_outcome="right panel mounts artifact-1 checklist",
                            cua_coro_factory=_claude_p2_cua)
                        out = ((cua_res or {}).get("text") or "").lower()
                        if "panel: open" in out or "panel: already_open" in out:
                            p["artifact_panel_open"] = True
                            try:
                                _runtime.claude_artifact_panel_open = True
                            except Exception:
                                pass
                            log("[Claude] artifact panel opened via CUA tier-3")
                        else:
                            log(f"[Claude] CUA tier-3 didn't confirm panel open: {out[:120]}", "WARN")
                    except asyncio.TimeoutError:
                        log("[Claude] CUA tier-3 timed out after 120s", "WARN")
                    except Exception as _ce:
                        log(f"[Claude] CUA tier-3 failed: {_ce}", "WARN")

            # ── Block 1b: inject MutationObserver INSIDE DR iframe ──
            # Host-page observer cannot see cross-origin iframe content;
            # without this, partial_text_len flatlines while DR streams.
            # Off by default — opt in via DG_CHATGPT_IFRAME_OBSERVER=1.
            # Retried each cycle until iframe exists (returns False if not yet).
            if (name == "ChatGPT"
                    and os.environ.get("DG_CHATGPT_IFRAME_OBSERVER", "0") == "1"
                    and not p.get("iframe_observer_injected")):
                try:
                    if await inject_chatgpt_dr_iframe_observer(p["page"]):
                        p["iframe_observer_injected"] = True
                except Exception as _ioe:
                    log(f"[ChatGPT] iframe observer inject failed: {_ioe}", "WARN")

            # ChatGPT activity-strip open — DOM tier-1 → CUA tier-3 fallback.
            # Strip rendered as styled <div> at bottom of chat thread reading
            # "Looking into X... N searches". Side panel with full step list +
            # source URLs only mounts AFTER click. Without it polling sees only
            # the truncated preview.
            #
            # 2026-04-26 (v3) lessons from 3 failed runs:
            #  - v1 narrow selector (button/[role="button"]) matched 0
            #    candidates because strip is a bare <div> — fix: walk * with
            #    full pointer/mouse event chain (see _open_chatgpt_activity_panel).
            #  - Iter-#1 fired before strip rendered — fix: iter-#3 gate
            #    (poll_cycles>=3 or elapsed>=180s — whichever first).
            #  - DOM "click" silently swallowed — fix: post-click verifier
            #    (`_verify_chatgpt_panel_open`) confirms side panel actually
            #    rendered before flipping the flag.
            #  - After 2 DOM misses → CUA tier-3 fallback (capped at 1/phase).
            # 2026-04-29: lowered gate from iter-#3/180s to iter-#2/90s. The
            # activity strip exists from t≈10s on a DR job; waiting 3 polls
            # left the FE narration card stuck on "0 sources, 0 chars" stub
            # copy for up to 3 minutes. Earlier gate = sub-2-min rich data.
            _cgpt_gate_ok = (p.get("poll_cycles", 0) >= 2 or elapsed >= 90)
            # Re-verify each cycle — ChatGPT auto-collapses the panel when
            # the user navigates sub-views or after long idle. The verifier
            # is a cheap JS call; if the panel stays open across cycles
            # this is a no-op early exit. If it collapsed, we re-open.
            if name == "ChatGPT" and _cgpt_gate_ok and p.get("chatgpt_activity_panel_open"):
                try:
                    if not await _verify_chatgpt_panel_open(p["page"]):
                        p["chatgpt_activity_panel_open"] = False
                        log(f"[ChatGPT] activity panel collapsed (cycle="
                            f"{p.get('poll_cycles')}) — will re-open this cycle",
                            "DEBUG")
                except Exception:
                    pass
            if (name == "ChatGPT" and _cgpt_gate_ok and
                    not p.get("chatgpt_activity_panel_open")):
                try:
                    res = await _open_chatgpt_activity_panel(p["page"])
                    cands = (res or {}).get("candidates", 0)
                    if not res or not res.get("found"):
                        p["chatgpt_panel_dom_misses"] = p.get("chatgpt_panel_dom_misses", 0) + 1
                        log(f"[ChatGPT] panel DOM miss #{p['chatgpt_panel_dom_misses']} "
                            f"(cycle={p.get('poll_cycles')}, walked_hits={cands}) — "
                            f"strip not yet rendered or wording changed", "DEBUG")
                    elif res.get("alreadyExpanded"):
                        p["chatgpt_activity_panel_open"] = True
                        p["chatgpt_panel_dom_misses"] = 0
                        log(f"[ChatGPT] activity panel already expanded at "
                            f"elapsed={int(elapsed)}s — label: \"{res.get('label','')[:80]}\"")
                    elif res.get("clicked"):
                        # Verify panel actually rendered (mitigates silent click failure).
                        await asyncio.sleep(2.0)
                        verified = await _verify_chatgpt_panel_open(p["page"])
                        if verified:
                            p["chatgpt_activity_panel_open"] = True
                            p["chatgpt_panel_dom_misses"] = 0
                            log(f"[ChatGPT] activity panel opened via DOM at "
                                f"elapsed={int(elapsed)}s — label: \"{res.get('label','')[:80]}\" "
                                f"clickedTag={res.get('clickedTag','?')}")
                        else:
                            p["chatgpt_panel_dom_misses"] = p.get("chatgpt_panel_dom_misses", 0) + 1
                            log(f"[ChatGPT] DOM clicked but panel didn't render — "
                                f"miss #{p['chatgpt_panel_dom_misses']}", "WARN")
                    else:
                        p["chatgpt_panel_dom_misses"] = p.get("chatgpt_panel_dom_misses", 0) + 1
                        log(f"[ChatGPT] panel found but click failed — "
                            f"label: \"{res.get('label','')[:80]}\" "
                            f"err={res.get('error','?')}", "WARN")
                except Exception as e:
                    log(f"[ChatGPT] activity panel open failed: {e}", "WARN")
                    p["chatgpt_panel_dom_misses"] = p.get("chatgpt_panel_dom_misses", 0) + 1

                # CUA tier-3 escalation after 2 DOM misses (capped at 1/phase).
                if (not p.get("chatgpt_activity_panel_open")
                        and p.get("chatgpt_panel_dom_misses", 0) >= 2
                        and p.get("chatgpt_panel_cua_attempts", 0) == 0
                        and cua_client):
                    log(f"[ChatGPT] DOM missed strip 2x — escalating to CUA tier-3 "
                        f"(cycle={p.get('poll_cycles')})")
                    emit_tier_transition(phase=2, agent="chatgpt",
                        op="open_activity_panel", from_tier="dom", to_tier="cua",
                        reason="dom_2_misses")
                    p["chatgpt_panel_cua_attempts"] = 1
                    async def _cgpt_p2_cua():
                        return await asyncio.wait_for(
                            agent_loop(cua_client, browser,
                                PROMPT_OPEN_CHATGPT_SOURCE_PANEL,
                                "Open the activity strip at the bottom of this ChatGPT "
                                "Deep Research conversation. ONE click only. Verify the "
                                "side panel slides out before reporting.",
                                model=CUA_MODEL, max_iterations=5,
                                verbose=verbose, target_page=p["page"]),
                            timeout=120.0)
                    try:
                        cua_res = await _shadow_observed_cua(
                            p["page"], hotspot_id="7c", phase=2, platform="chatgpt",
                            current_step="open_activity_panel",
                            context_hint=f"DOM 2-miss at cycle={p.get('poll_cycles')}",
                            expected_outcome="side panel mounts on right with step list",
                            cua_coro_factory=_cgpt_p2_cua)
                        out = ((cua_res or {}).get("text") or "").lower()
                        if "panel: open" in out or "panel: already_open" in out:
                            p["chatgpt_activity_panel_open"] = True
                            log("[ChatGPT] activity panel opened via CUA tier-3")
                        else:
                            log(f"[ChatGPT] CUA tier-3 didn't confirm panel open: {out[:120]}", "WARN")
                    except asyncio.TimeoutError:
                        log("[ChatGPT] CUA tier-3 timed out after 120s", "WARN")
                    except Exception as _ce:
                        log(f"[ChatGPT] CUA tier-3 failed: {_ce}", "WARN")

            # ── Block 1c: ChatGPT activity-panel scrape (mirror of Claude
            # artifact tracking). Runs every cycle once the panel is open,
            # walking the side panel for live steps/sections/source_urls/
            # searches count. Without this, _open_chatgpt_activity_panel
            # opens the panel for URL extraction at end-of-phase but
            # leaves the FE staring at "Deep Research in progress" the
            # whole run — Claude reads its artifact panel continuously
            # for the gold-standard narration; ChatGPT now does the same.
            # DOM-only: no CUA fallback. Reading from an already-open
            # panel is a cheap structural walk; if the walker yields
            # nothing the vision narration block below picks up the slack.
            if (name == "ChatGPT"
                    and p.get("chatgpt_activity_panel_open")
                    and (time.time() - p.get("last_chatgpt_panel_scrape", 0))
                            > ARTIFACT_SCRAPE_INTERVAL):
                try:
                    panel_data = await scrape_chatgpt_activity_panel_tracking(p["page"])
                    if panel_data:
                        # Merge into outer progress dict using dedupe-keep-
                        # first semantics (mirrors Claude artifact merge).
                        for key in ("source_urls", "steps", "sections"):
                            if panel_data.get(key):
                                existing = progress.get(key, []) or []
                                merged = list(dict.fromkeys(existing + panel_data[key]))
                                progress[key] = merged
                        # Invariant: progress["sources"] == len(progress["source_urls"]).
                        progress["sources"] = len(progress.get("source_urls", []) or [])
                        # Searches count — take max so transient lower
                        # reads don't shrink the chip.
                        _ps = int(panel_data.get("searches", 0) or 0)
                        if _ps > int(progress.get("searches", 0) or 0):
                            progress["searches"] = _ps
                        # Mark panel_open=True so the FE chip + the vision
                        # narration block both see the panel as live.
                        progress["panel_open"] = True
                        # Refresh progress text from latest step if our
                        # pre-scrape progress was empty (don't override a
                        # rich pre-existing string).
                        if (panel_data.get("progress")
                                and not (progress.get("progress") or "").strip()):
                            progress["progress"] = panel_data["progress"]
                        if int(panel_data.get("partial_text_len", 0) or 0) > int(progress.get("partial_text_len", 0) or 0):
                            progress["partial_text_len"] = panel_data["partial_text_len"]
                        scrape_ok = True
                        log(f"[ChatGPT] panel tracking: "
                            f"{len(panel_data.get('source_urls', []))} URLs, "
                            f"{len(panel_data.get('steps', []))} steps, "
                            f"{len(panel_data.get('sections', []))} sections, "
                            f"searches={panel_data.get('searches', 0)}")
                except Exception as _e:
                    log(f"[ChatGPT] activity panel scrape failed: {_e}", "DEBUG")
                p["last_chatgpt_panel_scrape"] = time.time()

            # ── Block 2: per-agent vision narration (P2 mirror of P1) ──
            # Same cooldown (90s) + budget (30/phase) enforced inside
            # narrate. Two triggers: (a) DOM walker is empty past
            # 60s warmup, or (b) every Nth poll for a fresh narration even
            # when DOM IS producing data. Continuous narration throughout
            # the phase — not one-shot at end.
            _elapsed_sec_now = int(time.time() - p["start_time"])
            _vn_steps_n = len(progress.get("steps", []) or [])
            _vn_progress_str = (progress.get("progress") or "").strip()
            _vn_sources = int(progress.get("sources", 0) or 0)
            _vn_panel_open = bool(progress.get("panel_open", False))
            # 2026-04-29: aggressive vision cadence (mirrors the P1 block
            # above). DOM-empty warmup 60s → 20s, panel-open gate 90s →
            # 30s. Narrator's MIN_GAP_S (30s) bounds actual call
            # frequency. With a working GEMINI_API_KEY the FE should see
            # a fresh narration sentence ~every poll once the agent is
            # past the 20s warmup.
            _vn_should_call = (
                _elapsed_sec_now > 20
                and _vn_steps_n < 2
                and _vn_sources == 0
            ) or (
                _elapsed_sec_now > 30 and _vn_panel_open
            )
            _vn_force_every_n = int(os.environ.get("GEMINI_NARRATE_FORCE_EVERY_N", "2"))
            if _vn_force_every_n > 0 and _elapsed_sec_now > 0:
                try:
                    _poll_interval = max(int(POLL_DEEP_RESEARCH), 1)
                except Exception:
                    _poll_interval = 30
                _poll_tick = _elapsed_sec_now // _poll_interval
                if _poll_tick > 0 and _poll_tick % _vn_force_every_n == 0:
                    _vn_should_call = True
            _vision_narration_p2 = ""
            _vision_phase_signal_p2 = ""
            if _vn_should_call:
                _vision_data_p2 = None
                try:
                    import narrate as _vn
                    _vision_data_p2 = await _vn.narrate_panel(
                        p["page"],
                        agent=normalize_agent_key(name),
                        phase=2,
                        workflow_name=name,
                        last_dom_progress=_vn_progress_str,
                        last_dom_sources=_vn_sources,
                        last_dom_steps_n=_vn_steps_n,
                    )
                except Exception as _vne:
                    log(f"[{name}] narrate failed: {_vne}", "DEBUG")
                    _vision_data_p2 = None
                # Confidence floor lowered 0.4 → 0.3 (matches P1 block).
                if _vision_data_p2 and float(_vision_data_p2.get("confidence", 0)) >= 0.3:
                    _vision_narration_p2 = _vision_data_p2.get("narration", "")
                    _vision_phase_signal_p2 = _vision_data_p2.get("phase_signal", "") or ""
                    _v_progress = _vision_data_p2.get("progress", "")
                    if _v_progress and len(_v_progress) > len(_vn_progress_str):
                        progress["progress"] = _v_progress
                    _v_steps = _vision_data_p2.get("steps") or []
                    if _v_steps:
                        _seen = set(s[:80] for s in (progress.get("steps") or []))
                        _merged = list(progress.get("steps") or [])
                        for s in _v_steps:
                            k = s[:80]
                            if k not in _seen:
                                _seen.add(k); _merged.append(s)
                        progress["steps"] = _merged[-15:]
                    if (not progress.get("sections")) and _vision_data_p2.get("sections"):
                        progress["sections"] = _vision_data_p2["sections"]
                    # Vision-derived source-count estimate kept SEPARATE from
                    # progress["sources"] (URL-derived) per Group B fix.
                    _so = int(_vision_data_p2.get("sources_observed") or 0)
                    if _so > 0:
                        progress["observed_sources"] = _so
                    log(f"[{name}] narrate hit: phase_signal={_vision_data_p2.get('phase_signal')} "
                        f"conf={_vision_data_p2.get('confidence',0):.2f} steps+={len(_v_steps)} "
                        f"narration=\"{_vision_narration_p2[:80]}\"", "INFO")
                    # Emit agent_narration so PhaseDropdown agent card updates
                    # mid-phase (the dedicated event stream Block 6 wired up).
                    # Same quality gate as the narrator loop — vision rarely
                    # fragments but the symmetric coverage is cheap.
                    _vn_text = (_vision_narration_p2 or "")[:140]
                    if _vn_text and _is_acceptable_narration(_vn_text):
                        try:
                            emit_event("agent_narration", phase=2,
                                       agent=normalize_agent_key(name),
                                       text=_vn_text)
                        except Exception as _en:
                            log(f"[{name}] agent_narration emit failed: {_en}", "DEBUG")

            # ── Block 3: vision-extract source URLs from side panel ──
            # One-shot per agent. Gated on panel-open success so screenshot
            # has real content. Supplements DOM scraping when URLs are in
            # collapsed rows / popovers / non-anchor click handlers.
            # Disabled by setting DG_VISION_URL_EXTRACT=0.
            if (os.environ.get("DG_VISION_URL_EXTRACT", "1") == "1"
                    and not p.get("vision_urls_done")):
                _gate_ok = (
                    (name == "ChatGPT" and p.get("chatgpt_activity_panel_open"))
                    or (name == "Claude" and p.get("artifact_panel_open"))
                    or (name == "Gemini" and elapsed > 120)
                )
                if _gate_ok:
                    try:
                        _vu = await extract_source_urls_via_vision(
                            p["page"], normalize_agent_key(name),
                            last_dom_count=int(progress.get("sources", 0) or 0))
                        if _vu:
                            existing = progress.get("source_urls") or []
                            seen_v = set(existing)
                            unioned_v = list(existing)
                            for u in _vu:
                                if u not in seen_v:
                                    seen_v.add(u); unioned_v.append(u)
                            if len(unioned_v) > len(existing):
                                progress["source_urls"] = unioned_v[:50]
                                progress["sources"] = len(progress["source_urls"])
                                log(f"[{name}] vision-urls extracted {len(_vu)} URLs "
                                    f"(DOM had {len(existing)}, union now "
                                    f"{len(progress['source_urls'])})", "INFO")
                        p["vision_urls_done"] = True
                    except Exception as _vue:
                        log(f"[{name}] vision-urls failed: {_vue}", "WARN")
                        p["vision_urls_done"] = True  # don't retry on failure

            # Emit agent_progress to frontend (critical for real-time UI)
            agent_key = normalize_agent_key(name)
            # If scrape failed we don't know the agent's real status — keep
            # elapsed-time progress text but omit stale/fake fields
            _status_val = progress.get("status") if scrape_ok else "generating"
            _progress_val = progress.get("progress") if scrape_ok else None
            if not _progress_val:
                _progress_val = f"Researching... ({int(time.time() - p['start_time']) // 60}m elapsed)"
            elapsed_sec = int(time.time() - p["start_time"])

            # DOM partial text length + MutationObserver stream.
            # Observer fires every ~500ms as tokens arrive (see inject_agent_observer);
            # DOM scrape runs every 30s. Use whichever is larger so the progress bar
            # climbs monotonically even between DOM scrapes.
            _obs = get_observer_state(p["page"])
            _obs_len = int(_obs.get("observer_text_len", 0) or 0)
            _obs_preview = str(_obs.get("observer_preview", "") or "")
            _partial_text_len = max(progress.get("partial_text_len", 0) or 0, _obs_len)
            p["observer_text_len"] = _obs_len  # Keep shared-dict snapshot fresh

            # ── Stuck-agent detection ──
            # Compare current text length AND source count against the last-
            # growth checkpoint. Only alert if BOTH haven't moved for 20 min
            # AND the agent isn't in a known "planning/thinking" status.
            # These gates avoid false alarms on agents mid-research (planning
            # phases are often 10+ min with no text growth but active sources).
            agent_key_stuck = normalize_agent_key(name)
            # observed_sources (Claude text count, ChatGPT vision count)
            # captures growth that URL extraction can't see. Treat as
            # liveness signal so the stall watchdog doesn't false-fire
            # during URL-light progress.
            _src_count = max(
                int(progress.get("sources", 0) or 0),
                int(progress.get("observed_sources", 0) or 0),
            )
            p.setdefault("last_growth_len", 0)
            p.setdefault("last_growth_sources", 0)
            p.setdefault("last_growth_time", p["start_time"])
            p.setdefault("stuck_warned_at", 0.0)
            if _partial_text_len > p["last_growth_len"] or _src_count > p["last_growth_sources"]:
                p["last_growth_len"] = max(p["last_growth_len"], _partial_text_len)
                p["last_growth_sources"] = max(p["last_growth_sources"], _src_count)
                p["last_growth_time"] = time.time()
            no_growth_secs = time.time() - p["last_growth_time"]
            since_warn = time.time() - p["stuck_warned_at"]
            _active_statuses = ("planning", "thinking", "researching", "searching")
            status_is_active = (_status_val or "").lower() in _active_statuses
            # Require: elapsed >20min, no-growth >20min, no active-status
            # signal, at least 120s since last warn (avoid spam on dedup miss),
            # AND CUA tier-3 hasn't successfully checked in within the last
            # 20 min. The CUA-recency gate is the load-bearing one — it
            # eliminates the false-positive class observed in 2026-04-28
            # where a 1,289-source ChatGPT DR was alerted as stalled because
            # the gemini narrator (404) and DR-iframe DOM scrape (cross-
            # origin) both reported 0/0, even though CUA tier-3 reads at the
            # same instant saw "1,289 sources and counting" in the panel.
            # If CUA confirmed activity recently, the agent is alive — the
            # streaming layer is the broken signal, not the agent.
            _cua_check_age = time.time() - p.get("last_cua_check", 0)
            if (elapsed > 1200 and no_growth_secs > 1200 and since_warn > 900
                    and not status_is_active and _cua_check_age > 1200):
                p["stuck_warned_at"] = time.time()
                fail_agent(agent_key_stuck,
                           (f"{name} stalled — no growth for {int(no_growth_secs/60)} min "
                            f"(currently {_partial_text_len} chars, {_src_count} sources)"),
                           ("The agent's output hasn't grown in a while. "
                            "Retry re-runs the agent from scratch. Skip drops this agent."))
                # Non-blocking: we don't await here since other agents are
                # still healthy. The command bus applies the user's choice
                # asynchronously — check on next tick.
            # Apply any async decision that landed since last tick.
            if _controls.consume_poke_agent(agent_key_stuck):
                log(f"[{name}] User poked — sending 'please continue' follow-up")
                try:
                    await browser.switch_to_page(p["page"])
                    await paste_followup(p["page"], "Please continue — output the rest of your research.",
                                         name.lower(), label=f"{name}-poke")
                except Exception as _e:
                    log(f"[{name}] Poke failed: {_e}", "WARN")
                p["last_growth_time"] = time.time()
            if _controls.consume_wait_longer_agent(agent_key_stuck):
                log(f"[{name}] User granted another 20 min of no-growth budget")
                p["last_growth_time"] = time.time()

            # Dedup: only emit when something meaningful changed (status / sources /
            # partialTextLen / sections-count). Otherwise we spam Firestore ~180 writes
            # per agent per run with identical payloads. Heartbeat still covers liveness.
            progress_key = json.dumps({
                "status": _status_val or "",
                "sources": progress.get("sources", 0),
                "partialTextLen": _partial_text_len,
                "sections_len": len(progress.get("sections", []) or []),
                "steps_len": len(progress.get("steps", []) or []),
                # Coarse elapsed bucket so slow-moving scrapes still re-emit occasionally
                "elapsed_bucket": elapsed_sec // 30,
                # Without progress_label + tool_uses, transitions like
                # "Reading source 3" → "Reading source 4" with no text-len /
                # source delta get suppressed and starve the watchdog.
                "progress_label": (_progress_val or "")[:80],
                "tool_uses_len": len(progress.get("tool_uses", []) or []),
                # Same gap as P1 (research.py:~10515) — without these
                # entries, a search-only or sectionsDone-only delta is
                # suppressed and the FE graph series flat-lines through
                # whole search bursts. Required for real-curve rendering.
                "searches": int(progress.get("searches", 0) or 0),
                "sections_done": int(progress.get("sections_done", 0) or 0),
                "sections_total": int(progress.get("sections_total", 0) or 0),
                "observed_sources": int(progress.get("observed_sources", 0) or 0),
            }, sort_keys=True)
            # Phase prefix: _last_progress is process-global, so without it
            # a P1 entry could dedupe a P2 emit with the same key.
            _dedupe_key = f"p2:{agent_key}"
            if _last_progress.get(_dedupe_key) != progress_key:
                _last_progress[_dedupe_key] = progress_key
                emit_event("agent_progress", phase=2, agent=agent_key,
                    status=_status_val or "generating",
                    progress=_progress_val,
                    sources=progress.get("sources", 0),
                    sourceUrls=progress.get("source_urls", []),
                    sections=progress.get("sections", []),
                    partialTextLen=_partial_text_len,
                    partialTextPreview=_obs_preview,
                    model=progress.get("model", ""),
                    thinking=progress.get("thinking", ""),
                    steps=progress.get("steps", []),
                    plan=progress.get("plan", ""),
                    toolUses=progress.get("tool_uses", []),
                    title=progress.get("title", ""),
                    visionNarration=_vision_narration_p2,
                    phaseSignal=_vision_phase_signal_p2,
                    panelOpen=bool(progress.get("panel_open", False)),
                    observedSources=int(progress.get("observed_sources", 0) or 0),
                    searches=int(progress.get("searches", 0) or 0),
                    # New rich-narration fields (2026-04-29). Consumed by the
                    # BE per-agent narrator + FE PhaseDropdown so the cards
                    # show "drafted 4/8 sections" / "currently focused on X"
                    # instead of "0 sources, 0 chars" stub copy.
                    sectionsDone=int(progress.get("sections_done", 0) or 0),
                    sectionsTotal=int(progress.get("sections_total", 0) or 0),
                    currentFocus=str(progress.get("progress", "") or "")[:200],
                    websitesCount=int(progress.get("searches", 0) or 0),
                    artifactCount=int(progress.get("artifact_count", 0) or 0),
                    elapsedSec=elapsed_sec,
                    expectedMinutes=get_expected_minutes(2),
                    scrapeOk=scrape_ok)
                # Per-agent progressHistory ring (mirrors P1 emit). Persisted
                # post-run for the FE GraphAnalysis sparklines + post-reload
                # in-tile chart restoration.
                try:
                    _hist_p2 = _runtime.agent_progress_history.setdefault(agent_key, [])
                    _hist_p2.append({
                        "t": int(elapsed_sec * 1000),
                        "sources": int(progress.get("sources", 0) or 0),
                        "chars": int(_partial_text_len or 0),
                        "sections": int(len(progress.get("sections", []) or [])),
                        "searches": int(progress.get("searches", 0) or 0),
                        "sectionsDone": int(progress.get("sections_done", 0) or 0),
                        "sectionsTotal": int(progress.get("sections_total", 0) or 0),
                    })
                    if len(_hist_p2) > 240:
                        del _hist_p2[:len(_hist_p2) - 240]
                except Exception:
                    pass
                # 2026-05-03: snapshot the rich fields so the P2 completion
                # emit at extract_and_record_agent can ship the same data to
                # the FE — without this, the `complete` event was bare and
                # the persisted Firestore agents map ended up missing
                # sourceUrls/sections/steps/searches, leaving the dropdown
                # post-completion card empty.
                try:
                    _runtime.agent_progress_snapshots[agent_key] = {
                        "source_urls": list(progress.get("source_urls", []) or [])[:50],
                        "sections":    list(progress.get("sections", []) or [])[:20],
                        "steps":       list(progress.get("steps", []) or [])[:15],
                        "searches":    int(progress.get("searches", 0) or 0),
                        "observed_sources": int(progress.get("observed_sources", 0) or 0),
                        "sources":     int(progress.get("sources", 0) or 0),
                        "partial_text_len": int(_partial_text_len or 0),
                        "current_focus": str(progress.get("progress", "") or "")[:200],
                    }
                except Exception:
                    pass

            # Heartbeat every 60s per agent
            if time.time() - p.get("last_heartbeat", 0) >= 60:
                emit_event("heartbeat", phase=2, agent=agent_key)
                p["last_heartbeat"] = time.time()

            # ── Playwright-primary completion check (2026-04-25 strict) ─────
            # The detect_completion_* functions return (done, reason, snap)
            # where snap = {text_len, sources, steps}. They report done=True
            # ONLY when the platform's definitive done-marker is present
            # (Stop button gone + "Thought for X" / Share & Export visible /
            # research_complete card). Caller-side 2-cycle gate confirms
            # text + sources + steps are all flat across 2 polling cycles
            # before extracting — eliminates the partial_len>5000,
            # artifacts>=2, transient-keyword false positives.
            detect_fn = DETECT_FNS.get(name)
            # 2026-04-28: drop the MIN_WAIT shadow on completion detection.
            # MIN_WAIT was a CUA-cost gate (the CUA fallback at the bottom
            # of this loop still respects it). detect_completion_* is
            # cheap Playwright scraping with strict done-markers, so it's
            # safe to run from t=0 — and ChatGPT can finish in 54s flat
            # for some prompts, which the 5-min MIN_WAIT was hiding from
            # the FE entirely (agent stayed "generating" until MIN_WAIT
            # cleared, ~5 min after the BE could SEE it was done).
            if detect_fn:
                try:
                    dom_done, dom_reason, snap = await detect_fn(p["page"])
                except Exception as _de:
                    log(f"[{name}] detect_completion error: {_de}", "WARN")
                    dom_done, dom_reason, snap = (False, f"detect_error: {_de}", {})
                p.setdefault("flat_history", [])
                p.setdefault("done_marker_first_at", 0.0)
                p.setdefault("extraction_attempts", 0)
                if not dom_done:
                    # Definitive done-marker absent — discard any flat history.
                    if p["flat_history"]:
                        log(f"[{name}] Done-marker lost — clearing flat_history ({dom_reason})")
                    p["flat_history"] = []
                    p["done_marker_first_at"] = 0.0
                else:
                    # Done-marker present — append snapshot. Need 2 snapshots
                    # over ≥30s all flat to extract (was 3 over ≥240s before
                    # 2026-04-28 v2; see history block below).
                    is_first_detection = (p["done_marker_first_at"] == 0.0)
                    if is_first_detection:
                        p["done_marker_first_at"] = time.time()
                    p["flat_history"].append((
                        int(snap.get("text_len", 0) or 0),
                        int(snap.get("sources", 0) or 0),
                        int(snap.get("steps", 0) or 0),
                    ))
                    p["flat_history"] = p["flat_history"][-2:]
                    log(f"[{name}] Done-marker confirmed #{len(p['flat_history'])} — "
                        f"{dom_reason}; snap={snap}")
                    # 2026-05-07 fast-confirm: on FIRST done-marker detection,
                    # do an inline re-poll instead of waiting for the next
                    # main-rotation tick (~120s at POLL_DEEP_RESEARCH cadence).
                    # Without this, even though the 2-snapshot gate is
                    # cheap to satisfy, the gap BETWEEN polling cycles is
                    # the dominant post-completion wait — user-observed
                    # "ChatGPT just finished but extraction hasn't started
                    # yet". Sleep matches the elapsed_done floor (30s) so
                    # the gate below clears in one shot. Trade-off: the
                    # other pending agents' status updates are delayed by
                    # ~30s on the iteration where any agent first detects
                    # done-marker — one-time per agent, net win.
                    if is_first_detection and len(p["flat_history"]) == 1:
                        _confirm_secs = int(os.environ.get("DG_DONE_FAST_CONFIRM_SECS", "30"))
                        log(f"[{name}] First done-marker — fast-confirm re-poll "
                            f"in {_confirm_secs}s (skipping wait for next main-rotation tick)")
                        await asyncio.sleep(_confirm_secs)
                        try:
                            dom_done2, dom_reason2, snap2 = await detect_fn(p["page"])
                        except Exception as _de2:
                            log(f"[{name}] fast-confirm detect_completion error: {_de2}", "WARN")
                            dom_done2, dom_reason2, snap2 = (False, f"detect_error: {_de2}", {})
                        if not dom_done2:
                            # Done-marker disappeared during fast-confirm window —
                            # agent transitioned between phases or streaming
                            # resumed. Reset and let the main loop poll normally.
                            p["flat_history"] = []
                            p["done_marker_first_at"] = 0.0
                            log(f"[{name}] Fast-confirm: done-marker lost after "
                                f"{_confirm_secs}s — back to streaming. "
                                f"Reason: {dom_reason2}")
                            continue
                        p["flat_history"].append((
                            int(snap2.get("text_len", 0) or 0),
                            int(snap2.get("sources", 0) or 0),
                            int(snap2.get("steps", 0) or 0),
                        ))
                        p["flat_history"] = p["flat_history"][-2:]
                        log(f"[{name}] Fast-confirm snapshot #2 captured — "
                            f"{dom_reason2}; snap={snap2}")
                    elapsed_done = time.time() - p["done_marker_first_at"]
                    # 2026-04-28 v2: tightened gate — 2 snapshots over ≥30s
                    # (was 3 snapshots over ≥90s). Reason: at the default
                    # 120s POLL_DEEP_RESEARCH cadence, "3 snapshots" needed
                    # 240s of wall-clock minimum even when the agent was
                    # visibly done — that 4-minute gate was the dominant
                    # contributor to the user-reported "gap before phase
                    # end starts" (advisor 2026-04-28). The tolerance gate
                    # below already prevents false-positives on signal
                    # jitter from auto-expand mutators, so 2 snapshots are
                    # enough confirmation. Saves ~120-240s per agent.
                    if len(p["flat_history"]) < 2 or elapsed_done < 30:
                        # Not enough samples yet — keep polling.
                        continue
                    t0, s0, st0 = p["flat_history"][0]
                    t1, s1, st1 = p["flat_history"][1]
                    def _stable(a, b, tol=0.05):
                        hi = max(a, b); lo = min(a, b)
                        return hi == 0 or (hi - lo) <= max(2, hi * tol)
                    flat = (
                        _stable(t0, t1)
                        and s1 <= int(s0 * 1.02) + 1
                        and st1 <= st0 + 1
                    )
                    if not flat:
                        log(f"[{name}] Done-marker present but signals still moving — "
                            f"text {t0}→{t1}, sources {s0}→{s1}, "
                            f"steps {st0}→{st1}; keep polling")
                        # Trim history so we re-anchor on the next snapshot —
                        # if a single late mutation slipped through, the next
                        # tick's snapshot becomes the new baseline.
                        p["flat_history"] = p["flat_history"][-1:]
                        continue
                    p["extraction_attempts"] += 1
                    log(f"[{name}] CONFIRMED DONE — done-marker + 2 cycles flat "
                        f"(text={t1}, sources={s1}, steps={st1}, "
                        f"elapsed_since_marker={int(elapsed_done)}s). "
                        f"Starting extract_and_record (attempt {p['extraction_attempts']})")
                    _queue_dir = (Path(__file__).parent / "queues" / _tracks_dir.name) \
                                 if _tracks_dir else None
                    res = await extract_and_record_agent(
                        name, p["page"], browser, cua_client,
                        queue_dir=_queue_dir,
                        elapsed_sec=int(elapsed),
                        verbose=verbose,
                        expected_text_len=int(_partial_text_len or 0),
                    )
                    # 2026-04-25: markdown-as-primary. "done" means text>0 +
                    # in-app primary emitted. res["url"] is the conversation
                    # URL (page.url) for resume; res["_in_app_url"] is the
                    # FE primary /documents?open=… link.
                    if res["status"] == "done":
                        _runtime.unregister_page(
                            name.lower().replace(" ", ""),
                            final_status="done",
                        )
                        _runtime.agent_chat_urls[
                            name.lower().replace(" ", "")
                        ] = res.get("url") or ""
                        results[name] = res
                        del pending[name]
                        log(f"[{name}] Extraction complete — "
                            f"{len(res['text'])} chars, "
                            f"in_app={(res.get('_in_app_url') or '')[:60]}, "
                            f"convo={(res.get('url') or '')[:60]}")
                        continue
                    # E4 (DGOPS-7366) cost guardrail: empty extraction → surface
                    # user decision on attempt 1, not 3. The DOM-primary
                    # ladder in extract_chatgpt_response means a real
                    # transient blip would be caught by the ladder itself,
                    # not by retrying the whole extraction 3 times.
                    log(f"[{name}] Extraction attempt {p['extraction_attempts']} "
                        f"returned no content — surfacing user decision", "WARN")
                    p["flat_history"] = []
                    p["done_marker_first_at"] = 0.0
                    if p["extraction_attempts"] >= 1:
                        fail_agent(agent_key,
                                   f"{name} extraction failed",
                                   ("Playwright confirmed done, but the extraction came back empty "
                                    "(DOM HTML→MD, JS innerText, and CUA clipboard fallback all "
                                    "returned no content). Retry re-runs extraction; Skip drops "
                                    "this agent."))
                        decision = await _controls.await_agent_decision(agent_key, timeout=600.0)
                        log(f"[{name}] Extraction-failed decision: {decision}")
                        if decision == "retry":
                            p["extraction_attempts"] = 0
                            p["flat_history"] = []
                            continue
                        if decision == "skip":
                            results[name] = {"status": "skipped_by_user",
                                             "text": "", "url": "",
                                             "page": p["page"],
                                             "elapsed_sec": int(elapsed)}
                            del pending[name]
                            emit_event("agent_skipped", phase=2, agent=agent_key,
                                       reason="extraction_failure_skip")
                            # status="skipped" auto-persisted by emit_event hook.
                            continue
                        if decision == "stop":
                            break
                    continue

            # Check completion — CUA-primary fallback (only if Playwright was
            # not confident within the MIN_WAIT + budget window). CUA checks
            # every 5 min per agent (cost-effective, actually works).
            # DGOPS-7367 hardening (2026-05-13): skip CUA while a DNS retry
            # is pending. Without this guard, CUA's 5-min check could fire
            # at T+300 or T+600 during attempt-3's 480s backoff window and
            # vote `is_done=True` against a chrome-error DOM (no stop button
            # + no loading marker satisfies the "done" verdict). The
            # is_error drop gate at L14730 only covers the `is_error`
            # branch — a false-positive `is_done` would slip past and
            # trigger the artifact-count nudge gate or hard-fail user-
            # decision modal mid-recovery.
            if p.get("dns_retry_at"):
                continue
            if (time.time() - p.get("last_cua_check", 0)) < CUA_CHECK_INTERVAL:
                # Not time for CUA check yet — skip this agent this cycle
                continue

            # Enforce minimum wait before first check
            min_wait = MIN_WAIT.get(name, 180)
            if elapsed < min_wait:
                continue

            # CUA visual check — SCROLL TO BOTTOM first (stop button + loading indicator live near composer/end)
            await browser.switch_to_page(p["page"])
            try:
                await p["page"].evaluate("""() => {
                    window.scrollTo(0, document.body.scrollHeight);
                    // Also scroll common chat containers (ChatGPT DR has internal scroll)
                    const containers = document.querySelectorAll(
                        '[class*="react-scroll"], [class*="chat-messages"], main, [role="presentation"], [data-testid*="conversation"]');
                    containers.forEach(c => { try { c.scrollTop = c.scrollHeight; } catch(e){} });
                }""")
                await asyncio.sleep(0.5)
            except Exception:
                pass
            log(f"[{name}] CUA checking completion ({int(elapsed/60)}m) — scrolled to bottom")
            # Platform-specific instruction for where to look for the stop signal
            platform_hint = {
                "ChatGPT": ("ChatGPT Deep Research renders the research output inside a RESEARCH CARD / DIALOG "
                            "(embedded in the chat, looks like a document panel). The stop button and progress "
                            "indicator live ON THAT CARD, not in the composer. Scroll down to find the card and "
                            "check if it still shows 'Researching...', a progress bar, or a stop button on the card."),
                "Gemini": ("Gemini Deep Research shows a stop button in the composer/input area and a progress "
                            "indicator in the message. Check the composer + the latest message area."),
                "Claude": ("Claude shows a stop button in the composer/input area while generating. After completion, "
                            "two document artifact buttons/cards may appear. Check composer for stop button; absence "
                            "means done."),
            }.get(name, "")
            diag = await agent_loop(cua_client, browser, PROMPT_DIAGNOSE,
                f"{platform_hint}\n\n"
                "Is the AI still generating (stop button visible, loading animation, spinner, 'Researching...' indicator)? "
                "Or is the response FULLY complete (no stop button anywhere, no loading, the final paragraph visible)? "
                "Answer 'still generating' or 'response complete'. "
                "If you see a Stop button ANYWHERE on the page (composer OR research card), answer 'still generating'.",
                model=CUA_MODEL, max_iterations=3, verbose=verbose,
                phase=2, agent_name=normalize_agent_key(name), target_page=p["page"])
            diag_text_raw = (diag.get("text") or "")
            diag_text = diag_text_raw.lower()
            p["last_cua_check"] = time.time()

            # ── Parse CUA diagnosis ──────────────────────────────────────
            # Old logic used bare substring matches — vulnerable to false
            # positives (e.g. "is NOT complete" contained "complete" →
            # is_done=True while agent was still running, causing premature
            # 0-char extractions at 23m). New logic:
            #   1. Prefer the structured "CONCLUSION: <verdict>" line that
            #      PROMPT_DIAGNOSE now mandates.
            #   2. If missing, use negation-aware heuristics.
            #   3. Stop-button-visible always vetos (per prompt decision rule).
            #   4. Default to still-generating on ambiguity (one extra CUA
            #      check is far cheaper than a zero-char extraction).
            verdict_match = re.search(
                r'conclusion\s*:\s*(generating|done|needs_click|error)',
                diag_text,
            )

            is_error = False
            if verdict_match:
                verdict = verdict_match.group(1)
                is_done = verdict == "done"
                is_generating = verdict == "generating"
                is_error = verdict == "error"
            else:
                still_running_phrases = (
                    "still in progress", "still running", "still researching",
                    "still being generated", "still working", "still generating",
                    "not complete", "not yet complete", "hasn't completed",
                    "has not completed", "not finished", "not yet done",
                    "not done yet", "isn't done", "is not done", "incomplete",
                )
                done_phrases = (
                    "response complete", "fully complete", "is complete",
                    "has completed", "appears complete", "finished generating",
                    "done generating", "no stop button", "no progress indicator",
                )
                stop_button_visible = bool(
                    re.search(r'stop button[^.]*\byes\b', diag_text) or
                    re.search(r'\bstop button\b[^.]{0,60}\b(visible|present|displayed|showing)\b', diag_text)
                )
                has_still_running = any(ph in diag_text for ph in still_running_phrases)
                has_done = any(ph in diag_text for ph in done_phrases)

                if stop_button_visible or has_still_running:
                    is_generating = True
                    is_done = False
                elif has_done:
                    is_done = True
                    is_generating = False
                else:
                    # Ambiguous — safer default
                    is_generating = True
                    is_done = False
                log(f"[{name}] CUA diag missing CONCLUSION line — heuristic verdict: "
                    f"{'generating' if is_generating else 'done' if is_done else 'unknown'}", "WARN")

            # ── Agent-side error verdict (e.g. ChatGPT "Research failed") ──
            # Without this branch the polling loop spins forever — neither
            # is_done nor is_generating fires and the agent gets stuck in
            # pending. Salvage whatever's on the page, fire fail_agent
            # once, drop the agent from rotation.
            if is_error:
                # DGOPS-7367 (2026-05-13): defer drop while a transient
                # network retry is pending. The retry path above will
                # either rejoin the agent (success), or exhaust the
                # backoff schedule and flip error_source to
                # "network_exhausted" — at which point we DO want to fall
                # through to the drop. is_error firing here against a
                # chrome-error DOM mid-retry is the exact pre-fix failure
                # mode: dropping immediately even though a 30s wait would
                # have recovered.
                if p.get("dns_retry_at") and p.get("error_source") == "network":
                    _in = max(0, int(p["dns_retry_at"] - time.time()))
                    log(f"[{name}] CUA reports error but DNS retry pending "
                        f"(attempt {p.get('dns_retry_attempts')}/"
                        f"{len(_DNS_BACKOFF_SECS)}, in {_in}s) — deferring drop", "INFO")
                    continue
                agent_key_err = normalize_agent_key(name)
                log(f"[{name}] CUA reported CONCLUSION: ERROR — agent UI shows a failure state. "
                    f"Salvaging partial output and dropping from rotation.", "WARN")
                _err_text = ""
                try:
                    _err_text = await extract_fns[name](
                        p["page"], browser=browser, cua_client=cua_client,
                        label=name, verbose=verbose) or ""
                except Exception as _e_err:
                    log(f"[{name}] Salvage extract during error verdict failed: {_e_err}", "WARN")
                if not p.get("failed_alert_emitted"):
                    fail_agent(agent_key_err,
                               f"{name} reported a failure mid-run",
                               (f"The {name} UI surfaced an error (e.g. 'Research failed'). "
                                f"Salvaged {len(_err_text)} chars of partial output. "
                                "Retry re-runs the agent fresh; Skip drops it."))
                    p["failed_alert_emitted"] = True
                results[name] = {
                    "status": "agent_error",
                    "text": _err_text,
                    "url": p.get("url", ""),
                    "page": p["page"],
                    "elapsed_sec": int(elapsed),
                }
                del pending[name]
                continue

            if is_generating and not is_done:
                log(f"[{name}] CUA: still generating ({int(elapsed/60)}m)")
                p["done_count"] = 0
                continue

            if is_done:
                p["done_count"] += 1
                # Need 2 consecutive CUA "done" readings to confirm
                if p["done_count"] < 2:
                    log(f"[{name}] CUA says done ({p['done_count']}/2 confirmations)")
                    p["last_cua_check"] = time.time() - 120  # Check again soon
                    continue
                log(f"[{name}] CUA confirms complete ✓ ({int(elapsed/60)}m)")

                # Gemini-specific: validate completion via source count + content length
                # Gemini Deep Research typically finds 10+ sources. If we have 0 sources
                # and minimal text early in the run, the "done" verdict is likely false.
                if name == "Gemini" and elapsed < (max_wait_min * 60 * 0.7):
                    try:
                        _gm_progress = await scrape_progress_gemini(p["page"])
                        _gm_sources = _gm_progress.get("sources", 0)
                        _gm_text = _gm_progress.get("partial_text_len", 0)
                        _gm_steps = len(_gm_progress.get("steps", []))
                        if _gm_sources < 3 and _gm_text < 2000:
                            log(f"[Gemini] CUA says done but only {_gm_sources} sources, "
                                f"{_gm_text} chars, {_gm_steps} steps at {int(elapsed/60)}m "
                                f"— likely still researching. Reverting.", "WARN")
                            p["done_count"] = 0
                            p["cua_confirmed"] = False
                            p["last_cua_check"] = time.time()
                            emit_event("agent_progress", phase=2, agent="gemini",
                                       status="generating",
                                       progress=f"Still researching — {_gm_sources} sources so far",
                                       elapsedSec=int(elapsed))
                            continue
                    except Exception:
                        pass

                # Claude-specific: validate completion via artifact count.
                # Research mode on Opus 4.8 with Adaptive Thinking USED to
                # produce TWO artifacts — (1) references, (2) the final
                # report. The 2026 layout collapses to ONE artifact card
                # whose text reads "Research complete · N sources · Xm Ys"
                # AND contains the full report inline. So:
                #
                #   • If body-text matches the "Research complete" marker
                #     → trust the done verdict regardless of artifact count
                #     (the marker only appears when streaming ends).
                #   • Else, fall through to the legacy artifact-count gate:
                #     < 80% budget + < 2 → revert to polling; ≥ 80% + < 2 →
                #     hard-fail with Retry/Skip/Wait modal.
                if name == "Claude":
                    try:
                        _art_count = await _count_claude_artifacts(p["page"])
                    except Exception:
                        _art_count = 2  # on DOM query failure, trust extraction
                    # 2026-04-26: bypass the artifact-count gate when the
                    # modern "Research complete · N sources · Xm Ys" marker
                    # is present. This lets the 1-artifact-card layout pass
                    # without nudging or hard-failing.
                    _claude_completion_marker = False
                    try:
                        # 2026-05-04: parity with detect_completion_claude — three
                        # markers: anchored "research complete · N sources" (legacy
                        # + modern 2026-04 layouts, body-text safe), anchored
                        # "Boom! Research report is ready" (2026-05+ ready
                        # callout, body-text safe), and the modern card title
                        # "<Title> · N sources · Xh Ym" (no "complete" prefix —
                        # body-text would false-positive mid-stream, scope to
                        # artifact/aside containers).
                        _claude_completion_marker = bool(await p["page"].evaluate(
                            """() => {
                                const body = document.body?.innerText || '';
                                if (/research\\s+complete(?:d)?\\s*[\\s·•—\\-]+\\d[\\d,]*\\s+sources?/i.test(body)) return true;
                                if (/\\bBoom!\\s+(?:Your\\s+)?[Rr]esearch\\s+report\\s+is\\s+ready\\b/.test(body)) return true;
                                const cards = document.querySelectorAll(
                                    '.font-claude-message [class*="artifact"], aside [class*="artifact"], aside [class*="card"]'
                                );
                                for (const el of cards) {
                                    if (/[\\s·•—\\-]+\\d[\\d,]*\\s+sources?\\s*[\\s·•—\\-]+\\d+\\s*[hms]/i.test(el.innerText || '')) return true;
                                }
                                return false;
                            }"""
                        ))
                    except Exception:
                        _claude_completion_marker = False
                    if _claude_completion_marker:
                        log(f"[Claude] Modern completion marker detected — accepting 1-artifact layout (art_count={_art_count})", "INFO")
                        # A1: telemetry so we can see how often this layout fires
                        # in the wild vs the legacy 2-artifact path.
                        try:
                            emit_event("agent_completion_detected", phase=2, agent="claude",
                                       layout="1-artifact-modern", art_count=_art_count)
                        except Exception:
                            pass
                        # Fall through to extraction (skip both gates below).
                    elif _art_count < 2 and elapsed < (max_wait_min * 60 * 0.8):
                        log(f"[Claude] CUA says done but only {_art_count} artifact(s) at "
                            f"{int(elapsed/60)}m — likely still researching. Reverting.", "WARN")
                        p["done_count"] = 0
                        p["cua_confirmed"] = False
                        p["last_cua_check"] = time.time()
                        emit_event("agent_progress", phase=2, agent="claude",
                                   status="generating",
                                   progress=f"Still researching — only {_art_count} artifact(s) so far",
                                   elapsedSec=int(elapsed))
                        continue
                    elif not _claude_completion_marker and _art_count < 2:
                        # ── C2: one-shot auto-nudge before the hard-fail modal ──
                        # Give Claude 90s to produce artifact 2 after an explicit
                        # ask, before interrupting the user. Fires once per agent
                        # per phase (p["nudged_artifact"]).
                        if not p.get("nudged_artifact"):
                            p["nudged_artifact"] = True
                            nudge_art = (
                                "Your research is incomplete — the final comprehensive report "
                                "artifact is missing. Please produce the complete research "
                                "document artifact now — include every section, finding, and "
                                "source. This is the deliverable document, not the references list."
                            )
                            try:
                                emit_event("agent_progress", phase=2, agent="claude",
                                           status="nudging",
                                           progress="Nudging Claude to publish artifact 2 (90s)…")
                                await browser.switch_to_page(p["page"])
                                await paste_followup(p["page"], nudge_art, "claude",
                                                     label="Claude-nudge-artifact")
                                log(f"[Claude] Sent artifact-2 nudge — waiting 90s")
                                await asyncio.sleep(90)
                            except Exception as _ne:
                                log(f"[Claude] Artifact nudge failed: {_ne}", "WARN")
                            # Rewind so next CUA tick re-checks artifact count
                            p["done_count"] = 0
                            p["cua_confirmed"] = False
                            p["last_cua_check"] = time.time()
                            p["start_time"] = time.time() - (max_wait_min * 60) + (10 * 60)
                            continue
                        # Hard-fail path — budget 80%+ spent and the 2nd
                        # artifact never materialized. Don't silently accept
                        # the 1st one (that's the references, not the report).
                        log(f"[Claude] Hard-fail: {int(elapsed/60)}m elapsed with only "
                            f"{_art_count} artifact(s) — final document missing", "ERROR")
                        agent_key_hf = "claude"
                        # agent_link_failed → AgentLinkFailedBanner with
                        # Retry · Skip. pipeline_warning lands on a phase-
                        # level surface the user won't notice.
                        try:
                            emit_event("agent_link_failed", phase=2, agent=agent_key_hf,
                                       attempts=1,
                                       lastError=f"Claude produced only {_art_count} artifact — final document missing")
                        except Exception:
                            pass
                        p.setdefault("hf_timeouts", 0)
                        decision = await _controls.await_agent_decision(agent_key_hf, timeout=300.0)
                        log(f"[Claude] 2-artifact hard-fail decision: {decision}")
                        if decision == "stop":
                            break
                        if decision == "skip":
                            continue
                        if decision == "retry":
                            p["hf_timeouts"] = 0
                            followup = (
                                "Your research is incomplete — the final comprehensive report artifact is missing. "
                                "Please produce the complete research document artifact now — include every section, "
                                "finding, and source. This is the deliverable document, not the references list."
                            )
                            try:
                                await browser.switch_to_page(p["page"])
                                await paste_followup(p["page"], followup, "claude", label="Claude-retry-artifact")
                            except Exception as _e:
                                log(f"[Claude] Retry follow-up failed: {_e}", "WARN")
                            p["start_time"] = time.time() - (max_wait_min * 60) + (15 * 60)
                            p["done_count"] = 0
                            p["cua_confirmed"] = False
                            p["last_cua_check"] = time.time()
                            p.pop("_cached_text", None)
                            p["empty_retries"] = 0
                            continue
                        # wait_longer / timeout → extend budget ONCE; after the
                        # 2nd unanswered timeout, auto-skip instead of looping
                        # hard-fails forever.
                        p["hf_timeouts"] += 1
                        if p["hf_timeouts"] >= 2:
                            log(f"[Claude] 2-artifact hard-fail timed out {p['hf_timeouts']}× "
                                f"without a user decision — auto-skipping agent", "WARN")
                            _controls.skipped_agents.add(agent_key_hf)
                            continue
                        p["start_time"] = time.time() - (max_wait_min * 60) + (15 * 60)
                        p["done_count"] = 0
                        p["cua_confirmed"] = False
                        continue

                # 2026-04-25: CUA-confirmed done → run the same extract +
                # emit ladder used by the Playwright-confirmed path. Single
                # source of truth for save+emit (extract_and_record_agent),
                # no inline duplication. Empty extractions still revert to
                # polling (CUA likely misread completion).
                _queue_dir = (Path(__file__).parent / "queues" / _tracks_dir.name) \
                             if _tracks_dir else None
                res = await extract_and_record_agent(
                    name, p["page"], browser, cua_client,
                    queue_dir=_queue_dir, elapsed_sec=int(elapsed),
                    verbose=verbose,
                    expected_text_len=int(_partial_text_len or 0),
                )
                if res["status"] == "done":
                    _runtime.unregister_page(name.lower().replace(" ", ""),
                                              final_status="done")
                    _runtime.agent_chat_urls[name.lower().replace(" ", "")] = res.get("url") or ""
                    results[name] = res
                    del pending[name]
                    log(f"[{name}] CUA-confirmed extraction complete — "
                        f"{len(res['text'])} chars, "
                        f"in_app={(res.get('_in_app_url') or '')[:60]}")
                    continue
                # E4 (DGOPS-7366) cost guardrail: empty extraction → ask the
                # user immediately. The previous 3-attempt silent retry loop
                # could burn 30+ min wall time and $5-10 in CUA spend on a
                # Wayland clipboard-fail run that produced zero output. With
                # DOM extraction now primary in extract_chatgpt_response, an
                # empty result here means the canvas DOM is genuinely missing
                # — alert once, decide once.
                p.setdefault("empty_retries", 0)
                p["empty_retries"] += 1
                log(f"[{name}] CUA said done but extraction empty (attempt "
                    f"{p['empty_retries']}) — surfacing user decision", "WARN")
                ag_key_empty = name.lower().replace(" ", "")
                fail_agent(ag_key_empty,
                           f"{name} finished but no readable text was extracted",
                           ("CUA says the agent is done, but the extraction came back empty "
                            "(DOM HTML→MD, JS innerText, and CUA clipboard fallback all returned "
                            "no content). Retry runs the agent fresh; Skip drops this agent."))
                empty_decision = await _controls.await_agent_decision(ag_key_empty, timeout=300.0)
                log(f"[{name}] Empty-final user decision: {empty_decision}")
                if empty_decision == "stop":
                    break
                if empty_decision == "skip":
                    continue
                if empty_decision == "retry":
                    followup = (
                        "It looks like your final response didn't come through. Please output "
                        "the complete research report now — include all sources, sections, and findings. "
                        "No preamble or post-amble."
                    )
                    try:
                        await browser.switch_to_page(p["page"])
                        await paste_followup(p["page"], followup, name.lower(), label=f"{name}-retry-empty")
                    except Exception as e:
                        log(f"[{name}] Retry follow-up failed: {e}", "WARN")
                    p["start_time"] = time.time() - max(0, int(elapsed) - (15 * 60))
                    p["done_count"] = 0
                    p["cua_confirmed"] = False
                    p["last_cua_check"] = time.time()
                    p["empty_retries"] = 0
                    continue
                # timeout / continue_partial → fall through and accept the empty result.
                results[name] = {"status": "empty", "text": "",
                                 "url": p["page"].url if p["page"] else "",
                                 "page": p["page"], "elapsed_sec": int(elapsed)}
                _runtime.unregister_page(name.lower().replace(" ", ""), final_status="empty")
                del pending[name]
            else:
                p["done_count"] = 0
                p["cua_confirmed"] = False

        # Status update per cycle
        if pending:
            parts = []
            for n, p in pending.items():
                m = int((time.time() - p["start_time"]) / 60)
                parts.append(f"{n}:{m}m")
            log(f"Still polling: {', '.join(parts)}")
            # 2026-04-28: speed up the poll cycle ONCE any pending agent
            # has hit its done-marker. Default poll_interval is 120s
            # (POLL_DEEP_RESEARCH) — fine while agents are mid-run, but
            # the 2-snapshot tolerance gate above wants a quick second
            # confirmation tick. Drop to 30s when at least one agent is
            # in done-marker-confirmed state (they finish at unrelated
            # times, so the cycle is gated by the slowest pending). Save
            # ~60-90s on the post-completion gap (advisor 2026-04-28 R2).
            _any_done_marker = any(
                p.get("done_marker_first_at", 0.0) > 0.0 for p in pending.values()
            )
            await asyncio.sleep(30 if _any_done_marker else poll_interval)

    return results


# ── Direct Playwright Submit (zero CUA cost) ─────────────────────────────────

async def submit_chatgpt_direct(browser, prompt):
    """Submit prompt to ChatGPT using direct Playwright selectors."""
    page = browser.page
    try:
        await asyncio.sleep(2)
        # Dismiss overlays
        for sel in ['button:has-text("Okay")', 'button:has-text("Got it")',
                    'button:has-text("Dismiss")', '[aria-label="Close"]']:
            try:
                btn = await page.query_selector(sel)
                if btn and await btn.is_visible(): await btn.click(); await asyncio.sleep(0.5)
            except Exception: pass

        # Find input
        textarea = None
        for sel in ['#prompt-textarea', 'div[contenteditable="true"]#prompt-textarea',
                    'textarea[placeholder*="Message"]', 'div[contenteditable="true"][data-placeholder]']:
            try:
                textarea = await page.wait_for_selector(sel, timeout=5000)
                if textarea: break
            except Exception: continue

        if not textarea:
            log("Direct submit: no textarea found", "WARN")
            return False

        await textarea.click()
        await asyncio.sleep(0.3)

        # insertText — instant, avoids ChatGPT's clipboard-to-file behavior
        try:
            await page.keyboard.insert_text(prompt)
        except Exception:
            try:
                await textarea.fill(prompt)
            except Exception:
                await page.keyboard.type(prompt, delay=5)

        await asyncio.sleep(0.5)

        # Send
        send_btn = None
        for sel in ['button[data-testid="send-button"]', 'button[aria-label="Send prompt"]', 'button[aria-label="Send"]']:
            try:
                send_btn = await page.query_selector(sel)
                if send_btn and await send_btn.is_enabled(): break
                send_btn = None
            except Exception: continue
        if send_btn:
            await send_btn.click()
        else:
            await page.keyboard.press("Enter")

        await asyncio.sleep(2)
        sent = await page.evaluate("""() => {
            const msgs = document.querySelectorAll('[data-message-author-role="user"]');
            return msgs.length > 0;
        }""")
        if sent: log("Direct submit: message sent ✓")
        return sent

    except Exception as e:
        log(f"Direct submit failed: {e}", "WARN")
        return False


# ── PDF Attachment (Playwright) ──────────────────────────────────────────────

async def attach_pdf_chatgpt(browser, pdf_path):
    """Attach a PDF to ChatGPT input via file chooser."""
    page = browser.page
    try:
        # Look for hidden file input first (most reliable)
        file_input = await page.query_selector('input[type="file"]')
        if file_input:
            await file_input.set_input_files(str(pdf_path))
            log(f"Attached PDF via hidden input: {Path(pdf_path).name}")
            await asyncio.sleep(2)
            return True

        # Fallback: click the attachment button and handle file chooser
        browser.set_upload_file(str(pdf_path))
        for sel in ['button[aria-label="Attach files"]', 'button[aria-label="Attach"]',
                    'button[data-testid="upload-button"]']:
            try:
                btn = await page.query_selector(sel)
                if btn and await btn.is_visible():
                    await btn.click()
                    await asyncio.sleep(3)
                    log(f"Attached PDF via button click: {Path(pdf_path).name}")
                    browser.clear_upload_file()
                    return True
            except Exception: continue

        browser.clear_upload_file()
        log(f"Could not find attachment button for: {Path(pdf_path).name}", "WARN")
        return False
    except Exception as e:
        browser.clear_upload_file()
        log(f"PDF attachment failed: {e}", "WARN")
        return False


# ── Response Extraction ──────────────────────────────────────────────────────
# Goal: extract the FULL response with proper formatting. Try platform's copy
# Extraction chain: HTML→MD (best formatting) → copy button → JS innerText → clipboard.


def html_to_markdown(html):
    """Convert HTML to clean markdown using markdownify. Preserves all formatting."""
    try:
        from markdownify import markdownify as md
        text = md(html, heading_style="ATX", bullets="-", strip=['img', 'script', 'style'])
        # Clean up excessive whitespace
        lines = text.split('\n')
        cleaned = []
        prev_empty = False
        for line in lines:
            is_empty = not line.strip()
            if is_empty and prev_empty:
                continue
            cleaned.append(line.rstrip())
            prev_empty = is_empty
        return '\n'.join(cleaned).strip()
    except ImportError:
        log("markdownify not installed — falling back to innerText", "WARN")
        return ""


# ChatGPT Deep Research wraps inline citation markers in Private Use Area
# sentinels:  starts a run,  separates tokens,  ends it.
# Two known prefix variants: "cite" (web/view/search citations) and
# "filecite" (file citations from user-attached docs). The PUA glyphs
# render as nothing in most fonts, so the user sees a long unbreakable
# token blob ("citeturn18view0turn18view1...") that the FE wraps as a
# wall of low-information noise. Stripping is safe by construction —
# PUA codepoints cannot appear in any legitimate prose (browser would
# render them as boxes), and the regex only matches between the two
# specific sentinels, so it cannot collide with the literal word "cite"
# elsewhere in text. Verified 2026-05-25 against a 39KB chatgpt.md
# from prod: 67 runs matched, 3,657 chars removed, zero PUA residue,
# zero false-matches on legitimate prose. Gemini/Claude extractors
# don't emit these sentinels (verified on same-day gemini.md / claude.md).
#
# Converting to numbered footnotes [1][2][3] was considered + rejected:
# the turn{N}{view|search|file}{M} indices reference ChatGPT's internal
# source list, NOT the source URLs we capture via observer-side
# extraction (research.py:~18261). Without a mapping we'd produce
# footnotes that point nowhere — strip is the correct choice.
_CHATGPT_CITE_TOKEN_RE = re.compile('[^]*')


def _strip_chatgpt_citation_tokens(md: str) -> str:
    """Strip ChatGPT's PUA-delimited citation token runs from extracted MD.
    Idempotent. No-op on input that doesn't contain the sentinels (e.g.,
    Gemini/Claude extractions), so safe to call from shared helpers if
    needed later."""
    if not md:
        return md
    return _CHATGPT_CITE_TOKEN_RE.sub('', md)


async def _extract_html_to_md(page, selectors, label):
    """Extract response HTML from page, convert to clean markdown.

    Returns a tuple-like sequence via the existing string return, but emits
    DEBUG telemetry on miss so the caller (and the next E2E) can see
    selector-level hit counts. Previously every miss was silent — when T2
    fell through on P2 ChatGPT we had no way to tell whether (a) no
    selectors matched, (b) selectors matched but innerHTML was too short,
    or (c) html_to_markdown returned an empty string."""
    biggest_html_len = 0
    biggest_sel = ""
    matched_sels = 0
    for sel in selectors:
        try:
            html = await page.evaluate(f"""() => {{
                const els = document.querySelectorAll('{sel}');
                if (els.length > 0) return els[els.length - 1].innerHTML;
                return '';
            }}""")
            if html:
                matched_sels += 1
                if len(html) > biggest_html_len:
                    biggest_html_len = len(html)
                    biggest_sel = sel
            if html and len(html) > 200:
                md_text = html_to_markdown(html)
                if md_text and len(md_text) > 100:
                    log(f"[{label}] Extracted via HTML→MD: {len(md_text)} chars")
                    return md_text
        except Exception:
            continue
    # Miss path — log what we found so the next failing E2E doesn't leave
    # us blind. matched_sels=0 means no selector hit any element (most
    # likely cause: DOM uses different class/data-testid conventions);
    # matched_sels>0 with biggest_html_len<=200 means content selectors
    # matched but the elements were empty/sparse (likely the wrong
    # container — narrow your selectors). INFO level so it survives
    # default log-level filters in prod.
    log(f"[{label}] HTML→MD miss: tried={len(selectors)} sels, matched={matched_sels}, "
        f"biggest_html_len={biggest_html_len}"
        + (f" (sel='{biggest_sel}')" if biggest_sel else ""), "INFO")
    return ""


def _chatgpt_dr_frame_targets(page):
    """Return the list of frame targets worth running hijack/HTML→MD
    against for ChatGPT Deep Research. Always begins with the main page,
    then appends any iframe whose URL matches the Deep Research sandbox.

    Why this exists (2026-05-13): the DR canvas/artifact lives inside a
    cross-origin sandboxed iframe (e.g.
    `connector_openai_deep_research.web-sandbox.oaiusercontent.com`).
    `page.evaluate` only sees the parent document, so every hijack
    attempt against the parent logged `no_button_clicked` and every
    HTML→MD scrape returned 0 chars — the chain fell through to CUA
    (Tier 3) which doesn't work on Wayland. Iterating frames here lets
    Tier 1 and Tier 2 actually reach the DR DOM.
    """
    targets = [page]
    try:
        for frame in page.frames:
            try:
                src = (frame.url or "").lower()
            except Exception:
                continue
            if not src:
                continue
            if ("deep_research" in src
                    or "oaiusercontent" in src
                    or "web-sandbox.oaiusercontent" in src):
                targets.append(frame)
    except Exception:
        pass
    return targets


async def _extract_html_to_md_anyframe(page, selectors, label):
    """Frame-aware HTML→MD scrape. Tries the main page first, then any
    iframe matching the ChatGPT Deep Research sandbox URL.

    Mirrors `_extract_html_to_md` per-frame so the existing call-site
    semantics (returns "" on miss, logs the first selector that landed)
    stay intact. Sibling of `_chatgpt_dr_frame_targets`; same 2026-05-13
    motivation.

    DR-iframe density fallback (2026-05-14): when none of the supplied
    selectors matched a rich-enough container INSIDE the DR sandbox
    iframe, ask the iframe for its largest text-rich block (single
    element with the most non-whitespace text content, excluding nav/
    toolbar/composer chrome). Catches the "DR canvas uses plain divs,
    none of our `.markdown`/`.prose` selectors match" case that silently
    fell through to T3 clipboard hijack — and gives T2 a real chance to
    win even on DOM-drifted pages.

    Intentionally NOT applied to the main page: the conversation thread
    is a giant text-rich `<div>` (prompt + prior assistant turns) that
    would falsely outrank the DR document on cumulative textContent."""
    targets = _chatgpt_dr_frame_targets(page)
    for idx, target in enumerate(targets):
        try:
            md = await _extract_html_to_md(target, selectors, label)
        except Exception:
            md = ""
        if md:
            return md
        # Density fallback runs ONLY inside the DR sandbox iframe (idx > 0;
        # idx == 0 is the main page target which contains the chat thread).
        if idx == 0:
            continue
        try:
            html = await target.evaluate(r"""() => {
                // Chrome exclusion via TAGS + ARIA roles + data-testid (no
                // class-substring matches — those false-excluded real
                // content nodes named "section-header", "response-header-
                // wrapper", etc.).
                const isChrome = (el) => !!el.closest(
                    'nav, header, footer, aside, ' +
                    '[role="navigation"], [role="banner"], ' +
                    '[role="contentinfo"], [role="toolbar"], ' +
                    '[data-testid*="composer"], [data-testid*="sidebar"]'
                );
                let best = null;
                let bestLen = 0;
                // article/main/section are usually <100 nodes; div is the
                // long-tail. Cap div iteration at 500 to avoid O(n*subtree)
                // walks on huge thread-like DOMs.
                const tags = ['article', 'main', 'section', 'div'];
                const CAP_PER_TAG = 500;
                for (const tag of tags) {
                    const allEls = document.querySelectorAll(tag);
                    const limit = Math.min(allEls.length, CAP_PER_TAG);
                    for (let i = 0; i < limit; i++) {
                        const el = allEls[i];
                        if (isChrome(el)) continue;
                        const txt = (el.textContent || '').trim();
                        if (txt.length <= bestLen) continue;
                        // Skip wrappers that are just the page-body parent
                        // of the real content; require some structure
                        // (>=2 child text-bearing nodes) to bias toward
                        // content-rich containers over the body root.
                        const childCount = el.children?.length || 0;
                        if (childCount < 2) continue;
                        bestLen = txt.length;
                        best = el;
                    }
                }
                return best ? best.innerHTML : '';
            }""")
            if html and len(html) > 200:
                md_text = html_to_markdown(html)
                if md_text and len(md_text) > 500:
                    log(f"[{label}] Extracted via HTML→MD density fallback: {len(md_text)} chars (iframe target {idx})")
                    return md_text
        except Exception:
            pass
    return ""


async def _copy_via_hijack(
    page,
    label,
    *,
    canvas_root_selectors=None,
    kebab_selectors=None,
    menuitem_text_pattern=None,
    direct_copy_selectors=None,
    scoping_excludes=None,
    wait_ms=5000,
    min_chars=500,
):
    """Click an agent's Copy button while a JS hijack captures the
    markdown the page writes to navigator.clipboard.writeText /
    navigator.clipboard.write / synthetic copy event. Bypasses the OS
    clipboard entirely — works on Wayland, X11, Windows, macOS.

    Closes DGOPS-7366 (ChatGPT canvas selector drift) AND the Wayland
    0-char clipboard bug in one pattern: the agent's own Copy button is
    the canonical-markdown emitter, and the hijack catches it before it
    leaves the page context.

    Two click patterns supported:
    - direct_copy_selectors=[…]: click the first matching, visible,
      non-excluded button.
    - canvas_root_selectors + kebab_selectors + menuitem_text_pattern:
      scope to a canvas root, click a kebab/more button, then click the
      revealed menuitem whose text matches the regex pattern
      (case-insensitive).

    Robustness (per advisor cross-check 2026-05-12):
    - Single atomic page.evaluate so install + click + capture + restore
      runs in one JS lifetime. A thrown exception inside JS still hits
      the `restoreAll()` in the wrapping try/catch.
    - window.__dg_hijack_lock guard prevents concurrent hijacks on the
      same page from clobbering each other.
    - beforeunload listener auto-restores if the page navigates mid-
      hijack.
    - Hooks copy event (text/plain + text/html), navigator.clipboard.
      writeText (legacy/string), navigator.clipboard.write (modern/
      ClipboardItem). Belt-and-suspenders — agents use different paths.
    - Scoping excludes (defaults: dialogs, code blocks, nav, code-copy
      buttons) prevent the click from misfiring onto a "Copy code" or
      "Copy link" button.
    """
    DEFAULT_EXCLUDES = [
        'mat-dialog-container',
        'pre code',
        '[class*="code-block"]',
        '[class*="codeblock"]',
        'nav',
        '[role="navigation"]',
    ]
    excludes = scoping_excludes if scoping_excludes is not None else DEFAULT_EXCLUDES
    try:
        result = await page.evaluate(r"""(opts) => new Promise(async (resolve) => {
            const {
                canvas_root_selectors,
                kebab_selectors,
                menuitem_text_pattern,
                direct_copy_selectors,
                scoping_excludes,
                wait_ms,
            } = opts;
            if (window.__dg_hijack_lock) {
                resolve({ ok: false, reason: 'hijack_in_progress' });
                return;
            }
            window.__dg_hijack_lock = true;

            let capturedText = null;
            let capturedHtml = null;
            let captureSource = '';

            const copyHandler = (e) => {
                try {
                    if (!e.clipboardData) return;
                    const t = e.clipboardData.getData('text/plain');
                    const h = e.clipboardData.getData('text/html');
                    if (t && (!capturedText || t.length > capturedText.length)) {
                        capturedText = t;
                        captureSource = 'copy_event:text/plain';
                    }
                    if (h && (!capturedHtml || h.length > capturedHtml.length)) {
                        capturedHtml = h;
                        if (!capturedText) captureSource = 'copy_event:text/html';
                    }
                } catch {}
            };
            document.addEventListener('copy', copyHandler, { capture: true });

            const origWriteText = navigator.clipboard && navigator.clipboard.writeText
                ? navigator.clipboard.writeText.bind(navigator.clipboard) : null;
            if (origWriteText) {
                navigator.clipboard.writeText = async (t) => {
                    try {
                        if (t && (!capturedText || t.length > capturedText.length)) {
                            capturedText = t;
                            captureSource = 'writeText';
                        }
                    } catch {}
                    return origWriteText(t);
                };
            }

            const origWrite = navigator.clipboard && navigator.clipboard.write
                ? navigator.clipboard.write.bind(navigator.clipboard) : null;
            if (origWrite) {
                navigator.clipboard.write = async (items) => {
                    try {
                        for (const item of items || []) {
                            for (const t of (item.types || [])) {
                                try {
                                    const blob = await item.getType(t);
                                    const s = await blob.text();
                                    if (t === 'text/plain' && s
                                        && (!capturedText || s.length > capturedText.length)) {
                                        capturedText = s;
                                        captureSource = 'write:text/plain';
                                    } else if (t === 'text/html' && s
                                        && (!capturedHtml || s.length > capturedHtml.length)) {
                                        capturedHtml = s;
                                        if (!capturedText) captureSource = 'write:text/html';
                                    }
                                } catch {}
                            }
                        }
                    } catch {}
                    return origWrite(items);
                };
            }

            const beforeUnload = () => restoreAll();
            window.addEventListener('beforeunload', beforeUnload, { once: true });

            function restoreAll() {
                try { document.removeEventListener('copy', copyHandler, { capture: true }); } catch {}
                if (origWriteText) {
                    try { navigator.clipboard.writeText = origWriteText; } catch {}
                }
                if (origWrite) {
                    try { navigator.clipboard.write = origWrite; } catch {}
                }
                try { window.removeEventListener('beforeunload', beforeUnload); } catch {}
                window.__dg_hijack_lock = false;
            }

            function isExcluded(btn) {
                if (!scoping_excludes) return false;
                for (const ex of scoping_excludes) {
                    try {
                        if (btn.closest(ex)) return true;
                    } catch {}
                }
                return false;
            }

            try {
                let clickedSel = null;
                if (direct_copy_selectors && direct_copy_selectors.length > 0) {
                    for (const sel of direct_copy_selectors) {
                        try {
                            const btns = document.querySelectorAll(sel);
                            for (const b of btns) {
                                if (b.offsetWidth === 0 && b.offsetHeight === 0) continue;
                                if (isExcluded(b)) continue;
                                b.click();
                                clickedSel = sel;
                                break;
                            }
                            if (clickedSel) break;
                        } catch {}
                    }
                }
                if (!clickedSel && kebab_selectors && menuitem_text_pattern) {
                    let canvasRoot = document;
                    if (canvas_root_selectors) {
                        for (const sel of canvas_root_selectors) {
                            try {
                                const r = document.querySelector(sel);
                                if (r) { canvasRoot = r; break; }
                            } catch {}
                        }
                    }
                    let kebabSel = null;
                    for (const sel of kebab_selectors) {
                        try {
                            const btns = canvasRoot.querySelectorAll(sel);
                            for (const b of btns) {
                                if (b.offsetWidth === 0 && b.offsetHeight === 0) continue;
                                b.click();
                                kebabSel = sel;
                                break;
                            }
                            if (kebabSel) break;
                        } catch {}
                    }
                    if (kebabSel) {
                        await new Promise(r => setTimeout(r, 400));
                        const pat = new RegExp(menuitem_text_pattern, 'i');
                        const items = document.querySelectorAll(
                            '[role="menuitem"], [role="menu"] button, [role="menu"] [role="button"]'
                        );
                        for (const it of items) {
                            const txt = (it.textContent || '').trim();
                            if (pat.test(txt)) {
                                it.click();
                                clickedSel = 'kebab(' + kebabSel + ') → menuitem(' + txt.slice(0, 40) + ')';
                                break;
                            }
                        }
                    }
                }

                if (!clickedSel) {
                    restoreAll();
                    resolve({ ok: false, reason: 'no_button_clicked' });
                    return;
                }

                const start = Date.now();
                while (Date.now() - start < wait_ms) {
                    if (capturedText || capturedHtml) break;
                    await new Promise(r => setTimeout(r, 100));
                }

                restoreAll();
                resolve({
                    ok: !!(capturedText || capturedHtml),
                    text: capturedText,
                    html: capturedHtml,
                    source: captureSource,
                    clicked: clickedSel,
                });
            } catch (e) {
                restoreAll();
                resolve({ ok: false, reason: 'error:' + (e && e.message || String(e)) });
            }
        })""", {
            "canvas_root_selectors": canvas_root_selectors,
            "kebab_selectors": kebab_selectors,
            "menuitem_text_pattern": menuitem_text_pattern,
            "direct_copy_selectors": direct_copy_selectors,
            "scoping_excludes": excludes,
            "wait_ms": wait_ms,
        })

        if not result or not result.get("ok"):
            # 2026-05-13 diagnostic: surface what (if anything) the hijack
            # actually clicked. `no_capture` (button clicked, no clipboard
            # write within wait_ms) is the silent-fail case we couldn't
            # diagnose before — knowing the clicked selector lets us see
            # whether the wrong button was hit or the right button just
            # doesn't fire a copy event with hijackable mime types.
            _rclick = (result or {}).get("clicked") or "—"
            _rreason = (result or {}).get("reason") or "no_capture"
            log(f"[{label}] Copy hijack: {_rreason} (clicked={_rclick})", "DEBUG")
            return ""
        text = result.get("text") or ""
        html = result.get("html") or ""
        src = result.get("source", "")
        clicked = result.get("clicked", "")
        # Prefer text/plain (canonical markdown). Fall through to html→md
        # if text was empty or below min_chars but html is rich.
        if text and len(text) >= min_chars:
            log(f"[{label}] Copy hijack captured {len(text)} chars via {src} (clicked: {clicked})")
            return text
        if html and len(html) >= max(200, min_chars // 4):
            md = html_to_markdown(html)
            if md and len(md) >= min_chars:
                log(f"[{label}] Copy hijack captured {len(html)}B HTML → {len(md)} chars MD via {src} (clicked: {clicked})")
                return md
        log(f"[{label}] Copy hijack captured but too short (text={len(text)}, html={len(html)}, src={src})", "DEBUG")
        return ""
    except Exception as e:
        log(f"[{label}] Copy hijack exception: {e}", "WARN")
        return ""


async def _extract_via_cua_download(
    page,
    browser,
    cua_client,
    label,
    cua_prompt,
    cua_user_msg,
    *,
    max_iterations=12,
    cua_timeout_s=180.0,
    # Must be >= cua_timeout_s * 1000 + a small grace, because
    # page.expect_download() starts its clock when the async-with enters
    # (BEFORE the CUA loop runs). With the prior 30s default, a future
    # caller using defaults would race the listener vs the CUA loop's
    # cua_timeout_s=180s wall-clock cap. cua_timeout_s + 15s grace.
    download_timeout_ms=195000,
    min_chars=500,
    verbose=False,
):
    """Tier 1 primitive for CUA-driven download flows (ChatGPT + Claude).

    CUA navigates the UI per the prompt (close panel, open canvas, click
    download icon, click Export/Download as Markdown menu item). Playwright's
    `expect_download()` captures the resulting file. Read as UTF-8 markdown.

    Wayland-safe: no OS clipboard. Selector-free: CUA does all clicking.

    Why this is Tier 1: it sidesteps DOM selector drift entirely. ChatGPT
    canvas / Claude artifact download buttons are visually consistent
    across versions; CUA finds them by sight. The download event hook is
    selector-independent — Playwright intercepts whichever file the menu
    item triggers.

    Returns "" on any failure (CUA exhausts iterations → expect_download
    never fires; or CUA cap hit → asyncio.TimeoutError; or content <
    min_chars). The empty return is the contract for the caller's Tier-2
    fallback.
    """
    if browser is None or cua_client is None:
        return ""
    try:
        await browser.switch_to_page(page)
    except Exception as e:
        log(f"[{label}] CUA download: switch_to_page failed: {e}", "WARN")
        return ""

    download = None
    cua_completed = False
    try:
        # Wrap the entire CUA loop in expect_download. The download event
        # fires WHENEVER CUA clicks the final menu item — could be early
        # in the iteration budget. expect_download buffers and waits up to
        # download_timeout_ms after the `async with` body exits, which
        # gives a small post-loop grace window for an in-flight download.
        try:
            async with page.expect_download(timeout=download_timeout_ms) as dl_info:
                try:
                    await asyncio.wait_for(
                        agent_loop(
                            cua_client, browser,
                            cua_prompt, cua_user_msg,
                            model=CUA_MODEL,
                            max_iterations=max_iterations,
                            verbose=verbose,
                            target_page=page,
                        ),
                        timeout=cua_timeout_s,
                    )
                    cua_completed = True
                except asyncio.TimeoutError:
                    # CUA hit its wall-clock cap. expect_download may still
                    # fire if the final click happened just before timeout
                    # — let the `async with` exit wait for it.
                    log(f"[{label}] CUA download: CUA timed out after {cua_timeout_s}s", "WARN")
                except Exception as e:
                    log(f"[{label}] CUA download: CUA raised: {e}", "WARN")
            download = await dl_info.value
        except Exception as e:
            _msg = str(e).split("\n")[0][:200]
            log(f"[{label}] CUA download: no download event within "
                f"{download_timeout_ms}ms ({_msg})", "WARN")
            return ""

        # Read the captured file.
        try:
            path = await download.path()
            if not path:
                log(f"[{label}] CUA download: download.path() returned None", "WARN")
                return ""
            with open(path, "r", encoding="utf-8", errors="replace") as f:
                content = f.read()
        except Exception as e:
            log(f"[{label}] CUA download: file read failed: {e}", "WARN")
            return ""

        if not content or len(content) < min_chars:
            log(f"[{label}] CUA download: captured {len(content or '')} "
                f"chars < min {min_chars} (cua_completed={cua_completed})", "WARN")
            return ""
        log(f"[{label}] CUA download captured {len(content)} chars "
            f"(cua_completed={cua_completed})")
        return content
    finally:
        # Best-effort cleanup of Playwright's temp file.
        if download is not None:
            try:
                await download.delete()
            except Exception:
                pass


async def _run_with_clipboard_hijack(
    page,
    label,
    trigger,
    *,
    timeout_ms=30000,
    min_chars=500,
):
    """Tier 3 primitive — install JS clipboard hooks in main page + all
    frames, run a caller-supplied async trigger (Playwright keyboard chord,
    button click, CUA agent_loop), then read the longest captured text
    back from `window.__dg_cb_captured_text` across every frame.
    Wayland-safe — never reads the OS clipboard.

    Captures from THREE sources per frame (longest wins):
    - `copy` event `clipboardData.getData('text/plain')` (page-side
      handlers that call setData — e.g. Gemini's Copy contents).
    - `window.getSelection().toString()` from inside the copy handler
      (RAW Ctrl+C path: the browser's default copy puts text onto the
      OS clipboard WITHOUT populating clipboardData, but the selection
      object still reflects what got copied).
    - navigator.clipboard.writeText / write (modern async API).

    Iframe coverage (2026-05-14): ChatGPT Deep Research canvas + Claude
    artifact bodies render inside sandbox iframes. CUA's Ctrl+A selects
    text INSIDE the iframe, so main-page getSelection() returns empty.
    We install the hook in EACH frame; each writes to its own window-
    scoped __dg_cb_captured_text; the poll step reads from every frame
    and returns the longest.

    `__dg_cb_*` global namespace is distinct from the older
    `_copy_via_hijack` (`__dg_hijack_lock`) so both helpers can coexist
    on the same page without races.

    `timeout_ms` bounds the trigger's run time. Set it ABOVE the trigger's
    own internal wait_for cap when wrapping a CUA loop (e.g. 200000 around
    an inner wait_for(180.0)) — otherwise the helper kills CUA prematurely.
    """
    install_script = r"""() => {
        if (window.__dg_cb_hijack_active) return false;
        window.__dg_cb_hijack_active = true;
        window.__dg_cb_captured_text = '';

        const setIfLonger = (s) => {
            try {
                if (s && s.length > (window.__dg_cb_captured_text || '').length) {
                    window.__dg_cb_captured_text = s;
                }
            } catch {}
        };

        const copyHandler = (e) => {
            // Source A: clipboardData (page-side setData path — works for
            // Copy buttons whose handlers call setData explicitly).
            try {
                if (e && e.clipboardData) {
                    setIfLonger(e.clipboardData.getData('text/plain') || '');
                }
            } catch {}
            // Source B (2026-05-14 fix): window.getSelection() — captures
            // the visually-selected text regardless of who triggered the
            // copy. Required for the RAW Ctrl+C path (CUA / Playwright
            // keyboard chord) where the browser's default copy puts text
            // onto the OS clipboard WITHOUT populating clipboardData.
            try {
                const sel = (window.getSelection && window.getSelection())
                    ? window.getSelection().toString() : '';
                setIfLonger(sel || '');
            } catch {}
        };
        document.addEventListener('copy', copyHandler, { capture: true });

        const origWriteText = navigator.clipboard && navigator.clipboard.writeText
            ? navigator.clipboard.writeText.bind(navigator.clipboard) : null;
        if (origWriteText) {
            navigator.clipboard.writeText = async (t) => {
                setIfLonger(t || '');
                return origWriteText(t);
            };
        }

        const origWrite = navigator.clipboard && navigator.clipboard.write
            ? navigator.clipboard.write.bind(navigator.clipboard) : null;
        if (origWrite) {
            navigator.clipboard.write = async (items) => {
                try {
                    for (const item of items || []) {
                        for (const ty of (item.types || [])) {
                            try {
                                const blob = await item.getType(ty);
                                const s = await blob.text();
                                if (ty === 'text/plain') setIfLonger(s || '');
                            } catch {}
                        }
                    }
                } catch {}
                return origWrite(items);
            };
        }

        const beforeUnload = () => { try { window.__dg_unhook?.(); } catch {} };
        window.addEventListener('beforeunload', beforeUnload, { once: true });

        window.__dg_unhook = () => {
            try { document.removeEventListener('copy', copyHandler, { capture: true }); } catch {}
            if (origWriteText) {
                try { navigator.clipboard.writeText = origWriteText; } catch {}
            }
            if (origWrite) {
                try { navigator.clipboard.write = origWrite; } catch {}
            }
            try { window.removeEventListener('beforeunload', beforeUnload); } catch {}
            window.__dg_cb_hijack_active = false;
        };
        return true;
    }"""

    # Collect every frame target (main + iframes). `page` itself covers
    # the main frame's window scope; iterate page.frames to pick up
    # iframes (skipping main_frame to avoid double-install).
    try:
        frame_list = list(page.frames)
    except Exception:
        frame_list = []
    targets = [page]
    for f in frame_list:
        try:
            if f is page.main_frame:
                continue
        except Exception:
            continue
        targets.append(f)

    installed_targets = []
    try:
        # ── Step 1: install hook in every target ──
        for tgt in targets:
            try:
                ok = await tgt.evaluate(install_script)
                if ok is not False:
                    installed_targets.append(tgt)
            except Exception as e:
                # Frame detached, cross-origin restriction we can't bypass,
                # or sandbox refusal. Skip and continue.
                try:
                    _url = getattr(tgt, "url", None) or "—"
                except Exception:
                    _url = "—"
                log(f"[{label}] Clipboard hijack: install skipped on frame "
                    f"({_url[:80]}): {type(e).__name__}", "DEBUG")
        if not installed_targets:
            log(f"[{label}] Clipboard hijack: install failed on all frames", "WARN")
            return ""

        # ── Step 2: run trigger (Playwright/CUA/whatever the caller wants) ──
        try:
            await asyncio.wait_for(trigger(), timeout=timeout_ms / 1000.0)
        except asyncio.TimeoutError:
            log(f"[{label}] Clipboard hijack: trigger exceeded {timeout_ms}ms", "WARN")
        except Exception as e:
            log(f"[{label}] Clipboard hijack: trigger raised: {e}", "WARN")

        # ── Step 3: poll for async clipboard writes across all frames ──
        captured = ""
        for _ in range(5):
            for tgt in list(installed_targets):
                try:
                    v = await tgt.evaluate(
                        "() => window.__dg_cb_captured_text || ''"
                    )
                except Exception:
                    # Frame detached mid-poll (canvas closed by CUA's
                    # final click). Drop it from the active set and keep
                    # reading the others.
                    try:
                        installed_targets.remove(tgt)
                    except ValueError:
                        pass
                    continue
                if v and len(v) > len(captured):
                    captured = v
            if captured and len(captured) >= min_chars:
                break
            await asyncio.sleep(0.2)

        if not captured or len(captured) < min_chars:
            # Per-frame capture-length distribution — distinguishes
            # "one frame caught a short capture, others dry" (selector
            # / scope problem) from "all frames dry" (trigger never
            # produced a copy event in any frame at all). The aggregate
            # `frames=N` count alone can't tell those apart, which made
            # the 2026-05-25 Kalki Gemini T1 zero-char failure hard to
            # diagnose. -1 entries mean the frame detached between the
            # poll loop and this introspection.
            per_frame_lens = []
            for tgt in installed_targets:
                try:
                    _l = await tgt.evaluate(
                        "() => (window.__dg_cb_captured_text || '').length"
                    )
                    per_frame_lens.append(int(_l))
                except Exception:
                    per_frame_lens.append(-1)
            log(f"[{label}] Clipboard hijack: captured {len(captured or '')} "
                f"chars < min {min_chars} (frames={len(installed_targets)} "
                f"lens={per_frame_lens})", "WARN")
            return ""
        log(f"[{label}] Clipboard hijack captured {len(captured)} chars "
            f"(across {len(installed_targets)} frame target(s))")
        return captured
    finally:
        # Restore originals on every frame we installed into.
        for tgt in installed_targets:
            try:
                await tgt.evaluate(
                    "() => { try { window.__dg_unhook && window.__dg_unhook(); } catch {} }"
                )
            except Exception:
                pass


async def extract_chatgpt_response(page, browser=None, cua_client=None, label="ChatGPT", verbose=False):
    """Extract ChatGPT response — 3 Wayland-safe tiers (rewritten 2026-05-14).

    Per-agent extraction model is intentionally divergent (the PR body's
    "T1 = X, T2 = Y, T3 = Z" describes the META-pattern — DOM → CUA →
    clipboard-hijack — not a uniform per-agent mapping):
      - ChatGPT (this fn): CUA download → HTML→MD → CUA copy hijack
      - Gemini (`extract_gemini_response`, research.py:19575): Share&Export
        hijack → HTML→MD → Ctrl+A/C hijack (reordered 2026-05-24 — native
        Share & Export menu is Gemini's authoritative export path; DOM
        scrape is the deterministic fallback when CUA can't drive the menu)
      - Claude (`extract_claude_response`, research.py:16640): two-mode —
        3 tiers in Deep Research artifact-aware mode (T1 CUA-download →
        T2 publish + HTML→MD on claude.site → T3 CUA + clipboard hijack;
        collapsed from a 4-tier ladder on 2026-05-13). Targets the LAST
        artifact since DR produces 2 (tracking checklist + final report).
        Chat-mode branch has its own Tier 1/2 (HTML→MD primary, Copy
        hijack fallback) — fires when Research wasn't enabled and the
        operator continued in chat.

    ChatGPT-specific tier ordering:
      Tier 1: CUA-driven download flow (close source panel, open canvas
              full-page, click download icon, click "Export to Markdown",
              expect_download captures the .md). Selector-free; CUA does
              all clicking. Wayland-safe.
      Tier 2: HTML→MD on whatever canvas state Tier 1 left mounted (canvas
              should be open full-page from CUA's enlarge click).
      Tier 3: CUA Copy + JS clipboard hijack (Ctrl+A/C with getSelection
              + iframe-aware install). Wayland-safe.

    Phase 1 (brief extraction) calls with browser=None / cua_client=None
    so Tier 1 + Tier 3 gate off — Tier 2 HTML→MD is its sole path.

    ChatGPT Deep Research outputs a document/artifact card, not regular chat text."""
    await asyncio.sleep(2)
    await page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
    await asyncio.sleep(1)

    # ── Tier 1: CUA-driven download flow ──
    # CUA handles: close any open side panel, click the artifact-card
    # enlarge button (opens canvas full-page), click the canvas's
    # download icon (top-right, distinct from Share icon), click
    # "Export to Markdown" in the dropdown. Playwright `expect_download()`
    # captures the resulting .md file. Selector-free end-to-end; CUA's
    # vision finds buttons regardless of DOM drift.
    if browser and cua_client:
        md = await _extract_via_cua_download(
            page, browser, cua_client, label,
            PROMPT_CHATGPT_DOWNLOAD_MD,
            "Close any open side panel, open the canvas, then click the "
            "download icon and choose Export to Markdown.",
            max_iterations=12, cua_timeout_s=180.0,
            # download_timeout_ms must exceed cua_timeout_s, since
            # page.expect_download() starts its clock when the `async with`
            # enters — which is BEFORE the CUA loop runs. With the prior
            # 30s value, ChatGPT's CUA loop (which takes ~30-45s to reach
            # the final 'Export to Markdown' click) would race the
            # listener: the listener expired ~2s before the click fired,
            # so the actual download wasn't captured and T1 silently
            # fell back to T3 clipboard hijack (which loses markdown
            # structure). cua_timeout_s + 15s grace covers the final
            # click + download-event RTT.
            download_timeout_ms=195000, min_chars=500, verbose=verbose,
        )
        if md and len(md) >= 500:
            if _is_sources_not_document(md, platform="chatgpt"):
                log(f"[{label}] T1 download wrong-artifact ({len(md)} chars) — falling to Tier 2", "WARN")
                try:
                    emit_event("wrong_artifact_rejected", phase=2, agent="chatgpt",
                               op="finalize_copy", length=len(md), tier="cua_download_md")
                except Exception:
                    pass
            else:
                md = _strip_chatgpt_citation_tokens(md)
                log(f"[{label}] Extracted via T1 CUA download (Export to Markdown): {len(md)} chars")
                return md

    # ── Tier 2: HTML→MD scrape (canvas should be open from T1) ──
    # If T1 succeeded in enlarging the canvas but the download itself
    # failed, the canvas DOM is now mounted — these selectors hit it.
    # If T1 never ran (P1 brief path, browser=None), HTML→MD against
    # the chat-side selectors still works for the brief.
    md = await _extract_html_to_md_anyframe(page, [
        '.canvas-content', '.artifact-content', '[data-testid="canvas-content"]',
        '[role="dialog"] .markdown', '[role="dialog"] .prose',
        '[role="dialog"] article',
        '[role="dialog"] [class*="markdown-content"]',
        'main [class*="canvas"] .markdown',
        'main [class*="canvas"] [class*="prose"]',
        'main [class*="artifact"] [class*="prose"]',
        '[data-testid*="canvas"] [class*="prose"]',
        '[data-testid*="canvas"] [class*="markdown"]',
        'aside[role="dialog"] [class*="prose"]',
        '[data-message-author-role="assistant"]:last-of-type .markdown',
        '[data-message-author-role="assistant"]:last-of-type [class*="prose"]',
        # Iframe-side: DR document body markup. These selectors don't
        # exist on chatgpt.com proper (the parent) so they only match
        # when we descend into the DR sandbox frame.
        'article',
        '.markdown',
        '.prose',
        'main article',
        'main .markdown',
        'main .prose',
    ], label)
    if md and len(md) > 2000:
        if _is_sources_not_document(md, platform="chatgpt"):
            log(f"[{label}] T2 HTML→MD wrong-artifact ({len(md)} chars source-panel-shape) "
                f"— falling to Tier 3", "WARN")
            try:
                emit_event("wrong_artifact_rejected", phase=2, agent="chatgpt",
                           op="finalize_copy", length=len(md), tier="dom_html_md")
            except Exception:
                pass
        elif _looks_like_nav_sidebar(md):
            log(f"[{label}] T2 HTML→MD looks-like-nav-sidebar ({len(md)} chars) — falling to Tier 3", "WARN")
        else:
            md = _strip_chatgpt_citation_tokens(md)
            log(f"[{label}] Extracted via T2 HTML→MD (canvas/artifact): {len(md)} chars")
            return md

    # ── Tier 3 (LAST RESORT, Wayland-safe): CUA + clipboard hijack ──
    # JS clipboard hijack reads window.getSelection().toString() inside
    # the copy event handler, so raw Ctrl+C captures selected text even
    # when no page-side setData fires. Iframe-aware install covers the
    # DR canvas sandbox iframe. Helper timeout_ms = 200000 sits ABOVE
    # the inner asyncio.wait_for(180.0) so the inner cap fires first.
    if browser and cua_client:
        async def _cgpt_t3_trigger():
            await browser.switch_to_page(page)
            await asyncio.wait_for(
                agent_loop(cua_client, browser, PROMPT_COPY_ARTIFACT_CHATGPT,
                    "Open the research report document and copy its full "
                    "content to clipboard.",
                    model=CUA_MODEL, max_iterations=12,
                    verbose=verbose, target_page=page),
                timeout=180.0)

        log(f"[{label}] CUA: Tier 3 copy with clipboard hijack")
        try:
            md = await _run_with_clipboard_hijack(
                page, label, _cgpt_t3_trigger,
                timeout_ms=200000, min_chars=500)
        except Exception as _e:
            log(f"[{label}] T3 clipboard hijack raised: {_e}", "WARN")
            md = ""
        if md and len(md) >= 500:
            if _is_sources_not_document(md, platform="chatgpt"):
                log(f"[{label}] T3 hijack wrong-artifact ({len(md)} chars) — rejecting", "WARN")
                try:
                    emit_event("wrong_artifact_rejected", phase=2, agent="chatgpt",
                               op="finalize_copy", length=len(md), tier="cua_hijack")
                except Exception:
                    pass
            else:
                md = _strip_chatgpt_citation_tokens(md)
                log(f"[{label}] Extracted via T3 CUA + clipboard hijack: {len(md)} chars")
                return md

    try:
        emit_event("extract_failed", phase=2, agent="chatgpt",
                   op="finalize_copy",
                   reason="all_methods_returned_empty_or_wrong_artifact")
    except Exception:
        pass
    log(f"[{label}] All extraction methods failed (canvas may not have opened)", "WARN")
    return ""


async def extract_gemini_response(page, browser=None, cua_client=None, label="Gemini", verbose=False):
    """Dedicated Gemini extractor — 3 panel-aware tiers:
      Tier 1: HTML→MD from Gemini's strict side-panel containers (DOM-scrape
              from immersive-panel / deep-research-panel — returns the full
              90k-146k-char report with heading hierarchy preserved by the
              semantic HTML, which the clipboard dump sometimes flattens).
      Tier 2: CUA Share & Export → "Copy contents", then read the OS
              clipboard (Gemini's native authoritative export; we read the
              clipboard because the in-page hijack misses Gemini's async-
              Clipboard-API copy — see the T2 fix note below).
      Tier 3: Ctrl+A / Ctrl+C with JS clipboard hijack (panel-focused).
    Each tier emits an explicit log line so the path that succeeded (or
    silently returned empty) is visible in the run log.
    Returns the markdown/text or "" on total failure."""
    await asyncio.sleep(2)
    await page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
    await asyncio.sleep(1)

    # 2026-05-25 PRE-FLIGHT: verify a Deep Research side-panel exists
    # before any tier runs. Two recent E2Es (Kalki + Golden Retriever)
    # saved 318/101,274 chars of CHAT-side content as gemini.md because
    # the panel selectors didn't match and tiers fell through to chat
    # selectors. Failing fast with status=failed (no MD upload) is
    # better than silently shipping chat as the research output.
    # Best-effort poll up to ~10s to absorb transient render lag.
    _panel_selectors_preflight = [
        'immersive-panel',
        'deep-research-panel',
        'aside[class*="artifact" i]',
        'aside[class*="report" i]',
        'aside[class*="research" i]',
        '[role="complementary"][aria-label*="research" i]',
        '[role="region"][aria-label*="research" i]',
    ]
    _panel_found_sel = ""
    for _attempt in range(5):
        for _sel in _panel_selectors_preflight:
            try:
                _count = await page.evaluate(
                    f"() => document.querySelectorAll('{_sel}').length"
                )
                if _count and int(_count) > 0:
                    _panel_found_sel = _sel
                    break
            except Exception:
                continue
        if _panel_found_sel:
            break
        await asyncio.sleep(2.0)
    if _panel_found_sel:
        log(f"[{label}] DR panel present (selector='{_panel_found_sel}')")
    else:
        log(f"[{label}] DR panel NOT present after 10s — upstream submit/Start "
            f"likely failed; running tiers anyway but expect failure", "WARN")

    # 2026-05-28 ARCHITECTURE (T1↔T2 swap from 2026-05-26 ordering): T1 =
    # HTML→MD side-panel scrape (the report DOM is already authoritative; the
    # markdown rendered from the panel's semantic HTML preserves heading
    # hierarchy + list structure that the clipboard dump occasionally
    # flattens — cross-run comparisons showed the HTML→MD output looked
    # cleaner than the CUA Copy-contents output). T2 = CUA Share & Export →
    # "Copy contents" (Gemini's native authoritative export, kept as the
    # fallback when panel selectors don't match the latest UI revision).
    # T3 = CUA Ctrl+A/C select-all. All three are PANEL-AWARE — the
    # post-2026-05 Gemini UI renders the report in a right-side panel
    # (immersive-panel / deep-research-panel) and Share & Export lives on
    # that panel's toolbar.
    #
    # T2 0-char FIX (2026-05-26, originally a T1 fix pre-swap): the CUA
    # click was always working (backend-2 logs: CUA clicks Share & Export →
    # Copy contents, page shows "copied") but the in-page clipboard hijack
    # captured 0 chars. Root cause: Gemini's "Copy contents" writes the
    # markdown to the REAL OS clipboard via the async Clipboard API against
    # a writeText reference it cached at page-load, so our late writeText
    # monkey-patch never sees it (and no `copy` event fires for the async
    # API, and nothing is visually selected, so the copy-event + getSelection
    # sources are dry too). The fix: after the click, READ the OS clipboard
    # (navigator.clipboard.readText → PowerShell get_clipboard fallback —
    # the same ladder the share-link extractor uses). The hijack capture is
    # still attempted first for the cases where it works.

    # ── Tier 1 (PRIMARY): HTML→MD from Gemini's research-panel containers ──
    # Panel-aware: STRICT side-panel scopes only (no chat-side ack). Reads
    # the report straight from the panel DOM and renders it through the
    # same html_to_md path the brief extractor uses — historically the path
    # that reliably got 90k-146k chars in prior E2Es and (per the user's
    # cross-run review on 2026-05-28) produced cleaner markdown than the
    # CUA Copy-contents export (semantic HTML preserves heading hierarchy +
    # list structure that the clipboard dump occasionally flattens). Falls
    # to T2 only when the panel selectors don't match the current UI.
    #
    # 2026-05-25 selector tighten: prior list included `[class*="immersive" i]
    # message-content` and `[class*="immersive" i] .markdown` — these are
    # TOO GREEDY because Gemini's 2026-05+ app wraps EVERYTHING (chat
    # included) in immersive ancestors. The greedy descendants matched
    # the chat's <message-content>, returning 101,274 chars of chat
    # (Golden Retriever E2E) as gemini.md. Legacy chat-inline fallbacks
    # (`message-content`, `.model-response-text`, `.response-container`)
    # also stripped — they would catch chat-side content when no real
    # panel exists. Now keep only STRICT side-panel scopes: custom
    # elements (`immersive-panel`, `deep-research-panel`), aside scopes
    # with class wildcards, and ARIA role-complementary/role-region
    # with aria-label="research". If none match, return empty (T2 follows).
    md = await _extract_html_to_md(page, [
        # Custom elements — only match the actual panel, not descendants
        'immersive-panel',
        'deep-research-panel',
        # Aside-scoped (aside is structural for side content)
        'aside immersive-panel',
        'aside deep-research-panel',
        'aside[class*="artifact" i] .markdown',
        'aside[class*="artifact" i]',
        'aside[class*="report" i] .markdown',
        'aside[class*="report" i]',
        'aside[class*="research" i] .markdown',
        'aside[class*="research" i]',
        # ARIA role-scoped — explicit research panel intent
        '[role="complementary"][aria-label*="research" i] .markdown',
        '[role="complementary"][aria-label*="research" i]',
        '[role="region"][aria-label*="research" i] .markdown',
        '[role="region"][aria-label*="research" i]',
    ], label)
    # 2026-05-25: strip Gemini's panel chrome + post-report sources/
    # thinking-trace noise BEFORE the threshold check. The 146kb Kalki
    # gemini.md (2026-05-25 E2E) had ~70kb of clean report and ~76kb of
    # citation chips + planning narration after a "Sources used in the
    # report" marker; selectors can't exclude that because it lives
    # inside the same panel DOM. Helper is idempotent.
    if md:
        md = _strip_gemini_panel_noise(md)
    # 2026-05-21: threshold raised 100 → 2000. The new UI's chat side
    # carries a ~200-char ack that would pass both _is_sources_not_
    # document and _looks_like_nav_sidebar — shipping it as the report
    # is the "stuck post-completion / wrong md" symptom. Real Deep
    # Research reports are >5000 chars; 2000 is a safe floor that
    # tolerates partial-render glitches while rejecting the ack shape.
    if md and len(md) > 2000:
        if _is_sources_not_document(md, platform="generic"):
            log(f"[{label}] T1 HTML→MD wrong-artifact — falling to Tier 2", "WARN")
        elif _looks_like_nav_sidebar(md):
            log(f"[{label}] T1 HTML→MD looks-like-nav-sidebar — falling to Tier 2", "WARN")
        else:
            log(f"[{label}] Extracted via T1 HTML→MD: {len(md)} chars")
            return md
    elif md:
        log(f"[{label}] T1 HTML→MD returned {len(md)} chars (below 2000-char threshold — "
            f"likely chat-side ack, not the report panel) — falling to Tier 2", "WARN")

    # ── Tier 2 (FALLBACK): CUA Share & Export → "Copy contents" + clipboard ──
    # The "Copy contents" action lives in the Share & Export dropdown on the
    # report PANEL's toolbar (top-right, same row as Contents / Create / X).
    # CUA opens it and clicks "Copy contents"; the report markdown lands on
    # the OS clipboard. We capture via (a) the in-page hijack, then (b)
    # navigator.clipboard.readText(), then (c) the OS clipboard (get_clipboard).
    # min_chars=2000 rejects a partial copy / chat ack. Kept as fallback for
    # the case where T1's panel selectors don't match the current UI revision.
    if browser and cua_client:
        async def _gemini_t2_trigger():
            await browser.switch_to_page(page)
            # Clear the clipboard first so a stale read (e.g. a prior copy)
            # can't masquerade as this run's "Copy contents". Best-effort —
            # if clipboard-write is denied, the post-copy read still gets the
            # fresh report (we just clicked Copy contents this iteration).
            try:
                await asyncio.wait_for(
                    page.evaluate("() => navigator.clipboard.writeText('')"),
                    timeout=2.0)
            except Exception:
                pass
            await asyncio.wait_for(
                agent_loop(cua_client, browser, PROMPT_GEMINI_COPY_CONTENTS,
                    "Click the Share & Export button in the response toolbar, "
                    "then click Copy contents in the dropdown menu.",
                    model=CUA_MODEL, max_iterations=8,
                    verbose=verbose, target_page=page),
                timeout=90.0)

        log(f"[{label}] T2: CUA Share & Export → Copy contents")
        try:
            md = await _run_with_clipboard_hijack(
                page, label, _gemini_t2_trigger,
                timeout_ms=120000, min_chars=2000,
            )
        except Exception as _e:
            log(f"[{label}] T2 clipboard hijack raised: {_e}", "WARN")
            md = ""
        # The hijack misses Gemini's async-Clipboard-API copy (see the
        # ARCHITECTURE note above) — so read the OS clipboard, where the
        # report markdown actually landed. readText() first (in-browser, 2s
        # cap for the permission-prompt hang), then PowerShell get_clipboard()
        # (3s cap for a locked clipboard). Longest wins.
        if not md or len(md) < 2000:
            _clip = ""
            try:
                _clip = await asyncio.wait_for(
                    page.evaluate("() => navigator.clipboard.readText()"),
                    timeout=2.0,
                ) or ""
            except (asyncio.TimeoutError, Exception):
                _clip = ""
            if not _clip or len(_clip) < 2000:
                try:
                    _os_clip = await asyncio.wait_for(
                        asyncio.to_thread(get_clipboard),
                        timeout=3.0,
                    )
                    if _os_clip and len(_os_clip) > len(_clip):
                        _clip = _os_clip
                except (asyncio.TimeoutError, Exception):
                    pass
            if _clip and len(_clip) >= 2000:
                md = _clip
                log(f"[{label}] T2 recovered {len(md)} chars from OS clipboard "
                    f"after Copy contents")
        if md and len(md) >= 2000:
            log(f"[{label}] Extracted via T2 CUA Share & Export + clipboard: {len(md)} chars")
            return md
        elif md:
            log(f"[{label}] T2 returned {len(md)} chars (below 2000-char threshold — "
                f"likely partial copy or chat ack) — falling to Tier 3", "WARN")

    # ── Tier 3 (LAST RESORT, Wayland-safe): Ctrl+A/C + clipboard hijack ──
    # JS clipboard hijack intercepts the browser's own copy event before
    # the OS clipboard is touched, so this works on Wayland, X11, Windows,
    # and macOS uniformly. No _IS_WAYLAND gate (that was the old OS-
    # clipboard path's limitation). First click the research panel to
    # ensure focus is on it (not the chat or composer); otherwise Ctrl+A
    # would select chat history or only the composer's input text.
    async def _gemini_t3_trigger():
        # Focus the research panel before select-all.
        # 2026-05-25: focus selectors tightened to side-panel ONLY —
        # prior list included `[class*="immersive" i]` (too greedy,
        # matches whole-app immersive wrapper) and chat selectors
        # `message-content`, `.model-response-text` (selecting these
        # makes Ctrl+A grab chat transcript, not the research). Now
        # restricted to explicit panel scopes; if none match, Ctrl+A
        # selects the page focus default (which is often the panel
        # after a completed run, but if not, we'll reject by threshold).
        try:
            await page.click(
                'immersive-panel, deep-research-panel, '
                'aside[class*="artifact" i], '
                'aside[class*="report" i], aside[class*="research" i], '
                '[role="complementary"][aria-label*="research" i], '
                '[role="region"][aria-label*="research" i]',
                timeout=2000)
        except Exception:
            # Best-effort — proceed even if click missed; the response
            # area is typically already focused after a completed turn.
            pass
        await asyncio.sleep(0.3)
        await page.keyboard.press("Control+a")
        await asyncio.sleep(0.5)
        await page.keyboard.press("Control+c")
        await asyncio.sleep(0.5)
        # 2026-05-24: clear the highlight after the copy event fires.
        # Without this, the full-page selection persists visually for
        # the user (observed on Claude where a Publish modal opens
        # shortly after — the highlighted text is visible behind the
        # modal). The hijack JS hook has already captured clipboardData
        # by this point, so removing the selection is safe.
        try:
            await page.evaluate(
                "() => { try { window.getSelection()?.removeAllRanges(); } catch (_) {} }"
            )
        except Exception:
            pass

    # 2026-05-25 min_chars raised 100 → 2000 to match T1/T2 floor.
    # Prior Kalki E2E captured 318 chars of chat fragments and saved
    # it; with the 2000 floor that path now rejects, agent flips to
    # status=failed (which is the correct outcome over "ship chat
    # as research").
    log(f"[{label}] Falling back to select-all + clipboard hijack (Tier 3)", "WARN")
    md = await _run_with_clipboard_hijack(
        page, label, _gemini_t3_trigger,
        timeout_ms=30000, min_chars=2000,
    )
    # 2026-05-25: same noise strip as T2 — select-all can grab the
    # panel chrome + sources tail too.
    if md:
        md = _strip_gemini_panel_noise(md)
    if md and len(md) >= 2000:
        # Apply same wrong-artifact filters as T2 — T3 has historically
        # been too permissive (raw select-all can grab anything).
        if _is_sources_not_document(md, platform="generic"):
            log(f"[{label}] T3 hijack wrong-artifact ({len(md)} chars) — rejecting", "WARN")
        elif _looks_like_nav_sidebar(md):
            log(f"[{label}] T3 hijack looks-like-nav-sidebar ({len(md)} chars) — rejecting", "WARN")
        else:
            log(f"[{label}] Extracted via select-all + clipboard hijack: {len(md)} chars")
            return md
    elif md:
        log(f"[{label}] T3 returned {len(md)} chars (below 2000-char threshold — "
            f"likely chat fragment, not research panel) — rejecting", "WARN")

    log(f"[{label}] All extraction tiers failed — returning empty", "ERROR")
    return ""


async def extract_claude_response(page, browser=None, cua_client=None, label="Claude", verbose=False,
                                   artifact_panel_open=False):
    """Extract Claude response — artifact-aware extraction.
    Claude Deep Research produces 2 artifacts: first = intermediate tracking
    (kept open during polling for live source streaming), second = final report.
    Targets the LAST artifact for extraction, with multiple fallback methods.

    artifact_panel_open: poll-loop signal that artifact 1's panel is currently
    open (commit d45807f keeps it open across polls via keep_open=True). When
    True we explicitly CLOSE artifact-1 first so the subsequent LAST-card click
    definitely opens a fresh panel onto artifact-2 (final report) — without
    this, relying on a panel-swap can race or no-op (artifact_count==1 case)
    and silently extract artifact-1's references instead of the final report.

    E2 / DGOPS-7364 — when the run is in user-acknowledged chat mode (Research
    setup couldn't be enabled and the operator chose Continue in chat mode),
    Claude returns a regular chat reply with NO research artifact. Skip the
    artifact-aware logic entirely and use the mode-agnostic DOM/JS extraction
    tail. _is_sources_not_document rejection also bypassed in chat mode (it
    expects the artifact shape that doesn't exist here)."""
    # E2 / DGOPS-7364 — read sticky chat-mode flag set by start_agent_no_gemini_wait.
    chat_mode = (getattr(_runtime, "agent_modes", {}) or {}).get("claude", {}).get("actual") == "chat"
    if chat_mode:
        log(f"[{label}] Running in CHAT MODE (user-acknowledged Research-unavailable) "
            f"— bypassing artifact-aware extraction, using DOM/JS tail only")
    # Clear clipboard first so stale brief text doesn't get returned
    clear_clipboard()
    await asyncio.sleep(2)
    await page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
    await asyncio.sleep(1)

    # ── Step 0 (BROADENED 2026-04-26 v3): probe DOM directly, not just flag ──
    # Polling sets artifact_panel_open=True, but if extract is reached via a
    # different path (Phase-2 timeout, hard-retry recovery, manual continue) the
    # flag may be stale or False while the panel IS still visually open. Directly
    # probe the DOM for any visible side artifact panel (>200px wide). Close it
    # if present — without this, the LAST-card click silently opens the wrong
    # artifact (the still-foregrounded artifact-1 / sources checklist).
    panel_visible_dom = False
    try:
        panel_visible_dom = await page.evaluate("""() => {
            const sels = [
                'aside',
                '[class*="artifact-panel" i]',
                '[class*="side-panel" i]',
                '[role="complementary"]'
            ];
            for (const s of sels) {
                for (const el of document.querySelectorAll(s)) {
                    const r = el.getBoundingClientRect();
                    if (r.width > 200 && r.height > 200) return true;
                }
            }
            return false;
        }""")
    except Exception:
        pass
    if panel_visible_dom or artifact_panel_open:
        log(f"[{label}] Closing artifact panel (visible_dom={panel_visible_dom}, "
            f"flag={artifact_panel_open}) before final extract")
        try:
            # Blur composer first so Escape isn't swallowed by textarea focus.
            try:
                await page.evaluate(
                    "document.activeElement && document.activeElement.blur && document.activeElement.blur()")
            except Exception:
                pass
            await _close_claude_artifact_panel(page)
            await asyncio.sleep(0.6)
        except Exception as _ce:
            log(f"[{label}] artifact-1 close before extract failed (continuing): {_ce}", "DEBUG")

    # ── Step 1: Count artifacts so we know which index = final report ──
    # 2026-04-26: scroll-to-bottom warmup forces lazy-load of latest turn —
    # without this, an early-rendered DOM may report artifact_count=1 when
    # artifact-2 (final report) is in the not-yet-mounted bottom portion →
    # target_idx=0 clicks artifact-1 (tracking checklist).
    try:
        for _ in range(2):
            await page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
            await asyncio.sleep(0.5)
    except Exception:
        pass
    # E2 / DGOPS-7364 — chat mode early return.
    # Claude in chat mode emits a regular assistant reply, NO artifact.
    # The artifact-aware Tiers 1-3 below (Research-mode path, line ~16877
    # onward — CUA download / publish + claude.site / CUA + clipboard
    # hijack) all target aside / artifact-panel / [class*="artifact"]
    # selectors that don't exist in chat mode, so they'd all return empty
    # and the function would falsely report "All extraction methods
    # failed". Instead, read the last assistant message via a tight
    # selector list scoped to chat-turn content.
    if chat_mode:
        # 2026-05-13 TIER SWAP (chat-mode branch): HTML→MD promoted to
        # Tier 1; Copy hijack demoted to Tier 2. Hijack-first never
        # succeeded in any prior log; HTML→MD is the proven path.
        #
        # Tier 1 (NEW PRIMARY): HTML→MD scoped to chat-turn content.
        try:
            md_chat = await _extract_html_to_md(page, [
                '[data-message-author-role="assistant"]:last-of-type .markdown',
                '[data-test-render-count] .font-claude-message:last-of-type',
                '.font-claude-message:last-of-type',
                'div[data-streamed]:last-of-type .markdown',
                'div[data-is-streaming="false"]:last-of-type .markdown',
            ], label)
            if md_chat and len(md_chat) > 100:
                if _looks_like_nav_sidebar(md_chat):
                    log(f"[{label}] chat-mode HTML→MD looks-like-nav-sidebar — falling to Tier 2", "WARN")
                else:
                    log(f"[{label}] Extracted via chat-mode HTML→MD: {len(md_chat)} chars")
                    return md_chat
        except Exception as _e:
            log(f"[{label}] chat-mode HTML→MD failed: {_e}", "WARN")

        # Tier 2 (FALLBACK): Copy hijack on the last assistant message Copy button.
        md_chat = await _copy_via_hijack(
            page, label,
            direct_copy_selectors=[
                '[data-message-author-role="assistant"]:last-of-type button[aria-label*="copy" i]:not([aria-label*="code" i]):not([aria-label*="link" i])',
                '.font-claude-message:last-of-type button[aria-label*="copy" i]',
                '[data-test-render-count]:last-of-type button[aria-label*="copy" i]',
            ],
            min_chars=100,
        )
        if md_chat and len(md_chat) >= 100:
            log(f"[{label}] Extracted via Copy hijack (chat-mode): {len(md_chat)} chars")
            return md_chat
        log(f"[{label}] Chat-mode extraction returned no readable content", "WARN")
        return ""
    # Research-mode path below (unchanged from pre-E2 — the artifact-aware ladder).
    artifact_count = await _count_claude_artifacts(page)
    log(f"[{label}] Post-completion: found {artifact_count} artifact(s)")

    # ── Step 2 — EXPLICITLY open the LAST artifact card (= final report) ──
    # The "LAST" artifact is the final research report. For 2-artifact runs this
    # is artifact-2 (after Step 0's close-1, panel is now closed → click opens
    # fresh onto artifact-2). For 1-artifact runs this is just the one artifact.
    if artifact_count > 0:
        target_idx = max(0, artifact_count - 1)  # Last artifact = final report
        log(f"[{label}] Post-completion: opening artifact[{target_idx}] (final report)")
        clicked = await _click_claude_artifact(page, index=target_idx)
        # 2026-05-14: when the DOM pre-click can't resolve a real artifact
        # button (Claude's `[data-testid*="artifact"]` selector can match
        # research-tracking cards, context-menu triggers, etc.), fall back
        # to CUA to open the LAST artifact card before running the tiers.
        # Without this fallback the entire tier ladder used to skip
        # silently — see 2026-05-13 run where T1/T2/T3 all returned in the
        # same second as the count log because every tier was nested
        # inside `if clicked:`. T1 and T2 require the artifact panel open
        # (Copy/down-arrow trio for T1, Publish button for T2); T3 has its
        # own navigate preamble so it can recover even when this CUA
        # fallback also misses.
        if not clicked and browser and cua_client and not chat_mode:
            log(f"[{label}] DOM pre-click missed — CUA fallback to open last artifact", "WARN")
            try:
                await asyncio.wait_for(
                    agent_loop(cua_client, browser,
                        PROMPT_NAVIGATE_CLAUDE_FINAL_ARTIFACT,
                        f"There are {artifact_count} artifact(s) in this "
                        f"conversation. Open the LAST (bottom) artifact card "
                        f"— that's the final research report.",
                        model=CUA_MODEL, max_iterations=8,
                        verbose=verbose, target_page=page),
                    timeout=120.0)
                clicked = True
                await asyncio.sleep(1.5)
            except asyncio.TimeoutError:
                log(f"[{label}] CUA fallback open timed out after 120s", "WARN")
            except Exception as _fe:
                log(f"[{label}] CUA fallback open raised: {_fe}", "WARN")

        # A1 (2026-05-01): content-driven wait — yields fast on a
        # normal mount, gives slow renders up to 8s before falling
        # through to CUA. Forgiving — if panel never mounts, T3's own
        # navigate preamble still has a shot.
        try:
            await page.wait_for_selector(
                'aside [class*="markdown"], aside .prose, '
                '[class*="artifact-panel"] [class*="markdown"], '
                '[class*="artifact-panel"] .prose',
                timeout=8000)
        except Exception:
            await asyncio.sleep(1.5)

        # 2026-05-13 ARCHITECTURE: collapsed from 4-tier ladder (panel-
        # reader + publish + html-md + copy-hijack + CUA-OS-clipboard)
        # into exactly 3 Wayland-safe tiers per user sign-off. Removes
        # the _IS_WAYLAND gate (Tier 3 now uses a JS clipboard hijack
        # that works on every backend) and removes the OS-clipboard
        # `get_clipboard()` read entirely.
        # 2026-05-14: tiers de-indented out of the prior `if clicked:`
        # gate so a missed pre-click doesn't silently skip everything.

        # ── Tier 1 (CUA-driven download): Download as Markdown ──
        # CUA finds the small down-arrow button next to the Copy button
        # in the artifact-panel header (Copy/▼/Published trio per user
        # screenshot), clicks it, then clicks "Download as Markdown".
        # Playwright expect_download() captures the .md file. Selector-
        # free; CUA's vision handles DOM drift. Wayland-safe.
        if browser and cua_client:
            md_dl = await _extract_via_cua_download(
                page, browser, cua_client, label,
                PROMPT_CLAUDE_DOWNLOAD_MD,
                "The artifact panel should be open on the right showing the "
                "final research report. If it isn't open yet, click the LAST "
                "artifact card in the chat to open it first. Then click the "
                "small down-arrow button next to the Copy button, and click "
                "Download as Markdown.",
                max_iterations=12, cua_timeout_s=150.0,
                # See ChatGPT T1 note above: download_timeout_ms must
                # exceed cua_timeout_s so the listener stays alive past
                # the final click. cua_timeout_s + 15s grace.
                download_timeout_ms=165000, min_chars=500, verbose=verbose,
            )
            if md_dl and len(md_dl) >= 500:
                if _is_sources_not_document(md_dl, platform="claude"):
                    log(f"[{label}] T1 CUA download wrong-artifact "
                        f"({len(md_dl)} chars) — falling to Tier 2", "WARN")
                    try:
                        emit_event("wrong_artifact_rejected", phase=2, agent="claude",
                                   op="finalize_copy", length=len(md_dl),
                                   tier="cua_download_md")
                    except Exception:
                        pass
                else:
                    log(f"[{label}] Extracted via T1 CUA download (.md): {len(md_dl)} chars")
                    return md_dl

        # ── Tier 2: publish + claude.site full-page HTML→MD ──
        # Publish artifact + open the resulting claude.site URL in a
        # new tab + HTML→MD scrape on the clean DOM. Zero chat/nav/
        # iframe chrome. New tab keeps main-page state intact.
        # Idempotent across calls.
        md_pub = await _extract_claude_via_published_page(
            page, browser, cua_client, label, verbose=verbose,
        )
        if md_pub and len(md_pub) > 500:
            if _is_sources_not_document(md_pub, platform="claude"):
                log(f"[{label}] T2 published-page wrong-artifact "
                    f"({len(md_pub)} chars) — falling to Tier 3", "WARN")
            elif _looks_like_nav_sidebar(md_pub):
                log(f"[{label}] T2 published-page looks-like-nav-sidebar "
                    f"({len(md_pub)} chars) — falling to Tier 3", "WARN")
            else:
                log(f"[{label}] Extracted via T2 published-page HTML→MD: {len(md_pub)} chars")
                return md_pub
        # If T2 fired but didn't return content, the publish-confirm
        # dialog may still be mounted on the main page. Dismiss with
        # Escape so dialog content doesn't bleed into T3 state.
        try:
            await page.keyboard.press("Escape")
            await asyncio.sleep(0.4)
        except Exception:
            pass

        # ── Tier 3 (LAST RESORT, Wayland-safe): CUA + clipboard hijack ──
        # _run_with_clipboard_hijack installs the JS hook before CUA's
        # Ctrl+A/C so the page's own copy event is intercepted in-DOM.
        # No OS clipboard read → Wayland-safe. Trigger chains the
        # existing two CUA prompts: navigate to LAST artifact (if
        # multiple), then Ctrl+A/C inside the open panel. No retry
        # loop, no shadow-wrap, no _IS_WAYLAND gate — helper owns
        # retry policy. Helper timeout_ms set ABOVE the inner CUA
        # wait_for budget so the inner caps fire first.
        if browser and cua_client and not chat_mode:
            async def _claude_t3_trigger():
                await browser.switch_to_page(page)
                if artifact_count >= 2:
                    try:
                        await asyncio.wait_for(
                            agent_loop(cua_client, browser,
                                PROMPT_NAVIGATE_CLAUDE_FINAL_ARTIFACT,
                                f"There are {artifact_count} artifacts in this "
                                f"conversation. Open the LAST (bottom) artifact — "
                                f"that's the final research report.",
                                model=CUA_MODEL, max_iterations=8,
                                verbose=verbose, target_page=page),
                            timeout=180.0)
                        await asyncio.sleep(1)
                    except asyncio.TimeoutError:
                        log(f"[{label}] T3 CUA nav timed out after 180s", "WARN")
                    except Exception as _ne:
                        log(f"[{label}] T3 CUA nav raised: {_ne}", "WARN")
                await asyncio.wait_for(
                    agent_loop(cua_client, browser, PROMPT_COPY_ARTIFACT_CLAUDE,
                        "Copy the full content of the artifact currently open "
                        "in the right panel to clipboard.",
                        model=CUA_MODEL, max_iterations=12,
                        verbose=verbose, target_page=page),
                    timeout=180.0)
                await asyncio.sleep(1)
                # 2026-05-24: clear the selection the CUA's Ctrl+A
                # left behind. Without this, the artifact text stays
                # visibly highlighted while the subsequent
                # publish_open_claude_artifact flow opens the Publish
                # modal — the user sees the blue highlight bleeding
                # behind the modal. Hijack JS hook has already
                # captured clipboardData (sleep 1 above), so removing
                # the selection is safe.
                try:
                    await page.evaluate(
                        "() => { try { window.getSelection()?.removeAllRanges(); } catch (_) {} }"
                    )
                except Exception:
                    pass

            log(f"[{label}] CUA: Tier 3 navigate + copy with clipboard hijack")
            try:
                md_hj = await _run_with_clipboard_hijack(
                    page, label, _claude_t3_trigger,
                    timeout_ms=400000, min_chars=500,
                )
            except Exception as _te:
                log(f"[{label}] T3 clipboard-hijack raised: {_te}", "WARN")
                md_hj = ""
            if md_hj and len(md_hj) >= 500:
                if _is_sources_not_document(md_hj, platform="claude"):
                    log(f"[{label}] T3 hijack wrong-artifact "
                        f"({len(md_hj)} chars) — rejecting", "WARN")
                    try:
                        emit_event("wrong_artifact_rejected", phase=2, agent="claude",
                                   op="finalize_copy", length=len(md_hj),
                                   tier="clipboard_hijack")
                    except Exception:
                        pass
                else:
                    log(f"[{label}] Extracted via T3 clipboard hijack: {len(md_hj)} chars")
                    return md_hj

    try:
        emit_event("extract_failed", phase=2, agent="claude",
                   op="finalize_copy",
                   reason="all_methods_returned_empty_or_wrong_artifact")
    except Exception:
        pass
    log(f"[{label}] All extraction methods failed", "WARN")
    return ""


async def publish_open_claude_artifact(page, browser, cua_client, verbose=False):
    """Publish the currently-open Claude artifact and return its public URL.
    Call this AFTER extract_claude_response while the artifact panel is still open."""
    try:
        # A1 (2026-05-01): wait up to 12s for the publish/share button to
        # mount before falling through to JS evaluate. Without this, the
        # JS query at first call returned empty when the panel was still
        # animating, immediately escalating to CUA — slow and brittle.
        try:
            await page.wait_for_selector(
                'aside button[aria-label*="Publish"], '
                'aside button[aria-label*="Share"], '
                '[class*="artifact"] button[aria-label*="Publish"], '
                '[class*="artifact"] button[aria-label*="Share"], '
                'button[data-testid="publish-artifact"]',
                timeout=12000)
        except Exception:
            log("[Claude] Publish/Share button never mounted within 12s — "
                "falling through to JS query (may still find icon-only variant)",
                "WARN")
        # Try DOM-first: click publish button on the artifact panel
        clicked = await page.evaluate("""() => {
            // Multiple selector strategies for the publish/share button
            const selectors = [
                'aside button[aria-label*="Publish"]',
                'aside button[aria-label*="Share"]',
                '[class*="artifact"] button[aria-label*="Publish"]',
                '[class*="artifact"] button[aria-label*="Share"]',
                'button[data-testid="publish-artifact"]',
                // Icon-based: globe or share icons in the artifact panel
                'aside button svg[class*="globe"]',
                'aside button svg[class*="share"]',
            ];
            for (const sel of selectors) {
                const el = document.querySelector(sel);
                if (el) {
                    const btn = el.closest('button') || el;
                    btn.click();
                    return 'clicked';
                }
            }
            return '';
        }""")
        if clicked == 'clicked':
            await asyncio.sleep(2)
            # Check if there's a "Publish" confirmation button in the dialog
            await page.evaluate("""() => {
                // Some versions show a confirmation dialog — click Publish/Confirm
                const btns = document.querySelectorAll('button, [role="button"]');
                for (const btn of btns) {
                    const txt = (btn.innerText || btn.textContent || '').toLowerCase().trim();
                    if (txt === 'publish' || txt === 'create public link' || txt === 'confirm') {
                        btn.click();
                        return 'confirmed';
                    }
                }
                return '';
            }""")
            await asyncio.sleep(2)
            # Look for the URL in the dialog (try multiple times — UI may be animating)
            for _attempt in range(3):
                url = await page.evaluate("""() => {
                    // Check for direct links
                    const links = document.querySelectorAll(
                        'a[href*="claude.site/artifacts"], input[value*="claude.site"]'
                    );
                    for (const el of links) {
                        const href = el.href || el.value || '';
                        if (href.includes('claude.site')) return href;
                    }
                    // Check visible text for claude.site URL
                    const text = document.body.innerText;
                    const m = text.match(/https:\\/\\/claude\\.site\\/artifacts\\/[a-f0-9-]+/);
                    if (m) return m[0];
                    return '';
                }""")
                if url and url.startswith('http') and 'claude.site' in url:
                    log(f"[Claude] Published artifact via DOM: {url}")
                    return url
                # Try clicking "Copy link" button
                copy_result = await page.evaluate("""() => {
                    const btns = document.querySelectorAll('button');
                    for (const b of btns) {
                        const txt = (b.innerText || '').toLowerCase();
                        if (txt.includes('copy link') || txt.includes('copy url')) {
                            b.click();
                            return 'copied';
                        }
                    }
                    return '';
                }""")
                if copy_result == 'copied':
                    await asyncio.sleep(0.5)
                    clip = get_clipboard()
                    if clip and 'claude.site' in clip:
                        log(f"[Claude] Published artifact via clipboard: {clip}")
                        return clip
                await asyncio.sleep(1)
    except Exception as e:
        log(f"[Claude] DOM publish attempt failed: {e}", "WARN")

    # CUA fallback for publishing
    if cua_client:
        result = await agent_loop(cua_client, browser,
            PROMPT_PUBLISH_CLAUDE_ARTIFACT,
            "Publish the artifact that's currently open in the right panel. "
            "Click the Publish/Share button, then confirm publishing. "
            "Get the public URL (claude.site/artifacts/...). Tell me the EXACT URL.",
            model=CUA_MODEL, max_iterations=10, verbose=verbose)
        text = result.get("text", "")
        m = re.search(r'https://claude\.site/artifacts/[a-f0-9-]+', text)
        if not m:
            m = re.search(r'https://claude\.(?:site|ai)/[^\s]+', text)
        if m:
            return m.group(0)
        clip = get_clipboard()
        if clip and 'claude.site' in clip:
            return clip

    return ""


# ── Phase 1: Research Brief Generation ───────────────────────────────────────

async def run_phase1(browser, cua_client, topic, pdf_paths, verbose=False, feedback="", _retry_count=0):
    """Phase 1: ChatGPT Pro + Extended Thinking → research brief.

    _retry_count: internal counter bounded to P1_MAX_USER_RETRIES. Incremented
    when the brief-short branch restarts Phase 1 at the user's request. Caps
    total attempts to avoid infinite loops."""
    log("=" * 60)
    log("PHASE 1: Research Brief Generation (ChatGPT Pro + Extended Thinking)")
    log("=" * 60)

    # Navigate to ChatGPT
    emit_event("agent_progress", phase=1, agent="chatgpt",
               status="starting",
               progress="Opening ChatGPT…")
    await browser.navigate("https://chatgpt.com")
    await asyncio.sleep(3)

    # Inject MutationObserver early — right after navigate, before HV check.
    # The scrape selector (`[data-message-author-role="assistant"]`) doesn't
    # exist on HV/login pages, so early-inject produces no false positives
    # and captures any brief streaming that starts before `verify-generating`
    # closes. `inject_agent_observer` is idempotent on re-call.
    try:
        await inject_agent_observer(browser.page, "chatgpt")
    except Exception:
        pass

    # Early HV check — if Cloudflare Turnstile / CAPTCHA is gating ChatGPT,
    # resolve it BEFORE running Pro-model selection. Those CUA calls can't
    # succeed on a blocked page and will burn workspace quota for nothing.
    # On clear-failure, return None so the pipeline runner emits
    # pipeline_error + pipeline_stopped via fail_phase(...) downstream.
    if cua_client:
        emit_event("agent_progress", phase=1, agent="chatgpt",
                   status="verifying",
                   progress="Checking for CAPTCHA / human-verification gate…")
        cleared = await check_hv_gate(browser, cua_client, "chatgpt", "ChatGPT",
                                       phase=1, verbose=verbose)
        if not cleared:
            log("Phase 1: HV gate could not be cleared — aborting phase", "ERROR")
            return None

    # Select Pro model via CUA. Hard 180s ceiling — max_iterations=15 is
    # generous enough that a stuck CUA could loiter for many minutes
    # without this wait_for. If timed out, log + assume Pro is unavailable
    # so the rest of Phase 1 falls through gracefully (the pipeline still
    # gets an Extended Thinking attempt without the Pro model upgrade).
    if cua_client:
        # DGOPS-7363 retry-aware Pro selection. Wrapped in a while-True so the
        # backstop alert's Retry button can re-run PROMPT_SELECT_PRO inline
        # after the user signs in with a Pro account. Exits the loop on:
        #  • Pro selected (no "no pro" in output) → break to PDFs
        #  • Stop pressed during the alert → return None
        #  • Continue with Free / generic resume → ack flag set, break
        #  • pro_warning_acknowledged already set on entry → break
        while True:
            log("Selecting Pro + Extended Thinking...")
            emit_event("agent_progress", phase=1, agent="chatgpt",
                       status="selecting_model",
                       progress="Selecting ChatGPT Pro with Extended Thinking…")
            try:
                result = await asyncio.wait_for(
                    agent_loop(cua_client, browser, PROMPT_SELECT_PRO,
                        "Select ChatGPT Pro model with Extended Thinking. Say 'no pro available' if not found.",
                        model=CUA_MODEL, max_iterations=15, verbose=verbose),
                    timeout=180.0,
                )
            except asyncio.TimeoutError:
                log("Phase 1: Pro+Extended Thinking selection timed out (180s) — proceeding without explicit Pro upgrade", "WARN")
                result = {"text": "no pro available (cua_timeout)"}
            last = (result.get("text") or "").lower()
            if not ("no pro" in last or "not available" in last):
                break  # Pro selected — exit the retry loop
            # Backstop: Phase 0 normally catches Pro-Free downgrade and pauses
            # for the alert. This branch fires only when:
            #  • skipInitVerify=true (Phase 0 was bypassed entirely), OR
            #  • Pro was revoked between Phase 0 verify and Phase 1 active
            #    (rare — usually means the subscription expired mid-day).
            if _controls.pro_warning_acknowledged:
                log("Phase 1: Pro unavailable — user opted into Free at Phase 0 (continuing)", "INFO")
                break
            # Log the exact CUA verdict that triggered the escalation so a
            # post-E2E review can tell a TRANSIENT detection miss (e.g.
            # "no pro available (cua_timeout)", selector not yet rendered) from a
            # genuine no-Pro subscription. The former is the Tier-1 silent-retry
            # candidate (#705 item 5); the latter is a correct Tier-2 escalation.
            log(f"Phase 1: Pro mode not available (cua verdict: {last[:120]!r}) — Phase 0 was skipped or Pro was revoked; surfacing alert", "WARN")
            _emit_pro_required_alert(phase=1, agent="chatgpt", source="phase1/setup_pro_backstop")
            _controls.request_pause("pro_required")
            emit_event("pipeline_paused", phase=1, reason="pro_required")
            await _controls.wait_if_paused()
            if _controls.is_stop():
                emit_event("pipeline_stopped", phase=1, reason="user_stop_pro_required")
                return None
            if _controls.consume_retry_phase(1):
                # User clicked Retry — re-run PROMPT_SELECT_PRO. Likely the
                # user signed into a Pro account in the open browser; the
                # next iteration will detect Pro and break.
                log("Phase 1: user clicked Retry on pro_required — re-running Pro selector", "INFO")
                emit_event("pipeline_resumed", phase=1, reason="pro_retry")
                continue
            # continue_anyway / generic resume → ack and proceed on Free.
            chose_free = _controls.consume_continue_anyway()
            _controls.pro_warning_acknowledged = True
            log("Phase 1: user opted into Free — proceeding with Free-tier brief", "INFO")
            # F3: clear stale pro_required alert documents from FE store BEFORE
            # the resumed event fires (resumed is what triggers the auto-clear
            # sweep on the FE). Order: flag → clear emit → resumed emit.
            _clear_pro_required_alerts(triggered_at_phase=1)
            emit_event("pipeline_resumed", phase=1,
                       reason="continue_with_free" if chose_free else "resume")
            break

    # Attach PDFs
    _pdf_total = len(pdf_paths) if pdf_paths else 0
    for _pdf_idx, pdf in enumerate(pdf_paths, 1):
        _pdf_name = Path(pdf).name
        log(f"Attaching PDF: {_pdf_name}")
        _pdf_progress = (f"Attaching {_pdf_name} ({_pdf_idx}/{_pdf_total})…"
                         if _pdf_total > 1 else f"Attaching {_pdf_name}…")
        emit_event("agent_progress", phase=1, agent="chatgpt",
                   status="attaching_pdf",
                   progress=_pdf_progress)
        attached = await attach_pdf_chatgpt(browser, pdf)
        if not attached and cua_client:
            log("Trying CUA for PDF attachment...")
            browser.set_upload_file(str(pdf))
            await agent_loop(cua_client, browser, PROMPT_ATTACH_PDF,
                f"Attach the file. The file dialog will auto-select it — just click the attachment button.",
                model=CUA_MODEL, max_iterations=10, verbose=verbose)
            browser.clear_upload_file()

    # Build and submit the brief prompt
    prompt = (
        f'Please create a detailed research report brief for a deep research LLM agent '
        f'that covers this topic: {topic}. Be as thorough as you can. Simply output the '
        f'research brief, no preamble or post-amble. I just need something I can copy and '
        f'paste into a research agent LLM.'
    )
    if feedback:
        prompt += f'\n\nUSER FEEDBACK (incorporate this): {feedback}'
        log(f"Phase 1: Injecting user feedback: {feedback[:100]}")
    emit_event("agent_progress", phase=1, agent="chatgpt",
               status="submitting",
               progress="Submitting the research-brief prompt…")
    submitted = await submit_chatgpt_direct(browser, prompt)
    if not submitted and cua_client:
        log("Falling back to CUA for submit...")
        await agent_loop(cua_client, browser, PROMPT_SUBMIT_FALLBACK,
            f"Submit this prompt to ChatGPT:\n\n{prompt}",
            model=CUA_MODEL, max_iterations=15, verbose=verbose)

    # VERIFY: confirm ChatGPT is generating
    emit_event("agent_progress", phase=1, agent="chatgpt",
               status="verifying_generation",
               progress="Waiting for ChatGPT Pro + Thinking to start generating…")
    verified = await wait_until_verified(verify_chatgpt_generating, browser.page, "Phase1",
        browser=browser, cua_client=cua_client, max_retries=15, interval=3, verbose=verbose)
    if not verified:
        log("Phase 1: Could not verify ChatGPT is generating", "ERROR")
        # No alert: orchestrator's outer retry loop handles re-attempts; if
        # it exhausts retries, fail_phase fires upstream.
        return None

    # Register brief page with dispatcher for mid-run user input.
    # MutationObserver was already injected earlier (right after navigate) so
    # the observer has been capturing token-level stream during verify.
    _runtime.phase = 1
    _runtime.sub_state = "1_brief_generating"
    _runtime.register_page("chatgpt", browser.page, browser.page.url)

    # Wait for response. 2026-05-06 (Stream 2 D2/D3): no inner wall-clock
    # cap — the outer _await_phase_with_active_deadline(1, PHASE_1_MAX_MIN,
    # soft_warn_only=True) is the sole P1 ceiling. Multi-signal stall
    # detector inside poll_until_done raises _BriefStreamStalled if
    # ChatGPT freezes mid-stream (text + sources + steps flat for 20m).
    log(f"Polling for response (every {POLL_PRO}s)...")
    try:
        completed = await poll_until_done(browser.page, verify_chatgpt_generating, "Phase1", POLL_PRO, MAX_WAIT_PRO,
            browser=browser, cua_client=cua_client, verbose=verbose, phase=1)
    except _BriefStreamStalled as _bs:
        log(f"Phase 1: brief stream stalled — {_bs}", "WARN")
        _runtime.unregister_page("chatgpt", final_status="stalled")
        retries_left_p1s = max(0, 2 - _retry_count)
        fail_phase(1,
                   "ChatGPT stream stalled — text + sources flat for 20 min",
                   "ChatGPT stopped streaming output mid-brief. Retry restarts the brief from scratch; Skip drops Phase 1 and asks for a manual brief.",
                   agent="chatgpt",
                   can_retry=retries_left_p1s > 0)
        if retries_left_p1s > 0:
            p1s_decision = await _controls.await_phase_decision(1)
            log(f"Phase 1 stall decision: {p1s_decision}")
            if p1s_decision == "stop":
                return None
            if p1s_decision == "retry":
                try:
                    emit_event("phase_restart", phase=1,
                               reason="user_retry_brief_stall",
                               attempt=_retry_count + 2)
                except Exception:
                    pass
                return await run_phase1(browser, cua_client, topic, pdf_paths,
                                        verbose=verbose, feedback=feedback,
                                        _retry_count=_retry_count + 1)
            # skip → fall through and extract whatever streamed
        completed = False
    # Unregister once brief is done (also covers stall-skip fall-through;
    # idempotent — safe to call even if already unregistered above).
    _runtime.unregister_page("chatgpt", final_status="done" if completed else "stalled-skipped")

    # ── Mid-Phase-1 injection: if user sent context while brief was generating,
    #    submit it as a follow-up to ChatGPT and wait for the updated brief ──
    # Only pop the buffer if we're going to use it — otherwise leave it for
    # Phase 2 / NotebookLM to consume (pop is destructive, so peek first).
    extra_ctx = None
    if completed and _controls.peek_extra_context():
        extra_ctx = _controls.pop_extra_context()
    if extra_ctx and completed:
        log(f"Phase 1: Injecting user context as follow-up ({len(extra_ctx)} chars)")
        emit_event("agent_progress", phase=1, agent="chatgpt",
                   status="refining", progress=f"Incorporating user input: {extra_ctx[:80]}...")
        followup = (
            f"Please update and improve the research brief above to also incorporate "
            f"the following additional context from the user:\n\n{extra_ctx}\n\n"
            f"Output the complete updated research brief. No preamble."
        )
        submitted_fu = await submit_chatgpt_direct(browser, followup)
        if not submitted_fu and cua_client:
            await agent_loop(cua_client, browser, PROMPT_SUBMIT_FALLBACK,
                f"Submit this follow-up prompt to ChatGPT:\n\n{followup[:500]}",
                model=CUA_MODEL, max_iterations=10, verbose=verbose)
        # Wait for the updated response
        await asyncio.sleep(5)
        verified_fu = await wait_until_verified(verify_chatgpt_generating, browser.page, "Phase1-followup",
            browser=browser, cua_client=cua_client, max_retries=10, interval=3, verbose=verbose)
        if verified_fu:
            log("Phase 1: Waiting for updated brief...")
            try:
                await poll_until_done(browser.page, verify_chatgpt_generating, "Phase1-followup",
                    POLL_PRO, 15,  # 15 min max — dead arg post-D2; kept for signature stability
                    browser=browser, cua_client=cua_client, verbose=verbose, phase=1)
            except _BriefStreamStalled as _bs_fu:
                log(f"Phase 1 followup stalled — using pre-followup brief: {_bs_fu}", "WARN")
        else:
            log("Phase 1: Follow-up may not have triggered generation — using original brief", "WARN")

    # Extract
    brief_text = await extract_chatgpt_response(browser.page)
    chat_url = await browser.current_url()

    brief_len = len(brief_text or "")
    # Brief-short guard: DR briefs are typically 2-5k chars. Under 500 while
    # we were expecting >1000 usually means ChatGPT errored or the extractor
    # grabbed the wrong element. Warn (not error) so the frontend can offer
    # [continue_anyway] / [retry] — the caller polls consume_continue_anyway()
    # to decide whether to accept the short brief.
    P1_MAX_USER_RETRIES = 2  # total attempts = 1 + P1_MAX_USER_RETRIES
    if brief_text and brief_len >= 100 and brief_len < 500:
        retries_left = max(0, P1_MAX_USER_RETRIES - _retry_count)
        fail_phase(1,
                   f"Brief looks short ({brief_len} chars) — expected >1000",
                   "ChatGPT returned a brief well below typical length. Retry regenerates from scratch.",
                   agent="chatgpt",
                   can_retry=retries_left > 0)
        # Wait for the user's decision via the standard phase-decision bus.
        if retries_left > 0:
            decision = await _controls.await_phase_decision(1)
            log(f"Phase 1 brief-short decision: {decision}")
            if decision == "stop":
                return None
            if decision == "retry":
                try:
                    emit_event("phase_restart", phase=1,
                               reason="user_retry_brief_short",
                               attempt=_retry_count + 2,
                               chars=brief_len)
                except Exception:
                    pass
                log(f"Phase 1: User requested retry (attempt {_retry_count + 2}/{P1_MAX_USER_RETRIES + 1})")
                return await run_phase1(browser, cua_client, topic, pdf_paths,
                                        verbose=verbose, feedback=feedback,
                                        _retry_count=_retry_count + 1)
            # 'continue_anyway' or 'timeout' → fall through and return short brief

    if brief_text and brief_len > 100:
        log(f"Brief extracted: {brief_len} chars")
        return {"text": brief_text, "url": chat_url}
    else:
        log(f"Brief too short ({brief_len} chars)", "WARN")
        return {"text": brief_text or "", "url": chat_url}


# ── Phase 2: Parallel Deep Research (Sequential Start + Verify) ──────────────

# ── Playwright-direct platform setup (replaces vision-based CUA setup) ────────

async def setup_chatgpt_dr(page) -> bool:
    """Enable ChatGPT Deep Research mode via direct selectors. Returns True on success.

    Step-by-step logs emit on every branch so next run's log tells us
    exactly which step broke — previously this was one-line "setup failed"
    with no detail, leaving us guessing whether the + menu opened, whether
    the DR option was found, or whether verification landed.
    """
    try:
        await asyncio.sleep(2)
        # Step 1: open the + / tools menu in the composer
        menu_sel = None
        for sel in ['button[aria-label*="Use a tool"]',
                    'button[aria-label*="Attach"]',
                    'button[data-testid="composer-plus-btn"]',
                    'button[aria-label*="More"]']:
            try:
                btn = await page.query_selector(sel)
                if btn:
                    await btn.click()
                    await asyncio.sleep(0.8)
                    menu_sel = sel
                    break
            except Exception:
                continue
        if not menu_sel:
            log("[setup_chatgpt_dr] Step 1 FAIL: tools/+ menu button not found — selectors may have rotated", "WARN")
            return False
        log(f"[setup_chatgpt_dr] Step 1 OK: opened tools menu via {menu_sel}")

        # Step 2: click "Deep research" option in the menu.
        # 2026-05-29 (#709): the DOM Step 2 FAILed 100% of last E2E on every
        # worker — the run only succeeded when the non-deterministic CUA
        # fallback happened to recover it. ROOT CAUSE (user-captured live "+"
        # dump): "Deep research" is a **role="menuitemradio"** with exact text
        # "Deep research" and EMPTY aria-label + EMPTY data-testid — but the
        # prior selector set was '[role="menuitem"], button, div[role="option"]'
        # which OMITTED role="menuitemradio", so the item was never even a
        # candidate. The text/`===` matching was fine; the element-role filter
        # excluded it. (Siblings "Create image"/"Web search" are also radios,
        # so we match EXACTLY "deep research", never a contains.) DR is
        # top-level in "+" — no "More" submenu. role+text is the only signal
        # (aria/testid empty), so that's what we pin; aria-label + starts-with
        # are kept as defensive fallbacks for a future relabel/icon-prefix.
        _dr_click_js = """() => {
            const norm = s => (s || '').replace(/\\s+/g, ' ').trim().toLowerCase();
            const items = document.querySelectorAll(
                '[role="menuitemradio"], [role="menuitem"], [role="option"], button, a, li');
            // Pass 1 — the real, current shape: exact "deep research".
            for (const el of items) {
                if (!el.offsetParent) continue;
                if (norm(el.textContent) === 'deep research' ||
                    norm(el.getAttribute('aria-label')) === 'deep research') {
                    el.click(); return true;
                }
            }
            // Pass 2 — defensive: starts-with / contains for a future icon-
            // prefixed or relabeled variant ("travel_exploreDeep research").
            for (const el of items) {
                if (!el.offsetParent) continue;
                const t = norm(el.textContent);
                const a = norm(el.getAttribute('aria-label'));
                if (t.startsWith('deep research') || t.includes('deep research') ||
                    a.startsWith('deep research')) {
                    el.click(); return true;
                }
            }
            return false;
        }"""
        clicked = await page.evaluate(_dr_click_js)
        if not clicked:
            # One-shot diagnostic dump (mirrors #708 Step 3A) so the NEXT E2E
            # pins the exact menu-item structure instead of us guessing the
            # selector. Grep backend.log for "Step 2 menu-item dump".
            try:
                dump = await page.evaluate("""() => {
                    const out = [];
                    for (const el of document.querySelectorAll(
                            '[role="menuitem"], [role="menuitemradio"], [role="option"], button, a, li')) {
                        if (!el.offsetParent) continue;
                        const t = (el.textContent || '').replace(/\\s+/g, ' ').trim();
                        const a = el.getAttribute('aria-label') || '';
                        if (!t && !a) continue;
                        out.push({ role: el.getAttribute('role') || el.tagName.toLowerCase(),
                                   text: t.slice(0, 60), aria: a.slice(0, 60),
                                   testid: el.getAttribute('data-testid') || '' });
                    }
                    return out.slice(0, 30);
                }""")
                log("[setup_chatgpt_dr] Step 2 menu-item dump: " + json.dumps(dump))
            except Exception as _de:
                log(f"[setup_chatgpt_dr] Step 2 dump failed: {_de}", "WARN")
            log("[setup_chatgpt_dr] Step 2 FAIL: 'Deep research' menu item not found — menu opened but option missing", "WARN")
            return False
        log("[setup_chatgpt_dr] Step 2 OK: clicked Deep research menu option")
        await asyncio.sleep(1.5)

        # Step 3: verify DR actually activated — look for the DR pill in the
        # composer area (not anywhere in body text, which was the previous
        # false-positive-prone check that matched tooltips and help labels).
        active = await page.evaluate("""() => {
            const composer = document.querySelector('form') || document.body;
            // Prefer a visible pill/chip inside the composer
            const chips = [...composer.querySelectorAll('button, [role="button"], span, div')];
            for (const el of chips) {
                if (!el.offsetParent) continue;
                const t = (el.textContent || '').trim().toLowerCase();
                if (t === 'deep research' || t === 'deep research off') {
                    // Composer-level visible pill is the active-mode indicator
                    return { ok: true, via: 'pill', text: el.textContent.trim().slice(0, 40) };
                }
            }
            // Secondary signal: composer placeholder changes for DR mode
            const ta = document.querySelector('#prompt-textarea, textarea, [contenteditable="true"]');
            if (ta) {
                const placeholder = (ta.getAttribute('placeholder') || ta.getAttribute('data-placeholder') || '').toLowerCase();
                if (placeholder.includes('research')) {
                    return { ok: true, via: 'placeholder', text: placeholder.slice(0, 60) };
                }
            }
            return { ok: false };
        }""")
        if not active or not active.get("ok"):
            log("[setup_chatgpt_dr] Step 3 FAIL: clicked DR but no pill/placeholder change visible after 1.5s — click may have been intercepted", "WARN")
            return False
        log(f"[setup_chatgpt_dr] Step 3 OK: verified DR active via {active.get('via')} → {active.get('text')}")
        return True
    except Exception as e:
        log(f"[setup_chatgpt_dr] exception: {e}", "WARN")
        return False


async def _gemini_select_flash_model(page) -> bool:
    """Pre-DR step: open the model dropdown and select 3.5 Flash.

    Why this matters: the pipeline runs Gemini Deep Research on 3.5 Flash
    (user-validated 2026-05-26 — Flash completes cleanly and its done-state
    becomes detectable after the periodic refresh, whereas 3.1 Pro DR ran
    1-2h and needed manual "is it done?" nudges to unstick). If the composer
    is left on whatever the dropdown defaults to, the DR job can run on the
    wrong model — so we explicitly pick 3.5 Flash before enabling DR.

    Approach: open the model button (data-test-id="bard-mode-menu-button"),
    click the "3.5 Flash" row (rejecting Flash-Lite / Pro / Deep Think
    siblings), then open the "Thinking level" submenu and click "Extended"
    — the pipeline wants "Flash Extended", not the default "Standard".
    Menu-row text is title+description concatenated ("3.5 FlashAll-around
    help"), so the model match avoids a trailing word boundary.
    Best-effort: if the dropdown rotated or 3.5 Flash isn't available,
    return False — the caller enables DR anyway. The Extended step is
    softer still: a miss only leaves the default thinking level (logged).

    Returns True when 3.5 Flash is selected (Extended is set best-effort
    within); False if the model couldn't be picked.
    """
    try:
        # Step 1: find the model dropdown button. Gemini's current UI uses
        # a button at the top of the chat header whose text is the current
        # model name ("3.5 Flash", "3.1 Pro", "Gemini 3.5 Flash", etc.). The
        # button usually has aria-haspopup="menu" or a chevron icon.
        # Common selectors across UI versions:
        #   - bard-mode-menu-button (legacy data-test-id)
        #   - button[aria-label*="model" i]
        #   - button[aria-haspopup="menu"] near the top of the page whose
        #     text contains "Gemini" / "3.5" / "Flash" / "Pro"
        opened = await page.evaluate("""() => {
            // No top-of-page guard: on the home-screen UI Gemini centers
            // the composer at ~30-50% of viewport, so the prior < 25%
            // position gate never matched the model button there (the
            // gate was right for sticky-header chat view, wrong for the
            // empty-chat landing). Precise selectors are model-button
            // specific, so we click them unconditionally; the text-
            // pattern fallback still uses a wide-but-bounded position
            // gate so an unrelated menu button (account chip) can't
            // accidentally match.
            const precise = document.querySelectorAll(
                'bard-mode-menu-button button, ' +
                'button[data-test-id="bard-mode-menu-button"], ' +
                'button[aria-label*="model" i], ' +
                'button[aria-label*="Switch model" i]'
            );
            for (const b of precise) {
                if (b.offsetParent) { b.click(); return true; }
            }
            // Fall back to text-pattern match across visible menu buttons.
            // Accept any version-number prefix (3.1 / 3.0 / 2.5) so the
            // probe still finds the dropdown if Google rotates the
            // model-name label between versions. Position gate widened
            // to top 95% so BOTH home-screen-centered composer (~50%
            // viewport) AND new-UI bottom-anchored composer (~85% on
            // tall viewports) qualify. The only thing this rules out is
            // a sub-footer banner.
            const inViewableArea = (b) => {
                const r = b.getBoundingClientRect();
                return r.top >= 0 && r.top < window.innerHeight * 0.95 && r.width > 0;
            };
            const buttons = document.querySelectorAll('button[aria-haspopup="menu"], button[aria-expanded]');
            for (const b of buttons) {
                if (!b.offsetParent || !inViewableArea(b)) continue;
                const t = (b.textContent || '').trim();
                if (/\\b(\\d\\.\\d|Gemini|Flash|Pro|Deep Think)\\b/i.test(t)) {
                    b.click(); return true;
                }
            }
            return false;
        }""")
        if not opened:
            log("[setup_gemini_dr] model-pick: dropdown button not found — skipping Flash selection", "INFO")
            return False
        await asyncio.sleep(0.8)

        # Step 2: click the "3.5 Flash" model row. The menu row's textContent
        # is the title CONCATENATED with its description ("3.5 FlashAll-around
        # help"), so match "3.5 flash" WITHOUT a trailing word boundary (a
        # \\bflash\\b would fail against "flashall..."). Reject Flash-Lite /
        # Pro / Deep Think siblings first — order matters ("Flash-Lite" also
        # contains "flash").
        picked = await page.evaluate("""() => {
            const items = document.querySelectorAll(
                '[role="menuitem"], [role="menuitemradio"], [role="option"], button, a, li');
            for (const el of items) {
                if (!el.offsetParent) continue;
                const t = (el.textContent || '').trim().toLowerCase();
                if (!t) continue;
                if (t.includes('lite') || t.includes('deep think') ||
                    /\\bpro\\b/.test(t)) continue;
                if (/3\\.5\\s*flash/i.test(t)) {
                    el.click();
                    return t.slice(0, 40);
                }
            }
            return '';
        }""")
        if not picked:
            log("[setup_gemini_dr] model-pick: 3.5 Flash item not found in dropdown — closing menu", "WARN")
            # Best-effort: close the open dropdown so the next step's + button
            # isn't sitting under an overlay.
            try:
                await page.keyboard.press("Escape")
            except Exception:
                pass
            return False
        await asyncio.sleep(0.6)
        log(f"[setup_gemini_dr] model-pick OK: clicked '{picked}'")

        # Step 3: set Thinking level = Extended (the pipeline wants "Flash
        # Extended", not the default "Standard"). The model menu carries a
        # "Thinking level" submenu trigger; clicking it expands a Standard /
        # Extended choice (click-driven, per captured UI). The menu stays open
        # after the model pick, but if it closed we reopen via the mode button.
        # Best-effort: a miss leaves the default level (Standard) and is logged,
        # not fatal.
        _reopen_js = """() => {
            const b = document.querySelector(
                'button[data-test-id="bard-mode-menu-button"], bard-mode-menu-button button');
            if (b && b.offsetParent) { b.click(); return true; }
            return false;
        }"""
        _click_tl_js = """() => {
            const items = document.querySelectorAll(
                '[role="menuitem"], [role="menuitemradio"], [role="option"], button, a, li');
            for (const el of items) {
                if (!el.offsetParent) continue;
                const t = (el.textContent || '').trim().toLowerCase();
                if (t.startsWith('thinking level') || t.includes('thinking level')) {
                    try { el.dispatchEvent(new MouseEvent('mouseover', {bubbles:true})); } catch(e){}
                    try { el.dispatchEvent(new MouseEvent('pointerover', {bubbles:true})); } catch(e){}
                    el.click();
                    return true;
                }
            }
            return false;
        }"""
        tl_opened = await page.evaluate(_click_tl_js)
        if not tl_opened:
            await page.evaluate(_reopen_js)
            await asyncio.sleep(0.6)
            tl_opened = await page.evaluate(_click_tl_js)
        if tl_opened:
            await asyncio.sleep(0.6)
            ext_picked = await page.evaluate("""() => {
                const items = document.querySelectorAll(
                    '[role="menuitem"], [role="menuitemradio"], [role="option"], button, a, li');
                for (const el of items) {
                    if (!el.offsetParent) continue;
                    const t = (el.textContent || '').trim().toLowerCase();
                    if (t.startsWith('standard')) continue;
                    if (t.startsWith('extended') || /\\bextended\\b/.test(t)) {
                        el.click();
                        return t.slice(0, 40);
                    }
                }
                return '';
            }""")
            await asyncio.sleep(0.5)
            if ext_picked:
                log(f"[setup_gemini_dr] model-pick: Thinking level -> Extended ('{ext_picked}')")
            else:
                log("[setup_gemini_dr] model-pick: 'Extended' option not found — leaving default thinking level", "WARN")
        else:
            log("[setup_gemini_dr] model-pick: 'Thinking level' submenu not found — leaving default thinking level", "WARN")

        # Verify the mode button now reflects Extended (best-effort), then close
        # the menu so it can't cover the composer + button in the next step.
        try:
            _mode_txt = await page.evaluate("""() => {
                const b = document.querySelector(
                    'button[data-test-id="bard-mode-menu-button"], bard-mode-menu-button button');
                return b ? ((b.getAttribute('aria-label') || '') + ' ' + (b.textContent || '')).toLowerCase() : '';
            }""")
            if 'extended' in (_mode_txt or ''):
                log("[setup_gemini_dr] model-pick verify: mode button shows Extended")
        except Exception:
            pass
        try:
            await page.keyboard.press("Escape")
        except Exception:
            pass
        return True
    except Exception as e:
        log(f"[setup_gemini_dr] model-pick exception: {e}", "WARN")
        return False


# #709 (2026-05-29) — single source of truth for "is Gemini Deep Research
# ACTIVE?". Shared by setup_gemini_dr's verification AND the pre-send
# ensure_deep_mode_active check so both agree exactly. The authoritative signal
# is the COMPOSER PLACEHOLDER (DR ON → "What do you want to research?"; chat →
# "Ask Gemini") — the DR pill's class (mat-tonal-button…) carries NO reliable
# pressed marker, so a pressed-class-only check false-negatived an ACTIVE pill
# last E2E and the CUA fallback then toggled the working DR OFF. Anchored to the
# composer (rich-textarea / lowest contenteditable) to avoid reading a stale
# dialog placeholder. Returns placeholderResearch (active), placeholderChat
# (confidently off), pressed (secondary), + pill diagnostics for the dump.
_GEMINI_DR_STATE_JS = """() => {
    const norm = s => (s || '').replace(/\\s+/g, ' ').trim().toLowerCase();
    let ce = document.querySelector('rich-textarea div[contenteditable="true"]')
          || document.querySelector('rich-textarea')
          || null;
    if (!ce) {
        const cands = [...document.querySelectorAll(
            'div[contenteditable="true"][data-placeholder], textarea[placeholder]')]
            .filter(e => e.offsetParent);
        if (cands.length) {
            cands.sort((a, b) => b.getBoundingClientRect().top - a.getBoundingClientRect().top);
            ce = cands[0];
        }
    }
    let placeholder = '';
    if (ce) placeholder = norm(ce.getAttribute('data-placeholder')
        || ce.getAttribute('placeholder') || ce.getAttribute('aria-label'));
    const placeholderResearch = placeholder.includes('research') ||
        placeholder.includes('what do you want to');
    const placeholderChat = placeholder.includes('ask gemini');
    let pill = null;
    for (const p of document.querySelectorAll('button, [role="button"]')) {
        if (!p.offsetParent) continue;
        if (norm(p.textContent) === 'deep research') { pill = p; break; }
    }
    let pillText = '', pillCls = '', pillAria = '';
    if (pill) {
        pillText = (pill.textContent || '').trim().slice(0, 40);
        pillCls = (pill.className || '').toString().toLowerCase();
        pillAria = (pill.getAttribute('aria-label') || '');
    }
    const pressed = pill ? (
        pill.getAttribute('aria-pressed') === 'true' ||
        pill.getAttribute('aria-selected') === 'true' ||
        pill.getAttribute('data-active') === 'true' ||
        pillCls.includes('--selected') || pillCls.includes('selected') ||
        pillCls.includes('active') || pillCls.includes('--filled')) : false;
    return { pillVisible: !!pill, pressed, placeholderResearch, placeholderChat,
             placeholder: placeholder.slice(0, 60),
             pillText, pillCls: pillCls.slice(0, 100), pillAria };
}"""


async def setup_gemini_dr(page) -> bool:
    """Enable Gemini Deep Research. Returns True only when DR is verified
    ACTIVE (pill visible + pressed/selected). Returns False otherwise so
    the caller's CUA fallback kicks in instead of letting the run proceed
    silently in chat mode.

    UI history:
      • 2026-05: + (attach) → "More tools" → "Deep Research" (current).
      • 2026-04: "Tools" → "Deep Research".
      • Older: direct DR pill in composer / DR in model dropdown.

    Tries the current path first, falls through each legacy path on miss,
    then strictly verifies the resulting pill state. Pre-fix, a missing
    active-state attribute downgraded to a WARN-and-return-True — that
    silently shipped chat-mode briefs as Deep Research output. Strict
    verification is the cost of avoiding that class of bug.

    2026-05-26: pre-selects "3.5 Flash" via _gemini_select_flash_model
    before enabling DR (the pipeline runs Gemini DR on 3.5 Flash — see
    that helper's docstring for why). Without an explicit pick, the
    dropdown's default could carry the wrong model into the DR run.
    """
    try:
        await asyncio.sleep(2)
        # Best-effort: pick 3.5 Flash before opening + menu. Non-fatal if it
        # misses (run proceeds on whatever model the dropdown was on).
        await _gemini_select_flash_model(page)
        await asyncio.sleep(0.5)
        direct_clicked = False

        # ── Step 1 (current UI 2026-05): + → More tools → Deep Research ──
        # The + button sits in the composer toolbar (left of the textarea).
        # As of 2026-05 it's an SVG icon that morphs +↔× on tap — it has NO
        # stable text "+", NO whitelisted aria-label in some builds, and is
        # NOT a Material FONT glyph, so the old text/label/mat-icon matching
        # missed it entirely ("+ button not in composer" every run). Detect it
        # by STRUCTURE instead: anchor on the composer input, then take visible
        # buttons to its LEFT on the same row (this excludes send/mic/stop,
        # which sit right of or are labelled), label-matchers ranked first.
        # We then click candidates best-first and REQUIRE a popup menu to open
        # before accepting — a wrong click can't silently arm mic/attach.
        n_cands = await page.evaluate("""() => {
            document.querySelectorAll('[data-dg-plus-cand]').forEach(
                el => el.removeAttribute('data-dg-plus-cand'));
            const input = document.querySelector(
                'rich-textarea div[contenteditable="true"], rich-textarea, '
                + 'div[contenteditable="true"][data-placeholder], '
                + 'div[contenteditable="true"], textarea');
            const ir = input ? input.getBoundingClientRect() : null;
            const looksPlus = (b) => {
                const a = (b.getAttribute('aria-label') || '').toLowerCase();
                const tt = (b.getAttribute('title') || '').toLowerCase();
                const tx = (b.textContent || '').trim();
                const addIcon = [...b.querySelectorAll(
                        'mat-icon, .material-symbols-outlined, .material-icons')]
                    .some(ic => { const n = (ic.textContent || '').trim().toLowerCase();
                                  return n === 'add' || n === 'add_circle'; });
                // "Upload & tools" is the current (2026-05) Gemini composer +
                // button aria-label (an mdc-icon-button with aria-haspopup=menu);
                // older builds used add/attach/more — keep them all.
                return a.includes('upload') || a === 'add' || a === 'add files' ||
                       a.includes('add files') || a === 'attach' || a === 'attachments' ||
                       a === 'more' || a === 'more options' || tt === 'add' ||
                       tt === 'more' || tt.includes('attach') || tx === '+' || addIcon;
            };
            const isBad = (b) => {
                const lbl = ((b.getAttribute('aria-label') || '') + ' '
                          + (b.getAttribute('title') || '')).toLowerCase();
                if (/mic|microph|voice|dictat|speak|send|submit|stop|cancel/.test(lbl))
                    return true;
                // Recent-chats sidebar "More options for <chat>" menus sit on
                // the composer's row when the sidebar is expanded, so same-row +
                // left-of-input would otherwise match them — exclude explicitly.
                const cls = (b.className || '').toString().toLowerCase();
                const tid = (b.getAttribute('data-test-id') || '').toLowerCase();
                return tid === 'actions-menu-button' ||
                       cls.includes('conversation-actions') ||
                       /more options for/.test(lbl);
            };
            const cands = [];
            for (const b of document.querySelectorAll('button, [role="button"]')) {
                if (!b.offsetParent || isBad(b)) continue;
                const r = b.getBoundingClientRect();
                if (r.width <= 0 || r.height <= 0) continue;
                const labelHit = looksPlus(b);
                let score = 0;
                if (ir) {
                    // Input anchor available: candidate MUST sit on the
                    // composer's row, left of the input (where + lives). Ties
                    // us to the composer by STRUCTURE regardless of absolute
                    // position — setup runs on the empty new-chat page where
                    // Gemini centers the composer (~30-50% of viewport), so an
                    // absolute "bottom-half only" gate would wrongly drop it.
                    const sameRow = r.top < ir.bottom && r.bottom > ir.top;
                    const leftOfInput = r.right <= ir.left + 8;
                    if (!(sameRow && leftOfInput)) continue;
                    score = 50 + (labelHit ? 100 : 0)
                          + Math.max(0, 20 - Math.round((ir.left - r.right) / 10));
                } else {
                    // No input anchor: fall back to a labelled button in the
                    // bottom region (the pre-2026-05 heuristic).
                    if (r.top < window.innerHeight * 0.4 || !labelHit) continue;
                    score = 100;
                }
                cands.push({ b, score, x: r.left });
            }
            cands.sort((p, q) => q.score - p.score || p.x - q.x);
            cands.slice(0, 5).forEach((c, i) =>
                c.b.setAttribute('data-dg-plus-cand', String(i)));
            return Math.min(cands.length, 5);
        }""")

        _count_visible_menus = """() => {
            let v = 0;
            for (const m of document.querySelectorAll(
                    '[role="menu"], [role="listbox"], [role="menuitem"], [role="option"]'))
                if (m.offsetParent) v++;
            return v;
        }"""
        plus_opened = False
        for _ci in range(int(n_cands or 0)):
            # Baseline visible-menu count BEFORE the click so the assertion
            # measures a DELTA, not an absolute — a menu/listbox already open
            # on the page can't false-positive us into accepting a dead click.
            _menu_before = await page.evaluate(_count_visible_menus)
            clicked = await page.evaluate(
                """(i) => { const el = document.querySelector(
                    '[data-dg-plus-cand="' + i + '"]');
                    if (!el) return false; el.click(); return true; }""", _ci)
            if not clicked:
                continue
            await asyncio.sleep(0.7)
            # Mandatory "menu opened" assertion — a real "+" click renders a
            # popup menu (and morphs the button to ×/aria-expanded). No new
            # menu = wrong control: dismiss and try the next candidate.
            menu_open = await page.evaluate("""(before) => {
                let v = 0;
                for (const m of document.querySelectorAll(
                        '[role="menu"], [role="listbox"], [role="menuitem"], [role="option"]'))
                    if (m.offsetParent) v++;
                const expanded = document.querySelector(
                    '[data-dg-plus-cand][aria-expanded="true"]');
                return v > before || !!expanded;
            }""", _menu_before)
            if menu_open:
                plus_opened = True
                break
            try:
                await page.keyboard.press("Escape")
                await asyncio.sleep(0.2)
            except Exception:
                pass
        try:
            await page.evaluate(
                """() => document.querySelectorAll('[data-dg-plus-cand]').forEach(
                    el => el.removeAttribute('data-dg-plus-cand'))""")
        except Exception:
            pass
        if plus_opened:
            await asyncio.sleep(0.8)
            log("[setup_gemini_dr] Step 1 (current UI): opened + menu")
            # Step 1a: scan the + tray top level for "Deep research" — current
            # 2026-05 UI places it as a SIBLING of "More tools", not inside
            # the submenu. Prior code descended into More tools first and
            # never found DR (More tools submenu now contains: Create music,
            # Learning, Guided learning, Personal Intelligence).
            direct_clicked = await page.evaluate("""() => {
                const items = document.querySelectorAll(
                    '[role="menuitem"], [role="option"], button, a, li');
                for (const el of items) {
                    if (!el.offsetParent) continue;
                    const t = (el.textContent || '').trim().toLowerCase();
                    const a = (el.getAttribute('aria-label') || '').toLowerCase();
                    if (t === 'deep research' || a === 'deep research' ||
                        t.startsWith('deep research') || a.startsWith('deep research')) {
                        el.click();
                        return true;
                    }
                }
                return false;
            }""")
            if direct_clicked:
                log("[setup_gemini_dr] Step 1 OK (current UI): + → Deep Research (top-level)")
            else:
                # Step 1b (older UI variant): + → More tools → Deep Research.
                # Kept as fallback for accounts still on the prior layout.
                more_tools_opened = await page.evaluate("""() => {
                    const items = document.querySelectorAll(
                        '[role="menuitem"], [role="option"], button, a, li');
                    for (const el of items) {
                        if (!el.offsetParent) continue;
                        const t = (el.textContent || '').trim().toLowerCase();
                        const a = (el.getAttribute('aria-label') || '').toLowerCase();
                        if (t === 'more tools' || t.startsWith('more tools') ||
                            a === 'more tools' || a.startsWith('more tools')) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }""")
                if more_tools_opened:
                    await asyncio.sleep(0.8)
                    log("[setup_gemini_dr] Step 1b (older UI): opened More tools submenu")
                    direct_clicked = await page.evaluate("""() => {
                        const items = document.querySelectorAll(
                            '[role="menuitem"], [role="option"], button, a, li');
                        for (const el of items) {
                            if (!el.offsetParent) continue;
                            const t = (el.textContent || '').trim().toLowerCase();
                            const a = (el.getAttribute('aria-label') || '').toLowerCase();
                            if (t === 'deep research' || a === 'deep research' ||
                                t.startsWith('deep research') || a.startsWith('deep research')) {
                                el.click();
                                return true;
                            }
                        }
                        return false;
                    }""")
                    if direct_clicked:
                        log("[setup_gemini_dr] Step 1b OK (older UI): + → More tools → Deep Research")
                    else:
                        log("[setup_gemini_dr] Step 1b (older UI): More tools submenu missing Deep Research — falling back", "WARN")
                else:
                    log("[setup_gemini_dr] Step 1 (current UI): no Deep Research top-level AND no More tools — falling back", "INFO")
        else:
            log("[setup_gemini_dr] Step 1 (current UI): no + candidate opened a menu — trying legacy paths", "INFO")

        # ── Step 2 (legacy 2026-04): Tools button → Deep Research ────
        if not direct_clicked:
            tools_opened = await page.evaluate("""() => {
                const candidates = document.querySelectorAll('button, [role="button"]');
                for (const b of candidates) {
                    if (!b.offsetParent) continue;
                    const t = (b.textContent || '').trim().toLowerCase();
                    const a = (b.getAttribute('aria-label') || '').toLowerCase();
                    const tt = (b.getAttribute('title') || '').toLowerCase();
                    if (t === 'tools' || a === 'tools' ||
                        a.includes('tools') || tt.includes('tools') ||
                        t.startsWith('tools')) {
                        b.click();
                        return true;
                    }
                }
                return false;
            }""")
            if tools_opened:
                await asyncio.sleep(0.8)
                log("[setup_gemini_dr] Step 2 (legacy): opened Tools menu")
                direct_clicked = await page.evaluate("""() => {
                    const items = document.querySelectorAll('[role="menuitem"], [role="option"], button, a, li');
                    for (const el of items) {
                        if (!el.offsetParent) continue;
                        const t = (el.textContent || '').trim().toLowerCase();
                        const a = (el.getAttribute('aria-label') || '').toLowerCase();
                        if (t === 'deep research' || a === 'deep research' ||
                            t.startsWith('deep research') || a.startsWith('deep research')) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }""")
                if direct_clicked:
                    log("[setup_gemini_dr] Step 2 OK (legacy): Tools → Deep Research")

        # ── Step 3 (legacy): direct DR pill in the composer ────────────
        if not direct_clicked:
            direct_clicked = await page.evaluate("""() => {
                const candidates = document.querySelectorAll('button, [role="button"], [role="menuitem"]');
                for (const b of candidates) {
                    if (!b.offsetParent) continue;
                    const t = (b.textContent || '').trim().toLowerCase();
                    const a = (b.getAttribute('aria-label') || '').toLowerCase();
                    if (t === 'deep research' || a === 'deep research' || t.startsWith('deep research')) {
                        b.click();
                        return true;
                    }
                }
                return false;
            }""")
            if direct_clicked:
                log("[setup_gemini_dr] Step 3 OK (legacy): clicked DR pill directly in composer")

        # ── Step 4 (legacy): DR inside the model dropdown ──────────────
        if not direct_clicked:
            for sel in ['button[aria-label*="model"]', 'button[data-test-id*="model"]']:
                try:
                    btn = await page.query_selector(sel)
                    if btn:
                        await btn.click()
                        await asyncio.sleep(0.8)
                        log(f"[setup_gemini_dr] Step 4 (legacy): opened {sel}")
                        direct_clicked = await page.evaluate("""() => {
                            const items = document.querySelectorAll('[role="menuitem"], [role="option"], button');
                            for (const el of items) {
                                const t = (el.textContent || '').trim().toLowerCase();
                                if (t.includes('deep research')) { el.click(); return true; }
                            }
                            return false;
                        }""")
                        if direct_clicked:
                            log(f"[setup_gemini_dr] Step 4 OK (legacy): DR selected via {sel} dropdown")
                            break
                        else:
                            log(f"[setup_gemini_dr] Step 4 {sel}: dropdown opened but DR option absent", "WARN")
                except Exception as e:
                    log(f"[setup_gemini_dr] Step 4 {sel} errored: {e}", "WARN")
                    continue

        if not direct_clicked:
            log("[setup_gemini_dr] FAIL: + menu, Tools menu, direct pill, and model-dropdown fallbacks all missed DR — selectors rotated", "WARN")
            return False

        await asyncio.sleep(1.5)

        # ── Verification: STRICT. DR must be visibly active before True.
        # 2026-05-29 (#709): the prior check relied SOLELY on the pill's
        # pressed/selected class. The real Gemini DR pill class
        # (`mdc-button mat-mdc-button-base mat-badge mat-tonal-button …`)
        # carries NONE of aria-pressed / --selected / .active even when DR is
        # OFF, so a present-but-INACTIVE pill returned False → CUA fallback →
        # the CUA falsely reported "chip already visible and active" → the run
        # proceeded in Flash chat mode (last E2E). The authoritative, cross-
        # version signal is the COMPOSER PLACEHOLDER: DR mode shows
        # "What do you want to research?"; chat mode shows "Ask Gemini". Lead
        # with the placeholder; treat the pressed-class as a secondary signal.
        _gem_active_js = _GEMINI_DR_STATE_JS
        st = await page.evaluate(_gem_active_js)
        # If — and ONLY if — we are CONFIDENT Deep Research is OFF (the composer
        # placeholder explicitly reads "Ask Gemini"), click the pill once to arm
        # the mode, then re-measure. This is the #709 "don't remove the working
        # DOM" guard: last E2E our verify false-negatived an ALREADY-ACTIVE pill
        # (its mat-tonal-button class has no pressed marker), the CUA fallback
        # then clicked that active pill and TOGGLED DEEP RESEARCH OFF. We never
        # click on an ambiguous read (placeholder unreadable / no chat signal) —
        # a toggle can only ever turn a confirmed-off pill ON, never an on pill
        # OFF.
        if (st.get("pillVisible") and st.get("placeholderChat")
                and not st.get("placeholderResearch") and not st.get("pressed")):
            log("[setup_gemini_dr] Verify: composer in chat mode ('Ask Gemini') "
                "with DR pill present — clicking pill to arm Deep Research")
            try:
                await page.evaluate("""() => {
                    const norm = s => (s || '').replace(/\\s+/g, ' ').trim().toLowerCase();
                    for (const p of document.querySelectorAll('button, [role="button"]')) {
                        if (p.offsetParent && norm(p.textContent) === 'deep research') {
                            p.click(); return true;
                        }
                    }
                    return false;
                }""")
                await asyncio.sleep(1.2)
            except Exception:
                pass
            st = await page.evaluate(_gem_active_js)
        active_ok = bool(st.get("placeholderResearch") or st.get("pressed"))
        if not active_ok:
            # One-shot diagnostic dump (mirrors #708) so the next E2E pins the
            # real active class / placeholder. Grep backend.log for
            # "Verify FAIL: DR not active — dump".
            try:
                log("[setup_gemini_dr] Verify FAIL: DR not active — dump " + json.dumps(st))
            except Exception:
                pass
            log(f"[setup_gemini_dr] Verify FAIL: DR pill visible but NOT active "
                f"(placeholder={st.get('placeholder')!r} pillCls={st.get('pillCls')!r}) "
                f"— returning False so CUA fallback retries", "WARN")
            return False
        log(f"[setup_gemini_dr] Verify OK: DR active "
            f"(placeholder={st.get('placeholder')!r}, pressed={st.get('pressed')})")
        return True
    except Exception as e:
        log(f"[setup_gemini_dr] exception: {e}", "WARN")
        return False


async def setup_claude_dr(page) -> bool:
    """Enable Claude Opus 4.8 + Max Effort + Adaptive Thinking + Research
    tool via direct Playwright selectors. As of 2026-05-28 the claude.ai UI
    splits these across the model popover + the tools menu:
        1. Model dropdown        → Opus 4.8
        2. Effort submenu        → Max          (inside the model popover)
        3. Adaptive Thinking     → on (toggle)  (inside the model popover)
        4. Research tool         → on (inside the "+" tools menu)
    Steps 2 + 3 are quality knobs (best-effort: WARN on miss). Correctness
    gates are the model + Research tool — those hard-return False on miss.
    The CUA fallback lives one layer up in setup_agent + validate_setup_with_cua
    so this routine can fail fast without fighting the DOM."""
    try:
        await asyncio.sleep(2)

        # ── Step 1: open model dropdown and pick Opus 4.8 ─────────────
        dropdown_clicked = await page.evaluate("""() => {
            const btns = [...document.querySelectorAll('button')].filter(b => b.offsetParent !== null);
            // Model selector button shows the currently-selected model name.
            // Priority: already-Opus > Sonnet > any button with "claude"
            let dropdown = btns.find(b => (b.textContent || '').toLowerCase().includes('opus'));
            if (!dropdown) dropdown = btns.find(b => {
                const t = (b.textContent || '').toLowerCase();
                return t.includes('sonnet') || t.includes('haiku') || t.includes('claude');
            });
            if (dropdown) { dropdown.click(); return true; }
            return false;
        }""")
        if dropdown_clicked:
            log("[setup_claude_dr] Step 1A OK: opened model dropdown")
            await asyncio.sleep(0.8)
            # Step 1B: pick the STRONGEST Opus (>= 4.8) from the OPEN popover.
            # Two prod failures (2026-05-28, backend.log 48681/49653) had this
            # land on "Opus 4.7 Extra" instead of "Opus 4.8 Max":
            #   (1) the model-selector TRIGGER button (which shows the CURRENT
            #       model, e.g. "Opus 4.7 Extra") was in the candidate set, and
            #   (2) when the 4.8 menu item hadn't rendered by the 0.8s mark, the
            #       old "any Opus 4.x" priority grabbed that trigger's 4.7.
            # Fixes: (a) scope candidates to the OPEN popover (role=menu/listbox/
            # dialog) so the composer trigger button is excluded; (b) version-gate
            # to >= 4.8 so we NEVER downgrade to 4.7/4.6/... even if 4.8 is slow;
            # (c) poll for the option to appear. If only sub-4.8 Opus exists,
            # return null so the CUA fallback (Opus-4.8 prompt) handles it rather
            # than silently selecting 4.7. Future-proof: picks the highest version.
            _pick_opus_js = """() => {
                const menus = [...document.querySelectorAll('[role="menu"], [role="listbox"], [role="dialog"]')]
                    .filter(m => m.offsetParent !== null);
                const roots = menus.length ? menus : [document.body];
                const seen = new Set();
                const items = roots.flatMap(m => [...m.querySelectorAll('[role="menuitem"], [role="option"], button, a, li')])
                    .filter(el => el.offsetParent !== null && !seen.has(el) && seen.add(el));
                const verOf = t => {
                    const m = (t || '').match(/opus[^0-9]*([0-9]+(?:\\.[0-9]+)?)/i);
                    return m ? parseFloat(m[1]) : null;
                };
                // Prefer leaf menu items over wrapper containers at the same
                // version (shorter text = more specific element).
                let best = null, bestV = -1, bestLen = Infinity;
                for (const el of items) {
                    const t = (el.textContent || '').trim();
                    const v = verOf(t);
                    if (v === null || v < 4.8) continue;   // only Opus >= 4.8 — never downgrade
                    if (v > bestV || (v === bestV && t.length < bestLen)) {
                        best = el; bestV = v; bestLen = t.length;
                    }
                }
                if (best) { best.click(); return best.textContent.trim(); }
                return null;
            }"""
            opus_selected = None
            for _attempt in range(8):
                opus_selected = await page.evaluate(_pick_opus_js)
                if opus_selected:
                    break
                await asyncio.sleep(0.4)
            if opus_selected:
                log(f"[setup_claude_dr] Step 1B OK: selected {opus_selected}")
            else:
                log("[setup_claude_dr] Step 1B FAIL: Opus >= 4.8 option not found in popover after polling — rollout/A-B difference or 4.8 retired?", "WARN")
                return False
            await asyncio.sleep(0.6)

            # ── Step 1C: set Effort = Max ──────────────────────────────
            # 2026-05-28: claude.ai split the old single "Opus 4.7 Adaptive"
            # option into Model (Opus 4.8) + an Effort submenu (Low/Medium/
            # High/Extra/Max) + an Adaptive-thinking toggle — all inside the
            # model popover, which STAYS open after picking a model. So we
            # open the Effort submenu and pick Max WITHOUT dismissing first.
            # Best-effort: Effort/Adaptive are quality knobs, not correctness
            # gates, so a miss here only WARNs — the CUA validate layer
            # (PROMPT_VALIDATE_CLAUDE_SETUP) is the real backstop.
            try:
                _eff_opened = await page.evaluate("""() => {
                    const els = [...document.querySelectorAll('[role="menuitem"], button, [role="option"], li')]
                        .filter(el => el.offsetParent !== null);
                    // The Effort row shows its current value + a submenu chevron.
                    const trigger = els.find(el => {
                        const t = (el.textContent || '').trim().toLowerCase();
                        return t === 'effort' || t.startsWith('effort');
                    });
                    if (trigger) { trigger.click(); return true; }
                    return false;
                }""")
                if _eff_opened:
                    await asyncio.sleep(0.5)
                    _eff_set = await page.evaluate("""() => {
                        const items = [...document.querySelectorAll('[role="menuitem"], [role="option"], button, li')]
                            .filter(el => el.offsetParent !== null);
                        // Exact-match the trimmed label so we don't catch the
                        // "Higher effort means…" helper text or a "Max Effort" blurb.
                        let pick = items.find(el => (el.textContent || '').trim().toLowerCase() === 'max');
                        if (!pick) pick = items.find(el => (el.textContent || '').trim().toLowerCase() === 'max effort');
                        if (pick) { pick.click(); return pick.textContent.trim().slice(0, 40); }
                        return null;
                    }""")
                    if _eff_set:
                        log(f"[setup_claude_dr] Step 1C OK: Effort set to '{_eff_set}'")
                    else:
                        log("[setup_claude_dr] Step 1C WARN: Effort submenu opened but 'Max' not found — CUA validate will fix", "WARN")
                else:
                    log("[setup_claude_dr] Step 1C WARN: Effort control not found (older UI / popover closed?) — CUA validate will fix", "WARN")
            except Exception as _ee:
                log(f"[setup_claude_dr] Step 1C errored: {_ee}", "WARN")
            await asyncio.sleep(0.4)

            # ── Step 1D: toggle Adaptive Thinking ON ───────────────────
            # Now a toggle inside the same model/effort popover (was a
            # separate composer control pre-2026-05-28). State-aware: only
            # click when not already on. Page-wide search so it works whether
            # the popover is open or the toggle lives elsewhere in a variant.
            adaptive_state = await page.evaluate("""() => {
                const els = [...document.querySelectorAll(
                    'button, [role="switch"], [role="checkbox"], [role="menuitem"], [role="option"], label'
                )].filter(el => el.offsetParent !== null);
                const matches = els.filter(el => {
                    const t = (el.textContent || '').trim().toLowerCase();
                    const a = (el.getAttribute('aria-label') || '').toLowerCase();
                    return t === 'adaptive thinking' ||
                           a === 'adaptive thinking' ||
                           t.startsWith('adaptive thinking') ||
                           a.startsWith('adaptive thinking');
                });
                if (!matches.length) return { found: false };
                const el = matches[0];
                const checked = el.getAttribute('aria-checked') === 'true' ||
                                 el.getAttribute('aria-pressed') === 'true' ||
                                 el.dataset.state === 'checked' || el.dataset.state === 'on';
                if (!checked) { el.click(); return { found: true, toggled: true, label: el.textContent.trim() }; }
                return { found: true, toggled: false, label: el.textContent.trim() };
            }""")
            if not adaptive_state.get("found"):
                log("[setup_claude_dr] Step 1D WARN: Adaptive Thinking toggle not found — UI may have shipped under a new label", "WARN")
            else:
                log(f"[setup_claude_dr] Step 1D OK: Adaptive Thinking {'just enabled' if adaptive_state.get('toggled') else 'already on'} "
                    f"(label='{adaptive_state.get('label')}')")
            await asyncio.sleep(0.4)
            # Dismiss the model popover so the tools menu + input are clickable.
            try:
                await page.keyboard.press("Escape")
                await asyncio.sleep(0.3)
            except Exception:
                pass
        else:
            log("[setup_claude_dr] Step 1A FAIL: model dropdown button not found — selector list likely stale", "WARN")
            return False

        # ── Step 3: open tools menu and enable Research ────────────────
        # Precise selectors first — the old `button[aria-label*="+"]`
        # wildcard was matching unrelated buttons ("New chat", etc.)
        # and occasionally opened the wrong surface.
        # 2026-05-29 (#708): these precise selectors matched NOTHING on every
        # prod run (backend.log Step 3A FAIL x100%), so Research never enabled
        # via DOM → setup returned False → the CUA fallback fired needlessly on
        # EVERY run. The CUA fallback proved the real control is the composer's
        # "+" button. So after the precise selectors we add a composer-scoped
        # "+" detector, and on total failure we DUMP the composer buttons so a
        # single E2E reveals the exact selector (no more blind selector-guessing).
        tools_opened = False
        tools_sel_used = None
        for sel in ['button[aria-label="Open tools menu"]',
                    'button[aria-label*="tools menu"]',
                    'button[aria-label*="Tools menu"]',
                    'button[data-testid*="tools"]',
                    'button[aria-label*="attach"]',
                    'button[aria-haspopup="menu"][aria-label*="tools"]']:
            try:
                btn = await page.query_selector(sel)
                if btn:
                    await btn.click()
                    await asyncio.sleep(0.6)
                    tools_opened = True
                    tools_sel_used = sel
                    break
            except Exception:
                continue
        if not tools_opened:
            # Composer-scoped "+" detector. Bounded to the editor's container
            # (NOT the whole page like the old wildcard), and explicitly skips
            # the model selector (opus/sonnet/haiku text) and the send button.
            try:
                plus_label = await page.evaluate("""() => {
                    const ce = document.querySelector('div[contenteditable="true"], .ProseMirror, [role="textbox"]');
                    // No composer found → do NOT click anything page-wide (would
                    // risk a sidebar "+"/menu button). Bail so the diagnostic
                    // dump runs and the CUA fallback handles it instead.
                    if (!ce) return null;
                    let scope = ce;
                    for (let i = 0; i < 5 && scope && scope.parentElement; i++) scope = scope.parentElement;
                    const root = scope || ce;   // never document.body — stay inside the composer subtree
                    const btns = [...root.querySelectorAll('button')].filter(b => b.offsetParent !== null);
                    const isModel = s => /opus|sonnet|haiku|claude|model/i.test(s || '');
                    const isSend  = s => /\\bsend\\b|submit/i.test(s || '');
                    // Never the model-selector or the send/submit button (check
                    // BOTH text and aria-label so an icon-only Send is excluded).
                    const skip = b => {
                        const a = (b.getAttribute('aria-label') || '');
                        const t = (b.textContent || '').trim();
                        return isModel(t) || isModel(a) || isSend(t) || isSend(a);
                    };
                    // Primary: an icon button that opens a menu.
                    let cand = btns.find(b => {
                        const pop = b.getAttribute('aria-haspopup');
                        return (pop === 'menu' || pop === 'true') && !skip(b);
                    });
                    // Fallback: an add/attach/tools/plus-labelled button.
                    if (!cand) cand = btns.find(b => {
                        if (skip(b)) return false;
                        const a = (b.getAttribute('aria-label') || '').toLowerCase();
                        const t = (b.textContent || '').trim();
                        return a.includes('attach') || a.includes('tool') || a.includes('add') ||
                               a.includes('plus') || a.includes('upload') || a.includes('more') || t === '+';
                    });
                    if (cand) { cand.click(); return (cand.getAttribute('aria-label') || cand.textContent || '+').trim().slice(0, 40); }
                    return null;
                }""")
                if plus_label:
                    await asyncio.sleep(0.6)
                    tools_opened = True
                    tools_sel_used = f"composer-plus[{plus_label}]"
            except Exception as _pe:
                log(f"[setup_claude_dr] Step 3A '+' detector errored: {_pe}", "WARN")
        if tools_opened:
            log(f"[setup_claude_dr] Step 3A OK: opened tools menu via {tools_sel_used}")
        else:
            log("[setup_claude_dr] Step 3A FAIL: tools menu button not found — aria-labels rotated or language changed", "WARN")
            # Diagnostic: dump the composer's buttons so the next E2E pins the
            # exact selector. Self-documenting — replaces blind selector-guessing.
            try:
                _btn_dump = await page.evaluate("""() => {
                    const ce = document.querySelector('div[contenteditable="true"], .ProseMirror, [role="textbox"]');
                    let scope = ce;
                    for (let i = 0; i < 5 && scope && scope.parentElement; i++) scope = scope.parentElement;
                    const root = scope || document.body;
                    return [...root.querySelectorAll('button')].filter(b => b.offsetParent !== null).slice(0, 25).map(b => ({
                        al: (b.getAttribute('aria-label') || '').slice(0, 40),
                        t: (b.textContent || '').trim().slice(0, 24),
                        pop: b.getAttribute('aria-haspopup') || '',
                        tid: b.getAttribute('data-testid') || ''
                    }));
                }""")
                log(f"[setup_claude_dr] Step 3A composer-button dump (fix selector from this): {json.dumps(_btn_dump, ensure_ascii=False)}", "WARN")
            except Exception:
                pass
        research_enabled = False
        if tools_opened:
            # State-aware + accept label variations ("Research", "Research
            # tool", "Deep research"). Only clicks when not already on.
            research_enabled = await page.evaluate("""() => {
                const items = [...document.querySelectorAll(
                    '[role="menuitem"], button, [role="switch"], [role="checkbox"], label'
                )].filter(el => el.offsetParent !== null);
                const target = items.find(el => {
                    const t = (el.textContent || '').trim().toLowerCase();
                    const a = (el.getAttribute('aria-label') || '').toLowerCase();
                    return t === 'research' || a === 'research' ||
                           t === 'research tool' || a === 'research tool' ||
                           t === 'deep research' || a === 'deep research' ||
                           t.startsWith('research ') || a.startsWith('research ');
                });
                if (!target) return false;
                const checked = target.getAttribute('aria-checked') === 'true' ||
                                 target.getAttribute('aria-pressed') === 'true' ||
                                 target.dataset.state === 'checked' || target.dataset.state === 'on';
                if (!checked) target.click();
                return true;
            }""")
            await asyncio.sleep(0.4)
            try:
                await page.keyboard.press("Escape")
                await asyncio.sleep(0.3)
            except Exception:
                pass
        if research_enabled:
            log("[setup_claude_dr] Step 3B OK: Research tool toggled on")
        else:
            log("[setup_claude_dr] Step 3B FAIL: Research tool item not found in tools menu — will run in chat mode, NOT research", "WARN")

        # Focus the input so the brief paste/attach lands cleanly.
        for sel in ['div[contenteditable="true"]', '[aria-label*="message"]', '.ProseMirror']:
            try:
                inp = await page.query_selector(sel)
                if inp:
                    await inp.click()
                    break
            except Exception:
                continue
        # Success only when all three critical knobs are in place
        return bool(opus_selected) and bool(research_enabled)
    except Exception as e:
        log(f"[setup_claude_dr] {e}", "WARN")
        return False


async def validate_setup_with_cua(browser, cua_client, page, platform, label, verbose=False):
    """Extra validation layer: CUA looks at the screen and confirms the intended
    options (Deep Research / Extended / Research tool) are actually active. If not,
    CUA tries to fix. Returns True if 'verified' or 'fixed', False otherwise."""
    validator_map = {
        "chatgpt": PROMPT_VALIDATE_CHATGPT_SETUP,
        "gemini": PROMPT_VALIDATE_GEMINI_SETUP,
        "claude": PROMPT_VALIDATE_CLAUDE_SETUP,
    }
    user_msg_map = {
        "chatgpt": "Verify Deep Research mode is ACTIVE in ChatGPT. Fix if not. Do not type.",
        "gemini": "Verify Gemini Deep Research is ACTIVE — the composer placeholder MUST read 'What do you want to research?' (NOT 'Ask Gemini'). A merely-visible chip is NOT enough proof. Fix if not. Do not type.",
        "claude": "Verify Opus 4.8 + Max effort + Adaptive thinking + Research tool are ON in Claude. Clear any stale attachments. Do not type.",
    }
    sys_prompt = validator_map.get(platform.lower())
    user_prompt = user_msg_map.get(platform.lower())
    if not sys_prompt:
        return True  # Unknown platform — skip
    try:
        await browser.switch_to_page(page)
        result = await agent_loop(cua_client, browser, sys_prompt, user_prompt,
            model=CUA_MODEL, max_iterations=6, verbose=verbose)
        text = (result.get("text") or "").lower()
        if "verified" in text or "fixed" in text:
            log(f"[{label}] CUA validation: {text[:120]}")
            return True
        if "failed" in text:
            log(f"[{label}] CUA validation FAILED: {text[:160]}", "WARN")
            return False
        # Ambiguous — treat as pass but log
        log(f"[{label}] CUA validation ambiguous: {text[:120]}", "WARN")
        return True
    except Exception as e:
        log(f"[{label}] CUA validation error: {e}", "WARN")
        return True  # Don't block pipeline on validator error


# ═════════════════════════════════════════════════════════════════════
# Phase-2 brief delivery via file attachment (Option A)
# ─────────────────────────────────────────────────────────────────────
# The research brief is ~30 KB. Inline pastes get silently converted
# to attachments by both ChatGPT and Claude, and the resulting state
# is inconsistent (duplicate attachments, empty textareas). We now
# attach the brief as brief.md directly and type a short inline prompt
# that references it. This matches how the platforms actually want to
# receive long input and dodges all the paste-verification issues.
# ═════════════════════════════════════════════════════════════════════

# ── Phase-2 user-source delivery ──────────────────────────────────────────
# When P1 is skipped and the user attaches source files, those files must
# reach every P2 agent. ChatGPT/Claude attach them natively (extra_files on
# the file input); Gemini drops uploads, so it gets their text pasted under
# the brief. The files live in queues/<run>/documents/ alongside the
# synthetic brief.md + (on resume/retry) agent-written artifacts, so we
# track an explicit ALLOWLIST manifest of user-attached filenames rather
# than a brief/consolidated denylist that would sweep agent outputs.

def _p2_run_dir():
    if not _tracks_dir:
        return None
    return Path(__file__).parent / "queues" / _tracks_dir.name


def _p2_sources_manifest_path():
    rd = _p2_run_dir()
    return (rd / ".p2_sources.json") if rd else None


def _write_user_sources_manifest(names):
    """Record which documents/ files are user-attached sources. Called by
    Flow B after downloads. `attach_to_p2` stays False until the orchestrator
    confirms P1 didn't run live this session (see _finalize_p2_source_decision)."""
    mp = _p2_sources_manifest_path()
    if not mp:
        return
    try:
        data = {}
        if mp.exists():
            data = json.loads(mp.read_text(encoding="utf-8"))
        merged = list(dict.fromkeys((data.get("files") or []) + [str(n) for n in names]))
        data["files"] = merged
        data.setdefault("attach_to_p2", False)
        mp.write_text(json.dumps(data), encoding="utf-8")
    except Exception as e:
        log(f"[p2-sources] manifest write failed: {e}", "WARN")


def _finalize_p2_source_decision(attach):
    """Record the definitive 'attach user sources to P2' decision exactly once,
    just before P2 runs. `attach` should be True only when P1 did NOT run a
    live brief generation this session (P1-ON already absorbed the files into
    the ChatGPT brief — re-attaching would double-feed). Idempotent via a
    `decided` flag: a P1-ON run that pauses and resumes INTO P2 (where the P1
    block is skipped and the gate would flip) keeps its original decision."""
    mp = _p2_sources_manifest_path()
    if not mp or not mp.exists():
        return
    try:
        data = json.loads(mp.read_text(encoding="utf-8"))
        if data.get("decided"):
            return
        data["attach_to_p2"] = bool(attach) and bool(data.get("files"))
        data["decided"] = True
        mp.write_text(json.dumps(data), encoding="utf-8")
        if data["attach_to_p2"]:
            log(f"[p2-sources] {len(data['files'])} user source(s) flagged for P2 delivery")
    except Exception as e:
        log(f"[p2-sources] manifest finalize failed: {e}", "WARN")


def _read_p2_source_paths():
    """Absolute paths of user source docs to hand each P2 agent. Empty unless
    the manifest exists AND attach_to_p2 is set. Durable across pause/resume
    and hard-retry because it reads from disk, not runtime state."""
    mp = _p2_sources_manifest_path()
    rd = _p2_run_dir()
    if not mp or not rd or not mp.exists():
        return []
    try:
        data = json.loads(mp.read_text(encoding="utf-8"))
        if not data.get("attach_to_p2"):
            return []
        out = []
        for name in (data.get("files") or []):
            p = rd / "documents" / name
            if p.exists() and p.is_file():
                out.append(str(p))
        return out
    except Exception as e:
        log(f"[p2-sources] manifest read failed: {e}", "WARN")
        return []


# Per-doc + total caps so a large PDF can't blow Gemini's composer paste
# (Gemini gets pasted text, not a file attachment).
_P2_SRC_CHARS_PER_DOC = 50000
_P2_SRC_CHARS_TOTAL = 150000


def _extract_source_text(path):
    """Best-effort plaintext of a user source. md/txt read natively; pdf/docx
    via import-guarded optional libs. Returns None when text can't be
    extracted (missing lib / parse failure) — caller logs + skips that file."""
    p = Path(path)
    suf = p.suffix.lower()
    try:
        if suf in (".md", ".txt"):
            return p.read_text(encoding="utf-8", errors="replace")
        if suf == ".pdf":
            try:
                from pypdf import PdfReader
            except Exception:
                try:
                    from PyPDF2 import PdfReader  # legacy fallback name
                except Exception:
                    return None
            parts = []
            for pg in PdfReader(str(p)).pages:
                parts.append(pg.extract_text() or "")
            return "\n".join(parts)
        if suf == ".docx":
            try:
                import docx
            except Exception:
                return None
            return "\n".join(par.text for par in docx.Document(str(p)).paragraphs)
    except Exception as e:
        log(f"[p2-extract] {p.name}: {e}", "WARN")
    return None


def _augment_brief_with_sources(brief, source_paths, label):
    """Append extracted source-doc text to a brief for paste-based delivery
    (Gemini). Honors per-doc + total size caps; returns the brief unchanged
    if nothing could be inlined."""
    if not source_paths:
        return brief
    chunks = []
    total = 0
    inlined = 0
    for sp in source_paths:
        name = Path(sp).name
        txt = _extract_source_text(sp)
        if not txt or not txt.strip():
            log(f"[{label}] Source '{name}' not inlined (no extractable text — "
                f"file still reaches NotebookLM in P3)", "WARN")
            continue
        txt = txt.strip()
        if len(txt) > _P2_SRC_CHARS_PER_DOC:
            txt = txt[:_P2_SRC_CHARS_PER_DOC] + "\n…[truncated]"
            log(f"[{label}] Source '{name}' truncated to {_P2_SRC_CHARS_PER_DOC} chars for paste", "WARN")
        if total + len(txt) > _P2_SRC_CHARS_TOTAL:
            log(f"[{label}] Source paste budget reached — '{name}' and any remaining sources dropped", "WARN")
            break
        chunks.append(f"--- SOURCE DOCUMENT: {name} ---\n{txt}")
        total += len(txt)
        inlined += 1
    if not chunks:
        return brief
    log(f"[{label}] Inlined {inlined} source doc(s) ({total} chars) into brief for paste")
    header = ("\n\n══════ ATTACHED SOURCE DOCUMENTS ══════\n"
              "Below are the full contents of the source files the user attached. "
              "Use them as the primary source material for your research.\n\n")
    return brief + header + "\n\n".join(chunks)


async def attach_brief_file(browser, page, brief_path, platform, label, extra_files=None):
    """Attach brief.md (and optional extra user-supplied files) to the
    composer via the hidden file input. Returns True if at least the
    brief landed.

    extra_files: list[str] of additional paths to attach alongside the
    brief (user_sources downloaded into queue_dir/documents/). Empty/None
    keeps the legacy single-attachment behavior. Playwright's
    set_input_files takes a list and uploads all in one call — most
    composers handle that natively, but we soft-fail per-platform if
    multi-attach doesn't take."""
    extra_files = extra_files or []
    all_paths = [str(brief_path)] + [str(p) for p in extra_files]
    try:
        # Clear any residual attachments from a previous attempt
        try:
            await page.evaluate("""() => {
                document.querySelectorAll(
                    'button[aria-label*="Remove"], button[aria-label*="Delete"], ' +
                    'button[data-testid*="remove-attachment"], button[data-testid*="delete-attachment"]'
                ).forEach(b => { try { b.click(); } catch(e){} });
            }""")
            await asyncio.sleep(0.5)
        except Exception:
            pass

        # PRIMARY — hidden file input (most reliable across all platforms)
        file_input = await page.query_selector('input[type="file"]')
        if file_input:
            try:
                await file_input.set_input_files(all_paths)
                await asyncio.sleep(3)  # Wait for UI to acknowledge
                if extra_files:
                    log(f"[{label}] Brief + {len(extra_files)} user file(s) attached via hidden file input")
                else:
                    log(f"[{label}] Brief attached via hidden file input")
                return True
            except Exception as _multi_err:
                if extra_files:
                    # Multi-file may fail on platforms that allow only one
                    # input file at a time. Retry with brief alone so the
                    # phase still proceeds — extras are still on disk for
                    # P3 NLM upload.
                    log(f"[{label}] Multi-file attach failed ({_multi_err}); retrying with brief only", "WARN")
                    await file_input.set_input_files(str(brief_path))
                    await asyncio.sleep(3)
                    log(f"[{label}] Brief attached (extras dropped — will reach NLM via P3)")
                    return True
                raise

        # FALLBACK — queue file for OS-level chooser then click attach
        # (single-file path; extras can't be plumbed through this branch).
        browser.set_upload_file(str(brief_path))
        for sel in ['button[aria-label*="Attach"]', 'button[aria-label*="Upload"]',
                    'button[data-testid*="upload"]', 'button[data-testid*="file"]']:
            try:
                btn = await page.query_selector(sel)
                if btn and await btn.is_visible():
                    await btn.click()
                    await asyncio.sleep(3)
                    browser.clear_upload_file()
                    log(f"[{label}] Brief attached via button click")
                    return True
            except Exception:
                continue
        browser.clear_upload_file()
        log(f"[{label}] Could not find file input or attach button", "WARN")
        return False
    except Exception as e:
        try: browser.clear_upload_file()
        except Exception: pass
        log(f"[{label}] Brief attach failed: {e}", "WARN")
        return False


async def type_short_inline_prompt(page, platform, label):
    """Type a short inline prompt instructing the agent to research the
    attached brief. Keeps the platform's 'Deep Research' mode as the
    operative instruction; the full brief content lives in the file."""
    # One message, short enough that no platform converts it to an attachment.
    prompt = (
        "Please perform deep research on the topic described in the attached brief. "
        "Use the brief as the complete context — objectives, scope, sections, sources to target. "
        "Produce a comprehensive research report with citations."
    )
    try:
        # Find the composer input (contenteditable or textarea) and type
        for sel in ['div[contenteditable="true"]', 'textarea', '.ProseMirror',
                    '[role="textbox"]', '[aria-label*="message"]']:
            try:
                inp = await page.query_selector(sel)
                if inp:
                    await inp.click()
                    await asyncio.sleep(0.3)
                    await page.keyboard.type(prompt, delay=5)
                    await asyncio.sleep(0.5)
                    log(f"[{label}] Inline prompt typed ({len(prompt)} chars)")
                    return True
            except Exception:
                continue
        log(f"[{label}] Could not find composer input for inline prompt", "WARN")
        return False
    except Exception as e:
        log(f"[{label}] Inline prompt type failed: {e}", "WARN")
        return False


async def ensure_deep_mode_active(page, platform, label) -> dict:
    """Just-before-send check: is the platform still in its required mode?
    Re-activates if it has been toggled off, then RE-EVALUATES state and
    returns it.

    E2 / DGOPS-7364 — return type was always-True; now returns a state
    dict so the caller can gate Send on whether the required mode is
    genuinely active (Claude specifically can fail Layer 1 + Layer 2 +
    re-activation and still arrive here with research=False; old code
    sent anyway, producing chat-mode output).

    Returns:
        {"platform": "chatgpt"|"gemini"|"claude",
         "active": bool,                # platform-specific overall flag
         # Claude only:
         "hasExtended": bool, "researchOn": bool}

    Errors are logged and treated as active=True (don't block the send
    on a measurement failure — measurement bugs shouldn't gate Send).
    The Claude branch is the only one whose caller actually gates on
    the result for now per DGOPS-7364 scope."""
    platform_l = platform.lower()
    try:
        if platform_l == "chatgpt":
            # 2026-05-29 (#709): return the REAL measured state (was always
            # active=True, so the caller could never gate the send). The prior
            # check also fell back to `body.innerText.includes('deep research')`
            # — a tooltip/help mention false-positived it. Scope the pill scan
            # to the composer/form; pill VISIBLE in the composer is ChatGPT's
            # active-DR signal (same as setup_chatgpt_dr Step 3).
            _cgpt_state_js = """() => {
                const norm = s => (s || '').replace(/\\s+/g, ' ').trim().toLowerCase();
                const form = document.querySelector('form') || document.body;
                let pillVisible = false;
                for (const p of form.querySelectorAll('button, [role="button"], span, div')) {
                    if (!p.offsetParent) continue;
                    const t = norm(p.textContent);
                    if (t === 'deep research') { pillVisible = true; break; }
                }
                let placeholder = '';
                const ta = document.querySelector('#prompt-textarea, textarea, [contenteditable="true"]');
                if (ta) placeholder = norm(ta.getAttribute('placeholder') || ta.getAttribute('data-placeholder'));
                return { active: pillVisible || placeholder.includes('research'),
                         pillVisible, placeholder: placeholder.slice(0, 60) };
            }"""
            state = await page.evaluate(_cgpt_state_js)
            if not state.get("active"):
                log(f"[{label}] ChatGPT Deep Research OFF before send "
                    f"(pillVisible={state.get('pillVisible')}) — re-activating", "WARN")
                await setup_chatgpt_dr(page)
                state = await page.evaluate(_cgpt_state_js)
                log(f"[{label}] ChatGPT DR post-re-activate: active={state.get('active')}", "INFO")
            return {"platform": "chatgpt", "active": bool(state.get("active"))}
        if platform_l == "gemini":
            # 2026-05-29 (#709): return the REAL state (was always active=True),
            # using the SHARED _GEMINI_DR_STATE_JS (composer-placeholder
            # authoritative) so this pre-send check and setup_gemini_dr's verify
            # agree exactly. A present-but-inactive pill must NOT read as active.
            st = await page.evaluate(_GEMINI_DR_STATE_JS)
            active = bool(st.get("placeholderResearch") or st.get("pressed"))
            if not active:
                log(f"[{label}] Gemini Deep Research not active before send "
                    f"(placeholder={st.get('placeholder')!r}) — re-activating", "WARN")
                await setup_gemini_dr(page)
                st = await page.evaluate(_GEMINI_DR_STATE_JS)
                active = bool(st.get("placeholderResearch") or st.get("pressed"))
                log(f"[{label}] Gemini DR post-re-activate: active={active} "
                    f"placeholder={st.get('placeholder')!r}", "INFO")
            return {"platform": "gemini", "active": active}
        if platform_l == "claude":
            # Check BOTH: high-tier Opus model AND Research tool are on.
            _claude_state_js = """() => {
                const txt = (document.body.innerText || '').toLowerCase();
                // 2026-05-28: the UI dropped the word "Extended" — the model
                // button now reads "Opus 4.8 Max" and Adaptive shows as a
                // "Thinking" toggle behind the popover. A body-wide "extended"
                // scan was therefore ALWAYS false → a needless re-activation on
                // EVERY Claude send (backend.log 49728). Read the model-selector
                // button instead: Opus >= 4.8 showing == the high-tier model is
                // active. (Adaptive/effort live behind the closed popover and are
                // confirmed by the CUA validate layer, not gated here.)
                const verOf = t => {
                    const m = (t || '').match(/opus[^0-9]*([0-9]+(?:\\.[0-9]+)?)/i);
                    return m ? parseFloat(m[1]) : null;
                };
                // Read the composer's model-selector TRIGGER button only —
                // EXCLUDE any Opus option rendered inside an open dropdown/menu
                // (a stale "Opus 4.8" menu item while the current model is 4.7
                // would otherwise false-positive). The trigger lives outside any
                // [role=menu]/[role=listbox]/[role=dialog] popover.
                const hasExtended = [...document.querySelectorAll('button, [role="button"]')]
                    .filter(b => !b.closest('[role="menu"], [role="listbox"], [role="dialog"]'))
                    .some(b => { const v = verOf(b.textContent); return v !== null && v >= 4.8; });
                // Research tool shows as a magnifying-glass icon / label near composer
                const researchOn = Array.from(document.querySelectorAll('button, [role="button"]'))
                    .some(b => {
                        const t = (b.textContent || '').toLowerCase();
                        const a = (b.getAttribute('aria-label') || '').toLowerCase();
                        return (t.includes('research') || a.includes('research')) &&
                               (b.getAttribute('aria-pressed') === 'true' ||
                                b.getAttribute('data-state') === 'on' ||
                                b.classList.contains('active') ||
                                b.classList.contains('selected'));
                    });
                return { hasExtended, researchOn };
            }"""
            state = await page.evaluate(_claude_state_js)
            if not state.get("hasExtended") or not state.get("researchOn"):
                log(f"[{label}] Claude mode regressed before send "
                    f"(extended={state.get('hasExtended')}, research={state.get('researchOn')}) — re-activating", "WARN")
                await setup_claude_dr(page)
                # E2 — re-evaluate AFTER the re-activation attempt so the
                # caller sees the actual final state, not the pre-fix one.
                # If Step 3A/3B selectors are still broken, researchOn will
                # remain False and the caller pauses for user decision.
                state = await page.evaluate(_claude_state_js)
                log(f"[{label}] Claude mode post-re-activate: "
                    f"extended={state.get('hasExtended')}, research={state.get('researchOn')}", "INFO")
            ok = bool(state.get("hasExtended") and state.get("researchOn"))
            return {"platform": "claude", "active": ok,
                    "hasExtended": bool(state.get("hasExtended")),
                    "researchOn": bool(state.get("researchOn"))}
    except Exception as e:
        log(f"[{label}] ensure_deep_mode_active error: {e}", "WARN")
    return {"platform": platform_l, "active": True}


async def detect_human_verification(page, platform: str, label: str) -> tuple[bool, str]:
    """Detect if the current page is blocked by a human-verification challenge.

    Looks for the most common gates Claude / ChatGPT / Gemini use when they
    flag the automated browser:
      - Cloudflare Turnstile ("Just a moment..." / iframe[src*=challenges])
      - Generic CAPTCHA iframes (reCAPTCHA, hCaptcha)
      - Claude's own "Verify you are human" interstitial
      - Anthropic's "Checking your browser" intermediate page

    Returns (blocked, reason). `reason` is a short, user-readable string like
    "Cloudflare challenge" or "reCAPTCHA" — safe to surface in a chat banner.

    Never raises — on any detection error, returns (False, "").
    """
    try:
        result = await page.evaluate("""() => {
            const findings = [];
            const text = (document.body?.innerText || '').toLowerCase();

            // Cloudflare Turnstile / "Just a moment..."
            if (document.querySelector('iframe[src*="challenges.cloudflare.com"], iframe[src*="turnstile"], .cf-turnstile, .cf-challenge')) {
                findings.push('Cloudflare');
            }
            if (text.includes('just a moment') && text.includes('cloudflare')) {
                findings.push('Cloudflare');
            }
            if (text.includes('checking your browser') || text.includes('checking if the site connection is secure')) {
                findings.push('Cloudflare');
            }

            // Google reCAPTCHA
            if (document.querySelector('iframe[src*="recaptcha"], .g-recaptcha, #recaptcha')) {
                findings.push('reCAPTCHA');
            }

            // hCaptcha
            if (document.querySelector('iframe[src*="hcaptcha"], .h-captcha')) {
                findings.push('hCaptcha');
            }

            // Claude / Anthropic human-verification interstitials
            if (text.includes('verify you are human') || text.includes('are you a human') ||
                text.includes('please complete the security check') ||
                text.includes('press and hold') || text.includes('tap and hold')) {
                findings.push('Claude human verification');
            }

            // Generic "blocked" / access-denied pages that we should surface
            if (text.includes('access denied') && text.length < 1000) {
                findings.push('Access denied');
            }

            return { findings: [...new Set(findings)] };
        }""")
        findings = result.get("findings", []) if isinstance(result, dict) else []
        if findings:
            return True, findings[0]
        return False, ""
    except Exception as e:
        log(f"[{label}] human-verification detect error: {e}", "WARN")
        return False, ""


async def detect_session_expiry(page, platform: str, label: str) -> tuple[bool, str]:
    """Detect if an agent page has lost its session mid-run (redirect to
    login URL, login form appeared, or "sign in to continue" message).

    Distinct from detect_human_verification — that handles CAPTCHA / Cloudflare.
    This handles actual logged-out state where the user needs to re-authenticate
    on their PC before the pipeline can resume.

    Returns (expired, reason). Never raises."""
    try:
        url = (page.url or "").lower()
        # URL markers for known login routes per platform
        url_markers = {
            "chatgpt":    ("/auth/login", "/auth/signin", "auth.openai.com"),
            "gemini":     ("accounts.google.com/signin", "accounts.google.com/serviceLogin"),
            "claude":     ("/login", "/sign-in", "/auth/"),
            "notebooklm": ("accounts.google.com/signin", "accounts.google.com/serviceLogin"),
        }
        markers = url_markers.get(platform.lower(), ("/login", "/signin", "/signup"))
        if any(m in url for m in markers):
            return True, f"redirect_to_login_url"

        # DOM markers: visible password field + no active chat UI
        result = await page.evaluate("""() => {
            const pwInput = document.querySelector('input[type="password"]:not([style*="display: none"])');
            if (!pwInput) return { expired: false };
            // Heuristic: if there's a visible password input AND no chat composer/send button,
            // we're on a login page. Use offsetParent check to filter hidden elements.
            if (pwInput.offsetParent === null) return { expired: false };
            const hasComposer = document.querySelector(
                '[data-testid="send-button"], button[aria-label*="Send prompt"], ' +
                'div[contenteditable="true"]#prompt-textarea, ' +
                'textarea[placeholder*="Message"], [data-test-id="send-button"]'
            );
            if (hasComposer) return { expired: false };
            const text = (document.body.innerText || '').toLowerCase();
            const loginPhrases = ['sign in to', 'log in to', 'please sign in',
                'welcome back', 'enter your password', 'email address'];
            const hasLoginText = loginPhrases.some(p => text.includes(p));
            return { expired: hasLoginText };
        }""")
        if isinstance(result, dict) and result.get("expired"):
            return True, "login_form_appeared"
        return False, ""
    except Exception as e:
        log(f"[{label}] session-expiry detect error: {e}", "WARN")
        return False, ""


async def _playwright_hv_click(page, label: str) -> bool:
    """Cheap DOM-based HV click. Returns True iff we actually clicked
    something. No budget for image-puzzles — those fall through to CUA.

    NEVER-DIE-MIGRATION-2026-04-18: Tier 0 of the HV chain. Cloudflare
    Turnstile is cross-origin-iframe'd so we can't touch its DOM, but we
    can mouse.click at the checkbox's known position inside the iframe.
    For in-page 'Verify you are human' / 'Continue' buttons, plain
    locator clicks work."""
    # Cloudflare Turnstile — checkbox inside a cross-origin iframe.
    try:
        cf = page.locator(
            'iframe[src*="challenges.cloudflare.com"], iframe[src*="turnstile"]'
        ).first
        if await cf.count() > 0:
            box = await cf.bounding_box()
            if box:
                # The checkbox sits ~30px in from the iframe's left edge,
                # vertically centered. Cross-origin body is unreachable
                # but mouse events at page coordinates land inside it.
                cx = box["x"] + 30
                cy = box["y"] + box["height"] / 2
                await page.mouse.click(cx, cy)
                log(f"[{label}] Playwright: clicked Turnstile checkbox at ({cx:.0f},{cy:.0f})")
                return True
    except Exception as e:
        log(f"[{label}] Playwright Turnstile click errored: {e}", "WARN")
    # In-page 'Verify you are human' / 'Continue' / 'I am human' buttons.
    for sel in (
        'button:has-text("Verify you are human")',
        'button:has-text("I am human")',
        'button:has-text("I\'m human")',
        'button:has-text("Continue")',
    ):
        try:
            loc = page.locator(sel).first
            if await loc.count() > 0 and await loc.is_visible():
                await loc.click(timeout=3000)
                log(f"[{label}] Playwright: clicked '{sel}'")
                return True
        except Exception:
            continue
    return False


async def wait_for_verification_clearance(browser, cua_client, page, platform: str, label: str,
                                          verbose=False, max_wait_loops: int = 120,
                                          phase: int = 2) -> bool:
    """Handle a human-verification gate on an agent page.

    Flow (NEVER-DIE-MIGRATION-2026-04-18, full HV chain):
      0. Playwright cheap-click — cross-origin iframe click on the
         Turnstile checkbox, or in-page 'Verify you are human' button.
         Zero CUA budget; most Cloudflare checkboxes clear here.
      1. CUA in-place (3 iter) — vision click for whatever Playwright
         missed. Silent on success.
      2. 3-minute cooldown + page reload — lets Cloudflare's bot score
         decay, re-runs stealth init against a fresh document.
      3. CUA retry (5 iter) — second pass on the reloaded page.
      4. Kill-tab — close the page, open a fresh tab at the same URL.
         A new cookie jar + clean document sometimes clears a stuck
         session that the reload alone couldn't.
      5. User pause — human_verification_required alert with
         Resume / Skip agent. Polls every 5s so a manual solve auto-
         resumes even if the user never taps Resume.

    `phase` parameter routes all emit_event calls to the correct phase tile
    in the frontend — default 2 for Phase 2 agents, pass 1/3/4/5 when
    calling from other phase handlers.
    """
    # Detect the specific challenge for banner copy AND to confirm there
    # IS one to solve before bothering CUA.
    _, reason = await detect_human_verification(page, platform, label)
    platform_key = platform.lower()

    # ── Tier 0: Playwright cheap-click ──
    # Most Cloudflare gates are a single checkbox. A direct Playwright
    # click clears them for zero CUA cost. Keep the banner subtle here —
    # only escalate to "retrying" alert if this attempt fails.
    try:
        clicked = await _playwright_hv_click(page, label)
        if clicked:
            await asyncio.sleep(3)
            blocked, _ = await detect_human_verification(page, platform, label)
            if not blocked:
                log(f"[{label}] Playwright cleared verification ✓ — CUA not needed")
                emit_event("agent_verified", phase=phase, agent=platform_key)
                return True
            log(f"[{label}] Playwright click didn't clear — escalating to CUA", "WARN")
    except Exception as e:
        log(f"[{label}] Playwright HV tier errored: {e} — escalating to CUA", "WARN")

    # ── CUA fallback — first pass (in place, 3 iterations) ──
    # Most Turnstile gates are a single "I am human" checkbox that CUA can
    # click. This keeps us silent in the common case. Only if it can't do we
    # cool down + reload and try once more, or (last) ask the user.
    sys_prompt = (
        "You are looking at a human-verification challenge (Cloudflare, CAPTCHA, or similar) "
        "that is blocking access to an AI agent. If you can see a simple checkbox or button labeled "
        "something like 'I am human', 'Verify', 'Continue', or 'Not a robot' — click it once. "
        "Do NOT try to solve image-selection puzzles or anything requiring complex reasoning. "
        "If there's nothing simple to click, STOP immediately and respond with the word 'blocked'."
    )
    user_prompt = "Click the single human-verification checkbox if one is visible. Otherwise stop and say 'blocked'."
    try:
        log(f"[{label}] Verification detected ({reason or 'unknown'}) — CUA fallback (3 iter, in place)…")
        await browser.switch_to_page(page)
        result = await agent_loop(cua_client, browser, sys_prompt, user_prompt,
            model=CUA_MODEL, max_iterations=3, verbose=verbose)
        # Give the page a moment to re-render after a successful click
        await asyncio.sleep(3)
        blocked, _ = await detect_human_verification(page, platform, label)
        if not blocked:
            log(f"[{label}] CUA cleared verification ✓ — proceeding silently")
            # Clear the dropdown badge immediately so the user sees recovery.
            emit_event("agent_verified", phase=phase, agent=platform_key)
            return True
        _cua_text = (result.get("text") or "")[:120]
        log(f"[{label}] CUA first pass didn't clear ({_cua_text}) — cooldown + reload + retry", "WARN")
    except Exception as e:
        log(f"[{label}] CUA first pass errored: {e} — cooldown + reload + retry", "WARN")

    # ── CUA fallback — second pass (cooldown + reload, 5 iterations) ──
    # Cloudflare's bot-score heuristic partially decays with time, and a clean
    # page navigation (blank → original URL) re-runs the stealth init script
    # against a fresh document, which often defuses a recently-flagged session.
    # If Turnstile still fires, CUA gets more iterations this time around
    # since it's our last auto-resort before bothering the user.
    try:
        original_url = page.url
        log(f"[{label}] CUA fallback retry: blank → 3 min cooldown → reload → CUA (5 iter)…")
        try:
            await page.goto("about:blank", wait_until="domcontentloaded", timeout=10000)
        except Exception:
            pass
        await asyncio.sleep(180)
        try:
            await page.goto(original_url, wait_until="domcontentloaded", timeout=30000)
            await asyncio.sleep(4)
        except Exception as e:
            log(f"[{label}] Reload failed: {e} — escalating to user", "WARN")

        blocked, _ = await detect_human_verification(page, platform, label)
        if blocked:
            log(f"[{label}] Turnstile still present after cooldown — CUA 5-iter retry")
            await browser.switch_to_page(page)
            await agent_loop(cua_client, browser, sys_prompt, user_prompt,
                model=CUA_MODEL, max_iterations=5, verbose=verbose)
            await asyncio.sleep(3)
            blocked, _ = await detect_human_verification(page, platform, label)

        if not blocked:
            # Page just reloaded — re-run platform-specific setup so the
            # caller's subsequent paste/send logic still finds Deep Research
            # pill / Opus Adaptive + Research tool / Pro Extended Thinking
            # active on the fresh page.
            log(f"[{label}] CUA retry cleared verification ✓ — re-running setup")
            emit_event("agent_verified", phase=phase, agent=platform_key)
            pl = platform.lower()
            try:
                if pl == "claude":
                    await setup_claude_dr(page)
                elif pl == "gemini":
                    await setup_gemini_dr(page)
                elif pl == "chatgpt":
                    await setup_chatgpt_dr(page)
            except Exception as e:
                log(f"[{label}] Post-clear setup re-run warning: {e}", "WARN")
            return True
        log(f"[{label}] CUA retry still blocked — escalating to tab-kill", "WARN")
    except Exception as e:
        log(f"[{label}] CUA retry errored: {e} — escalating to tab-kill", "WARN")

    # ── Tier 4: Kill the tab, open a fresh one ──
    # NEVER-DIE-MIGRATION-2026-04-18: Last automated tier before
    # surfacing to the user. Close + reopen the page — a fresh cookie
    # context and clean document layout occasionally clears a stubborn
    # bot flag that the cooldown + reload couldn't. Cheap insurance
    # before we interrupt the user.
    try:
        original_url = page.url
        log(f"[{label}] CUA exhausted — killing the tab and re-opening for a clean slate")
        try:
            await page.close()
        except Exception:
            pass
        page = await browser.new_tab(original_url)
        await asyncio.sleep(4)
        blocked, _ = await detect_human_verification(page, platform, label)
        if not blocked:
            log(f"[{label}] Fresh tab cleared verification ✓ — re-running setup")
            emit_event("agent_verified", phase=phase, agent=platform_key)
            pl = platform.lower()
            try:
                if pl == "claude":
                    await setup_claude_dr(page)
                elif pl == "gemini":
                    await setup_gemini_dr(page)
                elif pl == "chatgpt":
                    await setup_chatgpt_dr(page)
            except Exception as e:
                log(f"[{label}] Post-kill-tab setup re-run warning: {e}", "WARN")
            return True
        log(f"[{label}] Fresh tab still blocked — escalating to user", "WARN")
    except Exception as e:
        log(f"[{label}] Kill-tab tier errored: {e} — escalating to user", "WARN")

    # ── User manual fallback — pause pipeline, banner with Resume/Skip ──
    log(f"[{label}] HUMAN VERIFICATION REQUIRED — {reason or 'unknown challenge'} — pausing pipeline", "WARN")
    _hv_alert_id = f"phase{phase}_human_verify_{platform_key}"
    _hv_msg = f"{platform.capitalize()} is asking for human verification. I tried and couldn't clear it — solve it in the browser and tap Resume, or Skip this agent."
    emit_event("human_verification_required", phase=phase, agent=platform_key,
               platform=platform_key,
               platformLabel=platform.capitalize(),
               reason=reason or "Human verification challenge",
               message=_hv_msg,
               alert_id=_hv_alert_id)
    # DGOPS-7710-followup: pause with explicit reason + target agent so the
    # CLI dispatcher's `s` can target THIS platform via request_skip_agent
    # (the poll loop below checks skipped_agents; without target_agent, CLI
    # `s` sets skipped_phases — wrong set — and silently does nothing).
    _controls.pause_target_agent = (platform_key or "").strip().lower()
    _controls.request_pause("human_verification_required")
    emit_event("pipeline_paused", phase=phase, reason="human_verification_required", agent=platform_key)
    # #710 parity: durable mirror so opening this chat re-surfaces the
    # Resume/Skip card even if it wasn't the viewed tab when HV fired.
    # Cleared on the pipeline_resumed/stopped this gate emits when it unblocks.
    _persist_pending_decision({
        "kind": "human_verification_required",
        "phase": phase,
        "agent": platform_key,
        "platformLabel": platform.capitalize(),
        "reason": reason or "Human verification challenge",
        "message": _hv_msg,
        "alert_id": _hv_alert_id,
    })

    # Poll every 5s — if the user solves the challenge without tapping Resume,
    # we still notice and auto-continue. Also yields to stop/skip/resume signals.
    for _ in range(max_wait_loops):
        await asyncio.sleep(5)
        if _controls.is_stop():
            emit_event("pipeline_stopped", phase=phase, reason="stopped during human_verification", agent=platform_key)
            return False
        # User tapped "Skip agent" in the banner → drop this agent cleanly
        if platform_key in _controls.skipped_agents:
            _controls.skipped_agents.discard(platform_key)
            log(f"[{label}] User chose Skip agent during human verification — dropping {platform_key}", "INFO")
            emit_event("agent_skipped", phase=phase, agent=platform_key,
                       reason="human_verification_skipped")
            # status="skipped" auto-persisted by emit_event hook.
            emit_event("pipeline_resumed", phase=phase, reason="skip_agent_during_verification", agent=platform_key)
            _controls.request_resume()
            return False
        if not _controls.is_pause():
            # User tapped Resume — verify the challenge is actually cleared
            blocked, _ = await detect_human_verification(page, platform, label)
            if blocked:
                log(f"[{label}] Resume tapped but verification still present — re-pausing", "WARN")
                emit_event("human_verification_required", phase=phase, agent=platform_key,
                           platform=platform_key,
                           platformLabel=platform.capitalize(),
                           reason=reason or "Human verification challenge",
                           message=f"{platform.capitalize()} still shows verification. Solve it first, then Resume.",
                           alert_id=_hv_alert_id)
                # Re-set target_agent (request_resume cleared it on the
                # initial resume) so CLI `s` still targets this platform.
                _controls.pause_target_agent = (platform_key or "").strip().lower()
                _controls.request_pause("human_verification_required")
                continue
            log(f"[{label}] Verification cleared ✓")
            emit_event("pipeline_resumed", phase=phase, reason="human_verification_cleared", agent=platform_key)
            return True
        # Auto-detect clearance even without explicit resume
        blocked, _ = await detect_human_verification(page, platform, label)
        if not blocked:
            log(f"[{label}] Verification auto-cleared ✓")
            _controls.request_resume()
            emit_event("pipeline_resumed", phase=phase, reason="human_verification_cleared", agent=platform_key)
            return True

    log(f"[{label}] Human verification timed out ({max_wait_loops * 5}s) — skipping agent", "WARN")
    # #710: this timeout exit drops the agent WITHOUT emitting
    # pipeline_resumed/stopped, so the universal emit_event clear never fires —
    # retract the durable mirror here (load-bearing, like the login
    # skip_init_verify break) so a cold chat-open can't paint a ghost
    # "needs human verification" card for an agent that already timed out.
    _clear_pending_decision()
    return False


async def check_hv_gate(browser, cua_client, platform: str, label: str,
                         phase: int, verbose: bool = False) -> bool:
    """Early HV (human-verification) gate detection + clearance.

    Call this right after `browser.navigate(url)` in any phase handler. If
    the landing page is behind a Cloudflare / CAPTCHA / "verify you are
    human" gate, we resolve it BEFORE spending CUA budget on the phase's
    actual work (selector clicks, prompt submission, etc.) — those would
    fail anyway on a blocked page and burn rate-limit / workspace quota.

    Returns True if the gate is clear (either was never there, or we
    cleared it via CUA / user pause-resume). Returns False if the gate
    couldn't be cleared — caller should abort the phase cleanly.

    Historically only Phase 2 used this; ports to P1/P3/P4/P5 mirror
    `start_agent_no_gemini_wait` but scope events to the caller's phase."""
    try:
        blocked, reason = await detect_human_verification(browser.page, platform, label)
    except Exception as e:
        log(f"[{label}] HV detection errored ({e}) — assuming clear", "WARN")
        return True
    if not blocked:
        return True
    log(f"[{label}] Phase {phase}: HV gate detected ({reason or 'unknown'}) — clearing before phase work", "WARN")
    try:
        return await wait_for_verification_clearance(
            browser, cua_client, browser.page,
            platform=platform, label=label,
            verbose=verbose, phase=phase,
        )
    except Exception as e:
        log(f"[{label}] wait_for_verification_clearance errored: {e}", "WARN")
        return False


async def _try_inpage_retry_on_research_fail(page, platform, label, max_wait_s=20):
    """Detect the agent's own in-page Retry button after Send and click it once.

    When Deep Research kicks off but immediately fails (rate limit, internal
    error, brief-parse failure), the agent UI shows a 'Research stopped' /
    'Research failed' / 'Something went wrong' message with a Retry (or
    Regenerate / Try again) button right below it in the assistant area.
    This guard auto-clicks that button ONCE so the round-robin watchdog
    doesn't have to escalate to a human-intervention alert for what is
    effectively a transient agent-side glitch.

    Scope:
      - Only fires when the page actually shows failure-message text — no
        click happens on a healthy research start.
      - Buttons must live inside an assistant message area (not composer /
        toolbar / footer), with aria-label or text matching retry words.
      - Single click per call; idempotent.

    Returns True if a button was clicked, False otherwise. Wayland-safe
    (pure DOM click, no clipboard reads)."""
    platform_l = (platform or "").lower()
    deadline = asyncio.get_event_loop().time() + max_wait_s
    poll_n = 0
    # Failure-message regex — covers ChatGPT / Claude / Gemini wording
    # variants seen across recent runs. Word-boundary-loose because some
    # UIs render the text with extra punctuation.
    fail_re = (
        r"research\\s+stopped|research\\s+failed|"
        r"failed\\s+to\\s+(?:generate|complete|run|continue)|"
        r"something\\s+went\\s+wrong|encountered\\s+an?\\s+(?:issue|error)|"
        r"unable\\s+to\\s+(?:continue|complete|generate)|"
        r"couldn'?t\\s+complete|response\\s+stopped|"
        r"this\\s+research\\s+(?:was\\s+)?(?:stopped|interrupted)|"
        r"sorry,?\\s+(?:i'?m\\s+|i\\s+)?can'?t\\s+help|"
        r"i\\s+can'?t\\s+help\\s+(?:you\\s+)?with\\s+that|"
        r"can'?t\\s+help\\s+(?:you\\s+)?with\\s+that\\s+at\\s+this\\s+time|"
        r"i'?m\\s+(?:unable|not\\s+able)\\s+to\\s+help"
    )
    while asyncio.get_event_loop().time() < deadline:
        poll_n += 1
        try:
            clicked = await page.evaluate(
                f"""() => {{
                    const failPattern = new RegExp(`{fail_re}`, 'i');
                    // 2026-05-14: dropped 'resume' — too generic, could match
                    // Claude's resume-conversation button (unrelated to
                    // research-fail recovery).
                    const retryWords = /(?:^|\\s)(retry|regenerate|try\\s+again|rerun|restart)\\b/i;
                    const isInComposerOrToolbar = (el) => !!el.closest(
                        '[data-testid*="composer"], [data-testid*="prompt-textarea"], ' +
                        '[contenteditable="true"], form[data-message-id], ' +
                        '[role="toolbar"], footer, [class*="composer" i], ' +
                        '[class*="input-area" i], [class*="message-input" i]'
                    );
                    const isAssistantScoped = (el) => !!el.closest(
                        '[data-message-author-role="assistant"], .font-claude-message, ' +
                        '[data-testid*="conversation-turn"], ' +
                        // Gemini custom-element + class selectors for the model
                        // response bubble. Without these the refusal-text
                        // assistant-scope check returned false and the function
                        // skipped the regenerate-button click that the soft-
                        // refusal regex had just matched.
                        'message-content, model-response, ' +
                        '.model-response-text, .response-container'
                    );
                    const isVisible = (el) => {{
                        const r = el.getBoundingClientRect();
                        if (r.width < 16 || r.height < 16) return false;
                        const cs = getComputedStyle(el);
                        if (cs.display === 'none' || cs.visibility === 'hidden') return false;
                        if (parseFloat(cs.opacity) < 0.1) return false;
                        return true;
                    }};
                    // First confirm the failure-text actually shows on the page.
                    // No fail-text → not the failure case this guard is for.
                    const bodyText = document.body ? (document.body.innerText || '') : '';
                    if (!failPattern.test(bodyText)) return '';
                    const btns = Array.from(document.querySelectorAll('button, [role="button"]'));
                    for (const b of btns) {{
                        if (isInComposerOrToolbar(b)) continue;
                        if (!isVisible(b)) continue;
                        const aria = (b.getAttribute('aria-label') || '').toLowerCase();
                        const txt = (b.textContent || '').trim().toLowerCase();
                        if (!(retryWords.test(aria) || retryWords.test(txt))) continue;
                        // Require either assistant-scope OR a fail-text token
                        // inside the nearest block. Without one of those a
                        // composer regenerate icon outside the toolbar can
                        // sneak through.
                        if (!isAssistantScoped(b)) {{
                            const parent = b.closest('div, section, article, li, [role="dialog"]');
                            if (!parent || !failPattern.test(parent.innerText || '')) continue;
                        }}
                        b.click();
                        return aria || txt || 'matched';
                    }}
                    return '';
                }}"""
            )
            if clicked:
                log(f"[{label}] In-page Retry auto-clicked: '{clicked}' (poll {poll_n})", "INFO")
                try:
                    emit_event("inpage_retry_clicked", phase=2, agent=platform_l,
                               match=str(clicked)[:60])
                except Exception:
                    pass
                return True
        except Exception as _pe:
            log(f"[{label}] In-page retry probe raised: {_pe}", "DEBUG")
        await asyncio.sleep(1.5)
    return False


async def start_agent_no_gemini_wait(browser, cua_client, url, prompt_system, prompt_user,
                                     brief, label, platform, verbose=False,
                                     brief_path=None, source_paths=None):
    """Start agent: open tab → Playwright-direct setup → CUA validation → paste brief → submit.

    source_paths: user-attached source docs (skip-P1 flow). ChatGPT/Claude
    attach them natively alongside the brief; Gemini gets their text pasted
    (it silently drops file uploads). Empty/None = legacy behavior.

    Two-layer setup for reliability:
    1. Playwright clicks known selectors (fast, deterministic when UI is stable)
    2. CUA visually validates the intended state and fixes discrepancies
    """
    log(f"[{label}] Opening {url}...")
    page = await browser.new_tab(url)
    await asyncio.sleep(4)

    # LAYER 0: Detect human-verification gates BEFORE Playwright setup tries to
    # click selectors that don't exist under a Cloudflare / CAPTCHA overlay.
    # If a challenge is present, pause the pipeline and let the user solve it
    # in the browser, then auto-resume when cleared.
    platform_l = platform.lower()
    blocked, reason = await detect_human_verification(page, platform, label)
    if blocked:
        cleared = await wait_for_verification_clearance(browser, cua_client, page, platform, label, verbose=verbose)
        if not cleared:
            fail_agent(platform_l,
                       f"Couldn't clear human verification for {platform.capitalize()}",
                       "The human-verification challenge couldn't be cleared. Retry to relaunch the agent; Skip to drop it.")
            return page, False
        # Settle after clearance — page often reloads to the real content
        await asyncio.sleep(2)

    # LAYER 0.5 (Gemini-only): force fresh chat. `https://gemini.google.com`
    # natural-redirects to `/app` and Google then auto-routes to the most
    # recent `/app/<chat-id>` for accounts with history. Pasting the brief
    # into a past conversation produces the "stuck in past run" symptom
    # (Gemini answers in the old thread's context, the new run inherits
    # stale state, and detect_completion can fire on the prior turn's
    # Share button). Click "New chat" if URL has a chat id; fall back to
    # a direct nav to /app so we always land on a clean composer.
    if platform_l == "gemini":
        try:
            cur_url = (page.url or "").lower().rstrip("/")
            if "/app/" in cur_url and not cur_url.endswith("/app"):
                log(f"[{label}] Detected past-chat URL ({cur_url}) — forcing New chat")
                clicked = await page.evaluate("""() => {
                    const sel = 'button[aria-label*="New chat" i], a[aria-label*="New chat" i]';
                    const btn = document.querySelector(sel);
                    if (btn && btn.offsetParent !== null) { btn.click(); return true; }
                    for (const el of document.querySelectorAll('button, a, [role="button"]')) {
                        const t = (el.textContent || '').trim().toLowerCase();
                        if (t === 'new chat' && el.offsetParent !== null) { el.click(); return true; }
                    }
                    return false;
                }""")
                if clicked:
                    await asyncio.sleep(2)
                cur2 = (page.url or "").lower().rstrip("/")
                if "/app/" in cur2 and not cur2.endswith("/app"):
                    log(f"[{label}] Still on past chat ({cur2}) — direct nav to /app", "INFO")
                    try:
                        await page.goto("https://gemini.google.com/app")
                        await asyncio.sleep(3)
                    except Exception as _ne:
                        log(f"[{label}] Direct /app nav failed: {_ne}", "WARN")
                else:
                    log(f"[{label}] Fresh chat confirmed ({cur2 or 'unknown'})")
        except Exception as _fe:
            log(f"[{label}] Fresh-chat guard errored (continuing): {_fe}", "WARN")

    # LAYER 1: Playwright-direct setup first
    setup_ok = False
    if platform_l == "chatgpt":
        setup_ok = await setup_chatgpt_dr(page)
    elif platform_l == "gemini":
        setup_ok = await setup_gemini_dr(page)
    elif platform_l == "claude":
        setup_ok = await setup_claude_dr(page)

    # After Playwright tried to set up: if setup failed AND verification is now
    # visible (it can appear mid-setup when Claude's automation detection trips),
    # pause and wait before falling back to CUA.
    if not setup_ok:
        blocked, _ = await detect_human_verification(page, platform, label)
        if blocked:
            cleared = await wait_for_verification_clearance(browser, cua_client, page, platform, label, verbose=verbose)
            if not cleared:
                fail_agent(platform_l,
                           f"Couldn't clear human verification for {platform.capitalize()}",
                           "The human-verification challenge couldn't be cleared. Retry to relaunch the agent; Skip to drop it.")
                return page, False
            await asyncio.sleep(2)
            # Retry Playwright setup once, now that the challenge is gone
            if platform_l == "chatgpt":
                setup_ok = await setup_chatgpt_dr(page)
            elif platform_l == "gemini":
                setup_ok = await setup_gemini_dr(page)
            elif platform_l == "claude":
                setup_ok = await setup_claude_dr(page)

    if setup_ok:
        log(f"[{label}] Playwright-direct setup OK")
    else:
        # Playwright failed — try original CUA setup as a first fallback (tight iterations)
        log(f"[{label}] Playwright setup failed — CUA fallback setup (tight)...")
        result = await agent_loop(cua_client, browser, prompt_system, prompt_user,
            model=CUA_MODEL, max_iterations=8, verbose=verbose)

    # LAYER 2: CUA visual validation — confirms options are ACTUALLY active
    log(f"[{label}] CUA validating setup state...")
    cua_ok = await validate_setup_with_cua(browser, cua_client, page, platform, label, verbose)
    if not cua_ok:
        log(f"[{label}] CUA validation failed — proceeding anyway but agent may misbehave", "WARN")

    # ── Brief delivery ──
    # ChatGPT + Claude accept .md file attachments in Deep Research mode and
    # use them as the research plan input. Prefer file-attach for those two
    # platforms when we have a brief_path on disk — it sidesteps composer-
    # truncation edge cases (ChatGPT auto-converts large pastes to
    # attachments and the paste verification then fails).
    #
    # GEMINI EXCEPTION (2026-05-24 revert): file-attach `set_input_files()`
    # returns True (DOM call succeeds) but Gemini's UI silently drops the
    # upload — observed in production E2E where the conversation only
    # contained the inline prompt with no file chip, and extraction yielded
    # 2476 chars of chat transcript instead of the 20-45k char research
    # report seen historically with the paste path. Revert to text paste
    # for Gemini only; ChatGPT + Claude file-attach remains untouched.
    # Fall back to inline paste also when brief_path is missing/unavailable.
    is_gemini = platform.lower() == "gemini"
    use_file_attach = brief_path and Path(brief_path).exists() and not is_gemini

    if use_file_attach:
        if source_paths:
            log(f"[{label}] Attaching brief file + {len(source_paths)} user source(s): {Path(brief_path).name}")
        else:
            log(f"[{label}] Attaching brief file: {Path(brief_path).name}")
        attached = await attach_brief_file(browser, page, brief_path, platform, label,
                                           extra_files=source_paths)
        if attached:
            typed = await type_short_inline_prompt(page, platform, label)
            if not typed:
                log(f"[{label}] Inline prompt type failed — trying CUA fallback", "WARN")
                await browser.switch_to_page(page)
                await agent_loop(cua_client, browser,
                    "Type a short research prompt referring to the attached brief — then stop (do NOT send).",
                    "Click the message input, type: 'Please perform deep research on the topic described in the attached brief. Use Deep Research mode and produce a comprehensive report with citations.' Then STOP — do not click Send.",
                    model=CUA_MODEL, max_iterations=6, verbose=verbose)
        else:
            log(f"[{label}] Brief attachment failed — falling back to inline paste", "WARN")
            # Attach failed → inline the source docs' text so the agent still
            # gets the primary material it would have received as files.
            brief_to_paste = _augment_brief_with_sources(brief, source_paths, label)
            # DOM-once → CUA contract.
            paste_ok = await verified_paste_brief(page, brief_to_paste, platform, label)
            if not paste_ok:
                paste_ok = await cua_paste_fallback(page, browser, cua_client,
                                                     brief_to_paste, platform, label, verbose)
            if not paste_ok:
                log(f"[{label}] CRITICAL: Both attach and paste (DOM+CUA) failed — skipping this agent", "ERROR")
                fail_agent(platform_l, "Brief delivery failed",
                           "Both file-attach and DOM+CUA paste failed. Retry to relaunch the agent.")
                return page, False
    else:
        # Inline paste path — engaged in two cases:
        #   (a) Gemini (file-attach silently drops the upload on Gemini's
        #       UI as of 2026-05-24; paste is the empirically reliable path
        #       that yielded 15-45k char extractions historically)
        #   (b) brief_path not on disk (in-memory brief from older callers)
        if is_gemini:
            log(f"[{label}] Pasting brief directly (Gemini file-attach silently "
                f"drops the upload; paste path empirically works)")
        else:
            log(f"[{label}] Pasting full brief ({len(brief)} chars) with verification...")
        # Gemini (and the brief_path-missing fallback): inline the user's
        # source docs into the pasted brief. Gemini silently drops file
        # uploads, so paste is the only way it sees the primary material.
        brief_to_paste = _augment_brief_with_sources(brief, source_paths, label)
        # DOM-once → CUA contract: single DOM attempt, then a CUA-assisted
        # fallback (CUA focuses composer, Python pastes via clipboard).
        # Removed the old page-reload + 2nd-DOM-retry path — it amplified
        # tab-spam risk (off-target click on a fresh page) without buying
        # reliability that CUA doesn't provide.
        paste_ok = await verified_paste_brief(page, brief_to_paste, platform, label)
        if not paste_ok:
            paste_ok = await cua_paste_fallback(page, browser, cua_client,
                                                 brief_to_paste, platform, label, verbose)
        if not paste_ok:
            log(f"[{label}] CRITICAL: Brief paste failed (DOM + CUA) — skipping this agent", "ERROR")
            fail_agent(platform_l, "Brief paste failed",
                       "DOM and CUA paste both failed. Retry to relaunch the agent.")
            return page, False

    # ── Just-before-send: ensure the required mode is STILL active ──
    # Claude especially can silently drop Research tool / Extended model
    # between setup and send. Re-activate if needed.
    mode_state = await ensure_deep_mode_active(page, platform, label)

    # ── E2/DGOPS-7364 + #709 — Deep-Research chat-mode gate (all P2 agents) ──
    # If Layer 1 (setup_*_dr) + Layer 2 (CUA validation) + the just-done
    # pre-send re-activation have all failed to enable Deep Research, do NOT
    # silently send a regular chat prompt — that produces wrong-output (a fast
    # chat reply) instead of a Deep Research report AND the completion ladder
    # then green-ticks the short answer prematurely (#709). Pause and emit a
    # decision alert so the operator decides. Originally Claude-only
    # (DGOPS-7364); generalized to ChatGPT + Gemini on 2026-05-29 (#709) after
    # both stuck in chat mode in E2E (ChatGPT Extended Pro, Gemini Flash).
    if platform_l in ("claude", "gemini", "chatgpt"):
        _name_map = {"claude": "Claude", "gemini": "Gemini", "chatgpt": "ChatGPT"}
        _agent_name = _name_map.get(platform_l, platform_l.title())
        # Per-platform "is Deep Research actually active?" signal. Claude
        # carries an explicit researchOn flag; ChatGPT/Gemini report `active`.
        if platform_l == "claude":
            research_ok = bool((mode_state or {}).get("researchOn"))
        else:
            research_ok = bool((mode_state or {}).get("active"))
        if not research_ok:
            log(f"[{label}] Deep Research unavailable after Layer 1 + Layer 2 + "
                f"pre-send re-activation — emitting chat-mode decision alert", "WARN")
            _emit_chat_mode_alert(platform_l)
            _controls.request_pause(f"{platform_l}_chat_mode")
            emit_event("pipeline_paused", phase=2, agent=platform_l,
                       reason=f"{platform_l}_chat_mode")
            await _controls.wait_if_paused()
            if _controls.is_stop():
                emit_event("pipeline_stopped", phase=2, agent=platform_l,
                           reason="user_stop_chat_mode")
                return page, False
            # 3h timeout (matches the Claude default from 2026-05-12): a
            # DR-unavailable state is exceptional and NEEDS human eyes — a
            # short auto-continue would silently degrade an AFK operator's run
            # to chat mode. On timeout we SKIP the agent (rather than fall to
            # chat mode) so a missed decision doesn't auto-degrade fidelity.
            decision = await _controls.await_agent_decision(platform_l, timeout=10800.0)
            log(f"[{label}] Chat-mode user decision: {decision}", "INFO")
            if decision == "stop":
                emit_event("pipeline_stopped", phase=2, agent=platform_l,
                           reason="user_stop_chat_mode")
                return page, False
            # The chat-mode alert action set is [Continue in chat mode] /
            # [Skip <agent>] / [Stop] — there is NO Retry button here. But
            # await_agent_decision also drains the hard-retry set. To stay safe
            # if a stray retry_agent command lands while this wait is active,
            # surface a SKIP rather than silently falling through to
            # continue_anyway (which would auto-degrade the agent to chat mode
            # without consent).
            if decision == "retry":
                log(f"[{label}] Retry requested on chat-mode alert (no retry path here) "
                    f"— treating as Skip to avoid silent chat-mode degradation", "WARN")
                _runtime.agent_modes[platform_l] = {
                    "requested": "research", "actual": "skipped",
                    "user_acknowledged_chat": False,
                }
                emit_event("agent_skipped", phase=2, agent=platform_l,
                           reason="retry_on_chat_mode_alert_unsupported")
                fail_agent(platform_l, f"{_agent_name} skipped — retry not supported in chat-mode alert",
                           "Retry isn't a valid action on the Deep-Research-mode-unavailable "
                           "alert. The agent was skipped to avoid silently running in "
                           "chat mode without your consent.")
                return page, False
            if decision == "skip" or decision == "timeout":
                _runtime.agent_modes[platform_l] = {
                    "requested": "research",
                    "actual": "skipped",
                    "user_acknowledged_chat": False,
                }
                _reason = ("research_unavailable_user_skip"
                           if decision == "skip"
                           else "research_unavailable_timeout_default_skip")
                emit_event("agent_skipped", phase=2, agent=platform_l, reason=_reason)
                fail_agent(platform_l, f"{_agent_name} skipped — Deep Research unavailable",
                           (f"User opted to skip Phase 2 {_agent_name} after Deep Research "
                            "could not be enabled." if decision == "skip"
                            else "Decision alert timed out after 3h — skipping "
                                 f"{_agent_name} rather than silently falling to chat mode."))
                return page, False
            # continue_anyway → proceed in chat mode with sticky flag.
            # (Explicit-only per 2026-05-12: an AFK operator must not
            # accidentally consent to lower-fidelity chat-mode output.)
            _runtime.agent_modes[platform_l] = {
                "requested": "research", "actual": "chat",
                "user_acknowledged_chat": True,
            }
            log(f"[{label}] Proceeding in CHAT MODE — user acknowledged "
                f"(downstream extraction will use mode-agnostic path)", "WARN")
            emit_event("pipeline_resumed", phase=2, agent=platform_l,
                       reason="continue_chat_mode")
        else:
            _runtime.agent_modes[platform_l] = {
                "requested": "research", "actual": "research",
                "user_acknowledged_chat": False,
            }

    # Brief ready — now click Send
    await asyncio.sleep(1)
    sent = False
    for sel in ['button[data-testid="send-button"]', 'button[aria-label="Send prompt"]',
                'button[aria-label="Send"]', 'button[aria-label="Send message"]',
                'button[aria-label="Send Message"]', 'button[aria-label="Submit"]']:
        try:
            btn = await page.query_selector(sel)
            if btn and await btn.is_enabled():
                await btn.click()
                log(f"[{label}] Send clicked ✓")
                sent = True
                break
        except Exception:
            continue
    if not sent:
        try:
            sent = await page.evaluate("""() => {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    const a = (b.getAttribute('aria-label') || '').toLowerCase();
                    const t = b.textContent.trim().toLowerCase();
                    if ((a.includes('send') || t === 'send' || t === 'submit' || a.includes('submit'))
                        && !b.disabled) {
                        b.click(); return true;
                    }
                }
                return false;
            }""")
            if sent:
                log(f"[{label}] Send clicked via JS ✓")
        except Exception:
            pass
    if not sent:
        log(f"[{label}] Playwright can't find Send — CUA clicking...")
        await browser.switch_to_page(page)
        await agent_loop(cua_client, browser, PROMPT_CLICK_SEND,
            "Click the Send button to submit the message.",
            model=CUA_MODEL, max_iterations=5, verbose=verbose)
        log(f"[{label}] CUA send attempted")
        # CUA send is a last resort — Playwright couldn't find a send button
        # via any selector. The click may or may not have landed depending
        # on what CUA saw. Offer the user [Retry send] [Continue (trust it)]
        # [Skip agent] so they can course-correct without waiting 60s for the
        # agent to (maybe) start generating.
        ag_key_send = (platform or "").lower() or None
        # No alert: round-robin proceeds assuming the CUA click landed.
        # If the agent never produces output, fail_agent surfaces from
        # the wall-clock or stall path. Avoiding a banner here keeps
        # the per-agent dropdown clean during normal startup.
        # Wait up to 90s — agent startup is time-sensitive so don't block
        # polling long. Default (timeout) = continue (trust the CUA click).
        if ag_key_send:
            try:
                decision = await _controls.await_agent_decision(ag_key_send, timeout=90.0)
                log(f"[{label}] Send-fallback user decision: {decision}")
                if decision == "retry":
                    try:
                        await browser.switch_to_page(page)
                        await agent_loop(cua_client, browser, PROMPT_CLICK_SEND,
                            "Click the Send button to submit the message. The previous attempt may have missed — look carefully for the Send icon.",
                            model=CUA_MODEL, max_iterations=5, verbose=verbose)
                        log(f"[{label}] CUA send retry attempted")
                    except Exception as e:
                        log(f"[{label}] CUA send retry failed: {e}", "WARN")
                # 'skip' → skipped_agents set already populated; polling loop
                # drops the agent on its next tick. 'continue_partial' /
                # 'timeout' → proceed as-is. 'stop' → outer stop handler.
            except Exception as _e:
                log(f"[{label}] Send-decision wait errored: {_e}", "WARN")

    await asyncio.sleep(3)
    # 2026-05-14: in-page Retry auto-click guard (Fix #515) — Gemini-only.
    # When Gemini's "show thinking" path lands on a soft-refusal screen
    # ("Sorry, I can't help…") this clicks the in-page Retry button so
    # the round-robin watchdog doesn't escalate a transient soft-refusal
    # to a human-intervention alert.
    #
    # Originally invoked for all 3 platforms (Fix #515). Re-scoped on
    # 2026-05-14 to Gemini-only: ChatGPT/Claude soft-refusals are rarer,
    # and the fail-text regex could (rarely) match unrelated body text
    # on a healthy "Researching..." page, risking a false-fire that
    # closes a working DR session. Watchdog + verify recover real
    # failures for ChatGPT/Claude.
    if platform_l == "gemini":
        try:
            retried = await _try_inpage_retry_on_research_fail(
                page, platform, label, max_wait_s=90,
            )
            if retried:
                log(f"[{label}] In-page Retry auto-click handled — research re-kicked", "INFO")
                await asyncio.sleep(2)
        except Exception as _re:
            log(f"[{label}] In-page Retry guard raised (non-fatal): {_re}", "DEBUG")
    return page, True


async def run_phase2(browser, cua_client, brief_text, verbose=False, enabled_agents=None):
    """Phase 2: ChatGPT → Claude → Gemini (submit+plan) → scrape-pass → Gemini (Start) → Poll all.

    Sequence change: Gemini moved to last of the setup trio. One round-robin scrape
    pass (ChatGPT → Claude → Gemini) is inserted between Gemini's brief submission and
    the 'Start research' click — it primes the frontend with rich agent_progress data
    (sources, partial_text_len, steps) immediately, instead of waiting for the first
    main-rotation poll tick. Gemini stays in 'planning' (never 'complete') until its
    'Start research' button is clicked — gated by scrape_progress_gemini's planning-gate.

    enabled_agents: list of agent keys to run (e.g. ["chatgpt", "gemini"]). None = all."""
    log("=" * 60)
    log("PHASE 2: Deep Research")
    if enabled_agents:
        log(f"  Enabled agents: {enabled_agents}")
    log("  Sequence: ChatGPT → Claude → Gemini (submit+plan) → scrape-pass → Gemini (Start) → Poll all")
    log("=" * 60)

    # Ensure brief.md is on disk for file-attachment delivery (Option A).
    brief_path = None
    if _tracks_dir:
        brief_path = Path(__file__).parent / "queues" / _tracks_dir.name / "documents" / "brief.md"
        try:
            brief_path.parent.mkdir(parents=True, exist_ok=True)
            if not brief_path.exists() or brief_path.stat().st_size < 100:
                brief_path.write_text(
                    f"# Research Brief\n\n{brief_text}", encoding="utf-8")
                log(f"Wrote brief to disk for attachment: {brief_path.name} ({len(brief_text)} chars)")
            else:
                log(f"Using existing brief.md ({brief_path.stat().st_size} bytes)")
        except Exception as e:
            log(f"Could not prepare brief.md for attachment: {e}", "WARN")
            brief_path = None

    # User-attached source docs to deliver to every agent (skip-P1 flow).
    # Empty unless the orchestrator flagged them (P1 didn't run live). Read
    # from disk so it survives pause/resume + hard-retry.
    source_paths = _read_p2_source_paths()
    if source_paths:
        log(f"Phase 2: delivering {len(source_paths)} user source doc(s) to each agent: "
            f"{[Path(p).name for p in source_paths]}")

    agents = {}
    chatgpt_page = None
    claude_page = None
    gemini_page = None

    # ── Step 1 (2A): ChatGPT — already in ChatGPT from Phase 1, just open Deep Research ──
    if enabled_agents is None or "chatgpt" in enabled_agents:
        log("\n--- 2A: ChatGPT Deep Research (already in ChatGPT) ---")
        emit_event("agent_progress", phase=2, agent="chatgpt", status="starting", progress="Opening ChatGPT Deep Research mode...")
        for attempt in range(2):
            if attempt > 0:
                log("[2A] Retrying ChatGPT (fresh tab)...", "WARN")
                try: await chatgpt_page.close()
                except Exception: pass
            chatgpt_page, _chatgpt_setup_ok = await start_agent_no_gemini_wait(
                browser, cua_client, "https://chatgpt.com",
                PROMPT_CHATGPT_DEEP_RESEARCH,
                "Enable Deep Research mode in ChatGPT. Do NOT type — just set up and focus input. Say 'ready for paste'.",
                brief_text, "2A", "ChatGPT", verbose, brief_path=brief_path,
                source_paths=source_paths)
            if not _chatgpt_setup_ok:
                # Setup/paste failed — start_agent_no_gemini_wait already
                # emitted pipeline_error with Retry/Skip actions. Don't try
                # to verify — there's nothing to verify.
                verified_a = False
                break
            verified_a = await wait_until_verified(verify_chatgpt_generating, chatgpt_page, "2A",
                browser=browser, cua_client=cua_client, max_retries=15, interval=3, verbose=verbose)
            if verified_a:
                break
        agents["ChatGPT"] = {"page": chatgpt_page, "verified": verified_a, "url": chatgpt_page.url if chatgpt_page else ""}
        if verified_a:
            emit_event("agent_progress", phase=2, agent="chatgpt", status="generating", progress="ChatGPT Deep Research started and verified")
            log("[2A] ChatGPT Deep Research is running ✓")
            await inject_agent_observer(chatgpt_page, "chatgpt")
        else:
            # 2026-05-14: page-alive gating before fail_agent. If the URL
            # transitioned to /c/<id>, the brief WAS submitted and a
            # conversation was started — verify just couldn't read the
            # active state (cross-origin DR iframe). The round-robin
            # poller at poll_all_agents_round_robin already handles the
            # "verified=False but page exists" case (line ~13515), so we
            # hand off without firing the false-alarm banner that would
            # tempt the user into a hard retry that closes the working
            # tab. The fail_agent path remains for genuinely dead pages
            # (still on the bare chatgpt.com URL).
            _chatgpt_url = ""
            try:
                _chatgpt_url = (chatgpt_page.url or "").lower() if chatgpt_page else ""
            except Exception:
                pass
            _chatgpt_alive = "chatgpt.com/c/" in _chatgpt_url
            if _chatgpt_alive:
                log("[2A] verify_chatgpt_generating returned False but page is at /c/<id> — handing off to round-robin polling (no fail_agent banner)", "WARN")
                emit_event("agent_progress", phase=2, agent="chatgpt", status="generating",
                           progress="ChatGPT DR submitted — verifying via round-robin polling")
                await inject_agent_observer(chatgpt_page, "chatgpt")
            else:
                log("[2A] ChatGPT failed after 2 attempts", "ERROR")
                # Mark as terminally failed so the round-robin doesn't sit on it
                # forever waiting for events that will never arrive.
                emit_event("agent_progress", phase=2, agent="chatgpt", status="failed",
                           progress="ChatGPT setup/paste failed — agent did not start.")
                fail_agent("chatgpt", "ChatGPT failed to start after 2 attempts",
                           "Setup or brief paste failed twice. Retry to open a fresh tab.")
                try:
                    _controls.skipped_agents.add("chatgpt")
                except Exception:
                    pass
    else:
        log("\n--- 2A: ChatGPT SKIPPED (disabled in config) ---")

    # ── Startup gap: 30s before opening the next agent ──
    # Human-cadence stagger reduces anti-bot signal and lets ChatGPT's DR
    # iframe settle before we start issuing Claude commands. User-locked
    # 2026-04 overhaul: sequential 30s gaps, each agent verify-started
    # before moving on.
    if enabled_agents is None or "claude" in enabled_agents:
        log("\n[Startup gap] Waiting 30s before opening Claude...")
        await asyncio.sleep(30)

    # ── Step 2 (2B): Claude — Opus 4.8 + Max effort + Adaptive Thinking + Research tool ──
    if enabled_agents is None or "claude" in enabled_agents:
        log("\n--- 2B: Claude Deep Research ---")
        emit_event("agent_progress", phase=2, agent="claude", status="starting", progress="Opening Claude with Opus 4.8 (Max effort + Adaptive Thinking) + Research tools...")
        for attempt in range(2):
            if attempt > 0:
                log("[2B] Retrying Claude (fresh tab)...", "WARN")
                try: await claude_page.close()
                except Exception: pass
            claude_page, _claude_setup_ok = await start_agent_no_gemini_wait(
                browser, cua_client, "https://claude.ai/new",
                PROMPT_CLAUDE_DEEP_RESEARCH,
                "Select Opus 4.8 + Max effort + Adaptive Thinking + Research tool (if Opus 4.8 isn't offered, pick the highest Opus available — never downgrade to 4.7 when 4.8 exists). Do NOT type — just set up and focus input. Say 'ready for paste'.",
                brief_text, "2B", "Claude", verbose, brief_path=brief_path,
                source_paths=source_paths)
            if not _claude_setup_ok:
                verified_c = False
                break
            verified_c = await wait_until_verified(verify_claude_generating, claude_page, "2B",
                browser=browser, cua_client=cua_client, max_retries=15, interval=3, verbose=verbose)
            if verified_c:
                break
        agents["Claude"] = {"page": claude_page, "verified": verified_c, "url": claude_page.url if claude_page else ""}
        if verified_c:
            emit_event("agent_progress", phase=2, agent="claude", status="generating", progress="Claude Adaptive Thinking started and verified")
            log("[2B] Claude is running ✓")
            await inject_agent_observer(claude_page, "claude")
        else:
            # 2026-05-14: mirror Fix #5 from ChatGPT 2A. If the URL
            # transitioned from claude.ai/new to claude.ai/chat/<id>, the
            # brief was submitted and a conversation started — verify just
            # couldn't read the active state. Hand off to round-robin
            # polling without firing the false-alarm banner.
            _claude_url = ""
            try:
                _claude_url = (claude_page.url or "").lower() if claude_page else ""
            except Exception:
                pass
            _claude_alive = "claude.ai/chat/" in _claude_url
            if _claude_alive:
                log("[2B] verify_claude_generating returned False but page is at /chat/<id> — handing off to round-robin polling (no fail_agent banner)", "WARN")
                emit_event("agent_progress", phase=2, agent="claude", status="generating",
                           progress="Claude DR submitted — verifying via round-robin polling")
                await inject_agent_observer(claude_page, "claude")
            else:
                log("[2B] Claude failed after 2 attempts", "ERROR")
                emit_event("agent_progress", phase=2, agent="claude", status="failed",
                           progress="Claude setup/paste failed — agent did not start.")
                fail_agent("claude", "Claude failed to start after 2 attempts",
                           "Setup or brief paste failed twice. Retry to open a fresh tab.")
                try:
                    _controls.skipped_agents.add("claude")
                except Exception:
                    pass
    else:
        log("\n--- 2B: Claude SKIPPED (disabled in config) ---")

    # ── Startup gap: 30s before opening Gemini ──
    if enabled_agents is None or "gemini" in enabled_agents:
        log("\n[Startup gap] Waiting 30s before opening Gemini...")
        await asyncio.sleep(30)

    # ── Step 3 (2C): Gemini — submit brief, let it generate plan (don't click Start yet) ──
    gemini_setup_ok = False
    if enabled_agents is None or "gemini" in enabled_agents:
        log("\n--- 2C: Gemini Deep Research (submit + let it plan) ---")
        emit_event("agent_progress", phase=2, agent="gemini", status="starting", progress="Opening Gemini and submitting research brief...")
        gemini_page, gemini_setup_ok = await start_agent_no_gemini_wait(
            browser, cua_client, "https://gemini.google.com",
            PROMPT_GEMINI_DEEP_RESEARCH,
            "Enable Deep Research mode in Gemini. Do NOT type — just set up and focus input. Say 'ready for paste'.",
            brief_text, "2C", "Gemini", verbose, brief_path=brief_path,
            source_paths=source_paths)
        if gemini_setup_ok:
            log("[2C] Gemini brief submitted — letting it generate research plan")
            emit_event("agent_progress", phase=2, agent="gemini", status="generating", progress="Gemini generating research plan...")
        else:
            # Setup or paste failed — start_agent_no_gemini_wait already emitted
            # pipeline_error with Retry/Skip actions. Mark Gemini terminally
            # failed so the [2D] wait loop is skipped and the round-robin
            # poller treats it as done. No more lying about "generating plan".
            log("[2C] Gemini setup/brief delivery failed — marking agent failed, skipping [2D] plan wait", "ERROR")
            emit_event("agent_progress", phase=2, agent="gemini", status="failed",
                       progress="Gemini setup/brief delivery failed — agent did not start.")
            try:
                _controls.skipped_agents.add("gemini")
            except Exception:
                pass
    else:
        log("\n--- 2C: Gemini SKIPPED (disabled in config) ---")

    # ── First wave: 60s sequential per agent (2026-04 overhaul) ──
    # Instead of one instant snapshot, dwell on each agent's tab for 60s and
    # emit agent_progress every ~15s. This gives the frontend a richer,
    # ladder-like narration start while staying at human cadence. Sequence
    # order matches the original submission: ChatGPT → Claude → Gemini.
    # Gemini's planning-gate inside scrape_progress_gemini keeps its status
    # pinned to 'planning' while the Start-research button is still visible.
    # 2026-04-25: First-wave dwell DROPPED from 60s/agent (180s total) to 0s.
    # Round-robin starts immediately and emits agent_progress live as it
    # observes each tab; the dwell delayed real round-robin start without
    # adding signal the round-robin couldn't deliver itself.
    log("\n--- 2 first-wave (skipped — round-robin starts immediately) ---")
    _scrape_targets = [
        ("chatgpt", "ChatGPT", chatgpt_page, scrape_progress_chatgpt),
        ("claude",  "Claude",  claude_page,  scrape_progress_claude),
        ("gemini",  "Gemini",  gemini_page,  scrape_progress_gemini),
    ]
    _FIRST_WAVE_SEC = 0
    _FIRST_WAVE_TICK = 15
    for _ag_key, _ag_name, _ag_page, _scrape_fn in _scrape_targets:
        if _ag_page is None:
            continue
        try:
            await browser.switch_to_page(_ag_page)
            await asyncio.sleep(1)
        except Exception as _e:
            log(f"  [First-wave] switch to {_ag_name} failed: {_e}", "WARN")
            continue
        log(f"  [First-wave] Dwelling on {_ag_name} for {_FIRST_WAVE_SEC}s...")
        _wave_start = time.time()
        _last_emit_len = -1
        while time.time() - _wave_start < _FIRST_WAVE_SEC:
            try:
                _snap = await _scrape_fn(_ag_page) or {}
                if _ag_key == "gemini":
                    _st = (_snap.get("status") or "").lower()
                    if _st in ("complete", "done"):
                        _snap["status"] = "generating"
                        _snap["phase"] = "planning"
                _sources = int(_snap.get("sources", 0) or 0)
                _partial = int(_snap.get("partial_text_len", 0) or 0)
                _steps = _snap.get("steps", []) or []
                _progress = _snap.get("progress") or (
                    f"Working — {_sources} sources, {_partial} chars" if _partial else
                    (_steps[-1] if _steps else f"{_ag_name} starting up")
                )
                # Only emit if something actually changed to avoid frontend churn
                if _partial != _last_emit_len or _last_emit_len < 0:
                    emit_event("agent_progress", phase=2, agent=_ag_key,
                               status=_snap.get("status", "generating"),
                               progress=_progress,
                               sources=_sources,
                               source_urls=(_snap.get("source_urls", []) or [])[:50],
                               partial_text_len=_partial,
                               steps=_steps[-3:] if _steps else [],
                               thinking=(_snap.get("thinking") or "")[:300])
                    _last_emit_len = _partial
                    log(f"  [First-wave/{_ag_name}] status={_snap.get('status')}, "
                        f"sources={_sources}, partial_len={_partial}")
            except Exception as _e:
                log(f"  [First-wave/{_ag_name}] tick failed (non-fatal): {_e}", "WARN")
            await asyncio.sleep(_FIRST_WAVE_TICK)

    # ── Step 4 (2D): Return to Gemini — wait for plan + click "Start research" ──
    # 2026-04 overhaul: no rotation to ChatGPT/Claude during this wait. We
    # dwell on the Gemini tab until the Start-research button is clicked;
    # the OFFICIAL round-robin only begins after that click. ChatGPT/Claude
    # keep running in the background — their state from the first-wave dwell
    # is the last frontend update until the round-robin picks them up.
    #
    # Skip the entire [2D] loop if Gemini's setup failed (setup_ok == False)
    # OR was marked skipped (e.g. via Retry/Skip Skip path). Without this
    # gate the loop sits 10 minutes waiting for a "Start research" button
    # that will never appear because no plan was ever generated.
    _gemini_skipped = False
    try:
        _gemini_skipped = "gemini" in (_controls.skipped_agents or set())
    except Exception:
        _gemini_skipped = False
    if gemini_page is not None and gemini_setup_ok and not _gemini_skipped:
        log("\n--- 2D: Gemini — waiting for research plan + clicking 'Start research' (focused, no rotation) ---")
        await browser.switch_to_page(gemini_page)
        await asyncio.sleep(2)

        start_clicked = False
        _start_wait_max_sec = 10 * 60
        _loop_start = time.time()
        _last_plan_emit = 0.0
        while time.time() - _loop_start < _start_wait_max_sec:
            # 1. Check Start-research button on Gemini and click if present
            try:
                await browser.switch_to_page(gemini_page)
                clicked = await gemini_page.evaluate("""() => {
                    const btns = document.querySelectorAll('button');
                    for (const b of btns) {
                        const txt = b.textContent.trim().toLowerCase();
                        if (txt.includes('start research')) { b.click(); return true; }
                    }
                    return false;
                }""")
                if clicked:
                    log("[2D] Clicked 'Start research' via JS ✓")
                    start_clicked = True
                    await asyncio.sleep(5)
                    break
            except Exception:
                pass

            # 2. Emit a Gemini planning heartbeat every ~60s so the frontend
            # knows Gemini is still drafting the plan. No rotation — we do
            # NOT scrape ChatGPT/Claude here; they kept their first-wave
            # state and will refresh on the official round-robin.
            if time.time() - _last_plan_emit >= 60:
                try:
                    _gm = await scrape_progress_gemini(gemini_page) or {}
                    _gm_status = (_gm.get("status") or "generating")
                    if _gm_status in ("complete", "done"):
                        _gm_status = "generating"
                    emit_event("agent_progress", phase=2, agent="gemini",
                               status=_gm_status,
                               progress=_gm.get("progress") or "Gemini drafting research plan...",
                               sources=int(_gm.get("sources", 0) or 0),
                               source_urls=(_gm.get("source_urls", []) or [])[:50],
                               partial_text_len=int(_gm.get("partial_text_len", 0) or 0),
                               steps=(_gm.get("steps") or [])[-3:],
                               plan=(_gm.get("plan") or "")[:500])
                    _last_plan_emit = time.time()
                except Exception:
                    pass

            _elapsed = int(time.time() - _loop_start)
            log(f"[2D] Still waiting for Gemini research plan... ({_elapsed}s / {_start_wait_max_sec}s)")
            await asyncio.sleep(30)

        # CUA fallback for Start research
        if not start_clicked:
            log("[2D] JS couldn't find button — CUA clicking 'Start research'")
            await browser.switch_to_page(gemini_page)
            fix = await agent_loop(cua_client, browser,
                PROMPT_GEMINI_START_RESEARCH,
                "Click the 'Start research' button to begin the deep research.",
                model=CUA_MODEL, max_iterations=10, verbose=verbose)
            fix_text = (fix.get("text") or "").lower()
            if "click" in fix_text:
                start_clicked = True
                log("[2D] CUA clicked 'Start research' ✓")
                await asyncio.sleep(5)

        # Verify Gemini is actually researching
        verified_b = await wait_until_verified(verify_gemini_generating, gemini_page, "2D",
            browser=browser, cua_client=cua_client, max_retries=15, interval=3, verbose=verbose)
        # Record when research actually started (after "Start research" click)
        # so the round-robin doesn't check for completion prematurely
        agents["Gemini"] = {"page": gemini_page, "verified": verified_b, "url": gemini_page.url,
                            "research_started_at": time.time()}
        if verified_b:
            emit_event("agent_progress", phase=2, agent="gemini", status="generating", progress="Gemini Deep Research plan created and started")
            log("[2D] Gemini is researching ✓")
            await inject_agent_observer(gemini_page, "gemini")
        else:
            log("[2D] Gemini may not be running", "WARN")

    # ── Verify all launched agents are running ──
    total = len(agents)
    verified_count = sum(1 for a in agents.values() if a["verified"])
    log(f"\n{'='*60}")
    log(f"Agents started. {verified_count}/{total} verified as running.")
    for name, a in agents.items():
        log(f"  {name:10s} {'✓ running' if a['verified'] else '✗ not verified'}  {a['url'][:60]}")
    log(f"{'='*60}")

    # Round-robin poll all agents — checks each agent every cycle instead of blocking per-agent
    if not agents:
        log("No agents to poll — all were disabled or skipped")
        return {}
    results = await poll_all_agents_round_robin(
        agents, browser, cua_client,
        max_wait_min=MAX_WAIT_DEEP, poll_interval=POLL_DEEP_RESEARCH, verbose=verbose)

    return results


# ── Phase 2 → Phase 3 handoff ────────────────────────────────────────────────

def _build_phase2_to_phase3_handoff(results: dict, queue_dir) -> None:
    """Populate _runtime.p2_links_for_p3 + _runtime.p2_md_files_for_p3 from
    P2 state (results + _runtime.agent_share_urls + on-disk MDs). Idempotent.

    Called at end of P2 (the canonical population point) and as a no-op
    safety net at start of P3 (only does real work if _runtime was wiped
    on a process restart between P2 and P3 — i.e. resume-from-P3 case).

    P2 owns all share-URL extraction (DOM + CUA fallback + vision shadow).
    P3 just consumes this state and uploads to NotebookLM. No browser
    activity, no agent re-visits, no CUA in P3.
    """
    p3_links: dict[str, str] = {}
    p3_md_files: list = []
    for _name, _r in (results or {}).items():
        _md_name = _name.lower().replace(" ", "") + ".md"
        _md_path = Path(queue_dir) / "documents" / _md_name
        _has_md = _md_path.exists() and _md_path.stat().st_size > 100
        # Prefer the verified public share URL captured in P2's inline
        # extractor (DOM tier) or CUA fallback. Fall back to the
        # conversation URL captured at extraction time.
        _share = _runtime.agent_share_urls.get(_name) or {}
        _url = _share.get("url") or _r.get("url") or ""
        if _url:
            p3_links[_name] = _url
        if _has_md:
            p3_md_files.append(_md_path)
    # Flow B: P1 + all P2 skipped means `results` is empty, so the loop
    # above adds no md files. Scan documents/ for any user-supplied source
    # files (md/txt/pdf/docx — anything except brief.md / derived MDs) so
    # P3 still has something to upload to NotebookLM.
    #
    # GATE (2026-04-30): only scan when the per-agent loop above added
    # NOTHING. With agents present, p3_md_files already has every MD that
    # belongs in NotebookLM; running the scan anyway picks up derived
    # artifacts (consolidated.md is the offender — it's a P2 byproduct of
    # claude+gemini concatenation, used for the Documents page only) and
    # uploads them as duplicate sources. The Flow B scenario the scan was
    # written for has p3_md_files empty by definition (no agents ran).
    _DERIVED_STEMS = {"brief", "consolidated"}
    if not p3_md_files:
        _docs_dir = Path(queue_dir) / "documents"
        if _docs_dir.exists():
            _already = {p.name for p in p3_md_files}
            for _f in sorted(_docs_dir.iterdir()):
                if not _f.is_file():
                    continue
                # 2026-05-11: lowercase the stem to match _scan_p3_docs
                # below — defensive in case a future write path drops a
                # Capitalised filename onto disk (current code always
                # writes lowercase, but the file is the source of truth
                # for what NLM uploads so this guard is cheap).
                if _f.stem.lower() in _DERIVED_STEMS:
                    continue
                if _f.suffix.lower() not in (".md", ".txt", ".pdf", ".docx"):
                    continue
                if _f.name in _already:
                    continue
                if _f.stat().st_size < 32:
                    continue   # Empty / placeholder file — skip
                p3_md_files.append(_f)
    _runtime.p2_links_for_p3 = p3_links
    _runtime.p2_md_files_for_p3 = p3_md_files
    log(f"[Phase 2→3 handoff] {len(p3_links)} links, {len(p3_md_files)} files ready for NotebookLM")


# ── Phase 3: NotebookLM Upload ───────────────────────────────────────────────

async def _verify_and_repair_nlm_sources(browser, cua_client, md_files, verbose=False, max_rounds=2):
    """Post-upload health check for NotebookLM sources.

    NotebookLM ingests sources ASYNC after the file lands in the panel, so a
    source can appear (the per-file CUA "uploaded" check passes) and then flip
    to a red "failed" state during processing — observed 2026-05 where the
    first source uploaded *during notebook creation* (claude.md) went red and
    the audio overview was built from only 2/3 sources, silently.

    Gives ingestion a moment to settle, asks the CUA to report any source stuck
    in an error state BY FILENAME, and silently re-uploads each failed one
    (preferring NotebookLM's in-place retry over delete+re-add). Bounded to
    `max_rounds`. CONSERVATIVE: an "ALL OK" / ambiguous / unmappable verdict
    takes NO action, so the outcome is never worse than skipping this step.
    The caller wraps this so any exception just proceeds with what processed."""
    if not cua_client or not md_files:
        return
    by_name = {p.name: p for p in md_files}
    for _round in range(1, max_rounds + 1):
        # Let async ingestion settle before judging (spinners → ✓ or red).
        await asyncio.sleep(8)
        verdict = await agent_loop(
            cua_client, browser, PROMPT_NOTEBOOKLM_VERIFY_SOURCES,
            "Check the Sources panel and report any source in a failed/error (red) state.",
            model=CUA_MODEL, max_iterations=8, verbose=verbose)
        text = (verdict.get("text") if isinstance(verdict, dict) else "") or ""
        low = text.lower()
        # Conservative parse: only act on an explicit "FAILED:" verdict. "ALL
        # OK", empty, or anything without "failed:" → assume healthy and stop
        # (never blind-delete/re-add a good source on an ambiguous read).
        if "failed:" not in low:
            log(f"[NotebookLM] source verify (round {_round}): all sources OK")
            return
        failed_part = low.split("failed:", 1)[1]
        # Bail on explicit "no failure" phrasing the model may put after FAILED:.
        if failed_part.strip().split(",")[0].strip() in ("", "none", "n/a", "-", "nothing"):
            log(f"[NotebookLM] source verify (round {_round}): all sources OK")
            return
        # Token-equality match (split on commas/whitespace, trim stray
        # punctuation) — NOT a raw substring scan. A healthy filename mentioned
        # in prose after FAILED: (e.g. "FAILED: claude.md (gemini.md is fine)")
        # must NOT be matched and "repaired" by mistake.
        import re as _re
        _tokens = {t.strip().strip(".,;:()[]'\"") for t in _re.split(r"[\s,]+", failed_part) if t.strip()}
        failed = [name for name in by_name if name.lower() in _tokens]
        if not failed:
            log(f"[NotebookLM] source verify: failure reported but no known filename matched — "
                f"verdict='{text[:160]}' (skipping repair to avoid touching healthy sources)", "WARN")
            return
        log(f"[NotebookLM] source verify (round {_round}): {len(failed)} failed → re-uploading {failed}", "WARN")
        try:
            emit_event("agent_progress", phase=3, agent="notebooklm", status="repairing",
                       progress=f"Re-uploading {len(failed)} source(s) that failed to import…")
        except Exception:
            pass
        for name in failed:
            md_path = by_name[name]
            browser.set_upload_file(str(md_path))
            try:
                await agent_loop(
                    cua_client, browser, PROMPT_NOTEBOOKLM_REUPLOAD,
                    f"The source '{name}' failed to import. Retry it in place if possible, "
                    f"otherwise remove that one failed source and re-add the file (dialog auto-handled).",
                    model=CUA_MODEL, max_iterations=12, verbose=verbose)
            finally:
                browser.clear_upload_file()
            await asyncio.sleep(3)
    log("[NotebookLM] source verify: re-upload rounds exhausted — proceeding with whatever processed", "WARN")


async def run_phase3_upload(browser, cua_client, results, topic, queue_dir, verbose=False):
    """Phase 3: upload P2-built MDs to NotebookLM and make notebook public.
    Share-URL extraction lives entirely in P2 — this phase is pure NotebookLM."""
    log("=" * 60)
    log("PHASE 3: NotebookLM Upload")
    log("=" * 60)

    # 2026-04-26: log every MD on disk in queue_dir/documents/ at P3 entry.
    # Makes P2→P3 handoff debugging trivial — we can see at a glance which
    # of the 3 agent .md files made it to disk and at what size. If one is
    # missing or 0 bytes, P3 NotebookLM upload will silently miss that
    # source.
    try:
        _docs = queue_dir / "documents"
        if _docs.exists():
            _on_disk = [(f.name, f.stat().st_size) for f in sorted(_docs.glob("*.md"))]
            log(f"Phase 3: queue MDs on disk: " +
                (", ".join(f"{n}={s}b" for n, s in _on_disk) if _on_disk else "(none)"))
        else:
            log("Phase 3: queue_dir/documents does not exist — no MDs", "WARN")
    except Exception as _de:
        log(f"Phase 3: MD-on-disk audit failed: {_de}", "DEBUG")

    # Hydrate share links + MD files from P2's handoff (built at end of P2).
    # Resume safety: if _runtime was wiped (process restart between P2 and P3
    # — e.g. resume-from-P3 path), rebuild handoff state from results + disk.
    if not _runtime.p2_links_for_p3 and not _runtime.p2_md_files_for_p3:
        _build_phase2_to_phase3_handoff(results, queue_dir)
    links: dict[str, str] = dict(_runtime.p2_links_for_p3 or {})
    md_files: list = list(_runtime.p2_md_files_for_p3 or [])
    log(f"Phase 3: hydrated {len(links)} share links + {len(md_files)} MDs from P2 handoff")

    # Save links
    links_file = queue_dir / "links.json"
    links_file.write_text(json.dumps(links, indent=2), encoding="utf-8")
    log(f"Links saved: {links}")

    # Upload MDs to NotebookLM (wrapped in retry loop — user can re-attempt
    # after a login-expired or generic upload failure without losing the rest
    # of the pipeline).
    notebook_url = ""
    p3_max_retries = 2
    p3_attempt = 0
    while md_files and p3_attempt <= p3_max_retries:
        log(f"\n--- Uploading {len(md_files)} MDs to NotebookLM (attempt {p3_attempt + 1}/{p3_max_retries + 1}) ---")
        try:
            page = await browser.new_tab("https://notebooklm.google.com")
            await asyncio.sleep(4)

            # Early HV check — NotebookLM occasionally hits Google's bot gate
            # on fresh tabs when the session fingerprint looks suspicious.
            # Clearing first avoids wasted CUA calls on a blocked page.
            if cua_client:
                cleared = await check_hv_gate(browser, cua_client, "notebooklm", "NotebookLM",
                                               phase=3, verbose=verbose)
                if not cleared:
                    log("Phase 3: HV gate on NotebookLM could not be cleared — retrying or aborting", "ERROR")
                    p3_attempt += 1
                    continue

            for i, md_path in enumerate(md_files):
                log(f"Uploading {md_path.name} ({i+1}/{len(md_files)})...")
                emit_event("agent_progress", phase=3, agent="notebooklm",
                           status="uploading",
                           progress=f"Uploading source {i+1}/{len(md_files)}: {md_path.name}")
                browser.set_upload_file(str(md_path))

                _stop, _task = start_narration_ticker(
                    3, "notebooklm",
                    f"NotebookLM uploading source {i+1}/{len(md_files)}: {md_path.name}",
                    interval=20)
                try:
                    if i == 0:
                        await agent_loop(cua_client, browser, PROMPT_NOTEBOOKLM_UPLOAD,
                            "Create a new notebook and upload the first file. File dialog is auto-handled.",
                            model=CUA_MODEL, max_iterations=15, verbose=verbose)
                    else:
                        await agent_loop(cua_client, browser, PROMPT_NOTEBOOKLM_UPLOAD,
                            f"Add another source (file {i+1}). Click 'Add source' or '+'. File dialog is auto-handled.",
                            model=CUA_MODEL, max_iterations=10, verbose=verbose)
                finally:
                    await stop_narration_ticker(_stop, _task)

                browser.clear_upload_file()
                await asyncio.sleep(3)

            # Verify each source actually PROCESSED. NotebookLM ingests sources
            # ASYNC after the file lands in the panel, so a source can pass the
            # per-file "uploaded" check above and then flip to a red "failed"
            # state during processing — observed 2026-05: claude.md (the first
            # source, uploaded during notebook creation) went red and the audio
            # overview was built from only 2/3 sources, silently. This settles +
            # verifies + silently re-uploads any failed source. Best-effort:
            # wrapped so any error just proceeds with whatever processed.
            try:
                await _verify_and_repair_nlm_sources(browser, cua_client, md_files, verbose=verbose)
            except Exception as _ve:
                log(f"[NotebookLM] source verify/repair skipped (non-fatal): {_ve}", "WARN")

            # Rename notebook — use the smart title (Firestore-synced) so NotebookLM,
            # YouTube, and the email subject all line up on the same short name.
            title = smart_title(topic)
            log(f"Renaming notebook to '{title}'...")
            emit_event("agent_progress", phase=3, agent="notebooklm",
                       status="renaming",
                       progress=f"Renaming notebook to '{title}'…")
            await agent_loop(cua_client, browser, PROMPT_NOTEBOOKLM_RENAME,
                f"Rename this notebook to: {title}",
                model=CUA_MODEL, max_iterations=8, verbose=verbose)

            # C1: make notebook public (Share → "Anyone with the link" → Save)
            # BEFORE emitting the URL, so the frontend's link is always viewable.
            emit_event("agent_progress", phase=3, agent="notebooklm",
                       status="sharing",
                       progress="Setting notebook to 'Anyone with the link can view'…")
            notebook_url = await browser.current_url()
            try:
                log("NotebookLM: opening share dialog to set 'Anyone with link'...")
                nlm_share_res = await extract_notebooklm_url(browser, cua_client=cua_client, verbose=verbose)
                if nlm_share_res.verified and nlm_share_res.url:
                    notebook_url = nlm_share_res.url
                    log(f"NotebookLM public share OK: {notebook_url}")
                else:
                    log(f"NotebookLM public share uncertain — falling back to tab URL: {nlm_share_res.error}", "WARN")
            except Exception as e:
                log(f"NotebookLM public share flow error: {e} — falling back to tab URL", "WARN")
            log(f"NotebookLM: {notebook_url}")
            # Emit notebook link immediately — frontend shows it without waiting for phase end
            if notebook_url and "notebooklm.google.com/notebook" in notebook_url:
                emit_validated_link(3, "notebooklm", notebook_url, "NotebookLM Notebook")
            break  # Successful upload — exit retry loop
        except Exception as e:
            log(f"NotebookLM upload error: {e}", "ERROR")
            # Distinguish session-expired from generic upload failure — the
            # frontend can offer "re-login then retry" vs "just retry".
            _err_msg = str(e)
            _low = _err_msg.lower()
            is_login_err = any(k in _low for k in ("login", "signin", "auth", "unauthor"))
            retries_left = max(0, p3_max_retries - p3_attempt)
            _title = ("NotebookLM login expired"
                      if is_login_err else
                      f"NotebookLM upload failed: {_err_msg[:200]}")
            _details = ("Re-authenticate in the browser and Retry."
                        if is_login_err else
                        f"{_err_msg[:300]}")
            fail_phase(3, _title, _details, agent="notebooklm",
                       can_retry=retries_left > 0)
            # Wait up to 10 min for user decision. Retry → re-run upload; skip →
            # proceed without NotebookLM; timeout → skip (don't hang pipeline).
            if retries_left > 0:
                p3_decision = await _controls.await_phase_decision(3)
                log(f"Phase 3 upload decision: {p3_decision}")
                if p3_decision == "stop":
                    break
                if p3_decision == "retry":
                    p3_attempt += 1
                    # Close the (possibly borked) NotebookLM tab so the retry
                    # opens a clean one.
                    try:
                        await page.close()
                    except Exception:
                        pass
                    try:
                        emit_event("phase_restart", phase=3,
                                   reason="user_retry_notebooklm_upload",
                                   attempt=p3_attempt + 1)
                    except Exception:
                        pass
                    continue  # retry the upload loop
                # continue_anyway / skip / timeout → break out; proceed with empty notebook_url
                break
            else:
                # No retries left — log and proceed with empty notebook_url
                log("Phase 3: No NotebookLM retries left — proceeding without it", "WARN")
                break
    if not md_files:
        log("No MD files to upload to NotebookLM", "WARN")

    return {"links": links, "notebook_url": notebook_url, "md_files": [str(p) for p in md_files]}


# ── Phase 3 (audio): Audio Overview Generation ───────────────────────────────

async def run_phase3_audio(browser, cua_client, notebook_url, queue_dir, verbose=False, podcast_length="long", prefer_existing_audio: bool = False):
    """Phase 3 (step b): Generate audio overview in NotebookLM + share public.

    `prefer_existing_audio` (2026-05-27, Fix B): set by the no-audio
    auto-retry. When True and the notebook already holds exactly ONE
    completed audio card, treat it as THIS run's own (a prior attempt
    generated it but the download failed) — skip Generate + verification
    and go straight to the (re-anchored) download. Without this, a retry
    re-trips the "1 completed audio from a prior run" pre-flight guard and
    never downloads, or re-runs generation and risks a duplicate card.

    `podcast_length` (2026-05-13 feature): "short" / "default" / "long".
    Drives the customize-panel Format/Length selection via the
    make_prompt_audio_generate factory. Defaults to "long" for backward
    compatibility with callers that don't yet pass the kwarg."""
    log("=" * 60)
    log("PHASE 3 (audio): Audio Overview Generation")
    log("=" * 60)

    if not notebook_url:
        log("No NotebookLM notebook — skipping Phase 3 (audio)", "WARN")
        return {"audio_path": None}

    # Navigate to notebook if not already there
    current = await browser.current_url()
    if "notebooklm" not in current:
        await browser.navigate(notebook_url)
        await asyncio.sleep(4)

    # Early HV gate check — NotebookLM occasionally sits behind Google's bot
    # challenge when the session fingerprint drifts. Clearing it upfront
    # saves us from a cascade of failed CUA clicks that would consume
    # workspace quota without moving forward.
    if cua_client:
        cleared = await check_hv_gate(browser, cua_client, "notebooklm", "NotebookLM",
                                       phase=3, verbose=verbose)
        if not cleared:
            log("Phase 3: HV gate on NotebookLM could not be cleared — aborting audio step", "ERROR")
            return {"audio_path": None}

    # 2026-05-06 (Stream 2 D1): single-attempt audio generation. The outer
    # _await_phase_with_active_deadline(3, PHASE_3_AUDIO_MAX_MIN,
    # soft_warn_only=True) at the call site (:20049) is the sole audio
    # ceiling. User retry routes through that helper's
    # _PhaseSoftDecision('retry') OR through the post-helper no-audio loop
    # — no inner retry/timeout machinery here.
    audio_done = False
    # Fix B (2026-05-27): set when prefer_existing_audio + a single complete
    # card → reuse it (skip Generate + verification, download only).
    _reuse_existing = False

    # Pre-flight invariant check (2026-05-02). Per the user's
    # no-delete constraint, we cannot recover from a duplicate-audio
    # state — we have to prevent it. Two failure modes guarded:
    #   (a) >1 audio card visible → orphaned + duplicate state we
    #       can't safely resolve without deleting one. fail_phase.
    #   (b) exactly 1 card AND not generating → completed orphan
    #       from a prior run. fail_phase asks user to clean it up.
    # The 5s sleep absorbs panel-render lag after the navigate/reload
    # that preceded this loop iteration — without it the count can
    # come back as 0 prematurely.
    await asyncio.sleep(5)
    existing_cards = await _count_nlm_audio_cards(browser.page)
    already_generating = await _check_audio_generating(browser.page)
    log(f"[Phase3] Pre-flight inventory: {existing_cards} audio card(s), generating={already_generating}")

    if existing_cards >= 2:
        fail_phase(3,
                   f"NotebookLM Studio shows {existing_cards} audio entries (expected 0)",
                   "Open the notebook, delete the extra audio entries manually, then retry. We never auto-delete to avoid removing the wrong one.",
                   agent="notebooklm",
                   can_retry=True)
        return {"audio_path": None}

    if existing_cards == 1 and not already_generating:
        if prefer_existing_audio:
            # Fix B (2026-05-27): on a no-audio auto-retry the single
            # completed card is THIS run's own audio — a prior attempt
            # generated it but the download drifted/failed. It is NOT a
            # foreign orphan, so reuse it: skip Generate and go straight to
            # the (Fix-A re-anchored) download. Re-running the full generate
            # path here would re-trip this very guard and never download.
            log("[Phase3] Retry: 1 existing audio card is THIS run's — reusing it (skip Generate, download only)")
            _reuse_existing = True
        else:
            fail_phase(3,
                       "NotebookLM Studio has 1 completed audio from a prior run",
                       "Open the notebook, delete that audio entry manually, then retry. We never auto-delete to avoid touching the wrong one.",
                       agent="notebooklm",
                       can_retry=True)
            return {"audio_path": None}

    if _reuse_existing:
        # Do NOT click Generate. The poll loop's first DOM check
        # (_check_audio_complete_dom) confirms the existing card is complete
        # and breaks straight into the download.
        log("[Phase3] Reuse path: skipping Generate — poll loop will confirm the existing card and download it")
    elif already_generating:
        log("Audio already generating — skipping Generate click")
    else:
        # 2026-05-13: per-variant format + length names for log / narrator
        # / CUA task copy. Mirrors make_prompt_audio_generate's table.
        _variant_label = {
            "short": ("Brief", "the Brief format (no separate length step)"),
            "default": ("Deep Dive", "Deep Dive + Default length"),
            "long": ("Deep Dive", "Deep Dive + Long length"),
        }.get(podcast_length, ("Deep Dive", "Deep Dive + Long length"))
        _fmt_short, _human_desc = _variant_label
        log(f"Starting audio generation ({_human_desc})...")
        _stop, _task = start_narration_ticker(
            3, "notebooklm",
            f"Configuring audio overview ({_human_desc}) and clicking Generate",
            interval=20)
        try:
            _prompt = make_prompt_audio_generate(podcast_length)
            _task_str = (
                f"Generate ONE audio overview. Select all sources, set "
                f"{_human_desc}, click Generate ONCE. Say 'generating' when started."
            )
            _ag_result = await agent_loop(cua_client, browser, _prompt, _task_str,
                model=CUA_MODEL, max_iterations=15, verbose=verbose)
        finally:
            await stop_narration_ticker(_stop, _task)

        # 2026-05-14: capture CUA abort signals. The audio-generate prompt
        # (prompts.py:674-688) instructs CUA to emit exact "abort: …"
        # strings when it detects unsafe states (no customize affordance,
        # customize panel never opened, default audio fired by misclick,
        # or audio already present). Previously the caller ignored the
        # return value, so a CUA-detected misclick would fall through to
        # the post-generate invariant — which runs too early to catch a
        # delayed-rendering default audio card. Surfacing the abort lets
        # the user retry from a clean state instead of polling a confused
        # dual-audio panel for the full audio window.
        _ag_text = (_ag_result.get("text") or "").lower() if isinstance(_ag_result, dict) else ""
        if "abort:" in _ag_text:
            # Race vs. pre-flight: the inventory at :19454 saw 0 cards, but
            # CUA arrived and saw an entry already present. Most likely a
            # left-over from a prior run that the pre-flight missed due to
            # panel-render lag — surface a distinct message so the user
            # knows to clean up the panel.
            if "audio already present" in _ag_text:
                fail_phase(
                    3,
                    "NotebookLM already has an audio overview at start of Phase 3",
                    "CUA aborted because the Studio panel surfaced an existing audio "
                    "entry after our pre-flight check passed (panel-render lag). "
                    "Open the notebook, delete any lingering audio, then retry.",
                    agent="notebooklm",
                    can_retry=True,
                )
            else:
                # Other abort phrases: no_customize_affordance,
                # customize_did_not_open, misclick_default_fired. Fail
                # loud with the verbatim phrase so the user/log makes the
                # cause obvious.
                _reason_phrase = _ag_text.split("abort:", 1)[1].split("\n", 1)[0].strip()[:160]
                fail_phase(
                    3,
                    f"Phase 3 audio generation aborted by CUA — {_reason_phrase or 'unknown reason'}",
                    "The audio-generation step bailed out early to avoid an unsafe NotebookLM state "
                    "(missing customize affordance, default audio fired from a misclick, etc.). "
                    "Retry to try again; if it keeps aborting, open the notebook directly and "
                    "generate the audio overview manually.",
                    agent="notebooklm",
                    can_retry=True,
                )
            return {"audio_path": None}

    # Verify it started. Fix B (2026-05-27): on the reuse path the card is
    # ALREADY complete, so "verify generation started" is both meaningless
    # and dangerous — wait_until_verified escalates to a CUA "click any
    # needed buttons" fix attempt at its retry 7 (research.py wait_until_verified
    # Phase 3), which on a finished notebook can fire a duplicate/default
    # audio — the exact state the no-delete invariant can't recover from.
    if _reuse_existing:
        verified = True
    else:
        verified = await wait_until_verified(
            lambda page: _check_audio_generating(page),
            browser.page, "Phase3-audio", browser=browser, cua_client=cua_client,
            max_retries=10, interval=5, verbose=verbose)

    if not verified:
        log("Could not verify audio generation started", "WARN")

    # Post-generate invariant check (2026-05-02). If CUA misclicked
    # the Audio Overview tile body during the customize flow, the
    # NLM Studio panel auto-fires a default short audio in addition
    # to the one we explicitly requested — leaving the user with two
    # in-flight entries. We can't delete (user constraint), so we
    # fail_phase loud and ask the user to manually clean up the
    # unwanted entry. The 5s sleep gives the new card time to render
    # in the panel before the count.
    await asyncio.sleep(5)
    post_gen_cards = await _count_nlm_audio_cards(browser.page)
    log(f"[Phase3] Post-generate inventory: {post_gen_cards} audio card(s)")
    if post_gen_cards > 1:
        # 2026-05-14: length-aware cleanup instruction. The misclick-fired
        # auto-default is NLM's current default settings, which depends
        # on the user's last customize — so we can't promise which one it
        # is. We CAN promise which one the user wanted (from podcast_length)
        # and tell the user to keep that one.
        _kept = {
            "short": "Brief (~3–5 min, not Deep Dive)",
            "default": "Deep Dive · Default (~10–15 min)",
            "long": "Deep Dive · Long (~20–30 min)",
        }.get(podcast_length, "Deep Dive · Long (~20–30 min)")
        fail_phase(3,
                   f"Duplicate audio overview detected — NotebookLM Studio shows {post_gen_cards} entries",
                   f"Likely a CUA misclick fired a default audio alongside the {_kept} one you requested. "
                   f"Open the notebook, KEEP the {_kept} entry, delete the other one manually, then retry.",
                   agent="notebooklm",
                   can_retry=True)
        return {"audio_path": None}

    # Minimum 2 minute wait — audio generation typically starts within 1-2 min;
    # waiting 5 min was burning slack for no reason. First poll at 2 min is
    # safe (NotebookLM has reliably emitted progress signals by then).
    # Fix B: skip the pre-poll wait on the reuse path — the card is already
    # done, so the poll loop's first DOM check detects + breaks immediately.
    if not _reuse_existing:
        log("Waiting 2 minutes before first audio check (generation takes ~10-20 min)...")
    interrupt = await _controls.interruptible_sleep(0 if _reuse_existing else 2 * 60, check_interval=10)
    if interrupt == "stop":
        log("[Phase3] STOP during initial wait — aborting", "WARN")
        return {"audio_path": None}
    if interrupt == "pause":
        emit_event("pipeline_paused", phase=3)
        await _controls.wait_if_paused()
        if _controls.is_stop():
            return {"audio_path": None}

    # Poll for completion — refresh + CUA check every 3 min. No inner cap;
    # the outer _await_phase_with_active_deadline at :20049 (soft_warn_only=True)
    # is the sole audio ceiling.
    log("Polling for audio completion (every 3 min with refresh; outer soft-warn handles ceiling)...")
    poll_start = time.time()

    while True:
        # ── Stop/Pause check per cycle ──
        if _controls.is_stop():
            log("[Phase3] STOP requested — aborting audio poll")
            break
        if _controls.is_pause():
            emit_event("pipeline_paused", phase=3)
            await _controls.wait_if_paused()
            if _controls.is_stop():
                break

        # Refresh page every cycle (NotebookLM doesn't always auto-update)
        try:
            await browser.page.reload(wait_until="domcontentloaded", timeout=15000)
            await asyncio.sleep(5)
        except Exception:
            pass

        # Mid-poll auth check — NotebookLM session can expire during the
        # audio window. Without this, CUA keeps clicking on a logged-out
        # page. URL-only check (no tabs, no CUA) per the P0 sequential pattern.
        try:
            current_url = (browser.page.url or "").lower()
            if any(h in current_url for h in _LOGIN_HOST_NEGATIVES):
                log(f"[Phase3] NotebookLM session expired mid-audio-poll: {current_url}")
                emit_event("login_required", phase=3,
                           platforms=["notebooklm"],
                           platformLabels=["NotebookLM"],
                           message="NotebookLM session expired during audio generation. Sign back in to resume.",
                           attempt=1)
                emit_event("pipeline_paused", phase=3, reason="notebooklm_login_expired")
                await _controls.wait_if_paused()
                if _controls.is_stop():
                    break
                # User logged back in: reload + continue polling.
                try:
                    await browser.page.reload(wait_until="domcontentloaded", timeout=15000)
                    await asyncio.sleep(3)
                except Exception:
                    pass
        except Exception:
            pass

        # Mid-poll duplicate detection (2026-05-14). The post-generate
        # +5s invariant at :19518 only catches duplicates that render
        # immediately. In practice the misclick-fired default audio
        # can take 5-10 min to appear in the Studio panel — long after
        # the post-gen check has passed. Recount every poll cycle so
        # a duplicate caught mid-flight surfaces inside 3-4 min instead
        # of polling for the full audio window with a confused download
        # picker at the end.
        #
        # 3-min elapsed gate absorbs panel-render lag for the FIRST
        # card; without it a normal single-audio run could trip the
        # check on the first poll when the card is still pending.
        if (time.time() - poll_start) >= 180:
            _live_cards = await _count_nlm_audio_cards(browser.page)
            if _live_cards > 1:
                log(f"[Phase3] Mid-poll duplicate detected: {_live_cards} audio card(s) visible — failing phase so user can clean up", "ERROR")
                # 2026-05-14: length-aware operator instruction.
                _kept = {
                    "short": "Brief (~3–5 min, not Deep Dive)",
                    "default": "Deep Dive · Default (~10–15 min)",
                    "long": "Deep Dive · Long (~20–30 min)",
                }.get(podcast_length, "Deep Dive · Long (~20–30 min)")
                fail_phase(
                    3,
                    f"Duplicate audio detected mid-generation — NotebookLM Studio shows {_live_cards} entries",
                    f"NotebookLM started a second audio (likely a CUA misclick on the Audio Overview card). "
                    f"Open the notebook, KEEP the {_kept} entry you requested, delete the other one manually, then retry. "
                    f"We don't auto-delete in-flight audios to avoid removing the wrong one.",
                    agent="notebooklm",
                    can_retry=True,
                )
                return {"audio_path": None}

        # DOM-first: read the audio card directly. Avoids CUA's
        # page-wide-chrome confusion where unrelated NLM panel
        # spinners triggered "still generating" answers even after
        # the audio itself was done. CUA still runs as fallback.
        dom_complete = await _check_audio_complete_dom(browser.page)
        if dom_complete:
            log("Audio generation complete ✓ (DOM-detected)")
            audio_done = True
            break

        # CUA fallback — strict: only "audio complete" counts.
        # 2026-05-14: prompt is length-aware so CUA looks at the SAME
        # card the generate step produced (not a hardcoded Long + Deep
        # Dive that doesn't exist for short/default runs).
        diag = await agent_loop(cua_client, browser, make_prompt_audio_check(podcast_length),
            "Check: Has audio generation FINISHED? Is there a completed audio player "
            "with NO progress indicator? Answer 'audio complete' ONLY if fully done.",
            model=CUA_MODEL, max_iterations=3, verbose=verbose)
        diag_text = (diag.get("text") or "").lower()

        if "audio complete" in diag_text:
            log("Audio generation complete ✓ (CUA-detected)")
            audio_done = True
            break

        elapsed_min = 5 + int((time.time() - poll_start) / 60)
        log(f"[Phase3] Audio still generating... ({elapsed_min}m total)")
        # Live narration tick — without this the FE dropdown sits on the
        # last pre-poll string ("Setting notebook to…") for the full audio
        # window. Match the P2 round-robin cadence.
        try:
            _len_key = (podcast_length or "default").lower()
            _typ_low, _typ_high = _AUDIO_TYPICAL_RANGE_MIN.get(
                _len_key, _AUDIO_TYPICAL_RANGE_MIN["default"])
            emit_event("agent_progress", phase=3, agent="notebooklm",
                       status="generating",
                       progress=f"NotebookLM still generating audio overview… "
                                f"({elapsed_min}m total / {_typ_low}–{_typ_high}m typical)",
                       elapsedSec=elapsed_min * 60,
                       expectedMinutes=_typ_high)
        except Exception:
            pass
        interrupt = await _controls.interruptible_sleep(90, check_interval=10)
        if interrupt == "stop":
            log("[Phase3] STOP during poll wait — aborting")
            break
        if interrupt == "pause":
            emit_event("pipeline_paused", phase=3)
            await _controls.wait_if_paused()
            if _controls.is_stop():
                break

    # Download audio
    audio_path = None
    if audio_done:
        (queue_dir / "podcasts").mkdir(exist_ok=True)

        # Fix A (2026-05-27): re-anchor to THIS run's notebook before the
        # download agent_loop. Between generate and download the page can
        # drift (a stray CUA navigation, an NLM redirect, a recent-notebooks
        # click) and a drifted page surfaces a DIFFERENT notebook's audio
        # card — the verified root cause of a failed audio stream (the
        # download CUA saw two cards incl. a foreign prior-run one and
        # downloaded nothing). Re-assert the held notebook_url so the Studio
        # panel shows only this notebook's single card. No-op when already
        # anchored (happy path), so it can't disturb a correctly-placed page.
        try:
            _cur_url = await browser.current_url()
        except Exception:
            _cur_url = ""
        _want_nb = _nlm_notebook_id(notebook_url)
        if _want_nb and _want_nb != _nlm_notebook_id(_cur_url):
            log(f"[Phase3] Download re-anchor: page drifted to '{_cur_url[:70]}' — navigating back to this notebook", "WARN")
            try:
                await browser.navigate(notebook_url)
                await asyncio.sleep(5)
            except Exception as _ra_e:
                log(f"[Phase3] Download re-anchor navigate failed: {_ra_e}", "WARN")

        # Use Playwright download event to capture the file reliably
        download_future = asyncio.get_event_loop().create_future()

        async def _on_download(download):
            try:
                # Sanitize filename — special chars like $ break ffmpeg
                clean_name = re.sub(r'[^\w\s.-]', '', download.suggested_filename).strip() or "audio_overview.m4a"
                dest = queue_dir / "podcasts" / clean_name
                await download.save_as(str(dest))
                if not download_future.done():
                    download_future.set_result(dest)
                log(f"Audio downloaded via Playwright: {dest.name}")
            except Exception as e:
                log(f"Download save failed: {e}", "WARN")
                if not download_future.done():
                    download_future.set_result(None)

        browser.page.on("download", _on_download)

        emit_event("agent_progress", phase=3, agent="notebooklm",
                   status="downloading",
                   progress="Downloading audio file from NotebookLM…")
        _stop_d, _task_d = start_narration_ticker(
            3, "notebooklm",
            "Downloading audio overview .m4a from NotebookLM",
            interval=20)
        try:
            # 2026-05-14: length-aware download prompt — CUA targets the
            # SAME card the generate step created (Brief / Deep Dive Default
            # / Long Deep Dive), not the hardcoded Long + Deep Dive that
            # would either not exist (short) or pick the wrong card if a
            # parallel Deep Dive misclick existed (default).
            _dl_result = await agent_loop(cua_client, browser, make_prompt_audio_download(podcast_length),
                "Download the audio file.", model=CUA_MODEL, max_iterations=8, verbose=verbose)
            # Fix A (2026-05-27): the download agent_loop return was previously
            # ignored, so the new "abort: not on notebook" guard would be
            # swallowed. Surface it in the log for diagnostics — the existing
            # no-file fail_phase below still handles the recovery.
            _dl_text = (_dl_result.get("text") or "").lower() if isinstance(_dl_result, dict) else ""
            if "abort:" in _dl_text:
                log(f"[Phase3] Download CUA reported abort: {_dl_text[:160]}", "WARN")
        finally:
            await stop_narration_ticker(_stop_d, _task_d)

        # Wait up to 30s for download event
        try:
            audio_path = await asyncio.wait_for(download_future, timeout=30)
        except asyncio.TimeoutError:
            log("Download event not received — checking common download dirs...", "WARN")
            # Silent: the Downloads-folder scan below has its own fail_phase
            # if it also turns up empty.
            # Fallback: scan common download locations
            for dl_dir in [Path.home() / "Downloads", Path("D:/Downloads")]:
                if not dl_dir.exists():
                    continue
                for ext in ("*.mp3", "*.wav", "*.m4a", "*.webm"):
                    for f in sorted(dl_dir.glob(ext), key=lambda f: f.stat().st_mtime, reverse=True):
                        if (time.time() - f.stat().st_mtime) < 120:  # Created in last 2 min
                            dest = queue_dir / "podcasts" / f.name
                            shutil.move(str(f), str(dest))
                            audio_path = dest
                            log(f"Audio found in {dl_dir.name}: {f.name}")
                            break
                    if audio_path:
                        break
                if audio_path:
                    break

        try:
            browser.page.remove_listener("download", _on_download)
        except Exception:
            pass

        # If we got here with audio_done=True but no audio_path, both the
        # Playwright download event AND the Downloads-folder scan failed.
        # That's a real error — surface it so the user knows Phase 5 will
        # skip and can decide whether to re-run or accept report-only.
        if not audio_path:
            fail_phase(3, "Audio file not located on disk",
                       "NotebookLM finished but neither the Playwright download event nor the Downloads scan found the file.",
                       agent="notebooklm")

    # Strict-keep cleanup (moved 2026-05-02). Was inside the poll loop at
    # the audio-complete detection point — but cleanup-before-download is
    # structurally fragile: if the post-cleanup invariant fail_phased OR
    # cleanup's DOM manipulation re-rendered the panel before the
    # download click landed, the download below never ran. Cleanup
    # post-download means we already have the file on disk; cleanup then
    # prepares the panel for the share-link extract that follows. The
    # invariant degrades from fail_phase to log-warn — share-link extract
    # uses a notebook-level API that doesn't depend on card count.
    if audio_done and audio_path:
        try:
            cleanup = await _cleanup_nlm_keep_requested_audio(browser.page, podcast_length)
            log(f"[Phase3] NLM strict-keep cleanup ({podcast_length}): {cleanup}")
        except Exception as _ce:
            log(f"[Phase3] NLM cleanup failed: {_ce}", "WARN")
        try:
            await asyncio.sleep(2)  # let DOM settle after deletes
            dd_count = await _count_nlm_deep_dive_cards(browser.page)
            total_count = await _count_nlm_audio_cards(browser.page)
            log(f"[Phase3] Post-cleanup inventory ({podcast_length}): {dd_count} Deep Dive / {total_count} total audio card(s)")
            # Length-aware invariant (2026-05-14):
            #   "long"    → expect 1 Deep Dive + 1 total
            #   "default" → cleanup skipped (indistinguishable), accept any total ≥ 1
            #   "short"   → expect 0 Deep Dive + 1 total (Brief, not Deep Dive)
            if podcast_length == "long":
                _ok = (dd_count == 1 and total_count == 1)
            elif podcast_length == "short":
                _ok = (dd_count == 0 and total_count == 1)
            else:
                _ok = (total_count >= 1)
            if not _ok:
                log(f"[Phase3] Post-cleanup invariant warning ({podcast_length}): {dd_count} Deep Dive + {total_count} total — proceeding with share-link extract anyway since audio is already on disk", "WARN")
        except Exception as _ie:
            log(f"[Phase3] Post-cleanup invariant check failed: {_ie}", "WARN")

    # ── Extract NotebookLM Audio Overview shareable link ──
    # Audio overview share: three-dots/menu → Share → Notebook access → public → get link → Save
    audio_overview_url = ""
    if audio_done:
        try:
            page = browser.page
            # Step 1: Open three-dots / options menu near the audio player
            menu_opened = await page.evaluate("""() => {
                // Look for three-dots / more options button near audio player
                const menuBtns = document.querySelectorAll(
                    'button[aria-label*="More"], button[aria-label*="more"], ' +
                    'button[aria-label*="Options"], button[aria-label*="options"], ' +
                    'button[aria-label*="Menu"], button[aria-label*="menu"], ' +
                    '[class*="more"] button, [class*="menu"] button, ' +
                    'button[data-testid*="more"], button[data-testid*="menu"]'
                );
                // Also look for ⋮ (vertical dots) button
                for (const btn of menuBtns) {
                    if (btn.offsetParent !== null) { btn.click(); return 'menu_opened'; }
                }
                // Fallback: look for button with dots icon/text
                const allBtns = document.querySelectorAll('button');
                for (const b of allBtns) {
                    const txt = (b.innerText || '').trim();
                    const label = (b.getAttribute('aria-label') || '').toLowerCase();
                    if (txt === '⋮' || txt === '...' || txt === '⋯' ||
                        label.includes('action') || label.includes('overflow')) {
                        if (b.offsetParent !== null) { b.click(); return 'dots_opened'; }
                    }
                }
                return '';
            }""")
            if menu_opened:
                await asyncio.sleep(1)
                # Step 2: Click "Share" from the menu
                await page.evaluate("""() => {
                    const items = document.querySelectorAll(
                        '[role="menuitem"], [role="option"], li, button'
                    );
                    for (const item of items) {
                        const txt = (item.innerText || item.textContent || '').toLowerCase().trim();
                        if (txt === 'share' || txt === 'share notebook' || txt.startsWith('share')) {
                            item.click();
                            return 'share_clicked';
                        }
                    }
                    return '';
                }""")
                await asyncio.sleep(2)
            else:
                # Fallback: try direct share button
                await page.evaluate("""() => {
                    const shareBtn = document.querySelector(
                        'button[aria-label*="Share"], button[aria-label*="share"]'
                    );
                    if (shareBtn) shareBtn.click();
                    return '';
                }""")
                await asyncio.sleep(2)

            # Step 3: Use shared helper for NLM public access + get link + Save.
            # Helper returns (url, public_verified). Audio share doesn't have
            # a separate downstream consumer that gates on public_verified —
            # we still log it for diagnostic purposes and proceed.
            audio_overview_url, audio_public_verified = await _set_nlm_public_and_get_link(page, "Audio")
            if audio_public_verified:
                log("[Audio] Public share DOM-verified")
            else:
                log("[Audio] Public share NOT DOM-verified — audio link may be private", "WARN")

            if not audio_overview_url:
                # Fallback: NLM emits the same /notebook/{id} URL whether
                # you click "Share notebook" or the audio's three-dot Share,
                # so falling back to current_url (or notebook_url) preserves
                # public-link semantics — only the affordance differs (FE
                # renders the audio row as a Play button + Open-in-NLM link).
                try:
                    current_url = await browser.current_url()
                    if "notebooklm.google.com/notebook" in current_url:
                        audio_overview_url = current_url
                except Exception:
                    pass
                if not audio_overview_url and notebook_url:
                    audio_overview_url = notebook_url

            await page.keyboard.press("Escape")  # Close any remaining dialog
            await asyncio.sleep(0.5)
        except Exception as e:
            log(f"Audio overview link extraction failed: {e}", "WARN")
        if audio_overview_url:
            log(f"Audio overview link: {audio_overview_url}")
            # Emit link immediately — route through validate_link to prevent fake URLs.
            # link_kind="audio" stores it in the aggregate as a separate URL so
            # P5 doc body shows it as the "Link to Audio Overview:" line; FE
            # event keeps agent="notebooklm" so the NLM dropdown groups it.
            emit_validated_link(3, "notebooklm", audio_overview_url, "Audio Overview", link_kind="audio")
        else:
            log("Audio overview link not found — using notebook URL as fallback", "WARN")

    # ── Sync to Firebase Storage + Firestore audios subcollection ──
    # Upload the audio file so the Vercel Podcasts page can stream it
    # without needing the local backend to be reachable. Duration via
    # ffprobe for nice display (M:SS). Best-effort — pipeline continues
    # even if sync fails.
    if audio_path and audio_path.exists():
        try:
            dur_sec = 0
            try:
                # B2 (2026-05-01): wrap sync subprocess in asyncio.to_thread so
                # the asyncio event loop (and _heartbeat_loop on the same loop)
                # keeps ticking. Without this, ffprobe blocked the loop for up
                # to 5s — 1/3 of the 15s offline threshold.
                _probe = await asyncio.to_thread(
                    subprocess.run,
                    ["ffprobe", "-v", "quiet", "-show_entries",
                     "format=duration", "-of", "csv=p=0", str(audio_path)],
                    capture_output=True, text=True, timeout=5)
                dur_sec = int(float(_probe.stdout.strip()))
            except Exception:
                pass
            # B2: Firebase Storage upload (50-100MB on slow uplinks) was the
            # biggest single blocker — easily blew past the 15s offline window.
            audio_url = await asyncio.to_thread(upload_audio_to_storage, audio_path)
            # Use the filename stem as doc id so re-runs upsert in place
            # instead of stacking duplicates. Display name = research
            # title from Firestore (set by FE's /api/title early in P1)
            # so the Podcasts page shows one human-readable title instead
            # of the auto-generated underscore .m4a filename. If the
            # Firestore title isn't set (rare P3-before-P1-write race),
            # smart_title falls back to a stem-derived topic with
            # underscores swapped for spaces — still readable.
            display_name = smart_title(audio_path.stem.replace("_", " "))
            # B2: sync Firestore .set() — small payload but on slow links
            # still worth offloading.
            await asyncio.to_thread(save_audio_to_firestore,
                                    audio_path.stem, display_name, dur_sec, audio_url)
            # FE-P4 cutover (2026-05-10): also pin the Storage URL into
            # research.links.audio_file so the FE-P4 trigger
            # (readResearchForP4 → /api/uploadYouTube) can fetch the
            # downloadable audio without query-walking the audios
            # subcollection. links.audio stays as the NLM share URL
            # (page, not a media file) — the Doc still renders that as
            # "Audio Overview"; links.audio_file is purely for the FE
            # YouTube upload step.
            if audio_url:
                update_link_in_firestore("audio_file", audio_url,
                                         label="Podcast Audio (Storage)", phase=3,
                                         verified=True)
            # Storage upload is best-effort — local playback still works via
            # the backend, and Phase 5 can still upload to YouTube from the
            # local file. Warn (not error) if it failed.
            if not audio_url:
                log("[Phase3] Firebase Storage upload failed — audio still saved locally", "WARN")
        except Exception as e:
            log(f"Audio Firestore/Storage sync failed: {e}", "WARN")

    return {"audio_path": audio_path, "audio_overview_url": audio_overview_url}


async def _check_audio_generating(page):
    """Check if NotebookLM is generating audio."""
    try:
        return await page.evaluate("""() => {
            const text = document.body.innerText.toLowerCase();
            return text.includes('generating') || text.includes('creating audio') || text.includes('in progress');
        }""")
    except Exception:
        return False


async def _check_audio_complete_dom(page) -> bool:
    """Detect a completed NLM audio overview by reading the card's own DOM.
    Returns True only when an audio card has a present <audio> element AND
    no progress indicators AND no generating-related text. Used as a
    DOM-first check before CUA — avoids the page-wide-chrome false
    negatives where CUA reports "still generating" because some unrelated
    NLM panel still shows a spinner while the audio itself is done.
    """
    try:
        return await page.evaluate("""() => {
            const panel = document.querySelector(
                '[aria-label*="Studio" i], [data-testid*="studio" i], aside'
            ) || document.body;
            const candidates = panel.querySelectorAll(
                '[role="article"], [role="listitem"], '
                + '[class*="audio-card"], [class*="AudioCard"], '
                + '[data-testid*="audio"], [data-testid*="overview-item"]'
            );
            for (const el of candidates) {
                if (el.offsetParent === null) continue;
                const t = (el.innerText || '').toLowerCase();
                const isAudio = t.includes('audio overview')
                    || t.includes('conversation') || t.includes('discussion')
                    || t.includes('podcast');
                const isConfigTile = t.includes('customize');
                if (!isAudio || isConfigTile) continue;
                const hasAudioEl = !!el.querySelector('audio');
                if (!hasAudioEl) continue;
                const isBusy = el.getAttribute('aria-busy') === 'true'
                    || !!el.querySelector('[role="progressbar"]')
                    || !!el.querySelector('[aria-busy="true"]');
                const hasGeneratingText = t.includes('generating')
                    || t.includes('creating audio') || t.includes('preparing audio')
                    || t.includes('loading') || t.includes('in progress');
                if (isBusy || hasGeneratingText) continue;
                return true;
            }
            return false;
        }""") or False
    except Exception:
        return False


def _nlm_notebook_id(url: str) -> str:
    """Extract the NotebookLM notebook id from a /notebook/{id} URL.
    Used to detect CUA drift off the run's own notebook before the audio
    download (Fix A 2026-05-27): a drifted page surfaces a DIFFERENT
    notebook's audio card and breaks the download target. Returns "" when
    no id is present (e.g. the page navigated off NotebookLM entirely)."""
    try:
        m = re.search(r"/notebook/([\w-]+)", url or "")
        return m.group(1) if m else ""
    except Exception:
        return ""


# ── Audio-card invariant helpers (2026-05-02) ──────────────────────────────
# Pure read helpers used to enforce the "exactly one Long + Deep Dive
# audio overview" invariant without ever clicking or deleting. Pair with
# the pre-flight check before agent_loop and the post-generate check
# after wait_until_verified — both fail_phase loud if the count is wrong,
# letting the user clean up manually (per the no-delete constraint).
#
# DOM selectors mirror _cleanup_nlm_default_audio so all three functions
# count the same cards. If NotebookLM ships a Studio redesign that breaks
# the selectors, all three break together and the failure is consistent.

async def _count_nlm_audio_cards(page) -> int:
    """Count visible audio-overview cards in the NLM Studio panel.

    Returns the total number of audio entries (in-flight + completed).
    Read-only — never clicks anything. Returns 0 on any DOM exception.
    """
    try:
        return await page.evaluate("""() => {
            const panel = document.querySelector(
                '[aria-label*="Studio" i], [data-testid*="studio" i], aside'
            ) || document.body;
            const candidates = panel.querySelectorAll(
                '[role="article"], [role="listitem"], '
                + '[class*="audio-card"], [class*="AudioCard"], '
                + '[data-testid*="audio"], [data-testid*="overview-item"]'
            );
            let count = 0;
            candidates.forEach((el) => {
                if (el.offsetParent === null) return;
                const t = (el.innerText || '').toLowerCase();
                const isAudio = t.includes('audio overview')
                    || t.includes('conversation') || t.includes('discussion')
                    || t.includes('podcast');
                // Exclude the configuration TILE — the offering UI that
                // contains the "Customize" link/button. Its innerText
                // also matches "audio overview" but it's not a generated
                // entry. Real generated cards (in-flight or done) do not
                // render the word "customize" in their visible text.
                const isConfigTile = t.includes('customize');
                if (isAudio && !isConfigTile) count++;
            });
            return count;
        }""") or 0
    except Exception:
        return 0


async def _count_nlm_deep_dive_cards(page) -> int:
    """Count visible Deep Dive audio cards specifically.

    Distinct from _count_nlm_audio_cards — this only counts entries whose
    innerText contains 'deep dive', matching what the user explicitly
    asked for (Format=Deep Dive, Length=Long). Used by the post-completion
    invariant log to confirm we ended up with the right kind of audio.
    """
    try:
        return await page.evaluate("""() => {
            const panel = document.querySelector(
                '[aria-label*="Studio" i], [data-testid*="studio" i], aside'
            ) || document.body;
            const candidates = panel.querySelectorAll(
                '[role="article"], [role="listitem"], '
                + '[class*="audio-card"], [class*="AudioCard"], '
                + '[data-testid*="audio"], [data-testid*="overview-item"]'
            );
            let count = 0;
            candidates.forEach((el) => {
                if (el.offsetParent === null) return;
                const t = (el.innerText || '').toLowerCase();
                const isAudio = t.includes('audio overview')
                    || t.includes('conversation') || t.includes('discussion')
                    || t.includes('podcast');
                // Same configuration-tile filter as _count_nlm_audio_cards
                // — keep both helpers in lockstep so they count the same
                // population of cards.
                const isConfigTile = t.includes('customize');
                if (isAudio && !isConfigTile && t.includes('deep dive')) count++;
            });
            return count;
        }""") or 0
    except Exception:
        return 0


async def _cleanup_nlm_keep_requested_audio(page, podcast_length: str = "long") -> dict:
    """Strict-keep cleanup. Identifies the SINGLE NLM Studio audio card
    that matches the user-requested `podcast_length` and deletes every
    other audio card around it. If the keep target is missing or
    ambiguous, deletes NOTHING and reports the skip reason — the caller
    can then surface the issue to the user rather than risk nuking the
    real audio.

    2026-05-14: length-aware. Previously hardcoded to "long Deep Dive"
    which broke when the user picked "default" / "short" via the chat
    long-press. Length-specific keep predicates below.

    Length predicates:
      - "long":    hasDeepDive AND (hasLong OR durationMin >= 15)
      - "default": SKIP — both the requested Deep-Dive-Default and the
                   misclick-fired default audio are Deep Dive, so we
                   can't distinguish them by text. Log + warn instead
                   of risking the wrong delete.
      - "short":   NOT hasDeepDive AND durationMin < 10
                   (Brief format ≈ 3-5min; auto-fired default is also
                   Deep Dive so the !hasDeepDive predicate isolates the
                   Brief target cleanly when present.)

    Safety rails:
      - keep_candidates count must be EXACTLY 1; 0 → skip, >1 → skip.
      - delete only cards whose data-cleanup-idx differs from the keep.
      - log every intended deletion via emit_event for audit.
      - caller is expected to verify post-cleanup card count separately;
        this function reports `remaining_after` from a fresh count call
        so the caller doesn't have to re-scan.

    Returns a dict with keys:
      scanned, kept_idx, deleted, remaining_after, skipped_reason,
      podcast_length (echoed for telemetry).
    """
    result = {
        "scanned": 0,
        "kept_idx": None,
        "deleted": 0,
        "remaining_after": None,
        "skipped_reason": None,
        "podcast_length": podcast_length,
    }

    # "default" length: indistinguishable from the misclick-fired audio.
    # Skip cleanup entirely rather than risk a wrong delete — the caller
    # surfaces this via the post-cleanup invariant check.
    if podcast_length == "default":
        result["skipped_reason"] = "default_length_indistinguishable"
        result["remaining_after"] = await _count_nlm_audio_cards(page)
        try:
            emit_event("nlm_cleanup_skipped", phase=3,
                       reason="default_length_indistinguishable",
                       podcast_length=podcast_length)
        except Exception:
            pass
        return result

    try:
        cards = await page.evaluate(f"""() => {{
            const podcastLength = {json.dumps(podcast_length)};
            const panel = document.querySelector(
                '[aria-label*="Studio" i], [data-testid*="studio" i], aside'
            ) || document.body;
            const candidates = panel.querySelectorAll(
                '[role="article"], [role="listitem"], '
                + '[class*="audio-card"], [class*="AudioCard"], '
                + '[data-testid*="audio"], [data-testid*="overview-item"]'
            );
            const out = [];
            candidates.forEach((el, i) => {{
                if (el.offsetParent === null) return;
                const t = (el.innerText || '').toLowerCase();
                const isAudio = t.includes('audio overview')
                    || t.includes('conversation') || t.includes('discussion')
                    || t.includes('podcast');
                const isConfigTile = t.includes('customize');
                if (!isAudio || isConfigTile) return;
                // Length-aware keep predicate (2026-05-14):
                //   "long"  → deep dive AND (long-tag OR duration >= 15min)
                //   "short" → NOT deep dive AND duration < 10min (Brief)
                // "default" never reaches this block (early return above).
                const hasDeepDive = t.includes('deep dive');
                const hasLong = t.includes('long');
                const durMatch = t.match(/(\\d+):(\\d+)/);
                const durMinutes = durMatch ? parseInt(durMatch[1], 10) : 0;
                let isKeep = false;
                if (podcastLength === "short") {{
                    // Brief format audio: not Deep Dive AND short duration.
                    // durMinutes==0 happens when NLM hasn't rendered the
                    // duration yet — accept that as a candidate so we
                    // don't lose track of an in-flight Brief.
                    isKeep = !hasDeepDive && (durMinutes === 0 || durMinutes < 10);
                }} else {{
                    // "long" (and any unknown value falls back here)
                    const isLongDuration = durMinutes >= 15;
                    isKeep = hasDeepDive && (hasLong || isLongDuration);
                }}
                el.setAttribute('data-cleanup-idx', String(i));
                out.push({{
                    idx: i,
                    isKeep: isKeep,
                    hasDeepDive: hasDeepDive,
                    hasLong: hasLong,
                    durationMin: durMinutes,
                    snippet: t.slice(0, 100),
                }});
            }});
            return out;
        }}""") or []

        result["scanned"] = len(cards)
        keep_candidates = [c for c in cards if c["isKeep"]]

        # Safety rail: must have EXACTLY one unambiguous keep target.
        if len(keep_candidates) == 0:
            result["skipped_reason"] = "no_keep_target_found"
            try:
                emit_event("nlm_cleanup_skipped", phase=3,
                           reason="no_keep_target_found",
                           scanned=result["scanned"])
            except Exception:
                pass
            return result
        if len(keep_candidates) > 1:
            result["skipped_reason"] = f"ambiguous_keep_targets ({len(keep_candidates)} matches)"
            try:
                emit_event("nlm_cleanup_skipped", phase=3,
                           reason="ambiguous_keep_targets",
                           scanned=result["scanned"],
                           keep_count=len(keep_candidates))
            except Exception:
                pass
            return result

        keep = keep_candidates[0]
        result["kept_idx"] = keep["idx"]
        delete_targets = [c for c in cards if c["idx"] != keep["idx"]]

        # Nothing to delete — the panel is already in the desired state.
        if not delete_targets:
            result["remaining_after"] = await _count_nlm_audio_cards(page)
            return result

        # Audit log every intended deletion BEFORE clicking, so we have a
        # paper trail in telemetry even if the click sequence half-fails.
        try:
            emit_event("nlm_cleanup_plan", phase=3,
                       keep_snippet=keep["snippet"],
                       deletes=[d["snippet"] for d in delete_targets])
        except Exception:
            pass

        for card in delete_targets:
            # Open the card's "..." / More menu.
            opened = await page.evaluate(f"""() => {{
                const c = document.querySelector('[data-cleanup-idx="{card["idx"]}"]');
                if (!c) return false;
                const m = c.querySelector(
                    'button[aria-label*="More" i], button[aria-label*="Options" i], '
                    + 'button[aria-haspopup="menu"]'
                );
                if (!m) return false;
                m.click(); return true;
            }}""")
            if not opened:
                continue
            await asyncio.sleep(0.6)

            # Click Delete in the menu.
            deleted = await page.evaluate("""() => {
                const items = document.querySelectorAll(
                    '[role="menuitem"], [role="menuitemradio"]'
                );
                for (const m of items) {
                    const t = (m.innerText || '').trim().toLowerCase();
                    if (t === 'delete' || t === 'remove' || t.startsWith('delete')) {
                        m.click(); return true;
                    }
                }
                return false;
            }""")
            if not deleted:
                try:
                    await page.keyboard.press("Escape")
                except Exception:
                    pass
                continue
            await asyncio.sleep(0.5)

            # Confirm in the secondary dialog if NLM shows one.
            try:
                await page.evaluate("""() => {
                    const dlg = document.querySelector('[role="dialog"], [role="alertdialog"]');
                    if (!dlg) return false;
                    const btns = dlg.querySelectorAll('button');
                    for (const b of btns) {
                        const t = (b.innerText || '').trim().toLowerCase();
                        if (t === 'delete' || t === 'remove' || t === 'confirm') {
                            b.click(); return true;
                        }
                    }
                    return false;
                }""")
            except Exception:
                pass
            await asyncio.sleep(0.8)
            result["deleted"] += 1
            try:
                emit_event("nlm_cleanup_deleted", phase=3,
                           card_snippet=card["snippet"],
                           had_deep_dive=card["hasDeepDive"],
                           duration_min=card["durationMin"])
            except Exception:
                pass

        # Defensive: close any lingering menu/dialog so share-link
        # extraction runs against a clean DOM.
        try:
            await page.keyboard.press("Escape")
            await asyncio.sleep(0.3)
        except Exception:
            pass

        # Re-count so the caller can verify the invariant in one place.
        result["remaining_after"] = await _count_nlm_audio_cards(page)
        try:
            emit_event("nlm_cleanup_done", phase=3,
                       scanned=result["scanned"],
                       deleted=result["deleted"],
                       remaining_after=result["remaining_after"])
        except Exception:
            pass
        return result
    except Exception as e:
        result["skipped_reason"] = f"{type(e).__name__}: {e}"
        try:
            emit_event("nlm_cleanup_error", phase=3, error=str(e)[:200])
        except Exception:
            pass
        return result



# ── Checkpoint & Resume ───────────────────────────────────────────────────────

def save_checkpoint(queue_dir, phase, **kwargs):
    """Save pipeline checkpoint after completing a phase."""
    cp = {"last_completed_phase": phase, "timestamp": datetime.now().isoformat()}
    cp.update(kwargs)
    # Enrichment (2026-04-28, Commit 1 of error-redesign): persist tier
    # escalation history, per-agent state, and last_event_id so a Phoenix
    # restart can resume retry budgets fairly + dedupe replayed events.
    # Caller-supplied kwargs win — we only fill if not already passed.
    try:
        snap = _runtime.snapshot()
        for key in ("tier_escalation_history", "agent_states", "last_event_id"):
            if key not in cp and key in snap:
                cp[key] = snap[key]
    except Exception:
        pass
    (Path(queue_dir) / "checkpoint.json").write_text(json.dumps(cp, indent=2), encoding="utf-8")


def load_checkpoint(queue_dir):
    """Load checkpoint from a previous run. Returns dict or None."""
    cp_file = Path(queue_dir) / "checkpoint.json"
    if cp_file.exists():
        try:
            return json.loads(cp_file.read_text(encoding="utf-8"))
        except Exception:
            pass
    return None


# Sentence-boundary chars used to expand a URL match into its enclosing
# citation snippet. Treats double-newline (paragraph break) the same as
# a hard sentence ending so we don't bleed across markdown paragraphs.
_FIND_SENT_TAIL_RE = re.compile(r'(?:[.!?]\s|\n\n|\n#{1,4}\s)', re.MULTILINE)
_FIND_SENT_HEAD_RE = re.compile(r'(?:[.!?]\s|\n\n|\n#{1,4}\s)', re.MULTILINE)
_FIND_HEADING_RE = re.compile(r'^#{2,4}\s+(.{2,80})$', re.MULTILINE)
_FIND_MD_LINK_RE = re.compile(r'\[([^\]]{1,200})\]\(([^)]+)\)')


def _extract_findings(md: str, source_urls: list) -> list:
    """For each cited source URL, locate the enclosing sentence in the
    agent's markdown report and return a structured finding entry:
    `{"url": str, "snippet": str, "sourceTitle": str}`.

    Approach is regex-based — the agents' markdown is LLM-generated and
    not adversarial; URL substring matching plus sentence-boundary
    expansion (lookback to last `.`/`?`/`!`/double-newline, lookforward
    to next) gives a robust 80-280 char snippet without needing a full
    markdown AST.

    Snippet rules:
      - Strip markdown link syntax `[label](url)` → `label` so the
        body reads as prose, not raw markdown.
      - Cap at 280 chars with `…` suffix when sliced.
      - Skip when expanded snippet is < 30 chars (almost certainly a
        bare reference list entry, not a real cited mention).

    SourceTitle = first non-empty heading (`##` / `###`) preceding the
    URL, or hostname fallback if no heading is found before it.

    Caps result list at 12 per agent. Order = first-mention order in
    the markdown, deduped by URL.
    """
    if not md or not source_urls:
        return []
    findings: list = []
    seen_urls: set = set()
    # Pre-scan headings so we can find the nearest preceding heading
    # for any URL match in O(1) per match — without this, a huge md
    # would re-scan from start for every URL.
    headings: list = []
    for hm in _FIND_HEADING_RE.finditer(md):
        headings.append((hm.start(), hm.group(1).strip()))
    for url in source_urls:
        if not url or url in seen_urls:
            continue
        seen_urls.add(url)
        idx = md.find(url)
        if idx < 0:
            continue
        # Find sentence start: last sentence-end token BEFORE idx.
        head_search = md[:idx]
        head_match = None
        for m in _FIND_SENT_HEAD_RE.finditer(head_search):
            head_match = m
        sent_start = head_match.end() if head_match else 0
        # Find sentence end: first sentence-end token AFTER idx + len(url).
        url_end = idx + len(url)
        tail_match = _FIND_SENT_TAIL_RE.search(md, url_end)
        sent_end = tail_match.start() if tail_match else min(url_end + 200, len(md))
        snippet = md[sent_start:sent_end].strip()
        if len(snippet) < 30:
            continue
        # Replace markdown links with their label text — keeps prose
        # readable and avoids "click 'http://...'" awkwardness.
        snippet = _FIND_MD_LINK_RE.sub(lambda m: m.group(1), snippet)
        # Collapse internal whitespace so "  \n   " runs read as a
        # single space in the rendered card.
        snippet = re.sub(r'\s+', ' ', snippet).strip()
        if len(snippet) > 280:
            snippet = snippet[:279].rstrip() + "…"
        # Locate nearest preceding heading.
        title = ""
        for h_pos, h_text in headings:
            if h_pos > idx:
                break
            title = h_text
        if not title:
            try:
                from urllib.parse import urlparse as _urlparse
                _h = (_urlparse(url).hostname or "").lower()
                if _h.startswith("www."):
                    _h = _h[4:]
                title = _h
            except Exception:
                title = ""
        title = title[:80]
        findings.append({"url": url, "snippet": snippet, "sourceTitle": title})
        if len(findings) >= 12:
            break
    return findings


def save_meta(queue_dir, topic, phase, status="ongoing", **extra):
    """Save/update meta.json — powers ALL frontend components (graphs, analytics, tracking).
    Contains: Research object + per-agent stats + phase timeline + source references."""
    queue_dir = Path(queue_dir)
    meta_path = queue_dir / "meta.json"
    meta = {}
    if meta_path.exists():
        try:
            meta = json.loads(meta_path.read_text(encoding="utf-8"))
        except Exception:
            pass
    if "id" not in meta:
        meta["id"] = queue_dir.name
        meta["createdAt"] = int(time.time() * 1000)

    # ── Scan documents/ for files ──
    docs = []
    doc_dir = queue_dir / "documents"
    if doc_dir.exists():
        for f in sorted(doc_dir.glob("*.md")):
            if f.stat().st_size > 50:
                docs.append({"id": f.stem, "name": f.name, "type": f.stem,
                              "size": f"{f.stat().st_size / 1024:.0f} KB",
                              "createdAt": int(f.stat().st_mtime * 1000)})

    # ── Scan podcasts/ for audio files ──
    podcasts = []
    pod_dir = queue_dir / "podcasts"
    if pod_dir.exists():
        for f in pod_dir.glob("*.*"):
            # Try to get duration from ffprobe
            dur_sec = 0
            try:
                r = subprocess.run(["ffprobe", "-v", "quiet", "-show_entries",
                    "format=duration", "-of", "csv=p=0", str(f)],
                    capture_output=True, text=True, timeout=5,
                    creationflags=_PS_NO_WINDOW)
                dur_sec = int(float(r.stdout.strip()))
            except Exception:
                pass
            mins, secs = divmod(dur_sec, 60)
            podcasts.append({"id": f.stem, "name": f.name,
                             "duration": f"{mins}:{secs:02d}" if dur_sec else "",
                             "durationSec": dur_sec,
                             "createdAt": int(f.stat().st_mtime * 1000)})

    # ── Per-agent stats (for analytics graphs, radar chart, health score) ──
    agents = meta.get("agents", {})
    for platform in ["chatgpt", "gemini", "claude"]:
        md_file = doc_dir / f"{platform}.md" if doc_dir.exists() else None
        if md_file and md_file.exists() and md_file.stat().st_size > 100:
            content = md_file.read_text(encoding="utf-8")
            # Extract sections — markdown headings + bold standalone lines (ChatGPT style)
            sections = re.findall(r'^#{1,3}\s+(.+)$', content, re.MULTILINE)
            if len(sections) <= 2:
                # ChatGPT often uses **Bold Title** instead of # headings
                bold_sections = re.findall(r'^\*\*(.{5,80})\*\*\s*$', content, re.MULTILINE)
                # Also try numbered bold: **1. Title**
                numbered = re.findall(r'^\*\*\d+[\.\)]\s*(.{5,80})\*\*', content, re.MULTILINE)
                sections = sections + bold_sections + numbered
                sections = list(dict.fromkeys(sections))[:20]  # Dedupe
            # Filter out the file header we added
            sections = [s for s in sections if s not in ("ChatGPT Deep Research", "Gemini Deep Research", "Claude Deep Research")]
            # Extract source URLs from markdown links and references
            urls = re.findall(r'https?://[^\s\)\]\"\'>]+', content)
            unique_urls = list(dict.fromkeys(urls))[:50]  # Dedupe, cap at 50
            # Build/update agent entry. unique_urls is already capped at 50.
            existing = agents.get(platform, {})
            # 2026-05-04: pull the runtime per-agent progress snapshot so
            # searches + observedSources land in the persisted Firestore
            # agents map alongside the markdown-derived fields above. The
            # FE post-completion stub (PhaseDropdown.tsx _postCompletionStub)
            # reads these to recap "Xk chars, N sources, M searches" on
            # chat reopen — without persistence, the live pipeline_events
            # window prunes past 50 entries and the values defaulted to 0,
            # making the stub show only chars+sources after a long break.
            try:
                _snap = dict(getattr(_runtime, "agent_progress_snapshots", {}).get(platform, {}) or {})
            except Exception:
                _snap = {}
            # Downsample the per-agent progressHistory ring (cap 240) to
            # 60 evenly-spaced points + first + last. The FE GraphAnalysis
            # All-Agents sparklines + the post-reload chart restoration
            # both consume this — without persistence, reopening a
            # finished run shows flat "No data" because the in-memory
            # ring is already gone.
            try:
                _raw_hist = list(getattr(_runtime, "agent_progress_history", {}).get(platform, []) or [])
            except Exception:
                _raw_hist = []
            _down_hist: list = []
            if len(_raw_hist) <= 60:
                _down_hist = _raw_hist
            elif _raw_hist:
                _step = (len(_raw_hist) - 1) / 59.0
                _seen: set = set()
                for _i in range(60):
                    _idx = min(int(round(_i * _step)), len(_raw_hist) - 1)
                    if _idx not in _seen:
                        _seen.add(_idx)
                        _down_hist.append(_raw_hist[_idx])
                # Always pin first + last so the curve endpoints land on
                # real values, not the closest sampled neighbor.
                if _down_hist and _down_hist[0] is not _raw_hist[0]:
                    _down_hist[0] = _raw_hist[0]
                if _down_hist and _down_hist[-1] is not _raw_hist[-1]:
                    _down_hist[-1] = _raw_hist[-1]
            try:
                _findings = list(getattr(_runtime, "agent_findings", {}).get(platform, []) or [])
            except Exception:
                _findings = []
            agents[platform] = {
                "sources": len(unique_urls),
                "sourceUrls": unique_urls,
                "sections": sections[:15],
                "outputChars": len(content),
                "completionTimeSec": existing.get("completionTimeSec", 0),
                # Real cited-source findings populated by C4b (extractor
                # runs after each agent's markdown is written). Falls
                # back to section headings when the extractor returns
                # empty so legacy reads don't break — see C4b for the
                # extractor wiring.
                "findings": _findings if _findings else (sections[:3] if sections else []),
                "searches": int(_snap.get("searches", 0) or existing.get("searches", 0) or 0),
                "observedSources": int(_snap.get("observed_sources", 0) or existing.get("observedSources", 0) or 0),
                "progressHistory": _down_hist,
            }

    # ── Phase timeline (for timeline graph) ──
    phases = meta.get("phases", [])
    # Canonical 6-phase timeline (0-5). Audio is part of NotebookLM (phase 3),
    # NOT a separate phase — the BE records the whole NLM+audio span as phase 3
    # (see the phase_complete phase=3 with the full _p3_start duration). Phase 4
    # is YouTube, phase 5 is Delivery (both FE-stamped). The old 7-entry array
    # split "Audio Overview" out as its own phase, which mislabeled the Analytics
    # timeline; kept in lockstep with web PHASE_META + the FE P4/P5 phase stamps.
    phase_labels = ["Initializing", "Research Brief", "Deep Research",
                    "Links + NotebookLM + Audio", "Video + YouTube", "Delivery"]
    now_ms = int(time.time() * 1000)
    # Ensure all phases up to current exist
    while len(phases) <= phase:
        p_idx = len(phases)
        # Start time: use previous phase's completedAt, or createdAt for first phase
        start = meta.get("createdAt", now_ms)
        if p_idx > 0 and len(phases) > 0 and phases[-1].get("completedAt"):
            start = phases[-1]["completedAt"]
        phases.append({
            "phase": p_idx,
            "label": phase_labels[p_idx] if p_idx < len(phase_labels) else f"Phase {p_idx}",
            "startedAt": start,
            "completedAt": None,
            "durationSec": 0,
        })
    # Mark current phase as completed with actual duration
    if phase < len(phases) and phases[phase]["completedAt"] is None:
        phases[phase]["completedAt"] = now_ms
        started = phases[phase].get("startedAt", now_ms)
        phases[phase]["durationSec"] = max(0, (now_ms - started) // 1000)

    # ── Write meta ──
    meta.update({
        "title": topic[:100] if topic else meta.get("title", ""),
        "topic": topic or meta.get("topic", ""),
        "summary": extra.get("summary", meta.get("summary", "")),
        "status": status,
        "phase": phase,
        "platforms": ["chatgpt", "gemini", "claude"],
        "documents": docs,
        "audios": podcasts,
        "agents": agents,
        "phases": phases,
        "updatedAt": now_ms,
    })
    meta_path.write_text(json.dumps(meta, indent=2), encoding="utf-8")

    # ── Propagate structured agents/phases to Firestore research doc ──
    # Without this, the frontend Analytics page never sees per-agent stats or
    # phase timelines for live runs — they live only on disk. Uses a shallow
    # update so we don't clobber other fields (like pipelineConfig).
    try:
        _update_firestore_research({
            "agents": agents,
            "phases": phases,
            "status": status,
            "phase": phase,
            "updatedAt": now_ms,
        })
    except Exception as _e:
        log(f"save_meta: firestore propagation failed: {_e}", "WARN")


def detect_resume_phase(queue_dir):
    """Detect which phase to resume from based on existing output files.
    Returns (phase_number, description). 5-phase BE model (0-4) plus
    FE-owned Phase 5 (Doc + email). Return value of 5 means "BE work is
    done, FE-P5 still needs to fire" — run_pipeline handles this by
    re-emitting phase_complete phase=4 to retrigger triggerFeP5 on the
    frontend (its CAS guard makes a re-trigger idempotent). 6 means
    "delivery.json marks the run completed — nothing to resume"."""
    queue_dir = Path(queue_dir)
    if (queue_dir / "delivery.json").exists():
        try:
            delivery = json.loads((queue_dir / "delivery.json").read_text(encoding="utf-8"))
            if delivery.get("status") == "completed":
                return 6, "Pipeline already complete"
        except Exception:
            pass
    cp = load_checkpoint(queue_dir)
    # Phase 4 done — BE work complete, FE-P5 retriggered via re-emit of
    # phase_complete phase=4 inside run_pipeline.
    if cp and cp.get("youtube_url"):
        return 5, "YouTube done — Phase 4 complete, FE will pick up Phase 5"
    # Phase 3 done → resume from Phase 4: check if audio exists
    if cp and cp.get("audio_path") and Path(cp["audio_path"]).exists():
        return 4, "Audio exists — Phase 3 done, resuming from Phase 4 (YouTube)"
    audio_dir = queue_dir / "podcasts"
    if audio_dir.exists() and any(audio_dir.glob("*.*")):
        return 4, "Audio exists — Phase 3 done, resuming from Phase 4 (YouTube)"
    # Phase 2 done but no audio → resume from Phase 3: check if links/notebook exist
    if (queue_dir / "links.json").exists():
        return 3, "Links exist — resuming from Phase 3 (NotebookLM)"
    # Phase 2 done → resume from Phase 3 ONLY if the Phase-2 completion
    # marker is present. The marker is written after the round-robin poller
    # returned (i.e. all agents reached a terminal state). Without the
    # marker, "any non-brief MD >100 bytes" was too coarse — a backend crash
    # mid-P2 with only one agent's MD on disk would falsely jump to Phase 3,
    # silently skipping the agents that hadn't finished yet.
    marker = queue_dir / "phase2_complete.marker"
    if marker.exists():
        return 3, "Phase 2 complete marker present — resuming from Phase 3"
    # No marker but some MDs on disk → P2 was interrupted. Restart Phase 2
    # so the unfinished agents complete. NOTE: re-running P2 re-extracts
    # ALL enabled agents from scratch (`run_phase2` doesn't currently scan
    # disk to skip already-finished agents). Existing MDs are overwritten
    # via the Firestore upsert in `save_document_to_firestore`. Wasteful
    # on time but safe — the only correctness cost is a few extra minutes
    # of agent work; data-wise the new MDs are at least as good as the
    # old. An idempotency guard ("if documents/{agent}.md exists, skip
    # launching") would be a real refactor, not landed here.
    research_dir = queue_dir / "documents"
    has_partial_research = research_dir.exists() and any(
        f for f in research_dir.glob("*.md") if f.stat().st_size > 100 and f.stem != "brief")
    if has_partial_research:
        return 2, "Phase 2 partial MDs present without completion marker — re-running Phase 2 (all agents)"
    # Phase 1 done → resume from Phase 2: check if brief exists
    brief = queue_dir / "documents" / "brief.md"
    if not brief.exists():
        brief = queue_dir / "brief.md"
    if brief.exists() and brief.stat().st_size > 100:
        return 2, "Brief exists — Phase 1 done, resuming from Phase 2"
    return 0, "Starting from Phase 0 (Init)"


# ── Main Pipeline ─────────────────────────────────────────────────────────────

async def run_pipeline(topic, pdf_paths=None, brief_file=None, verbose=False,
                       api_key=None, email=None, resume_dir=None, config=None,
                       run_id=None, uid=None, research_id=None, brief_text="",
                       user_sources=None, user_links=None):
    """Run the full pipeline. Supports resume from a previous queue directory.

    brief_text (2026-04): inline brief content passed from the frontend when
    the user toggled Phase 1 off. Written to the new run's
    queues/<run>/documents/brief.md before Phase 1 decides its path; this
    makes `brief_file` point at the fresh file and flows through the
    `_brief_from_file` branch, skipping ChatGPT brief generation + share-link
    extraction.

    user_sources (2026-04-29): Flow B. List of {name, storagePath, mime}
    when P1 + all P2 agents are skipped — the user attached source files to
    NotebookLM directly. BE downloads each from Firebase Storage into
    queue_dir/documents/<name>.md before P3 fires; the existing
    _build_phase2_to_phase3_handoff scan then naturally feeds them into NLM.

    user_links (2026-04-29): Flow C. List of {kind, label, url} when P1 + P2
    + P3 are all skipped — the user pasted source URLs and just wants the
    final Doc + email. BE hydrates notebook_url / youtube_url / audio_url /
    links from these in the P3-skip block so P5 has something to compose."""
    user_sources = user_sources or []
    user_links = user_links or []
    pdf_paths = pdf_paths or []
    # Collapse internal whitespace runs in the topic to single spaces. Multi-
    # line topics (Flow C: user pastes URLs+labels, FE concatenates as topic
    # with newlines) would otherwise leak \n into the queue dir name, the Doc
    # title, the email subject, and FE storage. safe_name() handles the dir
    # part, but we want the topic STRING itself clean for downstream
    # consumers too.
    if isinstance(topic, str):
        topic = re.sub(r'\s+', ' ', topic).strip()
    api_key = resolve_api_key(api_key)
    if not api_key:
        log("No API key (set ANTHROPIC_API_KEY)", "ERROR")
        return

    import anthropic
    cua_client = anthropic.Anthropic(api_key=api_key)

    # ── Initialize pipeline controls + Firestore bridge ──
    _controls.reset()
    _runtime.reset()
    # Clear dedup cache — stale keys from a prior run in the same process
    # would otherwise suppress early events in this run.
    _last_progress.clear()
    # Defensive: clear the OS clipboard at run start. Several share-link
    # extractors (NotebookLM, ChatGPT share-URL, Claude artifact copy)
    # fall back to reading the clipboard via get_clipboard() when DOM
    # selectors miss. The OS clipboard is process-global and persists
    # across runs on every platform — a stale share URL from a prior
    # run sitting in the clipboard could be accepted as THIS run's link
    # and emitted to Firestore. Nukes the cross-run bleed channel.
    # (The original YouTube-specific rationale is gone — P4 is now FE-
    # owned and uses the YouTube Data API, no clipboard extraction —
    # but the bleed risk for the remaining BE extractors stands.)
    clear_clipboard()
    brief_artifact = None  # Set after Phase 1 completes
    # Validate email early (email is the user's Google account email from frontend)
    if email:
        ok, reason = validate_email(email)
        if not ok:
            log(f"[email] Invalid email received: {reason} — Phase 5 email will be skipped", "WARN")
            email = None
    if uid:
        # Use frontend research_id for Firestore paths (not run_id which is the backend dir name)
        setup_firestore_run(uid, research_id or run_id, asyncio.get_running_loop(), run_id=run_id)
    if _cli_mode:
        # CLI mode has no Firestore command listener — wire stdin instead so
        # the user can resume/skip/stop from the same terminal.
        _start_cli_command_reader(asyncio.get_running_loop())
    # Start mid-run input dispatcher (watches _controls.extra_context, pastes to active pages)
    try:
        _runtime.dispatcher_task = asyncio.create_task(run_input_dispatcher())
    except Exception as e:
        log(f"[dispatcher] Failed to start: {e}", "WARN")

    # ── Determine queue directory + start phase ──
    if resume_dir:
        queue_dir = Path(resume_dir)
        if not queue_dir.exists():
            log(f"Resume dir not found: {queue_dir}", "ERROR")
            return
        (queue_dir / "documents").mkdir(exist_ok=True)
        # Set the active-run global as early as possible so the
        # `clear_local_storage` device-command handler treats this dir
        # as protected. Without this, a clear fired during the lengthy
        # checkpoint-restore / config-load block below could rmtree the
        # dir we're about to resume from. Also re-set at line ~17235
        # for symmetry with the new-run branch — idempotent.
        init_tracks(queue_dir.name)
        # Mark as retry/resume so browser-crash sites surface the real alert
        # (auto-retry won't fire from finally for this attempt — the guard
        # at the bottom of run_pipeline gates on `not resume_dir`).
        _runtime.is_retry_attempt = True
        start_phase, reason = detect_resume_phase(queue_dir)
        log(f"RESUME: {reason}")
        # Emit resume marker so frontend knows to ignore events before this point
        emit_event("pipeline_resumed", phase=start_phase, resumeReason=reason)
        if start_phase >= 6:
            log("Pipeline already complete — nothing to resume")
            return
        if start_phase == 5:
            # P4 was done before crash but FE-P5 may not have completed
            # (Doc + email is FE-owned post-2026-04-30). Re-emit
            # phase_complete phase=4 with the checkpoint links so the FE
            # listener fires triggerFeP5 again. Its CAS guard
            # (casFeP5 + feP5State) handles "already completed" /
            # "in flight" idempotently.
            cp = load_checkpoint(queue_dir) or {}
            yt_url = cp.get("youtube_url", "")
            nb_url = cp.get("notebook_url", "")
            bf_url = cp.get("brief_url", "")
            _resume_links = []
            if yt_url:
                _resume_links.append({"label": "YouTube Video", "url": yt_url, "verified": True})
            if nb_url:
                _resume_links.append({"label": "NotebookLM", "url": nb_url, "verified": True})
            if bf_url:
                _resume_links.append({"label": "Research Brief", "url": bf_url, "verified": True})
            emit_event("phase_complete", phase=4, durationSec=0, links=_resume_links,
                       summary="Resumed from checkpoint — frontend handles Phase 5")
            log("Resume: P4 already done, re-emitted phase_complete phase=4 to retrigger FE-P5")
            update_delivery(status="completed")
            # Mirror the success-path handoff (~line 18663): advance both
            # phase AND currentPhase to 5 so the homepage tile diagram
            # stops glowing the YouTube node and FE-P5 picks up cleanly.
            # Pre-fix this only wrote phase=4, leaving currentPhase stale
            # at 4 and the diagram painting YouTube as the active node
            # forever post-resume.
            # 2026-05-11: same beDone marker as the main exit so the
            # queue gate also fires for resume-from-checkpoint runs.
            _update_firestore_research({
                "status": "ongoing", "phase": 5, "currentPhase": 5,
                "beDone": True, "beDoneAt": int(time.time() * 1000),
            })
            # 2026-05-12: autonomous P4/P5 trigger also fires on resume-
            # from-checkpoint so a Phoenix restart that lands here doesn't
            # leave the chain dangling on the FE listener (which may not
            # be alive when this resume path runs from the daemon-loop).
            try:
                _fire_fe_p4_trigger(_fb_uid, _fb_research_id)
            except Exception as _trig_err:
                log(f"FE trigger dispatch failed on resume (non-fatal): {_trig_err}", "WARN")
            return
        cp = load_checkpoint(queue_dir) or {}
        topic = topic or cp.get("topic", queue_dir.name.rsplit("_", 2)[0].replace("_", " "))
        # Load pipeline config on resume
        config_path = queue_dir / "config.json"
        pipeline_config = json.loads(config_path.read_text(encoding="utf-8")) if config_path.exists() else {}
        # Restore tier escalation history so retry budgets carry over from
        # the prior run (a Phoenix restart at T1 attempt 2 doesn't reset to
        # attempt 1 — the framework's 30-min window judges that fairly).
        try:
            for key, esc_dict in (cp.get("tier_escalation_history") or {}).items():
                if isinstance(esc_dict, dict):
                    _tier_escalations[key] = TierEscalation.from_dict(esc_dict)
            # Restore agent_states + last_event_id so a Phoenix-resumed run
            # rebuilds "where each agent was" before silence escalation.
            _runtime.agent_states = dict(cp.get("agent_states") or {})
            _runtime.last_event_id = cp.get("last_event_id", "") or ""
        except Exception as _re:
            log(f"[resume] tier/agent state restore failed: {_re}", "WARN")
    else:
        # Flow C cosmetic — when the user pasted only URLs (no prose), the
        # FE-supplied topic is the raw URL string. That makes for an ugly
        # Doc title, sidebar tile, queue dir name, and email subject.
        # Replace it with a label-based summary derived from the parsed
        # link kinds (e.g. "Research from NotebookLM, YouTube, Google Doc")
        # so every downstream consumer renders something readable. Pure
        # cosmetic — pipeline routing is unaffected.
        if user_links and topic.strip().lower().startswith(("http://", "https://")):
            _labels = []
            _seen_labels = set()
            for _l in user_links:
                _lbl = (_l.get("label") or "").strip()
                if _lbl and _lbl not in _seen_labels:
                    _seen_labels.add(_lbl)
                    _labels.append(_lbl)
            if _labels:
                topic = "Research from " + ", ".join(_labels[:5])
        run_name = run_id or f"{safe_name(topic)}_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
        queue_dir = Path(__file__).parent / "queues" / run_name
        queue_dir.mkdir(parents=True, exist_ok=True)
        (queue_dir / "documents").mkdir(exist_ok=True)
        # Set the active-run global immediately after mkdir so a
        # `clear_local_storage` device command fired during Flow B
        # source downloads / config write doesn't rmtree this dir
        # mid-construction. The init_tracks call at line ~17235 is
        # now redundant on this branch but harmless (idempotent).
        init_tracks(queue_dir.name)
        start_phase = 1
        cp = {}
        # Save pipeline config for new runs
        pipeline_config = config or {}
        (queue_dir / "config.json").write_text(json.dumps(pipeline_config, indent=2), encoding="utf-8")
        # Inline brief → persist as the new run's brief.md, then route the
        # pipeline through brief_file so Phase 1 lands on the `_brief_from_file`
        # branch (no ChatGPT brief generation, no share-link extraction).
        if brief_text and not brief_file:
            _inline_brief_path = queue_dir / "documents" / "brief.md"
            _inline_md = brief_text if brief_text.lstrip().startswith("# Research Brief") \
                         else f"# Research Brief\n\n{brief_text}"
            _inline_brief_path.write_text(_inline_md, encoding="utf-8")
            brief_file = str(_inline_brief_path)
            log(f"Inline brief persisted ({len(brief_text)} chars) → {_inline_brief_path.name}")

        # Flow B: P1 + all P2 skipped → user attached source files (uploaded
        # to Storage by the FE). Download each into queue_dir/documents/
        # preserving the original extension so NotebookLM ingests them
        # natively (NLM accepts md/txt/pdf/docx). The existing P3 file scan
        # at gate-decision time + run_phase3_upload pick them up like any
        # other agent-generated artifact. Failures are logged but the
        # pipeline continues with whatever sources DID download.
        if user_sources:
            try:
                # The synth device user has read access to
                # `users/{owner}/.../sources/...` when the device is
                # authorized for that owner (storage.rules helper
                # `deviceAuthorizedFor`). Stream each attached source
                # into queue_dir/documents/ before P3 hands them to
                # NotebookLM.
                _bucket_label = _resolve_storage_bucket() or "(unresolved)"
                _ok, _fail = 0, 0
                _dl_names = []  # user-source filenames → P2 delivery allowlist
                for _src in user_sources:
                    _name = (_src.get("name") or "source").strip() or "source"
                    _path = (_src.get("storagePath") or "").strip()
                    if not _path:
                        _fail += 1
                        continue
                    # Sanitize: keep alnum + . _ - and cap length so a
                    # malicious name can't escape queue_dir.
                    _safe = re.sub(r"[^A-Za-z0-9._-]", "-", _name)[:80] or "source"
                    # Avoid clobbering brief.md or another source with the
                    # same sanitized name — append a numeric suffix.
                    _dest = queue_dir / "documents" / _safe
                    if _dest.stem == "brief":
                        _dest = queue_dir / "documents" / f"src-{_safe}"
                    _i = 2
                    while _dest.exists():
                        _stem = _dest.stem
                        _ext = _dest.suffix
                        _dest = queue_dir / "documents" / f"{_stem}-{_i}{_ext}"
                        _i += 1
                    try:
                        if not _download_user_source_via_storage_rest(_path, _dest):
                            raise RuntimeError("Storage REST download failed")
                        log(f"Flow B source: gs://{_bucket_label}/{_path} → {_dest.name} ({_dest.stat().st_size} bytes)")
                        _dl_names.append(_dest.name)
                        _ok += 1
                    except Exception as _e:
                        log(f"Flow B source download FAILED ({_path}): {_e}", "WARN")
                        _fail += 1
                log(f"Flow B sources: {_ok} downloaded, {_fail} failed")
                # Record the allowlist so P2 delivery (and hard-retry) never
                # pick up agent-written artifacts in documents/. attach_to_p2
                # stays False until the orchestrator confirms P1 didn't run.
                if _dl_names:
                    _write_user_sources_manifest(_dl_names)
                # If every download failed, the run is doomed — P3 will trip
                # the gate and surface a generic "no documents" alert. Better
                # to fail fast with the actual reason so the user can retry
                # the upload or fix Storage permissions.
                if _ok == 0 and _fail > 0:
                    log(f"Flow B: ALL {_fail} source downloads failed — aborting", "ERROR")
                    # 2026-05-21: emit at whatever phase the pipeline is
                    # currently at (preflight always runs early so this is
                    # P0 in practice, but we read _runtime.phase dynamically
                    # so the alert always lands on the user's visible tile,
                    # not on the original Flow-B-target P3 NLM dropdown
                    # that the user can't see while the chat is at P0).
                    # Pre-fix: phase=3 hard-coded → alert vanished into the
                    # P3 dropdown the user never opens, manifesting as
                    # "stuck at init with no actionable button anywhere".
                    # Skip action still routes to skip_phase(3) so user can
                    # elect to run without NLM ingestion, but Retry restarts
                    # the current phase since most 403s are token/auth races.
                    _alert_phase = getattr(_runtime, "phase", 0) or 0
                    fail_phase(
                        phase=_alert_phase,
                        error=f"Couldn't download {_fail} attached source(s) from Storage",
                        reason="The pipeline couldn't fetch the file(s) you attached. Most often this is a Storage rules / auth-token race — Retry first. If it keeps failing, Skip drops the attachments and continues with no NotebookLM ingestion.",
                        actions=[
                            {"id": "retry", "label": "Retry", "style": "primary",
                             "command": {"action": "retry_phase", "phase": _alert_phase}},
                            {"id": "skip", "label": "Skip attachments", "style": "default",
                             "command": {"action": "skip_phase", "phase": 3}},
                        ],
                    )
                    return
            except Exception as _outer:
                log(f"Flow B handler failed (non-fatal): {_outer}", "WARN")

        # Bridge user_sources → P1/P2 attachments. After the Flow B block
        # downloaded everything into documents/, walk that dir and:
        #   - append any *.pdf / *.docx / *.md to pdf_paths so run_phase1
        #     attaches them to the ChatGPT brief request as context;
        #   - the same files remain on disk so the P2 round-robin pass can
        #     pick them up via _runtime.original_inputs (consumed by
        #     start_agent_no_gemini_wait's brief_path + auxiliary attach).
        # Only run when the user actually attached sources; otherwise leave
        # pdf_paths as the CLI-supplied default.
        if user_sources:
            _docs_dir = queue_dir / "documents"
            if _docs_dir.exists():
                _aux_paths = list(pdf_paths or [])
                for _f in sorted(_docs_dir.iterdir()):
                    if not _f.is_file():
                        continue
                    if _f.stem in ("brief", "consolidated"):
                        continue
                    if _f.suffix.lower() not in (".pdf", ".md", ".docx", ".txt"):
                        continue
                    _full = str(_f)
                    if _full not in _aux_paths:
                        _aux_paths.append(_full)
                if _aux_paths != list(pdf_paths or []):
                    log(f"User sources -> P1 attach list: {[Path(p).name for p in _aux_paths]}")
                pdf_paths = _aux_paths

    log(f"Queue: {queue_dir}")
    # init_tracks just sets the global `_tracks_dir` to a Path holding
    # the run name (same name as the queue dir). The local var is unused;
    # the side effect is what matters.
    init_tracks(queue_dir.name)

    # ── Pipeline config: reload from config.json before each phase (supports mid-pipeline changes) ──
    def reload_config():
        nonlocal pipeline_config
        config_path = queue_dir / "config.json"
        if config_path.exists():
            try:
                pipeline_config = json.loads(config_path.read_text(encoding="utf-8"))
            except Exception:
                pass
        # Merge any in-memory config updates from Firestore commands
        # (in case Firestore config arrived but HTTP PATCH didn't)
        ctrl_updates = _controls.pop_config_updates()
        if ctrl_updates:
            pipeline_config.update(ctrl_updates)
            # Persist merged config back to disk for next reload
            try:
                config_path.write_text(json.dumps(pipeline_config, indent=2), encoding="utf-8")
            except Exception:
                pass
        # 2026-05-13: Firestore overlay — read pipelineConfig from research doc
        # and merge restrictively (skip wins, agents-off wins, video/email-off
        # wins, podcastLength latest wins). Catches queued-state toggles that
        # don't propagate via writeCommand (30s stale-command gate at line
        # ~3348 discards old writes; the BE command listener also isn't
        # attached until the run picks up its slot, so writes from the
        # queued window land in Firestore but never reach _config_updates).
        # The research doc's pipelineConfig is the FE's authoritative snapshot,
        # updated synchronously on every toggle regardless of run status.
        try:
            if _firebase_db and _fb_uid and _fb_research_id:
                _rd_snap = _firebase_db.collection("users").document(_fb_uid) \
                    .collection("researches").document(_fb_research_id).get()
                if _rd_snap.exists:
                    _pc = (_rd_snap.to_dict() or {}).get("pipelineConfig") or {}
                    # skippedPhases (FE field name) or skipPhases (BE) — accept either
                    _fs_skip_raw = _pc.get("skippedPhases") if "skippedPhases" in _pc else _pc.get("skipPhases")
                    if isinstance(_fs_skip_raw, list):
                        _curr_skip = set(pipeline_config.get("skipPhases") or [])
                        _fs_skip = {int(x) for x in _fs_skip_raw if isinstance(x, (int, float))}
                        _added = _fs_skip - _curr_skip
                        if _added:
                            log(f"[config-overlay] FS adds skip phases {sorted(_added)} (disk had {sorted(_curr_skip)})", "WARN")
                            pipeline_config["skipPhases"] = sorted(_curr_skip | _fs_skip)
                    # agents — skip wins (FS off overrides disk on, never the reverse)
                    _fs_agents = _pc.get("agents") or {}
                    if _fs_agents:
                        _curr_agents = dict(pipeline_config.get("agents") or {})
                        for _k in ("chatgpt", "gemini", "claude"):
                            if _k in _fs_agents and not bool(_fs_agents[_k]) and _curr_agents.get(_k, True):
                                log(f"[config-overlay] FS agents.{_k}=false overrides disk", "WARN")
                                _curr_agents[_k] = False
                        pipeline_config["agents"] = _curr_agents
                    # videoEnabled / emailEnabled — false wins
                    if "videoEnabled" in _pc and not bool(_pc["videoEnabled"]) and pipeline_config.get("videoEnabled", True):
                        log("[config-overlay] FS videoEnabled=false overrides", "WARN")
                        pipeline_config["videoEnabled"] = False
                    if "emailEnabled" in _pc and not bool(_pc["emailEnabled"]) and pipeline_config.get("emailEnabled", True):
                        log("[config-overlay] FS emailEnabled=false overrides", "WARN")
                        pipeline_config["emailEnabled"] = False
                    # podcastLength — latest wins (any valid value)
                    _fs_pl = _pc.get("podcastLength")
                    if isinstance(_fs_pl, str) and _fs_pl in ("short", "default", "long"):
                        if _fs_pl != pipeline_config.get("podcastLength"):
                            log(f"[config-overlay] FS podcastLength={_fs_pl} overrides disk={pipeline_config.get('podcastLength')}", "WARN")
                            pipeline_config["podcastLength"] = _fs_pl
        except Exception as _overlay_err:
            _o_err = str(_overlay_err)
            if (
                "403" in _o_err
                or "PERMISSION_DENIED" in _o_err
                or "Missing or insufficient permissions" in _o_err
            ):
                # Track D: synth user denied on user-tree research-doc
                # read. The disk-side pipelineConfig already merged
                # ctrl_updates; FE-side queued-state toggles still need
                # this overlay (see cleanup #552 for structural rule
                # fix that lets synth user read research docs scoped
                # to its deviceId).
                log("[config-overlay] re-read denied (synth user) — using disk pipelineConfig", "DEBUG")
            else:
                log(f"[config-overlay] Firestore re-read failed (non-fatal): {_overlay_err}", "WARN")
        sp = set(pipeline_config.get("skipPhases", []))
        ac = pipeline_config.get("agents", {"chatgpt": True, "gemini": True, "claude": True})
        ve = pipeline_config.get("videoEnabled", True)
        ee = pipeline_config.get("emailEnabled", True)
        # 2026-05-13 (feature): NotebookLM audio-overview length —
        # "short" / "default" / "long". Default to "long" so pre-feature
        # runs preserve the historical hardcoded behavior. The Phase 3
        # audio-generation CUA prompt parameterizes its Length instruction
        # on this value below.
        pl_raw = pipeline_config.get("podcastLength", "long")
        pl = pl_raw if pl_raw in ("short", "default", "long") else "long"
        if 3 in sp:
            sp.add(4)
        # Brief-on requires ≥1 P2 agent — otherwise the brief feeds nothing
        # and Phase 3 has no documents. The FE has 3 separate guards (chat
        # panel, settings page, tile diagram) but a stale config.json or a
        # mid-pipeline command-config update can still land an invalid
        # combo here. Auto-enable ChatGPT silently rather than fail —
        # preserves the brief's investment, matches the FE auto-enable on
        # the skip-brief Settings toggle, and makes downstream phases work.
        # 2026-05-13: also require `2 not in sp` — when the user explicitly
        # toggles all P2 agents off, the FE cascades by adding 2 to
        # skippedPhases (ChatInput.tsx:312). Honoring that explicit intent
        # means we must NOT silently re-enable ChatGPT just because ac is
        # all-False; the user wants P2 skipped wholesale. Without this gate
        # the new Firestore overlay would correctly disable all 3 agents,
        # then this branch would clobber the user's explicit toggle.
        if 1 not in sp and 2 not in sp and not any(ac.values()):
            log("Config: brief on with 0 agents (not explicit skip) — auto-enabling ChatGPT", "WARN")
            ac["chatgpt"] = True
        # 2026-05-20 (queued-run init-skip parity): also honor
        # skipInitVerify from disk config. Pre-fix this was only set via
        # the per-run skip_init_verify action command at runtime — which
        # the queued run can't fire because the per-research command
        # listener isn't attached until after Phase 0 starts. Result:
        # the Settings → Pipeline "Skip verification" toggle worked for
        # immediate runs (whose Phase 0 was already running when the
        # listener attached and the command landed) but was silently
        # ignored for queued runs. Now reload_config returns the
        # disk-config value, and the Phase 0 entry block primes
        # _controls.skip_init_verify from it before the verify loop
        # starts.
        siv = bool(pipeline_config.get("skipInitVerify", False))
        return sp, ac, ve, ee, pl, siv

    skip_phases, agents_cfg, video_enabled, email_enabled, podcast_length, skip_init_verify_cfg = reload_config()
    # Prime the per-run controls. The FE Settings toggle and per-run
    # command both write to _controls.skip_init_verify; honoring the
    # disk config at Phase 0 entry ensures queued runs respect the
    # global Settings preference without depending on the per-research
    # command listener attaching first.
    if skip_init_verify_cfg:
        try:
            _controls.skip_init_verify = True
            log("[config] skipInitVerify=true from disk config — Phase 0 will skip login verification", "INFO")
        except Exception:
            pass

    # ── Preload data from previous phases (for resume) ──
    brief_text, brief_url = "", cp.get("brief_url", "")
    links, notebook_url, youtube_url = {}, cp.get("notebook_url", ""), cp.get("youtube_url", "")
    # CRITICAL: audio_overview_url must be initialized at module scope so
    # P5 (line ~15272 _effective_audio_url) doesn't NameError when resuming
    # past P3 (start_phase >= 4). The P3 sub-step normally assigns this
    # inside its `elif start_phase <= 3` branch; on resume, we restore it
    # from checkpoint. P4 path also sets `audio_overview_url = ""` so the
    # variable is always defined regardless of which branch P3 takes.
    audio_overview_url = cp.get("audio_overview_url", "")

    # ── Helper: update delivery.json incrementally (frontend reads this for live links) ──
    def update_delivery(**new_fields):
        d_path = queue_dir / "delivery.json"
        d = json.loads(d_path.read_text(encoding="utf-8")) if d_path.exists() else {
            "topic": topic, "status": "ongoing", "brief_url": "", "research_links": {},
            "notebook_url": "", "audio_url": "", "youtube_url": "", "doc_url": "", "email_sent": False,
        }
        d.update(new_fields)
        d_path.write_text(json.dumps(d, indent=2), encoding="utf-8")

    # Stop/pause are driven through `_controls` (asyncio events) now. The
    # .stop and .pause sentinel files are still written by the HTTP endpoints
    # for backward-compat with the resume flow + pipeline_state reporting —
    # no in-pipeline helper needed here.

    # ── Helper: read user feedback for a phase ──
    def get_feedback(phase_num):
        fb_path = queue_dir / "feedback.json"
        if fb_path.exists():
            try:
                fb = json.loads(fb_path.read_text(encoding="utf-8"))
                return fb.get(str(phase_num), "")
            except Exception:
                pass
        return ""

    def clear_feedback(phase_num):
        fb_path = queue_dir / "feedback.json"
        if fb_path.exists():
            try:
                fb = json.loads(fb_path.read_text(encoding="utf-8"))
                fb.pop(str(phase_num), None)
                fb_path.write_text(json.dumps(fb, indent=2), encoding="utf-8")
            except Exception:
                pass

    class _PhaseSoftDecision(Exception):
        """Raised by the soft-warn path of _await_phase_with_active_deadline
        when the user picks Retry or Skip. .decision is "retry" or "skip".
        Wait + Stop are handled inline (Wait = no signal, polling continues;
        Stop = CancelledError). 2026-05-04: introduced to support the user's
        'BE can't bail on long researches' contract — long Claude DR runs
        (1-2h) emit a soft warn at the phase deadline instead of hard-
        cancelling, and the user picks the next move."""
        def __init__(self, decision: str):
            super().__init__(f"phase soft decision: {decision}")
            self.decision = decision

    def _emit_phase_soft_warn(phase: int, max_min: int, alert_id: str):
        """Emit the phase-level soft-timeout pipeline_warning. Used only by
        _await_phase_with_active_deadline's soft path. Actions:
          - Wait: pure FE dismiss, no Firestore command needed because BE
            was never paused. Polling continues uninterrupted.
          - Retry from checkpoint: writes retry_phase command → helper
            consumes consume_retry_phase, cancels run_task, raises
            _PhaseSoftDecision("retry") so the caller can restart.
          - Skip phase: writes skip_phase command → helper consumes
            consume_phase_skip, cancels run_task, raises
            _PhaseSoftDecision("skip") so the caller can advance.
        """
        actions = [
            {"id": "wait", "label": "Wait — keep going", "style": "primary",
             "command": {"action": "dismiss_alert"}},
            {"id": "retry", "label": "Retry from checkpoint", "style": "default",
             "command": {"action": "retry_phase", "phase": phase}},
            {"id": "skip", "label": "Skip phase", "style": "default",
             "command": {"action": "skip_phase", "phase": phase}},
        ]
        # Phase-aware example so the banner's reassurance fits what's
        # actually running. P2 = Claude/ChatGPT/Gemini deep research,
        # P3 = NotebookLM podcast gen. Generic fallback covers any
        # future phase that opts into soft-warn.
        if phase == 1:
            _example = "ChatGPT brief generation can legitimately take 30+ minutes for large PDFs or complex topics"
        elif phase == 2:
            _example = "deep-research runs can legitimately take 1-2 hours"
        elif phase == 3:
            _example = "NotebookLM podcast generation can legitimately take 30-60 minutes on long sources"
        else:
            _example = "long-running phases can legitimately exceed this estimate"
        try:
            emit_event(
                "pipeline_warning", phase=phase,
                message=f"Phase {phase} has been running for {max_min} min — agent may still be working",
                details=(
                    f"The pipeline is still polling normally. Wait keeps watching ({_example}). "
                    "Retry restarts from the last checkpoint with a fresh budget. Skip "
                    "moves past this phase. You can also Stop the pipeline from "
                    "the chat input bar."
                ),
                actions=actions,
                alertType="warn",
                dismissible=True,
                alert_id=alert_id,
            )
        except Exception as _e:
            log(f"_emit_phase_soft_warn fallback ({_e})", "WARN")

    async def _phase_timeout_decision(phase: int, max_min: int, agent: str | None = None) -> str:
        """Recoverable response to a per-phase active-time ceiling. Per the
        never-die contract, BE-detected stuck phases do NOT terminate the
        run — they emit pipeline_error with [Retry, Skip] actions and pause
        for the user's call. User decides:
          - retry → restore from checkpoint, rerun the phase (fresh deadline)
          - skip  → mark phase done, advance to next
          - stop  → only fires if user explicitly hit Stop (chat input button)
                    while the alert was up; await_phase_decision picks that up
                    via _controls.is_stop()
        Returns the user's decision string. Does NOT write delivery.json
        status="stopped" — that's reserved for terminal stop paths only.

        2026-05-04: this is the HARD path. Soft-warn coverage:
          - P1 (brief gen, 60m): soft-warn at the deadline so 30+min
            briefs on large PDFs / complex topics aren't bailed on.
          - P2 (deep research, 120m): soft-warn at the deadline so
            1-2h DR runs aren't bailed on.
          - P3 audio sub-step (NLM podcast gen, 90m): soft-warn at
            the deadline so long-podcast generation isn't killed.
        P3 upload (15m) and P4 (15m) keep this hard-cancel + Retry/
        Skip pause-for-decision flow — they're bounded utility ops
        (NLM upload click flow, ffmpeg + YouTube upload)."""
        log(f"Phase {phase}: active-time ceiling {max_min}min hit — surfacing to user as recoverable error", "WARN")
        actions = [
            {"id": "retry", "label": "Retry from checkpoint", "style": "primary",
             "command": {"action": "retry_phase", "phase": phase}},
            {"id": "skip", "label": "Skip phase", "style": "default",
             "command": {"action": "skip_phase", "phase": phase}},
        ]
        try:
            fail_phase(
                phase=phase,
                error=f"Phase {phase} exceeded {max_min}-minute active-time ceiling",
                reason=(
                    f"This phase has been running for {max_min} minutes of active work "
                    "without completing — likely stuck on a CUA loop, frozen Playwright "
                    "operation, or a platform UI hiccup. Retry restores from the last "
                    "checkpoint and reruns this phase with a fresh budget. Skip moves "
                    "past this phase and continues with whatever artifacts are on disk. "
                    "You can also Stop the pipeline from the chat input bar."
                ),
                agent=agent,
                actions=actions,
            )
        except Exception as _e:
            log(f"_phase_timeout_decision: fail_phase fallback ({_e})", "WARN")
            fail_phase(phase, f"Phase {phase} exceeded {max_min}-minute active-time ceiling",
                       "Stuck — Retry from checkpoint or Skip the phase.",
                       agent=agent, actions=actions)
        # Pause flag freezes the active-time clock during the user's
        # decision wait, so a 20-min decision delay doesn't burn budget
        # against the next retry. Also flips the FE chat input to paused.
        _controls.request_pause()
        emit_event("pipeline_paused", phase=phase, reason="phase_timeout")
        decision = await _controls.await_phase_decision(phase)
        emit_event("pipeline_resumed", phase=phase, reason=f"phase_timeout_{decision}")
        return decision

    async def _await_phase_with_active_deadline(phase: int, max_min: int, coro_factory,
                                                  soft_warn_only: bool = False):
        """Run a phase coroutine factory with an ACTIVE-TIME wall-clock
        deadline. Time spent while `_controls.is_pause()` is True does NOT
        count toward the budget — so a user pausing for an hour doesn't
        kill a healthy phase.

        soft_warn_only=False (default — P3-upload + P4 hard-cap behavior):
          Cancels the coroutine when active-time exhausts and raises
          asyncio.TimeoutError. Caller runs `_phase_timeout_decision` to
          give the user Retry/Skip, and on Retry calls this helper AGAIN
          (factory creates a fresh coro). Existing behavior — unchanged.

        soft_warn_only=True (P1 + P2 + P3-audio — long-running advisory, 2026-05-04):
          Emits a pipeline_warning [Wait/Retry/Skip] (amber) at the
          deadline, DOES NOT cancel the coroutine, and continues polling
          for the user's decision while the run_task keeps doing work.
          Wait is implicit — no command needed; the polling never
          stopped, the alert FE-clears when user dismisses. Retry →
          cancel + raise _PhaseSoftDecision("retry"). Skip → cancel +
          raise _PhaseSoftDecision("skip"). User-Stop (chat input) →
          cancel + raise CancelledError. Run_task completing naturally
          returns its result. The user's contract: 'BE can't bail on
          long researches and fail.' One warn per helper invocation —
          if user clicks Wait and the run continues past another budget
          window, no re-warn (prevents spam).

        coro_factory is `Callable[[], Coroutine]` — must produce a fresh
        coroutine on each call so retry doesn't await an already-awaited
        coroutine. Tick is 5s — fine-grained enough for any budget."""
        run_task = asyncio.ensure_future(coro_factory())
        active_sec = 0.0
        deadline_sec = float(max_min * 60)
        tick = 5.0
        soft_warn_emitted = False
        # 2026-05-06 (Stream 2 D4): per-invocation nonce so the FE dedup
        # ledger (5-min/1-resurface) doesn't permanently silence the
        # 2nd / 3rd soft-warn emission when callers re-invoke this helper
        # (e.g., P3-audio retry-after-no-audio loop calls it up to 3
        # times per pipeline run). Each helper call gets a fresh
        # alert_id; FE treats them as distinct alerts, not duplicates.
        soft_alert_id = f"phase{phase}_soft_timeout_{int(time.monotonic() * 1000)}"
        while not run_task.done():
            try:
                await asyncio.sleep(tick)
            except asyncio.CancelledError:
                run_task.cancel()
                raise
            # User-Stop short-circuit: the deadline loop used to ignore the
            # Stop button and only react when the phase coroutine itself
            # noticed the stop flag — which could be deep inside a long
            # CUA call. Now we cancel-and-propagate immediately, so user
            # Stop during a stuck phase exits within one tick (5s) instead
            # of waiting up to `max_min` for the deadline.
            if _controls.is_stop():
                run_task.cancel()
                try: await run_task
                except BaseException: pass
                raise asyncio.CancelledError(f"phase {phase} stopped by user")
            # Soft-mode user-decision polling — only AFTER the warn is
            # emitted. Until then there's nothing for the user to decide.
            # Wait is implicit (no signal); Retry/Skip drive the existing
            # consume_retry_phase / consume_phase_skip controls.
            if soft_warn_only and soft_warn_emitted:
                if _controls.consume_retry_phase(phase):
                    log(f"Phase {phase}: user chose Retry on soft-warn — cancelling run_task", "INFO")
                    run_task.cancel()
                    try: await run_task
                    except BaseException: pass
                    raise _PhaseSoftDecision("retry")
                if _controls.consume_phase_skip(phase):
                    log(f"Phase {phase}: user chose Skip on soft-warn — cancelling run_task", "INFO")
                    run_task.cancel()
                    try: await run_task
                    except BaseException: pass
                    raise _PhaseSoftDecision("skip")
            if not _controls.is_pause():
                active_sec += tick
            if active_sec >= deadline_sec and not run_task.done():
                if soft_warn_only and not soft_warn_emitted:
                    # Soft path: emit pipeline_warning ONCE, keep polling.
                    # Run_task continues uninterrupted; user's Wait/Retry/
                    # Skip is consumed in subsequent ticks above. Per the
                    # 'BE can't bail on long researches' contract, Wait
                    # is implicit — no command, no stop, polling intact.
                    log(f"Phase {phase}: active-time {active_sec:.0f}s past "
                        f"{deadline_sec:.0f}s — soft warn emitted, polling continues", "WARN")
                    _emit_phase_soft_warn(phase, max_min, soft_alert_id)
                    soft_warn_emitted = True
                    continue
                if soft_warn_only and soft_warn_emitted:
                    # Already warned, user undecided. Keep polling — the
                    # run_task may finish naturally; if it does, we exit
                    # the while loop and return its result below.
                    continue
                # Hard-cap path (P1/P3/P4 default behavior — unchanged).
                log(f"Phase {phase}: active-time {active_sec:.0f}s exceeded {deadline_sec:.0f}s — cancelling for user decision", "WARN")
                run_task.cancel()
                # CancelledError inherits from BaseException (not Exception)
                # since Python 3.8, so `except Exception: pass` did NOT catch
                # the post-cancel re-raise — and the `raise TimeoutError`
                # below was never reached. Catching BaseException converts
                # the cancel into the TimeoutError the retry loop expects.
                try: await run_task
                except BaseException as _drained:
                    # DEBUG-log the drained class so any future regression
                    # where something unexpected leaks (custom exception,
                    # SystemExit, etc.) doesn't go silent.
                    log(f"Phase {phase}: drained {type(_drained).__name__} post-cancel", "DEBUG")
                raise asyncio.TimeoutError(
                    f"phase {phase} exceeded {max_min}-min active-time budget"
                )
        return await run_task

    # Create delivery.json immediately (frontend can see the run from the start)
    if not (queue_dir / "delivery.json").exists():
        update_delivery()

    browser = Browser(_profile_dir(WORKER_ID), headless=False)
    # Expose the live Browser instance to the stop / discard / hard-reset
    # paths so they can schedule a graceful close without waiting for
    # the pipeline to reach its next is_stop() phase boundary. Pause+resume
    # paths below re-create the Browser and re-assign this ref.
    global _active_browser_ref
    _active_browser_ref = browser
    try:
        # ══════════════════════ PHASE 0: Preflight ══════════════════════
        # Phase 0 does real work now: launch browser, verify each platform's
        # login session, check env dependencies (Gemini key, ffmpeg). If any
        # platform is not logged in, emit `login_required` and pause the
        # pipeline — frontend shows a sticky banner with Retry.
        emit_event("phase_start", phase=0, description="Verifying environment + logins")
        _update_firestore_research({"phase": 0, "currentPhase": 0, "status": "ongoing"})
        _p0_start = time.time()

        emit_event("agent_progress", phase=0, agent="system", status="Launching",
                   progress="Starting Chromium browser with automation profile…")
        # ARCHITECTURE 2026-04-18 (never-die): browser-launch failures are
        # user-recoverable (close other Chrome, run `playwright install`,
        # etc.). Retry re-invokes browser.start() in-place; Stop ends the
        # run. Skip isn't offered — every downstream phase needs a working
        # browser, so skipping Phase 0 is meaningless.
        while True:
            try:
                await browser.start()
                # F4 / DGOPS-7451 — scrub any persisted Google auth state +
                # internal-infra cookies/storage BEFORE Phase 0 runs. Closes
                # the silent session-inheritance vector that let Gemini ride
                # a persisted @distributedglobal.com Workspace session into
                # dg-security-monitor.web.app on 2026-05-05.
                try:
                    await _scrub_persisted_google_auth(
                        browser.context, scope="run_start",
                        reason="DGOPS-7451 F4 — pre-pipeline auth scrub")
                except Exception as _scrub_err:
                    log(f"[security] run-start scrub failed (non-fatal): {_scrub_err}", "WARN")
                break
            except Exception as _launch_err:
                # Most common launch failures:
                #   • Profile locked by another running Chrome instance →
                #     SingletonLock couldn't be removed (another Playwright run)
                #   • Playwright not installed → `playwright install chromium` missing
                #   • Chromium binary missing / corrupt
                _err_msg = str(_launch_err)
                _low = _err_msg.lower()
                if "profile" in _low and ("lock" in _low or "in use" in _low or "singleton" in _low):
                    _friendly = f"Chrome profile is locked by another session. Close any running automation browsers (or previous pipeline runs), then click Retry."
                elif "executable" in _low or "chromium" in _low or "browser" in _low:
                    _friendly = f"Browser binary missing or failed to start. Run `playwright install chromium`, then click Retry."
                else:
                    _friendly = f"Browser launch failed: {_err_msg[:200]}"
                log(f"Phase 0 browser launch failed: {_err_msg[:200]} — awaiting user decision", "ERROR")
                fail_phase(
                    phase=0,
                    error=f"Browser launch failed: {_err_msg[:200]}",
                    reason=_friendly,
                    agent="system",
                    actions=[
                        {"id": "retry", "label": "Retry", "style": "primary",
                         "command": {"action": "retry_phase", "phase": 0}},
                    ],
                )
                decision = await _controls.await_phase_decision(0)
                if decision == "retry":
                    log("Phase 0 browser launch: user requested retry", "INFO")
                    emit_event("phase_restart", phase=0, reason="user_retry_browser_launch", attempt=0)
                    continue
                # skip (not offered but handled defensively) / stop / timeout
                log(f"Phase 0 browser launch: user {decision} — terminating pipeline", "INFO")
                emit_event("pipeline_stopped", phase=0, reason=f"user_{decision}_browser_launch")
                return

        # Build list of platforms to verify based on enabled agents + phases
        _agents_cfg = config.get("agents", {}) if isinstance(config, dict) else {}
        _need_chatgpt = _agents_cfg.get("chatgpt", True)
        _need_gemini = _agents_cfg.get("gemini", True)
        _need_claude = _agents_cfg.get("claude", True)
        _need_notebooklm = 3 not in skip_phases
        # P4 (YouTube) dropped 2026-05-10 — FE-owned via Data API, no BE
        # browser involvement. P5 (Doc + email) dropped 2026-04-30 — FE-owned
        # via Docs API + Resend. Neither needs login verification in the BE
        # preflight; both use the OAuth refresh token in App Hosting Secrets.

        preflight_platforms = []
        if _need_chatgpt:    preflight_platforms.append(("ChatGPT", "chatgpt"))
        if _need_gemini:     preflight_platforms.append(("Gemini", "gemini"))
        if _need_claude:     preflight_platforms.append(("Claude", "claude"))
        if _need_notebooklm: preflight_platforms.append(("NotebookLM", "notebooklm"))

        # Honor the user's preference (global Settings → Pipeline → Skip
        # login verification, plus any per-run override in pipeline_config).
        # When on, we skip the per-platform CUA round entirely: browser is
        # already running, Phase 1 will navigate itself to ChatGPT.
        _skip_verify_pref = bool(pipeline_config.get("skipInitVerify", False)) if isinstance(pipeline_config, dict) else False
        if _skip_verify_pref:
            log("Phase 0: skipInitVerify=true — bypassing login verification per user pref", "INFO")
            emit_event("agent_progress", phase=0, agent="system", status="Skipped",
                       progress="Login verification skipped (per your pipeline settings)")
            preflight_platforms = []  # Nothing to verify below — while loop skipped

        # SEQUENTIAL-2026-04-19: walk platforms one at a time. Old flow
        # opened all 7 tabs in a loop before surfacing a single bulk
        # login_required — that's (a) a Cloudflare-visible robotic burst
        # and (b) overwhelming for the user, who now has to juggle 7
        # partial login flows simultaneously. New flow: cookie-check
        # first, tab-open only on miss, CUA-verify, and if STILL not
        # logged in, emit `login_required` scoped to THAT platform and
        # wait for user retry before touching the next one. This mirrors
        # how the --pair script already walks setup Step 2.
        label_by_key = {key: label for label, key in preflight_platforms}
        _preflight_tabs: dict[str, object] = {}
        _pf_opened = 0  # Counts real tab-opens across the whole sequence for stagger pacing
        _global_skip = False
        for idx, (label, key) in enumerate(preflight_platforms):
            if _global_skip or _controls.skip_init_verify:
                _global_skip = True
                log(f"Phase 0: SKIP_INIT_VERIFY — skipping remaining platform {label}", "INFO")
                continue
            attempt = 0
            while True:
                attempt += 1
                if _controls.skip_init_verify:
                    _global_skip = True
                    break
                # NOTE (2026-04-24 #2): cookie + Playwright pre-checks both
                # removed. Cookies lie when the session is server-side
                # invalidated but the cookie hasn't expired yet; Playwright
                # strict DOM selectors match cached sidebar fragments on
                # ChatGPT's logged-out landing (and probably other
                # platforms' skeleton UIs too). Both gave us speed but let
                # false positives through, which was tolerable only until
                # we removed the per-phase login probe safety net — now
                # Phase 0 is the only gate, and it must not lie.
                #
                # Flow below: tab open → 4s settle → URL check → CUA.
                # Vision is the single source of truth. Slower (~5-10s per
                # platform × up to 4 = ~40s worst case on cold starts)
                # but it actually looks at what's on screen. Not a
                # performance win we can afford to keep taking.
                # STEALTH-2026-04-19: jitter between cold-start tab opens.
                # Back-to-back opens in <2s are a strong robotic signal.
                if _pf_opened > 0 and key not in _preflight_tabs:
                    await asyncio.sleep(random.uniform(2.5, 4.5))
                log(f"Phase 0: checking {label} (attempt {attempt})", "INFO")
                emit_event("agent_progress", phase=0, agent=key, status="checking",
                           progress=f"Verifying {label} login…")
                try:
                    info = LOGIN_PLATFORMS.get(key)
                    root = info["root"] if info else "about:blank"
                    tab = _preflight_tabs.get(key)
                    if tab is None:
                        tab = await browser.new_tab(root)
                        _pf_opened += 1
                        _preflight_tabs[key] = tab
                    else:
                        # Retry path — re-navigate so we pick up new login state.
                        try:
                            await tab.goto(root, wait_until="domcontentloaded", timeout=15000)
                        except Exception:
                            pass
                    # Settle for SPA hydration — Claude.ai / Google Docs paint a
                    # neutral "loading" shell for 3-4s that CUA misreads as a
                    # login wall if we peek too early.
                    await asyncio.sleep(4.0)
                    # Cheap negative signal first: URL on a known login host →
                    # definitely logged out. Skip the CUA call to save budget.
                    try:
                        current_url = (tab.url or "").lower()
                    except Exception:
                        current_url = ""
                    if any(h in current_url for h in _LOGIN_HOST_NEGATIVES):
                        log(f"Phase 0: {label} on login URL ({current_url[:60]}) — not logged in", "INFO")
                        ok = False
                    else:
                        # Vision verification is the gate. URL already
                        # cleared the cheap "obvious login wall" case;
                        # everything else is a CUA decision.
                        ok = await verify_login_cua(tab, key, cua_client)
                except CuaUnavailableError as cua_err:
                    # Structural Anthropic failure (billing cap / invalid
                    # key / 529). Surface a distinct alert so the user
                    # doesn't chase a phantom auth issue.
                    # 2026-05-05 (DGOPS-7357 follow-up): Skip removed.
                    # Without CUA the pipeline can't tell login walls
                    # from authenticated sessions, so skipping verification
                    # is a footgun — it lets a logged-out platform flow
                    # into Phase 1/2/3 where it crashes harder and later.
                    # Only Retry. The global Settings → Skip login
                    # verification toggle still bypasses the loop entirely
                    # at the top of the platform-walk (line ~18677); that
                    # path is the right escape hatch for "I know what I'm
                    # doing, run without CUA on purpose".
                    log(f"Phase 0: CUA unavailable for {label}: {cua_err}", "ERROR")
                    fail_phase(
                        0, "CUA vision check can't run",
                        (f"{str(cua_err)[:180]}\n\n"
                         "This usually means one of these:\n"
                         "• Rate-limited (429) — the key hit its request / quota "
                         "limit. Load or switch to another key in Account → API "
                         "Config, then Retry.\n"
                         "• Invalid or missing Anthropic key — add or rotate it in "
                         "Account → API Config (preferred, no restart), or set "
                         "ANTHROPIC_API_KEY on the backend machine and restart.\n"
                         "• Workspace usage cap or 400 overage — raise the cap in "
                         "console.anthropic.com → Workspaces, wait for the "
                         "monthly reset, OR paste a key from a different "
                         "workspace (or a personal key) in Account → API Config "
                         "to bypass the capped one.\n"
                         "• Anthropic temporarily overloaded (529) — wait a moment "
                         "and click Retry.\n\n"
                         "Without CUA verification, the pipeline can't reliably "
                         "tell login walls from authenticated sessions, so we "
                         "don't allow continuing without it. Click Retry once "
                         "you've fixed the underlying issue."),
                        agent=key,
                        actions=[
                            {"id": "retry", "label": "Retry", "style": "primary",
                             "command": {"action": "retry_phase", "phase": 0}},
                        ],
                    )
                    _controls.request_pause("cua_unavailable")
                    emit_event("pipeline_paused", phase=0, reason="cua_unavailable")
                    await _controls.wait_if_paused()
                    if _controls.is_stop():
                        emit_event("pipeline_stopped", phase=0, reason="stopped during cua_unavailable")
                        return
                    # DGOPS-7710-followup: honor skip_init_verify so CLI `s`
                    # (or FE Skip-verification toggle) breaks out of the CUA
                    # retry loop. Without this check the function just falls
                    # through to consume_retry_phase and continues, ignoring
                    # the user's skip signal. Mirrors the login_required
                    # pattern at line ~21700.
                    if _controls.skip_init_verify:
                        log(f"Phase 0: SKIP_INIT_VERIFY during cua_unavailable — bailing CUA loop", "INFO")
                        _global_skip = True
                        break
                    # retry — clear flag + loop continues, fresh CUA call
                    # picks up the new key.
                    _controls.consume_retry_phase(0)
                    _controls.retry_init_verify = False
                    continue
                except Exception as e:
                    log(f"Phase 0: login check failed for {key}: {e}", "WARN")
                    ok = False

                if ok:
                    emit_event("agent_progress", phase=0, agent=key,
                               status="ok", progress=f"{label}: logged in ✓")
                    # Pro-tier verification (DGOPS-7363). Runs only for
                    # platforms that have a Pro/Free split affecting Deep
                    # Research output (ChatGPT/Claude/Gemini). Skipped if
                    # the user already opted into Free on a prior platform
                    # in this run, or if no CUA client is available.
                    if (key in _PRO_TIER_PLATFORMS
                            and cua_client is not None
                            and not _controls.pro_warning_acknowledged):
                        emit_event("agent_progress", phase=0, agent=key,
                                   status="checking_tier",
                                   progress=f"{label}: checking subscription tier…")
                        try:
                            tier = await _cua_pro_tier_call(tab, key, cua_client)
                        except CuaUnavailableError as cua_err:
                            log(f"Phase 0: CUA unavailable during {label} tier check — assuming Pro: {cua_err}", "WARN")
                            tier = "unsure"
                        if tier == "free":
                            log(f"Phase 0: {label} on Free tier — emitting pro_required alert", "INFO")
                            emit_event("agent_progress", phase=0, agent=key,
                                       status="not_pro",
                                       progress=f"{label}: Pro NOT detected — Phase output will be degraded")
                            _emit_pro_required_alert(phase=0, agent=key, source=f"phase0/platform={key}")
                            _controls.request_pause("pro_required")
                            emit_event("pipeline_paused", phase=0, reason="pro_required")
                            await _controls.wait_if_paused()
                            if _controls.is_stop():
                                emit_event("pipeline_stopped", phase=0, reason="user_stop_pro_required")
                                return
                            if _controls.consume_retry_phase(0):
                                # User clicked Retry — they're (presumably)
                                # signing in with a Pro account. Close the
                                # current tab so the next iteration re-opens
                                # fresh and re-runs login + tier checks from
                                # scratch. The while loop's `continue` re-runs
                                # the whole verification for THIS platform.
                                log(f"Phase 0: user clicked Retry on {label} pro_required — re-verifying", "INFO")
                                emit_event("pipeline_resumed", phase=0, reason="pro_retry")
                                _t = _preflight_tabs.pop(key, None)
                                if _t is not None:
                                    try: await _t.close()
                                    except Exception: pass
                                emit_event("phase_start", phase=0,
                                           description=f"Re-checking {label} after Pro retry (attempt {attempt + 1})")
                                _update_firestore_research({"phase": 0, "currentPhase": 0, "status": "ongoing"})
                                continue  # re-run the while loop for this platform
                            if _controls.consume_continue_anyway():
                                _controls.pro_warning_acknowledged = True
                                log(f"Phase 0: user opted into Free — suppressing further Pro alerts this run", "INFO")
                                # F3: clear stale pro_required alert documents
                                # from FE store BEFORE the resumed event fires
                                # (resumed triggers the FE auto-clear sweep).
                                # Order: flag → clear emit → resumed emit.
                                _clear_pro_required_alerts(triggered_at_phase=0)
                                emit_event("pipeline_resumed", phase=0, reason="continue_with_free")
                                emit_event("agent_progress", phase=0, agent=key,
                                           status="free_acknowledged",
                                           progress=f"{label}: continuing on Free (user-acknowledged)")
                            else:
                                # Resume without continue_anyway / retry — treat
                                # as acknowledgement (user dismissed the alert
                                # then resumed via chat-box).
                                _controls.pro_warning_acknowledged = True
                                log(f"Phase 0: pro_required pause resumed without explicit choice — treating as Free-acknowledged", "INFO")
                                # F3: same clear pattern — even on a generic
                                # resume the user has effectively acknowledged
                                # Free, so the actionable alert must go away.
                                _clear_pro_required_alerts(triggered_at_phase=0)
                                emit_event("pipeline_resumed", phase=0, reason="resume")
                        elif tier == "pro":
                            log(f"Phase 0: {label} Pro detected ✓", "INFO")
                            emit_event("agent_progress", phase=0, agent=key,
                                       status="pro_ok", progress=f"{label}: Pro tier ✓")
                        else:  # unsure → fail open
                            log(f"Phase 0: {label} tier UNSURE — assuming Pro (fail-open)", "INFO")
                    break  # move to next platform

                # Not logged in — emit login_required scoped to JUST this
                # platform and wait for user retry.
                emit_event("agent_progress", phase=0, agent=key,
                           status="needs_login", progress=f"{label}: login required ✗")
                _login_msg = f"Log into {label} in the browser on your setup PC."
                # alert_id aligns Phase 0 with the phase>=1 path so the live
                # event card and the doc-hydrated card dedup on the same key.
                _login_alert_id = f"phase0_login_required_{key}"
                emit_event("login_required",
                           phase=0,
                           platforms=[key],
                           platformLabels=[label],
                           machineName=socket.gethostname(),
                           attempt=attempt,
                           message=_login_msg,
                           alert_id=_login_alert_id)
                _controls.request_pause("login_required")
                emit_event("pipeline_paused", phase=0, reason="login_required")
                # Durable mirror so opening this chat re-surfaces the Retry card
                # even when it wasn't the viewed tab as the gate fired.
                _persist_pending_decision({
                    "kind": "login_required",
                    "phase": 0,
                    "platforms": [key],
                    "platformLabels": [label],
                    "machineName": socket.gethostname(),
                    "attempt": attempt,
                    "message": _login_msg,
                    "alert_id": _login_alert_id,
                })
                await _controls.wait_if_paused()
                # Gate resolved (resume / skip / stop) — retract the durable
                # card. A still-failing retry re-persists on the next loop.
                _clear_pending_decision()
                if _controls.is_stop():
                    emit_event("pipeline_stopped", phase=0, reason="stopped during login_required")
                    return
                if _controls.skip_init_verify:
                    log(f"Phase 0: SKIP_INIT_VERIFY during {label} — skipping remaining platforms", "INFO")
                    _global_skip = True
                    break
                # Unify retry signals: the login_required banner's dedicated
                # "Retry" button writes action="retry_init_verify", but the
                # generic PhaseAlertPanel Retry button writes action="retry_phase"
                # with phase=0. Both mean the same thing here — the user
                # acted in the browser, re-check this platform with fresh state.
                if _controls.consume_retry_phase(0):
                    _controls.retry_init_verify = True
                _is_retry = bool(_controls.retry_init_verify)
                emit_event("pipeline_resumed", phase=0, reason="retry" if _is_retry else "resume")
                # Always close the tab on resume. The user just did something
                # in the browser (logged in, solved a CAPTCHA, dismissed a
                # popup) — re-using the stale tab would make the next CUA
                # screenshot identical to the pre-pause one, defeating the retry.
                _t = _preflight_tabs.pop(key, None)
                if _t is not None:
                    try: await _t.close()
                    except Exception: pass
                if _is_retry:
                    _controls.retry_init_verify = False
                    emit_event("phase_start", phase=0,
                               description=f"Re-checking {label} (attempt {attempt + 1})")
                    _update_firestore_research({"phase": 0, "currentPhase": 0, "status": "ongoing"})
                log(f"Phase 0: resumed ({'retry' if _is_retry else 'resume'}) — re-checking {label}", "INFO")
                # while loop continues — re-check same platform with fresh state
            # Inner while exited — either verified, skipped globally, or stopped.
            if _global_skip:
                emit_event("agent_progress", phase=0, agent="system", status="Skipped",
                           progress="Verification skipped by user")
                break  # break outer for

        # 2026-05-11: bridge the silent gap between the last platform's
        # CUA verdict and phase_complete:0. Without an emit here, the
        # dropdown sat quiet after the final ✓ while env_check +
        # preflight tab cleanup ran (~0.5-2s on a warm path; longer when
        # resolve_api_key round-trips to Firestore for a per-user
        # override). User reports a "stuck for a small instance" feel
        # after the 2026-05-10 cutover dropped youtube/gmail/gdocs from
        # preflight — 4 platforms make the trailing env-check window
        # proportionally more visible than it was with 7. Skip when
        # verification was globally bypassed (the _global_skip branch
        # above emits its own status), and skip when no real platforms
        # were verified (env-only path is too short to need a bridge).
        if not _global_skip and preflight_platforms:
            emit_event("agent_progress", phase=0, agent="system",
                       status="Finalizing",
                       progress="All sessions verified — handing off to the research phases…")

        # Env checks: required keys for the pipeline + ffmpeg for video.
        # Run these regardless of whether login verification was skipped —
        # missing env breaks the pipeline whether or not logins are verified.
        # All three checks resolve via the SAME functions the actual call
        # sites use, so a key set in the Account page (Firestore) wins over
        # any local env. Without this, the gate would falsely refuse a run
        # the BE could otherwise complete.
        _env_ok = True
        _env_errors: list[str] = []
        # Anthropic / CUA — needed across phases for vision tier-2 + tier-3
        # (CUA fallback). Hard requirement for any non-trivial run; surface
        # the error before phase 1 so the user gets a clear "add it via
        # Account → API Config" instead of a mid-phase vision crash.
        if not resolve_api_key():
            _env_ok = False
            _env_errors.append("Anthropic API key missing — add it in Account → API Config (preferred), or set ANTHROPIC_API_KEY on the BE machine. Vision/CUA tiers can't run without it.")
        if not _env_ok:
            emit_event("login_required",
                       phase=0,
                       platforms=[],
                       platformLabels=[],
                       machineName=socket.gethostname(),
                       envErrors=_env_errors,
                       attempt=1,
                       message="Environment check failed — see errors above.",
                       alert_id="phase0_env_check")
            # #710 parity: durable mirror so an env-check failure raised while
            # this chat wasn't the viewed tab re-surfaces the card on open.
            # (Same kind as login_required — the FE's isEnv branch renders it.)
            _persist_pending_decision({
                "kind": "login_required",
                "phase": 0,
                "platforms": [],
                "platformLabels": [],
                "machineName": socket.gethostname(),
                "envErrors": _env_errors,
                "attempt": 1,
                "message": "Environment check failed — see errors above.",
                "alert_id": "phase0_env_check",
            })
            _controls.request_pause()
            emit_event("pipeline_paused", phase=0, reason="login_required")
            await _controls.wait_if_paused()
            if _controls.is_stop():
                emit_event("pipeline_stopped", phase=0, reason="stopped during env_error")
                return
            emit_event("pipeline_resumed", phase=0, reason="retry")

        # Close the preflight verification tabs so they don't clutter the
        # window through Phases 1-5. CRITICAL: Browser.new_tab() reassigns
        # self.page to each new tab, so `browser.page` is the LAST preflight
        # tab we opened. Phase 1 navigates `browser.page` to ChatGPT — we
        # must KEEP that page alive. So: close every preflight tab EXCEPT
        # whichever one is currently browser.page. Phase 1's navigate() will
        # then reuse that page as its ChatGPT tab.
        primary = browser.page
        for _key, _tab in _preflight_tabs.items():
            if _tab is primary:
                continue
            try:
                await _tab.close()
            except Exception:
                pass
        _preflight_tabs.clear()

        if _skip_verify_pref or _controls.skip_init_verify:
            _p0_summary = "Preflight skipped — trusting existing sessions"
        elif preflight_platforms:
            _p0_summary = f"Preflight passed — {len(preflight_platforms)} platform(s) ready"
        else:
            _p0_summary = "Preflight complete"
        emit_event("phase_complete", phase=0,
                   durationSec=int(time.time() - _p0_start),
                   summary=_p0_summary)

        # Pre-emit phase_start(1) BEFORE the verify gate runs so the FE
        # renders the P1 chip immediately instead of a blank gap during
        # the gate's 4s SPA hydration + verify_login_cua + Pro tier check
        # (skip_init_verify=true path). If the gate / dispatch below skips
        # P1, phase_skipped follows and the FE flips the chip running →
        # skipped — same lifecycle as a mid-phase skip click.
        _p1_start_emitted = False
        if (start_phase <= 1 and 1 not in skip_phases
                and 1 not in _controls.skipped_phases
                and not _controls.is_stop()):
            emit_event("phase_start", phase=1,
                       description="Generating research brief with ChatGPT Pro + Extended Thinking",
                       agents=["chatgpt"])
            _update_firestore_research({"phase": 1, "currentPhase": 1, "status": "ongoing"})
            _p1_start_emitted = True

        # ══════════════════════ PHASE 1 verify gate (BE-2) ══════════════════════
        # When init was skipped (skip_init_verify=True), re-verify ChatGPT
        # login + Pro before P1 touches it. Skip routes into manual_brief
        # flow inline — caller pre-populates brief_text + brief_artifact and
        # marks _gate_skipped_p1=True so the dispatch chain steers into the
        # SKIP branch (which then emits phase_skipped + creates BriefArtifact).
        # No-op when init verified normally.
        _gate_skipped_p1 = False
        # Did Phase 1 run a LIVE brief generation (ChatGPT) this session? Init
        # above the P1 block so it's always defined — including resume-into-P2
        # where the P1 block is skipped. Gates P2 source-doc delivery: only
        # attach the user's sources to P2 when P1 did NOT distill them into a
        # brief itself (P1-ON would double-feed). Set True only at the live
        # `brief_text = p1["text"]` point below.
        _p1_ran_live = False
        if (start_phase <= 1 and 1 not in skip_phases
                and 1 not in _controls.skipped_phases
                and _controls.skip_init_verify
                and not _controls.is_stop()):
            _p1_gate = await _phase_verify_gate(1, "chatgpt", browser, cua_client)
            if _p1_gate == "stop":
                emit_event("pipeline_stopped", phase=1, reason="user_stop_at_verify_gate")
                return
            if _p1_gate == "skipped":
                # User picked Skip on the P1 ChatGPT verify alert. Per the
                # ChatGPT-runs-twice design (P1 brief + P2 task), skip-at-P1
                # cannot silently produce an empty brief — Phase 2 hard-fails
                # with "No brief text available". Mirror the existing post-fail
                # manual_brief flow at ~line 20554: emit manual_brief_required,
                # block on extra_context (3h backstop), consume the user-typed
                # brief, then steer the dispatch into SKIP so brief_artifact
                # is created and Phase 2 runs with the manual brief.
                log("Phase 1: verify gate skipped → manual brief flow", "INFO")
                emit_event("manual_brief_required", phase=1,
                           message="Type your research brief into chat, then press Resume.",
                           actions=[],
                           dismissible=True,
                           alert_id="phase1_manual_brief_required")
                _BRIEF_WAIT_BACKSTOP_S = 3 * 3600
                _brief_wait_start = time.time()
                while not _controls.peek_extra_context() and not _controls.is_stop():
                    if (time.time() - _brief_wait_start) > _BRIEF_WAIT_BACKSTOP_S:
                        log("Phase 1: manual brief wait exceeded 3h — auto-failing", "WARN")
                        fail_phase(1,
                                   "Manual brief not received in 3h",
                                   "Phase 1 was waiting for you to type a research "
                                   "brief into chat after skipping ChatGPT verification, "
                                   "but no brief arrived in 3 hours. Retry to re-prompt "
                                   "and start over, or Skip to abandon Phase 1.")
                        emit_event("pipeline_stopped", phase=1,
                                   reason="manual_brief_wait_backstop_3h")
                        return
                    await asyncio.sleep(0.5)
                if _controls.is_stop():
                    log("Phase 1: stop pressed during manual brief wait", "INFO")
                    emit_event("pipeline_stopped", phase=1, reason="user_stop_during_manual_brief")
                    return
                brief_text = (_controls.pop_extra_context() or "").strip()
                brief_url = ""
                log(f"Phase 1: user supplied manual brief via gate ({len(brief_text)} chars)")
                _gate_skipped_p1 = True

        # ══════════════════════ PHASE 1: Brief ══════════════════════
        p1 = None
        _user_skip_p1 = _controls.consume_phase_skip(1)
        if 1 in skip_phases or _user_skip_p1 or _gate_skipped_p1:
            if _gate_skipped_p1:
                _reason = "user_skip_at_verify_gate"
            elif _user_skip_p1:
                _reason = "user_skip"
            else:
                _reason = "Disabled in pipeline config"
            log(f"Phase 1: SKIPPED ({_reason})")
            emit_event("phase_skipped", phase=1, reason=_reason)
            # Phase-1-skip must still hydrate brief_text so Phase 2 has a
            # brief to paste. Priority: explicit brief_file > on-disk
            # documents/brief.md (written by the inline-brief path earlier,
            # or by a previous run we're resuming). Phase 2 hard-fails
            # without this ("No brief text available — cannot run Phase 2").
            _loaded_from = None
            if brief_file and Path(brief_file).exists():
                try:
                    brief_text = Path(brief_file).read_text(encoding="utf-8")
                    _loaded_from = f"brief_file={brief_file}"
                except Exception as _e:
                    log(f"Phase 1 skip: could not read brief_file ({_e})", "WARN")
            if not brief_text:
                for _bp in [queue_dir / "documents" / "brief.md", queue_dir / "brief.md"]:
                    if _bp.exists():
                        try:
                            brief_text = _bp.read_text(encoding="utf-8")
                            _loaded_from = f"disk={_bp}"
                            break
                        except Exception:
                            continue
            if brief_text.startswith("# Research Brief\n\n"):
                brief_text = brief_text[len("# Research Brief\n\n"):]
            brief_artifact = BriefArtifact(text=brief_text, url="")
            if brief_text:
                log(f"Phase 1 skip: loaded brief ({len(brief_text)} chars) from {_loaded_from}")
            else:
                log("Phase 1 skip: no brief source — Phase 2 will fail unless one appears", "WARN")
        elif start_phase <= 1:
            if not _p1_start_emitted:
                # Edge case: pre-emit was gated out above (e.g. stop pressed
                # mid-verify-gate, then cleared). Emit now so the dispatch
                # has a corresponding start event.
                emit_event("phase_start", phase=1, description="Generating research brief with ChatGPT Pro + Extended Thinking", agents=["chatgpt"])
                _update_firestore_research({"phase": 1, "currentPhase": 1, "status": "ongoing"})
            _p1_start = time.time()
            # Active-time ceiling for Phase 1 — paused seconds don't count.
            # If the user pauses for lunch, the budget is preserved.
            # Enforced via _await_phase_with_active_deadline at each call
            # below; budget is shared across the for _p1_attempt restart loop.
            # PHASE_1_MAX_MIN is the cap (env-overridable).
            # Per-phase login probe removed (2026-04-24) for the happy
            # path. Phase 0 is the single source of truth for login state
            # — if Phase 0 marked a platform "ok" (cookie + DOM or CUA
            # verdict), we trust it and proceed. On real session drift
            # mid-run, the phase's own navigation + scraping will surface
            # a real failure through fail_phase, which the alert panel
            # handles.
            #
            # 2026-05-08 follow-up: when init verification is skipped
            # (skip_init_verify=True), _phase_verify_gate runs above this
            # block to re-verify login + Pro on a per-platform basis,
            # mirroring P0's flow. The "Phase 0 is the single gate"
            # invariant holds for the verified-init path; the gate
            # re-introduces phase-time verification ONLY for the explicit
            # skip-init path, where the alternative is silent degradation.
            # ARCHITECTURE 2026-04-18: Never-die retry loop. Any fail_phase
            # inside this block awaits the user's Retry/Skip/Stop decision
            # via _controls.await_phase_decision(1). Retry loops back; Skip
            # breaks out with brief_text="" so downstream phases can decide
            # what to do with no brief; Stop returns from the pipeline.
            _p1_skipped_after_error = False
            _brief_from_file = False
            while True:
                if brief_file:
                    brief_text = Path(brief_file).read_text(encoding="utf-8")
                    # Strip the common "# Research Brief\n\n" prefix if present so
                    # downstream token counts / paste ops aren't inflated by it.
                    if brief_text.startswith("# Research Brief\n\n"):
                        brief_text = brief_text[len("# Research Brief\n\n"):]
                    log(f"Phase 1: SKIPPED — loaded brief from {brief_file} ({len(brief_text)} chars)")
                    brief_url = ""
                    _brief_from_file = True
                    break
                fb1 = get_feedback(1)
                # Restart loop: if mid-phase pause+input+resume trips
                # `_runtime.restart_requested`, merge the buffered context into
                # the topic and rerun Phase 1. Capped at 3 attempts.
                p1 = None
                current_topic = topic
                for _p1_attempt in range(3):
                    _runtime.restart_requested = False
                    # Inner timeout-retry loop: if the active-time ceiling
                    # fires, surface to user with [Retry, Skip] (recoverable),
                    # NOT terminate the run. lambda factory creates a fresh
                    # coroutine on each retry — can't await an already-awaited
                    # coroutine, so the helper takes a factory now.
                    while True:
                        try:
                            p1 = await _await_phase_with_active_deadline(
                                1, PHASE_1_MAX_MIN,
                                lambda: run_phase1(browser, cua_client, current_topic, pdf_paths, verbose, feedback=fb1),
                                soft_warn_only=True,  # 2026-05-04: long brief gens (30+m on large PDFs) are legitimate; warn but don't bail
                            )
                            break  # success — exit inner retry loop
                        except _PhaseSoftDecision as _sd:
                            if _sd.decision == "retry":
                                emit_event("phase_restart", phase=1, reason="user_retry_after_soft_timeout")
                                continue
                            if _sd.decision == "skip":
                                emit_event("phase_skipped", phase=1, reason="user_skip_after_soft_timeout")
                                _p1_skipped_after_error = True
                                p1 = None
                                break
                            log(f"[P1] Unexpected _PhaseSoftDecision.decision={_sd.decision!r}", "ERROR")
                            raise
                        except asyncio.TimeoutError:
                            # Legacy hard-path safety net — with soft_warn_only=True the
                            # helper raises _PhaseSoftDecision instead of TimeoutError, so
                            # this branch is normally unreachable. Kept as a guard in case
                            # something inside run_phase1 raises a bare TimeoutError that
                            # escapes the helper's wrap.
                            _decision = await _phase_timeout_decision(1, PHASE_1_MAX_MIN, agent="chatgpt")
                            if _decision == "retry":
                                emit_event("phase_restart", phase=1, reason="user_retry_after_timeout")
                                continue  # rerun via factory with fresh deadline
                            if _decision == "skip":
                                emit_event("phase_skipped", phase=1, reason="user_skip_after_timeout")
                                _p1_skipped_after_error = True
                                p1 = None
                                break
                            # stop / fall-through (user explicitly hit Stop)
                            emit_event("pipeline_stopped", phase=1, reason=f"user_{_decision}_after_timeout")
                            return
                    if _p1_skipped_after_error:
                        break  # exit outer for _p1_attempt loop too
                    if fb1:
                        clear_feedback(1)
                        fb1 = ""  # only feed in on first attempt
                    if not _runtime.restart_requested:
                        break
                    extra_ctx_retry = _controls.pop_extra_context()
                    if not extra_ctx_retry:
                        break
                    current_topic = current_topic + "\n\nADDITIONAL USER CONTEXT:\n" + extra_ctx_retry
                    log(f"[Phase 1] Mid-phase restart with +{len(extra_ctx_retry)} chars of user input")
                    emit_event("phase_restart", phase=1,
                               reason="mid_phase_input_on_resume",
                               chars=len(extra_ctx_retry), attempt=_p1_attempt+1)
                if _controls.is_stop():
                    # User pressed Stop during Phase 1 (e.g. on the Pro-required
                    # backstop alert). Don't fire the "no brief generated"
                    # alert — Stop already emitted pipeline_stopped. Outer
                    # finally cleans up the browser. Pre-existing latent bug
                    # surfaced by DGOPS-7363's Phase 1 backstop.
                    log("Phase 1: stop_event set — exiting cleanly (no fail_phase cascade)", "INFO")
                    return
                if not p1 or not p1["text"]:
                    log("Phase 1 failed — no brief generated; awaiting user decision", "ERROR")
                    fail_phase(
                        phase=1,
                        error="no brief generated",
                        reason="ChatGPT Pro didn't produce a research brief after all retries. Check the ChatGPT session is signed in, then try again.",
                        agent="chatgpt",
                    )
                    decision = await _controls.await_phase_decision(1)
                    if decision == "retry":
                        log("Phase 1: user requested retry — re-running from the top", "INFO")
                        emit_event("phase_restart", phase=1, reason="user_retry_after_error", attempt=0)
                        continue
                    if decision == "skip":
                        log("Phase 1: user skipped after error — switching to manual brief entry mode", "INFO")
                        emit_event("phase_skipped", phase=1, reason="user_skip_after_error")
                        # ── P1 skip → manual brief flow ──
                        # Instead of proceeding with an empty brief, ask the
                        # user to paste their own. Emit a Template-shape info
                        # alert with [Dismiss] and block on extra_context
                        # until the chat input lands a brief. On consume,
                        # use the pasted text as the brief and continue.
                        emit_event("manual_brief_required", phase=1,
                                   message="Type your research brief into chat, then press Resume.",
                                   actions=[],
                                   dismissible=True,
                                   alert_id="phase1_manual_brief_required")
                        # 3h backstop (2026-04-30): if the user walks away
                        # and never pastes a brief or stops, the wait used
                        # to hang forever, leaving the run in `ongoing`
                        # status indefinitely. After 3h we auto-fail the
                        # phase with [Retry, Skip] so the run reaches a
                        # terminal-or-actionable state.
                        _BRIEF_WAIT_BACKSTOP_S = 3 * 3600
                        _brief_wait_start = time.time()
                        while not _controls.peek_extra_context() and not _controls.is_stop():
                            if (time.time() - _brief_wait_start) > _BRIEF_WAIT_BACKSTOP_S:
                                log("Phase 1: manual brief wait exceeded 3h — auto-failing", "WARN")
                                # 2026-05-15: previously this path emitted
                                # fail_phase (recoverable alert with
                                # [Retry, Skip]) THEN immediately
                                # pipeline_stopped + return — tearing down
                                # the run while the user saw Retry/Skip
                                # buttons that did nothing. Honor the
                                # never-die contract: fail_phase emits the
                                # actionable alert, await the user's
                                # decision, and act on it. Mirrors the
                                # pattern at research.py:22131-22146.
                                fail_phase(1,
                                           "Manual brief not received in 3h",
                                           "Phase 1 was waiting for you to type a research "
                                           "brief into chat, but no brief arrived in 3 hours. "
                                           "Retry to wait another 3 hours, or Skip to "
                                           "abandon Phase 1.")
                                _bs_decision = await _controls.await_phase_decision(1)
                                if _bs_decision == "retry":
                                    emit_event("phase_restart", phase=1,
                                               reason="user_retry_after_brief_wait_backstop")
                                    _brief_wait_start = time.time()
                                    continue
                                if _bs_decision == "skip":
                                    emit_event("phase_skipped", phase=1,
                                               reason="user_skip_after_brief_wait_backstop")
                                    _p1_skipped_after_error = True
                                    # Break out of the inner backstop loop.
                                    # The post-while skip-propagation check
                                    # below carries _p1_skipped_after_error
                                    # out through the outer `while True:` so
                                    # downstream skip handling (stub
                                    # phase_complete, empty brief artifact,
                                    # P2 continues without a brief) actually
                                    # runs — `return` here would discard the
                                    # flag and exit run_phase1 prematurely.
                                    break
                                # "stop" / "timeout" — terminate the run.
                                # pipeline_stopped emit matches the
                                # canonical pattern at research.py:22128.
                                emit_event("pipeline_stopped", phase=1,
                                           reason=f"user_{_bs_decision}_after_brief_wait_backstop")
                                return
                            await asyncio.sleep(0.5)
                        # 2026-05-15: skip-after-backstop propagation.
                        # When the 3h-backstop skip branch breaks the inner
                        # loop with _p1_skipped_after_error=True, exit the
                        # outer `while True:` so the run_phase1 tail at
                        # ~line 22275 sees the flag and emits the stub
                        # phase_complete + sets up an empty brief artifact.
                        # Without this guard we'd fall through to the
                        # "user typed a brief" path below and reset the flag.
                        if _p1_skipped_after_error:
                            break
                        if _controls.is_stop():
                            log("Phase 1: stop pressed during manual brief wait", "INFO")
                            emit_event("pipeline_stopped", phase=1, reason="user_stop_during_manual_brief")
                            return
                        brief_text = (_controls.pop_extra_context() or "").strip()
                        brief_url = ""
                        log(f"Phase 1: user supplied manual brief ({len(brief_text)} chars)")
                        _p1_skipped_after_error = False
                        break
                    # stop / timeout — only way the pipeline actually ends
                    log(f"Phase 1: user {decision} after error — terminating pipeline", "INFO")
                    emit_event("pipeline_stopped", phase=1, reason=f"user_{decision}_after_error")
                    return
                brief_text = p1["text"]
                brief_url = p1.get("url", "")
                _p1_ran_live = True  # ChatGPT generated the brief — sources already absorbed
                # Stamp the "don't attach to P2" decision durably NOW, not at
                # P2 entry — otherwise a pause AFTER P1 but BEFORE P2 entry
                # leaves the manifest un-decided, and resume-into-P2 (where the
                # P1 block is skipped + _p1_ran_live re-inits False) would flip
                # it to attach, double-feeding sources P1 already distilled.
                _finalize_p2_source_decision(False)
                # Propagate the ChatGPT-share / conversation URL to the
                # Firestore aggregate so P5's Doc body shows the
                # "ChatGPT Brief: <url>" line. This URL is NOT emitted as
                # a separate link_extracted (P1 surfaces only the in-app
                # /documents primary to the FE) — but the Doc spec
                # requires it, so we land it directly in the aggregate.
                if brief_url:
                    try:
                        update_link_in_firestore("brief", brief_url,
                                                 label="ChatGPT Brief", phase=1, verified=True)
                    except Exception:
                        pass
                break
            # Save brief in documents/
            if _p1_skipped_after_error:
                # User chose Skip after a brief-generation error — emit a
                # stub phase_complete so the pipeline tile shows the skip
                # outcome instead of hanging, and set brief_artifact to an
                # empty shell so downstream Phase 2 can make its own
                # decision (it has its own fail_phase + await_phase_decision
                # when the paste step finds no content).
                brief_artifact = BriefArtifact(text="", url="")
                emit_event("phase_complete", phase=1, durationSec=int(time.time() - _p1_start),
                    summary="Phase 1 skipped after error — no brief generated")
                _update_firestore_research({"phase": 1, "status": "ongoing"})
                # Tile/Icon Consistency (mirrors P2 at line ~19244): persist
                # a terminal P1+ChatGPT status to the root doc so the listing
                # tile + chat phase icon + agent dropdown stay correct after
                # reload. Without this, on reopen the FE falls back to the
                # last volatile per-agent status (e.g. "submitting"), which
                # never matches the green-tick gate.
                _write_phase_terminal_status(1, "skipped")
                # 2026-05-12: REMOVED `_write_agent_terminal_status("chatgpt", "skipped")` —
                # the `chatgpt` agent slot is shared between P1 (brief) and
                # P2 (deep research). Writing P1's status there made the
                # in-chat ChatGPT P2 config icon show a green/skipped badge
                # before P2 ChatGPT had run. P1's status is fully captured by
                # phases[1].status (read by the Brief icon, which has no
                # `agent` field). P2 ChatGPT writes its own agents.chatgpt
                # at P2 finalize (research.py:12716).
            elif _brief_from_file:
                # Phase 1 bypassed via --brief-file (or frontend briefText).
                # Persist to disk + Firestore. The user supplied the text;
                # there's no ChatGPT session to share from. Link to the
                # in-app document viewer (FE Documents page renders the
                # markdown in app theme).
                _brief_md = f"# Research Brief\n\n{brief_text}"
                (queue_dir / "documents" / "brief.md").write_text(_brief_md, encoding="utf-8")
                save_document_to_firestore("brief", _brief_md, "Research Brief")
                _in_app_brief_url = f"/documents?open={_fb_research_id}:brief" if _fb_research_id else "/documents"
                brief_artifact = BriefArtifact(text=brief_text, url=_in_app_brief_url)
                log(f"BriefArtifact (from file): {brief_artifact.chars} chars, "
                    f"{len(brief_artifact.sections)} sections")
                _p1_links = [{"label": "Read brief", "url": _in_app_brief_url, "verified": True, "primary": True}]
                save_checkpoint(queue_dir, 1, topic=topic, brief_url=_in_app_brief_url)
                save_meta(queue_dir, topic, 1, summary=brief_text[:200].strip())
                emit_event("phase_complete", phase=1,
                    durationSec=int(time.time() - _p1_start), links=_p1_links,
                    summary=f"Research brief loaded from file ({brief_artifact.chars} chars)")
                _update_firestore_research({"phase": 1, "status": "ongoing", "links.phase1": _p1_links})
                _write_phase_terminal_status(1, "complete")
                # 2026-05-12: REMOVED `_write_agent_terminal_status("chatgpt", "complete")` —
                # the chatgpt slot is shared with P2 deep research; writing
                # P1's status there made the P2 ChatGPT config icon show
                # green ✓ before P2 finished. See _p1_skipped_after_error
                # branch above for the full rationale.
            else:
                _brief_md = f"# Research Brief\n\n{brief_text}"
                (queue_dir / "documents" / "brief.md").write_text(_brief_md, encoding="utf-8")
                # Sync to Firestore documents subcollection — this is the
                # source of truth the FE Documents page renders. Phase 2
                # uses brief_artifact.text for paste; the URL is purely for
                # display in the phase dropdown + chat.
                save_document_to_firestore("brief", _brief_md, "Research Brief")
                # ── Markdown-as-primary architecture (2026-04-25) ──
                # phase_complete fires as SOON as the brief markdown is
                # in Firestore. The primary link points at the in-app
                # Documents viewer — guaranteed to work, no platform
                # share-link scraping required. Share-link extraction
                # runs AFTER as a best-effort secondary (90s budget,
                # conversation URL fallback) and lands via link_extracted.
                # Goals: (a) phase_complete is no longer gated on a
                # flaky CUA share-modal flow; (b) the chat/dropdown link
                # always works; (c) the run advances even if ChatGPT's
                # share UI changes overnight.
                _in_app_brief_url = f"/documents?open={_fb_research_id}:brief" if _fb_research_id else "/documents"
                brief_artifact = BriefArtifact(text=brief_text, url=_in_app_brief_url)
                log(f"BriefArtifact: {brief_artifact.chars} chars, {len(brief_artifact.sections)} sections")
                _p1_links = [{"label": "Read brief", "url": _in_app_brief_url, "verified": True, "primary": True}]
                save_checkpoint(queue_dir, 1, topic=topic, brief_url=_in_app_brief_url)
                update_delivery(brief_url=_in_app_brief_url)
                save_meta(queue_dir, topic, 1, summary=brief_text[:200].strip())
                emit_event("phase_complete", phase=1, durationSec=int(time.time() - _p1_start),
                    links=_p1_links,
                    summary=f"Research brief generated ({brief_artifact.chars} chars, {len(brief_artifact.sections)} sections)")
                _update_firestore_research({"phase": 1, "status": "ongoing", "links.phase1": _p1_links})
                _write_phase_terminal_status(1, "complete")
                # 2026-05-12: REMOVED `_write_agent_terminal_status("chatgpt", "complete")` —
                # see _p1_skipped_after_error branch above for rationale
                # (chatgpt slot is shared with P2).
                # 2026-04-25: P1 secondary "View on ChatGPT" link removed.
                # The in-app /documents?open=…:brief primary is the only link
                # surfaced to the FE. The conversation URL (brief_url, captured
                # at line ~12209) still propagates to Phase 5 for the Google
                # Doc — it just isn't streamed as a separate link_extracted.
        else:
            # Load brief from documents/ (new location) or root (old location)
            for bp in [queue_dir / "documents" / "brief.md", queue_dir / "brief.md"]:
                if bp.exists():
                    raw = bp.read_text(encoding="utf-8")
                    brief_text = raw.replace("# Research Brief\n\n", "", 1)
                    break
            log(f"Phase 1: Loaded existing brief ({len(brief_text)} chars)")

        if _controls.is_stop_or_pause():
            if _controls.is_stop():
                log("STOP requested after Phase 1 — pipeline terminated", "WARN")
                save_meta(queue_dir, topic, 1, status="stopped")
                update_delivery(status="stopped")
                emit_event("pipeline_stopped", phase=1, reason="stop")
                _update_firestore_research({"status": "stopped", "phase": 1})
            else:
                log("PAUSE requested after Phase 1 — closing browser, awaiting resume", "WARN")
                save_meta(queue_dir, topic, 1, status="paused")
                update_delivery(status="paused")
                _update_firestore_research({"status": "paused", "phase": 1})
                _runtime.original_inputs = {"topic": topic, "pdf_paths": [str(p) for p in (pdf_paths or [])]}
                stopped = await pause_and_close_browser(browser, queue_dir, phase=1,
                                                        extra_kwargs={"topic": topic, "brief_url": brief_url})
                if stopped:
                    save_meta(queue_dir, topic, 1, status="stopped")
                    emit_event("pipeline_stopped", phase=1, reason="stop_after_pause")
                    _update_firestore_research({"status": "stopped", "phase": 1})
                    return
                # Relaunch browser on resume
                browser = Browser(_profile_dir(WORKER_ID), headless=False)
                await browser.start()
                _active_browser_ref = browser  # re-point stop handler at fresh session
                emit_event("pipeline_resumed", phase=1)
                _update_firestore_research({"status": "ongoing"})
                # Pause+resume+input semantics: rerun the paused phase with the
                # user's input folded into the combined topic. The resulting
                # brief carries the new guidance forward into Phase 2 naturally.
                if _controls.peek_extra_context():
                    resume_input = _controls.pop_extra_context()
                    log(f"Phase 1 resume-with-input — regenerating brief with {len(resume_input)} extra chars")
                    emit_event("phase_restart", phase=1, reason="user_input_on_resume", chars=len(resume_input))
                    combined_topic = topic + "\n\nADDITIONAL USER CONTEXT:\n" + resume_input
                    p1_new = await run_phase1(browser, cua_client, combined_topic, pdf_paths, verbose, feedback="")
                    if p1_new and p1_new.get("text"):
                        brief_text = p1_new["text"]
                        brief_url = p1_new.get("url", brief_url)
                        _brief_md_regen = f"# Research Brief\n\n{brief_text}"
                        (queue_dir / "documents" / "brief.md").write_text(_brief_md_regen, encoding="utf-8")
                        save_document_to_firestore("brief", _brief_md_regen, "Research Brief")
                        brief_artifact = BriefArtifact(text=brief_text, url=brief_url)
                        emit_event("phase_complete", phase=1,
                                   summary=f"Brief regenerated with user input ({len(brief_text)} chars)",
                                   links=[{"label": "ChatGPT Brief", "url": brief_url}] if brief_url else [])
                        # Resume-with-input regen still needs the terminal
                        # phase write because the original P1 write (if any)
                        # was for the pre-pause attempt.
                        _write_phase_terminal_status(1, "complete")
                        # 2026-05-12: REMOVED `_write_agent_terminal_status("chatgpt", "complete")` —
                        # chatgpt slot conflict with P2 (see other P1 branches).
            if _controls.is_stop():
                return

        skip_phases, agents_cfg, video_enabled, email_enabled, podcast_length, _ = reload_config()
        # ══════════════════════ PHASE 2: Deep Research ══════════════════════
        results = {}
        _user_skip_p2 = _controls.consume_phase_skip(2)
        # Flow B/C entry: when every P2 agent is disabled in agents_cfg,
        # the FE intent is "skip P2 entirely" (the user toggled all 3
        # agents off) — even though the FE doesn't write `2` into
        # skip_phases. Without this branch the elif below would fail_phase
        # with "No brief text available" because Flow B has no brief by
        # design (the user attached source docs that go straight to NLM).
        _all_agents_off = not any(agents_cfg.values())
        # 2026-05-12: also auto-skip P2 when P1 was skipped + no brief is
        # available + the user supplied Flow B sources. Without this, the
        # FE's "skip brief + pasted sources" UX hard-fails P2 just because
        # the user didn't ALSO toggle every individual P2 agent icon off.
        # Running P2 in this state is impossible (no brief to feed agents)
        # so we choose to skip rather than crash the pipeline.
        _flow_b_no_brief = (
            (1 in skip_phases) and (not brief_text) and bool(user_sources)
        )
        if 2 in skip_phases or _user_skip_p2 or _all_agents_off or _flow_b_no_brief:
            if _user_skip_p2:
                _reason = "user_skip"
            elif _all_agents_off:
                _reason = "All Phase 2 agents disabled"
            elif _flow_b_no_brief:
                _reason = "Flow B (P1 skipped + sources attached, no brief to feed agents)"
            else:
                _reason = "Disabled in pipeline config"
            log(f"Phase 2: SKIPPED ({_reason})")
            emit_event("phase_skipped", phase=2, reason=_reason)
        elif start_phase <= 2:
            if not brief_text:
                log("No brief text available — cannot run Phase 2", "ERROR")
                fail_phase(2, "No brief text available", "Phase 1 produced no brief; cannot run Phase 2.")
                return
            # Record the P2 source-doc decision once, before run_phase2 reads
            # the manifest: attach the user's sources only when P1 did NOT run
            # a live brief generation this session (skip-P1 / manual brief /
            # brief-from-file / resume-into-P2). A no-op when no sources were
            # attached; idempotent so a P1-ON run that resumes into P2 keeps
            # its original "don't re-attach" decision.
            _finalize_p2_source_decision(not _p1_ran_live)
            # Note: pre-2026-05-13 had an inline phase2-config-guard here that
            # re-read pipelineConfig.agents from Firestore. That logic is now
            # in reload_config() above (the [config-overlay] block) so every
            # phase entry — not just P2 — benefits. agents_cfg already
            # reflects the FS overlay by the time we reach this line.
            enabled_agents = [a for a, on in agents_cfg.items() if on]
            disabled_agents = [a for a, on in agents_cfg.items() if not on]
            log(f"[phase2] enabled_agents={enabled_agents} disabled_agents={disabled_agents}")
            # Pre-emit phase_start(2) BEFORE the verify gate. Mirrors the
            # P0→P1 eager-start pattern: without this, P1 ticked complete
            # and the FE sat on a blank gap while the per-agent verify gate
            # ran 4-15s of CUA verify_login calls (skip_init_verify path).
            # _p2_initial_enabled remembers the pre-gate roster so the
            # canonical re-emit below can detect whether the gate trimmed
            # the list and re-fire with the corrected agents= field. Also
            # writes "phase: 2, currentPhase: 2, status: ongoing" to root
            # doc so the listing tile + queue gate flip immediately.
            _p2_start_emitted = False
            _p2_initial_enabled = list(enabled_agents)
            if not _controls.is_stop():
                emit_event("phase_start", phase=2, agents=enabled_agents,
                           description="Parallel deep research across AI platforms")
                _update_firestore_research({"phase": 2, "currentPhase": 2, "status": "ongoing"})
                _p2_start_emitted = True

            # ── P2 verify gate (BE-2) ──
            # When init was skipped, re-verify each enabled agent's login +
            # Pro before P2 runs. Skip drops just that agent from
            # enabled_agents (P2 continues with the rest). All-skipped →
            # fail_phase since P2 can't run with zero agents.
            if _controls.skip_init_verify and not _controls.is_stop():
                _p2_dropped_at_gate: list[str] = []
                for _ag in list(enabled_agents):
                    _p2_gate = await _phase_verify_gate(2, _ag, browser, cua_client)
                    if _p2_gate == "stop":
                        emit_event("pipeline_stopped", phase=2, reason="user_stop_at_verify_gate")
                        return
                    if _p2_gate == "skipped":
                        _p2_dropped_at_gate.append(_ag)
                        log(f"Phase 2: {_ag} dropped at verify gate", "INFO")
                        emit_event("agent_skipped", phase=2, agent=_ag,
                                   reason="user_skip_at_verify_gate")
                if _p2_dropped_at_gate:
                    enabled_agents = [a for a in enabled_agents if a not in _p2_dropped_at_gate]
                if not enabled_agents:
                    log("Phase 2: all agents skipped at verify gate — aborting", "WARN")
                    fail_phase(2,
                               "All Phase 2 agents skipped at verify gate",
                               "All Phase 2 agents were skipped during phase-time "
                               "login verification. Phase 2 cannot run with no agents.")
                    emit_event("pipeline_stopped", phase=2,
                               reason="all_agents_skipped_at_verify_gate")
                    return
            # Canonical phase_start(2) re-emit — refreshes the agents= list
            # post-verify-gate (gate may have dropped agents into the
            # _p2_dropped_at_gate set). When the eager pre-emit above already
            # fired with the un-trimmed list, this second emit overwrites the
            # agents field cleanly via deterministic phaseId; if the eager
            # emit was gated out (stop pressed mid-config-reload then cleared),
            # this acts as the primary start.
            if not _p2_start_emitted:
                emit_event("phase_start", phase=2, agents=enabled_agents, description="Parallel deep research across AI platforms")
                _update_firestore_research({"phase": 2, "currentPhase": 2, "status": "ongoing"})
            elif enabled_agents != _p2_initial_enabled:
                # Verify gate dropped one or more agents — re-emit so the FE
                # tile reflects the trimmed enabled set.
                emit_event("phase_start", phase=2, agents=enabled_agents, description="Parallel deep research across AI platforms")
            for da in disabled_agents:
                # F2 (2026-05-06): emit with `reason` so the emit_event hook
                # at :5818-5833 persists agents[<da>].status="skipped" to the
                # root doc. Pre-fix, the for-loop omitted reason and the hook
                # gated persistence on truthy reason — leaving individually-
                # config-skipped agents (e.g. Claude off, others on) without
                # a runtime status. The FE could only fall back to deriving
                # from pipelineConfig.agents which (per F1) wasn't reliably
                # persisted either, so the listing tile rendered the skipped
                # agent as completed (green ✓). Dual-source defense-in-depth.
                emit_event("agent_skipped", phase=2, agent=da, reason="Disabled in pipeline config")
            _p2_start = time.time()
            # Active-time ceiling for Phase 2 — paused seconds don't count.
            # Per-phase login probe removed (2026-04-24) — Phase 0 is the
            # single login gate. See the matching note in the Phase 1
            # block above.
            fb2 = get_feedback(2)
            # Use BriefArtifact for full verified paste (never the "already_sent" heuristic)
            research_brief = (brief_artifact.text if brief_artifact else brief_text)
            # Append any extra context from user
            extra_ctx = _controls.pop_extra_context()
            if extra_ctx:
                research_brief += f'\n\nADDITIONAL CONTEXT: {extra_ctx}'
                log(f"Phase 2: Injecting extra user context ({len(extra_ctx)} chars)")
            if fb2:
                research_brief += f'\n\nUSER FEEDBACK (incorporate this into your research): {fb2}'
                log(f"Phase 2: Injecting user feedback: {fb2[:100]}")
                clear_feedback(2)
            # Restart loop: if mid-phase pause + input triggers a restart, merge
            # the new context into the brief and rerun the whole phase. Cap at
            # 3 restarts to prevent infinite loops if something goes sideways.
            results = {}
            _p2_user_skipped = False
            for _p2_attempt in range(3):
                _runtime.restart_requested = False
                while True:  # timeout-retry loop
                    try:
                        results = await _await_phase_with_active_deadline(
                            2, PHASE_2_MAX_MIN,
                            lambda: run_phase2(browser, cua_client, research_brief, verbose,
                                               enabled_agents=enabled_agents),
                            soft_warn_only=True,  # 2026-05-04: long DR runs are legitimate; warn but don't bail
                        )
                        break  # success
                    except _PhaseSoftDecision as _sd:
                        # User picked Retry/Skip on the soft-timeout warn.
                        # Wait is implicit — never reaches this except (the
                        # helper keeps polling on Wait until run_task either
                        # finishes naturally OR user picks Retry/Skip).
                        if _sd.decision == "retry":
                            emit_event("phase_restart", phase=2, reason="user_retry_after_soft_timeout")
                            results = {}
                            continue
                        if _sd.decision == "skip":
                            emit_event("phase_skipped", phase=2, reason="user_skip_after_soft_timeout")
                            _p2_user_skipped = True
                            results = {}
                            break
                        # Defensive — _PhaseSoftDecision only carries
                        # "retry"/"skip"; anything else means the helper
                        # contract drifted. Log + re-raise so it surfaces.
                        log(f"[P2] Unexpected _PhaseSoftDecision.decision={_sd.decision!r}", "ERROR")
                        raise
                    except asyncio.TimeoutError:
                        # Legacy hard-path. With soft_warn_only=True the
                        # helper raises _PhaseSoftDecision instead of
                        # TimeoutError, so this except block is normally
                        # unreachable for P2. Kept as a safety net in case
                        # something inside run_phase2 raises a bare
                        # TimeoutError that escapes the helper's wrap.
                        _decision = await _phase_timeout_decision(2, PHASE_2_MAX_MIN)
                        if _decision == "retry":
                            emit_event("phase_restart", phase=2, reason="user_retry_after_timeout")
                            results = {}
                            continue
                        if _decision == "skip":
                            emit_event("phase_skipped", phase=2, reason="user_skip_after_timeout")
                            _p2_user_skipped = True
                            results = {}
                            break
                        emit_event("pipeline_stopped", phase=2, reason=f"user_{_decision}_after_timeout")
                        return
                if _p2_user_skipped:
                    break  # exit outer for loop too
                if not _runtime.restart_requested:
                    break
                extra_ctx_retry = _controls.pop_extra_context()
                if not extra_ctx_retry:
                    log("[Phase 2] restart_requested but extra_context empty — continuing", "WARN")
                    break
                research_brief += f'\n\nADDITIONAL USER CONTEXT (restart #{_p2_attempt+1}):\n{extra_ctx_retry}'
                log(f"[Phase 2] Mid-phase restart with +{len(extra_ctx_retry)} chars of user input")
                emit_event("phase_restart", phase=2,
                           reason="mid_phase_input_on_resume",
                           chars=len(extra_ctx_retry), attempt=_p2_attempt+1)
            # Safety filter: ensure only enabled agents appear in results
            if enabled_agents:
                agent_name_map = {"chatgpt": "ChatGPT", "gemini": "Gemini", "claude": "Claude"}
                enabled_names = {agent_name_map.get(a, a) for a in enabled_agents}
                results = {n: r for n, r in results.items() if n in enabled_names}
            # ── 2026-05-10: Emit phase_complete:2 EARLY (before heavy persistence) ──
            # The MD writes, consolidated.md build, save_meta enrichment, and
            # P2→P3 handoff are BE-internal (FE doesn't gate on them). Emitting
            # phase_complete:2 FIRST:
            #   • Flips the P2 tile to green immediately on the FE.
            #   • Auto-cancels the per-tick narrator (emit_event hook at
            #     ~line 6225) so "Claude is refining..." stops echoing
            #     while the user waits for P3.
            #   • Writes the per-agent terminal status to the root doc so
            #     reopen / tile listing renders correctly post-reload.
            # The marker write also moves up (still gated on a clean finish)
            # so crash-recovery resume sees P2 as done before the heavy
            # persistence below has a chance to run. Resume from a crash in
            # the heavy persistence block is safe: the only thing that hasn't
            # finished is BE-internal disk/Firestore mirroring of agent MDs;
            # the next BE run rebuilds them from results on resume, or P3
            # rebuilds the handoff via its own safety-net call.
            # F5 (2026-05-13): three-way split (linked / errored / skipped)
            # so Firestore-sync-failed agents don't get phantom "Read X report"
            # links pointing at unreachable docs. Bucketing rules:
            #   - has text AND verified (md_saved) → linked
            #   - has text AND NOT verified         → errored (sync failed)
            #   - no text                           → skipped (extraction failed)
            # Linked is the only bucket that surfaces a link button on the FE.
            _p2_links: list[dict] = []
            _p2_errored_agents: list[str] = []
            _p2_skipped_agents: list[str] = []
            for name, r in results.items():
                in_app = r.get("_in_app_url") or ""
                if in_app and r.get("text") and r.get("verified"):
                    _p2_links.append({
                        "label": f"Read {name} report",
                        "url": in_app,
                        "verified": True,
                        "primary": True,
                    })
                elif r.get("text"):
                    # Extraction succeeded locally but Firestore sync failed —
                    # red badge already drives the FE state via the failed
                    # branch in extract_and_record_agent (agent_progress=failed
                    # + _write_agent_terminal_status=errored).
                    _p2_errored_agents.append(name)
                else:
                    _p2_skipped_agents.append(name)
            done_count = sum(1 for r in results.values() if r["status"] == "done")
            total_chars = sum(len(r.get("text", "")) for r in results.values())
            log(f"[Phase 2] Built {len(_p2_links)} in-app primary links, "
                f"{len(_p2_errored_agents)} errored (sync failed), "
                f"{len(_p2_skipped_agents)} skipped (no MD)")
            # ── C8: phase_complete invariant — every non-skipped non-errored ──
            # ── enabled agent should have an in-app primary link entry.       ──
            # ── Missing entries mean MD save itself failed mysteriously.      ──
            _linked_agents = set()
            for _l in _p2_links:
                _lbl = _l.get("label") or ""
                _parts = _lbl.split(" ")
                if len(_parts) >= 2 and _parts[0] == "Read":
                    _linked_agents.add(_parts[1])
            _expected_agents = (
                set(results.keys()) - set(_p2_skipped_agents) - set(_p2_errored_agents)
            )
            _missing_links = _expected_agents - _linked_agents
            if _missing_links:
                log(f"[Phase 2] phase_complete invariant breach: {sorted(_missing_links)} "
                    f"have text + verified=True but no in-app primary link. Emitting "
                    f"phase_complete anyway — these agents will render as unlinked. "
                    f"Investigate the in-app URL build path.", "ERROR")
            emit_event("phase_complete", phase=2, durationSec=int(time.time() - _p2_start), links=_p2_links,
                skippedAgents=_p2_skipped_agents,
                erroredAgents=_p2_errored_agents,
                summary=f"{done_count}/{len(results)} agents completed — {total_chars:,} chars — "
                        f"{len(_p2_links)} in-app primary links")
            _update_firestore_research({"phase": 2, "links.phase2": _p2_links})
            # Tile/Icon Consistency (2026-05-01): write the phase-complete
            # status to root doc so the listing-page tile + chat phase
            # icons + in-chat config icons stay green post-reload.
            _write_phase_terminal_status(2, "complete")
            # Per-agent terminal status. "done" → "complete"; other statuses
            # ("failed" / "skipped" / "paused") are written at their own emit
            # sites, don't overwrite here.
            for _ag_name, _ag_r in results.items():
                _ag_status = (_ag_r.get("status") or "").lower()
                _ag_key_lc = _ag_name.lower().replace(" ", "")
                if _ag_status in ("done", "complete", "completed", "done_partial"):
                    _write_agent_terminal_status(_ag_key_lc, "complete")
            # Phase-2 completion marker — only on a CLEAN finish (not stop/pause).
            # Tells detect_resume_phase that P2 actually finished, so resume
            # doesn't re-run P2 mid-flight.
            _p2_clean_finish = (not _controls.is_stop_or_pause())
            if _p2_clean_finish:
                try:
                    (queue_dir / "phase2_complete.marker").write_text(
                        json.dumps({
                            "completedAt": int(time.time() * 1000),
                            "doneCount": done_count,
                            "totalAgents": len(results),
                            "skippedAgents": list(_p2_skipped_agents),
                        }),
                        encoding="utf-8",
                    )
                except Exception as _mk_e:
                    log(f"[Phase 2] failed to write phase2_complete.marker: {_mk_e}", "WARN")
            else:
                log("[Phase 2] stop/pause detected — skipping phase2_complete.marker so resume re-runs P2", "INFO")

            # ── Heavy persistence (BE-internal, FE-invisible) ──
            # Per-agent MD disk writes + Firestore documents subcollection,
            # consolidated.md build, save_meta enrichment, P2→P3 handoff.
            # Runs AFTER phase_complete:2 so the user sees P2 turn green
            # immediately while this work completes invisibly.
            for name, r in results.items():
                if r["text"]:
                    fname = name.lower().replace(" ", "") + ".md"
                    _agent_md = f"# {name} Deep Research\n\n{r['text']}"
                    (queue_dir / "documents" / fname).write_text(_agent_md, encoding="utf-8")
                    # Sync to Firestore documents subcollection — doc_type is the
                    # agent key (chatgpt / gemini / claude), consistent with the
                    # frontend's Documents page expectation.
                    _agent_lc = name.lower().replace(" ", "")
                    save_document_to_firestore(_agent_lc, _agent_md, f"{name} Deep Research")
                    # Backstop findings extraction at the P2 finalize re-save
                    # site. The primary site is in extract_and_record_agent
                    # (~research.py:10988), but this resave path can run on
                    # resume / manual re-finalize when the snapshot ring may
                    # have been cleared. Skip if findings already exist.
                    try:
                        if _agent_lc not in (getattr(_runtime, "agent_findings", {}) or {}):
                            _src_urls = list(getattr(_runtime, "agent_progress_snapshots", {}).get(_agent_lc, {}).get("source_urls", []) or [])
                            if _src_urls:
                                _findings = _extract_findings(_agent_md, _src_urls)
                                if _findings:
                                    _runtime.agent_findings[_agent_lc] = _findings
                    except Exception:
                        pass
            # Generate consolidated report
            consolidated_parts = [f"# Consolidated Research Report: {topic}\n"]
            for name in ["ChatGPT", "Gemini", "Claude"]:
                r = results.get(name, {})
                if r.get("text"):
                    consolidated_parts.append(f"\n## {name} Research\n\n{r['text']}")
            if len(consolidated_parts) > 1:
                _consolidated_md = "\n".join(consolidated_parts)
                (queue_dir / "documents" / "consolidated.md").write_text(_consolidated_md, encoding="utf-8")
                save_document_to_firestore("consolidated", _consolidated_md, "Consolidated Report")
                log(f"Consolidated report: {len(_consolidated_md)} chars")
                # 2026-05-10: kick off the final post-research summary using
                # the consolidated findings (all 3 agent reports merged).
                # Overwrites the earlier brief-based stub with a "what the
                # research found" line — this is the version users see on
                # /researches after the pipeline finishes. Non-blocking
                # daemon thread; subsequent P3 (podcast) and FE P4/P5
                # (distribution) phases add no new research content, so
                # this is the final summary refresh.
                try:
                    _generate_research_summary_async(
                        topic,
                        brief_artifact.text if brief_artifact else "",
                        _consolidated_md,
                    )
                except Exception as _sum_e:
                    log(f"[summary] post-P2 dispatch failed: {_sum_e}", "WARN")
                # 2026-05-11: also refresh research.title now that we have
                # actual findings (not just the user's raw brief). The FE
                # /api/title call at pipeline start gave us a 4-8 word
                # startup title based ONLY on the user's input — often a
                # paragraph with "Goal:" / "Already sorted" sections that
                # produces a less-focused title. Post-P2 the agents have
                # produced concrete findings; the refresh reflects what
                # was actually researched.
                try:
                    _refresh_research_title_async(
                        topic,
                        brief_artifact.text if brief_artifact else "",
                        _consolidated_md,
                    )
                except Exception as _tit_e:
                    log(f"[title-refresh] post-P2 dispatch failed: {_tit_e}", "WARN")
            log(f"\nPHASE 2 COMPLETE: {done_count}/{len(results)} agents finished")
            for name, r in results.items():
                log(f"  {name:10s} status={r['status']:12s} text={len(r['text']):>6d} chars")
            save_checkpoint(queue_dir, 2, topic=topic, brief_url=brief_url)
            # Update delivery with live agent URLs
            agent_urls = {n: r.get("url", "") for n, r in results.items() if r.get("url")}
            if agent_urls:
                update_delivery(research_links=agent_urls)
            # Enrich meta with per-agent data from results + track events
            save_meta(queue_dir, topic, 2)
            meta_path = queue_dir / "meta.json"
            if meta_path.exists():
                meta = json.loads(meta_path.read_text(encoding="utf-8"))
                agents = meta.get("agents", {})
                for name, r in results.items():
                    key = name.lower().replace(" ", "")
                    if key not in agents:
                        agents[key] = {}
                    agents[key]["completionTimeSec"] = r.get("elapsed_sec", 0)
                # 2026-04-29: events.jsonl scrape merge removed — events.jsonl
                # is no longer written to disk (Firestore pipeline_events is
                # the single transport). The agents map is already kept in
                # sync via per-event `_update_firestore_research` calls
                # during P2; the disk-merge here was a redundant backstop.
                meta["agents"] = agents
                meta_path.write_text(json.dumps(meta, indent=2), encoding="utf-8")
            # ── 2026-04-25: Markdown-as-primary phase_complete (P1 mirror) ──
            # extract_and_record_agent already emitted link_extracted with the
            # in-app /documents primary the moment each agent's MD landed.
            # Share-link extraction is now fully scoped to P2 (DOM tier +
            # vision-shadow-wrapped CUA fallback inside extract_and_record_agent
            # and extract_share_link_chatgpt). P3 just consumes _runtime.p2_*
            # state and goes straight to NotebookLM.
            # Build the P2→P3 handoff now so P3 starts clean. Idempotent —
            # safe to call again as a fallback at start of P3 if needed.
            try:
                _build_phase2_to_phase3_handoff(results, queue_dir)
            except Exception as _hoe:
                log(f"[Phase 2→3 handoff] build failed (P3 will rebuild on entry): {_hoe}", "WARN")
        else:
            log("Phase 2: Loading existing research files")

        if _controls.is_stop_or_pause():
            if _controls.is_stop():
                log("STOP requested after Phase 2 — collecting partial results", "WARN")
                doc_dir = queue_dir / "documents"
                partial_agents = []
                for name in ["ChatGPT", "Gemini", "Claude"]:
                    fname = name.lower().replace(" ", "") + ".md"
                    if (doc_dir / fname).exists() and (doc_dir / fname).stat().st_size > 100:
                        partial_agents.append(name)
                log(f"  Partial results saved: {partial_agents or 'none'}")
                save_meta(queue_dir, topic, 2, status="stopped")
                update_delivery(status="stopped")
                emit_event("pipeline_stopped", phase=2, reason="stop",
                           partial_agents=partial_agents)
                _update_firestore_research({"status": "stopped", "phase": 2})
                return
            else:
                log("PAUSE requested after Phase 2 — closing browser, awaiting resume", "WARN")
                save_meta(queue_dir, topic, 2, status="paused")
                update_delivery(status="paused")
                _update_firestore_research({"status": "paused", "phase": 2})
                _runtime.original_inputs = {"topic": topic, "brief": brief_text}
                stopped = await pause_and_close_browser(browser, queue_dir, phase=2,
                                                        extra_kwargs={"topic": topic, "brief_url": brief_url})
                if stopped:
                    save_meta(queue_dir, topic, 2, status="stopped")
                    emit_event("pipeline_stopped", phase=2, reason="stop_after_pause")
                    _update_firestore_research({"status": "stopped", "phase": 2})
                    return
                # Relaunch — agents in Phase 2 are already complete at this boundary
                browser = Browser(_profile_dir(WORKER_ID), headless=False)
                await browser.start()
                _active_browser_ref = browser  # re-point stop handler at fresh session
                emit_event("pipeline_resumed", phase=2)
                _update_firestore_research({"status": "ongoing"})
                # Restart-phase logic: if user supplied input while paused, re-run Phase 2 with combined input
                if _controls.peek_extra_context():
                    resume_input = _controls.pop_extra_context()
                    log(f"Phase 2: Resume-with-input — rerunning 3 agents with {len(resume_input)} extra chars")
                    emit_event("phase_restart", phase=2, reason="user_input_on_resume", chars=len(resume_input))
                    combined_brief = (brief_artifact.text if brief_artifact else brief_text) + \
                                      "\n\nADDITIONAL USER CONTEXT:\n" + resume_input
                    enabled_agents_now = [a for a, on in agents_cfg.items() if on]
                    results = await run_phase2(
                        browser, cua_client, combined_brief, verbose,
                        enabled_agents=enabled_agents_now)
                    # Rewrite documents
                    for name, r in results.items():
                        if r.get("text"):
                            fname = name.lower().replace(" ", "") + ".md"
                            _regen_md = f"# {name} Deep Research (regenerated)\n\n{r['text']}"
                            (queue_dir / "documents" / fname).write_text(_regen_md, encoding="utf-8")
                            save_document_to_firestore(name.lower().replace(" ", ""), _regen_md, f"{name} Deep Research")
                    # Build links from round-robin results — prefer in-app primary
                    # (always present when MD landed) over conversation URL.
                    _p2_links = []
                    for n, r in results.items():
                        in_app = r.get("_in_app_url") or ""
                        if in_app and r.get("text"):
                            _p2_links.append({"label": f"Read {n} report", "url": in_app,
                                              "verified": True, "primary": True})
                    emit_event("phase_complete", phase=2, links=_p2_links,
                               summary=f"Phase 2 regenerated with user input")

        # ── Check we have research output to continue ──
        # ARCHITECTURE 2026-04-18 (never-die): no retries_left cap. If
        # Phase 2 produced nothing, surface a phase alert and wait for
        # the user to choose Retry / Skip / Stop. Retry re-runs Phase 2;
        # Skip advances past Phase 3 entirely (no notebook/audio); Stop
        # ends the run. Previously we capped at 1 retry and then
        # silently marked the run failed — that broke the contract.
        doc_dir = queue_dir / "documents"
        # Source scan: include user-attached PDFs/DOCX/TXT alongside agent
        # MDs so Flow B (P1+P2 skipped, sources-only) doesn't trip the
        # "no documents" gate. brief.md AND consolidated.md are excluded —
        # brief.md is the P1 input (not a NotebookLM source) and
        # consolidated.md is a P2 byproduct of claude+gemini concatenation
        # used for the Documents page only. 2026-05-11 fix: on a
        # checkpoint resume after PC death, `results` is empty and the
        # synthesis loop at ~21117 used to hydrate results from this scan;
        # consolidated.md slipped in as a fourth "agent" and the rebuilt
        # NotebookLM notebook included it alongside chatgpt/claude/gemini.
        _P3_DERIVED_STEMS = {"brief", "consolidated"}
        def _scan_p3_docs():
            if not doc_dir.exists():
                return []
            return [f for f in doc_dir.iterdir()
                    if f.is_file()
                    and f.suffix.lower() in (".md", ".txt", ".pdf", ".docx")
                    and f.stat().st_size > 100
                    and f.stem.lower() not in _P3_DERIVED_STEMS]
        md_files = _scan_p3_docs()
        has_results = md_files or any(r.get("text") for r in results.values())
        # Flow B context detection: P2 was *deliberately* skipped (config or
        # all-agents-off via the FE), so the user's intent was P3-as-entry
        # with attached source files. The legacy gate ("Phase 2 produced no
        # documents — Retry Phase 2") is wrong for this path: P2 wasn't
        # supposed to produce anything, and Retry would just re-run P2 with
        # the same all-agents-off config and loop forever. Surface a Flow-B-
        # specific error and don't offer Retry P2 in that case.
        _p2_was_skipped = (2 in skip_phases) or (not any(agents_cfg.values()))
        _flow_b_intent = _p2_was_skipped and (1 in skip_phases)
        # Flow C bypass: P3 already in skip_phases means the user's intent
        # was P5-as-entry (or P4-as-entry) with user-pasted URLs hydrating
        # delivery.json. The P3 entry block below detects 3 in skip_phases
        # and runs the user_links hydration flow — no documents required.
        # Skipping the gate here lets Flow C runs proceed without the user
        # having to click "Skip P3" on a misleading "Phase 2 produced no
        # documents" alert.
        _p3_already_skipped = (3 in skip_phases)
        _p3gate_skipped = False
        _p3gate_attempt = 0
        while not has_results and not _p3_already_skipped:
            _p3gate_attempt += 1
            log(f"No research output (attempt {_p3gate_attempt}) — awaiting user decision "
                f"(flow_b_intent={_flow_b_intent}, p2_was_skipped={_p2_was_skipped})", "WARN")
            if _flow_b_intent:
                # Flow B: P1+P2 skipped, user expected to bring source docs.
                # Either none were attached, or all downloads failed (the
                # download block at run_pipeline entry already would have
                # fail_phase'd that case explicitly). Reaching here means
                # zero usable sources landed on disk. No Retry P2 action —
                # there's nothing to retry. Offer Skip P3 (run P5 with
                # whatever the pipeline can salvage) or stop.
                fail_phase(
                    phase=3,
                    error="No source documents found for NotebookLM",
                    reason=("Phase 1 + Phase 2 are skipped, so the pipeline "
                            "expects you to attach source files (.md/.txt/"
                            ".pdf/.docx) for NotebookLM to ingest. None of "
                            "your attachments landed on disk — they may "
                            "have failed to upload, or the run was started "
                            "without any. Skip Phase 3 to continue with "
                            "whatever artifacts the later phases can "
                            "produce, or stop and re-attach."),
                    actions=[
                        {"id": "skip", "label": "Skip Phase 3", "style": "primary",
                         "command": {"action": "skip_phase", "phase": 3}},
                    ],
                )
            else:
                fail_phase(
                    phase=3,
                    error="Phase 2 produced no documents — can't continue to NotebookLM.",
                    reason="All three agents timed out, errored, or returned empty. Retry re-runs Phase 2 with the same brief; Skip moves past Phase 3 (no notebook, no audio).",
                    actions=[
                        {"id": "retry", "label": "Retry Phase 2", "style": "primary",
                         "command": {"action": "retry_phase", "phase": 3}},
                        {"id": "skip", "label": "Skip Phase 3", "style": "default",
                         "command": {"action": "skip_phase", "phase": 3}},
                    ],
                )
            gate_decision = await _controls.await_phase_decision(3)
            log(f"Phase 3 gate decision: {gate_decision}")
            if gate_decision == "retry" and not _flow_b_intent:
                try:
                    emit_event("phase_restart", phase=2, reason="user_retry_p3_gate", attempt=_p3gate_attempt + 1)
                except Exception:
                    pass
                _retry_brief_text = (brief_artifact.text if brief_artifact else brief_text) or ""
                _retry_enabled = [a for a, on in agents_cfg.items() if on]
                results = await run_phase2(
                    browser, cua_client, _retry_brief_text, verbose,
                    enabled_agents=_retry_enabled)
                # Rewrite documents from the fresh results
                for name, r in results.items():
                    if r.get("text"):
                        fname = name.lower().replace(" ", "") + ".md"
                        _regen_md = f"# {name} Deep Research (retry)\n\n{r['text']}"
                        (queue_dir / "documents" / fname).write_text(_regen_md, encoding="utf-8")
                        save_document_to_firestore(name.lower().replace(" ", ""), _regen_md, f"{name} Deep Research")
                # Re-check gate using the same source scan helper.
                md_files = _scan_p3_docs()
                has_results = md_files or any(r.get("text") for r in results.values())
                continue
            if gate_decision == "skip":
                log("Phase 3 gate: user skipped — continuing past Phase 3 with no documents", "INFO")
                emit_event("phase_skipped", phase=3, reason="user_skip_no_docs")
                # await_phase_decision(3) already consumed the skip flag, so
                # re-add it to the set. The Phase 3 entry block below reads
                # consume_phase_skip(3) and will short-circuit past the upload
                # step when the flag is present.
                _controls.skipped_phases.add(3)
                _p3gate_skipped = True
                break
            # stop / timeout → end the run
            log(f"Phase 3 gate: user {gate_decision} — terminating pipeline", "INFO")
            emit_event("pipeline_stopped", phase=3, reason=f"user_{gate_decision}_no_docs")
            return

        # Post-Phase-2: add_context is no longer accepted (guarded at command
        # listener). Any residual extra_context from a pre-P2 race is dropped
        # with a warning — no NotebookLM addendum, no prompt, no cascade.
        if _controls.peek_extra_context():
            dropped = _controls.pop_extra_context()
            log(f"Dropping {len(dropped)} chars of residual extra_context post-P2 "
                f"(add_context disabled for Phase 3+)", "WARN")

        skip_phases, agents_cfg, video_enabled, email_enabled, podcast_length, _ = reload_config()
        # ── 2026-05-10: Eager phase_start:3 BEFORE the verify gate ──
        # Pre-fix, the verify gate (when skip_init_verify=True) ran a 5-15s
        # CUA call BEFORE phase_start:3 was emitted — FE saw P2 done + blank
        # gap. Now: flip P3 to "running" first; the gate runs visibly under
        # the P3 tile (the gate's own agent_progress notebooklm status emits
        # at line ~6529 light up the dropdown). If the gate or downstream
        # skip-check decides skip, the existing phase_skipped:3 emit at
        # line ~20875 cleanly flips running → skipped via the FE's
        # deterministic phaseId. The canonical phase_start:3 emit later in
        # the elif at ~line 20939 is idempotent (same phaseId, just refreshes
        # description).
        if (start_phase <= 3
                and 3 not in skip_phases
                and 3 not in _controls.skipped_phases
                and not _controls.is_stop()):
            emit_event("phase_start", phase=3, description="Preparing NotebookLM…", agents=["notebooklm"])
            _update_firestore_research({"phase": 3, "currentPhase": 3, "status": "ongoing"})
        # ══════════════════════ PHASE 3 verify gate (BE-2) ══════════════════════
        # When init was skipped, re-verify NotebookLM login before P3 runs.
        # Skip cascades to P4 (no YouTube without podcast — same rule as the
        # skip_phase command handler at ~line 2833). NLM has no Pro/Free
        # split (not in _PRO_TIER_PLATFORMS), so only login is checked.
        if (start_phase <= 3 and 3 not in skip_phases
                and 3 not in _controls.skipped_phases
                and _controls.skip_init_verify
                and not _controls.is_stop()):
            _p3_gate = await _phase_verify_gate(3, "notebooklm", browser, cua_client)
            if _p3_gate == "stop":
                emit_event("pipeline_stopped", phase=3, reason="user_stop_at_verify_gate")
                return
            if _p3_gate == "skipped":
                log("Phase 3: NLM verify gate skipped → cascade-skipping P4 (no YouTube without podcast)", "INFO")
                _controls.skipped_phases.add(3)
                _controls.skipped_phases.add(4)
        # ══════════════════════ PHASE 3: NotebookLM Processing (upload + audio) ══════════════════════
        audio_path = None
        _user_skip_p3 = _controls.consume_phase_skip(3)
        if 3 in skip_phases or _user_skip_p3:
            _reason = "user_skip" if _user_skip_p3 else "Disabled in pipeline config"
            log(f"Phase 3: SKIPPED ({_reason})")
            emit_event("phase_skipped", phase=3, reason=_reason)
            # Flow C: when P3 is skipped AND the user pasted source URLs at
            # start time, hydrate the P5-bound locals from those URLs so the
            # final Doc + email body have something to render. Every pasted
            # link is appended to a Firestore `userSources` array
            # (collision-safe, validation-skipping, label-preserving) so the
            # FE-P5 Doc composer sees the full list — no link is ever
            # dropped due to key overwrite or strict validate_link rejection.
            #
            # First-of-kind also writes to the keyed `links` aggregate via
            # emit_validated_link (notebook / youtube / audio) so existing
            # FE consumers that key on those slots (P3/P4 dropdowns) keep
            # working uniformly with non-Flow-C runs.
            if user_links:
                _flow_c_count = 0
                for _link in user_links:
                    _kind = (_link.get("kind") or "").lower()
                    _url = (_link.get("url") or "").strip()
                    _label = (_link.get("label") or "Source").strip() or "Source"
                    if not _url:
                        continue
                    # Always append to userSources — guarantees the Doc
                    # renders every pasted link with the user's label.
                    append_user_source_in_firestore(_kind, _url, _label, phase=3)
                    # Populate keyed-aggregate slots for first-of-kind so
                    # phase dropdowns + downstream pipeline consumers find
                    # them at the canonical paths.
                    if _kind == "brief" and not brief_url:
                        # User-pasted brief link (e.g. "ChatGPT Brief:" label
                        # in front of a chatgpt.com/share URL). Routes to
                        # the canonical Research Brief slot so FE-P5 emits
                        # body.brief_url and the Doc renders it under the
                        # standard "Research Brief" HEADING_2 section,
                        # parallel to Flow A/B's pipeline-generated brief.
                        brief_url = _url
                        emit_validated_link(2, "brief", _url, _label or "Research Brief")
                    elif _kind == "notebook" and not notebook_url:
                        notebook_url = _url
                        emit_validated_link(3, "notebooklm", _url, _label or "NotebookLM Notebook")
                    elif _kind == "youtube" and not youtube_url:
                        youtube_url = _url
                        emit_validated_link(4, "youtube", _url, _label or "YouTube Video")
                    elif _kind == "audio" and not audio_overview_url:
                        audio_overview_url = _url
                        emit_validated_link(3, "notebooklm", _url, _label or "Audio Overview", link_kind="audio")
                    elif _kind in ("doc", "agent", "other"):
                        # In-memory map keeps existing label-suffix collision
                        # avoidance for delivery.json mirror + downstream uses.
                        # Firestore truth lives in userSources (above).
                        _key = _label
                        _i = 2
                        while _key in links:
                            _key = f"{_label} ({_i})"
                            _i += 1
                        links[_key] = _url
                    _flow_c_count += 1
                log(f"Flow C hydration: {_flow_c_count} link(s) → notebook={'set' if notebook_url else '∅'} "
                    f"youtube={'set' if youtube_url else '∅'} audio={'set' if audio_overview_url else '∅'} "
                    f"sources={len(links)}")
                # Mirror to delivery.json so P5 reads them on resume + the FE
                # tile shows them as the run progresses.
                update_delivery(notebook_url=notebook_url, youtube_url=youtube_url,
                                audio_url=audio_overview_url, research_links=dict(links))
        elif start_phase <= 3:
            emit_event("phase_start", phase=3, description="Uploading to NotebookLM + generating audio overview", agents=["notebooklm"])
            _update_firestore_research({"phase": 3, "currentPhase": 3, "status": "ongoing"})
            _p3_start = time.time()
            # Phase 3 has two sub-steps with separate budgets:
            #   • upload (3a): PHASE_3_UPLOAD_MAX_MIN=15 — hard-cap, bounded utility op
            #   • audio  (3b): PHASE_3_AUDIO_MAX_MIN=90 — soft-warn (advisory),
            #     long-podcast generation is legitimate.
            # Paused seconds don't count toward either active-time ceiling.
            # Per-phase login probe removed (2026-04-24) — see Phase 1 note.
            if not results:
                # 2026-05-11: only synthesize results for the three known
                # agent stems. Pre-fix, the dict.get(stem, stem) fallback
                # let an unrecognized stem (e.g. consolidated.md after a
                # checkpoint resume) become a synthetic "consolidated"
                # agent that flowed back through the P2→P3 handoff and
                # was uploaded to NotebookLM as a fourth source. The
                # _scan_p3_docs filter above already excludes brief/
                # consolidated stems, but this allowlist is the
                # belt-and-suspenders guard for anything else that ends
                # up in documents/.
                _AGENT_NAME_BY_STEM = {"chatgpt": "ChatGPT", "gemini": "Gemini", "claude": "Claude"}
                for md_file in md_files:
                    stem = md_file.stem.lower()
                    name = _AGENT_NAME_BY_STEM.get(stem)
                    if not name:
                        continue
                    results[name] = {"status": "done", "text": md_file.read_text(encoding="utf-8"),
                                     "url": "", "page": None}
            # Sub-step 3a: Upload to NotebookLM
            _p3a_user_skipped = False
            # 2026-05-07 (Bug A1): narrow-retry budget for the upload step.
            # When run_phase3_upload silently completes with a bogus URL
            # (e.g. CUA returned 'blocked: Google Sign-in' because the user
            # got logged out), looping just extract_notebooklm_url against
            # that broken page never recovers. The link-extract decision
            # branch below re-runs run_phase3_upload (up to MAX_REATTEMPTS
            # additional times) when the URL clearly isn't on the NotebookLM
            # domain. Total upload attempts = 1 + MAX_REATTEMPTS.
            _p3_upload_attempt = 0
            _P3_UPLOAD_MAX_REATTEMPTS = 1
            while True:  # timeout-retry loop
                try:
                    p3 = await _await_phase_with_active_deadline(
                        3, PHASE_3_UPLOAD_MAX_MIN,
                        lambda: run_phase3_upload(browser, cua_client, results, topic, queue_dir, verbose),
                    )
                    break
                except asyncio.TimeoutError:
                    _decision = await _phase_timeout_decision(3, PHASE_3_UPLOAD_MAX_MIN, agent="notebooklm")
                    if _decision == "retry":
                        emit_event("phase_restart", phase=3, reason="user_retry_after_timeout")
                        continue
                    if _decision == "skip":
                        emit_event("phase_skipped", phase=3, reason="user_skip_after_timeout")
                        _p3a_user_skipped = True
                        p3 = {"links": {}, "notebook_url": ""}
                        break
                    emit_event("pipeline_stopped", phase=3, reason=f"user_{_decision}_after_timeout")
                    return
            links = p3.get("links", {})
            notebook_url = p3.get("notebook_url", "")
            # B1: Link-first — retry notebook URL extraction on validation failure.
            # ARCHITECTURE 2026-04-18 (never-die): wrap the retry in a decision
            # loop so repeated extract failures surface as a phase alert with
            # Retry / Skip instead of silently terminating.
            #
            # 2026-05-07: when the user picked Skip at the upload-step timeout
            # decision, notebook_url is empty by design — skip the entire
            # link-extract block instead of falling through into a retry loop
            # that would re-prompt for a notebook that doesn't exist.
            if _p3a_user_skipped:
                pass  # user skipped upload — nothing to extract
            elif not (notebook_url and validate_link("notebooklm", notebook_url)):
                log("[NotebookLM] Notebook URL missing/invalid — retrying via extractor (3×)", "WARN")
                while True:
                    nb_res = await extract_with_retry(
                        phase=3, agent="notebooklm", browser=browser, cua_client=cua_client,
                        extractor_fn=extract_notebooklm_url,
                        label="NotebookLM Notebook", verbose=verbose,
                    )
                    # 2026-04-25 (Commit 9 follow-up): `verified` now requires
                    # BOTH a NotebookLM URL shape AND a DOM-confirmed public
                    # share. The DOM-verify can fail for benign reasons
                    # (Material dropdown without aria-selected, transient
                    # eval error, dialog already closed), so gating the
                    # recovery loop on `verified` alone would starve fine
                    # notebooks. Accept URL-shape-only here — the link still
                    # works for the user even if not DOM-confirmed public.
                    # If the link turns out to be private, downstream Doc/email
                    # consumers will surface the auth error to the recipient,
                    # which is the only context where it actually matters.
                    if nb_res.verified or (nb_res.url and "notebooklm.google.com/notebook" in nb_res.url):
                        notebook_url = nb_res.url
                        if not nb_res.verified:
                            log("[NotebookLM] URL-shape OK but public-share NOT DOM-verified — "
                                "downstream link may be private", "WARN")
                        break
                    log(f"Phase 3: no verified NotebookLM URL after retries — awaiting user decision ({nb_res.error})", "ERROR")
                    fail_phase(
                        phase=3,
                        error=f"Could not extract verified NotebookLM URL: {nb_res.error}",
                        reason="NotebookLM extraction couldn't confirm a valid notebook URL. Retry tries again; Skip moves past Phase 3 without a notebook link.",
                        agent="notebooklm",
                    )
                    decision = await _controls.await_phase_decision(3)
                    if decision == "retry":
                        # 2026-05-07 (Bug A1): if the URL we have isn't even on
                        # the NotebookLM domain (sign-in redirect, blank, etc.),
                        # the upload itself never landed — re-running just the
                        # extractor against the same broken page recovers
                        # nothing. Re-run run_phase3_upload from scratch. The
                        # domain-substring gate is more lenient than
                        # validate_link's "/notebook/" check, so a partial-
                        # success URL on notebooklm.google.com (e.g. /home or
                        # a non-canonical path) bypasses re-upload and falls
                        # through to extractor-only retry — bounding the
                        # re-upload to genuine "upload-never-happened" cases.
                        # run_phase3_upload opens a fresh tab via
                        # browser.new_tab(...) on every entry, so no manual
                        # cleanup is needed between attempts.
                        _url_looks_like_notebook = bool(
                            notebook_url and "notebooklm.google.com" in notebook_url
                        )
                        if (not _url_looks_like_notebook
                                and _p3_upload_attempt < _P3_UPLOAD_MAX_REATTEMPTS):
                            _p3_upload_attempt += 1
                            log(f"Phase 3 retry: URL '{notebook_url}' not on NotebookLM domain — "
                                f"re-running run_phase3_upload "
                                f"({_p3_upload_attempt}/{_P3_UPLOAD_MAX_REATTEMPTS})", "INFO")
                            emit_event("phase_restart", phase=3, reason="user_retry_re_upload",
                                       attempt=_p3_upload_attempt)
                            try:
                                p3 = await _await_phase_with_active_deadline(
                                    3, PHASE_3_UPLOAD_MAX_MIN,
                                    lambda: run_phase3_upload(browser, cua_client, results, topic, queue_dir, verbose),
                                )
                                links = p3.get("links", {})
                                notebook_url = p3.get("notebook_url", "")
                            except asyncio.TimeoutError:
                                # Hard timeout on the re-upload — leave URLs
                                # as-is and fall through to extractor retry.
                                # User can hit Retry again, exhaust the
                                # re-upload budget, and end up just looping
                                # the extractor (no infinite re-upload).
                                log("Phase 3 re-upload hit hard timeout — falling through to extractor retry", "WARN")
                            continue
                        log("Phase 3 link extraction: user requested retry", "INFO")
                        emit_event("phase_restart", phase=3, reason="user_retry_link_extract", attempt=0)
                        continue
                    if decision == "skip":
                        log("Phase 3 link extraction: user skipped — proceeding without notebook URL", "INFO")
                        notebook_url = ""
                        break
                    log(f"Phase 3 link extraction: user {decision} — terminating pipeline", "INFO")
                    emit_event("pipeline_stopped", phase=3, reason=f"user_{decision}_link_extract")
                    return
            else:
                emit_validated_link(3, "notebooklm", notebook_url, "NotebookLM Notebook")
            (queue_dir / "links.json").write_text(json.dumps(links, indent=2), encoding="utf-8")
            save_checkpoint(queue_dir, 3, topic=topic, brief_url=brief_url,
                            notebook_url=notebook_url)
            update_delivery(research_links=links, notebook_url=notebook_url)
            # Sub-step 3b: Generate audio overview
            audio_overview_url = ""
            _p3_audio_user_skipped = False
            if notebook_url:
                while True:  # timeout-retry loop
                    try:
                        _p3_audio = await _await_phase_with_active_deadline(
                            3, PHASE_3_AUDIO_MAX_MIN,
                            lambda: run_phase3_audio(browser, cua_client, notebook_url, queue_dir, verbose, podcast_length=podcast_length),
                            soft_warn_only=True,  # 2026-05-04: NLM audio gen legitimately runs 30-45m on long podcasts; warn but don't bail
                        )
                        break
                    except _PhaseSoftDecision as _sd:
                        # User picked Retry/Skip on the soft-timeout warn.
                        # Wait is implicit — never reaches this except (the
                        # helper keeps polling on Wait until run_task either
                        # finishes naturally OR user picks Retry/Skip).
                        if _sd.decision == "retry":
                            emit_event("phase_restart", phase=3, reason="user_retry_after_audio_soft_timeout")
                            continue
                        if _sd.decision == "skip":
                            emit_event("phase_skipped", phase=3, reason="user_skip_after_audio_soft_timeout")
                            _p3_audio = {"audio_path": None, "audio_overview_url": ""}
                            _p3_audio_user_skipped = True
                            _controls.skipped_phases.add(4)
                            break
                        log(f"[P3-audio] Unexpected _PhaseSoftDecision.decision={_sd.decision!r}", "ERROR")
                        raise
                    except asyncio.TimeoutError:
                        # Legacy hard-path safety net — with soft_warn_only=True
                        # the helper raises _PhaseSoftDecision instead of
                        # TimeoutError, so this branch is normally unreachable.
                        # Kept as a guard in case run_phase3_audio raises a bare
                        # TimeoutError that escapes the helper's wrap.
                        _decision = await _phase_timeout_decision(3, PHASE_3_AUDIO_MAX_MIN, agent="notebooklm")
                        if _decision == "retry":
                            emit_event("phase_restart", phase=3, reason="user_retry_audio_timeout")
                            continue
                        if _decision == "skip":
                            emit_event("phase_skipped", phase=3, reason="user_skip_audio_timeout")
                            _p3_audio = {"audio_path": None, "audio_overview_url": ""}
                            _p3_audio_user_skipped = True
                            _controls.skipped_phases.add(4)
                            break
                        emit_event("pipeline_stopped", phase=3, reason=f"user_{_decision}_audio_timeout")
                        return
                audio_path = _p3_audio.get("audio_path")
                audio_overview_url = _p3_audio.get("audio_overview_url", "")
                save_checkpoint(queue_dir, 3, topic=topic, brief_url=brief_url,
                                notebook_url=notebook_url,
                                audio_path=str(audio_path) if audio_path else "",
                                audio_overview_url=audio_overview_url)
                # Use audio overview URL if available, else notebook URL for audio reference
                _audio_link = audio_overview_url or notebook_url
                update_delivery(audio_url=_audio_link)
                if audio_overview_url:
                    emit_validated_link(3, "notebooklm", audio_overview_url, "Audio Overview", link_kind="audio")
            # B2: save_meta runs ffprobe per podcast file inline (~5s/file).
            # 2026-05-10: spawn on a daemon thread (NOT awaited) so the
            # ffprobe doesn't gate phase_complete:3 emission. FE-P4 was
            # waiting on this and the P3→P4 transition looked stuck for
            # ~5s. save_meta only enriches meta.json with audio duration;
            # no downstream phase reads from meta.json synchronously.
            try:
                _threading.Thread(
                    target=save_meta,
                    args=(queue_dir, topic, 3),
                    name="p3-savemeta-ffprobe",
                    daemon=True,
                ).start()
            except Exception as _smt_e:
                log(f"[Phase 3] failed to dispatch save_meta thread: {_smt_e}", "WARN")
            # Build Phase 3 links — include both notebook and audio overview
            # Only include links that pass validation (no fake/placeholder URLs)
            _p3_links = []
            if notebook_url and validate_link("notebooklm", notebook_url):
                _p3_links.append({"label": "NotebookLM Notebook", "url": notebook_url, "verified": True})
            # NLM emits the same /notebook/{id} URL for both notebook and
            # audio share dialogs by design. Keep both rows so the FE can
            # render the Audio Overview as a Play button + external
            # Open-in-NotebookLM affordance (Option 3 hybrid). Dedup by
            # label+url at FE allLinks lets the second row survive.
            if audio_overview_url and validate_link("notebooklm", audio_overview_url):
                _p3_links.append({"label": "Audio Overview", "url": audio_overview_url, "verified": True})
            # Hard rule (user_locked 2026-05-02): P3 marks complete only when
            # both notebook AND audio are obtained. Surface a [Retry, Skip]
            # alert when audio is missing rather than emitting phase_complete
            # with stale-audio risk and tripping P4's no-audio fail_phase.
            # Fix B (2026-05-27): bounded AUTO-retry for missing audio,
            # replacing the old UNBOUNDED await_phase_decision(3). In
            # autonomous/serve mode no human clicks Retry, so that wait
            # dead-hung the run for hours until the outer watchdog killed it
            # (the verified deadlock). Instead, auto-retry up to 3× at 5-min
            # intervals, reusing THIS run's already-generated card via
            # prefer_existing_audio=True (Fix A re-anchors each download to
            # the run's own notebook). Only after all 3 fail do we fall back
            # to notebook-link-only — a non-blocking outcome.
            # INVARIANT: no path here waits unboundedly for a human.
            _AUDIO_MAX_AUTO_RETRIES = 3
            _AUDIO_RETRY_INTERVAL_SEC = 5 * 60
            _audio_auto_retries = 0
            while bool(notebook_url) and not audio_path and not _p3_audio_user_skipped:
                if _controls.is_stop():
                    log("Phase 3: stop requested during no-audio handling — aborting", "INFO")
                    return
                if _audio_auto_retries >= _AUDIO_MAX_AUTO_RETRIES:
                    # Exhausted auto-retries → graceful, non-blocking fallback:
                    # continue with notebook-link-only. P5 still delivers the
                    # notebook link + report; P4 (YouTube) cascades off. Inform
                    # the user with a dismissible amber warning (NOT a red error
                    # — the run succeeded apart from the podcast file).
                    log(f"Phase 3: audio still missing after {_AUDIO_MAX_AUTO_RETRIES} auto-retries — continuing with notebook link only", "WARN")
                    try:
                        emit_event(
                            "pipeline_warning", phase=3, agent="notebooklm",
                            message="Audio Overview couldn't be captured after 3 retries — continuing with the notebook link only.",
                            details=("NotebookLM produced the podcast but the audio file couldn't be downloaded and streamed "
                                     "after 3 attempts. The notebook link is still delivered in your report and email; the "
                                     "YouTube upload step is skipped. Re-run this research if you want to retry the audio."),
                            alertType="warn", dismissible=True,
                            alert_id=f"phase3_audio_giveup_{int(time.time())}",
                        )
                    except Exception:
                        pass
                    emit_event("phase_skipped", phase=3, reason="audio_unavailable_after_auto_retries")
                    _p3_audio_user_skipped = True
                    _controls.skipped_phases.add(4)
                    break

                _audio_auto_retries += 1
                _wait_min = _AUDIO_RETRY_INTERVAL_SEC // 60
                log(f"Phase 3: audio file missing — auto-retry {_audio_auto_retries}/{_AUDIO_MAX_AUTO_RETRIES} in {_wait_min} min", "WARN")
                emit_event("agent_progress", phase=3, agent="notebooklm", status="downloading",
                           progress=f"Audio not captured yet — retrying ({_audio_auto_retries}/{_AUDIO_MAX_AUTO_RETRIES}) in {_wait_min} min…")

                # 5-min interval wait — interruptible so Stop/Pause are honored
                # (the wait must never become an unbounded human hang).
                _interrupt = await _controls.interruptible_sleep(_AUDIO_RETRY_INTERVAL_SEC, check_interval=10)
                if _interrupt == "stop":
                    log("Phase 3: stop during no-audio retry wait — aborting", "INFO")
                    return
                if _interrupt == "pause":
                    emit_event("pipeline_paused", phase=3)
                    await _controls.wait_if_paused()
                    if _controls.is_stop():
                        return

                emit_event("phase_restart", phase=3, reason="auto_retry_audio_missing", attempt=_audio_auto_retries)
                try:
                    _p3_audio = await _await_phase_with_active_deadline(
                        3, PHASE_3_AUDIO_MAX_MIN,
                        lambda: run_phase3_audio(browser, cua_client, notebook_url, queue_dir, verbose,
                                                 podcast_length=podcast_length, prefer_existing_audio=True),
                        soft_warn_only=True,
                    )
                    audio_path = _p3_audio.get("audio_path")
                    _ao_url = _p3_audio.get("audio_overview_url", "")
                    if _ao_url:
                        audio_overview_url = _ao_url
                        emit_validated_link(3, "notebooklm", _ao_url, "Audio Overview", link_kind="audio")
                        if validate_link("notebooklm", _ao_url) and not any(l.get("url") == _ao_url for l in _p3_links):
                            _p3_links.append({"label": "Audio Overview", "url": _ao_url, "verified": True})
                    if audio_path:
                        log(f"Phase 3: audio recovered on auto-retry {_audio_auto_retries}/{_AUDIO_MAX_AUTO_RETRIES}", "INFO")
                        save_checkpoint(queue_dir, 3, topic=topic, brief_url=brief_url,
                                        notebook_url=notebook_url,
                                        audio_path=str(audio_path),
                                        audio_overview_url=audio_overview_url)
                        # Parity with the primary path: refresh delivery.json's
                        # audio link so P5's report/email point at the recovered
                        # audio overview. (FE streaming uses the Firestore audioUrl
                        # written inside run_phase3_audio's tail, independent of this.)
                        update_delivery(audio_url=(audio_overview_url or notebook_url))
                except _PhaseSoftDecision as _sd:
                    # A user clicked Retry/Skip on the soft-timeout warn during
                    # this attempt. Skip → notebook-link-only + cascade P4.
                    # Retry → loop again (the next auto-retry handles it).
                    log(f"Phase 3 audio auto-retry soft decision: {_sd.decision}", "INFO")
                    if _sd.decision == "skip":
                        emit_event("phase_skipped", phase=3, reason="user_skip_during_audio_auto_retry")
                        _p3_audio_user_skipped = True
                        _controls.skipped_phases.add(4)
                        audio_path = None
                        break
                    audio_path = None
                except asyncio.TimeoutError:
                    log("Phase 3 audio auto-retry timed out", "WARN")
                    audio_path = None
                except Exception as _ar:
                    log(f"Phase 3 audio auto-retry failed: {_ar}", "WARN")
                    audio_path = None
                continue
            if not _p3_audio_user_skipped:
                emit_event("phase_complete", phase=3, durationSec=int(time.time() - _p3_start), links=_p3_links,
                    summary=f"NotebookLM notebook created{', audio generated' if audio_path else ''}{', audio link extracted' if audio_overview_url else ''}")
        else:
            links_file = queue_dir / "links.json"
            if links_file.exists():
                links = json.loads(links_file.read_text(encoding="utf-8"))
            audio_str = cp.get("audio_path", "")
            if audio_str and Path(audio_str).exists():
                audio_path = Path(audio_str)
            log(f"Phase 3: Loaded existing (links={len(links)}, audio={'yes' if audio_path else 'no'})")

        if _controls.is_stop_or_pause():
            if _controls.is_stop():
                log("STOP requested after Phase 3 — pipeline terminated", "WARN")
                save_meta(queue_dir, topic, 3, status="stopped")
                update_delivery(status="stopped")
                emit_event("pipeline_stopped", phase=3, reason="stop")
                _update_firestore_research({"status": "stopped", "phase": 3})
                return
            else:
                log("PAUSE requested after Phase 3 — closing browser, awaiting resume", "WARN")
                save_meta(queue_dir, topic, 3, status="paused")
                update_delivery(status="paused")
                _update_firestore_research({"status": "paused", "phase": 3})
                stopped = await pause_and_close_browser(browser, queue_dir, phase=3,
                                                        extra_kwargs={"topic": topic, "brief_url": brief_url,
                                                                      "notebook_url": notebook_url})
                if stopped:
                    save_meta(queue_dir, topic, 3, status="stopped")
                    emit_event("pipeline_stopped", phase=3, reason="stop_after_pause")
                    _update_firestore_research({"status": "stopped", "phase": 3})
                    return
                browser = Browser(_profile_dir(WORKER_ID), headless=False)
                await browser.start()
                _active_browser_ref = browser  # re-point stop handler at fresh session
                emit_event("pipeline_resumed", phase=3)
                _update_firestore_research({"status": "ongoing"})
                # Post-P2 input is disabled. Drop any residual buffer silently.
                if _controls.peek_extra_context():
                    _ = _controls.pop_extra_context()

        # ══════════════════════ P4 + P5 are now FE-owned (cutover 2026-05-10) ══════════════════════
        # Phase 4 (YouTube upload) and Phase 5 (Doc + email) both run in
        # the FE post-2026-05-10. After P3 completes the audio upload to
        # Firebase Storage (links.audio_file written above), the FE
        # listener picks up phase_complete:3, fires triggerFeP4 →
        # /api/uploadYouTube which downloads from Storage,
        # ffmpeg-encodes a static-image+audio mp4, uploads to YouTube
        # unlisted via youtube.videos.insert, then chains directly into
        # triggerFeP5 (Doc + email).
        #
        # BE exits cleanly here. We do NOT:
        #   - run any P4 code (run_phase4, extract_youtube_url, Studio
        #     DOM automation, CUA fallbacks — all dead)
        #   - emit phase_start:4 / phase_complete:4 / phase_skipped:4
        #     (FE-P4 emits those from triggerFeP4 itself)
        #   - touch currentPhase (FE-P4 advances it to 4, FE-P5 to 5)
        #   - emit pipeline_complete (FE-P5 owns it)
        #
        # delivery.status="completed" tells the daemon-loop the BE work
        # is done so it can advance to the next queue item; the
        # user-visible research.status stays "ongoing" until FE-P5's
        # markFeP5Completed flips it to "completed".
        update_delivery(status="completed")
        # 2026-05-11: write beDone marker so the queue gate
        # (_wait_for_prior_fe_completion) knows BE handed off to FE.
        # research.status stays "ongoing" until FE-P5 flips it to
        # "completed" — that's the signal the gate actually waits on;
        # beDoneAt anchors the 4200s fallback timer.
        _update_firestore_research({"beDone": True, "beDoneAt": int(time.time() * 1000)})
        # 2026-05-12: autonomous P4/P5 trigger. BE has finished its work
        # through P3 (audio in Firebase Storage). Enqueue a Cloud Task that
        # POSTs to /api/uploadYouTube so Cloud Run runs P4 (YouTube upload)
        # + P5 (Doc + email) + flips status="completed" server-side. The
        # queue gate (_wait_for_prior_fe_completion) waits on status, so
        # this chain advances the queue even when the user's phone or tab
        # isn't open. Cloud Tasks owns delivery + retries; the call below
        # is a fast unary RPC (~50ms typical) — no thread held.
        try:
            _fire_fe_p4_trigger(_fb_uid, _fb_research_id)
        except Exception as _trig_err:
            log(f"FE trigger dispatch failed (non-fatal): {_trig_err}", "WARN")
        log(f"\n{'='*60}")
        log("BE PIPELINE COMPLETE — through Phase 3 (FE owns Phases 4 + 5)")
        log(f"  NotebookLM: {notebook_url or 'N/A'}")
        log(f"  Audio Overview: {audio_overview_url or 'N/A'}")
        log(f"  Queue: {queue_dir}")
        log(f"{'='*60}")

    except KeyboardInterrupt:
        log("Interrupted — progress saved to checkpoint", "WARN")
        raise
    except Exception as e:
        # Uncaught exception anywhere in the pipeline — surface it with
        # whatever phase context we have so the frontend can route the
        # error to the correct phase tile instead of silently dropping it.
        import traceback
        tb = traceback.format_exc()
        log(f"Fatal: {e}", "ERROR")
        traceback.print_exc()
        # _runtime.phase is the most-recently-entered phase — use it as
        # the routing hint so the error lands on the right phase tile
        # instead of defaulting to 0 and polluting the P0 dropdown.
        last_phase = 0
        try:
            rp = getattr(_runtime, "phase", None)
            if isinstance(rp, int):
                last_phase = rp
        except Exception:
            pass
        fail_phase(
            phase=last_phase,
            error=str(e)[:200] or "unexpected failure",
            reason="The pipeline hit an unexpected error. Details saved to backend.log.",
            agent=None,
        )
    finally:
        # New pause semantics: browser is closed by pause_and_close_browser when pause fires.
        # Here we just ensure cleanup on stop/complete/error — don't double-close if already closed.
        try:
            if _runtime.dispatcher_task and not _runtime.dispatcher_task.done():
                _runtime.dispatcher_task.cancel()
                try:
                    await _runtime.dispatcher_task
                except (asyncio.CancelledError, Exception):
                    pass
        except Exception:
            pass
        try:
            if browser is not None and browser.context is not None:
                await browser.close()
        except Exception as e:
            log(f"Browser final close error: {e}", "WARN")
        # Clear the active-browser ref AFTER close() runs. _schedule_server_
        # exit's child-PID sweep is the safety net for any chromium that
        # outlived close() (e.g. patchright node-driver hang), but the
        # ref-clear here matters for non-exit shutdowns (clean completes,
        # crashes that recover via auto-retry) where the next pipeline
        # creates a fresh Browser instance.
        _active_browser_ref = None
        _runtime.reset()
        teardown_firestore_run()
        # Clear the active-run global so subsequent device commands
        # (e.g. `clear_local_storage`) don't preserve a stale dir from
        # the just-finished run. Without this reset, the global keeps
        # pointing at the most recently completed run forever — every
        # idle clear would skip that one dir, leaking it indefinitely.
        global _tracks_dir
        _tracks_dir = None

    # Auto-retry from checkpoint if pipeline failed mid-way
    # Skip if: completed, stopped (terminal), or paused (intentional freeze)
    #
    # Two retry policies:
    #   - One-shot retry on the initial run (resume_dir is None at entry).
    #     The recursion sets resume_dir, so a second failure of any kind
    #     normally surfaces a [Retry, Skip] alert.
    #   - Browser-crash retry is always-auto: bypass the resume_dir gate
    #     so a recursive crash also auto-retries. Outer worker 5h ceiling
    #     is the safety net against infinite chrome-death loops.
    _kind = getattr(_runtime, "last_failure_kind", "") or ""
    _is_browser_crash = (_kind == "browser_crash")
    if queue_dir and (not resume_dir or _is_browser_crash):
        try:
            d_path = queue_dir / "delivery.json"
            d_status = json.loads(d_path.read_text(encoding="utf-8")).get("status") if d_path.exists() else ""
        except Exception:
            d_status = ""
        if d_status not in ("completed", "stopped", "paused") \
                and not (queue_dir / ".stop").exists() \
                and not (queue_dir / ".pause").exists():
            phase, _ = detect_resume_phase(queue_dir)
            # Phase 5 means BE finished P4 — FE owns Phase 5, no BE auto-retry
            # needed. The supervised-rehydrate auto-resume + manual Resume
            # paths both call run_pipeline which re-emits phase_complete
            # phase=4 to retrigger FE-P5. Cap at 4 so the auto-retry only
            # fires for actual BE-recoverable work (mid-phase crashes).
            if 1 < phase <= 4:
                _why = "browser-crash" if _is_browser_crash else f"failed at phase {phase}"
                log(f"Pipeline {_why} — auto-retrying from checkpoint...", "WARN")
                await asyncio.sleep(5)
                # Forward uid/research_id/run_id so the retry rebinds its
                # Firestore command listener (cancel/config/retry from FE).
                # Without these, setup_firestore_run is skipped (line ~16169
                # `if uid:`) and the FE's Stop button writes to a Firestore
                # commands subcollection no one is listening to — the BE
                # keeps running orphaned while the FE shows "stopped".
                await run_pipeline(topic=topic, email=email, verbose=verbose,
                                   api_key=api_key, resume_dir=str(queue_dir),
                                   config=config,
                                   run_id=run_id, uid=uid, research_id=research_id)


# ── Server Mode (Web App API) ────────────────────────────────────────────────

async def run_server(port=8000):
    """Start FastAPI server for real-time web app streaming."""
    from fastapi import FastAPI
    from fastapi.responses import JSONResponse
    from fastapi.middleware.cors import CORSMiddleware
    import uvicorn

    # Reset module-level exit-scheduled flag. Daemon-respawn already gives
    # us a fresh process (so the flag resets naturally), but if the same
    # process is somehow re-entering run_server (test harness, future
    # in-process restarts), we want a clean slate so a new stop can
    # actually schedule its exit.
    global _exit_scheduled
    _exit_scheduled = False

    app = FastAPI(title="Research Pipeline API")
    app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_methods=["*"], allow_headers=["*"])

    queues_root = Path(__file__).parent / "queues"

    # ── Startup sweep: purge stale failed runs older than 7 days ──
    # Without this, queues/ piles up forever with partial MDs, partial
    # audio, and orphaned Firestore docs. We only sweep entries whose
    # delivery.json status is NOT in a clean-parked set, and only if the
    # dir hasn't been touched in > 7 days so active debugging sessions
    # aren't wiped out. (tracks/ removed 2026-04-29 — was the only other
    # local artifact; nothing to sweep there anymore.)
    try:
        now_ts = time.time()
        STALE_SECONDS = 7 * 86400
        KEEP_STATUSES = {"completed", "paused", "paused_backend_restart"}
        swept = 0
        if queues_root.exists():
            for d in queues_root.iterdir():
                if not d.is_dir():
                    continue
                delivery_path = d / "delivery.json"
                status = ""
                try:
                    if delivery_path.exists():
                        status = json.loads(delivery_path.read_text(encoding="utf-8")).get("status", "")
                except Exception:
                    pass
                if status in KEEP_STATUSES:
                    continue
                try:
                    mtime = d.stat().st_mtime
                except Exception:
                    continue
                if (now_ts - mtime) < STALE_SECONDS:
                    continue
                # Cascade Firestore cleanup if owner.json is present
                owner_path = d / "owner.json"
                if owner_path.exists() and _firebase_db:
                    try:
                        owner = json.loads(owner_path.read_text(encoding="utf-8"))
                        uid, rid = owner.get("uid"), owner.get("researchId")
                        if uid and rid:
                            ref = _firebase_db.collection("users").document(uid) \
                                .collection("researches").document(rid)
                            for sub in ("documents", "audios", "messages",
                                        "pipeline_events", "commands"):
                                try:
                                    for sd in ref.collection(sub).stream():
                                        try: sd.reference.delete()
                                        except Exception: pass
                                except Exception: pass
                            try: ref.delete()
                            except Exception: pass
                    except Exception: pass
                # Nuke local queue dir.
                import shutil as _shutil
                try: _shutil.rmtree(d)
                except Exception: pass
                swept += 1
        if swept:
            log(f"[startup-sweep] purged {swept} stale run(s) older than 7 days", "INFO")
    except Exception as _se:
        log(f"[startup-sweep] failed: {_se}", "WARN")

    # ── Periodic orphan sweep ──
    # Complements the startup time-based sweep above. This one is
    # existence-based: it iterates queues/, reads each owner.json, and
    # nukes the local dirs IF the corresponding Firestore research doc
    # has been deleted (e.g. by the FE deleteResearch cascade). Catches
    # user-initiated deletes within ~5 min instead of waiting 7 days.
    # Race protection:
    #   1) Skip dirs younger than 5 min so a fresh run mid-creation is
    #      never killed before delivery.json/owner.json are written.
    #   2) Re-verify Firestore existence after a 250ms jitter just before
    #      rmtree, in case the doc was created in the same window.
    #   3) Defensive defaults: missing delivery.json/owner.json/status,
    #      Firestore unreachable, or unknown status all SKIP delete.
    ORPHAN_SWEEP_INTERVAL_SEC = 300
    ORPHAN_SWEEP_MIN_AGE_SEC = 300
    ORPHAN_SWEEP_IN_FLIGHT_STATUSES = {"ongoing", "queued"}

    async def _orphan_sweep_loop():
        import shutil as _shutil
        while True:
            try:
                await asyncio.sleep(ORPHAN_SWEEP_INTERVAL_SEC)
                if not _firebase_db or not queues_root.exists():
                    continue
                now_ts_inner = time.time()
                swept_n = 0
                for d in queues_root.iterdir():
                    if not d.is_dir():
                        continue
                    try:
                        if (now_ts_inner - d.stat().st_mtime) < ORPHAN_SWEEP_MIN_AGE_SEC:
                            continue
                    except Exception:
                        continue
                    delivery_path = d / "delivery.json"
                    if not delivery_path.exists():
                        continue
                    try:
                        status = json.loads(delivery_path.read_text(encoding="utf-8")).get("status", "")
                    except Exception:
                        continue
                    if not status or status in ORPHAN_SWEEP_IN_FLIGHT_STATUSES:
                        continue
                    owner_path = d / "owner.json"
                    if not owner_path.exists():
                        continue
                    try:
                        owner = json.loads(owner_path.read_text(encoding="utf-8"))
                        uid, rid = owner.get("uid"), owner.get("researchId")
                    except Exception:
                        continue
                    if not uid or not rid:
                        continue
                    try:
                        ref = _firebase_db.collection("users").document(uid) \
                            .collection("researches").document(rid)
                        if ref.get().exists:
                            continue
                    except Exception:
                        continue
                    await asyncio.sleep(0.25)
                    try:
                        if ref.get().exists:
                            continue
                    except Exception:
                        continue
                    try:
                        _shutil.rmtree(d)
                    except Exception as _e:
                        log(f"[orphan-sweep] rmtree {d.name} failed: {_e}", "WARN")
                        continue
                    swept_n += 1
                if swept_n:
                    log(f"[orphan-sweep] purged {swept_n} orphan(s) (Firestore research doc missing)", "INFO")
            except asyncio.CancelledError:
                return
            except Exception as _e:
                log(f"[orphan-sweep] iteration failed: {_e}", "WARN")

    @app.get("/api/runs")
    async def list_runs():
        """List all pipeline runs — returns frontend-compatible Research objects."""
        runs = []
        if queues_root.exists():
            for d in sorted(queues_root.iterdir(), reverse=True):
                if not d.is_dir():
                    continue
                meta_path = d / "meta.json"
                if meta_path.exists():
                    try:
                        runs.append(json.loads(meta_path.read_text(encoding="utf-8")))
                        continue
                    except Exception:
                        pass
                # Fallback: build from checkpoint
                cp = load_checkpoint(d)
                has_delivery = (d / "delivery.json").exists()
                phase = cp.get("last_completed_phase", 0) if cp else 0
                runs.append({
                    "id": d.name,
                    "title": cp.get("topic", d.name) if cp else d.name,
                    "topic": cp.get("topic", d.name) if cp else d.name,
                    "status": "completed" if has_delivery else "ongoing",
                    "phase": max(0, phase - 1),
                    "platforms": ["chatgpt", "gemini", "claude"],
                    "documents": [], "audios": [],
                    "createdAt": int(d.stat().st_ctime * 1000),
                    "updatedAt": int(d.stat().st_mtime * 1000),
                })
        return runs

    @app.get("/api/runs/{run_id}")
    async def get_run(run_id: str):
        """Get full details — meta.json + delivery + checkpoint + pipeline_state."""
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        # Load meta (frontend-compatible Research object)
        meta_path = queue / "meta.json"
        meta = json.loads(meta_path.read_text(encoding="utf-8")) if meta_path.exists() else None
        cp = load_checkpoint(queue)
        delivery_file = queue / "delivery.json"
        delivery = json.loads(delivery_file.read_text(encoding="utf-8")) if delivery_file.exists() else None
        # Pipeline state: stopped is terminal, paused is resumable
        pipeline_state = "running"
        if (queue / ".stop").exists():
            pipeline_state = "stopped"
        elif (queue / ".pause").exists():
            pipeline_state = "paused"
        elif delivery and delivery.get("status") == "completed":
            pipeline_state = "completed"
        return {"meta": meta, "checkpoint": cp, "delivery": delivery, "pipeline_state": pipeline_state}

    # 2026-04-29: GET /api/runs/{id}/events + WS /ws/{run_id} +
    # _find_events_file removed. Both read events.jsonl from disk, but
    # writes were dropped (Firestore pipeline_events is the FE transport).
    # No live FE consumers — verified zero callsites in the FE source.

    @app.post("/api/runs/{run_id}/stop")
    async def stop_run(run_id: str):
        """STOP: terminate pipeline, save partial results, mark as stopped (not resumable).

        Also schedules a hard process exit 3s later — matches the Firestore
        command-listener path so that hitting Stop reliably ends the backend
        no matter which transport got there first.
        """
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        (queue / ".stop").write_text("stop", encoding="utf-8")
        p = queue / ".pause"
        if p.exists():
            p.unlink()
        # Set asyncio event for immediate response, then schedule the backend
        # exit via the shared helper. Idempotent if the Firestore-command path
        # already fired — we won't spawn duplicate exit threads.
        _controls.request_stop()
        # 2026-05-21: schedule graceful browser teardown inline before the
        # exit timer fires — without this, mid-Phase awaits keep the
        # patchright session open until os._exit reaps the process tree.
        # We're already in an async handler so asyncio.create_task works
        # directly (no call_soon_threadsafe needed).
        _b = _active_browser_ref
        if _b is not None:
            try:
                asyncio.create_task(_b.close())
            except Exception as _ce:
                log(f"[http-stop] inline browser.close schedule failed: {_ce}", "WARN")
        _schedule_server_exit("http-endpoint")
        return {"status": "stop_requested", "id": run_id}

    @app.post("/api/runs/{run_id}/pause")
    async def pause_run(run_id: str):
        """PAUSE: freeze pipeline at next checkpoint, save state for resume."""
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        (queue / ".pause").write_text("pause", encoding="utf-8")
        _controls.request_pause()
        return {"status": "pause_requested", "id": run_id}

    @app.post("/api/runs/{run_id}/feedback")
    async def submit_feedback(run_id: str, request_data: dict):
        """Submit user feedback for a phase. Stops pipeline + saves feedback for next resume.
        Body: {phase: 1, message: "Brief is too narrow, include biotech"}"""
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        phase = str(request_data.get("phase", ""))
        message = request_data.get("message", "")
        if not message:
            return JSONResponse({"error": "message is required"}, 400)
        # Load existing feedback or create new
        fb_path = queue / "feedback.json"
        fb = json.loads(fb_path.read_text(encoding="utf-8")) if fb_path.exists() else {}
        fb[phase] = message
        fb_path.write_text(json.dumps(fb, indent=2), encoding="utf-8")
        # Auto-pause pipeline so it picks up feedback on resume (not terminal stop)
        (queue / ".pause").write_text("pause", encoding="utf-8")
        _controls.request_pause()
        return {"status": "feedback_saved", "phase": phase, "will_redo_from": phase}

    @app.post("/api/runs/{run_id}/add_context")
    async def add_context(run_id: str, request_data: dict):
        """Add context to running pipeline WITHOUT pausing. Context is injected at next opportunity.
        Only valid during Phase 1; Phase 2+ rejects (matches FE input lock + Firestore listener).
        Body: {text: "Also look at biotech angle"}"""
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        text = request_data.get("text", "")
        if not text:
            return JSONResponse({"error": "text is required"}, 400)
        if _runtime.phase >= 2:
            log(f"REST add_context REJECTED (phase={_runtime.phase} — input disabled from Phase 2 onward)", "WARN")
            return JSONResponse({"error": f"context rejected — phase {_runtime.phase} does not accept input"}, 409)
        _controls.add_context(text)
        log(f"Context added ({len(text)} chars) — will be injected at next phase boundary")
        return {"status": "context_added", "chars": len(text)}

    @app.post("/api/runs/{run_id}/resume")
    async def resume_run(run_id: str, request_data: dict = None):
        """Resume a paused/failed pipeline run. Queued if another is running.
        If feedback exists, pipeline redoes that phase with feedback injected.
        NOTE: only paused runs can be resumed — stopped runs are terminal."""
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        # Block resume of stopped (terminal) runs
        if (queue / ".stop").exists():
            return JSONResponse({"error": "Run was stopped (terminal). Cannot resume — start a new run."}, 409)
        # Clear .pause signal
        p = queue / ".pause"
        if p.exists():
            p.unlink()
        # If feedback targets a specific phase, reset checkpoint to redo from there
        fb_path = queue / "feedback.json"
        cp = load_checkpoint(queue)
        if fb_path.exists() and cp:
            fb = json.loads(fb_path.read_text(encoding="utf-8"))
            if fb:
                earliest_phase = min(int(p) for p in fb.keys())
                # Reset checkpoint so pipeline redoes from the feedback phase
                cp["last_completed_phase"] = max(0, earliest_phase - 1)
                (queue / "checkpoint.json").write_text(json.dumps(cp, indent=2), encoding="utf-8")
                # Remove outputs from that phase onwards so they get regenerated
                if earliest_phase <= 1:
                    for f in (queue / "documents").glob("brief.md"):
                        try: f.unlink()
                        except Exception: pass
                if earliest_phase <= 2:
                    for f in (queue / "documents").glob("*.md"):
                        if f.stem != "brief":
                            try: f.unlink()
                            except Exception: pass
                if earliest_phase <= 3:
                    for p in [queue / "links.json"]:
                        try: p.unlink(missing_ok=True)
                        except Exception: pass
                    podcasts_dir = queue / "podcasts"
                    if podcasts_dir.exists():
                        for f in podcasts_dir.glob("*.*"):
                            try: f.unlink()
                            except Exception: pass
        # If request has config, merge with existing config.json
        if request_data and request_data.get("config"):
            config_path = queue / "config.json"
            existing = json.loads(config_path.read_text(encoding="utf-8")) if config_path.exists() else {}
            existing.update(request_data["config"])
            config_path.write_text(json.dumps(existing, indent=2), encoding="utf-8")
        # Reset delivery + meta status from "paused" back to "ongoing"
        d_path = queue / "delivery.json"
        if d_path.exists():
            try:
                d = json.loads(d_path.read_text(encoding="utf-8"))
                if d.get("status") == "paused":
                    d["status"] = "ongoing"
                    d_path.write_text(json.dumps(d, indent=2), encoding="utf-8")
            except Exception:
                pass
        m_path = queue / "meta.json"
        if m_path.exists():
            try:
                m = json.loads(m_path.read_text(encoding="utf-8"))
                if m.get("status") == "paused":
                    m["status"] = "ongoing"
                    m_path.write_text(json.dumps(m, indent=2), encoding="utf-8")
            except Exception:
                pass
        topic = cp.get("topic", "") if cp else ""
        email = (request_data or {}).get("email", "")
        await _job_queue.put({"topic": topic, "email": email, "resume_dir": str(queue)})
        return {"status": "queued_resume", "id": run_id, "queue_position": _job_queue.qsize()}

    # ── Job queue: one pipeline at a time, multiple can be queued ──
    _job_queue = asyncio.Queue()
    # `_QUEUE_STATE["running"]` is the single source of truth for worker
    # busy-state. The closure-local _queue_running was dropped in Q7 — it
    # was a vestigial duplicate that could diverge from _QUEUE_STATE if a
    # write raised between the two assignments. /api/queue, /api/health,
    # _aegis_pulse_loop, and the listener all now read _QUEUE_STATE.
    _QUEUE_STATE["queue_ref"] = _job_queue
    _QUEUE_STATE["recompute_fn"] = None  # set below after defining helper

    def _flip_queued_to_ongoing(uid_val, research_id_val):
        """Worker pickup: flip status from queued → ongoing and clear queue
        fields. Transactional — only flips if current status is "queued",
        so a concurrent cancel that wrote status="stopped" between dequeue
        and this call wins the race. Without this, a cancel landing in the
        ms between worker dequeue and worker.flip() would be silently
        overwritten back to "ongoing" and the user would see "Cancelled" in
        chat while the tile said running. No-op if Firestore is unavailable
        or uid/rid missing (HTTP /api/runs path doesn't carry them)."""
        if not (_firebase_db and uid_val and research_id_val):
            return
        try:
            from google.cloud import firestore as _firestore
            doc_ref = _firebase_db.collection("users").document(uid_val) \
                .collection("researches").document(research_id_val)

            @_firestore.transactional
            def _flip_txn(tx):
                snap = doc_ref.get(transaction=tx)
                if not snap.exists:
                    return "missing"
                cur = (snap.to_dict() or {}).get("status")
                if cur != "queued":
                    return f"skipped({cur})"
                tx.update(doc_ref, _be_payload({
                    "status": "ongoing",
                    "queuePosition": _firestore.DELETE_FIELD,
                    "queuedBehindRunId": _firestore.DELETE_FIELD,
                    "queuedBehindTitle": _firestore.DELETE_FIELD,
                }))
                return "flipped"

            outcome = _flip_txn(_firebase_db.transaction())
            if outcome.startswith("skipped"):
                log(f"[flip] {research_id_val[:8]}… {outcome} — leaving status as-is (cancel race won)", "INFO")
            elif outcome == "missing":
                log(f"[flip] {research_id_val[:8]}… research doc missing — Q3 cascade-cancel should catch this", "WARN")
            return outcome
        except Exception as e:
            # 2026-05-28: surface the ROOT cause. A permission error inside the
            # transaction makes google-cloud-firestore raise "transaction has no
            # transaction ID, so it cannot be rolled back", which MASKS the real
            # 403 (the flip's research-doc update was denied — see the
            # deviceUpdatingFor self-heal fix). Log __cause__/__context__ so any
            # future flip failure is diagnosable instead of misleading.
            _root = getattr(e, "__cause__", None) or getattr(e, "__context__", None)
            log(
                f"Failed to flip queued→ongoing for {research_id_val}: {e}"
                + (f" | root: {_root!r}" if _root is not None else ""),
                "WARN",
            )
            return None

    def _recompute_queue_positions():
        """After a job finishes, shift remaining queued jobs' positions up by
        one and re-point their `queuedBehindRunId/Title` at the new head (or
        clear if they're next). Reads `_job_queue._queue` as a snapshot.

        Uses a single Firestore WriteBatch so all N position updates land
        atomically — the FE never sees an inconsistent intermediate state
        where two queued runs both think they're #1 (Q4: cancel #1 →
        positions #2,#3 must become #1,#2 in one render frame, no flicker).
        WriteBatch caps at 500 ops; for typical N (single-digit queued runs)
        this is one batch; safety chunk at 450 ops if ever exceeded."""
        if not _firebase_db:
            return
        try:
            pending = list(_job_queue._queue)
        except Exception:
            return
        if not pending:
            return
        try:
            from google.cloud.firestore import DELETE_FIELD
        except Exception:
            DELETE_FIELD = None  # pyright: ignore[reportConstantRedefinition]
        # Build patch list first so we can chunk into 450-op batches if N
        # ever exceeds Firestore's 500-op WriteBatch ceiling.
        patches: list[tuple[str, str, dict]] = []
        for idx, qjob in enumerate(pending):
            uid_v = qjob.get("uid")
            rid_v = qjob.get("research_id")
            if not uid_v or not rid_v:
                continue
            new_pos = idx + 1
            if idx == 0:
                # Position #1's "behind" is the currently-running pipeline
                # when there is one. Two callers reach this branch with
                # different semantics:
                #   • Completion flow (after task_done at :25549) —
                #     `_QUEUE_STATE["running"]` was just flipped False and
                #     `current_job` set to None. The else-branch clears
                #     behind fields (no run ahead — position #1 is next up).
                #   • Enqueue flow (called from the start-listener lambda
                #     after _safe_enqueue) — `running` is True and
                #     `current_job` is the live pipeline. Set behind to
                #     the running job's title so QueuedBanner reads
                #     "Will play after <running>" instead of either no
                #     reference or (pre-fix) the wrong one the FE wrote
                #     at submit time based on its own activeOnDevice
                #     guess.
                running_job = _QUEUE_STATE.get("current_job")
                if (running_job
                        and _QUEUE_STATE.get("running")
                        and running_job.get("research_id") != rid_v):
                    patch = {
                        "queuePosition": new_pos,
                        "queuedBehindRunId": running_job.get("research_id") or "",
                        "queuedBehindTitle": (running_job.get("topic") or "")[:60],
                    }
                else:
                    patch = {"queuePosition": new_pos}
                    if DELETE_FIELD is not None:
                        patch["queuedBehindRunId"] = DELETE_FIELD
                        patch["queuedBehindTitle"] = DELETE_FIELD
            else:
                prev = pending[idx - 1]
                patch = {
                    "queuePosition": new_pos,
                    "queuedBehindRunId": prev.get("research_id") or "",
                    "queuedBehindTitle": (prev.get("topic") or "")[:60],
                }
            patches.append((uid_v, rid_v, patch))
        CHUNK = 450
        for i in range(0, len(patches), CHUNK):
            batch = _firebase_db.batch()
            for uid_v, rid_v, patch in patches[i:i + CHUNK]:
                ref = _firebase_db.collection("users").document(uid_v) \
                    .collection("researches").document(rid_v)
                batch.update(ref, _be_payload(patch))
            try:
                batch.commit()
            except Exception as e:
                log(f"Failed to commit queue-position batch [{i}:{i+CHUNK}]: {e}", "WARN")

    # Expose the recompute helper to the module-level Firestore listener so
    # the cancel-queued action can also trigger a position refresh.
    _QUEUE_STATE["recompute_fn"] = _recompute_queue_positions
    # Real-time deferred-doc renumber (2026-05-22): module-level
    # `_recompute_deferred_queue_positions` updates positions for the
    # Firestore-deferred docs the local recompute can't see. Wired into
    # the listener claim path, idle-rescan after claim, and the
    # _do_cancel deferred-cancel branch. See helper docstring.
    _QUEUE_STATE["recompute_deferred_fn"] = _recompute_deferred_queue_positions
    # 2026-05-15: initialise the hard-reset lock here, before the device-cmd
    # listener thread is spawned at research.py:24898. The lock makes the
    # gate-state clear+persist (in the device-cmd thread) atomic w.r.t. the
    # worker `finally` block writes (in the asyncio main thread). Without it,
    # a worker finishing between the clear (line 1916-1918) and the persist
    # (line 1919) of hard_reset would write stale uid_X back to _QUEUE_STATE,
    # which the persist would then snapshot to disk — defeating the reset.
    _QUEUE_STATE["_hard_reset_lock"] = _threading.Lock()
    _QUEUE_STATE["_pending_enq_lock"] = _threading.Lock()

    # ── pending_queue.json (Phoenix T3 resume) ─────────────────────────────
    # The in-memory _job_queue (asyncio.Queue) is lost when the BE process
    # exits — daemon-loop relaunch otherwise restarts with an empty queue,
    # losing any work that hadn't reached `status=queued` in Firestore yet.
    # Snapshot to disk on every worker boundary so a Phoenix restart can
    # restore. Firestore-driven rehydration (line ~17850) takes precedence;
    # this is a belt-and-suspenders fallback for racing/network-blocked cases.
    # Per-worker pending-queue file (2026-05-21). Pre-multi-worker, all
    # writers raced on `_pending_queue.json` (+ its `.tmp` sibling). With
    # N workers, the tmp-then-replace dance still races: two workers
    # writing different snapshots both name the tmp the same, the second
    # write clobbers the first mid-buffer. Per-worker file isolates each
    # snapshot. Restore (research.py:~26649, 26991) reads MY worker's
    # file only — siblings restore their own. Single-worker installs
    # keep the legacy filename (worker 1 = no suffix) so a pre-PR install
    # that never re-pairs into multi-worker still finds its snapshot.
    if WORKER_ID == 1:
        _pending_queue_path = queues_root / "_pending_queue.json"
    else:
        _pending_queue_path = queues_root / f"_pending_queue_worker_{WORKER_ID}.json"

    # Forward declaration so the module-scope device-cmd listener at
    # research.py:1766 can call this closure via _QUEUE_STATE["persist_fn"].
    # The assignment happens immediately after the function body below.
    def _persist_pending_queue(current_job=None):
        """Snapshot _job_queue contents (+ optional current_job) to disk.
        Returns True on success, False on persist failure. Never raises.

        On failure with a current_job, immediately writes
        status=paused_backend_restart_failed + lastError to the affected
        research's Firestore doc so the FE recovery banner surfaces. The
        Phoenix auto-restore path on respawn relies on this snapshot — if
        it didn't write, there's nothing to restore from, and the run
        would otherwise be silently lost on BE restart."""
        try:
            queues_root.mkdir(parents=True, exist_ok=True)
            try:
                pending = list(_job_queue._queue)
            except Exception:
                pending = []
            payload = {
                "ts_ms": int(time.time() * 1000),
                "current": current_job,
                "pending": pending,
                # 2026-05-11: persist the queue-gate's prior-run state so
                # a daemon restart mid-FE-P5 doesn't lose the wait
                # context. Without this, fresh _QUEUE_STATE after respawn
                # means the gate skips and the next pipeline races
                # against the in-flight FE-P5 of the prior run.
                "gate": {
                    "last_completed_uid": _QUEUE_STATE.get("last_completed_uid"),
                    "last_completed_rid": _QUEUE_STATE.get("last_completed_rid"),
                    "last_be_done_at": int(_QUEUE_STATE.get("last_be_done_at") or 0),
                },
            }
            # 2026-05-11: atomic write — write to tmp, then os.replace
            # (atomic on POSIX and Windows same-volume). Protects against
            # the Q7 watchdog path where _schedule_server_exit's 3s timer
            # can race os._exit(0) past a slow in-progress write_text(),
            # leaving _pending_queue.json truncated. On respawn the
            # truncated file fails json.loads and disk-restore silently
            # skips, losing the gate state for the very FIRST post-restart
            # dequeue (the case the boot-race fix already mitigates, but
            # the truncated-file mode would also lose pending in-memory
            # jobs not yet visible in Firestore).
            _tmp_path = _pending_queue_path.with_suffix(".json.tmp")
            _tmp_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
            os.replace(str(_tmp_path), str(_pending_queue_path))
            return True
        except Exception as e:
            log(f"[pending_queue] persist failed: {e}", "WARN")
            if current_job and _firebase_db is not None:
                uid = current_job.get("uid")
                rid = current_job.get("research_id")
                if uid and rid:
                    if _update_research_doc(uid, rid, {
                        "status": "paused_backend_restart_failed",
                        "lastError": (
                            "Pipeline state could not be saved before "
                            f"backend restart ({str(e)[:120]}). Tap "
                            "Resume to attempt manual recovery from "
                            "the last checkpoint, or Discard to abandon."
                        ),
                    }):
                        log(f"[pending_queue] Surfaced persist failure for "
                            f"{rid[:24]} — FE will show recovery banner", "WARN")
            return False

    # 2026-05-15: expose the persist closure to the module-scope device-cmd
    # listener at research.py:1766 so hard_reset can flush a clean snapshot
    # to disk before os._exit (the listener can't directly close over this
    # function — it lives in a different scope).
    _QUEUE_STATE["persist_fn"] = _persist_pending_queue

    # Outer ACTIVE-TIME ceiling for a single pipeline run (Fix D 2026-05-27:
    # was raw wall-clock). Phase budgets inside run_pipeline are cooperative
    # — long Playwright/CUA awaits without timeouts can deadlock the worker
    # indefinitely, leaving /api/queue stuck at running:true and pending
    # jobs starved. Q7 watchdog: if a run's ACTIVE work-time exceeds this we
    # declare it stuck, request_stop, mark the doc stopped_by_watchdog, and
    # schedule a process exit so the daemon-loop respawns a fresh worker that
    # drains the rest of the queue. The supervisor at the run_pipeline call
    # site does NOT accrue time while _controls.is_pause() or
    # _controls._awaiting_user (blocked on a user decision) — so legitimate
    # waits never trip it (the old wall-clock version false-killed a run that
    # sat for hours on an unbounded await_phase_decision). Generous 5h of
    # active time — a healthy run is under 90min; sized to allow P1+P2+P3-
    # audio soft-warn advisories (60+120+90 = 270 min) of real work before
    # the deadlock backstop. 2026-05-06 (Stream 2 F12): bumped 4h → 5h.
    WORKER_OUTER_TIMEOUT_SEC = 5 * 60 * 60
    # BE_PHASES_TIMEOUT_SEC lives at module scope (research.py:1224) since
    # 2026-05-12 so the Firestore start listener (also module-level) can
    # predict whether the gate will block when assigning queue position.
    # This block kept as a doc anchor — the constant itself moved.

    async def _wait_for_prior_fe_completion(_current_job=None):
        """Hold the next dequeue until the prior run's FE-P5 reports
        completion via research.status=='completed', or the fallback
        timer expires.

        `_current_job` is the just-dequeued job (passed in by the worker
        BEFORE _QUEUE_STATE["current_job"] is set). Used to detect the
        resume-of-same-rid edge case described below."""
        _puid = _QUEUE_STATE.get("last_completed_uid")
        _prid = _QUEUE_STATE.get("last_completed_rid")
        _pdone = int(_QUEUE_STATE.get("last_be_done_at") or 0)
        if not _firebase_db or not _puid or not _prid:
            return  # first run or missing context — nothing to wait on
        # 2026-05-11: skip the gate when the dequeued job IS the same rid
        # as the just-finished run. This happens on resume-from-checkpoint
        # paths where Firestore re-enqueues the same rid after a BE crash
        # or restart — the "prior" run from the gate's POV is actually
        # the current dequeued run; waiting on its own FE-P5 would
        # circular-deadlock (BE never starts → FE-P5 never fires → gate
        # waits the full 4200s fallback). Resume semantics handle the
        # state machine separately; the gate only matters for the
        # successor-pipeline-after-different-prior case.
        if _current_job and (_current_job.get("research_id") or "") == _prid:
            log(f"[queue-gate] dequeued rid {_prid[:8]}… matches last_completed_rid — resume path, skipping wait")
            return
        if _pdone <= 0:
            # Error path marker: prior run was watchdog-stopped /
            # errored / never reached BE PIPELINE COMPLETE. FE-P5
            # will never write "completed" for it, so don't block.
            log("[queue-gate] prior run errored — skipping FE-completion wait")
            return
        deadline = _pdone + BE_PHASES_TIMEOUT_SEC * 1000
        # Mid-session stuck-status self-heal — if the prior FE-P5 just
        # legitimately ghosted (user closed the tab, FE-P5 errored without
        # flipping status, browser was force-quit), the gate previously
        # waited the full 70-min deadline before giving up. Now: take a
        # snapshot of (status, feP5State) on entry and force-release if
        # both stay unchanged for STUCK_STATUS_RELEASE_MS (5 min). The
        # deadline still backstops the slow-FE-P5 case (large YouTube
        # uploads), but the common-case stuck-prior gets unstuck in 5 min
        # without needing a BE restart or Reset Backend tap.
        STUCK_STATUS_RELEASE_MS = 5 * 60 * 1000
        _stuck_first_seen_ms: int = 0
        _stuck_status_signature: str = ""  # f"{status}|{feP5State}"
        log(f"[queue-gate] waiting for prior run {_prid[:8]}… FE-P5 completion (fallback in {BE_PHASES_TIMEOUT_SEC}s)")
        # 2026-05-12: register the gate-pending job so cancel handlers can
        # see it. Without this, a cancel that arrives while the worker is
        # blocked in the gate wait silently no-ops — neither in job_queue
        # (already popped) nor in current_job (not set until after gate).
        # User saw "Cancel: rid=… removed_from_queue=False" with no status
        # flip + no banner unmount. Cleared on gate return.
        if _current_job:
            _QUEUE_STATE["gate_pending_job"] = _current_job
        while True:
            # 2026-05-12: honor explicit stop requests during gate wait.
            # When the cancel handler matches gate_pending_job and calls
            # request_stop, this poll loop exits cleanly so the worker can
            # bail out of the gate and drop the job.
            try:
                if _controls.is_stop():
                    log("[queue-gate] stop requested during gate wait — releasing", "INFO")
                    _QUEUE_STATE.pop("gate_pending_job", None)
                    return
            except Exception:
                pass
            now_ms = int(time.time() * 1000)
            if now_ms >= deadline:
                log(f"[queue-gate] FE never reported completed in {BE_PHASES_TIMEOUT_SEC}s — force-dequeueing")
                _QUEUE_STATE.pop("gate_pending_job", None)
                return
            try:
                # 2026-05-11: offload the blocking Firestore .get() to a
                # worker thread so the gate's 2s poll doesn't block the
                # event loop on the round-trip (50-200ms typical, longer
                # under network contention). Keeps heartbeat / listener
                # callbacks responsive while the gate waits.
                _doc_ref = _firebase_db.collection("users").document(_puid) \
                    .collection("researches").document(_prid)
                snap = await asyncio.to_thread(_doc_ref.get)
                if not snap.exists:
                    # Prior research doc was deleted (user purged from
                    # /researches). Treat as terminal — there's nothing
                    # left to wait on. Without this branch the gate
                    # would spin silently until the deadline fires
                    # (worst case BE_PHASES_TIMEOUT_SEC = 70 min).
                    log(f"[queue-gate] prior run {_prid[:8]}… doc missing — dequeueing")
                    _QUEUE_STATE.pop("gate_pending_job", None)
                    return
                if snap.exists:
                    data = snap.to_dict() or {}
                    status = data.get("status", "")
                    fe_p5_state = data.get("feP5State", "")
                    if status in ("completed", "stopped", "stopped_by_watchdog",
                                  "cancelled", "terminated_by_user_discard", "errored"):
                        log(f"[queue-gate] prior run terminal (status={status}) — dequeueing")
                        _QUEUE_STATE.pop("gate_pending_job", None)
                        return
                    # 2026-05-11: markFeP5Failed writes feP5State="failed"
                    # but doesn't flip research.status — so a thrown FE-P5
                    # exception would hang the gate for the full 4200s.
                    # Release the gate on this fast-fail marker too.
                    if fe_p5_state == "failed":
                        log("[queue-gate] prior run's FE-P5 failed — dequeueing")
                        _QUEUE_STATE.pop("gate_pending_job", None)
                        return
                    # Stuck-status self-heal: if (status, feP5State) hasn't
                    # changed in STUCK_STATUS_RELEASE_MS, the prior FE has
                    # ghosted and is never coming back. Force-release. The
                    # first-seen marker resets on any signature change so
                    # a slow-but-progressing FE-P5 (e.g., long YouTube
                    # upload that flips feP5State queued→running→completed
                    # over several minutes) doesn't trip the heal.
                    _sig = f"{status}|{fe_p5_state}"
                    if _sig != _stuck_status_signature:
                        _stuck_status_signature = _sig
                        _stuck_first_seen_ms = now_ms
                    elif (now_ms - _stuck_first_seen_ms) >= STUCK_STATUS_RELEASE_MS:
                        log(
                            f"[queue-gate] prior run {_prid[:8]}… stuck at "
                            f"({status},{fe_p5_state}) for "
                            f"{int((now_ms - _stuck_first_seen_ms) / 1000)}s — "
                            f"FE-P5 ghosted, force-dequeueing"
                        )
                        _QUEUE_STATE.pop("gate_pending_job", None)
                        return
            except Exception as e:
                _e_str = str(e)
                if (
                    "403" in _e_str
                    or "PERMISSION_DENIED" in _e_str
                    or "Missing or insufficient permissions" in _e_str
                ):
                    # Track D: synth user denied on prior run's research
                    # doc. We can't poll its terminal status — but we
                    # also can't sit in a 2-second poll loop spamming
                    # 403s and wedging the queue for BE_PHASES_TIMEOUT_SEC
                    # (4200s by default). The on-disk gate-state and
                    # _safe_enqueue's whitelist already de-dupe restart
                    # races, so release the gate immediately and let
                    # the worker proceed. Under-Track-D this is the
                    # right behavior: every research is owned by some
                    # device, the BE only sees its own device-queue
                    # entries, and two queued runs on the same device
                    # arrive in order via the start listener.
                    log("[queue-gate] read denied (synth user) — releasing gate (Track D)", "DEBUG")
                    _QUEUE_STATE.pop("gate_pending_job", None)
                    return
                log(f"[queue-gate] Firestore read failed: {e}", "WARN")
            await asyncio.sleep(2)

    async def _rescan_queue_for_unclaimed():
        """Multi-worker orphan recovery (2026-05-21).

        Scenario: N workers all busy when doc D arrives → every worker's
        on_snapshot fires but each gates on busy → D sits in
        `devices/{deviceId}/queue/` with no `assignedWorker`. Firestore
        won't re-fire ADDED for D when a worker becomes idle (it's not
        a new doc anymore), so without this rescan D would orphan.

        Called from the worker's finally block (after every job ends).
        On entry, the worker is idle. Scan the queue collection for
        unclaimed start-action docs, attempt Firestore transactional
        claim on the first match, and enqueue locally. Single attempt
        per call — if the claim races and loses, the next worker idle
        triggers another rescan.

        No-op in single-worker mode (workerCount=1): the on_snapshot
        listener doesn't gate on busy there, so all docs are enqueued
        as they arrive; orphan path never reached.
        """
        if not _firebase_db:
            return
        if load_worker_count() <= 1:
            return  # single-worker mode — listener never gates on busy
        # Shutdown gate (2026-05-22): STOP scheduled exit makes the
        # worker's `finally` block trigger an idle-rescan even though
        # the process is about to die. Without this gate, the rescan
        # would claim a deferred-FIFO doc, log "picking up orphan",
        # then exit before completing the side effects — leaving the
        # doc half-claimed in Firestore (`assignedWorker` set, no
        # actual work happening). The next respawn's stale-skip
        # would then delete the legit FIFO entry. Skip the whole
        # rescan when a stop is in flight.
        if _exit_scheduled:
            log(f"[idle-rescan] worker {WORKER_ID}: skipping — exit scheduled", "INFO")
            return
        if _QUEUE_STATE.get("running") or _job_queue.qsize() > 0:
            return  # not actually idle
        did = load_device_id()
        if not did:
            return
        try:
            col = _firebase_db.collection("devices").document(did).collection("queue")
            candidates = await asyncio.to_thread(lambda: list(col.limit(20).stream()))
        except Exception as e:
            log(f"[idle-rescan] worker {WORKER_ID}: scan failed: {e}", "WARN")
            return

        # FIFO sort (PR 3, 2026-05-21): pick oldest unclaimed first so an
        # orphan that's been sitting longer gets picked up before a newer
        # one. Stream order is by doc-id (random for auto-IDs), so without
        # sorting the rescan was effectively "first-found-wins" — could
        # leave the OLDEST orphan sitting under a newer one. Sort by
        # client-ms `timestamp` ASC, missing-timestamp docs sort LAST
        # (Firestore `order_by` excludes them entirely, so in-process
        # sort handles them gracefully without a separate fallback pass).
        def _fifo_key(_snap):
            _hd = _snap.to_dict() or {}
            _ts = _hd.get("timestamp")
            if isinstance(_ts, (int, float)) and _ts > 0:
                return (0, _ts, _snap.id)
            return (1, 0, _snap.id)
        candidates.sort(key=_fifo_key)

        for snap in candidates:
            d = snap.to_dict() or {}
            if d.get("processed") or d.get("assignedWorker"):
                continue
            if (d.get("action") or "start") != "start":
                continue  # cancel/resume handled by their own paths
            # Re-check busy + shutdown before each claim attempt (could
            # have flipped mid-scan: a sibling claimed a different doc
            # OR a STOP landed between candidates).
            if _exit_scheduled or _QUEUE_STATE.get("running") or _job_queue.qsize() > 0:
                return

            # Conditional-update claim (replaces TX-based claim that
            # masked BeginTransaction failures — 2026-05-22 root-cause
            # fix). Helper handles retries + race-loss + unexpected
            # errors with full __context__ surfacing.
            _outcome = await asyncio.to_thread(
                _try_claim_queue_doc, snap.reference, WORKER_ID,
                "[idle-rescan]",
            )
            if _outcome is None:
                # Claim helper logged the root cause — surface a
                # topic-bearing marker too so the silent continue isn't
                # invisible. submittedBy + research_id help cross-
                # account triage when the orphan is a sharer's doc.
                log(
                    f"[idle-rescan] worker {WORKER_ID}: claim error — skipping {(d.get('researchId') or '')[:8]}… "
                    f"topic={(d.get('topic') or '')[:40]!r} submittedBy={(d.get('submittedBy') or '?')[:8]}",
                    "WARN",
                )
                continue
            if _outcome is False:
                log(
                    f"[idle-rescan] worker {WORKER_ID}: lost to sibling — skipping {(d.get('researchId') or '')[:8]}… "
                    f"topic={(d.get('topic') or '')[:40]!r} submittedBy={(d.get('submittedBy') or '?')[:8]}",
                    "INFO",
                )
                continue

            # Final shutdown gate: even with a successful claim, don't
            # proceed if a STOP scheduled exit during the claim RPC.
            # The claim wrote assignedWorker + claimedAt — release them
            # via DELETE_FIELD so the doc returns to "unclaimed" state
            # and the next worker (sibling or respawned-self) can pick
            # it up cleanly. Best-effort: if the release write fails,
            # commit 3's stale-skip discrimination handles the zombie.
            if _exit_scheduled:
                log(
                    f"[idle-rescan] worker {WORKER_ID}: claimed {(d.get('researchId') or '')[:8]}… "
                    f"but exit scheduled — releasing claim",
                    "WARN",
                )
                try:
                    from google.cloud.firestore import DELETE_FIELD as _DF
                    await asyncio.to_thread(
                        snap.reference.update,
                        {"assignedWorker": _DF, "claimedAt": _DF},
                    )
                except Exception as _re:
                    log(f"[idle-rescan] release-claim failed (non-fatal): {_re}", "WARN")
                return

            # Won — replicate the listener's minimal start-action side
            # effects: validate fields, flip research doc to ongoing,
            # delete the queue doc, enqueue locally. We DON'T replicate
            # the full listener (stale-skip, cancel handling, etc.) —
            # those are only relevant for newly-arrived docs the
            # listener already gated.
            uid = (d.get("uid") or "").strip()
            research_id = (d.get("researchId") or "").strip()
            topic = (d.get("topic") or "").strip()
            if not uid or not research_id or not topic:
                log(f"[idle-rescan] claimed doc missing required fields — deleting", "WARN")
                try:
                    await asyncio.to_thread(snap.reference.delete)
                except Exception:
                    pass
                continue

            run_id = f"{safe_name(topic)}_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            log(f"[idle-rescan] worker {WORKER_ID}: picking up orphan {research_id[:8]}… ({topic[:40]}) submittedBy={(d.get('submittedBy') or '?')[:8]}")

            # Flip research-doc status to ongoing (the listener path
            # writes this when the worker is idle on first dequeue;
            # mirror that here for the rescanned doc). Clear the stale
            # queue fields too — pre-fix, the orphan carried its
            # deferred-state `queuePosition` / `queuedBehindRunId` /
            # `queuedBehindTitle` into ongoing, briefly rendering a
            # stale "queue position" badge on the tile during the
            # listener round-trip before the FE filter on `status` took
            # effect. Listener claim path does this cleanup via the
            # status_payload branches; mirror here for parity.
            try:
                from google.cloud.firestore import DELETE_FIELD as _DF_RESCAN
                _update_research_doc(uid, research_id, {
                    "backendRunId": run_id,
                    "status": "ongoing",
                    "queuePosition": _DF_RESCAN,
                    "queuedBehindRunId": _DF_RESCAN,
                    "queuedBehindTitle": _DF_RESCAN,
                })
            except Exception as _ue:
                log(f"[idle-rescan] research-doc update failed: {_ue}", "WARN")

            # Delete the queue doc — we've claimed and are about to run.
            try:
                await asyncio.to_thread(snap.reference.delete)
            except Exception:
                pass

            # Enqueue locally. Use _safe_enqueue mirror of the listener
            # path so cancellations between claim and enqueue still
            # reach the right place.
            _safe_enqueue(_job_queue, {
                "topic": topic,
                "email": d.get("email", ""),
                "config": d.get("config", {}),
                "run_id": run_id,
                "uid": uid,
                "research_id": research_id,
                "brief_text": (d.get("briefText") or "").strip(),
                "user_sources": d.get("userSources") or [],
                "user_links": d.get("userLinks") or [],
            }, source="idle-rescan")
            # Real-time deferred-doc renumber (2026-05-22): the just-
            # claimed orphan was at some position N in the global FIFO
            # (often head — idle-rescan picks the oldest unclaimed).
            # Shift everyone behind it up by one. Fire-and-forget via
            # to_thread; the scan is bounded to limit(50).
            _recompute_deferred = _QUEUE_STATE.get("recompute_deferred_fn")
            if _recompute_deferred is not None:
                try:
                    asyncio.create_task(asyncio.to_thread(_recompute_deferred))
                except Exception as _re:
                    log(
                        f"[idle-rescan] deferred-recompute launch failed: {_re}",
                        "WARN",
                    )
            return  # one at a time — let the worker process this before next rescan

    async def _job_worker():
        """Process pipeline jobs one at a time from the queue."""
        while True:
            job = await _job_queue.get()
            # 2026-05-25: clear stale stop flag before gate-wait. A
            # prior HARD_RESET that fired while the worker was idle
            # (no run in flight to consume the flag) leaves
            # _controls.is_stop()=True dangling. Without this reset,
            # the next job's gate-wait check at ~29094 sees the stale
            # flag and bails with "cancelled during gate wait — skipping
            # run_pipeline" — the user's Kalki repro from today's E2E
            # (HARD_RESET at 18:13:28 with no active run → Kalki claimed
            # at 18:20:45 → bailed 18:20:46 without ever starting).
            # Safe because (a) cancels for in-queue jobs remove from
            # queue (never reach pop), (b) cancels for THIS job's gate-
            # pending phase will RE-SET the flag via the gate_pending_job
            # match at research.py:4421, (c) cancels for the running job
            # set the flag and run_pipeline consumes it internally.
            try:
                _controls.reset()
            except Exception:
                pass
            # 2026-05-11: gate on prior run's FE-P5 completion. Phases
            # 4+5 are FE-owned — BE PIPELINE COMPLETE fires after P3,
            # but the actual run isn't done until FE Doc+Email lands.
            # Without this gate, the next pipeline's BE phases race
            # against the prior pipeline's FE-P4/P5 (resource contention,
            # listener cross-pollination, the queue-pileup symptom).
            # Pass `job` so the gate can detect resume-of-same-rid and
            # skip (otherwise circular deadlock — see helper docstring).
            await _wait_for_prior_fe_completion(_current_job=job)
            # 2026-05-12: stop-requested-during-gate-wait shortcut. The
            # cancel handler at research.py:2208 flips status="stopped"
            # and request_stop()s when a cancel matches gate_pending_job.
            # Honor it here so we don't proceed to launch a browser for
            # an already-cancelled job. Clear the stop flag so the next
            # job runs clean.
            try:
                if _controls.is_stop():
                    log(f"[worker] job {job.get('research_id', '')[:8]}… cancelled during gate wait — skipping run_pipeline", "INFO")
                    try:
                        _controls.reset()
                    except Exception:
                        pass
                    # The listener bumped the pending counter when it
                    # claimed this job; we're skipping the running-flag
                    # flip below where the normal decrement lands. Drain
                    # the counter here so a stop-during-gate-wait
                    # doesn't leak a slot (would falsely defer all
                    # subsequent submissions on this worker).
                    _pending_enq_dec()
                    _job_queue.task_done()
                    # Keep the queue running but drop this job entirely.
                    continue
            except Exception:
                pass
            _QUEUE_STATE["running"] = True
            _QUEUE_STATE["current_job"] = job
            # Listener-replay counter decrement (Bug B fix). Tied to
            # the running-flag flip rather than the earlier
            # `_job_queue.get()` because `_wait_for_prior_fe_completion`
            # above can suspend the coroutine for the full
            # BE_PHASES_TIMEOUT_SEC window; decrementing at get() would
            # let the gate at research.py:~4106 look idle (counter=0,
            # qsize=0, running still False) for minutes while this
            # worker is occupied waiting on FE-P5. Setting running=True
            # FIRST then dec'ing closes that window.
            _pending_enq_dec()
            # Multi-worker claim sentinel. Written here (at dequeue, the
            # earliest point we own the job) so a sibling worker booting
            # up sees our claim before doing rehydration auto-resume.
            # Cleared in the finally block below. Helper docstring at
            # research.py:_write_worker_lock explains the flat-layout
            # choice + crash-leftover defenses.
            _write_worker_lock(
                WORKER_ID,
                job.get("research_id") or "",
                job.get("run_id") or "",
            )
            # 2026-05-28: mark this worker busy in the device-doc
            # `busyWorkerIds` array. Runs for ALL workers (not gated
            # to worker-1) — FE QueuedBanner stall detector reads
            # `busyWorkerIds.length < workerCount` to know whether
            # any worker is idle while a queued run sits at position
            # #1. Released by _clear_current_run_id_best_effort on
            # finally / exit / next-boot. Idempotent via array_union.
            try:
                _did_bw = load_device_id()
                if _firebase_db and _did_bw:
                    from google.cloud.firestore import ArrayUnion as _AU
                    # 2026-05-28: also seed this worker's per-sharer usage
                    # entry for the owner's "Shared with" popup. Dotted-path
                    # `workers.<id>` merges only this slot (never clobbers a
                    # sibling worker's entry). Runs for ALL workers (mirrors
                    # busyWorkerIds), unlike the worker-1-only currentRun*
                    # block below — so a sharer's run on worker N>=2 still
                    # gets a green badge. Cleared in
                    # _clear_current_run_id_best_effort on every exit. phase
                    # starts at 0; emit_event refreshes it live per worker.
                    _firebase_db.collection("devices").document(_did_bw).update({
                        "busyWorkerIds": _AU([WORKER_ID]),
                        f"workers.{WORKER_ID}": {
                            "uid": job.get("uid") or "",
                            "runId": job.get("research_id") or "",
                            "title": (job.get("topic") or "")[:60],
                            "phase": 0,
                            "totalPhases": 6,
                        },
                    })
            except Exception as _bw_pub_err:
                log(
                    f"[device] busyWorkerIds claim (w{WORKER_ID}) failed (non-fatal): {_bw_pub_err}",
                    "DEBUG",
                )
            log(f"Starting queued job: {job['topic'][:60]}")
            # Publish currentRunId on the device doc so sharers / sibling
            # tabs can see "device is busy with run X" and render the
            # QueuedBanner correctly when they submit a NEW research.
            # Pre-fix, sharers' FE only had their OWN cachedResearches to
            # check, so the owner's in-flight run was invisible and the
            # sharer's submission rendered the Phase 0 INIT tile instead
            # of "queued behind X". The synth-user write is gated by the
            # devices-doc allow-list rule (62530fb + 2026-05-20 expansion
            # to include currentRunId fields).
            # Multi-worker (2026-05-21): only worker 1 publishes
            # currentRunId. The device doc has a single currentRunId
            # field; if both workers wrote, the value would flip-flop
            # to whichever flipped last. FE QueuedBanner reads this to
            # show "device busy with X" — with worker-1-only writes,
            # the banner reflects w1's current run while w2's runs
            # complete invisibly to the banner. Sibling tabs / sharers
            # firing a 3rd run still see "queued" status because both
            # worker queues are busy; the specific title may be w1's
            # rather than w2's. Acceptable compromise — FE display
            # quirk does not affect actual execution. PR 3 may expand
            # this to a currentRunIds.{workerId} map field.
            if WORKER_ID == 1:
                try:
                    _did = load_device_id()
                    if _firebase_db and _did:
                        # 2026-05-26: publish phase=0 alongside the run-meta
                        # fields. The phase_start emit at ~line 26504 will
                        # re-write the same value within a few hundred ms
                        # — but BEFORE that fires there's a gap (job claim
                        # → run_pipeline entry → first phase_start) during
                        # which the FE QueuedBanner's "Current run is in
                        # Phase X" head-phase line either rendered the
                        # PRIOR run's stale phase or stayed silent (if the
                        # field was never set on this device). Publishing
                        # phase=0 on pickup eliminates that window. Paired
                        # with the matching clear in
                        # `_clear_current_run_id_best_effort` so STOP /
                        # hard_reset don't leak a stale value into the
                        # next run's pickup.
                        _now_ms = int(time.time() * 1000)
                        _crun_patch: dict = {
                            "currentRunId": job.get("research_id") or "",
                            "currentRunOwnerUid": job.get("uid") or "",
                            "currentRunTitle": (job.get("topic") or "")[:60],
                            "currentRunStartedAt": _now_ms,
                            "currentRunPhase": 0,
                            "currentRunPhaseStartedAt": _now_ms,
                        }
                        _firebase_db.collection("devices").document(_did).update(_crun_patch)
                except Exception as _crun_err:
                    log(f"[device] currentRunId publish failed (non-fatal): {_crun_err}", "DEBUG")
            # Snapshot AFTER popping so an exit during run_pipeline can
            # restore both the running job AND remaining queue. Without the
            # current_job param a Phoenix restart would lose this in-flight
            # research.
            _persist_pending_queue(current_job=job)
            # Flip this run's research doc from queued → ongoing. No-op for
            # the very first start in an idle backend (already ongoing).
            flip_outcome = _flip_queued_to_ongoing(job.get("uid"), job.get("research_id"))
            # Q8 (2026-04-30): bail ONLY when the flip is skipped AND the
            # actual current status is a terminal/recovery state (cancelled
            # mid-run, paused after BE restart, watchdog-stopped, user-
            # discarded, fully completed). For ANY active state — ongoing
            # (FE optimistically pre-flipped before BE picked up the job —
            # this is the normal happy path), paused (user paused mid-run,
            # wants to resume), queued (flip already handled it) — proceed
            # with run_pipeline. The original bug was that a stale
            # paused_backend_restart from a crashing supervisor child
            # caused run_pipeline to launch a browser and the orphan-
            # Chrome killer chewed live siblings. Bailing too eagerly
            # blocks every legitimate run because FE writes ongoing
            # client-side before the BE worker dequeues. None outcome
            # (no firebase / missing args / exception) is treated as
            # legacy success — proceed.
            BAIL_STATUSES = {
                "paused_backend_restart",
                "paused_backend_restart_failed",
                "stopped_by_watchdog",
                "terminated_by_user_discard",
                "stopped",
                "cancelled",
                "completed",
            }
            should_run = True
            if flip_outcome and flip_outcome.startswith("skipped(") and flip_outcome.endswith(")"):
                actual_status = flip_outcome[len("skipped("):-1]
                if actual_status in BAIL_STATUSES:
                    should_run = False
                    # 2026-05-11: flag bail as errored so the queue gate
                    # short-circuits on the next dequeue. Without this,
                    # a bail on paused_backend_restart* (which is NOT in
                    # the gate's terminal status set) would wedge the
                    # next gate for the full 4200s fallback.
                    _QUEUE_STATE["_errored"] = True
                    log(f"[worker] Bailing on job — actual_status={actual_status} (terminal/recovery), skipping run_pipeline to spare sibling browsers", "INFO")
                else:
                    log(f"[worker] Proceeding despite skipped flip — actual_status={actual_status} is active (FE pre-flipped or normal mid-run resume)", "INFO")
            try:
                if should_run:
                    # Fix D (2026-05-27): ACTIVE-TIME-aware outer ceiling. The
                    # old asyncio.wait_for counted raw wall-clock, so a run
                    # that legitimately waited on a user decision (or was
                    # paused) got mislabeled "stuck" and killed at the 5h mark.
                    # Run run_pipeline as a task and only accrue toward the
                    # ceiling while it's doing ACTIVE work — never while
                    # _controls.is_pause() (HV/login/user pause) or
                    # _controls._awaiting_user (blocked on await_phase_decision).
                    # Genuine active-spin deadlocks still trip it. _controls is
                    # a per-PROCESS singleton (reset in place, never rebound),
                    # so each worker is independently guarded ⇒ N-worker safe.
                    # On breach we raise asyncio.TimeoutError, reusing the
                    # existing handler below unchanged.
                    _pipe_task = asyncio.ensure_future(
                        run_pipeline(topic=job["topic"], email=job.get("email", ""),
                                     verbose=True, resume_dir=job.get("resume_dir"),
                                     config=job.get("config"), run_id=job.get("run_id"),
                                     uid=job.get("uid"), research_id=job.get("research_id"),
                                     brief_text=job.get("brief_text", ""),
                                     user_sources=job.get("user_sources") or [],
                                     user_links=job.get("user_links") or []))
                    _wd_active_sec = 0.0
                    _wd_tick = 10.0
                    while not _pipe_task.done():
                        try:
                            await asyncio.sleep(_wd_tick)
                        except asyncio.CancelledError:
                            # Worker loop / server shutting down — cancel the
                            # pipeline and propagate (drain with BaseException
                            # so its finally blocks run first).
                            _pipe_task.cancel()
                            try:
                                await _pipe_task
                            except BaseException:
                                pass
                            raise
                        if not (_controls.is_pause() or _controls._awaiting_user):
                            _wd_active_sec += _wd_tick
                        if _wd_active_sec >= WORKER_OUTER_TIMEOUT_SEC and not _pipe_task.done():
                            _pipe_task.cancel()
                            # Drain with BaseException (CancelledError is
                            # BaseException-derived since 3.8) so run_pipeline's
                            # finally blocks (browser close, etc.) complete
                            # before we raise — mirrors asyncio.wait_for's own
                            # cancel-then-await semantics.
                            try:
                                await _pipe_task
                            except BaseException:
                                pass
                            raise asyncio.TimeoutError(
                                f"pipeline exceeded {WORKER_OUTER_TIMEOUT_SEC}s active-time ceiling")
                    # Natural completion: surface result / re-raise any
                    # run_pipeline exception exactly as asyncio.wait_for did
                    # (the except Exception handler below catches it).
                    await _pipe_task
            except asyncio.TimeoutError:
                # Q7 outer-ceiling deadlock guard. Mark the doc, request
                # cooperative stop, schedule hard exit. Daemon-loop
                # respawns a fresh worker; pending jobs drain on the
                # next process.
                hours = WORKER_OUTER_TIMEOUT_SEC // 3600
                log(f"[worker-watchdog] Pipeline exceeded {hours}h ACTIVE-time ceiling (excludes paused / user-decision waits) — declaring stuck and scheduling restart", "ERROR")
                try:
                    _controls.request_stop()
                except Exception:
                    pass
                if _firebase_db and job.get("uid") and job.get("research_id"):
                    _update_research_doc(job["uid"], job["research_id"], {
                        "status": "stopped_by_watchdog",
                        "summary": f"Stopped — pipeline exceeded {hours}h ceiling",
                    })
                # 2026-05-11: error path — daemon-restart will reset
                # _QUEUE_STATE anyway, but flag for completeness.
                _QUEUE_STATE["_errored"] = True
                _schedule_server_exit("worker-watchdog")
            except Exception as e:
                log(f"Pipeline job error: {e}", "ERROR")
                # 2026-05-11: error path — flag so the next dequeue's
                # gate doesn't block waiting for FE-P5 on a run that
                # will never reach it.
                _QUEUE_STATE["_errored"] = True
            finally:
                # Capture before clearing — `current_job` is the job that
                # just finished. We need its uid+rid to clear stale queue
                # fields below; `_recompute_queue_positions` only patches
                # the *remaining* queued docs, not the one that just left.
                completed = _QUEUE_STATE.get("current_job") or {}
                _QUEUE_STATE["running"] = False
                _QUEUE_STATE["current_job"] = None
                # Release multi-worker claim sentinel. Best-effort —
                # stale locks from process kills are caught by
                # _scan_sibling_locks_for_research's PID-liveness + 8h
                # started_at-age guards.
                _delete_worker_lock(WORKER_ID)
                # Clear currentRunId on device doc — release the "device
                # is busy" signal so the next submitter's FE doesn't think
                # we're still mid-run. Best-effort. Shared helper covers
                # all exit paths (STOP / hard_reset / watchdog / etc.)
                # too via _schedule_server_exit at research.py:_schedule_server_exit
                # 2026-05-22).
                _clear_current_run_id_best_effort("job-finally")
                # 2026-05-11: record what the next dequeue's gate needs.
                # last_be_done_at=0 on error/watchdog paths short-circuits
                # the gate (since FE-P5 will never write "completed").
                _errored = _QUEUE_STATE.pop("_errored", False)
                # 2026-05-15: skip gate-state writes if a hard_reset is
                # in progress. Without this guard, a worker finishing
                # within hard_reset's exit window resurrects the wedged
                # prior-run pointer the user just clicked Reset Backend
                # to escape. The lock acquisition makes the check-and-act
                # atomic w.r.t. hard_reset's clear+persist (research.py:
                # ~1920) — without the lock, a thread schedule between
                # our flag-read and our state-write lets hard_reset's
                # clear land BEFORE our write, and our write resurrects
                # the uid_X we should be discarding.
                _hr_lock = _QUEUE_STATE.get("_hard_reset_lock")
                if _hr_lock is not None:
                    with _hr_lock:
                        if not _QUEUE_STATE.get("_hard_reset_in_progress"):
                            _QUEUE_STATE["last_completed_uid"] = completed.get("uid")
                            _QUEUE_STATE["last_completed_rid"] = completed.get("research_id")
                            _QUEUE_STATE["last_be_done_at"] = 0 if _errored else int(time.time() * 1000)
                else:
                    # Lock not initialised yet (impossible at runtime: the
                    # worker only runs inside run_server, which sets up
                    # the lock at research.py:~24058 before launching the
                    # worker — kept as belt-and-braces).
                    _QUEUE_STATE["last_completed_uid"] = completed.get("uid")
                    _QUEUE_STATE["last_completed_rid"] = completed.get("research_id")
                    _QUEUE_STATE["last_be_done_at"] = 0 if _errored else int(time.time() * 1000)
                _job_queue.task_done()
                # Clear the just-finished job's queue tracking fields from
                # Firestore. `_flip_queued_to_ongoing` already deletes
                # these on the queued→ongoing flip (:20869-20874), but if
                # the worker raced through completion before the listener
                # delivered the "ongoing" intermediate frame — or the run
                # errored / was watchdog-stopped without the flip running
                # — the doc retains stale `queuePosition` /
                # `queuedBehindRunId` / `queuedBehindTitle`. Reopening the
                # chat then wedges QueuedBanner because liveStatus reads
                # them as still-queued. Idempotent on already-cleared docs.
                _cuid, _crid = completed.get("uid"), completed.get("research_id")
                if _firebase_db and _cuid and _crid:
                    from google.cloud.firestore import DELETE_FIELD as _DF
                    _update_research_doc(_cuid, _crid, {
                        "queuePosition": _DF,
                        "queuedBehindRunId": _DF,
                        "queuedBehindTitle": _DF,
                    })
                # Shift remaining queued jobs up one position.
                _recompute_queue_positions()
                # Re-snapshot post-completion (current cleared, pending may
                # have been cancelled/reordered).
                # 2026-05-15: re-check the hard-reset flag under the same
                # lock as hard_reset's clear+persist. Without the lock, a
                # hard_reset can fire between our flag-check and our
                # persist, and we'd snapshot stale memory to disk AFTER
                # hard_reset already wrote a clean snapshot — racing past
                # the very write the lock was added to protect.
                _hr_lock2 = _QUEUE_STATE.get("_hard_reset_lock")
                if _hr_lock2 is not None:
                    with _hr_lock2:
                        if not _QUEUE_STATE.get("_hard_reset_in_progress"):
                            _persist_pending_queue(current_job=None)
                else:
                    _persist_pending_queue(current_job=None)
                # Multi-worker idle rescan (2026-05-21). If a sibling
                # worker was busy when a queue doc arrived AND so was I,
                # the on_snapshot listener gated both of us → doc orphaned
                # in devices/{deviceId}/queue/ with no assignedWorker.
                # Now that I'm idle, check for unclaimed docs and pick
                # one up. No-op in single-worker mode. Fire-and-forget —
                # the worker's next loop iteration awaits _job_queue.get()
                # which the rescan's _safe_enqueue feeds.
                try:
                    asyncio.create_task(_rescan_queue_for_unclaimed())
                except Exception as _re:
                    log(f"[idle-rescan] launch failed (non-fatal): {_re}", "WARN")

    # Worker + Firestore start listener are launched below in the direct
    # startup path (before `await server.serve()`). We used to ALSO register
    # an `@app.on_event("startup")` handler that did the same thing as a
    # belt-and-suspenders fallback — but FastAPI did fire it, and the result
    # was TWO concurrent `_job_worker` tasks. Queue #2 got popped by worker
    # B while worker A was still running #1, a second Browser(PROFILE_DIR)
    # was instantiated, and Browser.start()'s orphan-Chrome sweep killed
    # #1's browser mid-flight. Single-worker startup is now the only path.

    @app.get("/api/queue")
    async def get_queue_status():
        """Get queue status: current job + pending count."""
        return {"running": bool(_QUEUE_STATE.get("running")), "pending": _job_queue.qsize()}

    @app.get("/api/health")
    async def health_check():
        """Server health check. Q8: includes lastHeartbeatAt (millis since
        epoch) + consecutive heartbeat failure count so the FE can sanity-
        check 'device offline despite localhost responsive' cases. The
        Account-tile online indicator reads Firestore lastHeartbeat — if
        Firestore writes are failing but local HTTP is fine, this endpoint
        shows the disparity directly."""
        return {
            "status": "ok",
            "running": bool(_QUEUE_STATE.get("running")),
            "pending": _job_queue.qsize(),
            "lastHeartbeatAt": _last_heartbeat_at_ms,
            "heartbeatFailures": _heartbeat_failures,
            # #717 — supervisor watchdog signals. lastTickAt is a per-worker
            # liveness pulse (every worker bumps it via _firebase_reconnect_loop),
            # so the watchdog spots a wedged event loop on ANY worker — not just
            # worker 1 (the only one that writes lastHeartbeatAt). `relinking`
            # tells the watchdog this worker is in a legit up-to-15-min revoke
            # relink poll and must not be force-respawned.
            "lastTickAt": _last_loop_tick_ms,
            "downReason": _firebase_down_reason,
            "relinking": _firebase_down_reason == "revoked",
        }

    @app.patch("/api/runs/{run_id}/config")
    async def update_config(run_id: str, request_data: dict):
        """Update pipeline config mid-run. Pipeline checks config.json before each phase."""
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)
        config_path = queue / "config.json"
        try:
            existing = json.loads(config_path.read_text(encoding="utf-8")) if config_path.exists() else {}
        except Exception:
            existing = {}
        existing.update(request_data)
        config_path.write_text(json.dumps(existing, indent=2), encoding="utf-8")
        # Forward to in-memory controls (for mid-phase config awareness)
        _controls.update_config(existing)
        # Emit to Firestore pipeline_events so frontend gets it
        emit_event("config_updated", config=existing)
        return {"status": "config_updated", "id": run_id, "config": existing}

    @app.delete("/api/runs/{run_id}")
    async def delete_run(run_id: str):
        """Delete a completed/stopped run's queue dir + cascade-delete the
        matching Firestore documents/audios/messages/pipeline_events/
        commands subcollections. Without the cascade, partial docs from
        failed runs would linger in Firestore forever."""
        import shutil
        queue = queues_root / run_id
        if not queue.exists():
            return JSONResponse({"error": "not found"}, 404)

        # ── Cascade Firestore cleanup before nuking the owner file ──
        owner_path = queue / "owner.json"
        if owner_path.exists() and _firebase_db:
            try:
                owner = json.loads(owner_path.read_text(encoding="utf-8"))
                uid = owner.get("uid")
                rid = owner.get("researchId")
                if uid and rid:
                    research_ref = _firebase_db.collection("users").document(uid) \
                        .collection("researches").document(rid)
                    # Delete known subcollections. Firestore requires enumerating
                    # docs and deleting individually — no native recursive delete
                    # in the Python SDK's positional-arg API.
                    for sub in ("documents", "audios", "messages",
                                "pipeline_events", "commands"):
                        try:
                            for sd in research_ref.collection(sub).stream():
                                try: sd.reference.delete()
                                except Exception: pass
                        except Exception as _se:
                            log(f"[delete_run] subcollection {sub} sweep: {_se}", "WARN")
                    # Finally drop the research doc itself
                    try: research_ref.delete()
                    except Exception as _rde:
                        log(f"[delete_run] research doc delete: {_rde}", "WARN")
                    log(f"[delete_run] cascaded Firestore for users/{uid}/researches/{rid}")
            except Exception as _oe:
                log(f"[delete_run] owner.json parse failed: {_oe}", "WARN")

        try:
            shutil.rmtree(queue)
        except Exception as e:
            return JSONResponse({"error": str(e)}, 500)
        return {"status": "deleted", "id": run_id}

    @app.post("/api/runs")
    async def start_run(request_data: dict):
        """Start a new pipeline run. Queued if another is already running.
        Body: {topic, email?, briefText?, config?: {agents, skipPhases, videoEnabled, emailEnabled}}

        briefText: inline brief content that bypasses Phase 1 brief generation.
        When provided, Phase 1 is skipped and Phase 2 runs against this brief."""
        topic = request_data.get("topic")
        if not topic or not topic.strip():
            return JSONResponse({"error": "topic is required"}, 400)
        topic = topic.strip()
        email = request_data.get("email", "")
        uid = request_data.get("uid", "")  # Firebase user ID for Firestore bridge
        config = request_data.get("config", {})
        brief_text = (request_data.get("briefText") or "").strip()
        # Validate config
        agents_cfg = config.get("agents", {"chatgpt": True, "gemini": True, "claude": True})
        if not any(agents_cfg.values()):
            return JSONResponse({"error": "at least one agent must be enabled"}, 400)
        from datetime import datetime as _dt
        run_id = f"{safe_name(topic)}_{_dt.now().strftime('%Y%m%d_%H%M%S')}"
        await _job_queue.put({"topic": topic, "email": email, "config": config,
                              "run_id": run_id, "uid": uid, "brief_text": brief_text})
        position = _job_queue.qsize()
        is_running = bool(_QUEUE_STATE.get("running"))
        status = "running" if position <= 1 and not is_running else f"queued (position {position})"
        return {"status": status, "topic": topic, "queue_position": position, "id": run_id}

    @app.get("/api/runs/{run_id}/documents/{doc_type}")
    async def get_document(run_id: str, doc_type: str):
        """Get document content. doc_type: brief, chatgpt, gemini, claude."""
        # All documents live in documents/ (brief included)
        path = queues_root / run_id / "documents" / f"{doc_type}.md"
        if not path.exists():
            path = queues_root / run_id / f"{doc_type}.md"  # Legacy fallback
        if not path.exists():
            return JSONResponse({"error": "not found"}, 404)
        content = path.read_text(encoding="utf-8")
        return {
            "type": doc_type,
            "name": f"{doc_type}.md",
            "size": f"{len(content) / 1024:.0f} KB",
            "content": content,
        }

    @app.get("/api/runs/{run_id}/audio/{filename}")
    async def get_audio(run_id: str, filename: str):
        """Serve audio file from podcasts directory."""
        from fastapi.responses import FileResponse as _FileResponse
        # Sanitize filename to prevent path traversal
        safe = Path(filename).name
        path = queues_root / run_id / "podcasts" / safe
        if not path.exists():
            return JSONResponse({"error": "audio not found"}, 404)
        mime_map = {".m4a": "audio/mp4", ".mp3": "audio/mpeg",
                    ".wav": "audio/wav", ".webm": "audio/webm"}
        media_type = mime_map.get(path.suffix.lower(), "application/octet-stream")
        return _FileResponse(str(path), media_type=media_type, filename=safe)

    # Banner shows localhost so users can copy-click; uvicorn still binds
    # to 0.0.0.0 below so the FE web app can reach this BE.
    log(f"Starting API server on http://localhost:{port}")
    log(f"  GET  /api/runs                     — List all runs")
    log(f"  POST /api/runs                     — Start new run {{topic, email}}")
    log(f"  GET  /api/runs/{{id}}                — Run details + meta")
    log(f"  GET  /api/runs/{{id}}/documents/{{type}} — Document content (brief/chatgpt/gemini/claude)")
    log(f"  GET  /api/runs/{{id}}/events         — Progress events")
    log(f"  WS   /ws/{{run_id}}                  — Real-time event stream")
    # Start worker directly (don't rely on @app.on_event which is deprecated and
    # sometimes doesn't fire reliably with newer FastAPI versions)
    # Initialize Firebase Admin SDK for Firestore bridge
    init_firebase()
    # Load run analytics for realistic ETAs
    load_analytics()
    # Track D: device identity loads via load_device_id() / the OS
    # keystore. No legacy researchToken to fetch here — if init_firebase
    # already failed, the user needs to run --pair first.
    # 2026-05-11: hoist queue-gate state rehydration above worker
    # creation. The full disk-restore block at the bottom of serve
    # (rehydrates pending + current_job) runs much later, after the
    # Firestore start listener has already enqueued docs. If the
    # worker had been created first, it could dequeue a Firestore-
    # rehydrated job and call _wait_for_prior_fe_completion() with
    # fresh-init _QUEUE_STATE (last_completed_uid=None → gate skips)
    # BEFORE the disk snapshot's gate sub-object lands. That'd race
    # the first post-restart pipeline against the previous run's
    # in-flight FE-P5. Pure dict mutation here — no I/O dependency on
    # the later block.
    try:
        if _pending_queue_path.exists():
            _snap = json.loads(_pending_queue_path.read_text(encoding="utf-8"))
            _gate = _snap.get("gate") or {}
            _gate_uid = _gate.get("last_completed_uid")
            _gate_rid = _gate.get("last_completed_rid")
            if _gate_uid and _gate_rid:
                # Orphan detection — three cases get treated as terminal so
                # the gate doesn't wedge the next submission:
                #   (a) Prior research doc DELETED (user purged it from
                #       /researches → snap.exists False).
                #   (b) Prior status is non-terminal ("queued"/"ongoing")
                #       → BE crashed mid-run; without a worker to
                #       advance it, the status never becomes terminal.
                #   (c) Read failed entirely (network, transient denial)
                #       → safer to release than wedge for 70 min.
                # In every case we drop the gate-state IN-MEMORY *and* on
                # disk; otherwise the next BE restart's rehydrate re-loads
                # the same zombie pointer and the wedge re-engages.
                _is_orphan = False
                _orphan_reason = ""
                if _firebase_db:
                    try:
                        _prior_snap = _firebase_db.collection("users") \
                            .document(_gate_uid).collection("researches") \
                            .document(_gate_rid).get()
                        if not _prior_snap.exists:
                            _is_orphan = True
                            _orphan_reason = "doc deleted"
                        else:
                            _prior_status = (_prior_snap.to_dict() or {}).get("status", "")
                            # Terminal-non-success statuses also qualify as
                            # orphan: a prior run that errored / stopped /
                            # was watchdog-killed never reaches FE-P5
                            # (Phase 4 + 5 only run on a clean BE finish),
                            # so the queue-gate's wait-for-prior-FE-P5
                            # would block forever (BE_PHASES_TIMEOUT_SEC =
                            # 4200s fallback). Treat them like queued/
                            # ongoing — clear the gate so the next run
                            # can dequeue. Pre-fix the gate wedged every
                            # new submission with "waiting for prior run
                            # … FE-P5 completion" for 70 minutes whenever
                            # the prior run hit any failure path.
                            if _prior_status in (
                                "queued", "ongoing",
                                "error", "errored", "stopped",
                            ):
                                _is_orphan = True
                                _orphan_reason = f"status={_prior_status}"
                    except Exception as _orphan_check_err:
                        log(f"[queue-gate] orphan-check read failed — treating as orphan: {_orphan_check_err}", "DEBUG")
                        _is_orphan = True
                        _orphan_reason = "read failed"
                if _is_orphan:
                    log(f"[queue-gate] prior-run {_gate_rid[:8]}… orphaned ({_orphan_reason}) — clearing gate state")
                    # Best-effort status flip (will silently 403 for legacy
                    # research docs without a deviceId field, since
                    # deviceUpdatingFor requires resource.data.deviceId match;
                    # don't depend on it).
                    try:
                        _update_research_doc(_gate_uid, _gate_rid, {
                            "status": "stopped",
                            "lastError": "Backend restarted before this run reached completion. Resubmit to retry.",
                        })
                    except Exception:
                        pass
                    # Drop gate state both in memory AND on disk so next
                    # restart doesn't re-engage the wedge.
                    _QUEUE_STATE["last_completed_uid"] = None
                    _QUEUE_STATE["last_completed_rid"] = None
                    _QUEUE_STATE["last_be_done_at"] = 0
                    try:
                        _clean = {**_snap, "gate": {
                            "last_completed_uid": None,
                            "last_completed_rid": None,
                            "last_be_done_at": 0,
                        }}
                        _tmp = _pending_queue_path.with_suffix(".json.tmp")
                        _tmp.write_text(json.dumps(_clean, indent=2), encoding="utf-8")
                        os.replace(str(_tmp), str(_pending_queue_path))
                    except Exception as _persist_err:
                        log(f"[queue-gate] orphan-clear persist failed (continuing): {_persist_err}", "WARN")
                else:
                    _QUEUE_STATE["last_completed_uid"] = _gate_uid
                    _QUEUE_STATE["last_completed_rid"] = _gate_rid
                    _QUEUE_STATE["last_be_done_at"] = int(_gate.get("last_be_done_at") or 0)
                    log(f"[queue-gate] pre-worker rehydrate: prior-run {_gate_rid[:8]}…")
    except Exception as _e:
        log(f"[queue-gate] pre-worker rehydrate failed (non-fatal): {_e}", "WARN")

    worker_task = asyncio.create_task(_job_worker())
    log("Job worker started (direct)")
    # Firestore start listener — must fire exactly once per serve session.
    # This used to live inside an @app.on_event("startup") handler alongside
    # a second _job_worker create_task; that duplicated the worker and caused
    # the queue race where #2 killed #1's browser mid-run. Single-start here.
    if _firebase_db:
        start_firestore_start_listener(_job_queue, asyncio.get_event_loop())
    # Reset-recovery watcher. Armed unconditionally so a post-Reset
    # boot (keystore wiped → init_firebase returned False above) can
    # still auto-relink the moment the owner enters the new code at
    # Account → Add Device. Loop is idle while _firebase_db is set.
    asyncio.create_task(_revoked_recovery_loop())
    # Transient-outage reconnect watcher (#717/#718). Armed unconditionally on
    # EVERY worker so a dropped Firestore client (DNS/network blip) self-heals on
    # a tight backoff — no manual restart, no 1-hour-cap wait. Idle while
    # _firebase_db is set. After any reconnect it schedules a clean respawn (when
    # idle) so the fresh boot re-binds every Firestore listener.
    asyncio.create_task(_firebase_reconnect_loop())
    # Start heartbeat so frontend can show Online/Offline status.
    # Multi-worker (2026-05-21): only worker 1 heartbeats. FE only needs
    # a single "device alive" signal and devices/{deviceId}.lastHeartbeat
    # is a single field — both workers writing it would double the
    # Firestore RPC rate for no FE benefit. If worker 1 dies but worker
    # 2 survives, the heartbeat goes stale and FE flips Offline; that's
    # accurate from the FE's perspective because there's no longer a
    # primary serve binding port 8000.
    heartbeat_task = None
    if _firebase_db and WORKER_ID == 1:
        heartbeat_task = asyncio.create_task(_heartbeat_loop())
        log(f"Heartbeat started ({HEARTBEAT_INTERVAL_SEC}s interval)")

    if _firebase_db:
        # Aegis pulse — slow standing-watch heartbeat in the log every 60s
        # while the queue is idle. Alternates ◆/◇ glyph so a tail of the
        # log shows a faint pulse instead of flat repetition. Suppressed
        # during active pipeline runs (the job worker is already chatty).
        # Per-worker (each worker logs its own pulse, prefixed with its
        # ID) so a tail of any worker's log shows liveness.
        async def _aegis_pulse_loop():
            glyphs = ("◆", "◇")
            i = 0
            try:
                while True:
                    await asyncio.sleep(60)
                    if not _QUEUE_STATE.get("running"):
                        log(f"[aegis] worker {WORKER_ID}: {glyphs[i % 2]} standing watch")
                        i += 1
            except asyncio.CancelledError:
                return
        asyncio.create_task(_aegis_pulse_loop())
        # Periodic orphan sweep: existence-based cleanup of local queues/
        # dirs whose Firestore research doc has been deleted. Worker-1
        # only — the queues/ tree is shared across workers and sweep is
        # idempotent; running it N times wastes Firestore RPC budget and
        # opens a small race window where two sweeps could each see the
        # same dir and contend on rmtree.
        if WORKER_ID == 1:
            asyncio.create_task(_orphan_sweep_loop())
            log(f"[orphan-sweep] started ({ORPHAN_SWEEP_INTERVAL_SEC}s interval)")
        # Refresh the paired device doc so the Account page sees this PC
        # online immediately on server start.
        paired_uid = load_paired_uid()
        # Boot-clear: release this worker's footprint on the device doc.
        # The helper handles both responsibilities — array_remove'ing
        # THIS WORKER_ID from busyWorkerIds (all workers; powers the FE
        # multi-worker idle signal) AND, for worker-1, clearing the
        # currentRun* mirror fields. Backstop for any exit path that
        # bypassed `_schedule_server_exit` — process SIGKILL, OOM,
        # daemon-loop crash, `--retire` (externally killed). Without
        # this, a stale currentRunId persists into the next session AND
        # a leaked busyWorkerIds entry would make the FE think a worker
        # is busy when it isn't (false-positive on the queue-stall
        # detector's worker-idle check).
        #
        # If a job is auto-resumed by rehydration below, its dequeue at
        # research.py:~26948 will re-write the fields. The 1-15s window
        # between this clear and re-write is invisible to the FE
        # because the cross-user fallback predicate requires
        # `currentRunId` set; cleared state ⇒ fallback not engaged ⇒ no
        # banner.
        _clear_current_run_id_best_effort(f"worker-{WORKER_ID}-boot")
        # Track every Firestore research_id touched by rehydration — used by
        # the disk-restore block below so an ongoing run that got marked
        # paused_backend_restart isn't falsely re-enqueued from
        # pending_queue.json (would run twice). Hoisted out of the try so
        # the disk-restore block downstream can reference it even if
        # rehydration raised partway through.
        _rehydrated_rids: "set[str]" = set()
        if paired_uid:
            # The heartbeat loop writes lastHeartbeat + status to
            # devices/{deviceId} every 5s, so a startup-side eager write
            # is no longer necessary — the first heartbeat tick (within
            # ~5s of --serve binding the port) brings the Account-page
            # tile online.

            # Queue rehydration: recover mid-run runs from the previous
            # daemon session. Browser/CUA state is gone, so we either
            # mark them paused_backend_restart (FE shows a Resume CTA)
            # or auto-resume on supervised devices (re-enqueue with
            # resume_dir from checkpoint). Queued-status docs are NOT
            # rehydrated here — the on_snapshot listener replays every
            # queue doc as ADDED on first attach and the FIFO pre-query
            # handles them across all submitters (owner + sharers).
            #
            # Per-query 15s wall-clock cap via asyncio.wait_for + to_thread.
            # The sync .get() can hang indefinitely if the gRPC channel got
            # into a bad state (observed once during E2E with the wrong
            # paired_uid synth-vs-owner mismatch). A hung query here blocks
            # the event loop and prevents uvicorn from binding port 8000 ->
            # `--resurrect` handoff fails its API health check.
            #
            # Multi-worker (2026-05-21): only worker 1 runs the
            # Firestore rehydration. Pre-fix, every worker would scan
            # the same users/{uid}/researches collection, re-enqueue
            # every queued doc into its own local job_queue, and both
            # would race the same Browser(_profile_dir(K)) for the same
            # backendRunId — double-running the pipeline. Disk-restore
            # (the pending_queue_*.json snapshot) is per-worker file
            # (commit 4) so it's already safe; only the Firestore-side
            # rehydration needs gating. Workers 2+ rely on the listener
            # claim path + idle-rescan to pick up unclaimed Firestore
            # queue docs on next dequeue.
            rehydrated = 0
            orphaned = 0
            if WORKER_ID != 1:
                log(f"[rehydration] worker {WORKER_ID}: skipping Firestore rehydration (worker-1-only)", "INFO")
            try:
                if WORKER_ID != 1:
                    raise _SkipRehydration()  # local sentinel, caught below
                researches_col = _firebase_db.collection("users").document(paired_uid) \
                    .collection("researches")
                # 2026-05-22: dropped "queued" from rehydration. The
                # Firestore on_snapshot listener replays every existing
                # queue doc as ADDED on first attach (research.py:3458)
                # and the FIFO pre-query (3955-3989) handles ordering
                # across all submitters (owner + sharers). Rehydrating
                # queued docs from `users/{paired_uid}/researches/` was
                # owner-tree-only AND created a dual-processing race:
                # worker 1 ran the rehydrated job locally while
                # worker 2's idle-rescan claimed the UNTOUCHED Firestore
                # queue doc and ran a second copy. The on-disk safety
                # net for "FE wrote research doc but queue write failed"
                # is covered by the FE-side orphan-queue watchdog
                # (commit 4 of this batch). "ongoing" status is still
                # rehydrated for paused_backend_restart marking +
                # supervised auto-resume — independent code path.
                for status_val in ("ongoing",):
                    try:
                        snaps = await asyncio.wait_for(
                            asyncio.to_thread(
                                lambda sv=status_val: list(
                                    researches_col.where("status", "==", sv).get()
                                )
                            ),
                            timeout=15.0,
                        )
                    except asyncio.TimeoutError:
                        log(f"Rehydrate query ({status_val}) timed out after 15s — skipping", "WARN")
                        continue
                    except Exception as e:
                        err_str = str(e)
                        if (
                            "403" in err_str
                            or "PERMISSION_DENIED" in err_str
                            or "Missing or insufficient permissions" in err_str
                        ):
                            # Track D: synth-device-user can't read
                            # users/{ownerUid}/researches/* under the
                            # current rules (allow read: if request.auth.uid
                            # == userId). The device-side queue at
                            # devices/{deviceId}/queue/* is the source of
                            # truth for new submissions; on-disk queues/
                            # checkpoints handle mid-run resume. Skip
                            # Firestore-side rehydration silently.
                            #
                            # Structural fix (cleanup #552): add a
                            # `deviceMemberOf` Firestore rule analogous to
                            # `deviceWritingTo` so the synth user can read
                            # research docs routed to its device.
                            log(
                                f"[rehydrate:{status_val}] read denied (synth user can't read user-tree research docs) — relying on device-queue + on-disk state",
                                "DEBUG",
                            )
                        else:
                            log(f"Rehydrate query ({status_val}) failed: {e}", "WARN")
                        continue
                    for snap in snaps:
                        data = snap.to_dict() or {}
                        research_id = snap.id
                        _rehydrated_rids.add(research_id)
                        if status_val == "ongoing":
                            # Sibling-claim guard (2026-05-22). If a
                            # sibling worker on this device has the lock
                            # for this research_id (.worker.N.lock with
                            # live PID + fresh started_at), the sibling
                            # is actively running the pipeline.
                            # Auto-resuming locally would dual-spawn
                            # (two browsers, two FE phase streams, two
                            # Doc/Email writes). Skip both the auto-
                            # resume AND the paused_backend_restart
                            # marker — the sibling owns this run and
                            # the FE should keep seeing "ongoing".
                            #
                            # Repro context: STOP killed worker 1, the
                            # user fired a new submission while worker 1
                            # was restarting, worker 2 claimed it via
                            # the start-listener (Firestore queue doc
                            # deleted post-claim — no Firestore signal
                            # available 4s later when worker 1 booted),
                            # worker 1 saw research status=ongoing +
                            # queue_dir on disk and re-enqueued the
                            # same job. The lock files are the only
                            # cross-worker signal that survives queue-
                            # doc deletion.
                            _sibling_holders = _scan_sibling_locks_for_research(
                                research_id, WORKER_ID
                            )
                            if _sibling_holders:
                                h = _sibling_holders[0]
                                _age_s = (int(time.time() * 1000) - h["started_at"]) // 1000
                                log(
                                    f"[rehydrate] {research_id[:24]}… already claimed by sibling "
                                    f"worker {h['worker_id']} (PID {h['pid']}, started {_age_s}s ago) "
                                    f"— skipping auto-resume + paused mark to avoid dual-spawn",
                                    "INFO",
                                )
                                continue
                            # Mid-run runs need either auto-resume (supervised
                            # device — supervisor just respawned us, take the
                            # natural next step and resume the runs too) or a
                            # paused_backend_restart marker so the FE shows a
                            # Resume CTA. Browser + CUA state is gone either
                            # way, but checkpoints on disk
                            # (documents/*.md + checkpoint.json + delivery.json
                            # under queues/{run}/) let detect_resume_phase()
                            # skip already-completed phases.
                            #
                            # Resolve the run's device's supervised flag — if
                            # supervised, attempt auto-resume so the FE's
                            # passive banner clears via pipeline_resumed
                            # without any user click.
                            device_id = data.get("deviceId") or ""
                            is_supervised = False
                            if device_id:
                                # Track D: top-level devices/{deviceId} is the
                                # canonical home; synth user CAN read its own
                                # doc (rule: auth.uid == syntheticDeviceUid).
                                # Legacy users/{ownerUid}/devices/{deviceId}
                                # read 403s under synth auth, so try modern
                                # first and only fall back on miss.
                                try:
                                    dev_snap = _firebase_db.collection("devices") \
                                        .document(device_id).get()
                                    if dev_snap.exists:
                                        is_supervised = bool(
                                            (dev_snap.to_dict() or {})
                                            .get("supervised", False))
                                except Exception as _de:
                                    log(f"Rehydrate: top-level device read failed for {research_id[:24]}…: {_de}", "WARN")
                                if not is_supervised:
                                    try:
                                        dev_snap = _firebase_db.collection("users") \
                                            .document(paired_uid) \
                                            .collection("devices") \
                                            .document(device_id).get()
                                        if dev_snap.exists:
                                            is_supervised = bool(
                                                (dev_snap.to_dict() or {})
                                                .get("supervised", False))
                                    except Exception:
                                        # Synth user is denied on user-tree
                                        # devices subcollection — expected.
                                        pass

                            auto_resumed = False
                            if is_supervised:
                                run_id = data.get("backendRunId") or ""
                                if run_id:
                                    queue_dir = Path(__file__).parent / "queues" / run_id
                                    # Only auto-resume if the on-disk artifacts
                                    # are intact and the run wasn't terminally
                                    # stopped (.stop sentinel set by Stop /
                                    # watchdog T3).
                                    if queue_dir.exists() and not (queue_dir / ".stop").exists():
                                        cp = load_checkpoint(queue_dir)
                                        topic = (cp or {}).get("topic", "") or data.get("topic", "")
                                        cfg = dict(data.get("pipelineConfig") or {})
                                        if "skippedPhases" in cfg and "skipPhases" not in cfg:
                                            cfg["skipPhases"] = cfg.pop("skippedPhases")
                                        if topic:
                                            # Clear any stale .pause signal so
                                            # the resumed run drains immediately.
                                            p_signal = queue_dir / ".pause"
                                            if p_signal.exists():
                                                try: p_signal.unlink()
                                                except Exception: pass
                                            if _safe_enqueue(_job_queue, {
                                                "topic": topic,
                                                "email": "",  # delivery prefs are on disk in delivery.json
                                                "config": cfg,
                                                "run_id": run_id,
                                                "resume_dir": str(queue_dir),
                                                "uid": paired_uid,
                                                "research_id": research_id,
                                            }, source="rehydrate-supervised-auto-resume"):
                                                rehydrated += 1
                                                auto_resumed = True
                                                log(f"Rehydrate: auto-resumed {research_id[:24]}… on supervised device")

                            if not auto_resumed:
                                # Either unsupervised, or supervised-but-couldn't-
                                # auto-resume (queue_dir missing, run_id absent,
                                # .stop sentinel set, etc.). Mark
                                # paused_backend_restart so the FE recovery
                                # banner fires — actionable for unsupervised,
                                # passive-with-2min-escalation for supervised.
                                try:
                                    researches_col.document(research_id).update({
                                        "status": "paused_backend_restart",
                                        "summary": "Backend restarted mid-run — hit Resume to pick up from the last checkpoint.",
                                    })
                                    orphaned += 1
                                except Exception as e:
                                    log(f"Rehydrate: mark paused_backend_restart failed for {research_id}: {e}", "WARN")
                        # queued-status branch removed 2026-05-22 — see
                        # comment at the for-loop above for rationale.
                        # The on_snapshot listener handles queued docs.
                if rehydrated or orphaned:
                    log(f"Queue rehydration: auto-resumed {rehydrated} supervised run(s), marked {orphaned} as paused_backend_restart")
            except _SkipRehydration:
                # Worker N≥2 — intentional skip, not an error. Already
                # logged above; no-op here.
                pass
            except Exception as e:
                log(f"Queue rehydration failed: {e}", "WARN")

        # ── pending_queue.json restoration (Phoenix T3 fallback) ──────────
        # Firestore-driven rehydration above is the source of truth, but a
        # research that hadn't yet reached `status=queued` (e.g. crashed in
        # the put_nowait → Firestore-write window) won't appear there. The
        # disk snapshot covers that gap. Dedupe by research_id so we don't
        # double-enqueue something Firestore already restored — including
        # ongoing runs that got marked paused_backend_restart and shouldn't
        # silently re-launch from a stale disk snapshot.
        try:
            if _pending_queue_path.exists():
                snap = json.loads(_pending_queue_path.read_text(encoding="utf-8"))
                # 2026-05-11: rehydrate queue-gate state so the worker
                # gate respects a still-in-flight FE-P5 across daemon
                # restart. The "gate" key was added 2026-05-11; legacy
                # snapshots without it default to empty (gate becomes a
                # no-op for that one boot — same as fresh start).
                _gate = snap.get("gate") or {}
                if _gate.get("last_completed_uid"):
                    _QUEUE_STATE["last_completed_uid"] = _gate.get("last_completed_uid")
                    _QUEUE_STATE["last_completed_rid"] = _gate.get("last_completed_rid")
                    _QUEUE_STATE["last_be_done_at"] = int(_gate.get("last_be_done_at") or 0)
                    log(f"[queue-gate] rehydrated prior-run state for {(_gate.get('last_completed_rid') or '')[:8]}…")
                # Seed dedupe with anything Firestore-rehydration touched
                # (ongoing-status only — queued docs are handled by the
                # listener, not rehydration), then add what's currently
                # in the in-memory queue (auto-resumed supervised runs).
                already = set(_rehydrated_rids)
                try:
                    for q in list(_job_queue._queue):
                        rid = (q or {}).get("research_id") or ""
                        if rid:
                            already.add(rid)
                except Exception:
                    pass
                # Restore current_job FIRST if it was mid-flight (so it
                # resumes ahead of pending). Then the rest of pending in
                # original order.
                cur = snap.get("current") or None
                disk_jobs = []
                if cur and (cur.get("research_id") or "") not in already:
                    disk_jobs.append(cur)
                for j in (snap.get("pending") or []):
                    rid = (j or {}).get("research_id") or ""
                    if rid and rid in already:
                        continue
                    disk_jobs.append(j)
                # Funnel each disk-restored job through _safe_enqueue
                # (Q7) — it does the same Firestore existence check the
                # Q1 inline loop did, plus a status-whitelist (queued /
                # ongoing / paused_backend_restart). Fail-closed posture
                # is preserved (helper skips on missing/error/no-firebase
                # rather than re-fire). The skipped-count is rolled up;
                # per-job reasons are in the helper's own logs.
                restored = 0
                skipped = 0
                for j in disk_jobs:
                    if _safe_enqueue(_job_queue, j, source="disk-restore"):
                        restored += 1
                    else:
                        skipped += 1
                if restored or skipped:
                    log(f"[pending_queue] Disk snapshot processed: restored={restored}, skipped={skipped}")
                else:
                    log("[pending_queue] Disk snapshot empty — nothing to restore")
        except Exception as e:
            log(f"[pending_queue] restore failed: {e}", "WARN")

        # Device-scoped command channel — receives hard_reset and any
        # future device-level controls (vs research-scoped commands which
        # ride users/{uid}/researches/{rid}/commands). Listener lives for
        # the lifetime of --serve. Best-effort: if the device isn't
        # paired yet, this no-ops; the next --serve restart after pairing
        # will pick it up.
        try:
            _paired_uid_for_cmds = load_paired_uid() or ""
            _device_id_for_cmds = load_device_id() or ""
            if _paired_uid_for_cmds and _device_id_for_cmds:
                _start_device_command_listener(
                    _paired_uid_for_cmds,
                    _device_id_for_cmds,
                    loop=asyncio.get_event_loop(),
                )
        except Exception as _dce:
            log(f"[device-cmds] listener attach failed: {_dce}", "WARN")

    # ── Branded --serve banner — 'aegis, standing watch' ──
    # Shows which account this backend is paired to, where it's listening,
    # and how to tear it down. Keeps the structural DNA of --pair /
    # --resurrect / --retire (SUPER RESEARCH wordmark + dim rule + Latin
    # tagline) so the three commands feel like a matched set.
    _branded_header("aegis", _BOLD + _ACCENT, "standing watch")
    _paired_uid_now = load_paired_uid()
    _device_id_now = load_device_id() or ""
    # Pull owner identity + device metadata from the device doc, not
    # the (synth-user-inaccessible) users/{uid}/ path. ownerEmail +
    # ownerDisplayName are written by the claim Cloud Function;
    # name + os are written by initiate-pair and user-editable from
    # the FE Account-page tile.
    _meta = _fetch_device_meta()
    _paired_email = _meta.get("ownerEmail", "") or ""
    _paired_name = _meta.get("ownerDisplayName", "") or ""
    if _paired_name and _paired_email:
        _paired_val = f"{_c(_BOLD, _paired_name)}  {_c(_DIM, '(' + _paired_email + ')')}"
    elif _paired_email:
        _paired_val = _c(_BOLD, _paired_email)
    elif _paired_uid_now:
        _paired_val = f"{_c(_DIM, _paired_uid_now[:8] + '…')}"
    else:
        _paired_val = _c(_DIM, "(not paired)")
    _device_name = (
        _meta.get("name", "")
        or _meta.get("machineName", "")
        or _meta.get("hostname", "")
        or (f"{_device_id_now[:8]}…" if _device_id_now else "(none)")
    )
    _device_os = _meta.get("os", "") or ""
    if _device_id_now:
        if _device_os:
            _device_val = (
                f"{_c(_BOLD, _device_name)}  {_c(_DIM, '(' + _device_os + ')')}  "
                f"{_c(_OK, '(active)')}"
            )
        else:
            _device_val = f"{_c(_BOLD, _device_name)}  {_c(_OK, '(active)')}"
    else:
        _device_val = _c(_DIM, "(none)")
    _ctx_rows_serve = [
        ("Paired to", _paired_val),
        ("Device",    _device_val),
        ("Local API", _c(_BOLD, f"http://localhost:{port}")),
        ("Heartbeat", _c(_BOLD, f"{HEARTBEAT_INTERVAL_SEC}s cadence")),
    ]
    _bat_serve = _battery_state()
    if _bat_serve:
        _ctx_rows_serve.append(("Power", _c(_DIM, _bat_serve)))
    _render_context_strip(_ctx_rows_serve)
    print()
    print(f"  {_c(_BOLD + _ACCENT, '  Listening for pipeline jobs.')}  {_c(_DIM, 'Keep this terminal open.')}")
    print()
    print(f"  {_c(_DIM, 'Stop:')}  {_c(_BOLD, 'Ctrl+C')}")

    # Context-aware hint: fresh users running --serve without pairing see
    # the banner succeed (port bound, listeners started) but no jobs will
    # ever arrive until the app claims a token. Surface --pair. If paired
    # but On Startup isn't enabled, surface --resurrect so users discover
    # the "run in background" capability.
    # _detect_supervised runs schtasks subprocess — Windows can occasionally
    # hang the call past its own timeout, parking startup before uvicorn binds.
    # Treat it as best-effort (default to False), banner just shows --resurrect
    # action whether supervised or not — UX is harmless either way.
    try:
        _currently_supervised = await asyncio.wait_for(
            asyncio.to_thread(_detect_supervised), timeout=8.0,
        )
    except (asyncio.TimeoutError, Exception):
        _currently_supervised = False
    if not (_device_id_now and _paired_uid_now):
        print()
        print(f"  {_c(_WARN, '⚠')}  Not paired yet — jobs will be ignored until this machine is paired.")
        _render_next_actions([
            ("python research.py --pair", "pair this machine to your account"),
        ])
    elif not _currently_supervised:
        _render_next_actions([
            ("python research.py --resurrect", "enable On Startup (auto-start in background)"),
            ("python research.py --unpair",    "fully disconnect this machine"),
        ])
    else:
        _render_next_actions([
            ("python research.py --retire", "disable On Startup"),
            ("python research.py --unpair", "fully disconnect this machine"),
        ])

    config = uvicorn.Config(app, host="0.0.0.0", port=port, log_level="info")
    server = uvicorn.Server(config)
    try:
        await server.serve()
    finally:
        worker_task.cancel()
        if heartbeat_task:
            heartbeat_task.cancel()
        global _token_relink_watch, _device_cmd_watch
        if _token_relink_watch is not None:
            try:
                _token_relink_watch.unsubscribe()
            except Exception:
                pass
            _token_relink_watch = None
        if _device_cmd_watch is not None:
            try:
                _device_cmd_watch.unsubscribe()
            except Exception:
                pass
            _device_cmd_watch = None
        # No explicit "offline" stamp on shutdown — the FE derives
        # online/offline from heartbeat age (60s threshold), which the
        # device doc ages into naturally once heartbeats stop. Under
        # daemon-loop supervision, stamping on shutdown would oscillate
        # green↔red on every respawn cycle.


# ── Setup ────────────────────────────────────────────────────────────────────

def _fresh_user_mode_id_token() -> "str | None":
    """Return a fresh Firebase ID token for the synth device user, or None
    if the keystore is empty / refresh token revoked. Used by user-mode
    code paths that need to authenticate against an FE Cloud Function
    (e.g. /api/devices/unpair-self, oauth-callback hand-offs). Forces a
    refresh on every call so the token can't be expired by the time the
    HTTP request lands."""
    try:
        from auth import credentials, keystore
        from auth.v2_flow import WEB_API_KEY
    except ImportError as e:
        log(f"user-mode id-token: auth/ import failed: {e}", "WARN")
        return None
    iuid = keystore.install_uuid()
    if keystore.try_recover(iuid) is None:
        return None
    try:
        creds = credentials.RefreshTokenCredentials(iuid, WEB_API_KEY)
        creds.refresh(None)  # type: ignore[arg-type]
        return creds.token  # type: ignore[no-any-return]
    except credentials.RevokedError:
        log("user-mode id-token: refresh token revoked — wiping keystore", "WARN")
        keystore.clear_all(iuid)
        return None
    except Exception as e:
        log(f"user-mode id-token: refresh failed: {e}", "WARN")
        return None


def _pair_patch_device(
    device_id: str,
    set_fields: "dict[str, object]",
    delete_fields: "list[str] | None" = None,
) -> bool:
    """PATCH the top-level `devices/{deviceId}` doc directly via Firestore
    REST, authenticated with the synth user's fresh idToken from the
    keystore. Used during pair to mirror state (pairConfirmedAt,
    supervised intent) to Firestore in real time without depending on a
    constructed gRPC client — the keystore is bootstrapped within
    `cmd_pair_v2` but `_firebase_db` (Track-D-user-scoped client) isn't
    initialized until `--serve`.

    `set_fields` accepts bool / str / int values and converts to the
    Firestore REST primitive shape. `delete_fields` are added to the
    updateMask but omitted from the body so the server clears them.
    Best-effort: returns False on any failure, never raises.
    """
    id_token = _fresh_user_mode_id_token()
    if not id_token:
        log("[pair-patch] no id_token — keystore not yet bootstrapped", "WARN")
        return False
    try:
        from auth.v2_flow import PROJECT_ID as _PID
        import requests as _requests
    except ImportError as e:
        log(f"[pair-patch] import failed: {e}", "WARN")
        return False
    update_mask_fields = list(set_fields.keys()) + list(delete_fields or [])
    params = [("updateMask.fieldPaths", f) for f in update_mask_fields]
    fields_body: "dict[str, dict]" = {}
    for k, v in set_fields.items():
        if isinstance(v, bool):
            fields_body[k] = {"booleanValue": v}
        elif isinstance(v, int):
            fields_body[k] = {"integerValue": str(v)}
        elif isinstance(v, str):
            fields_body[k] = {"stringValue": v}
        else:
            fields_body[k] = {"stringValue": str(v)}
    url = (
        f"https://firestore.googleapis.com/v1/projects/{_PID}"
        f"/databases/(default)/documents/devices/{device_id}"
    )
    try:
        resp = _requests.patch(
            url,
            params=params,
            headers={
                "Authorization": f"Bearer {id_token}",
                "Content-Type": "application/json",
            },
            json={"fields": fields_body},
            timeout=10,
        )
    except _requests.RequestException as e:
        log(f"[pair-patch] network error: {e}", "WARN")
        return False
    if resp.status_code == 200:
        return True
    log(
        f"[pair-patch] HTTP {resp.status_code}: {resp.text[:200]}",
        "WARN",
    )
    return False


def _cleanup_partial_pair(device_id: str) -> None:
    """Reverse a partially-completed pair when the user Ctrl+Cs (or the
    flow errors out) between Stage 1 exchange and Stage 5 completion.

    Track D writes pairConfirmedAt:true to the device doc the moment
    exchange succeeds so the FE Account tile appears at Stage 1 — but
    that means a mid-flow cancellation would leave a "confirmed" tile
    with no working backend behind it. This helper:
      1) POSTs /api/devices/unpair-self with the just-minted idToken
         (full server-side retire — deletes device doc + revokes synth
         Firebase user, drops the pollSecretHash entry).
      2) Wipes the OS keystore.
      3) Removes research_config.json.
      4) Best-effort supervisor disarm (schtasks /Delete on Windows /
         launchctl bootout on mac / systemctl --user disable on linux)
         in case the cancellation happened during Stage 5 arming.

    Best-effort throughout — never raises, prints WARN on each failed
    step so the user can run `--unpair` manually if anything sticks."""
    import requests as _requests
    import subprocess as _sp
    # Server-side: delete the device doc + revoke synth user. Requires
    # an idToken which is still mintable from the just-bootstrapped
    # keystore at this point (we haven't wiped it yet).
    try:
        from auth.v2_flow import FE_BASE_URL as _FE_BASE_URL
        _id_token = _fresh_user_mode_id_token()
        if _id_token:
            try:
                _resp = _requests.post(
                    f"{_FE_BASE_URL}/api/devices/unpair-self",
                    headers={"Authorization": f"Bearer {_id_token}"},
                    json={"deviceId": device_id},
                    timeout=10,
                )
                if _resp.status_code == 200:
                    log("[cleanup] device retired server-side ✓", "INFO")
                else:
                    log(
                        f"[cleanup] /unpair-self HTTP {_resp.status_code} — "
                        f"run --unpair to clean up manually",
                        "WARN",
                    )
            except Exception as e:
                log(f"[cleanup] server-side retire failed: {e}", "WARN")
        else:
            log("[cleanup] no idToken — skipping server-side retire", "WARN")
    except Exception as e:
        log(f"[cleanup] auth import failed: {e}", "WARN")
    # Local: wipe keystore + research_config.json so the next --pair
    # starts from a clean slate.
    try:
        from auth import keystore as _ks
        _ks.clear_all(_ks.install_uuid())
        log("[cleanup] OS keystore cleared", "INFO")
    except Exception as e:
        log(f"[cleanup] keystore wipe failed: {e}", "WARN")
    try:
        if RESEARCH_CONFIG_PATH.exists():
            RESEARCH_CONFIG_PATH.unlink()
            log("[cleanup] research_config.json removed", "INFO")
    except Exception as e:
        log(f"[cleanup] config wipe failed: {e}", "WARN")
    # In-memory caches — anything still running in this process can't
    # re-read pre-wipe values.
    global _device_id, _device_paired_uid
    _device_id = None
    _device_paired_uid = None
    # Supervisor: best-effort disarm in case Ctrl+C landed during Stage
    # 5 arming. Failures are silent — `--retire` is the user's fallback.
    try:
        _plat = _supervisor_platform()
        if _plat == "Windows":
            _sp.run(
                ["schtasks", "/Delete", "/TN", _SUPERVISOR_TASK_NAME, "/F"],
                capture_output=True, timeout=10, creationflags=_PS_NO_WINDOW,
            )
        elif _plat == "Darwin":
            _sp.run(
                ["launchctl", "bootout", f"gui/{os.getuid()}/{_SUPERVISOR_PLIST_LABEL}"],
                capture_output=True, timeout=10,
            )
        elif _plat == "Linux":
            _sp.run(
                ["systemctl", "--user", "disable", "--now", _SUPERVISOR_UNIT_NAME],
                capture_output=True, timeout=10,
            )
    except Exception:
        pass


# ── Pair-flow API key verifiers ───────────────────────────────────────
# Cheap live-API calls invoked during --pair Stage 3 to confirm a pasted
# key actually authenticates before we persist it. Verification at paste
# time means the operator catches typos / revoked keys / wrong-account
# pastes immediately, instead of mid-pipeline. All verifiers return one
# of three string statuses:
#   "ok"            — key authenticates
#   "auth_failed"   — provider rejected the key (401/403/specific error
#                     code) — re-prompt makes sense
#   "network_error" — timeout / connection / unrecognized error — the
#                     caller treats this as "save anyway, the user can
#                     run a job and see what happens" so offline pairs
#                     and transient blips don't block setup
def _verify_anthropic_key(key: str) -> str:
    """Verify an Anthropic API key against the live API.

    Calls `models.list()` with a 5s timeout and `max_retries=0` so the
    pair UX feels snappy on flaky connections. `models.list` requires a
    well-formed, recognized key but does NOT exercise message-API
    billing — a never-funded key still passes here and fails at first
    `messages.create`. Good enough for pair-time format-checking; full
    billing verification belongs in the first job's error surface."""
    if not key:
        return "auth_failed"
    try:
        import anthropic as _anth
    except ImportError:
        # Anthropic SDK missing — can't verify; treat as network so the
        # caller saves the key anyway and the operator installs the SDK
        # separately. Unblocks the pair flow.
        return "network_error"
    try:
        _anth.Anthropic(api_key=key, timeout=5.0, max_retries=0).models.list()
        return "ok"
    except _anth.AuthenticationError:
        return "auth_failed"
    except _anth.PermissionDeniedError:
        # 403 — workspace cap / org-disabled. Same UX outcome as a bad
        # key (user needs to paste a different one), so we re-prompt.
        return "auth_failed"
    except (_anth.APITimeoutError, _anth.APIConnectionError):
        return "network_error"
    except Exception:
        # Catch-all for unexpected SDK errors. We'd rather save an
        # unverified key than crash the pair flow.
        return "network_error"


def _verify_gemini_key(key: str) -> str:
    """Verify a Gemini / Google AI API key against the live API.

    Issues an unauthenticated `GET /v1beta/models?key=...` (5s timeout)
    and inspects the JSON error body. Google's URL-param auth returns
    HTTP 400 with `error.status=INVALID_ARGUMENT` and `details[].reason=
    API_KEY_INVALID` for structurally bad keys, and HTTP 403 with
    `PERMISSION_DENIED` for revoked / scope-disabled keys. We only
    re-prompt on those two specific signals — 429 quota and 5xx blips
    fall through to network_error so the user isn't blocked."""
    if not key:
        return "auth_failed"
    try:
        import requests as _requests
    except ImportError:
        return "network_error"
    url = "https://generativelanguage.googleapis.com/v1beta/models"
    try:
        resp = _requests.get(url, params={"key": key}, timeout=5.0)
    except _requests.RequestException:
        return "network_error"
    if resp.status_code == 200:
        return "ok"
    try:
        err = (resp.json() or {}).get("error", {}) or {}
        reasons = {
            str((d or {}).get("reason", ""))
            for d in (err.get("details") or [])
        }
    except Exception:
        return "network_error"
    if "API_KEY_INVALID" in reasons:
        return "auth_failed"
    if str(err.get("status", "")) == "PERMISSION_DENIED":
        return "auth_failed"
    # 429 quota, 5xx, or unrecognized error shape — save and let the
    # operator find out at first run. Don't block the pair flow on a
    # transient provider issue.
    return "network_error"


async def _pair_prompt_one_key(label: str, example: str, help_url: str) -> str:
    """Single-key paste loop for --pair Stage 4/5.

    Returns the trimmed key string on paste, or "" on skip / Ctrl+C / EOF.
    Skip is first-class — pair completes regardless; missing keys surface
    at first-job via the cua_unavailable / narrator-disabled paths (both
    already user-recoverable from the FE alert).

    Uses `getpass.getpass` so the key DOES NOT echo to the terminal or
    scrollback — important on shared Linux/macOS machines and when
    screen-sharing during setup. Falls back to `input` only on platforms
    where getpass can't suppress echo (rare).
    """
    import getpass as _getpass
    print(f"  {_c(_BOLD, label)}  {_c(_DIM, f'— get one at {help_url}')}")
    prompt = (
        f"  {_c(_ACCENT, '>')}  Paste {label} key ({example})  "
        f"{_c(_DIM, 'or [S]kip — input hidden:')} "
    )
    while True:
        try:
            raw = await asyncio.to_thread(_getpass.getpass, prompt)
        except (EOFError, KeyboardInterrupt):
            print()
            return ""
        except _getpass.GetPassWarning:
            # No-echo support unavailable on this terminal — fall back to
            # echoed input rather than crashing. User loses the privacy
            # benefit but the prompt still works.
            try:
                raw = await asyncio.to_thread(input, prompt)
            except (EOFError, KeyboardInterrupt):
                print()
                return ""
        s = (raw or "").strip()
        # Strip surrounding quotes — users often copy from .env-style snippets
        if len(s) >= 2 and s[0] in ('"', "'") and s[-1] == s[0]:
            s = s[1:-1].strip()
        if not s:
            print(f"  {_c(_WARN, '     Enter a key or type s to skip.')}")
            continue
        if s.lower() in ("s", "skip"):
            return ""
        # Loose sanity: real keys are well over 20 chars and contain no whitespace
        if len(s) < 20 or any(ch.isspace() for ch in s):
            print(f"  {_c(_WARN, '     That does not look like a valid key. Try again or type s to skip.')}")
            continue
        return s


async def _pair_prompt_one_key_with_verify(
    label: str,
    example: str,
    help_url: str,
    verifier,
    max_attempts: int = 3,
) -> str:
    """Paste-and-verify loop for --pair Stage 3.

    Wraps `_pair_prompt_one_key` with an API-call verifier (cheap
    `models.list`-style probe). A visible `_async_spinner_ctx` runs
    during the probe so the operator sees verification is happening
    (the probe itself is up to 5s — silent would feel like a hang).
    On verify result:
      - "ok": print `✓ {label} key verified.` + return the key —
        caller persists it.
      - "auth_failed": warn + re-prompt up to `max_attempts` times.
        After the last fail, ask "save anyway? [y/N]" — yes returns
        the last pasted key with a stern warning, no returns "" (skip).
      - "network_error": warn + return the key as-is. Offline-tolerant
        pair — the user can still set up on a flaky connection; jobs
        fail-loud at first run if the key is actually bad.

    Skip path (`_pair_prompt_one_key` returns "") never invokes the
    verifier — skip is first-class and free.
    """
    attempts = 0
    last_key = ""
    while True:
        key = await _pair_prompt_one_key(label, example, help_url)
        if not key:
            return ""  # Skip — no verification needed
        # Wrap the verifier in to_thread so the 5s network call doesn't
        # block the event loop (defensive; pair has nothing else running).
        # Spinner gives the user visible feedback that the probe is
        # actually running — silent would feel like a hang on slow
        # networks.
        async with _async_spinner_ctx(f"Verifying {label} key"):
            status = await asyncio.to_thread(verifier, key)
        if status == "ok":
            print(f"  {_c(_OK, '✓')}  {label} key verified.")
            return key
        if status == "network_error":
            print(f"  {_c(_WARN, '!')}  Could not reach {label} API to verify "
                  f"{_c(_DIM, '(network error — saving without check).')}")
            print(f"  {_c(_DIM, '     Jobs will fail-loud at first run if the key is invalid.')}")
            return key
        # status == "auth_failed"
        attempts += 1
        last_key = key
        if attempts < max_attempts:
            remaining = max_attempts - attempts
            print(
                f"  {_c(_WARN, '!')}  {label} rejected this key "
                f"{_c(_DIM, f'({remaining} attempt' + ('s' if remaining != 1 else '') + ' left — try again or type s to skip).')}"
            )
            continue
        # Last attempt failed — escape hatch in case the verifier endpoint
        # itself is misbehaving (e.g. enterprise proxy MITM that breaks
        # TLS). Default to no.
        print(
            f"  {_c(_WARN, '!')}  {label} rejected this key on attempt "
            f"{attempts}/{max_attempts}."
        )
        try:
            ans = await asyncio.to_thread(
                input,
                f"  {_c(_ACCENT, '>')}  Save this key anyway "
                f"{_c(_DIM, '[y/N]:')} ",
            )
        except (EOFError, KeyboardInterrupt):
            print()
            return ""
        if (ans or "").strip().lower() in ("y", "yes"):
            print(
                f"  {_c(_WARN, '⚠')}  Saving unverified key. "
                f"{_c(_DIM, 'Jobs will fail-loud at first run if it remains invalid.')}"
            )
            return last_key
        return ""


async def _pair_prompt_api_keys(uid: str):
    """Stage 3/5 of --pair: detect-or-prompt for Anthropic + Gemini.

    Per key: if any source already resolves (Firestore Account-page key /
    Windows User-scope env / shell env / .dg-supervisor.env via
    _load_env_file), skip the prompt and tell the user we're using that.
    Otherwise prompt with paste-or-skip, then VERIFY the pasted key
    against the provider's API before persisting — typos / revoked keys
    / wrong-account pastes surface immediately, not mid-pipeline. On
    verified paste: write to BE-local persistence (Win User-scope env
    on Windows; `.dg-supervisor.env` on POSIX) + os.environ (in-memory
    for this session) + bust _RESOLVED_KEY_CACHE so the change is picked
    up immediately by Stage 4 browser-login CUA init AND by Stage 5
    supervisor arming.

    Pair-time keys live ONLY on the paired machine — they are NOT
    written to Firestore. The FE Account → API Config page is a
    SEPARATE surface that does write to Firestore; when a user pastes
    a key there it takes precedence over the BE-local pair-time key
    (resolver order: Firestore → User-scope → shell env). Keeping the
    surfaces disjoint prevents the FE Account page from auto-filling
    with a pair-time key the user never typed there.

    Anthropic and Gemini are independent — skipping one doesn't affect
    the other. Pair always completes; degraded modes (cua_unavailable
    for missing Anthropic, narration disabled for missing Gemini) are
    user-recoverable via FE alert + Account → API Config."""
    del uid  # No longer used — pair-time persistence is BE-local, not Firestore.
    # ── Anthropic ─────────────────────────────────────────────────────────
    if resolve_api_key():
        print(f"  {_c(_OK, '✓')}  Anthropic key {_c(_DIM, 'already configured — using existing source.')}")
    else:
        key = await _pair_prompt_one_key_with_verify(
            label="Anthropic",
            example="sk-ant-...",
            help_url="https://console.anthropic.com/settings/keys",
            verifier=_verify_anthropic_key,
        )
        if key:
            # Persist to BE-local FIRST, then mirror to os.environ for the
            # in-flight session (User-scope env / .env file are only seen
            # by *new* processes — the current pair session needs the
            # os.environ mirror to use the key in Stage 4 / Stage 5).
            #
            # Single canonical name only — `CUA_API_KEY` was retired
            # 2026-05-23 in favor of the Anthropic-SDK standard
            # `ANTHROPIC_API_KEY`. Existing devices with a CUA_API_KEY
            # set are migrated to ANTHROPIC_API_KEY by
            # _migrate_legacy_api_keys() at startup.
            ok_anth = _save_api_key_local("ANTHROPIC_API_KEY", key)
            os.environ["ANTHROPIC_API_KEY"] = key
            _RESOLVED_KEY_CACHE.update(key=None, ts=0.0)
            if ok_anth:
                print(f"  {_c(_OK, '✓')}  Saved to this machine {_c(_DIM, '— survives reboots via the supervisor.')}")
            else:
                print(f"  {_c(_WARN, '⚠')}  Could not persist — applied to this session only.")
                print(f"  {_c(_DIM, '     Save permanently from the web app: Account → API Config.')}")
        else:
            print(f"  {_c(_DIM, '─')}  Skipped Anthropic — set later from the web app (Account → API Config).")

    print()

    # ── Gemini ────────────────────────────────────────────────────────────
    if resolve_gemini_api_key():
        print(f"  {_c(_OK, '✓')}  Gemini key {_c(_DIM, 'already configured — using existing source.')}")
    else:
        key = await _pair_prompt_one_key_with_verify(
            label="Gemini",
            example="AIza...",
            help_url="https://aistudio.google.com/app/apikey",
            verifier=_verify_gemini_key,
        )
        if key:
            # Single canonical name only — `GOOGLE_API_KEY` was retired
            # 2026-05-23 in favor of the Gemini-API-docs standard
            # `GEMINI_API_KEY`. Existing devices with GOOGLE_API_KEY set
            # are migrated by _migrate_legacy_api_keys() at startup.
            ok_gem = _save_api_key_local("GEMINI_API_KEY", key)
            os.environ["GEMINI_API_KEY"] = key
            # resolve_gemini_api_key() has no cache — nothing to bust. If a
            # Gemini cache is ever added (mirroring _RESOLVED_KEY_CACHE), add
            # the equivalent reset here so this site doesn't silently break.
            if ok_gem:
                print(f"  {_c(_OK, '✓')}  Saved to this machine {_c(_DIM, '— survives reboots via the supervisor.')}")
            else:
                print(f"  {_c(_WARN, '⚠')}  Could not persist — applied to this session only.")
                print(f"  {_c(_DIM, '     Save permanently from the web app: Account → API Config.')}")
        else:
            print(f"  {_c(_DIM, '─')}  Skipped Gemini — set later from the web app (Account → API Config).")


async def cmd_pair_v2(profile_dir: "str | None" = None):
    """Track D user-mode pair (post-D5c default — plain `--pair` routes
    here on fresh installs).

    Stage 1: mint a 256-bit pollSecret locally, call the FE Cloud
    Function `/api/devices/initiate-pair`, display the 8-char code (and
    QR), poll the pending-customToken subdoc, exchange the JWT for a
    refresh token, persist it to the OS keystore via
    RefreshTokenCredentials.bootstrap. No Admin SDK, no
    firebase-service-account.json on disk.

    Stages 2-5 are then handled by the shared
    `_continue_pair_stages_2_to_5` helper (same code path the legacy
    `run_pair` uses after its research_token handshake) — On Startup
    prompt, API keys via the FE bridge (D5c-2), browser logins,
    Ready/supervisor.
    """
    from auth import v2_flow
    import socket as _socket
    import platform as _platform

    # Per-step timing instrumentation, kept at DEBUG so the user-facing
    # terminal stays clean. Set `DG_PAIR_TRACE=1` in the env to re-enable
    # the `[pair +X.XXs]` step prefix on stderr for diagnosis. The
    # actual user-facing progress lines (✓ Refresh token saved, etc.)
    # are plain `print()` calls below so they always show.
    _pair_t0 = time.monotonic()
    _pair_trace = os.environ.get("DG_PAIR_TRACE") == "1"
    def _pt(msg: str, kind: str = "DEBUG") -> None:
        if not _pair_trace and kind == "DEBUG":
            return
        elapsed = time.monotonic() - _pair_t0
        log(f"[pair +{elapsed:5.2f}s] {msg}", kind)

    _setup_logo()
    _setup_step(1, 5, "Token setup")

    existing_secret = load_poll_secret()
    if existing_secret:
        poll_secret = existing_secret
        print(f"  {_c(_DIM, 'Reusing pollSecret from config — same hash → same Firestore subdoc path.')}")
    else:
        poll_secret = v2_flow.generate_poll_secret()
        print(f"  {_c(_OK, '✓')} Minted new 256-bit pollSecret.")

    poll_secret_hash = v2_flow.compute_poll_secret_hash(poll_secret)

    hostname = _socket.gethostname()
    os_string = f"{_platform.system()} {_platform.release()}"

    captured = {"device_id": None, "pair_code": None}

    def _on_code(device_id: str, pair_code: str) -> None:
        captured["device_id"] = device_id
        captured["pair_code"] = pair_code
        formatted = (
            f"{pair_code[:4]}-{pair_code[4:]}" if len(pair_code) == 8 else pair_code
        )
        print()
        print(f"  {_c(_DIM, 'Pair code')}")
        print(f"  {_c(_BOLD + _ACCENT, formatted)}")
        print()
        try:
            import qrcode
            qr = qrcode.QRCode(
                border=1, box_size=1,
                error_correction=qrcode.constants.ERROR_CORRECT_L,
            )
            qr.add_data(pair_code)
            qr.make(fit=True)
            # invert=True uses ANSI reverse-video — only safe when we know
            # the terminal honors color (matches F12 of the CLI audit).
            qr.print_ascii(tty=True, invert=bool(_USE_COLOR))
        except ImportError:
            log("    qrcode lib missing — pip install -r requirements.txt", "WARN")
        except Exception as e:
            log(f"    QR render failed: {e}", "WARN")
        print()
        print(f"  {_c(_DIM, 'Enter this code in the Super Research app:')}")
        print(f"       {_c(_ACCENT, '•')} Account → Pipeline Connection → Add Device")
        print()

    last_tick = {"sec": -1}

    def _on_waiting(elapsed: float) -> None:
        sec = int(elapsed)
        # Print every 5s — printing every poll spams the terminal.
        if sec - last_tick["sec"] >= 5:
            last_tick["sec"] = sec
            # \r keeps the line in-place; trailing spaces wipe the previous
            # counter so single-digit→double-digit transitions don't leave
            # stale chars. F7 width clamp would be cleaner but the message
            # is short.
            sys.stdout.write(
                f"  {_c(_DIM, f'Waiting for FE claim... {sec}s')}                 \r"
            )
            sys.stdout.flush()

    _pt("calling /api/devices/initiate-pair...")
    # captured_device_id is set immediately after a successful exchange
    # so the try/finally cleanup at the bottom of this function can
    # reverse a partial pair if the user Ctrl+Cs between Stage 1 and
    # Stage 5. Stays None when we never got past polling — the device
    # doc's 24h initiate-pair TTL handles that case server-side.
    captured_device_id: "str | None" = None
    pair_completed = False
    try:
        try:
            result = await v2_flow.do_pair_v2(
                poll_secret_hash=poll_secret_hash,
                machine_name=hostname,
                hostname=hostname,
                os_string=os_string,
                on_code=_on_code,
                on_waiting=_on_waiting,
            )
        except v2_flow.PollTimeout:
            print()
            _pt("polling timed out — re-run --pair to start fresh", "ERROR")
            return
        except v2_flow.InitiatePairError as e:
            print()
            _pt(f"could not contact backend: {e}", "ERROR")
            log("  Check internet + that superresearch.io is reachable.", "ERROR")
            return
        except KeyboardInterrupt:
            print()
            log("Cancelled before exchange — nothing to clean up server-side.", "WARN")
            return
        except Exception as e:
            print()
            _pt(f"unexpected error: {e}", "ERROR")
            return
        # Past this point we have a live device entry in Firestore that
        # cleanup needs to revert if the flow doesn't finish.
        captured_device_id = result["device_id"]

        print()  # Clear the polling line.
        _pt(f"exchange OK — deviceId={result['device_id'][:12]}… uid={result['uid'][:14]}…")

        # Initial save — uses the synth uid as paired_uid until the
        # owner-lookup below resolves the real owner. Without this
        # write-then-rewrite split, a Ctrl+C between save + owner-
        # lookup would leave research_config.json without the real
        # ownerUid, breaking queue rehydration on the next --serve.
        # The post-lookup save below replaces paired_uid with the
        # genuine owner uid.
        save_user_mode_state(
            device_id=result["device_id"],
            paired_uid=result["uid"],
            poll_secret=poll_secret,
        )
        _pt("refresh token saved to OS keystore")
        print(f"  {_c(_OK, '✓')} Refresh token saved to OS keystore.")

        # Real-time atomic-pair confirmation. With the keystore bootstrapped
        # the BE is genuinely paired — Firestore should reflect that right
        # now so the FE Account-page tile appears at Stage 1, not after the
        # supervisor-started --serve eventually heartbeats. Mirrors the
        # contract heartbeat would write: pairConfirmedAt:true + delete
        # expireAt (cancels the 5-min "must confirm" TTL set by the claim
        # Cloud Function). Best-effort — if this fails the heartbeat at
        # Stage 5 still writes both via the same path.
        if _pair_patch_device(
            result["device_id"],
            {"pairConfirmedAt": True},
            delete_fields=["expireAt"],
        ):
            _pt("device confirmed in Firestore — FE tile should appear")
        else:
            _pt("device-confirm patch failed (heartbeat will retry)", "WARN")

        # Owner-lookup via Firestore REST GET, authed with the freshly-
        # minted idToken. Sidesteps the cold gRPC client init (~10-15s on
        # Windows the first time) that init_firestore_user_scoped does, so
        # the "Linked to {name} ({email})" banner shows the real owner
        # instead of falling back to the synth uid. Bounded by a 10s HTTP
        # timeout + graceful fallback — pair never blocks here.
        owner_uid = result["uid"]
        owner_label = ""
        owner_email = ""
        try:
            from auth.v2_flow import PROJECT_ID as _PID
            import requests as _requests
            _id_token = result["credentials"].token  # set by RefreshTokenCredentials.bootstrap
            _url = (
                f"https://firestore.googleapis.com/v1/projects/{_PID}"
                f"/databases/(default)/documents/devices/{result['device_id']}"
            )
            _resp = await asyncio.to_thread(
                _requests.get,
                _url,
                headers={"Authorization": f"Bearer {_id_token}"},
                timeout=10,
            )
            if _resp.status_code == 200:
                _fields = (_resp.json() or {}).get("fields", {}) or {}
                _owner_field = (_fields.get("ownerUid") or {}).get("stringValue") or ""
                _label = (_fields.get("ownerDisplayName") or {}).get("stringValue") or ""
                _email = (_fields.get("ownerEmail") or {}).get("stringValue") or ""
                owner_uid = _owner_field or owner_uid
                owner_label = _label or (_email.split("@")[0] if _email else "")
                owner_email = _email
                _pt(f"owner resolved — uid={owner_uid[:14]}… label={owner_label!r} email={owner_email!r}")
            else:
                _pt(f"owner read HTTP {_resp.status_code} — falling back", "DEBUG")
        except Exception as e:
            _pt(f"owner lookup failed: {e} (falling back)", "DEBUG")

        # Re-write research_config.json with the REAL owner uid in
        # paired_uid. The earlier save (right after exchange) used the
        # synth uid as a placeholder — pointing user-tree queries on
        # the next --serve at `users/device-d754.../researches/`
        # instead of the actual owner's collection, which made queue
        # rehydration look at an empty path. Now that we have the real
        # ownerUid from the device doc, overwrite. Atomic-write helper
        # in save_user_mode_state handles partial-file safety.
        if owner_uid and owner_uid != result["uid"]:
            save_user_mode_state(
                device_id=result["device_id"],
                paired_uid=owner_uid,
                poll_secret=poll_secret,
            )
            _pt(f"paired_uid updated: synth → {owner_uid[:14]}…")

        print()
        print(f"  {_c(_DIM, 'Device id  ·')}  {_c(_BOLD, result['device_id'])}")
        print()
        # Banner: "✓ Linked to Rocky (rocky@gmail.com)" when we have both;
        # falls back to label-only, then email-only, then "your account".
        if owner_label and owner_email:
            _linked_to = f"{_c(_BOLD, owner_label)} {_c(_DIM, '(' + owner_email + ')')}"
        elif owner_label:
            _linked_to = _c(_BOLD, owner_label)
        elif owner_email:
            _linked_to = _c(_BOLD, owner_email)
        else:
            _linked_to = _c(_BOLD, "your account")
        print(f"  {_c(_OK, '✓')}  Linked to {_linked_to}")
        print()

        _pt("entering stages 2-5 (On Startup → API keys → Logins → Ready)")
        # Stages 2-5 — On Startup, API keys (via FE bridge in user-mode),
        # browser logins, Ready/supervisor. The helper writes per-platform
        # login progress to devices/{deviceId}.logins via the user-scoped
        # Firestore client (rule permits synth user updates of `logins`).
        await _continue_pair_stages_2_to_5(
            profile_dir or str(PROFILE_DIR),
            linked_uid=owner_uid,
            linked_email=owner_email or owner_label or owner_uid[:8],
            initial_paired_uid=None,
            token="",
            device_id_for_progress=result["device_id"],
        )
        # Reached only if Stages 2-5 returned cleanly (no Ctrl+C, no
        # exception). The finally below uses this sentinel to decide
        # whether to run server-side cleanup.
        pair_completed = True
    finally:
        if captured_device_id and not pair_completed:
            print()
            log(
                "Pair interrupted — reverting partial state so your FE "
                "Account doesn't show a half-paired device tile.",
                "WARN",
            )
            _cleanup_partial_pair(captured_device_id)
            log(
                "Cleanup done. Re-run `python research.py --pair` to try "
                "again from a clean slate.",
                "INFO",
            )


async def _walk_platform_logins(
    browser,
    services: "list[tuple[str, str, str]]",
    cua_client,
    *,
    results: "dict[str, bool]",
    emit_row,
    push_progress=None,
    initial_pro_acknowledged: bool = False,
) -> "tuple[bool, bool]":
    """Sequentially walk per-platform login during pair Stage 4.

    Extracted from `_continue_pair_stages_2_to_5` so the multi-profile
    Stage 4 outer loop (2026-05-21) can reuse the exact same flow on
    additional browser profiles without duplicating ~180 lines. Behavior
    is byte-identical to the pre-extraction inline loop — same pacing
    jitter, same URL/CUA gates, same Pro-tier branches.

    SETUP-2026-04-19 design rationale (still applies): one platform at a
    time, never bulk-open. Two problems with the earlier batch flow:
    (1) opening many tabs within seconds reads as a robotic burst to
    Cloudflare scoring, and (2) asking the user to juggle N simultaneous
    login flows is overwhelming. This walk opens → settles → URL check
    → CUA verify → closes, one platform at a time.

    `results` is mutated in-place (not returned) so the caller's
    `push_progress` closure sees fresh state without re-passing the dict
    on every callback invocation.
    """
    cancelled = False
    pair_pro_acknowledged = initial_pro_acknowledged

    for idx, (name, url, key) in enumerate(services):
        # 2026-04-30: cookie fast-path REMOVED. Was raising false positives —
        # cookies persist past server-side session invalidation, so
        # cookie_login_hit returned "logged in" when the session was actually
        # dead. Mirrors the same removal init/Phase 0 made on 2026-04-24
        # (research.py:16894-16902). Always open tab → settle → URL check →
        # CUA. Slower but it looks at what's actually on screen.

        # Stagger tab opens just like the probe paths — a user clicking
        # through bookmarks takes a beat between each one.
        if idx > 0:
            await asyncio.sleep(random.uniform(2.5, 4.5))

        try:
            tab = await browser.new_tab(url)
        except Exception as e:
            log(f"    Failed to open {name}: {e}", "WARN")
            results[key] = False
            emit_row(name, False, f"could not open ({e})")
            if push_progress:
                push_progress()
            continue

        # SPA hydration — matches Phase 0 / probe timing. CUA misreads
        # the neutral loading shell as a login wall if we peek too early.
        await asyncio.sleep(4.0)

        print("")
        print(f"  {_c(_BOLD, name)}  {_c(_DIM, '— log in on the tab that just opened.')}")

        platform_ok = False
        while True:
            try:
                await asyncio.to_thread(input, f"  {_c(_ACCENT, '>')}  Press Enter when done ")
            except (EOFError, KeyboardInterrupt):
                print("")
                log("Setup cancelled by user", "INFO")
                cancelled = True
                try:
                    await tab.close()
                except Exception:
                    pass
                break

            # 2026-04-30: cookie + Playwright DOM shortcuts REMOVED. Both
            # raised false positives — cookies survive server-side session
            # invalidation, and strict DOM selectors match cached sidebar
            # fragments on logged-out landings. Mirror init's gate
            # (research.py:16934-16947): URL host negative signal first,
            # then CUA as the single source of truth.

            # Cheap negative signal first: URL on a known login host →
            # definitely not logged in. Skip the CUA call to save budget.
            try:
                current_url = (tab.url or "").lower()
            except Exception:
                current_url = ""
            if any(h in current_url for h in _LOGIN_HOST_NEGATIVES):
                print(f"  {_c(_WARN, 'Not logged in yet — finish the flow and press Enter again.')}")
                continue

            # Vision verification is the gate. URL already cleared the
            # cheap "obvious login wall" case; everything else is a CUA
            # decision. If no CUA client (Anthropic key missing/disabled),
            # accept on URL pass — that mirrors init's behavior in the
            # CuaUnavailableError fallback path.
            if not cua_client:
                platform_ok = True
                break
            try:
                cua_ok = await verify_login_cua(tab, key, cua_client)
            except Exception as e:
                log(f"    CUA verify error for {key}: {e}", "WARN")
                cua_ok = False
            if cua_ok:
                # Pro-tier verify (DGOPS-7357 re-open). Login-OK is no longer
                # the final gate for ChatGPT/Claude/Gemini — the OAuth-side-
                # effect cookie can hydrate Gemini as the WORK account when
                # the user wanted the personal one, and CUA only answers
                # "logged in?", not "as whom?". Trust the user to fix the
                # account in-tab; the Pro check at least catches the most
                # common silent miscompare (work=Free, personal=Pro).
                #
                # Control-flow contract (refactored 2026-05-07 to address
                # PR review C4 — original was correct but reviewers misread
                # the break-then-fall-through pattern as a skip-bug).
                # Each branch below now sets platform_ok + break EXPLICITLY,
                # eliminating the dangling unconditional `platform_ok = True`
                # at the end of the if cua_ok body that previously read as
                # "always set True after any cua_ok=True". No behavior change.
                if (key in _PRO_TIER_PLATFORMS
                        and not pair_pro_acknowledged):
                    print(f"  {_c(_DIM, 'Verifying subscription tier…')}")
                    try:
                        tier = await _cua_pro_tier_call(tab, key, cua_client)
                    except CuaUnavailableError as cua_err:
                        # Pre-pipeline: Phase 0 will re-check with the same
                        # client and surface its own canonical alert. Don't
                        # block setup on a transient billing/cap blip.
                        log(f"    Setup pro_tier: CUA unavailable for {key} ({cua_err}) — skipping tier check", "WARN")
                        tier = "unsure"
                    except Exception as e:
                        log(f"    Setup pro_tier: unexpected error for {key} ({e}) — assuming Pro (fail-open)", "WARN")
                        tier = "unsure"
                    if tier == "free":
                        # 3-option terminal prompt. Free-tier was caught;
                        # the user picks how to handle it.
                        title, _details = _PRO_TIER_DETAILS_BY_KEY.get(
                            key, (f"{name} Pro required", ""))
                        print("")
                        print(f"  {_c(_WARN, title)}")
                        print(f"  {_c(_DIM, 'This account is on Free — Phase 1/2 quality will be degraded.')}")
                        print(f"  {_c(_DIM, '  [c] continue with Free   [r] retry (sign in with Pro)   [s] skip this platform')}")
                        choice = ""
                        while True:
                            try:
                                choice = (await asyncio.to_thread(
                                    input, f"  {_c(_ACCENT, '>')}  Choose [c/r/s] ")
                                ).strip().lower()
                            except (EOFError, KeyboardInterrupt):
                                print("")
                                log("Setup cancelled by user during Pro alert", "INFO")
                                cancelled = True
                                try:
                                    await tab.close()
                                except Exception:
                                    pass
                                break
                            if choice in ("c", "continue", ""):
                                pair_pro_acknowledged = True
                                log(f"    Setup: user chose Continue with Free for {name}", "INFO")
                                platform_ok = True
                                break
                            if choice in ("r", "retry"):
                                log(f"    Setup: user chose Retry on {name} Free-tier alert — re-running login walk", "INFO")
                                # Stay on this platform: same tab, user signs
                                # out / signs back in with Pro, presses Enter
                                # again. Fall through to the outer press-Enter
                                # loop below via `continue`.
                                platform_ok = False
                                break
                            if choice in ("s", "skip"):
                                log(f"    Setup: user chose Skip for {name} (Free-tier)", "INFO")
                                platform_ok = False
                                break
                            print(f"  {_c(_WARN, 'Pick c, r, or s.')}")
                        if cancelled:
                            break
                        if choice in ("r", "retry"):
                            # Don't break the press-Enter loop — `continue`
                            # so the user gets the Press Enter prompt again
                            # on the same tab after switching accounts.
                            continue
                        # c or s: leave the press-Enter loop with platform_ok
                        # already set (True for c, False for s).
                        break
                    elif tier == "pro":
                        log(f"    Setup: {name} Pro detected", "INFO")
                        platform_ok = True
                        break
                    else:  # unsure → fail open
                        log(f"    Setup: {name} tier UNSURE — assuming Pro (fail-open)", "INFO")
                        platform_ok = True
                        break
                else:
                    # Either pair_pro_acknowledged is True (user already
                    # chose Continue-with-Free on a prior platform), or
                    # this platform isn't in _PRO_TIER_PLATFORMS (e.g.,
                    # NotebookLM, where the pro-tier prompt doesn't apply).
                    # CUA confirmed login — that's enough.
                    platform_ok = True
                    break
            print(f"  {_c(_WARN, 'CUA could not confirm login — try again and press Enter.')}")

        if cancelled:
            break

        try:
            await tab.close()
        except Exception:
            pass

        results[key] = platform_ok
        emit_row(name, platform_ok)
        if push_progress:
            push_progress()

    return cancelled, pair_pro_acknowledged


async def _continue_pair_stages_2_to_5(
    profile_dir: str,
    *,
    linked_uid: str,
    linked_email: str,
    initial_paired_uid: "str | None",
    token: str,
    device_id_for_progress: "str | None",
) -> None:
    """Stages 2-5 of pair — On Startup → API keys → Browser logins → Ready.

    Shared between legacy `run_pair` (whose Stage 1 mints a research_token
    and waits for the app to claim it) and user-mode `cmd_pair_v2` (whose
    Stage 1 is the pollSecret + customToken handshake). Each Stage-1
    flow pre-fills the parameters this helper needs.

    `_push_firestore_progress` writes per-platform login state to:
      - `devices/{device_id_for_progress}.logins` when in user-mode
        (rule allows synth-user updates of [lastHeartbeat, status,
        logins, authMode] only — so we don't write setupState /
        lastSetupCheck in this branch),
      - `research_tokens/{token}.{logins, setupState, lastSetupCheck}`
        otherwise (legacy, unchanged behavior).
    """
    _initial_paired_uid = initial_paired_uid  # legacy local-var alias

    # ══════════════════════════════════════════════════════════════════════
    # [2/5] ON STARTUP — ask whether to enable On Startup mode. We only
    #       CAPTURE the answer here; the actual arming (schtasks install
    #       + detached daemon-loop spawn) happens in Stage 5 AFTER logins
    #       succeed, so an aborted login can't leave Firestore with
    #       supervised=true while platforms are half-logged-in.
    # ══════════════════════════════════════════════════════════════════════
    _setup_step(2, 5, "On Startup")
    print(f"  {_c(_DIM, 'Keep the backend running in the background?')}")
    print(f"  {_c(_DIM, 'It will auto-start when you log in and stay alive through crashes')}")
    print(f"  {_c(_DIM, 'and reboots. You can turn it off anytime with --retire.')}")
    print()
    enable_on_startup = False
    try:
        _startup_typed = await asyncio.to_thread(
            input, f"  {_c(_ACCENT, '>')}  Enable On Startup? {_c(_DIM, '[Y/n]')}: ",
        )
        _ans = _startup_typed.strip().lower()
        if _ans in ("", "y", "yes"):
            enable_on_startup = True
    except (EOFError, KeyboardInterrupt):
        # Ctrl+C at the prompt — safer default is to skip arming, so a
        # user who meant to abort doesn't end up with a silently-armed
        # supervisor if they continue through the rest of --pair anyway.
        enable_on_startup = False
        print()
    print()
    if enable_on_startup:
        print(f"  {_c(_OK, '✓')}  On Startup will be enabled after the logins finish.")
    else:
        print(f"  {_c(_DIM, '     Skipped. You will run --serve manually in step 5.')}")
        print(f"  {_c(_DIM, '     Enable later with:')}  {_c(_BOLD, 'python research.py --resurrect')}")
    # Mirror the Stage 2 intent to the device doc so the FE Account-page
    # On Startup toggle flips in real time. The actual supervisor arm
    # still happens in Stage 5; if it fails the user can fix via
    # --resurrect later. Best-effort.
    if device_id_for_progress:
        _pair_patch_device(device_id_for_progress, {"supervised": bool(enable_on_startup)})
    print()

    # ══════════════════════════════════════════════════════════════════════
    # [3/5] API KEYS — detect-or-prompt for Anthropic + Gemini BEFORE
    #       browser logins so the keys (especially Anthropic) are available
    #       for the CUA + Vision verification path during Stage 4. Without
    #       this ordering, login verification falls back to Playwright-only
    #       (less rigorous) and the Pro-tier check can't run at all.
    #       Each key is independently skippable; pair continues either way.
    #       On paste: writes Firestore (canonical, cross-device, matches FE
    #       Account page — or via FE bridge in user-mode, per D5c-2) +
    #       os.environ (current session) + busts the resolver cache so the
    #       very-next resolve_api_key() call (in the CUA-client init at the
    #       top of Stage 4) sees the new key. NOT written to .dg-supervisor
    #       .env — would create a 3rd source of truth and drift on rotation.
    # ══════════════════════════════════════════════════════════════════════
    _setup_step(3, 5, "API keys")
    print(f"  {_c(_DIM, 'Anthropic powers the agents (CUA + Vision).  Gemini powers narration.')}")
    print(f"  {_c(_DIM, 'Already-set keys are detected and reused. Skip to set later via the web app.')}")
    print()
    await _pair_prompt_api_keys(linked_uid)
    print()

    # ══════════════════════════════════════════════════════════════════════
    # [4/5] BROWSER LOGINS — open 4 platform tabs and wait for real auth.
    #       Uses CUA + Vision when Anthropic key was set in Stage 3 (above),
    #       or falls back to Playwright-only if user skipped.
    # ══════════════════════════════════════════════════════════════════════
    _setup_step(4, 5, "Browser logins")
    print(f"  {_c(_DIM, 'Walking through logins one platform at a time.')}")
    print(f"  {_c(_DIM, 'Each tab opens, you log in, then press Enter — vision verifies the session.')}")
    print(f"  {_c(_DIM, 'If a Pro-tier check trips, you decide whether to continue, retry, or skip.')}")
    print("")

    browser = Browser(profile_dir, headless=False)
    await browser.start()

    # F4 / DGOPS-7451 — refuse to add a Google account to a profile that
    # already has one signed in. Multi-account state in this profile is
    # the root enabler of the session-inheritance class of incident this
    # safety check defends against; full incident context lives in
    # DGOPS-7451. Detect read-only first; if a prior Google auth is
    # present AND it points to a different account than the one just
    # claimed (account_switch case), surface a clear unpair-first message
    # and exit before walking Stage 4 logins. First-pair / same-account
    # re-pair pass through with a passive notice.
    try:
        prior = await _detect_persisted_google_auth(browser.context)
    except Exception as _de:
        log(f"[security] pair preflight detection failed (continuing): {_de}", "WARN")
        prior = None
    if prior:
        # F4 / DGOPS-7451 relaxation (2026-05-18): refuse pair only when the
        # device was previously paired to a DIFFERENT account. That's the
        # actual incident-class risk (silent account switch mid-life). On
        # first-pair (no prior `_initial_paired_uid`) OR re-pair to the
        # same account, the existing cookies are presumably from the user
        # about to claim THIS link — refusing here creates a catch-22 with
        # --unpair preserving the profile.
        _account_mismatch = bool(_initial_paired_uid) and (_initial_paired_uid != linked_uid)
        if _account_mismatch:
            try:
                await browser.close()
            except Exception:
                pass
            print("")
            print(f"  {_c(_BOLD, 'Refusing to pair: switching to a different account, but prior Google auth still present.')}")
            print(f"  {_c(_DIM,  'Multi-account state is unsafe — agents inherit any persisted Google session and can')}")
            print(f"  {_c(_DIM,  'navigate to Workspace-protected resources silently. See DGOPS-7451 for context.')}")
            print("")
            print(f"  Detected: {prior['cookieMatches']} Google auth cookie(s)  ·  prior uid: {_initial_paired_uid[:8]}…  ·  new uid: {linked_uid[:8]}…")
            for s in prior.get("sample", []):
                print(f"    • {s}")
            print("")
            print(f"  {_c(_BOLD, 'To complete this account switch:')}")
            print(f"    1. {_c(_BOLD, 'python research.py --unpair --deep')}  {_c(_DIM, '(clears pairing state + browser profile)')}")
            print(f"    2. {_c(_BOLD, 'python research.py --pair')}  {_c(_DIM, '(re-runs the full flow with a fresh browser)')}")
            print("")
            try:
                emit_event("security_pair_refused",
                           reason="account_switch_with_prior_cookies",
                           cookieMatches=prior["cookieMatches"],
                           priorPairedUid=_initial_paired_uid,
                           newLinkedUid=linked_uid,
                           sample=prior.get("sample", []))
            except Exception:
                pass
            return
        # First-pair or same-account re-pair — allow cookies through with
        # a passive notice. The Google session is presumed to belong to
        # the user about to authenticate, not a leaked third-party login.
        _reason = "first_pair" if not _initial_paired_uid else "same_account_repair"
        log(f"[security] {prior['cookieMatches']} prior Google auth cookie(s) detected — "
            f"allowing pair through ({_reason}). Account-switch refusal still active for "
            f"future re-pair to a different uid.", "INFO")
        try:
            emit_event("security_pair_allowed_with_prior_cookies",
                       reason=_reason,
                       cookieMatches=prior["cookieMatches"],
                       linkedUid=linked_uid)
        except Exception:
            pass

    # CUA client for visual double-verification. Best-effort: if no key is
    # available, Stage 4 (Browser logins) falls back to Playwright-only
    # verification (same as before). With a key present — set in Stage 3
    # via the API-key prompt OR already resolved via Firestore / user-scope
    # env / shell rc / .dg-supervisor.env — each platform has to pass BOTH
    # Playwright DOM checks AND CUA vision before Stage 4 clears it.
    # Matches Phase 0 init rigor.
    _setup_cua_client = None
    # Route through `resolve_api_key()` (research.py:203) so this site honors
    # the full precedence chain (Firestore → user-scope env → os.environ),
    # not just flat os.environ. Was previously a two-ladder inconsistency
    # with vision.py:269 — both now go through the same resolver. After the
    # 2026-05-18 stage reorder, Stage 3 also busts `_RESOLVED_KEY_CACHE` so
    # a freshly-pasted key is visible here without restart.
    _setup_cua_api_key = resolve_api_key()
    if _setup_cua_api_key:
        try:
            import anthropic as _anthropic
            _setup_cua_client = _anthropic.Anthropic(api_key=_setup_cua_api_key)
            log("Setup Stage 4: CUA vision verifier enabled — each platform will be double-checked.", "INFO")
        except Exception as e:
            log(f"Setup Stage 4: Could not init CUA client ({e}) — Playwright-only verification.", "WARN")
    else:
        log("Setup Stage 4: No ANTHROPIC_API_KEY — Playwright-only verification (less rigorous). Re-run --pair and paste a key at Stage 3 to enable CUA.", "WARN")

    services = [
        ("ChatGPT",        "https://chatgpt.com",           "chatgpt"),
        ("Gemini",         "https://gemini.google.com",     "gemini"),
        ("Claude",         "https://claude.ai",             "claude"),
        ("NotebookLM",     "https://notebooklm.google.com", "notebooklm"),
        # YouTube Studio dropped 2026-05-10 — P4 is FE-owned (Data API
        # via OAuth refresh token), BE no longer uploads. Gmail + Google
        # Docs dropped 2026-04-30 — P5 is FE-owned.
    ]
    # Per-platform login walk runs in _walk_platform_logins (above) —
    # design rationale + sequencing notes live in that helper's docstring.
    pad = max(len(n) for n, _u, _k in services)
    results: dict[str, bool] = {}
    cancelled = False
    all_ok = False
    # Pair-local "user already opted into Free" flag. Mirrors
    # _controls.pro_warning_acknowledged in init/Phase 0 but stays
    # scoped to this pair invocation — pair exits before any
    # pipeline_run, so no cross-coupling. Continue-with-Free on one
    # Pro platform suppresses the alert for the remaining platforms
    # in the same setup pass. (DGOPS-7357 follow-up, 2026-05-05.)
    pair_pro_acknowledged = False

    def _emit_row(_name, ok, label=""):
        mark = _c(_OK, "[ok]") if ok else _c(_WARN, "[--]")
        suffix = f"  {_c(_DIM, label)}" if label else ""
        print(f"        {mark}  {_name.ljust(pad)}{suffix}")

    def _push_firestore_progress():
        if not _firebase_db:
            return
        logins_map = {k: bool(results.get(k, False)) for _n, _u, k in services}
        try:
            if device_id_for_progress:
                # Track D user-mode: top-level devices doc. The synth-user
                # rule allows updates only of [lastHeartbeat, status,
                # logins, authMode], so we drop setupState + lastSetupCheck
                # (legacy-only telemetry).
                _firebase_db.collection("devices").document(device_id_for_progress).update({
                    "logins": logins_map,
                })
            elif token:
                _firebase_db.collection("research_tokens").document(token).update({
                    "logins": logins_map,
                    "setupState": "ready" if all(logins_map.values()) else "awaiting_login",
                    "lastSetupCheck": int(time.time()),
                })
        except Exception:
            pass

    cancelled, pair_pro_acknowledged = await _walk_platform_logins(
        browser,
        services,
        _setup_cua_client,
        results=results,
        emit_row=_emit_row,
        push_progress=_push_firestore_progress,
        initial_pro_acknowledged=pair_pro_acknowledged,
    )

    if not cancelled:
        all_ok = all(results.get(k, False) for _n, _u, k in services)
    last_results = dict(results)

    _push_firestore_progress()
    await browser.close()

    print("")

    # ══════════════════════════════════════════════════════════════════════
    # Multi-profile login loop (2026-05-21). Each successful profile = 1
    # concurrent run slot. Gated on profile-1 success — no point chaining
    # profiles when the primary failed. workerCount is persisted
    # incrementally so a Ctrl+C mid-loop preserves the profiles that
    # DID complete (e.g. user adds profile 2 ok, bails on profile 3 →
    # workerCount stays at 2). PR 2 (daemon-loop) reads workerCount to
    # spawn N --serve workers, each pinned to _profile_dir(k).
    #
    # Reuses _walk_platform_logins (above) so the per-platform UX is
    # byte-identical to profile-1's walk. push_progress is None for
    # profile-2+ — Firestore's devices/{deviceId}.logins map stays as
    # the canonical profile-1 set (FE-visible login status); per-profile
    # logins are tracked locally only.
    # ══════════════════════════════════════════════════════════════════════
    if all_ok and not cancelled:
        # Anchor profile-1 as the baseline (covers the downgrade path: a
        # prior pair may have set workerCount=3, and the user now wants 1.
        # This write resets the floor before the loop bumps it back up.)
        try:
            save_worker_count(1)
        except Exception as _wc_err:
            log(f"save_worker_count(1) failed (continuing): {_wc_err}", "WARN")

        print(f"  {_c(_OK, '✓')}  Profile 1 logins complete.")
        print("")
        print(f"  {_c(_DIM, 'Each browser profile = 1 concurrent run slot. Recommended: 2 profiles total.')}")
        print(f"  {_c(_DIM, 'Past your slot count, fired runs go into the queue.')}")
        print("")

        next_profile_n = 2
        while True:
            try:
                ans = (await asyncio.to_thread(
                    input,
                    f"  {_c(_ACCENT, '>')}  Add another browser profile (profile {next_profile_n})? {_c(_DIM, '[y/N]')}: ",
                )).strip().lower()
            except (EOFError, KeyboardInterrupt):
                print("")
                log(f"Multi-profile loop: Ctrl+C at profile {next_profile_n} prompt — keeping workerCount={next_profile_n - 1}", "INFO")
                break
            if ans not in ("y", "yes"):
                break

            prof_path = _profile_dir(next_profile_n)
            print(f"  {_c(_DIM, f'Opening browser profile {next_profile_n} at {prof_path}…')}")
            try:
                browser_n = Browser(str(prof_path), headless=False)
                await browser_n.start()
            except Exception as e:
                log(f"Setup: failed to open browser for profile {next_profile_n}: {e}", "ERROR")
                print(f"  {_c(_WARN, f'Could not launch browser for profile {next_profile_n}: {e}')}")
                print(f"  {_c(_DIM, 'Stopping multi-profile loop. Pair continues with the profiles already set up.')}")
                break

            # F4 / DGOPS-7451 awareness — profile-N is fresh on first setup,
            # but a re-pair may find leftover cookies. We surface a passive
            # notice; the device is already paired to linked_uid, so prior
            # cookies likely belong to the same account. A stricter "refuse
            # if account_mismatch" gate would need to read the cookie's
            # account_id which Stage 4 doesn't do either — keep symmetric.
            try:
                prior_n = await _detect_persisted_google_auth(browser_n.context)
            except Exception as _de:
                log(f"[security] profile {next_profile_n} preflight detection failed (continuing): {_de}", "WARN")
                prior_n = None
            if prior_n:
                _n_cookies = prior_n.get("cookieMatches", 0) if isinstance(prior_n, dict) else 0
                _msg = f"Profile {next_profile_n}: {_n_cookies} prior Google auth cookie(s) detected — continuing (presumed same account)."
                print(f"  {_c(_DIM, _msg)}")

            # Fresh results dict per profile — push_progress=None so the
            # canonical Firestore logins map stays bound to profile-1.
            profile_n_results: "dict[str, bool]" = {}
            n_cancelled, pair_pro_acknowledged = await _walk_platform_logins(
                browser_n,
                services,
                _setup_cua_client,
                results=profile_n_results,
                emit_row=_emit_row,
                push_progress=None,
                initial_pro_acknowledged=pair_pro_acknowledged,
            )

            n_all_ok = (not n_cancelled) and all(
                profile_n_results.get(k, False) for _n, _u, k in services
            )

            try:
                await browser_n.close()
            except Exception:
                pass

            print("")
            if n_all_ok:
                try:
                    save_worker_count(next_profile_n)
                except Exception as _wc_err:
                    log(f"save_worker_count({next_profile_n}) failed (continuing): {_wc_err}", "WARN")
                print(f"  {_c(_OK, '✓')}  Profile {next_profile_n} logins complete — concurrent capacity is now {next_profile_n}.")
                next_profile_n += 1
            else:
                if n_cancelled:
                    print(f"  {_c(_WARN, '⚠')}  Profile {next_profile_n} logins cancelled — keeping workerCount={next_profile_n - 1}.")
                else:
                    _missing = [_name for _name, _u, _key in services if not profile_n_results.get(_key, False)]
                    print(f"  {_c(_WARN, '⚠')}  Profile {next_profile_n} logins incomplete — keeping workerCount={next_profile_n - 1}.")
                    if _missing:
                        print(f"       {_c(_DIM, 'Did not verify: ' + ', '.join(_missing))}")
                # Don't increment — the dir at _profile_dir(next_profile_n)
                # may have stale partial cookies. User can wipe via
                # --unpair --deep and re-pair to retry that slot.
                break
        print("")

    if all_ok:
        # ══════════════════════════════════════════════════════════════════════
        # [5/5] READY — pair is complete. If the user opted into On Startup
        #       back in step 2, arm the supervisor NOW (deferred from step 2
        #       so an aborted login couldn't leave Firestore flagged as
        #       supervised while platforms were half-logged-in). Final
        #       message branches on whether the supervisor is live.
        # ══════════════════════════════════════════════════════════════════════
        _setup_step(5, 5, "Ready")
        print(f"  {_c(_OK, '✓')}  Paired with {_c(_BOLD, linked_email or '—')}")
        print(f"  {_c(_OK, '✓')}  All {len(services)} platforms logged in")
        print(f"  {_c(_OK, '✓')}  Browser closed")

        supervised_armed = False
        if enable_on_startup:
            print()
            # Spin while arming — the 5s daemon-loop detection wait would
            # otherwise look frozen.
            async with _async_spinner_ctx("Enabling On Startup"):
                ok, pid, info, killed_serves = await asyncio.to_thread(_arm_supervisor_quiet)
            if ok:
                supervised_armed = True
                _write_supervised_flag(True)
                _step4_plat = _supervisor_platform()
                if _step4_plat == "Darwin":
                    print(f"  {_c(_OK, '✓')}  LaunchAgent installed ({_SUPERVISOR_PLIST_LABEL})")
                elif _step4_plat == "Linux":
                    print(f"  {_c(_OK, '✓')}  systemd user unit installed ({_SUPERVISOR_UNIT_NAME})")
                else:
                    print(f"  {_c(_OK, '✓')}  Scheduled Task pinned to login ({_SUPERVISOR_TASK_NAME})")
                if killed_serves:
                    plural = "es" if killed_serves != 1 else ""
                    print(f"  {_c(_DIM, f'     Stopped {killed_serves} running --serve process{plural} to free port 8000.')}")
                if pid is not None and info == "already running":
                    print(f"  {_c(_OK, '✓')}  Backend already running (PID {pid})")
                elif pid is not None:
                    print(f"  {_c(_OK, '✓')}  Backend started (PID {pid}, running in background)")
                else:
                    print(f"  {_c(_WARN, '⚠')}  {info or 'Backend did not appear within 5s'}")
                    print(f"  {_c(_DIM, '     The scheduled task still fires at next login as a fallback.')}")
                print(f"  {_c(_OK, '✓')}  Synced to the Super Research app")
            else:
                if info == "unsupported":
                    print(f"  {_c(_WARN, '⚠')}  Only Windows / macOS / Linux desktop is supported.")
                else:
                    print(f"  {_c(_WARN, '⚠')}  Could not enable On Startup: {info}")
                print(f"  {_c(_DIM, '     Run manually with:')}  {_c(_BOLD, 'python research.py --resurrect')}")
        else:
            # User chose N to On Startup. Enforce that: remove any
            # previously-installed scheduled task + kill any running
            # daemon-loop / serve from a prior pair, so "N" genuinely means
            # "nothing is running in the background — I will run --serve
            # manually". Without this, a leftover supervisor from an
            # earlier --pair/--resurrect keeps respawning --serve and the
            # user can't tell where the backend is coming from.
            print()
            async with _async_spinner_ctx("Enforcing unsupervised mode"):
                task_info, killed_procs = await asyncio.to_thread(_disarm_supervisor_quiet)
            _write_supervised_flag(False)
            if task_info == "removed":
                print(f"  {_c(_OK, '✓')}  Removed leftover {_supervisor_artifact_label()} ({_SUPERVISOR_TASK_NAME})")
            elif task_info in ("missing", "no-task"):
                # macOS/Linux disarm helpers return "no-task" rather than
                # "missing"; both mean the same thing — nothing to remove.
                print(f"  {_c(_DIM, '     No supervisor was installed.')}")
            elif task_info in ("non-Windows", "unsupported"):
                pass  # silent — no supervisor artifact to remove on this platform
            else:
                print(f"  {_c(_WARN, '⚠')}  Supervisor teardown: {task_info}")
            if killed_procs:
                plural = "es" if killed_procs != 1 else ""
                print(f"  {_c(_OK, '✓')}  Stopped {killed_procs} leftover backend process{plural}")
            else:
                print(f"  {_c(_DIM, '     No backend processes were running.')}")

        print()
        if supervised_armed:
            print(f"  {_c(_BOLD + _ACCENT, '  The bond is forged.')}  {_c(_DIM, 'The backend is live — running in the background.')}")
            _render_next_actions([
                ("python research.py --retire", "disable On Startup"),
                ("python research.py --unpair", "fully disconnect this machine"),
            ])
        else:
            print(f"  {_c(_BOLD + _ACCENT, '  The bond is forged.')}  {_c(_DIM, 'Start the backend in this terminal to accept jobs:')}")
            print()
            print(f"       {_c(_BOLD, 'python research.py --serve')}")
            print()
            print(
                f"  {_c(_BOLD + _BRIGHT, '◇')}  "
                f"{_c(_BOLD + _ACCENT, 'vinctus est')}  "
                f"{_c(_BOLD + _BRIGHT, '◇')}    "
                f"{_c(_DIM, 'Bound. Backend listening on this machine.')}"
            )
            _render_next_actions([
                ("python research.py --resurrect", "enable On Startup (auto-start in background)"),
                ("python research.py --unpair", "fully disconnect this machine"),
            ])
    else:
        print()
        print(f"  {_rule('━', _WARN)}")
        print(f"  {_c(_WARN, 'Setup cancelled — not all platforms logged in yet.')}")
        print(f"  {_rule('━', _WARN)}")
        print("")
        if last_results:
            print(f"  {_c(_DIM, 'Last check:')}")
            for name, _u, key in services:
                ok = last_results.get(key)
                mark = _c(_OK, "[ok]") if ok else _c(_DIM, "[  ]")
                print(f"        {mark}  {name if ok else _c(_DIM, name)}")
            print("")
        print(f"  {_c(_DIM, 'Your token is saved. Re-run when ready:')}")
        print(f"        {_c(_BOLD, 'python research.py --pair')}")
        print("")


# ── Supervised mode (--resurrect / --retire) ───────────────────────────
#
# Installs a Windows Scheduled Task that auto-starts `python research.py
# --serve` at user logon, so a reboot (Windows Update, power blip, crash)
# doesn't need manual re-launch. Paired with the backend's existing startup
# auto-retry (research.py:8099 detects an incomplete checkpoint and resumes),
# this makes the pipeline survive unexpected downtime end-to-end.
#
# Task is scoped to the CURRENT USER — never elevated to SYSTEM — so it
# retains access to the user's Chrome profile / cookies, which Playwright
# needs for the logged-in agents.

_SUPERVISOR_TASK_NAME = "SuperResearchBackend"

# ── Cross-platform supervisor scaffolding (Track C, 2026-05-18) ────────────
# Per-platform bodies live in `*_windows` / `*_macos` / `*_linux` siblings;
# dispatchers at the original names route via `_supervisor_platform()`.
# All three platforms are first-class supported as of the 2026-05-18 gate
# drop. Windows uses a Scheduled Task; macOS uses launchd; Linux uses a
# systemd-user unit. Implementations live in `_arm_supervisor_macos`,
# `_arm_supervisor_linux`, `_arm_supervisor_quiet_windows` + their
# disarm + detect siblings; see README.md § Step 5a / 5b / 5c.

_SUPERVISOR_PLIST_LABEL = "com.dgresearch.supervisor"
_SUPERVISOR_PLIST_PATH = Path.home() / "Library" / "LaunchAgents" / f"{_SUPERVISOR_PLIST_LABEL}.plist"
_SUPERVISOR_UNIT_NAME = "dgresearch-supervisor.service"
_SUPERVISOR_UNIT_PATH = Path.home() / ".config" / "systemd" / "user" / _SUPERVISOR_UNIT_NAME

# Per-machine env file consumed by the supervisor at startup. See PR-Env in
# scripts/dg-supervisor.env.example. Values applied via `os.environ.setdefault()` —
# existing process env (Windows user-scope from "Account → API Config") wins
# for `resolve_api_key` callers (research.py:204-218). Missing file is fail-
# soft (Vision defaults to off per research.py:66, CUA fallthrough is safe).
_SUPERVISOR_ENV_FILE_DEFAULT_PATH = Path(__file__).parent / ".dg-supervisor.env"


def _load_env_file(path) -> dict[str, str]:
    """Parse `KEY=value` lines from `path`; apply via `os.environ.setdefault`.

    Tolerates `#` comments, blank lines, whitespace around `=`, matching
    outer quotes. UTF-8 BOM tolerated via `encoding="utf-8-sig"`. Missing
    file → WARN + {}. Malformed lines → WARN + skip. Returns the subset of
    keys actually applied (skips keys already present in os.environ — so the
    existing Windows user-scope env wins for the resolve_api_key chain).
    """
    if path is None:
        return {}
    p = Path(path) if not isinstance(path, Path) else path
    if not p.exists():
        log(f"[env] {p} not found — supervisor starts without persisted env vars", "WARN")
        return {}
    applied: dict[str, str] = {}
    try:
        text = p.read_text(encoding="utf-8-sig")
    except Exception as e:
        log(f"[env] failed to read {p}: {e}", "WARN")
        return {}
    for lineno, raw in enumerate(text.splitlines(), 1):
        s = raw.strip()
        if not s or s.startswith("#"):
            continue
        if "=" not in s:
            log(f"[env] {p}:{lineno} skipped (no '='): {s[:60]}", "WARN")
            continue
        k, _, v = s.partition("=")
        k = k.strip()
        v = v.strip()
        if len(v) >= 2 and v[0] == v[-1] and v[0] in ('"', "'"):
            v = v[1:-1]
        if not k or not all(c.isalnum() or c == "_" for c in k):
            log(f"[env] {p}:{lineno} skipped (bad key): {k!r}", "WARN")
            continue
        if k not in os.environ:
            os.environ[k] = v
            applied[k] = v
    return applied


def _seed_env_file_if_missing() -> bool:
    """Copy scripts/dg-supervisor.env.example to .dg-supervisor.env if absent.
    On POSIX, chmod 0600 (API key sensitivity). Idempotent — no-op if target
    exists. Returns True if a fresh seed was written. Called by `--resurrect`
    so first-time install lays down a documented, all-commented env file."""
    target = _SUPERVISOR_ENV_FILE_DEFAULT_PATH
    if target.exists():
        return False
    example = Path(__file__).parent / "scripts" / "dg-supervisor.env.example"
    if not example.exists():
        log(f"[env] no example template at {example} — skipping seed", "WARN")
        return False
    try:
        target.write_text(example.read_text(encoding="utf-8-sig"), encoding="utf-8")
    except Exception as e:
        log(f"[env] failed to seed {target}: {e}", "WARN")
        return False
    if sys.platform != "win32":
        try:
            os.chmod(target, 0o600)
        except Exception as e:
            log(f"[env] could not chmod 0600 {target}: {e}", "WARN")
    log(f"[env] seeded {target} from scripts/dg-supervisor.env.example", "INFO")
    return True


def _supervisor_platform() -> str:
    """Return 'Windows' | 'Darwin' | 'Linux' | 'Unsupported'.

    Centralizes the platform dispatch so every site is one branch. macOS
    launchd + Linux systemd-user are first-class supported supervisors
    (2026-05-18 — DG_ALLOW_CROSS_PLATFORM=1 gate retired after Linux smoke
    verified the daemon-loop + --serve spawn chain on Crostini). The gate
    served its purpose protecting users from untested code; with smoke
    in hand, the cross-platform paths are production behavior.
    """
    import platform as _p
    sysname = _p.system()
    if sysname in ("Windows", "Darwin", "Linux"):
        return sysname
    return "Unsupported"


def _parse_etime(s: str) -> "float | None":
    """Parse `ps -o etime=` output. Accepts 'MM:SS', 'HH:MM:SS', 'DD-HH:MM:SS'."""
    s = s.strip()
    if not s:
        return None
    try:
        if "-" in s:
            days, rest = s.split("-", 1)
            d = int(days)
        else:
            d = 0
            rest = s
        parts = rest.split(":")
        if len(parts) == 3:
            h, m, sec = int(parts[0]), int(parts[1]), int(parts[2])
        elif len(parts) == 2:
            h, m, sec = 0, int(parts[0]), int(parts[1])
        else:
            return None
        return float(d * 86400 + h * 3600 + m * 60 + sec)
    except (ValueError, IndexError):
        return None


def _wait_for_daemon_loop(enumerate_fn, timeout_s: float = 5.0) -> "int | None":
    """Poll `enumerate_fn()` every 0.5s until a daemon-loop pid appears, or
    timeout. launchctl / systemctl return before the spawned process has
    materialized, so callers that need the pid poll via this helper."""
    import time as _t
    deadline = _t.time() + timeout_s
    while _t.time() < deadline:
        _t.sleep(0.5)
        for pid, _cmd, role in enumerate_fn():
            if role == "daemon-loop":
                return pid
    return None


def _kill_until_clean(enumerate_fn, kill_fn, timeout_s: float = 8.0) -> int:
    """Loop kill+re-enumerate until no daemon-loop or serve procs remain,
    or timeout. Skips the calling process so we don't kill ourselves.
    Returns total kills."""
    import time as _t
    self_pid = os.getpid()
    killed_total = 0
    deadline = _t.time() + timeout_s
    while True:
        procs = [p for p in enumerate_fn() if p[0] != self_pid]
        daemon_pids = [pid for pid, _cmd, role in procs if role == "daemon-loop"]
        serve_pids = [pid for pid, _cmd, role in procs if role == "serve"]
        if not daemon_pids and not serve_pids:
            return killed_total
        killed_total += kill_fn(daemon_pids) + kill_fn(serve_pids)
        if _t.time() >= deadline:
            return killed_total
        _t.sleep(0.5)


def _supervisor_python_exe() -> str:
    """Return pythonw.exe (no-console interpreter) sibling of the current
    interpreter, falling back to sys.executable. Used for the Scheduled
    Task action and detached daemon-loop spawns so the supervisor doesn't
    pop a visible console window at logon."""
    cur = Path(sys.executable)
    if cur.name.lower() == "python.exe":
        sib = cur.parent / "pythonw.exe"
        if sib.exists():
            return str(sib)
    return str(cur)


def _console_python_exe() -> str:
    """Return python.exe (console interpreter) sibling of the current
    interpreter, falling back to sys.executable. Used by daemon-loop when
    spawning --serve so uvicorn keeps predictable stdio semantics even when
    daemon-loop itself is running under pythonw.exe. Platform-agnostic —
    on POSIX the `pythonw.exe` check fails and the function falls through
    to `sys.executable`, which is the right answer there too."""
    cur = Path(sys.executable)
    if cur.name.lower() == "pythonw.exe":
        sib = cur.parent / "python.exe"
        if sib.exists():
            return str(sib)
    return str(cur)


# ── POSIX-shared helpers (macOS in PR1, reused by Linux in PR2) ────────────

def _enumerate_research_py_procs_posix() -> list[tuple[int, str, str]]:
    """POSIX sibling of `_enumerate_research_py_procs_windows`. Reads
    `ps -ww -eo pid=,command=` and matches the `research.py` substring.
    `-ww` (BSD wide) prevents the default ~80-char cmdline truncation
    that would otherwise mask long invocations. Role logic mirrors
    Windows: --daemon-loop → daemon-loop, --serve → serve, else other."""
    import subprocess as _sp
    try:
        r = _sp.run(
            ["ps", "-ww", "-eo", "pid=,command="],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return []
    if r.returncode != 0:
        return []
    results: list[tuple[int, str, str]] = []
    for line in (r.stdout or "").splitlines():
        line = line.strip()
        if not line or "research.py" not in line:
            continue
        parts = line.split(None, 1)
        if len(parts) != 2:
            continue
        try:
            pid = int(parts[0])
        except ValueError:
            continue
        cmd = parts[1]
        if "--daemon-loop" in cmd:
            role = "daemon-loop"
        elif "--serve" in cmd:
            role = "serve"
        else:
            role = "other"
        results.append((pid, cmd, role))
    return results


def _proc_age_seconds_posix(pid: int) -> "float | None":
    """POSIX sibling of `_proc_age_seconds_windows`. Reads
    `ps -o etime= -p <pid>` and parses via `_parse_etime`. Returns None
    on unknown pid or unparseable output."""
    import subprocess as _sp
    try:
        r = _sp.run(
            ["ps", "-o", "etime=", "-p", str(pid)],
            capture_output=True, text=True, timeout=5,
        )
    except Exception:
        return None
    if r.returncode != 0:
        return None
    return _parse_etime(r.stdout or "")


def _kill_pids_posix(pids: list[int]) -> int:
    """POSIX sibling of `_kill_pids_windows`. SIGTERM each PID, wait 1s,
    SIGKILL survivors. Returns count confirmed terminated via kill(0) probe."""
    import signal as _signal
    import time as _t
    if not pids:
        return 0
    for pid in pids:
        try:
            os.kill(pid, _signal.SIGTERM)
        except (ProcessLookupError, PermissionError, OSError):
            pass
    _t.sleep(1.0)
    for pid in pids:
        try:
            os.kill(pid, _signal.SIGKILL)
        except (ProcessLookupError, PermissionError, OSError):
            pass
    confirmed = 0
    for pid in pids:
        try:
            os.kill(pid, 0)
        except (ProcessLookupError, PermissionError, OSError):
            confirmed += 1
    return confirmed


# ── macOS launchd helpers ───────────────────────────────────────────────────

def _arm_supervisor_macos() -> "tuple[bool, int | None, str, int]":
    """macOS sibling of `_arm_supervisor_quiet_windows`. Writes the launchd
    user agent plist at ~/Library/LaunchAgents/com.dgresearch.supervisor.plist
    and bootstraps it into gui/$(id -u). Returns the same tuple shape as the
    Windows path: (installed_ok, daemon_pid_or_None, info, killed_serve_count).

    `PATH` stays in plist's `EnvironmentVariables` because launchd does not
    inherit shell env and needs it to locate python3. All other env vars
    (Vision, CUA, API key) live in `.dg-supervisor.env` and are loaded by
    Python via `--env-file` before subcommand dispatch.

    EUID guard: refuses to install if running under sudo — would write the
    plist to /root/Library/... and leave it un-managed by the actual user."""
    import subprocess as _sp
    import os as _os

    if _os.geteuid() == 0:
        return False, None, "refuse: do not run under sudo (user agent must be in your own home)", 0

    _seed_env_file_if_missing()

    script_dir = Path(__file__).parent
    log_dir = script_dir / "logs"
    try:
        log_dir.mkdir(exist_ok=True)
        _SUPERVISOR_PLIST_PATH.parent.mkdir(parents=True, exist_ok=True)
    except Exception as e:
        return False, None, f"could not create dirs: {e}", 0

    python_exe = sys.executable
    script_path = str(Path(__file__).resolve())
    env_file = _SUPERVISOR_ENV_FILE_DEFAULT_PATH
    plist_xml = f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key>
  <string>{_SUPERVISOR_PLIST_LABEL}</string>
  <key>ProgramArguments</key>
  <array>
    <string>{python_exe}</string>
    <string>{script_path}</string>
    <string>--daemon-loop</string>
    <string>--env-file</string>
    <string>{env_file}</string>
  </array>
  <key>WorkingDirectory</key>
  <string>{script_dir}</string>
  <key>RunAtLoad</key>
  <true/>
  <key>KeepAlive</key>
  <true/>
  <key>ThrottleInterval</key>
  <integer>10</integer>
  <key>StandardOutPath</key>
  <string>{log_dir / 'supervisor.out.log'}</string>
  <key>StandardErrorPath</key>
  <string>{log_dir / 'supervisor.err.log'}</string>
  <key>EnvironmentVariables</key>
  <dict>
    <key>PATH</key>
    <string>/usr/local/bin:/usr/bin:/bin</string>
  </dict>
</dict>
</plist>
"""
    try:
        _SUPERVISOR_PLIST_PATH.write_text(plist_xml, encoding="utf-8")
    except Exception as e:
        return False, None, f"plist write failed: {e}", 0

    uid = _os.getuid()
    domain = f"gui/{uid}"
    label = f"{domain}/{_SUPERVISOR_PLIST_LABEL}"

    # Bootout first (idempotent — clears any prior install). Errors ignored.
    try:
        _sp.run(["launchctl", "bootout", label],
                capture_output=True, text=True, timeout=10)
    except Exception:
        pass

    # Bootstrap into gui/$uid so the agent runs in the Aqua session (Chrome
    # needs that scope for display + clipboard).
    try:
        r = _sp.run(["launchctl", "bootstrap", domain, str(_SUPERVISOR_PLIST_PATH)],
                    capture_output=True, text=True, timeout=15)
        if r.returncode != 0:
            return False, None, f"bootstrap failed: {(r.stderr or r.stdout).strip()[:120]}", 0
    except Exception as e:
        return False, None, f"bootstrap exception: {e}", 0

    # Enable + kickstart (best-effort — bootstrap usually starts the job,
    # kickstart forces a run regardless).
    try:
        _sp.run(["launchctl", "enable", label],
                capture_output=True, text=True, timeout=10)
    except Exception:
        pass
    try:
        _sp.run(["launchctl", "kickstart", "-k", label],
                capture_output=True, text=True, timeout=10)
    except Exception:
        pass

    # Sweep stale --serve procs (port 8000 conflict).
    procs = _enumerate_research_py_procs_posix()
    plain_serve_pids = [pid for pid, _c, role in procs if role == "serve"]
    killed_serve = _kill_pids_posix(plain_serve_pids) if plain_serve_pids else 0

    # Wait for daemon-loop pid (launchctl returns before child materializes).
    daemon_pid = _wait_for_daemon_loop(_enumerate_research_py_procs_posix, timeout_s=5.0)
    if daemon_pid is not None:
        return True, daemon_pid, "", killed_serve
    return True, None, "daemon-loop did not appear within 5s", killed_serve


def _disarm_supervisor_macos() -> "tuple[str, int]":
    """macOS sibling of `_disarm_supervisor_quiet_windows`. Bootout the
    launchd user agent, delete the plist, kill survivors. Returns
    (status, killed_total)."""
    import subprocess as _sp
    import os as _os

    if _os.geteuid() == 0:
        return "refuse: do not run under sudo", 0

    uid = _os.getuid()
    label = f"gui/{uid}/{_SUPERVISOR_PLIST_LABEL}"

    status = "no-task"
    try:
        r = _sp.run(["launchctl", "bootout", label],
                    capture_output=True, text=True, timeout=10)
        if r.returncode == 0:
            status = "removed"
        elif "could not find" in (r.stderr or "").lower() or "no such" in (r.stderr or "").lower():
            status = "no-task"
        else:
            status = (r.stderr or r.stdout or "bootout returned non-zero").strip()[:100]
    except Exception as e:
        status = f"bootout exception: {e}"

    # Delete plist regardless of bootout outcome.
    try:
        if _SUPERVISOR_PLIST_PATH.exists():
            _SUPERVISOR_PLIST_PATH.unlink()
    except Exception as e:
        if status == "removed":
            status = f"removed (plist unlink warning: {e})"

    killed = _kill_until_clean(_enumerate_research_py_procs_posix, _kill_pids_posix)
    return status, killed


def _detect_supervised_macos() -> bool:
    """macOS sibling of `_detect_supervised_windows`. Probes both `launchctl
    print gui/$uid/<label>` (definitive but session-scoped) AND `launchctl
    list <label>` (legacy fallback that works in some session-detached
    contexts). Returns True if either returns 0; False on any error /
    not bootstrapped. Belt-and-suspenders parity with the Linux probe at
    research.py:_detect_supervised_linux."""
    import subprocess as _sp
    import os as _os
    print_ok = False
    list_ok = False
    try:
        uid = _os.getuid()
        r = _sp.run(["launchctl", "print", f"gui/{uid}/{_SUPERVISOR_PLIST_LABEL}"],
                    capture_output=True, text=True, timeout=5)
        print_ok = (r.returncode == 0)
    except Exception as e:
        log(f"[supervisor-macos] launchctl print probe failed: {e}", "WARN")
    try:
        r = _sp.run(["launchctl", "list", _SUPERVISOR_PLIST_LABEL],
                    capture_output=True, text=True, timeout=5)
        list_ok = (r.returncode == 0)
    except Exception as e:
        log(f"[supervisor-macos] launchctl list probe failed: {e}", "WARN")
    return print_ok or list_ok


# ── Linux systemd-user helpers ──────────────────────────────────────────────

def _check_linger_status() -> str:
    """Probe `loginctl show-user $USER --property=Linger`. Returns
    'yes' | 'no' | 'unknown'. Linger=yes means the systemd user manager
    survives logout — required for the supervisor to keep daemon-loop
    alive across user sessions. If 'no', the user needs to run
    `sudo loginctl enable-linger $USER` manually (we don't escalate)."""
    import subprocess as _sp
    try:
        user = os.environ.get("USER") or os.environ.get("LOGNAME") or ""
        if not user:
            return "unknown"
        r = _sp.run(["loginctl", "show-user", user, "--property=Linger"],
                    capture_output=True, text=True, timeout=5)
        if r.returncode != 0:
            return "unknown"
        out = (r.stdout or "").strip().lower()
        if "linger=yes" in out:
            return "yes"
        if "linger=no" in out:
            return "no"
        return "unknown"
    except Exception:
        return "unknown"


def _arm_supervisor_linux() -> "tuple[bool, int | None, str, int]":
    """Linux sibling of `_arm_supervisor_macos`. Writes a systemd user
    unit at ~/.config/systemd/user/dgresearch-supervisor.service and
    enables it via `systemctl --user enable --now`. Returns
    (installed_ok, daemon_pid_or_None, info, killed_serve_count).

    `PassEnvironment=DISPLAY WAYLAND_DISPLAY XDG_RUNTIME_DIR` lets the
    supervisor see the graphical session — Chrome needs that for the
    visible browser window. Without this the service starts but Chrome
    has nowhere to render.

    Linger probe: WARN-only if `loginctl Linger=no`. User must run
    `sudo loginctl enable-linger $USER` themselves; we don't escalate.
    Without linger, daemon-loop dies at logout (the user-session systemd
    manager is reaped).

    EUID guard: refuses under sudo — unit would land in
    /root/.config/systemd/user/ (wrong manager)."""
    import subprocess as _sp
    import os as _os

    if _os.geteuid() == 0:
        return False, None, "refuse: do not run under sudo (user unit must be in your own home)", 0

    _seed_env_file_if_missing()

    # Linger probe — warn but don't fail. Without linger the supervisor
    # works while user is logged in but dies on logout. Acceptable for
    # PR2; user can enable linger separately.
    linger = _check_linger_status()
    if linger == "no":
        log("[supervisor-linux] loginctl Linger=no for this user. Run "
            "`sudo loginctl enable-linger $USER` so daemon-loop survives "
            "logout.", "WARN")

    script_dir = Path(__file__).parent
    log_dir = script_dir / "logs"
    try:
        log_dir.mkdir(exist_ok=True)
        _SUPERVISOR_UNIT_PATH.parent.mkdir(parents=True, exist_ok=True)
    except Exception as e:
        return False, None, f"could not create dirs: {e}", 0

    python_exe = sys.executable
    script_path = str(Path(__file__).resolve())
    env_file = _SUPERVISOR_ENV_FILE_DEFAULT_PATH

    # Capture display env from the CURRENT shell (the one running
    # --resurrect / --pair). Bake these into the unit's Environment=
    # lines so the supervisor has DISPLAY on every container restart —
    # PassEnvironment alone is a race condition: on Crostini and other
    # Linux desktops without a full DE, the user-systemd manager auto-
    # fires enabled units BEFORE Sommelier / the graphical session
    # populates DISPLAY in the manager env. By the time PassEnvironment
    # runs there's nothing to pass. Hardcoding from --resurrect's shell
    # gives reboot-safe behavior. 2026-05-19 — caught during Linux
    # Chromebook smoke when Playwright failed to launch Chromium under
    # the systemd-spawned --serve despite working from terminal.
    _shell_disp    = (os.environ.get("DISPLAY") or "").strip()
    _shell_wayland = (os.environ.get("WAYLAND_DISPLAY") or "").strip()
    _shell_xauth   = (os.environ.get("XAUTHORITY") or "").strip()
    _shell_xdg_rt  = (os.environ.get("XDG_RUNTIME_DIR") or "").strip()
    env_lines = []
    if _shell_disp:
        env_lines.append(f'Environment="DISPLAY={_shell_disp}"')
    if _shell_wayland:
        env_lines.append(f'Environment="WAYLAND_DISPLAY={_shell_wayland}"')
    if _shell_xauth:
        env_lines.append(f'Environment="XAUTHORITY={_shell_xauth}"')
    if _shell_xdg_rt:
        env_lines.append(f'Environment="XDG_RUNTIME_DIR={_shell_xdg_rt}"')
    if not env_lines:
        log("[supervisor-linux] no DISPLAY in the calling shell — unit "
            "will rely on PassEnvironment only. If browser launch fails "
            "post-reboot, re-run --resurrect from a graphical-session "
            "terminal so DISPLAY is captured.", "WARN")
    env_block = "\n".join(env_lines)

    # systemd `ExecStart=` is whitespace-tokenized — any path with a space
    # (we live under "DG Research") must be double-quoted or systemd will
    # split `/home/.../DG` from `Research/research.py` and try to exec a
    # non-existent script in a tight Restart=always loop. `WorkingDirectory=`
    # and `StandardOutput=append:<path>` take single values (not tokenized)
    # but we quote consistently for hygiene.
    unit_content = f"""[Unit]
Description=DG Super Research Backend Supervisor
After=network-online.target graphical-session.target
Wants=network-online.target
StartLimitIntervalSec=120
StartLimitBurst=10

[Service]
Type=simple
WorkingDirectory={script_dir}
ExecStart="{python_exe}" "{script_path}" --daemon-loop --env-file "{env_file}"
Restart=always
RestartSec=10
{env_block}
PassEnvironment=DISPLAY WAYLAND_DISPLAY XAUTHORITY XDG_RUNTIME_DIR

StandardOutput=append:{log_dir}/supervisor.out.log
StandardError=append:{log_dir}/supervisor.err.log

[Install]
WantedBy=default.target
"""
    try:
        _SUPERVISOR_UNIT_PATH.write_text(unit_content, encoding="utf-8")
    except Exception as e:
        return False, None, f"unit write failed: {e}", 0

    # daemon-reload picks up the new unit (systemd doesn't auto-scan).
    try:
        _sp.run(["systemctl", "--user", "daemon-reload"],
                capture_output=True, text=True, timeout=10)
    except Exception:
        pass

    # Belt-and-suspenders: import current shell's graphical-session env
    # into the user-systemd manager BEFORE enabling the unit. Fixes the
    # immediate post-resurrect run on machines where the manager hadn't
    # picked up DISPLAY yet. The embedded Environment= lines above handle
    # reboot-survival; this handles "I just installed and want it to
    # work without restart" UX. Idempotent — safe to no-op if vars are
    # missing from the shell.
    _import_vars = []
    if _shell_disp:    _import_vars.append("DISPLAY")
    if _shell_wayland: _import_vars.append("WAYLAND_DISPLAY")
    if _shell_xauth:   _import_vars.append("XAUTHORITY")
    if _shell_xdg_rt:  _import_vars.append("XDG_RUNTIME_DIR")
    if _import_vars:
        try:
            _sp.run(["systemctl", "--user", "import-environment", *_import_vars],
                    capture_output=True, text=True, timeout=10)
        except Exception as _ie:
            log(f"[supervisor-linux] import-environment failed (non-fatal): {_ie}", "WARN")

    # enable --now sets WantedBy=default.target AND starts immediately.
    try:
        r = _sp.run(["systemctl", "--user", "enable", "--now", _SUPERVISOR_UNIT_NAME],
                    capture_output=True, text=True, timeout=15)
        if r.returncode != 0:
            return False, None, f"systemctl enable --now failed: {(r.stderr or r.stdout).strip()[:120]}", 0
    except Exception as e:
        return False, None, f"systemctl exception: {e}", 0

    # Sweep stale --serve procs (port 8000 conflict).
    procs = _enumerate_research_py_procs_posix()
    plain_serve_pids = [pid for pid, _c, role in procs if role == "serve"]
    killed_serve = _kill_pids_posix(plain_serve_pids) if plain_serve_pids else 0

    daemon_pid = _wait_for_daemon_loop(_enumerate_research_py_procs_posix, timeout_s=5.0)
    if daemon_pid is not None:
        return True, daemon_pid, "", killed_serve
    return True, None, "daemon-loop did not appear within 5s", killed_serve


def _disarm_supervisor_linux() -> "tuple[str, int]":
    """Linux sibling of `_disarm_supervisor_macos`. `systemctl --user
    disable --now`, delete unit file, daemon-reload, kill survivors."""
    import subprocess as _sp
    import os as _os

    if _os.geteuid() == 0:
        return "refuse: do not run under sudo", 0

    status = "no-task"
    try:
        r = _sp.run(["systemctl", "--user", "disable", "--now", _SUPERVISOR_UNIT_NAME],
                    capture_output=True, text=True, timeout=15)
        if r.returncode == 0:
            status = "removed"
        else:
            combined = ((r.stderr or "") + (r.stdout or "")).lower()
            if "does not exist" in combined or "no such file" in combined or "not loaded" in combined:
                status = "no-task"
            else:
                status = (r.stderr or r.stdout or "systemctl returned non-zero").strip()[:100]
    except Exception as e:
        status = f"systemctl exception: {e}"

    # Delete unit file regardless.
    try:
        if _SUPERVISOR_UNIT_PATH.exists():
            _SUPERVISOR_UNIT_PATH.unlink()
    except Exception as e:
        if status == "removed":
            status = f"removed (unit unlink warning: {e})"

    # daemon-reload to forget the unit.
    try:
        _sp.run(["systemctl", "--user", "daemon-reload"],
                capture_output=True, text=True, timeout=10)
    except Exception:
        pass

    killed = _kill_until_clean(_enumerate_research_py_procs_posix, _kill_pids_posix)
    return status, killed


def _detect_supervised_linux() -> bool:
    """Linux sibling of `_detect_supervised_macos`. Probes BOTH `is-enabled`
    and `is-active` because `is-enabled` alone returns non-zero in legitimate
    "supervisor is running fine" states like `static`, `enabled-runtime`, or
    `linked`, and on Crostini-style transient managers where the unit auto-
    starts via `WantedBy=default.target` but `is-enabled` reports `linked`.
    The toggle should reflect "is the supervisor going to keep --serve alive",
    which is satisfied if EITHER the unit is enabled OR currently active.

    Returns True if either check returns 0; False otherwise (including
    timeout / DBus unavailable / systemctl missing)."""
    import subprocess as _sp
    enabled_ok = False
    active_ok = False
    try:
        r = _sp.run(["systemctl", "--user", "is-enabled", _SUPERVISOR_UNIT_NAME],
                    capture_output=True, text=True, timeout=5)
        # `is-enabled` returns 0 for enabled / static / alias / generated.
        # `enabled-runtime` / `linked` / `linked-runtime` exit 0 in current
        # systemd, but legacy versions exited non-zero on those. Fall back
        # to stdout parse so older systemd doesn't trip us.
        out = (r.stdout or "").strip().lower()
        enabled_ok = (r.returncode == 0) or out in {
            "enabled", "enabled-runtime", "static", "linked",
            "linked-runtime", "alias", "generated",
        }
    except Exception as e:
        log(f"[supervisor-linux] is-enabled probe failed: {e}", "WARN")
    try:
        r = _sp.run(["systemctl", "--user", "is-active", _SUPERVISOR_UNIT_NAME],
                    capture_output=True, text=True, timeout=5)
        active_ok = (r.returncode == 0) or (r.stdout or "").strip() == "active"
    except Exception as e:
        log(f"[supervisor-linux] is-active probe failed: {e}", "WARN")
    return enabled_ok or active_ok


def _enumerate_research_py_procs() -> list[tuple[int, str, str]]:
    """Dispatcher — routes to `_enumerate_research_py_procs_windows` or
    `_enumerate_research_py_procs_posix`. Returns [] on Unsupported."""
    plat = _supervisor_platform()
    if plat == "Windows":
        return _enumerate_research_py_procs_windows()
    if plat in ("Darwin", "Linux"):
        return _enumerate_research_py_procs_posix()
    return []


def _enumerate_research_py_procs_windows() -> list[tuple[int, str, str]]:
    """Return [(pid, cmdline, role), ...] for every python.exe / pythonw.exe
    whose command line references this script. role ∈ {'daemon-loop',
    'serve', 'other'}. Single source of truth for --resurrect (what's
    running before I spawn?) and --retire (what do I need to kill?).

    Matches on "research.py" substring so subprocess invocations launched
    from different cwd styles (absolute, relative, with/without quotes)
    all get caught.

    Includes pythonw.exe because the Scheduled Task action runs the
    supervisor under the no-console interpreter."""
    try:
        ps = subprocess.run(
            ["wmic", "process", "where",
             "(name='python.exe' or name='pythonw.exe')",
             "get", "processid,commandline", "/format:list"],
            capture_output=True, text=True, timeout=15,
            creationflags=_PS_NO_WINDOW,
        )
    except Exception:
        return []
    # wmic /format:list emits blank lines BETWEEN fields of the same entry
    # (CommandLine=...\n\nProcessId=...\n\n\n\n) on Windows 10/11. The old
    # parser treated any blank line as an entry boundary, splitting each
    # process into two single-field entries — silently broke this function
    # on real systems. New parser flushes only when BOTH expected fields
    # have been collected.
    entries: list[dict[str, str]] = []
    cur: dict[str, str] = {}
    for line in (ps.stdout or "").splitlines():
        line = line.strip()
        if not line:
            continue
        if "=" in line:
            k, _, v = line.partition("=")
            cur[k.strip()] = v.strip()
            if "CommandLine" in cur and "ProcessId" in cur:
                entries.append(cur); cur = {}
    if cur:
        entries.append(cur)
    results: list[tuple[int, str, str]] = []
    for e in entries:
        cmdline = e.get("CommandLine", "")
        if "research.py" not in cmdline:
            continue
        try:
            pid = int(e.get("ProcessId", ""))
        except ValueError:
            continue
        if "--daemon-loop" in cmdline:
            role = "daemon-loop"
        elif "--serve" in cmdline:
            role = "serve"
        else:
            role = "other"
        results.append((pid, cmdline, role))
    return results


def _proc_age_seconds(pid: int) -> "float | None":
    """Dispatcher — routes to `_proc_age_seconds_windows` or `_proc_age_seconds_posix`."""
    plat = _supervisor_platform()
    if plat == "Windows":
        return _proc_age_seconds_windows(pid)
    if plat in ("Darwin", "Linux"):
        return _proc_age_seconds_posix(pid)
    return None


def _proc_age_seconds_windows(pid: int) -> "float | None":
    """Return seconds since process creation, or None if unknown.
    Best-effort via wmic CreationDate (yyyymmddHHMMSS.ffffff±zzz)."""
    try:
        r = subprocess.run(
            ["wmic", "process", "where", f"ProcessId={pid}",
             "get", "CreationDate", "/format:list"],
            capture_output=True, text=True, timeout=10,
            creationflags=_PS_NO_WINDOW,
        )
        for line in (r.stdout or "").splitlines():
            if line.startswith("CreationDate="):
                stamp = line.split("=", 1)[1].strip()[:14]
                if len(stamp) == 14:
                    import datetime as _dt
                    created = _dt.datetime.strptime(stamp, "%Y%m%d%H%M%S")
                    return (_dt.datetime.now() - created).total_seconds()
    except Exception:
        return None
    return None


def _kill_pids(pids: list[int]) -> int:
    """Dispatcher — routes to `_kill_pids_windows` or `_kill_pids_posix`."""
    plat = _supervisor_platform()
    if plat == "Windows":
        return _kill_pids_windows(pids)
    if plat in ("Darwin", "Linux"):
        return _kill_pids_posix(pids)
    return 0


def _free_port_8000() -> "list[int]":
    """Find and force-kill any process listening on port 8000 so a fresh
    --serve can bind. Used by --resurrect (and any future arming path)
    to clear stale squatters — both crashed-but-port-leaked --serves and
    accidentally-running third-party apps.

    Returns the list of PIDs that were killed. Returns [] when port is
    already free or no killable owner could be identified (best-effort).
    Cross-platform — Windows uses netstat, POSIX uses lsof.
    """
    import subprocess as _sp
    plat = _supervisor_platform()
    pids_to_kill: "set[int]" = set()
    try:
        if plat == "Windows":
            r = _sp.run(
                ["netstat", "-ano", "-p", "TCP"],
                capture_output=True, text=True, timeout=8,
                creationflags=_PS_NO_WINDOW,
            )
            for line in (r.stdout or "").splitlines():
                # Format: "  TCP    0.0.0.0:8000    0.0.0.0:0    LISTENING    1234"
                if "LISTENING" not in line:
                    continue
                if ":8000 " not in line and not line.endswith(":8000"):
                    if " :8000\t" not in line and "0.0.0.0:8000" not in line and "[::]:8000" not in line:
                        continue
                parts = line.split()
                if not parts:
                    continue
                try:
                    pid = int(parts[-1])
                except ValueError:
                    continue
                if pid > 0 and pid != os.getpid():
                    pids_to_kill.add(pid)
        elif plat in ("Darwin", "Linux"):
            r = _sp.run(
                ["lsof", "-ti", ":8000"],
                capture_output=True, text=True, timeout=8,
            )
            for line in (r.stdout or "").splitlines():
                line = line.strip()
                if not line:
                    continue
                try:
                    pid = int(line)
                except ValueError:
                    continue
                if pid > 0 and pid != os.getpid():
                    pids_to_kill.add(pid)
    except Exception:
        return []
    if not pids_to_kill:
        return []
    _kill_pids(list(pids_to_kill))
    return sorted(pids_to_kill)


def _kill_pids_windows(pids: list[int]) -> int:
    """taskkill /F each PID. Returns count that successfully terminated.
    Silent on individual failures — caller can re-enumerate to confirm."""
    killed = 0
    for pid in pids:
        try:
            r = subprocess.run(
                ["taskkill", "/F", "/PID", str(pid)],
                capture_output=True, text=True, timeout=10,
                creationflags=_PS_NO_WINDOW,
            )
            if r.returncode == 0:
                killed += 1
        except Exception:
            pass
    return killed


def _wait_for_port_free(port: int, max_wait_s: float = 10.0) -> bool:
    """Poll bindability of 0.0.0.0:<port> until it becomes free or the
    timeout fires. Returns True if the port is bindable, False if we
    gave up. Used by the daemon-loop's restart cycle so a fresh --serve
    isn't immediately wedged by Windows holding the previous socket in
    TIME_WAIT (typically <1s on a clean exit, but can stretch to ~30s
    if uvicorn was force-killed mid-handshake).

    Uses SO_REUSEADDR=0 (default) for the probe — we want to know if
    the port is *truly* free, not whether we could squeeze in. The
    real --serve subprocess will bind without REUSEADDR moments later,
    so a probe success guarantees uvicorn won't hit EADDRINUSE."""
    import socket as _socket
    import time as _t  # `_time` is only imported inside run_daemon_loop;
                       # this helper runs module-level so it imports its own.
    deadline = _t.time() + max_wait_s
    while _t.time() < deadline:
        sock = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
        try:
            sock.bind(("0.0.0.0", port))
            sock.close()
            return True
        except OSError:
            sock.close()
            _t.sleep(0.5)
    return False


def run_daemon_loop(port: int = 8000):
    """Wrapper that keeps `--serve` alive. The scheduled task installed by
    --resurrect invokes this instead of --serve directly so that the
    backend restarts automatically on ANY exit — clean shutdown from the
    Stop button (which calls os._exit to force Chromium cleanup), crashes,
    upstream failures, anything. Without this, --resurrect only fires the
    process once per logon, which defeats the "supervised" promise.

    Loops forever with a 5s delay between restarts. Exits on
    KeyboardInterrupt OR on SIGTERM/taskkill (so --retire can stop
    the live loop without requiring a reboot). The --serve child
    process is NOT killed — it stays alive so the current pipeline
    finishes, and the user manages it manually from then on."""
    import sys as _sys
    import subprocess as _subprocess
    import time as _time

    script_path = str(Path(__file__).resolve())
    _log_dir = Path(script_path).parent
    _serve_log = _log_dir / "backend.log"
    _serve_err = _log_dir / "backend.err.log"

    # When the Scheduled Task action runs the supervisor under pythonw.exe
    # (no-console interpreter — keeps the daemon-loop window from appearing
    # at logon), sys.stdout / sys.stderr are None and any print() inside
    # log() crashes. Tee both to the backend log files BEFORE the first
    # log() call so the supervisor stays observable and never raises on a
    # write. No-op when running under console-attached python.exe.
    if Path(_sys.executable).name.lower() == "pythonw.exe":
        try:
            _sys.stdout = open(_serve_log, "a", encoding="utf-8", buffering=1)
            _sys.stderr = open(_serve_err, "a", encoding="utf-8", buffering=1)
        except Exception:
            pass

    # --serve always runs under console python.exe for predictable stdio
    # semantics even when the supervisor itself is pythonw.exe; uvicorn
    # output still flows into the redirected log files below, and
    # CREATE_NO_WINDOW keeps the child invisible regardless of parent.
    python_exe = _console_python_exe()

    # When --resurrect spawns daemon-loop detached (DETACHED_PROCESS), this
    # wrapper runs with no console. A naked `subprocess.run` on python.exe
    # (a console app) then forces Windows to ALLOCATE A NEW CONSOLE for
    # every --serve spawn — and every restart pops another visible terminal
    # window. CREATE_NO_WINDOW suppresses that allocation, and redirecting
    # stdio to the log files keeps uvicorn's output tailable without a
    # window ever appearing.
    #
    # 2026-05-18 (Track C smoke caught this) — `creationflags` is Windows-
    # only at the subprocess level. Passing any non-zero value to Popen on
    # POSIX raises `ValueError: creationflags is only supported on Windows
    # platforms`. The pre-fix `getattr(...CREATE_NO_WINDOW, 0x08000000)`
    # fallback fired on Linux + macOS (CREATE_NO_WINDOW doesn't exist there
    # → 0x08000000 default), making every `--serve` respawn explode in the
    # daemon-loop. Match the module-level `_PS_NO_WINDOW` pattern at
    # research.py:128 — 0 on non-Windows is the only safe value.
    _NO_WINDOW = (
        getattr(_subprocess, "CREATE_NO_WINDOW", 0x08000000)
        if sys.platform == "win32"
        else 0
    )

    # Pre-flight orphan sweep — runs once at wrapper startup. Catches:
    #   (a) other daemon-loop PIDs (only one wrapper at a time; PT5M task
    #       repetition with MultipleInstances=IgnoreNew should prevent this,
    #       but defend in depth in case of manual --daemon-loop alongside),
    #   (b) stale --serve PIDs from a prior wrapper death — port 8000 must
    #       belong to the --serve we're about to spawn,
    #   (c) one-off `python research.py "<topic>"` runs older than
    #       DG_ORPHAN_MAX_AGE_HOURS (default 4h) — manual smoke tests that
    #       were never reaped. Set =0 to disable, =24 for safety on long runs.
    self_pid = os.getpid()
    try:
        max_age_h = float(os.environ.get("DG_ORPHAN_MAX_AGE_HOURS", "4"))
    except ValueError:
        max_age_h = 4.0
    sweep_pids: list[int] = []
    try:
        for pid, _cmd, role in _enumerate_research_py_procs():
            if pid == self_pid:
                continue
            if role in ("daemon-loop", "serve"):
                sweep_pids.append(pid)
            elif role == "other" and max_age_h > 0:
                age_s = _proc_age_seconds(pid)
                if age_s is not None and age_s > max_age_h * 3600:
                    sweep_pids.append(pid)
    except Exception as _se:
        log(f"[daemon-loop] Pre-flight sweep enumeration failed: {_se}", "WARN")
    if sweep_pids:
        killed = _kill_pids(sweep_pids)
        log(f"[daemon-loop] Pre-flight sweep: killed {killed}/{len(sweep_pids)} stale research.py procs ({sweep_pids})")

    # Pre-flight dependency probe — runs once before the respawn loop.
    # Catches the silent-crash trap: when --serve fails its import
    # chain (e.g. fastapi missing, or google.auth transitive dep absent),
    # the supervisor would otherwise retry forever at 5s/cycle with no
    # loud signal. One loud abort is much better than infinite quiet
    # retries — the supervisor's re-fire still gives a second chance
    # after the user reinstalls deps.
    try:
        import importlib
        # Full dotted module paths — importlib.import_module handles
        # submodules (PIL.Image, google.auth, google.cloud.firestore) but
        # `import PIL; getattr(PIL, "Image")` raises AttributeError
        # because PIL.Image is a submodule, not an attribute of the
        # PIL package.
        _critical = [
            "fastapi", "uvicorn", "websockets", "pydantic",
            "typing_extensions", "anthropic", "playwright", "patchright",
            "google.auth", "google.cloud.firestore", "keyring",
            "PIL.Image", "markdownify", "requests", "qrcode",
        ]
        _missing: list[str] = []
        for _mod in _critical:
            try:
                importlib.import_module(_mod)
            except Exception as _ie:
                _missing.append(f"{_mod} ({_ie.__class__.__name__}: {_ie})")
        if _missing:
            _req_path = _log_dir / "requirements.txt"
            _msg = (
                f"SUPERVISOR ABORT: {len(_missing)} required import(s) failed under "
                f"{python_exe}. Run: \"{python_exe}\" -m pip install -r \"{_req_path}\". "
                f"Missing: " + "; ".join(_missing)
            )
            try:
                log(_msg, "ERROR")
            except Exception:
                pass
            try:
                with open(_serve_err, "a", encoding="utf-8") as _ef:
                    _bar = "=" * 80
                    _ef.write(f"\n{_bar}\n[{_time.strftime('%H:%M:%S')}] {_msg}\n{_bar}\n")
            except Exception:
                pass
            _sys.exit(2)
    except SystemExit:
        raise
    except Exception as _pe:
        log(f"[daemon-loop] Pre-flight import probe crashed (continuing anyway): {_pe}", "WARN")

    # ──── Multi-worker branch (2026-05-21) ────────────────────────────
    # workerCount > 1 means pair Stage 4 set up N>=2 browser profiles —
    # spawn N --serve subprocesses (one per profile slot) in parallel via
    # Popen + a poll loop. Each worker K binds port (port + K - 1) and
    # is pinned to its own profile dir via --worker-id=K. Single-worker
    # mode (workerCount=1) falls through to the existing subprocess.run
    # blocking loop below — same behavior as pre-PR.
    CRASH_WINDOW_SEC = 30
    CRASH_THRESHOLD = 3
    # #717 — liveness watchdog. The crash tracker above only fires on process
    # EXIT; a worker can also WEDGE (event loop stalled, or Firestore stuck
    # offline despite localhost up) without exiting. The watchdog polls
    # /api/health and force-respawns a wedged worker. It is damped by its OWN
    # window (NOT crash_window) so a watchdog respawn NEVER trips the worker-1
    # keystore-wipe path, and capped so a sustained global outage (every worker
    # unreachable) doesn't storm. Backstops are idle-only and worker-aware to
    # avoid false-killing a busy run or the heartbeat-silent worker 2.
    WATCHDOG_HANG_SEC = 180          # /api/health unreachable this long while IDLE → wedged
    WATCHDOG_HANG_RUNNING_SEC = 420  # ...lenient if it was mid-run (runs can briefly block the loop)
    WATCHDOG_TICK_STALE_SEC = 120    # health OK but reconnect-loop pulse frozen → event loop wedged
    WATCHDOG_OFFLINE_SEC = 150       # worker-1 only: health OK but device heartbeat stale → reconnect failing
    WATCHDOG_KILL_THRESHOLD = 3      # watchdog respawns within the window → give up (likely a sustained outage)
    WATCHDOG_KILL_WINDOW_SEC = 600
    n_workers = load_worker_count()
    if n_workers > 1:
        log(f"[daemon-loop] Multi-worker mode: spawning {n_workers} workers")
        # Per-worker state: process handle, log file handles, crash window,
        # keystore-wiped flag, restart count. None = dead (won't respawn —
        # for workers that hit crash-loop threshold; worker-1 always retries
        # via the keystore-wipe recovery path).
        workers: dict[int, dict] = {}

        def _open_logs(k: int):
            # Worker 1 keeps the legacy log filenames so existing tooling
            # (tail backend.log) keeps working. Workers 2+ get -{k} suffix
            # so the streams don't interleave.
            if k == 1:
                return (_log_dir / "backend.log", _log_dir / "backend.err.log")
            return (_log_dir / f"backend-{k}.log", _log_dir / f"backend-{k}.err.log")

        def _spawn_worker(k: int):
            w_port = port + (k - 1)
            log_out_path, log_err_path = _open_logs(k)
            # Port probe — if the port is wedged from a prior session,
            # log it and try anyway (uvicorn will surface EADDRINUSE).
            if not _wait_for_port_free(w_port, max_wait_s=10.0):
                log(f"[daemon-loop] worker {k}: port {w_port} still in use after 10s — spawning anyway", "WARN")
            try:
                _out_fh = open(log_out_path, "ab")
                _err_fh = open(log_err_path, "ab")
            except Exception as _oe:
                log(f"[daemon-loop] worker {k}: log file open failed: {_oe}", "ERROR")
                return None
            try:
                proc = _subprocess.Popen(
                    [python_exe, script_path, "--serve",
                     "--port", str(w_port), "--worker-id", str(k)],
                    stdin=_subprocess.DEVNULL,
                    stdout=_out_fh,
                    stderr=_err_fh,
                    creationflags=_NO_WINDOW,
                )
            except Exception as _se:
                log(f"[daemon-loop] worker {k}: Popen failed: {_se}", "ERROR")
                try:
                    _out_fh.close()
                    _err_fh.close()
                except Exception:
                    pass
                return None
            log(f"[daemon-loop] worker {k}: started PID={proc.pid} port={w_port}")
            return {
                "process": proc,
                "out_fh": _out_fh,
                "err_fh": _err_fh,
                "port": w_port,
                "crash_window": [],
                "keystore_wiped": False,
                "restarts": 0,
                # #717 watchdog state (separate from crash tracking)
                "watchdog_window": [],
                "unreachable_since": None,
                "last_running": False,
                "watchdog_killing": False,
                "watchdog_gaveup": False,
            }

        def _probe_worker_health(w_port: int):
            """GET /api/health on a worker. Returns the parsed dict, or None if
            unreachable (connection refused / timeout / bad response). stdlib
            urllib so the supervisor needs no extra deps. (#717)"""
            try:
                import urllib.request as _u
                with _u.urlopen(f"http://127.0.0.1:{w_port}/api/health", timeout=3) as _r:
                    return json.loads(_r.read().decode("utf-8"))
            except Exception:
                return None

        def _watchdog_respawn(k: int, state: dict, reason: str):
            """Force-respawn a wedged worker. Uses a SEPARATE damping window so
            it never feeds the crash tracker (which wipes worker-1's keystore on
            a 3x loop). Hard terminate — a wedged event loop can't run its own
            graceful exit; the respawned worker's Browser.start() orphan sweep
            reaps any leftover chromium. Gives up after WATCHDOG_KILL_THRESHOLD
            respawns in the window so a sustained outage (every worker
            unreachable at once) doesn't storm. (#717)"""
            now = _time.time()
            win = [t for t in state.get("watchdog_window", []) if t > now - WATCHDOG_KILL_WINDOW_SEC]
            if len(win) >= WATCHDOG_KILL_THRESHOLD:
                if not state.get("watchdog_gaveup"):
                    log(f"[watchdog] worker {k}: {WATCHDOG_KILL_THRESHOLD} respawns in "
                        f"<{WATCHDOG_KILL_WINDOW_SEC}s — GIVING UP watchdog respawns "
                        f"(likely a sustained outage, not a per-worker wedge). "
                        f"Last reason: {reason}", "ERROR")
                    state["watchdog_gaveup"] = True
                return
            win.append(now)
            state["watchdog_window"] = win
            state["watchdog_killing"] = True
            state["unreachable_since"] = None
            log(f"[watchdog] worker {k}: force-respawning — {reason}", "WARN")
            try:
                state["process"].terminate()
            except Exception as _te:
                log(f"[watchdog] worker {k}: terminate failed: {_te}", "WARN")

        def _watchdog_check(k: int, state: dict):
            """Poll a RUNNING worker's health and respawn it if wedged. Scoped to
            avoid false-kills: device-heartbeat staleness is worker-1 only (only
            w1 writes it); active-run + relink workers are exempt from the idle
            backstops; the frozen-pulse check uses the per-worker lastTickAt so
            it also covers the heartbeat-silent worker 2. (#717)"""
            if state.get("watchdog_gaveup") or state.get("watchdog_killing"):
                return
            now = _time.time()
            health = _probe_worker_health(state.get("port"))
            if health is None:
                # Unreachable — could be a wedge, or a worker still booting.
                if state.get("unreachable_since") is None:
                    state["unreachable_since"] = now
                was_running = state.get("last_running", False)
                limit = WATCHDOG_HANG_RUNNING_SEC if was_running else WATCHDOG_HANG_SEC
                if now - state["unreachable_since"] > limit:
                    _watchdog_respawn(k, state,
                        f"/api/health unreachable {int(now - state['unreachable_since'])}s "
                        f"(was_running={was_running})")
                return
            # Reachable — refresh cached state, clear the unreachable timer.
            state["unreachable_since"] = None
            running = bool(health.get("running"))
            relinking = bool(health.get("relinking"))
            state["last_running"] = running
            # Idle backstops only — never force-respawn mid-run or mid-relink
            # (defer to the in-run watchdog / the legit 15-min relink poll).
            if running or relinking:
                return
            tick = int(health.get("lastTickAt") or 0)
            if tick > 0 and (now * 1000 - tick) > WATCHDOG_TICK_STALE_SEC * 1000:
                _watchdog_respawn(k, state,
                    f"reconnect-loop pulse frozen {int(now - tick / 1000)}s (event loop wedged)")
                return
            if k == 1:
                hb = int(health.get("lastHeartbeatAt") or 0)
                if hb > 0 and (now * 1000 - hb) > WATCHDOG_OFFLINE_SEC * 1000:
                    _watchdog_respawn(k, state,
                        f"device heartbeat stale {int(now - hb / 1000)}s despite reachable "
                        f"health (in-process reconnect failing)")

        # Initial spawn of all workers.
        for k in range(1, n_workers + 1):
            workers[k] = _spawn_worker(k) or {"_dead": True}

        try:
            while True:
                _time.sleep(2)
                for k in range(1, n_workers + 1):
                    state = workers.get(k)
                    if state is None or state.get("_dead"):
                        # Spawn-failed-permanently slots can be retried on
                        # the next iteration in case the underlying issue
                        # (port held, disk full, etc.) cleared.
                        new_state = _spawn_worker(k)
                        if new_state is not None:
                            workers[k] = new_state
                        continue
                    rc = state["process"].poll()
                    if rc is None:
                        # Still running — liveness watchdog (#717).
                        _watchdog_check(k, state)
                        continue
                    # Worker exited — close logs, track crash, decide.
                    log(f"[daemon-loop] worker {k}: exited with code {rc}")
                    try:
                        state["out_fh"].close()
                        state["err_fh"].close()
                    except Exception:
                        pass
                    # A watchdog-initiated terminate must NOT feed the crash
                    # tracker — that path wipes worker-1's keystore on a 3x loop
                    # and would force a re-pair. Respawn clean, carrying only the
                    # watchdog's own damping window. (#717)
                    if state.pop("watchdog_killing", False):
                        log(f"[daemon-loop] worker {k}: respawning after watchdog terminate")
                        _time.sleep(2)
                        new_state = _spawn_worker(k)
                        if new_state is not None:
                            new_state["watchdog_window"] = state.get("watchdog_window", [])
                            workers[k] = new_state
                        else:
                            workers[k] = {"_dead": True}
                        continue
                    if rc == 0:
                        state["crash_window"] = []
                        state["keystore_wiped"] = False
                        state["watchdog_window"] = []  # clean exit resets watchdog damping too
                    else:
                        _now = _time.time()
                        state["crash_window"].append(_now)
                        state["crash_window"] = [
                            t for t in state["crash_window"] if t > _now - CRASH_WINDOW_SEC
                        ]
                        if (
                            len(state["crash_window"]) >= CRASH_THRESHOLD
                            and not state["keystore_wiped"]
                        ):
                            if k == 1:
                                # Worker 1 owns the keystore; on crash loop,
                                # wipe so the next --serve enters recovery.
                                log(
                                    f"[daemon-loop] worker 1: crash loop "
                                    f"({len(state['crash_window'])} non-zero exits "
                                    f"in <{CRASH_WINDOW_SEC}s) — wiping keystore",
                                    "WARN",
                                )
                                try:
                                    from auth import keystore as _ks_recovery
                                    _ks_recovery.clear_all(_ks_recovery.install_uuid())
                                    state["keystore_wiped"] = True
                                    state["crash_window"] = []
                                except Exception as _ke:
                                    log(f"[daemon-loop] keystore wipe failed: {_ke}", "ERROR")
                            else:
                                # Worker 2+ crash loop: most likely a port
                                # conflict or missing profile dir. Stop
                                # respawning to prevent log spam; primary
                                # (w1) keeps running so the device stays
                                # functional in degraded mode.
                                log(
                                    f"[daemon-loop] worker {k}: crash loop "
                                    f"({len(state['crash_window'])} non-zero exits "
                                    f"in <{CRASH_WINDOW_SEC}s) — STOPPING respawn "
                                    f"for this worker. Check backend-{k}.err.log "
                                    f"and fix the underlying issue (port "
                                    f"conflict / profile dir missing / dep mismatch).",
                                    "ERROR",
                                )
                                workers[k] = {"_dead": True}
                                continue
                    state["restarts"] += 1
                    log(f"[daemon-loop] worker {k}: restarting (restart #{state['restarts']}) in 5s…")
                    _time.sleep(5)
                    new_state = _spawn_worker(k)
                    if new_state is not None:
                        # Carry over crash tracking across the respawn.
                        new_state["crash_window"] = state["crash_window"]
                        new_state["keystore_wiped"] = state["keystore_wiped"]
                        new_state["restarts"] = state["restarts"]
                        new_state["watchdog_window"] = state.get("watchdog_window", [])  # (#717)
                        workers[k] = new_state
                    else:
                        workers[k] = {"_dead": True}
        except KeyboardInterrupt:
            log("[daemon-loop] Interrupted — terminating all workers")
            for k, state in workers.items():
                if state and not state.get("_dead"):
                    try:
                        state["process"].terminate()
                    except Exception:
                        pass
            return
        except Exception as _mw_err:
            # Any other exception in the multi-worker loop (rare:
            # resource exhaustion in _time.sleep, corrupted Popen state,
            # etc.) MUST NOT fall through to the single-worker code
            # below — that path would spawn an additional --serve on
            # port 8000 racing the existing worker-1. Terminate all
            # known children, log loudly, and exit the wrapper so the
            # supervisor's scheduled-task respawn can give us a fresh
            # event loop. Without this `return`, the multi-worker loop's
            # spawned children remain alive AND the single-worker loop
            # spins up its own --serve, leaving 2× the worker count.
            log(f"[daemon-loop] Multi-worker loop crashed: {_mw_err} — terminating workers + exiting wrapper for clean respawn", "ERROR")
            for k, state in workers.items():
                if state and not state.get("_dead"):
                    try:
                        state["process"].terminate()
                    except Exception:
                        pass
            return

    # ──── Single-worker branch (legacy, workerCount==1) ────────────────
    # Crash-loop safety net. If --serve exits non-zero CRASH_THRESHOLD
    # times within CRASH_WINDOW_SEC, the daemon-loop wipes the OS
    # keystore so the recovery loop inside the next --serve can take
    # over from a clean slate. Without this, a stuck refresh token
    # (e.g. an edge-case Firebase error the parser at credentials.py
    # doesn't recognize as revoked) traps the BE in an infinite
    # respawn — the FE "Reset backend" button can't help because the
    # device-commands listener lives inside --serve, which never
    # finishes starting up. Auto-recovery: keystore goes empty -> next
    # --serve's init_firebase returns False -> _firebase_db = None ->
    # _revoked_recovery_loop polls the pending subdoc for a fresh
    # customToken from a Reset+Approve cycle. User-visible action: tap
    # Reset on the device tile in the FE Account page; the email's
    # Approve link deposits the customToken the recovery loop is
    # waiting for. `keystore_wiped_by_crashloop` gates against repeated
    # wipes if --serve keeps crashing for a different reason after the
    # wipe — wiping again would do nothing.
    crash_window: list[float] = []
    keystore_wiped_by_crashloop = False
    restarts = 0
    while True:
        try:
            log(f"[daemon-loop] Starting --serve (restart #{restarts})")
            with open(_serve_log, "ab") as _out, open(_serve_err, "ab") as _err:
                result = _subprocess.run(
                    [python_exe, script_path, "--serve", "--port", str(port)],
                    stdin=_subprocess.DEVNULL,
                    stdout=_out,
                    stderr=_err,
                    creationflags=_NO_WINDOW,
                )
            log(f"[daemon-loop] --serve exited with code {result.returncode}")
            # Track crash-loop pattern. Code 0 = clean exit (Ctrl+C from
            # outside, or `_revoked_recovery_loop` calling os._exit(0)
            # after picking up a fresh customToken). Clean exits reset
            # the window so a healthy restart doesn't get falsely
            # flagged later.
            if result.returncode == 0:
                crash_window = []
                keystore_wiped_by_crashloop = False
            else:
                _now = _time.time()
                crash_window.append(_now)
                crash_window = [t for t in crash_window if t > _now - CRASH_WINDOW_SEC]
                if (
                    len(crash_window) >= CRASH_THRESHOLD
                    and not keystore_wiped_by_crashloop
                ):
                    log(
                        f"[daemon-loop] Crash loop detected: {len(crash_window)} "
                        f"non-zero exits in <{CRASH_WINDOW_SEC}s. Wiping the OS "
                        f"keystore so the recovery loop in the next --serve can "
                        f"poll for a fresh customToken.",
                        "WARN",
                    )
                    try:
                        from auth import keystore as _ks_recovery
                        _ks_recovery.clear_all(_ks_recovery.install_uuid())
                        keystore_wiped_by_crashloop = True
                        crash_window = []
                        log(
                            "[daemon-loop] Keystore wiped. The next --serve will "
                            "boot into recovery mode and wait for a Reset+Approve "
                            "from the FE Account page (Settings → Manage devices "
                            "→ Reset, then click Approve in the email).",
                            "INFO",
                        )
                    except Exception as _ke:
                        log(
                            f"[daemon-loop] Keystore wipe failed: {_ke}. The user "
                            f"may need to run `python research.py --unpair && "
                            f"python research.py --pair` to recover manually.",
                            "ERROR",
                        )
        except KeyboardInterrupt:
            log("[daemon-loop] Interrupted — exiting wrapper")
            return
        except Exception as e:
            log(f"[daemon-loop] Subprocess launch failed: {e}", "WARN")
        restarts += 1
        log(f"[daemon-loop] Restarting in 5s…")
        try:
            _time.sleep(5)
        except KeyboardInterrupt:
            log("[daemon-loop] Interrupted during sleep — exiting wrapper")
            return

        # Per-iteration sweep + port-free probe. The wrapper-startup
        # sweep (above) only runs once; without this mid-cycle check
        # a serve that died mid-bind, or a hard-reset that didn't
        # quite release the socket, would leave port 8000 blocked
        # and the next subprocess.run would crash on EADDRINUSE in
        # uvicorn's startup — looping forever at 5s/cycle. Sweep
        # any orphan --serve PIDs first, then poll the port for up
        # to 10s. If still blocked, log and proceed anyway —
        # subprocess.run's failure logs will reveal the real cause.
        # Wrapped in the same KeyboardInterrupt handler shape as the
        # surrounding subprocess.run / sleep blocks so a Ctrl-C lands
        # in `_wait_for_port_free`'s inner sleep doesn't escape and
        # crash the wrapper.
        try:
            # 2026-05-11: also sweep peer daemon-loop wrappers. Pre-fix
            # this only killed stale --serve children but NOT peer
            # --daemon-loop supervisors — so if someone (or an external
            # tool) spawned a second wrapper, both wrappers' children
            # raced for port 8000 in a permanent crash loop (winner
            # served; loser kept exiting code 1 on EADDRINUSE and the
            # daemon-loop respawned it every 5s). The "self_pid !=" guard
            # is critical — we're a daemon-loop too; we'd otherwise kill
            # ourselves.
            stale_serve: list[int] = []
            stale_daemon: list[int] = []
            for pid, _cmd, role in _enumerate_research_py_procs():
                if pid == self_pid:
                    continue
                if role == "serve":
                    stale_serve.append(pid)
                elif role == "daemon-loop":
                    stale_daemon.append(pid)
            if stale_daemon:
                killed = _kill_pids(stale_daemon)
                log(f"[daemon-loop] Pre-restart sweep: killed {killed}/{len(stale_daemon)} peer daemon-loop wrappers ({stale_daemon})")
            if stale_serve:
                killed = _kill_pids(stale_serve)
                log(f"[daemon-loop] Pre-restart sweep: killed {killed}/{len(stale_serve)} stale --serve procs ({stale_serve})")
            if not _wait_for_port_free(port, max_wait_s=10.0):
                log(f"[daemon-loop] Port {port} still in use after 10s — spawning anyway; uvicorn will surface the cause", "WARN")
        except KeyboardInterrupt:
            log("[daemon-loop] Interrupted during pre-restart sweep — exiting wrapper")
            return
        except Exception as _se:
            log(f"[daemon-loop] Pre-restart sweep/probe failed: {_se}", "WARN")


def _write_supervised_flag(enabled: bool):
    """Push the Supervised flag to the top-level `devices/{deviceId}` doc
    so the FE Account-page On Startup toggle reflects the supervisor
    state. Uses Firestore REST PATCH via _pair_patch_device — no gRPC
    client init needed, so callers (--resurrect / --retire / --pair
    Stage 5) don't pay the ~10-30s init_firebase wall-clock on Windows.

    Best-effort: if no deviceId on disk or the PATCH fails, returns
    silently (the Scheduled Task / launchd / systemd unit is the actual
    source of truth for supervisor state, and the heartbeat will re-
    write supervised on next --serve boot)."""
    device_id = load_device_id()
    if not device_id:
        log("Device not paired — skipping Firestore flag update.", "WARN")
        return
    if _pair_patch_device(device_id, {"supervised": bool(enabled)}):
        log(f"Supervised flag = {enabled} written to device doc.")
    else:
        log(f"Could not update supervised flag (REST patch failed)", "WARN")


def _apply_supervisor_respawn_policy() -> "tuple[bool, str]":
    """Layer recurring trigger + restart-on-failure onto an existing
    SuperResearchBackend Scheduled Task. schtasks /SC ONLOGON does not
    expose Repetition or RestartCount via command-line, so we shell out
    to PowerShell once the task is created to set them.

    PT5M repetition + MultipleInstances=IgnoreNew → max ~5-min offline
    gap if daemon-loop dies for any reason (clean exit, Ctrl+C, crash).
    RestartCount=3 + RestartInterval=PT1M backstops non-zero failure
    exits with up to 3 retries spaced 1 minute apart.

    Returns (ok, msg). Best-effort: failure leaves the bare /SC ONLOGON
    behavior intact (one-shot at logon, no auto-respawn mid-session).
    """
    import subprocess as _subprocess
    ps = (
        "$ErrorActionPreference='Stop'; "
        f"$t = Get-ScheduledTask -TaskName '{_SUPERVISOR_TASK_NAME}'; "
        "$t.Triggers[0].Repetition.Interval = 'PT5M'; "
        "$t.Settings.RestartCount = 3; "
        "$t.Settings.RestartInterval = 'PT1M'; "
        "$t.Settings.StartWhenAvailable = $true; "
        # Vista compat-mode defaults gate task start/run on AC power. On a
        # laptop, this means the supervisor goes "Queued" forever the moment
        # the cable is unplugged. Disable both so the supervisor stays alive
        # whether the user is on battery or on AC.
        "$t.Settings.DisallowStartIfOnBatteries = $false; "
        "$t.Settings.StopIfGoingOnBatteries = $false; "
        f"Set-ScheduledTask -TaskName '{_SUPERVISOR_TASK_NAME}' "
        "-Trigger $t.Triggers[0] -Settings $t.Settings | Out-Null"
    )
    try:
        result = _subprocess.run(
            ["powershell", "-NoProfile", "-NonInteractive", "-Command", ps],
            capture_output=True, text=True, timeout=30,
            creationflags=_PS_NO_WINDOW,
        )
        if result.returncode != 0:
            return False, (result.stderr or result.stdout or "PS exit non-zero").strip()
        return True, "applied"
    except Exception as e:
        return False, f"PS error: {e}"


def _arm_supervisor_quiet() -> "tuple[bool, int | None, str, int]":
    """Dispatcher — routes to `_arm_supervisor_quiet_windows`,
    `_arm_supervisor_macos`, or `_arm_supervisor_linux`. Returns the same
    4-tuple shape regardless of platform: (installed_ok, daemon_pid_or_None,
    info, killed_serve_count)."""
    plat = _supervisor_platform()
    if plat == "Windows":
        return _arm_supervisor_quiet_windows()
    if plat == "Darwin":
        return _arm_supervisor_macos()
    if plat == "Linux":
        return _arm_supervisor_linux()
    # Unsupported returns a consistent "not supported" tuple so callers
    # don't need platform branches.
    return False, None, "unsupported", 0


def _arm_supervisor_quiet_windows() -> "tuple[bool, int | None, str, int]":
    """Install the SuperResearchBackend scheduled task AND spawn a detached
    daemon-loop. No terminal narration — callers do their own.

    Returns (installed_ok, pid_or_None, info, killed_serve_count):
      • installed_ok         — schtasks install succeeded
      • pid_or_None          — daemon-loop pid if live-detected within 5s
      • info:
          - "non-Windows"    — platform not supported
          - "already running" — daemon-loop was already live; pid reflects that
          - ""               — fresh spawn detected within 5s
          - "<error string>" — failure (schtasks error, Popen failed, spawn
                               took > 5s to appear, etc.)
      • killed_serve_count   — number of plain --serve processes we had to
                               stop to free port 8000 for the supervised
                               child. Callers warn the user since the other
                               terminal's --serve died silently.

    installed_ok=True + pid=None means the scheduled task is installed but
    the live spawn did not appear — the next login will still fire it, so
    On Startup mode is enabled for the future even if this turn didn't
    catch the process handoff."""
    import sys as _sys
    import subprocess as _subprocess
    import platform as _platform
    import time as _time

    if _platform.system() != "Windows":
        return False, None, "non-Windows", 0

    # Seed `.dg-supervisor.env` from scripts/dg-supervisor.env.example if
    # the user hasn't created one yet. Idempotent — no-op when target exists.
    _seed_env_file_if_missing()

    # pythonw.exe (no-console subsystem) keeps the supervisor invisible at
    # logon — under the `/IT` interactive token, console-mode python.exe
    # would otherwise pop a visible daemon-loop terminal. Scheduled Task
    # invokes pythonw DIRECTLY (NOT via a cmd.exe /c wrapper) — the cmd
    # intermediary would flash a console window on every PT5M trigger
    # fire. The same quoted-path pattern as before; --env-file is an extra
    # quoted arg that Python loads via _load_env_file() before subcommand
    # dispatch.
    python_exe = _supervisor_python_exe()
    script_path = str(Path(__file__).resolve())
    env_file = _SUPERVISOR_ENV_FILE_DEFAULT_PATH
    task_run = f'"{python_exe}" "{script_path}" --daemon-loop --env-file "{env_file}"'

    cmd = [
        "schtasks", "/Create",
        "/TN", _SUPERVISOR_TASK_NAME,
        "/TR", task_run,
        "/SC", "ONLOGON",
        "/RL", "LIMITED",
        "/IT",
        "/F",
    ]
    try:
        result = _subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                 creationflags=_PS_NO_WINDOW)
    except Exception as e:
        return False, None, f"schtasks error: {e}", 0
    if result.returncode != 0:
        return False, None, (result.stderr or result.stdout or "schtasks returned non-zero").strip(), 0

    # Layer respawn policy (PT5M repetition + restart-on-failure) onto the
    # freshly-created task — best-effort; failure leaves bare /SC ONLOGON.
    _apply_supervisor_respawn_policy()

    procs = _enumerate_research_py_procs()
    daemon_pid = next((pid for pid, _cmd, role in procs if role == "daemon-loop"), None)
    if daemon_pid is not None:
        return True, daemon_pid, "already running", 0

    plain_serve_pids = [pid for pid, _cmd, role in procs if role == "serve"]
    killed_serve_count = 0
    if plain_serve_pids:
        killed_serve_count = _kill_pids(plain_serve_pids)

    # Belt-and-suspenders: gate creationflags on win32 to mirror
    # `run_daemon_loop`'s pattern (research.py:27223-27240) — function is
    # already Windows-only by name + caller chain, but a future refactor
    # that bypasses the dispatcher could otherwise re-introduce the same
    # POSIX ValueError class. 2026-05-18: caught after Linux Track C smoke
    # hit the same anti-pattern in `run_daemon_loop`.
    _DETACHED = (
        getattr(_subprocess, "DETACHED_PROCESS", 0x00000008)
        if sys.platform == "win32" else 0
    )
    _NEWGROUP = (
        getattr(_subprocess, "CREATE_NEW_PROCESS_GROUP", 0x00000200)
        if sys.platform == "win32" else 0
    )
    try:
        _subprocess.Popen(
            [python_exe, script_path, "--daemon-loop"],
            creationflags=_DETACHED | _NEWGROUP,
            stdout=_subprocess.DEVNULL,
            stderr=_subprocess.DEVNULL,
            stdin=_subprocess.DEVNULL,
            close_fds=True,
        )
    except Exception as e:
        return True, None, f"spawn failed: {e}", killed_serve_count

    deadline = _time.time() + 5.0
    while _time.time() < deadline:
        _time.sleep(0.5)
        for pid, _cmd, role in _enumerate_research_py_procs():
            if role == "daemon-loop":
                return True, pid, "", killed_serve_count
    return True, None, "daemon-loop did not appear within 5s", killed_serve_count


def _disarm_supervisor_quiet() -> "tuple[str, int]":
    """Dispatcher — routes to `_disarm_supervisor_quiet_windows`,
    `_disarm_supervisor_macos`, or `_disarm_supervisor_linux`. Returns
    (status, killed_total) on all platforms."""
    plat = _supervisor_platform()
    if plat == "Windows":
        return _disarm_supervisor_quiet_windows()
    if plat == "Darwin":
        return _disarm_supervisor_macos()
    if plat == "Linux":
        return _disarm_supervisor_linux()
    return "unsupported", 0


def _disarm_supervisor_quiet_windows() -> "tuple[str, int]":
    """Inverse of _arm_supervisor_quiet_windows. Removes the Scheduled Task AND
    kills every daemon-loop + --serve process. No terminal narration —
    callers do their own.

    Shared by the --pair N-branch (enforce "user said unsupervised") and
    any future "reset supervisor" entry point. run_retire / run_unpair
    still inline their own narration-rich versions since their step
    reporting differs.

    Returns (task_info, killed_count):
      • task_info: "removed" | "missing" | "non-Windows" | error string
      • killed_count: number of daemon-loop + serve procs stopped
    """
    import subprocess as _subprocess
    import platform as _platform
    import time as _time

    task_info = "non-Windows"
    if _platform.system() == "Windows":
        cmd = ["schtasks", "/Delete", "/TN", _SUPERVISOR_TASK_NAME, "/F"]
        try:
            result = _subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                     creationflags=_PS_NO_WINDOW)
            if result.returncode == 0:
                task_info = "removed"
            elif "cannot find the file" in (result.stdout + result.stderr).lower():
                task_info = "missing"
            else:
                task_info = (result.stderr or result.stdout or "non-zero exit").strip()
        except Exception as e:
            task_info = f"schtasks error: {e}"

    self_pid = os.getpid()
    killed_total = 0
    deadline = _time.time() + 8.0
    while True:
        procs = [p for p in _enumerate_research_py_procs() if p[0] != self_pid]
        daemon_pids = [pid for pid, _cmd, role in procs if role == "daemon-loop"]
        serve_pids = [pid for pid, _cmd, role in procs if role == "serve"]
        if not daemon_pids and not serve_pids:
            break
        killed_total += _kill_pids(daemon_pids) + _kill_pids(serve_pids)
        if _time.time() >= deadline:
            break
        _time.sleep(0.5)
    return task_info, killed_total


def run_resurrect():
    """Install a Windows Scheduled Task that launches `python research.py
    --serve` at user logon. Idempotent — re-running overwrites the existing
    task. Prints actionable output on success/failure."""
    import sys as _sys
    import subprocess as _subprocess
    import platform as _platform

    _branded_header("resurgam", _BOLD + _BRIGHT, "the backend rises")

    plat = _supervisor_platform()
    if plat not in ("Windows", "Darwin", "Linux"):
        # Truly unsupported platform (FreeBSD, headless WSL without GUI, etc.).
        print()
        print(f"  {_c(_WARN, '⚠')} Only Windows / macOS / Linux desktop is supported.")
        return

    if plat in ("Darwin", "Linux"):
        # POSIX path — refactored 2026-05-20 from a bare-bones flow into the
        # same 4-step scaffolding as Windows. Removes the "parity-of-mechanism,
        # not parity-of-UX" gap the user flagged during Linux testing. Helpers
        # (`_render_context_strip`, `_setup_step`, `_print_with_flourish`,
        # `_render_next_actions`) were already platform-agnostic; we just call
        # them. Platform-specific install lives in `_arm_supervisor_<plat>`
        # which spawns the daemon-loop inline (vs Windows which spawns it in
        # Step 4 — that asymmetry is intentional, see Step 4 below).
        # NOTE: init_firebase() + _fetch_paired_email() deliberately skipped
        # — see the matching comment in the Windows path below. supervised
        # flag goes through _pair_patch_device (REST), no gRPC dep.
        paired_uid = load_paired_uid()
        device_id = load_device_id()
        # Pull friendly name + owner email from the device doc via REST so
        # the banner shows "VivobookPro" / "Rocky (alice@example.com)"
        # instead of the raw deviceId UUID / uid[:8] prefix. Best-effort —
        # drops back to the raw values on any failure.
        _meta_b = _fetch_device_meta_rest()
        device_name = (
            (_meta_b.get("name") if isinstance(_meta_b.get("name"), str) else "")
            or (_meta_b.get("hostname") if isinstance(_meta_b.get("hostname"), str) else "")
            or device_id
            or "(not paired)"
        )
        owner_display = _meta_b.get("ownerDisplayName") if isinstance(_meta_b.get("ownerDisplayName"), str) else ""
        owner_email = _meta_b.get("ownerEmail") if isinstance(_meta_b.get("ownerEmail"), str) else ""
        if owner_display and owner_email:
            paired_email = f"{owner_display}  ({owner_email})"
        elif owner_email:
            paired_email = owner_email
        elif paired_uid:
            paired_email = paired_uid[:8] + "…"
        else:
            paired_email = "(not paired)"
        currently_supervised = _detect_supervised()
        _ctx_rows = [
            ("Device",    _c(_BOLD, device_name)),
            ("Paired to", _c(_BOLD, paired_email)),
            ("On Startup", _aegis_rune(currently_supervised, transition_to="on")),
        ]
        _bat = _battery_state()
        if _bat:
            _ctx_rows.append(("Power", _c(_DIM, _bat)))
        _render_context_strip(_ctx_rows)

        # ── [1/4] Pre-flight ──
        _setup_step(1, 4, "Pre-flight")
        if not paired_uid:
            print(f"  {_c(_WARN, '⚠')} Device not paired yet.")
            print(f"  {_c(_DIM, '     Run')} {_c(_BOLD, 'python research.py --pair')} {_c(_DIM, 'first, then retry --resurrect.')}")
            return
        print(f"  {_c(_OK, '✓')}  Pairing complete on this machine")
        _seed_env_file_if_missing()

        # ── [2/4] Installing supervisor + auto-spawn ──
        _setup_step(2, 4, f"Installing {_supervisor_artifact_label()}")
        if plat == "Linux" and _is_wsl():
            # F15 of the CLI audit — WSL2's systemd-user requires
            # `systemd=true` in /etc/wsl.conf [boot] (not the default).
            # If that's missing, the unit installs but won't survive
            # `wsl --shutdown`. Warn but don't bail — users with systemd
            # already enabled get exactly what they want.
            print(f"  {_c(_WARN, '⚠')}  WSL detected — systemd-user units need `systemd=true` in /etc/wsl.conf [boot].")
            print(f"  {_c(_DIM, '     If unset: add it, run `wsl --shutdown` from PowerShell, then re-run --resurrect.')}")
        if plat == "Linux" and _check_linger_status() == "no":
            _linger_user = os.environ.get("USER") or os.environ.get("LOGNAME") or "$USER"
            print(f"  {_c(_WARN, '⚠')}  loginctl Linger=no — daemon-loop will die at logout.")
            print(f"  {_c(_DIM, '     Run:')} {_c(_BOLD, f'sudo loginctl enable-linger {_linger_user}')}")
            print(f"  {_c(_DIM, '     (continuing — supervisor still works while logged in)')}")
        if plat == "Darwin":
            ok, daemon_pid, info, killed_serve = _arm_supervisor_macos()
            if not ok:
                print(f"  {_c(_WARN, '⚠')}  launchd install failed: {info}")
                return
            print(f"  {_c(_OK, '✓')}  LaunchAgent installed ({_SUPERVISOR_PLIST_LABEL})")
        else:
            ok, daemon_pid, info, killed_serve = _arm_supervisor_linux()
            if not ok:
                print(f"  {_c(_WARN, '⚠')}  systemctl install failed: {info}")
                return
            print(f"  {_c(_OK, '✓')}  systemd user unit installed ({_SUPERVISOR_UNIT_NAME})")
        if killed_serve:
            _plural_s = "es" if killed_serve != 1 else ""
            print(f"  {_c(_DIM, f'     Stopped {killed_serve} stale --serve process{_plural_s}.')}")

        # ── [3/4] Firestore sync ──
        _setup_step(3, 4, "Firestore sync")
        _write_supervised_flag(True)
        print(f"  {_c(_OK, '✓')}  Synced to the Super Research app")

        # ── [4/4] Handoff — verify daemon-loop is live + API responds ──
        # Asymmetric with Windows: `_arm_supervisor_<plat>` already spawned
        # daemon-loop in Step 2 (launchd/systemd handle the spawn at install
        # time). Here we just confirm the spawn succeeded and that uvicorn
        # bound port 8000. Matches the Windows handoff's "did the daemon
        # actually come up?" verification.
        _setup_step(4, 4, "Handoff")
        _kind = "launchd" if plat == "Darwin" else "systemd"
        _retry_hint = "KeepAlive=true" if plat == "Darwin" else "Restart=always"
        if daemon_pid is not None:
            print(f"  {_c(_OK, '✓')}  Backend started (PID {daemon_pid}, supervised by {_kind})")
        else:
            print(f"  {_c(_WARN, '⚠')}  {info or 'daemon-loop did not appear within 5s'} — {_kind} will retry ({_retry_hint}).")
        # API health probe (matches Windows handoff's _local_api_health call).
        import time as _time_pos
        _time_pos.sleep(2)  # let uvicorn finish startup
        _api_ok, _api_detail = _local_api_health()
        if _api_ok:
            print(f"  {_c(_OK, '✓')}  API responding ({_api_detail})")
        else:
            print(f"  {_c(_WARN, '⚠')}  API not responding yet: {_api_detail}")
            print(f"  {_c(_DIM, '     daemon-loop may still be initializing — curl localhost:8000/api/health in ~30s.')}")

        # ── Final flourish + next actions (matches Windows path) ──
        print()
        _print_with_flourish(
            f"  {_c(_BOLD + _BRIGHT, '  The supervisor holds watch.')}  "
            f"{_c(_DIM, '--serve respawns on any exit.')}",
            fade_to_color=_BOLD + _ACCENT,
            hold_s=0.3,
        )
        _render_next_actions([
            ("python research.py --retire", "disable On Startup"),
        ])
        return

    # Seed `.dg-supervisor.env` from scripts/dg-supervisor.env.example so the
    # user-facing happy path lays down a documented config file at install
    # time. Idempotent — no-op when target exists.
    _seed_env_file_if_missing()

    # pythonw.exe (no-console subsystem) keeps the supervisor invisible at
    # logon — under the `/IT` interactive token, console-mode python.exe
    # would otherwise pop a visible daemon-loop terminal. Falls back to
    # sys.executable if pythonw.exe isn't installed alongside.
    python_exe = _supervisor_python_exe()
    script_path = str(Path(__file__).resolve())
    env_file = _SUPERVISOR_ENV_FILE_DEFAULT_PATH
    # Use the full path to python.exe so the task runs even if PATH isn't set
    # up for the scheduler's session. Quote both to tolerate spaces.
    # Launch the daemon-loop wrapper (not --serve directly) so the backend
    # auto-restarts on any exit — including the os._exit(0) that the Stop
    # button calls for Chromium cleanup. Without this, the scheduled task
    # only fires once per logon and the backend stays dead after Stop.
    # --env-file directs research.py to load .dg-supervisor.env via
    # _load_env_file() before subcommand dispatch (parity with the
    # _arm_supervisor_quiet install path).
    task_run = f'"{python_exe}" "{script_path}" --daemon-loop --env-file "{env_file}"'

    # NOTE: deliberately skip `init_firebase()` + `_fetch_paired_email()` here.
    # The only Firestore-side action --resurrect needs is the supervised:true
    # flag write in step 3, which goes through _pair_patch_device (Firestore
    # REST + bootstrapped idToken — no gRPC client init). Skipping the cold
    # gRPC channel construction shaves ~30-60s off resurrect on Windows.
    paired_uid = load_paired_uid()
    device_id = load_device_id()
    # Pull friendly name + owner email from the device doc via REST so the
    # banner shows "VivobookPro" / "Rocky (alice@example.com)" instead of
    # the raw deviceId UUID / uid[:8] prefix. Best-effort — drops back to
    # the raw values on any failure.
    _meta_b = _fetch_device_meta_rest()
    device_name = (
        (_meta_b.get("name") if isinstance(_meta_b.get("name"), str) else "")
        or (_meta_b.get("hostname") if isinstance(_meta_b.get("hostname"), str) else "")
        or device_id
        or "(not paired)"
    )
    owner_display = _meta_b.get("ownerDisplayName") if isinstance(_meta_b.get("ownerDisplayName"), str) else ""
    owner_email = _meta_b.get("ownerEmail") if isinstance(_meta_b.get("ownerEmail"), str) else ""
    if owner_display and owner_email:
        paired_email = f"{owner_display}  ({owner_email})"
    elif owner_email:
        paired_email = owner_email
    elif paired_uid:
        paired_email = paired_uid[:8] + "…"
    else:
        paired_email = "(not paired)"
    currently_supervised = _detect_supervised()
    _ctx_rows = [
        ("Device",    _c(_BOLD, device_name)),
        ("Paired to", _c(_BOLD, paired_email)),
        ("On Startup", _aegis_rune(currently_supervised, transition_to="on")),
    ]
    _bat = _battery_state()
    if _bat:
        _ctx_rows.append(("Power", _c(_DIM, _bat)))
    _render_context_strip(_ctx_rows)

    # ── [1/4] Pre-flight ──
    _setup_step(1, 4, "Pre-flight")
    if not paired_uid:
        print(f"  {_c(_WARN, '⚠')} Device not paired yet.")
        print(f"  {_c(_DIM, '     Run')} {_c(_BOLD, 'python research.py --pair')} {_c(_DIM, 'first, then retry --resurrect.')}")
        return
    print(f"  {_c(_OK, '✓')}  Pairing complete on this machine")

    # ── [2/4] Scheduling auto-start ──
    _setup_step(2, 4, "Scheduling auto-start")
    cmd = [
        "schtasks", "/Create",
        "/TN", _SUPERVISOR_TASK_NAME,
        "/TR", task_run,
        "/SC", "ONLOGON",
        "/RL", "LIMITED",       # keep user privileges (Chrome profile access)
        "/IT",                  # interactive — required for Playwright headed mode
        "/F",                   # overwrite existing
    ]
    try:
        result = _subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                 creationflags=_PS_NO_WINDOW)
    except Exception as e:
        print(f"  {_c(_WARN, '⚠')}  Failed to run schtasks: {e}")
        return

    if result.returncode != 0:
        print(f"  {_c(_WARN, '⚠')}  schtasks returned non-zero status.")
        if result.stderr.strip():
            print(f"  {_c(_DIM, '     stderr:')}")
            for line in result.stderr.strip().splitlines():
                print(f"       {line}")
        return

    print(f"  {_c(_OK, '✓')}  Scheduled Task pinned to login ({_SUPERVISOR_TASK_NAME})")
    print(f"  {_c(_DIM, '     Executes:')} {task_run}")

    # Layer respawn policy onto the task — PT5M repetition + restart-on-failure.
    _ok, _msg = _apply_supervisor_respawn_policy()
    if _ok:
        print(f"  {_c(_OK, '✓')}  Respawn policy applied (5-min repetition + restart-on-failure)")
    else:
        print(f"  {_c(_WARN, '⚠')}  Could not apply respawn policy: {_msg}")
        print(f"  {_c(_DIM, '     Backend still spawns at next login as a fallback.')}")

    # ── [3/4] Firestore sync ──
    _setup_step(3, 4, "Firestore sync")
    _write_supervised_flag(True)  # uses _pair_patch_device internally — fast
    print(f"  {_c(_OK, '✓')}  Synced to the Super Research app")

    # ── [4/4] Handoff — activate the supervisor NOW, not at next logon ──
    # Without this, --resurrect only schedules the task and leaves the
    # backend on whatever the user had before. Active supervised mode
    # needs --daemon-loop running so --serve is supervised. Steps:
    #   (a) detect an already-running daemon-loop (re-run = no-op),
    #   (b) taskkill any plain --serve so port 8000 is free for the
    #       supervised child,
    #   (c) spawn --daemon-loop DETACHED + CREATE_NEW_PROCESS_GROUP so
    #       it outlives this call and doesn't inherit our console,
    #   (d) verify the spawn actually worked by re-polling until the
    #       daemon-loop PID appears (so we don't print "started" for
    #       a child that crashed on import).
    _setup_step(4, 4, "Handoff")
    import time as _time
    procs = _enumerate_research_py_procs()
    daemon_pid = next((pid for pid, _cmd, role in procs if role == "daemon-loop"), None)
    plain_serve_pids = [pid for pid, _cmd, role in procs if role == "serve"]

    # Pre-flight orphan visibility: count what's about to be reaped before
    # the daemon-loop starts, so the user sees the sweep working rather
    # than just a silent kill. Same enumeration the daemon-loop wrapper
    # would do; we mirror it here so it's surfaced at install time too.
    _self_pid_r = os.getpid()
    _stale_daemons = [pid for pid, _c, role in procs
                      if role == "daemon-loop" and pid != _self_pid_r]
    _other_procs = [(pid, cmd) for pid, cmd, role in procs if role == "other"]
    if _stale_daemons or plain_serve_pids or _other_procs:
        bits = []
        if _stale_daemons:
            bits.append(f"{len(_stale_daemons)} stale daemon-loop")
        if plain_serve_pids:
            bits.append(f"{len(plain_serve_pids)} stale --serve")
        if _other_procs:
            bits.append(f"{len(_other_procs)} manual one-off run(s) preserved")
        print(f"  {_c(_DIM, '     Pre-flight: ' + ', '.join(bits))}")

    if daemon_pid is not None:
        print(f"  {_c(_OK, '✓')}  Backend already running (PID {daemon_pid}) — nothing to spawn")
    else:
        if plain_serve_pids:
            killed = _kill_pids(plain_serve_pids)
            plural = "es" if killed != 1 else ""
            print(f"  {_c(_DIM, f'     Stopped {killed} running --serve process{plural} to free port 8000.')}")
        # Belt-and-suspenders: even after killing known research.py --serve
        # processes, port 8000 can still be held by:
        #   - a stale --serve that crashed without releasing (rare)
        #   - a different app the user happened to bind there
        #   - a TIME_WAIT socket from a recent --serve exit
        # Without this, daemon-loop will spawn --serve which hits "address
        # already in use" on the first uvicorn bind and crash-loops every
        # 5s. _free_port_8000 catches it once at install time.
        port_squatters = _free_port_8000()
        if port_squatters:
            print(f"  {_c(_DIM, f'     Cleared port 8000 (killed PID(s): {port_squatters})')}")
        # Belt-and-suspenders: gate on win32 (mirrors `run_daemon_loop`'s
        # _NO_WINDOW pattern at research.py:27223-27240). This branch is
        # already only reachable on Windows after the Darwin/Linux early-
        # returns above, but the constants now self-defend against future
        # refactors that bypass the dispatcher. 2026-05-18.
        _DETACHED = (
            getattr(_subprocess, "DETACHED_PROCESS", 0x00000008)
            if sys.platform == "win32" else 0
        )
        _NEWGROUP = (
            getattr(_subprocess, "CREATE_NEW_PROCESS_GROUP", 0x00000200)
            if sys.platform == "win32" else 0
        )
        try:
            _subprocess.Popen(
                [python_exe, script_path, "--daemon-loop"],
                creationflags=_DETACHED | _NEWGROUP,
                stdout=_subprocess.DEVNULL,
                stderr=_subprocess.DEVNULL,
                stdin=_subprocess.DEVNULL,
                close_fds=True,
            )
        except Exception as e:
            print(f"  {_c(_WARN, '⚠')}  Could not start backend: {e}")
            print(f"  {_c(_DIM, '     The scheduled task still fires at next login.')}")
        else:
            spawned_pid = None
            with _sync_spinner_ctx("Starting backend"):
                deadline = _time.time() + 5.0
                while _time.time() < deadline:
                    _time.sleep(0.5)
                    for pid, _cmd, role in _enumerate_research_py_procs():
                        if role == "daemon-loop":
                            spawned_pid = pid
                            break
                    if spawned_pid is not None:
                        break
            if spawned_pid is not None:
                print(f"  {_c(_OK, '✓')}  Backend started (PID {spawned_pid}, running in background)")
                # Health probe — confirm the API is actually responding
                # before declaring success. Daemon-loop has to (1) start
                # --serve, (2) Firestore client init (~3-5s on Windows
                # cold), (3) uvicorn bind. Retry up to ~12s with a
                # spinner so the user doesn't see a false-alarm WARN
                # for the common "uvicorn just hasn't bound yet" case.
                _api_ok = False
                _api_detail = ""
                with _SyncSpinnerCtx("Waiting for API"):
                    for _hb_attempt in range(8):  # 8 × 1.5s = 12s
                        _time.sleep(1.5)
                        _api_ok, _api_detail = _local_api_health()
                        if _api_ok:
                            break
                if _api_ok:
                    print(f"  {_c(_OK, '✓')}  API responding ({_api_detail})")
                else:
                    print(f"  {_c(_WARN, '⚠')}  API not responding yet: {_api_detail}")
                    print(f"  {_c(_DIM, '     daemon-loop may still be initializing — give it ~30s, then curl /api/health.')}")
            else:
                print(f"  {_c(_WARN, '⚠')}  Backend did not appear within 5s — check backend.err.log.")
                print(f"  {_c(_DIM, '     The scheduled task still fires at next login as a fallback.')}")

    print()
    _print_with_flourish(
        f"  {_c(_BOLD + _BRIGHT, '  The supervisor holds watch.')}  "
        f"{_c(_DIM, '--serve respawns on any exit.')}",
        fade_to_color=_BOLD + _ACCENT,
        hold_s=0.3,
    )
    _render_next_actions([
        ("python research.py --retire", "disable On Startup"),
    ])


def run_retire():
    """Disable On Startup — completely. Idempotent: succeeds whether or not
    the scheduled task and backend are currently running.

    Full-reset semantics: after --retire the machine is back to "nothing
    related to research.py is running in the background". If a pipeline was
    in-flight under the supervised --serve, it aborts — that's the deliberate
    cost of a clean undo. Re-run --serve yourself to bring the backend back,
    or --resurrect to re-enable On Startup.

    Three-step reset:
      1. Delete the Windows Scheduled Task so daemon-loop won't auto-start
         at next login.
      2. Kill every running daemon-loop AND every --serve process, looping
         for up to 8s so a mid-enumeration respawn (daemon-loop spawns
         --serve every ~5s between deaths) still gets caught.
      3. Flip the Firestore On Startup flag to off + verify stragglers."""
    import subprocess as _subprocess
    import platform as _platform

    _branded_header("requiescat", _BOLD + _RED, "let the loop rest")

    plat = _supervisor_platform()
    if plat not in ("Windows", "Darwin", "Linux"):
        # Truly unsupported platform (FreeBSD, headless WSL without GUI, etc.).
        print()
        print(f"  {_c(_WARN, '⚠')} Only Windows / macOS / Linux desktop is supported.")
        return

    if plat in ("Darwin", "Linux"):
        # POSIX path — refactored 2026-05-20 to match the Windows 3-step
        # scaffolding (Context strip → [1/3] Unbinding → [2/3] Stopping →
        # [3/3] Firestore sync → flourish + next-actions). Closes the
        # "Polish deferred" gap so --retire reads the same on every OS.
        # NOTE: init_firebase + _fetch_paired_email skipped — supervised
        # flag goes via _write_supervised_flag → _pair_patch_device REST.
        paired_uid = load_paired_uid()
        device_id = load_device_id()
        # Pull friendly name + owner email from the device doc via REST so
        # the banner shows "VivobookPro" / "Rocky (alice@example.com)"
        # instead of the raw deviceId UUID / uid[:8] prefix. Best-effort —
        # drops back to the raw values on any failure.
        _meta_b = _fetch_device_meta_rest()
        device_name = (
            (_meta_b.get("name") if isinstance(_meta_b.get("name"), str) else "")
            or (_meta_b.get("hostname") if isinstance(_meta_b.get("hostname"), str) else "")
            or device_id
            or "(not paired)"
        )
        owner_display = _meta_b.get("ownerDisplayName") if isinstance(_meta_b.get("ownerDisplayName"), str) else ""
        owner_email = _meta_b.get("ownerEmail") if isinstance(_meta_b.get("ownerEmail"), str) else ""
        if owner_display and owner_email:
            paired_email = f"{owner_display}  ({owner_email})"
        elif owner_email:
            paired_email = owner_email
        elif paired_uid:
            paired_email = paired_uid[:8] + "…"
        else:
            paired_email = "(not paired)"
        currently_supervised = _detect_supervised()

        _ctx_rows = [
            ("Device",     _c(_BOLD, device_name)),
            ("Paired to",  _c(_BOLD, paired_email)),
            ("On Startup", _aegis_rune(currently_supervised, transition_to="nothing-to-undo")),
        ]
        _bat = _battery_state()
        if _bat:
            _ctx_rows.append(("Power", _c(_DIM, _bat)))
        _render_context_strip(_ctx_rows)

        # Short-circuit: nothing armed AND nothing running → no-op (mirrors
        # the Windows branch). Avoids three separate "nothing to do" lines.
        self_pid = os.getpid()
        running_now = any(
            role in ("daemon-loop", "serve")
            for pid, _cmd, role in _enumerate_research_py_procs()
            if pid != self_pid
        )
        if not currently_supervised and not running_now:
            print()
            print(f"  {_c(_DIM, 'Nothing to retire — On Startup is already off and no backend is running.')}")
            _render_next_actions([
                ("python research.py --resurrect", "enable On Startup"),
            ])
            return

        # ── [1/3] Unbinding schedule ──
        _setup_step(1, 3, "Unbinding schedule")
        if plat == "Darwin":
            status, killed_during_disarm = _disarm_supervisor_macos()
            if status == "removed":
                print(f"  {_c(_OK, '✓')}  LaunchAgent removed ({_SUPERVISOR_PLIST_LABEL})")
            elif status == "no-task":
                print(f"  {_c(_DIM, '     Nothing bound — LaunchAgent was not installed.')}")
            else:
                print(f"  {_c(_WARN, '⚠')}  bootout returned: {status}")
        else:
            status, killed_during_disarm = _disarm_supervisor_linux()
            if status == "removed":
                print(f"  {_c(_OK, '✓')}  systemd user unit removed ({_SUPERVISOR_UNIT_NAME})")
            elif status == "no-task":
                print(f"  {_c(_DIM, '     Nothing bound — systemd unit was not installed.')}")
            else:
                print(f"  {_c(_WARN, '⚠')}  systemctl disable returned: {status}")

        # ── [2/3] Stopping backend ──
        _setup_step(2, 3, "Stopping backend")
        if killed_during_disarm:
            _plural = "es" if killed_during_disarm != 1 else ""
            print(f"  {_c(_OK, '✓')}  Stopped {killed_during_disarm} process{_plural}")
        else:
            print(f"  {_c(_DIM, '     No daemon-loop / --serve processes were running.')}")

        # ── [3/3] Firestore sync ──
        _setup_step(3, 3, "Firestore sync")
        _write_supervised_flag(False)
        print(f"  {_c(_OK, '✓')}  Synced to the Super Research app")

        # ── Final flourish + next actions (matches Windows path) ──
        print()
        _print_with_flourish(
            f"  {_c(_BOLD + _RED, '  Silence.')}  "
            f"{_c(_DIM, 'No research.py process remains.')}",
            fade_to_color=_DIM + _RED,
            hold_s=0.5,
        )
        _render_next_actions([
            ("python research.py --resurrect", "re-enable On Startup"),
        ])
        return

    # Context strip — what's about to get torn down. Skip init_firebase
    # + email fetch; supervised flag goes via _write_supervised_flag →
    # _pair_patch_device REST.
    paired_uid = load_paired_uid()
    device_id = load_device_id()
    # Pull friendly name + owner email from the device doc via REST so the
    # banner shows "VivobookPro" / "Rocky (alice@example.com)" instead of
    # the raw deviceId UUID / uid[:8] prefix. Best-effort — drops back to
    # the raw values on any failure.
    _meta_b = _fetch_device_meta_rest()
    device_name = (
        (_meta_b.get("name") if isinstance(_meta_b.get("name"), str) else "")
        or (_meta_b.get("hostname") if isinstance(_meta_b.get("hostname"), str) else "")
        or device_id
        or "(not paired)"
    )
    owner_display = _meta_b.get("ownerDisplayName") if isinstance(_meta_b.get("ownerDisplayName"), str) else ""
    owner_email = _meta_b.get("ownerEmail") if isinstance(_meta_b.get("ownerEmail"), str) else ""
    if owner_display and owner_email:
        paired_email = f"{owner_display}  ({owner_email})"
    elif owner_email:
        paired_email = owner_email
    elif paired_uid:
        paired_email = paired_uid[:8] + "…"
    else:
        paired_email = "(not paired)"
    currently_supervised = _detect_supervised()
    _ctx_rows_r = [
        ("Device",     _c(_BOLD, device_name)),
        ("Paired to",  _c(_BOLD, paired_email)),
        ("On Startup", _aegis_rune(currently_supervised, transition_to="nothing-to-undo")),
    ]
    _bat_r = _battery_state()
    if _bat_r:
        _ctx_rows_r.append(("Power", _c(_DIM, _bat_r)))
    _render_context_strip(_ctx_rows_r)

    # Short-circuit: if nothing is armed and nothing is running, there's
    # nothing to retire. Walking through all 3 steps just to print "Nothing
    # bound / No processes running" 3 times is noise — tell the user directly.
    import time as _time
    self_pid = os.getpid()
    running_now = any(role in ("daemon-loop", "serve")
                      for pid, _cmd, role in _enumerate_research_py_procs()
                      if pid != self_pid)
    if not currently_supervised and not running_now:
        print()
        print(f"  {_c(_DIM, 'Nothing to retire — On Startup is already off and no backend is running.')}")
        _render_next_actions([
            ("python research.py --resurrect", "enable On Startup"),
        ])
        return

    # ── [1/3] Unbinding schedule ──
    _setup_step(1, 3, "Unbinding schedule")
    cmd = [
        "schtasks", "/Delete",
        "/TN", _SUPERVISOR_TASK_NAME,
        "/F",
    ]
    try:
        result = _subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                 creationflags=_PS_NO_WINDOW)
    except Exception as e:
        print(f"  {_c(_WARN, '⚠')}  Failed to run schtasks: {e}")
        return

    # Exit code 1 with a "does not exist" message means the task wasn't
    # installed to begin with — that's fine, we still clear the flag.
    not_installed = (
        result.returncode != 0
        and "ERROR: The system cannot find the file specified." in (result.stdout + result.stderr)
    )
    if result.returncode == 0:
        print(f"  {_c(_OK, '✓')}  Scheduled Task removed ({_SUPERVISOR_TASK_NAME})")
    elif not_installed:
        print(f"  {_c(_DIM, '     Nothing bound — task was not installed.')}")
    else:
        print(f"  {_c(_WARN, '⚠')}  schtasks returned non-zero status.")
        if result.stderr.strip():
            print(f"  {_c(_DIM, '     stderr:')}")
            for line in result.stderr.strip().splitlines():
                print(f"       {line}")

    # ── [2/3] Stopping backend ──
    # The daemon-loop respawns --serve every ~5s between deaths, so a
    # single-shot enumerate+kill misses any --serve that happened to be
    # respawning at the wrong moment. Loop for up to 8s, re-enumerating
    # each tick. Always kill daemon-loop first so it can't respawn a
    # freshly-killed --serve. `self_pid` is excluded in case --retire
    # was itself launched through the supervisor.
    _setup_step(2, 3, "Stopping backend")
    killed_daemon_total = 0
    killed_serve_total = 0
    deadline = _time.time() + 8.0
    last_survivors: list[tuple[int, str, str]] = []
    with _sync_spinner_ctx("Stopping backend — waiting for processes to exit"):
        while True:
            procs = [p for p in _enumerate_research_py_procs() if p[0] != self_pid]
            daemon_pids = [pid for pid, _cmd, role in procs if role == "daemon-loop"]
            serve_pids = [pid for pid, _cmd, role in procs if role == "serve"]
            if not daemon_pids and not serve_pids:
                last_survivors = procs  # only 'other' left, which we don't touch
                break
            killed_daemon_total += _kill_pids(daemon_pids)
            killed_serve_total += _kill_pids(serve_pids)
            if _time.time() >= deadline:
                last_survivors = [p for p in _enumerate_research_py_procs() if p[0] != self_pid]
                break
            _time.sleep(0.5)

    if killed_daemon_total:
        plural = "es" if killed_daemon_total != 1 else ""
        print(f"  {_c(_OK, '✓')}  Stopped {killed_daemon_total} daemon-loop process{plural}")
    else:
        print(f"  {_c(_DIM, '     No daemon-loop processes were running.')}")
    if killed_serve_total:
        plural = "s" if killed_serve_total != 1 else ""
        print(f"  {_c(_OK, '✓')}  Stopped {killed_serve_total} --serve process{plural}")
    else:
        print(f"  {_c(_DIM, '     No --serve processes were running.')}")

    # Manual one-off runs (role="other") are NOT killed by --retire — those
    # are user-launched `python research.py "<topic>"` invocations. Surface
    # them so the user knows what's still alive on their box.
    other_procs = [(pid, cmd) for pid, cmd, role in last_survivors if role == "other"]
    if other_procs:
        plural = "s" if len(other_procs) != 1 else ""
        print(f"  {_c(_DIM, f'     Preserved {len(other_procs)} manual run{plural} (not touched by --retire):')}")
        for pid, cmd in other_procs[:3]:
            age = _proc_age_seconds(pid)
            age_s = f"{int(age/3600)}h" if (age and age >= 3600) else (f"{int(age/60)}m" if age else "?")
            cmd_short = cmd.split('research.py', 1)[-1][:60] if 'research.py' in cmd else cmd[:60]
            print(f"       {_c(_DIM, f'PID {pid}  age {age_s}  research.py{cmd_short}')}")
        if len(other_procs) > 3:
            print(f"       {_c(_DIM, f'... and {len(other_procs) - 3} more')}")
        print(f"       {_c(_DIM, f'Stop manually with: {_kill_pid_hint()}')}")

    # ── [3/3] Firestore sync + verification ──
    _setup_step(3, 3, "Firestore sync")
    _write_supervised_flag(False)
    print(f"  {_c(_OK, '✓')}  Synced to the Super Research app")

    stragglers = [(pid, role) for pid, _cmd, role in last_survivors if role in ("daemon-loop", "serve")]
    print()
    if stragglers:
        print(f"  {_c(_WARN, '⚠')}  {len(stragglers)} related process(es) would not terminate:")
        for pid, role in stragglers:
            print(f"       {_c(_BOLD, f'PID {pid}')}  ({role})")
        print(f"  {_c(_DIM, f'       Kill them from {_process_manager_label()} or re-run --retire.')}")
    else:
        _print_with_flourish(
            f"  {_c(_BOLD + _RED, '  Silence.')}  "
            f"{_c(_DIM, 'No research.py process remains.')}",
            fade_to_color=_DIM + _RED,
            hold_s=0.5,
        )
    _render_next_actions([
        ("python research.py --resurrect", "re-enable On Startup"),
    ])


def run_unpair(deep: bool = False):
    """Fully disconnect this machine from Super Research — opposite of --pair.

    Semantics: after --unpair, this PC appears nowhere in the Super
    Research app. The device doc is deleted via the unpair-self Cloud
    Function call, local pairing config + OS-keystore refresh token
    are wiped, the scheduled-task supervisor (if any) is removed, and
    every daemon-loop / --serve process owned by this user is killed.
    A subsequent --pair starts fresh — there's no quiet "rejoin" path
    that resurrects the old identity.

    Preserved by default (delete manually for a truly clean machine):
      • Chrome profile(s) at ~/.super-research/browser-profile*/ (your logins)
      • Pipeline history in queues/

    With `deep=True` (CLI: `--unpair --deep`), ALSO wipes:
      • All ~/.super-research/browser-profile*/ dirs (fresh browsers
        on next --pair) + workerCount reset to 1.
      • Pair-time API keys (ANTHROPIC_API_KEY and GEMINI_API_KEY,
        plus the retired legacy aliases CUA_API_KEY and GOOGLE_API_KEY
        in case any survived the startup migration) from Windows
        User-scope env (HKCU) or `.dg-supervisor.env` on POSIX, plus the current
        process's os.environ + _RESOLVED_KEY_CACHE — so the next
        --pair Stage 3 actually re-prompts and re-verifies instead
        of short-circuiting on a leftover key.
      • Transient multi-worker state files at queues/ root
        (`.worker.*.lock` and `_pending_queue*.json`, including
        their `.tmp` siblings). Per-run history dirs (research
        outputs) under queues/ are still preserved. The wiped
        files are auto-recreated by the next worker's first job
        pickup, so a same-account re-pair sees a clean slate
        without losing research history.
    Use this when re-pairing to a different account or when the
    multi-account safety check refuses pair due to stale Google auth.

    Five-step reset (order matters):
      0. Pre-step: while keystore is still alive, mint an ID token and
         POST /api/devices/unpair-self so the FE drops the device tile
         instantly across every browser.
      1. Wipe local research_config.json + OS-keystore refresh token
         + zero in-memory caches. A respawned --serve now reads empty
         state and the heartbeat loop bails on its missing-deviceId
         guard.
      2. Remove the supervisor artifact; kill every daemon-loop +
         --serve process.
      3. Confirm the server-side retire (or fall back to FE Unlink for
         pre-cutover devices the BE can't reach).
      4. Local artifacts summary.
      5. Verify no related process survived."""
    import subprocess as _subprocess
    import platform as _platform
    import time as _time

    _branded_header("absolvo", _BOLD + _ACCENT, "the bond dissolves")

    # Load context BEFORE we nuke local state — the load_* helpers read
    # research_config.json, which step 4 deletes. NOTE: we deliberately
    # skip `init_firebase()` here — the only Firestore operation unpair
    # needs is the retire POST below, which authenticates with an
    # idToken minted via `_fresh_user_mode_id_token()` (its own
    # creds.refresh, no Firestore client init required). Skipping the
    # cold gRPC channel construction shaves ~10-15s off the user-facing
    # unpair wall-clock on Windows.
    paired_uid = load_paired_uid()
    device_id = load_device_id()
    paired_email = ""  # cosmetic only — banner falls back to uid[:8]

    # Bug C extension (2026-05-22): sweep stale research docs before
    # the device doc gets deleted. Without this, runs that were
    # ongoing/queued/paused_backend_restart on this device persist
    # under the owner's tree with no device link (cloud function
    # deletes the device doc but doesn't cascade-update research
    # docs), leaving zombie chat tiles the owner can't Resume.
    # Mirror of the HARD_RESET sweep — same helper, different
    # stopped_by/summary labels for audit-trail differentiation.
    #
    # Cost: ~10-15s wall-clock for init_firebase() on Windows (the
    # bypass-init optimization is intentionally reverted here for
    # correctness — a clean-state guarantee outweighs the wall-clock
    # for a once-per-device-lifetime operation).
    if paired_uid and device_id:
        try:
            init_firebase()
            global _firebase_db
            if _firebase_db:
                _swp_n, _swp_f = _sweep_stuck_research_docs_for_device(
                    _firebase_db, paired_uid, device_id,
                    stopped_by="unpair_sweep",
                    summary="Cancelled by Unpair",
                )
                if _swp_n or _swp_f:
                    log(f"[unpair] Firestore sweep marked {_swp_n} stale run(s) as stopped ({_swp_f} failed) — owner + sharer trees", "INFO")
                else:
                    log("[unpair] Firestore sweep — no stale runs found (owner + sharers)", "DEBUG")
            else:
                log("[unpair] skipping Firestore sweep — init_firebase did not produce a client", "WARN")
        except Exception as _sw_err:
            log(f"[unpair] Firestore sweep failed (continuing): {_sw_err}", "WARN")

    # Best-effort server-side retire BEFORE we wipe the keystore. The
    # endpoint deletes the top-level devices/{deviceId} doc + revokes
    # the synth-device-user's refresh tokens, so the FE listenToDevices
    # subscription drops the tile across every browser instantly. Once
    # we wipe the keystore in step 1 we lose the ability to mint an ID
    # token, so this MUST run first. Non-fatal if it fails — the local
    # wipe still happens and the FE Unlink button is the fallback.
    _retire_action = None
    if device_id:
        try:
            import requests as _requests
            from auth.v2_flow import FE_BASE_URL as _FE_BASE_URL
            _id_token = _fresh_user_mode_id_token()
            if _id_token:
                _resp = _requests.post(
                    f"{_FE_BASE_URL}/api/devices/unpair-self",
                    headers={"Authorization": f"Bearer {_id_token}"},
                    json={"deviceId": device_id},
                    timeout=15,
                )
                if _resp.status_code == 200:
                    try:
                        _retire_action = (_resp.json() or {}).get("action")
                    except Exception:
                        _retire_action = "retired"
                else:
                    log(
                        f"[unpair] retire endpoint HTTP {_resp.status_code}: {_resp.text[:200]}",
                        "WARN",
                    )
        except Exception as _re:
            log(f"[unpair] retire endpoint failed (continuing): {_re}", "WARN")

    # NOTE: no "nothing to do" short-circuit here even when local config is
    # missing. A prior --unpair (or manual config wipe) can leave orphan
    # daemon-loop + serve processes and a scheduled task behind — those are
    # the root cause of the "paired-but-serve-crash-looping" state. We want
    # --unpair to ALWAYS run step 1 (process kill + schtasks removal) so
    # re-running it is a guaranteed-clean cleanup. Steps 2-4 already no-op
    # gracefully when the relevant state is missing.

    # Context strip — what's about to vanish.
    _render_context_strip([
        ("Device",    _c(_BOLD, device_id or "(unknown)")),
        ("Paired to", _c(_BOLD, paired_email)),
    ])

    total = 5

    # ── [1/5] Wipe local config FIRST ──
    # Ordering: research_config.json + keystore disappear BEFORE we
    # kill processes. A daemon-loop respawns --serve on a 5s loop; if
    # processes were killed first, a freshly-spawned --serve could
    # read still-valid config and re-attach to Firestore. Wiping config
    # first means any respawned --serve reads empty state and the
    # heartbeat loop bails on its missing-deviceId guard before any
    # external writes happen.
    _setup_step(1, total, "Wiping local pairing config")
    wiped = []
    try:
        if RESEARCH_CONFIG_PATH.exists():
            RESEARCH_CONFIG_PATH.unlink()
            wiped.append(RESEARCH_CONFIG_PATH.name)
    except Exception as e:
        print(f"  {_c(_WARN, '⚠')}  Could not delete {RESEARCH_CONFIG_PATH.name}: {e}")
    try:
        if _LEGACY_PIPE_CONFIG_PATH.exists():
            _LEGACY_PIPE_CONFIG_PATH.unlink()
            wiped.append(_LEGACY_PIPE_CONFIG_PATH.name)
    except Exception:
        pass
    # Clear the OS keystore so the refresh token can't re-auth this BE.
    try:
        from auth import keystore as _ks
        _ks.clear_all(_ks.install_uuid())
        wiped.append("OS keystore")
    except Exception as _ke:
        print(f"  {_c(_WARN, '⚠')}  Keystore clear failed: {_ke}")
    # Zero in-memory state too, so anything still running in this process
    # can't re-read pre-wipe values from the global caches.
    global _device_id, _device_paired_uid
    _device_id = None
    _device_paired_uid = None
    if wiped:
        print(f"  {_c(_OK, '✓')}  Deleted: {', '.join(wiped)}")
    else:
        print(f"  {_c(_DIM, '     No local config files to wipe.')}")

    # ── [2/5] Stop supervisor + serve ──
    _setup_step(2, total, "Stopping running processes")
    plat = _supervisor_platform()
    if plat == "Windows":
        cmd = ["schtasks", "/Delete", "/TN", _SUPERVISOR_TASK_NAME, "/F"]
        try:
            result = _subprocess.run(cmd, capture_output=True, text=True, timeout=30,
                                     creationflags=_PS_NO_WINDOW)
            if result.returncode == 0:
                print(f"  {_c(_OK, '✓')}  Scheduled Task removed ({_SUPERVISOR_TASK_NAME})")
            elif "cannot find the file" in (result.stdout + result.stderr):
                print(f"  {_c(_DIM, '     No scheduled task was installed.')}")
            else:
                print(f"  {_c(_WARN, '⚠')}  schtasks returned non-zero — continuing.")
        except Exception as e:
            print(f"  {_c(_WARN, '⚠')}  schtasks error (continuing): {e}")
    elif plat == "Darwin":
        # launchctl bootout + plist removal. The subsequent kill loop
        # below handles process termination cross-platform via dispatchers.
        if os.geteuid() == 0:
            print(f"  {_c(_WARN, '⚠')}  Refusing under sudo — user agent must be in your own home.")
        else:
            uid = os.getuid()
            label = f"gui/{uid}/{_SUPERVISOR_PLIST_LABEL}"
            try:
                r = _subprocess.run(["launchctl", "bootout", label],
                                    capture_output=True, text=True, timeout=10)
                if r.returncode == 0:
                    print(f"  {_c(_OK, '✓')}  LaunchAgent removed ({_SUPERVISOR_PLIST_LABEL})")
                elif "could not find" in (r.stderr or "").lower() or "no such" in (r.stderr or "").lower():
                    print(f"  {_c(_DIM, '     No LaunchAgent was installed.')}")
                else:
                    print(f"  {_c(_WARN, '⚠')}  bootout: {(r.stderr or r.stdout).strip()[:80]}")
            except Exception as e:
                print(f"  {_c(_WARN, '⚠')}  bootout exception: {e}")
            try:
                if _SUPERVISOR_PLIST_PATH.exists():
                    _SUPERVISOR_PLIST_PATH.unlink()
            except Exception:
                pass
    elif plat == "Linux":
        # systemctl --user disable --now + unit unlink. Kill loop below
        # handles process termination cross-platform via dispatchers.
        if os.geteuid() == 0:
            print(f"  {_c(_WARN, '⚠')}  Refusing under sudo — user unit must be in your own home.")
        else:
            try:
                r = _subprocess.run(["systemctl", "--user", "disable", "--now", _SUPERVISOR_UNIT_NAME],
                                    capture_output=True, text=True, timeout=15)
                if r.returncode == 0:
                    print(f"  {_c(_OK, '✓')}  systemd unit removed ({_SUPERVISOR_UNIT_NAME})")
                else:
                    combined = ((r.stderr or "") + (r.stdout or "")).lower()
                    if "does not exist" in combined or "no such" in combined or "not loaded" in combined:
                        print(f"  {_c(_DIM, '     No systemd unit was installed.')}")
                    else:
                        print(f"  {_c(_WARN, '⚠')}  systemctl disable: {(r.stderr or r.stdout).strip()[:80]}")
            except Exception as e:
                print(f"  {_c(_WARN, '⚠')}  systemctl exception: {e}")
            try:
                if _SUPERVISOR_UNIT_PATH.exists():
                    _SUPERVISOR_UNIT_PATH.unlink()
            except Exception:
                pass
            try:
                _subprocess.run(["systemctl", "--user", "daemon-reload"],
                                capture_output=True, text=True, timeout=10)
            except Exception:
                pass

    # Loop-until-clean pattern so a daemon-loop mid-respawn of --serve
    # still gets fully caught.
    self_pid = os.getpid()
    killed_total = 0
    deadline = _time.time() + 8.0
    with _sync_spinner_ctx("Stopping backend — waiting for processes to exit"):
        while True:
            procs = [p for p in _enumerate_research_py_procs() if p[0] != self_pid]
            daemon_pids = [pid for pid, _cmd, role in procs if role == "daemon-loop"]
            serve_pids = [pid for pid, _cmd, role in procs if role == "serve"]
            if not daemon_pids and not serve_pids:
                break
            killed_total += _kill_pids(daemon_pids) + _kill_pids(serve_pids)
            if _time.time() >= deadline:
                break
            _time.sleep(0.5)
    if killed_total:
        plural = "es" if killed_total != 1 else ""
        print(f"  {_c(_OK, '✓')}  Stopped {killed_total} backend process{plural}")
    else:
        print(f"  {_c(_DIM, '     No backend processes were running.')}")

    # ── [3/5] Confirm the server-side retire that ran before step 1 ──
    _setup_step(3, total, "Removing device from your account")
    if _retire_action == "retired":
        print(f"  {_c(_OK, '✓')}  Deleted devices/{device_id} on the server.")
        print(f"  {_c(_DIM, '     The device tile will disappear from all browsers immediately.')}")
    elif _retire_action == "left-shared":
        print(f"  {_c(_OK, '✓')}  Removed your account from the device's shared list.")
    elif device_id:
        print(f"  {_c(_WARN, '⚠')}  Server-side retire didn't complete — the device tile may stick around.")
        print(f"  {_c(_DIM, '     If it does, tap Unlink on the tile in your Account page.')}")
    else:
        print(f"  {_c(_DIM, '     No paired modern device on this machine — nothing to remove server-side.')}")
    # Pre-cutover devices live at users/{uid}/devices/{deviceId} — the
    # synth-device-user BE can't delete them, and the unpair-self
    # endpoint only handles top-level devices. The FE Account page
    # surfaces an Unlink button on those legacy tiles for owner-side
    # cleanup; mention it so the user knows.
    print(f"  {_c(_DIM, '     Pre-cutover devices: tap Unlink on the tile in your Account page.')}")

    # ── [4/5] Local pairing artifacts ──
    _setup_step(4, total, "Local pairing artifacts")
    print(f"  {_c(_OK, '✓')}  Local config wiped (step 1) + keystore cleared.")

    # Deep cleanup: also wipe pair-time API keys. Lives in Step 4 because
    # API keys are conceptually "local pairing artifacts" — they're
    # persisted by --pair Stage 3 and live in the same axis as the
    # config + keystore. _save_api_key_local writes to Windows User-
    # scope env (HKCU) on Windows and to .dg-supervisor.env on POSIX.
    # Default --unpair leaves these in place so a re-pair on the same
    # machine skips re-pasting (Stage 3 short-circuits via
    # resolve_api_key/resolve_gemini_api_key "already configured").
    # --deep is the "I want a truly fresh slate" path — wipe the
    # persisted keys too so the next --pair Stage 3 fires the paste-
    # and-verify loop end-to-end.
    #
    # We also pop from os.environ in this process so an immediate
    # --pair launched in the SAME shell session (rare but happens
    # during development / E2E testing) doesn't inherit the stale keys
    # via the shell env fallback (resolver rank 5/6).
    api_keys_cleared = 0
    if deep:
        api_key_names = (
            "ANTHROPIC_API_KEY",
            "CUA_API_KEY",
            "GEMINI_API_KEY",
            "GOOGLE_API_KEY",
        )
        for _name in api_key_names:
            try:
                if _clear_api_key_local(_name):
                    api_keys_cleared += 1
            except Exception as _ke:
                log(f"API key clear failed for {_name}: {_ke}", "WARN")
            # Strip from current process too. shell-inherited env on
            # POSIX or pythonw inheritance on Windows can both stash a
            # stale value that would re-resolve in a same-shell --pair.
            os.environ.pop(_name, None)
        # Bust the hot-path key cache so any in-process resolver
        # (shouldn't be any, but defense in depth) sees the cleared
        # state immediately on next call.
        try:
            _RESOLVED_KEY_CACHE.update(key=None, ts=0.0)
        except Exception:
            pass
    api_keys_wiped = api_keys_cleared > 0
    if api_keys_wiped:
        print(f"  {_c(_OK, '✓')}  Pair-time API keys cleared (`--deep`) — Stage 3 will re-prompt and re-verify on next --pair.")

    # 2026-05-26: also wipe queues/ runtime-state files under --deep.
    # Per-run history dirs are intentionally preserved (the rest of
    # queues/ is "research history" per the docstring); only the
    # transient multi-worker state files at the root get cleaned —
    # they're rehydrated lazily on the next worker's first job
    # pickup (_write_worker_lock auto-creates the dir + lock,
    # _persist_pending_queue tmp+replaces the snapshot). Stale ones
    # surviving a cross-account re-pair cause the new BE to try
    # reprocessing the prior pair's jobs under a uid that doesn't
    # own them (Firestore 403 noise) and the worker-lock sibling-
    # claim scanner to see dead-PID locks (handled by the PID-
    # liveness guard but still ugly). Globs at queues/ root only
    # — never per-run subdirs, never README.md.
    queue_state_wiped = 0
    if deep:
        try:
            queues_root = Path(__file__).parent / "queues"
            if queues_root.exists():
                _patterns = (
                    ".worker.*.lock",
                    ".worker.*.lock.tmp",
                    "_pending_queue.json",
                    "_pending_queue_worker_*.json",
                    "_pending_queue.json.tmp",
                    "_pending_queue_worker_*.json.tmp",
                )
                for _pat in _patterns:
                    for _stale in queues_root.glob(_pat):
                        try:
                            _stale.unlink()
                            queue_state_wiped += 1
                        except Exception as _qse:
                            log(
                                f"[unpair] queue-state wipe failed for {_stale.name}: {_qse}",
                                "DEBUG",
                            )
        except Exception as _qe:
            log(f"[unpair] queue-state wipe pass failed (continuing): {_qe}", "WARN")
    if queue_state_wiped:
        _plural = "s" if queue_state_wiped != 1 else ""
        print(f"  {_c(_OK, '✓')}  Cleared {queue_state_wiped} stale worker-state file{_plural} from queues/ (`--deep`).")

    # ── [5/5] Verify ──
    _setup_step(5, total, "Confirming silence")
    stragglers = [p for p in _enumerate_research_py_procs()
                  if p[0] != self_pid and p[2] in ("daemon-loop", "serve")]
    if stragglers:
        print(f"  {_c(_WARN, '⚠')}  {len(stragglers)} related process(es) would not terminate:")
        for pid, _cmd, role in stragglers:
            print(f"       {_c(_BOLD, f'PID {pid}')}  ({role})")
        print(f"  {_c(_DIM, f'       Kill them from {_process_manager_label()} or re-run --unpair.')}")
    else:
        print(f"  {_c(_OK, '✓')}  No research.py process remains")

    # Deep cleanup: also wipe ALL Playwright browser profiles if --unpair
    # --deep was passed. Default --unpair preserves the profiles so a
    # re-pair on the same account doesn't force the user back through
    # ChatGPT/Gemini/Claude/NotebookLM logins. --deep is for the explicit
    # "I want a fresh browser, e.g. switching accounts" case + the F4
    # cookie-refusal recovery path.
    #
    # 2026-05-21: multi-profile aware. Globs ~/.super-research/browser-profile*
    # so profile-1 (legacy `browser-profile/`) AND any profile-N dirs
    # (`browser-profile-2/`, `browser-profile-3/`, …) all get wiped in one
    # pass. Without this, a re-pair after --unpair --deep would see stale
    # cookies in profile-2+ and the new pair's Stage 4 multi-profile loop
    # would inherit them. workerCount is also reset to 1 so the post-deep
    # state matches a fresh-install baseline.
    browser_wiped_count = 0
    if deep:
        try:
            import shutil as _shutil
            profile_root = PROFILE_DIR.parent  # ~/.super-research
            wiped_names: list[str] = []
            survived_names: list[str] = []
            if profile_root.exists():
                for sub in profile_root.iterdir():
                    # Match exactly `browser-profile` and `browser-profile-{N}`,
                    # not arbitrary `browser-profile_backup` or similar.
                    if not sub.is_dir():
                        continue
                    name = sub.name
                    if name != "browser-profile" and not (
                        name.startswith("browser-profile-")
                        and name[len("browser-profile-"):].isdigit()
                    ):
                        continue
                    try:
                        _shutil.rmtree(str(sub), ignore_errors=True)
                    except Exception as _sub_err:
                        log(f"Browser profile wipe failed for {name}: {_sub_err}", "WARN")
                        survived_names.append(name)
                        continue
                    if sub.exists():
                        survived_names.append(name)
                        log(f"Browser profile wipe partial — some files survived at {sub}", "WARN")
                    else:
                        wiped_names.append(name)
                        log(f"Browser profile wiped: {sub}", "INFO")
            browser_wiped_count = len(wiped_names)
            if browser_wiped_count:
                # Reset worker capacity to fresh-install baseline. Next pair's
                # Stage 4 multi-profile loop will re-establish whatever count
                # the user wants.
                try:
                    save_worker_count(1)
                    log("workerCount reset to 1 after --unpair --deep", "INFO")
                except Exception as _wc_err:
                    log(f"workerCount reset failed (non-fatal): {_wc_err}", "WARN")
        except Exception as _de:
            log(f"Browser profile wipe failed: {_de}", "WARN")
    browser_wiped = browser_wiped_count > 0

    print()
    print(f"  {_c(_BOLD + _ACCENT, '  The bond dissolves.')}  {_c(_DIM, 'This machine is no longer paired.')}")
    print()
    if browser_wiped:
        if browser_wiped_count == 1:
            print(f"  {_c(_OK, '✓')}  Chrome profile wiped (`--deep`) — fresh browser on next --pair.")
        else:
            print(f"  {_c(_OK, '✓')}  {browser_wiped_count} Chrome profiles wiped (`--deep`) — fresh browsers on next --pair.")
    if browser_wiped or api_keys_wiped:
        print(f"  {_c(_DIM, 'Preserved on disk (remove manually for a fully clean slate):')}")
        print(f"       {_c(_DIM, '• Research history in queues/')}")
        print(f"       {_c(_DIM, '• firebase-service-account.json  (needed to re-pair)')}")
    else:
        print(f"  {_c(_DIM, 'Preserved on disk (remove manually for a fully clean slate):')}")
        print(f"       {_c(_DIM, '• Chrome profile(s) at ~/.super-research/browser-profile*/  (your logins)')}")
        print(f"       {_c(_DIM, '• Research history in queues/')}")
        print(f"       {_c(_DIM, '• firebase-service-account.json  (needed to re-pair)')}")
        print(f"       {_c(_DIM, '  Add --deep to also wipe the Chrome profile(s) + pair-time API keys next time.')}")
    _render_next_actions([
        ("python research.py --pair", "reconnect this machine (mints a fresh token)"),
    ])


def run_commands_help():
    """Branded CLI command reference. Listed by use-case (daily / lifecycle /
    advanced / debugging) rather than alphabetically, since users learn the
    workflow not the argparse layout. Use --help for the full argparse dump."""
    _branded_header("manuale", _BOLD + _ACCENT, "command reference")
    print()

    def _section(title, rows):
        print(f"  {_c(_BOLD, title)}")
        print(f"  {_rule(max_width=64)}")
        # Align command column; longest command wins the padding budget.
        pad = max(len(cmd) for cmd, _desc in rows)
        for cmd, desc in rows:
            print(f"  {_c(_BOLD, cmd.ljust(pad))}   {_c(_DIM, desc)}")
        print()

    _section("Daily", [
        ("python research.py --pair",
         "Pair this PC to your Super Research account (5-stage guided setup)"),
        ("python research.py --serve",
         "Run the backend in the foreground (Ctrl+C to stop)"),
        ("python research.py \"<topic>\"",
         "One-shot CLI research run (no web app)"),
    ])

    _section("Lifecycle (supervised auto-restart)", [
        ("python research.py --resurrect",
         "Install OS-native supervisor — auto-start at login + restart on crash"),
        ("python research.py --retire",
         "Disable On Startup — removes the supervisor; foreground --serve unchanged"),
        ("python research.py --unpair",
         "Fully disconnect this PC (deletes token + device doc + local config)"),
        ("python research.py --unpair --deep",
         "Same as --unpair, but ALSO wipes browser-profile*/ dirs + pair-time API keys + stale worker-state files + resets workerCount"),
    ])

    _section("Advanced", [
        ("python research.py --brief-file <path>",
         "Skip Phase 1 — start from an existing brief.md"),
        ("python research.py --pdf <file> [--pdf <file>...]",
         "Attach PDF(s) to Phase 1 (repeatable)"),
        ("python research.py --resume <queue-name|path>",
         "Resume a previous run from its queue/ directory"),
        ("python research.py --port <N>",
         "Override the default port 8000 for --serve"),
        ("python research.py --env-file <path>",
         "Load env vars from a custom file (default: .dg-supervisor.env)"),
        ("python research.py --api-key <key>",
         "One-shot Anthropic key override (bypasses Firestore / env resolve)"),
    ])

    _section("Diagnostics", [
        ("python research.py --doctor",
         "Diagnose + auto-repair common issues (pair state / Chromium / supervisor / DISPLAY / port 8000)"),
    ])

    _section("Internal / Debug", [
        ("python research.py --daemon-loop",
         "Wrapper that keeps --serve alive; spawned by the supervisor"),
        ("python research.py --verbose",
         "Tee extra logs to stdout (combine with any other command)"),
        ("python research.py --help",
         "Full argparse dump — all flags + types"),
        ("python research.py --commands",
         "This screen"),
    ])

    # Platform-specific hint surfaced at the bottom so users don't miss it.
    _plat = _supervisor_platform()
    if _plat == "Darwin":
        print(f"  {_c(_DIM, '• macOS supervisor: ~/Library/LaunchAgents/com.dgresearch.supervisor.plist')}")
    elif _plat == "Linux":
        print(f"  {_c(_DIM, '• Linux supervisor: ~/.config/systemd/user/dgresearch-supervisor.service')}")
    else:
        print(f"  {_c(_DIM, '• Windows supervisor: Scheduled Task `SuperResearchBackend`')}")
    # Cross-platform descriptor — F13 of the CLI audit. Pre-fix it only printed
    # under the Linux branch; Windows + macOS users never saw the full set.
    print(f"  {_c(_DIM, '  (Cross-platform: Windows Scheduled Task / macOS LaunchAgent / Linux systemd-user)')}")
    print(f"  {_c(_DIM, '• Config file: .dg-supervisor.env  (template at scripts/dg-supervisor.env.example)')}")
    print(f"  {_c(_DIM, '• Pipeline broken? Run')}  {_c(_BOLD, 'python research.py --doctor')}  {_c(_DIM, 'to diagnose + auto-fix.')}")
    print(f"  {_c(_DIM, '• Full docs: README.md   ·   ARCHITECTURE.md')}")
    print()


def run_doctor():
    """Diagnostic + auto-repair for common Super Research issues.

    Runs platform-aware checks and applies safe auto-fixes where possible.
    Designed to be the first thing a user runs when something feels wrong —
    surfaces the actual root cause (DISPLAY not propagated through systemd,
    stale supervisor unit, port-bound by another process, missing Chromium
    binary, etc.) instead of leaving them to grep logs.

    No destructive operations — never deletes user data, never unpairs,
    never modifies firebase-service-account.json. Worst case: restarts the
    supervisor + imports the calling shell's graphical-session env into
    the user-systemd manager (Linux only)."""
    import subprocess as _sp

    _branded_header("medicus", _BOLD + _ACCENT, "diagnose + heal")
    print()

    plat = _supervisor_platform()
    issues_found = 0
    fixes_applied = 0
    manual_actions: list[str] = []

    def _ok(label: str, detail: str = ""):
        suffix = f"  {_c(_DIM, '· ' + detail)}" if detail else ""
        print(f"  {_c(_OK, '✓')}  {label}{suffix}")

    def _warn(label: str, detail: str = ""):
        nonlocal issues_found
        issues_found += 1
        suffix = f"  {_c(_DIM, '· ' + detail)}" if detail else ""
        print(f"  {_c(_WARN, '⚠')}  {label}{suffix}")

    def _fail(label: str, detail: str = ""):
        nonlocal issues_found
        issues_found += 1
        suffix = f"  {_c(_DIM, '· ' + detail)}" if detail else ""
        print(f"  {_c(_ERR, '✗')}  {label}{suffix}")

    def _fix(label: str):
        nonlocal fixes_applied
        fixes_applied += 1
        print(f"     {_c(_ACCENT, '→')} {label}")

    # ── [1] Platform + pair state ──
    print(f"  {_c(_BOLD, 'Platform + pair state')}")
    print(f"  {_rule(max_width=58)}")
    if plat == "Unsupported":
        _fail(f"Platform unsupported ({sys.platform})", "Only Windows / macOS / Linux desktop.")
        print()
        print(f"  {_c(_DIM, 'Cannot continue diagnostics on this platform.')}")
        return
    _ok(f"Platform: {plat}")

    paired_uid = load_paired_uid()
    device_id = load_device_id()
    if paired_uid and device_id:
        _ok("Pair state", f"deviceId={device_id}")
    else:
        _fail("Not paired", "research_config.json missing or incomplete — run --pair")
        manual_actions.append("Run `python research.py --pair`")

    if init_firebase():
        _ok("Firestore client", "user-mode (refresh-token credentials)")
    else:
        _fail("Firestore init failed", "OS keystore empty or refresh token revoked")
        manual_actions.append("Run `python research.py --pair`")
    print()

    # ── [2] Browser dependencies (Playwright + Chromium) ──
    print(f"  {_c(_BOLD, 'Browser dependencies')}")
    print(f"  {_rule(max_width=58)}")
    try:
        import patchright  # noqa: F401
        _ok("patchright package", "installed in active venv")
    except ImportError:
        _fail("patchright not importable", "pip install -r requirements.txt")
        manual_actions.append("pip install -r requirements.txt")
    try:
        # All-semicolons probe so `python -c` parses on every platform
        # (compound try/except blocks with embedded \n break -c). If
        # chromium can't launch, the launch() raises and the subprocess
        # exits non-zero — we read that return code + stderr instead of
        # relying on a try/except inside -c. 60s timeout because cold
        # Chromium boot on slow hardware (Crostini, low-power) can take
        # a while; this probe runs once per `--doctor`, not per request.
        _probe = (
            "from patchright.sync_api import sync_playwright; "
            "pp=sync_playwright().start(); "
            "b=pp.chromium.launch(headless=True); "
            "b.close(); pp.stop(); "
            "print('OK')"
        )
        _chromium_check = _sp.run(
            [sys.executable, "-c", _probe],
            capture_output=True, text=True, timeout=60,
        )
        _stdout = (_chromium_check.stdout or "").strip()
        _stderr = (_chromium_check.stderr or "").strip()
        _combined = (_stdout + " " + _stderr).lower()
        if _chromium_check.returncode == 0 and "OK" in _stdout:
            _ok("Chromium binary", "patchright launches headless cleanly")
        elif "executable doesn't exist" in _combined or "browsertype.launch" in _combined or "playwright install" in _combined:
            _fail("Chromium binary missing", "run patchright install chromium")
            manual_actions.append("patchright install chromium")
        elif "modulenotfounderror" in _combined or "no module named" in _combined:
            _fail("patchright module not importable in subprocess", "venv mismatch?")
            manual_actions.append("source .venv/bin/activate && pip install -r requirements.txt")
        else:
            _warn("Chromium launch test inconclusive",
                  (_stderr[:80] or _stdout[:80] or f"exit={_chromium_check.returncode}"))
    except _sp.TimeoutExpired:
        _warn("Chromium launch probe timed out (>60s)", "machine under heavy load?")
    except Exception as e:
        _warn("Chromium launch probe errored", str(e)[:80])
    print()

    # ── [3] Supervisor unit / task ──
    print(f"  {_c(_BOLD, 'Supervisor')}")
    print(f"  {_rule(max_width=58)}")
    if plat == "Linux":
        if _SUPERVISOR_UNIT_PATH.exists():
            _ok("Unit file present", str(_SUPERVISOR_UNIT_PATH))
            _unit_content = _SUPERVISOR_UNIT_PATH.read_text(encoding="utf-8", errors="replace")
            if "Environment=" in _unit_content and "DISPLAY=" in _unit_content:
                _ok("Unit has DISPLAY embedded", "reboot-safe")
            else:
                _warn("Unit missing Environment=DISPLAY=...",
                      "browser may fail post-reboot — re-run --resurrect")
                manual_actions.append("python research.py --resurrect  (from a graphical-session terminal)")
        else:
            _warn("Unit file not installed", "supervisor disabled")
            manual_actions.append("python research.py --resurrect")
        try:
            r = _sp.run(["systemctl", "--user", "is-active", _SUPERVISOR_UNIT_NAME],
                        capture_output=True, text=True, timeout=5)
            state = (r.stdout or "").strip()
            if state == "active":
                _ok(f"systemctl is-active", state)
            else:
                _warn(f"systemctl is-active", state or "unknown")
                try:
                    _sp.run(["systemctl", "--user", "restart", _SUPERVISOR_UNIT_NAME],
                            capture_output=True, text=True, timeout=15)
                    _fix("Restarted dgresearch-supervisor")
                except Exception as _re:
                    manual_actions.append(f"systemctl --user restart dgresearch-supervisor  (was: {_re})")
        except Exception as e:
            _warn("systemctl probe failed", str(e)[:80])
        linger = _check_linger_status()
        if linger == "yes":
            _ok("loginctl Linger", "yes — survives logout")
        elif linger == "no":
            _warn("loginctl Linger=no", "daemon-loop dies at logout")
            manual_actions.append("sudo loginctl enable-linger $USER")
        else:
            _warn("loginctl Linger unknown")
    elif plat == "Darwin":
        if _SUPERVISOR_PLIST_PATH.exists():
            _ok("LaunchAgent plist present", str(_SUPERVISOR_PLIST_PATH))
            if _detect_supervised_macos():
                _ok("launchctl bootstrapped", _SUPERVISOR_PLIST_LABEL)
            else:
                _warn("launchctl not bootstrapped", "plist exists but agent not loaded")
                # Auto-fix attempt: re-bootstrap into the gui session.
                try:
                    uid = os.getuid()
                    _sp.run(["launchctl", "bootstrap", f"gui/{uid}", str(_SUPERVISOR_PLIST_PATH)],
                            capture_output=True, text=True, timeout=10)
                    _fix("Re-bootstrapped LaunchAgent into gui session")
                except Exception as _le:
                    manual_actions.append(f"launchctl bootstrap gui/$(id -u) {_SUPERVISOR_PLIST_PATH}  (was: {_le})")
        else:
            _warn("LaunchAgent plist not installed")
            manual_actions.append("python research.py --resurrect")
    else:  # Windows
        if _detect_supervised_windows():
            _ok("Scheduled Task installed", _SUPERVISOR_TASK_NAME)
            # Confirm the task is currently scheduled to run (not just registered).
            try:
                r = _sp.run(["schtasks", "/Query", "/TN", _SUPERVISOR_TASK_NAME, "/FO", "LIST"],
                            capture_output=True, text=True, timeout=5,
                            creationflags=_PS_NO_WINDOW)
                _qout = (r.stdout or "").lower()
                if "ready" in _qout or "running" in _qout:
                    _ok("Scheduled Task state", "ready/running")
                elif "disabled" in _qout:
                    _warn("Scheduled Task state", "disabled")
                    try:
                        _sp.run(["schtasks", "/Change", "/TN", _SUPERVISOR_TASK_NAME, "/ENABLE"],
                                capture_output=True, text=True, timeout=5,
                                creationflags=_PS_NO_WINDOW)
                        _fix("Re-enabled SuperResearchBackend Scheduled Task")
                    except Exception as _se:
                        manual_actions.append(f"schtasks /Change /TN {_SUPERVISOR_TASK_NAME} /ENABLE  (was: {_se})")
            except Exception:
                pass
        else:
            _warn("Scheduled Task not installed")
            manual_actions.append("python research.py --resurrect")
    print()

    # ── [4] Process tree + port ──
    print(f"  {_c(_BOLD, 'Process tree')}")
    print(f"  {_rule(max_width=58)}")
    procs = _enumerate_research_py_procs()
    daemon_pids = [pid for pid, _c2, role in procs if role == "daemon-loop"]
    serve_pids  = [pid for pid, _c2, role in procs if role == "serve"]
    if daemon_pids:
        _ok(f"daemon-loop running", f"PID {daemon_pids[0]}")
    else:
        _warn("daemon-loop not running",
              "supervisor inactive — see Supervisor section above")
    if serve_pids:
        _ok(f"--serve running", f"PID {serve_pids[0]}")
    else:
        _fail("--serve not running", "no API server → FE will show offline")
    # Port 8000 ownership
    if plat in ("Linux", "Darwin"):
        try:
            r = _sp.run(["ss", "-ltnp"], capture_output=True, text=True, timeout=5)
            if ":8000" in (r.stdout or ""):
                if serve_pids and f"pid={serve_pids[0]}" in r.stdout:
                    _ok("Port 8000", f"bound by our --serve (PID {serve_pids[0]})")
                else:
                    _warn("Port 8000", "bound by a non-Super-Research process")
                    manual_actions.append("Identify with `ss -ltnp | grep :8000` and kill the stale binding")
            else:
                _warn("Port 8000 not bound", "API unreachable")
        except Exception:
            pass
    print()

    # ── [5] Linux-specific: DISPLAY propagation ──
    if plat == "Linux":
        print(f"  {_c(_BOLD, 'Graphical-session env (Linux)')}")
        print(f"  {_rule(max_width=58)}")
        shell_disp = os.environ.get("DISPLAY", "")
        if shell_disp:
            _ok("Shell DISPLAY", shell_disp)
        else:
            _warn("Shell DISPLAY empty", "you're in a non-graphical session (SSH? cron?)")
        # Manager env
        try:
            r = _sp.run(["systemctl", "--user", "show-environment"],
                        capture_output=True, text=True, timeout=5)
            mgr_env = r.stdout or ""
            if "DISPLAY=" in mgr_env:
                _ok("user-systemd manager DISPLAY", "present")
            else:
                _warn("user-systemd manager DISPLAY missing",
                      "supervisor children won't see it")
                if shell_disp:
                    try:
                        _sp.run(["systemctl", "--user", "import-environment",
                                 "DISPLAY", "WAYLAND_DISPLAY", "XAUTHORITY", "XDG_RUNTIME_DIR"],
                                capture_output=True, text=True, timeout=10)
                        _fix("Imported DISPLAY/WAYLAND_DISPLAY/XAUTHORITY into user-systemd manager")
                        # Restart so children pick it up
                        try:
                            _sp.run(["systemctl", "--user", "restart", _SUPERVISOR_UNIT_NAME],
                                    capture_output=True, text=True, timeout=15)
                            _fix("Restarted dgresearch-supervisor to inherit new env")
                        except Exception:
                            pass
                    except Exception as e:
                        manual_actions.append(f"systemctl --user import-environment DISPLAY WAYLAND_DISPLAY XAUTHORITY  (was: {e})")
        except Exception as e:
            _warn("systemctl show-environment failed", str(e)[:80])
        # --serve actual env
        if serve_pids:
            try:
                env_blob = Path(f"/proc/{serve_pids[0]}/environ").read_bytes().decode("utf-8", errors="replace")
                if "DISPLAY=" in env_blob:
                    _ok("--serve DISPLAY env", "present")
                else:
                    _warn("--serve DISPLAY missing",
                          "running browser will fail — restart supervisor after the import-environment above")
            except Exception:
                pass
        print()

    # ── Summary ──
    print(f"  {_rule(max_width=58)}")
    if issues_found == 0:
        print(f"  {_c(_OK + _BOLD, '✓  Healthy.')}  {_c(_DIM, 'All checks passed.')}")
    else:
        print(f"  {_c(_BOLD, f'Found {issues_found} issue(s); applied {fixes_applied} auto-fix(es).')}")
        if manual_actions:
            print()
            print(f"  {_c(_BOLD, 'Manual steps still required:')}")
            for i, a in enumerate(manual_actions, 1):
                print(f"    {_c(_ACCENT, f'{i}.')} {a}")
    print()


# ── CLI ──────────────────────────────────────────────────────────────────────

def main():
    parser = argparse.ArgumentParser(description="Multi-Agent Deep Research Pipeline")
    parser.add_argument("topic", nargs="?", help="Research topic")
    parser.add_argument("--pdf", action="append", default=[], help="PDF to attach (Phase 1)")
    parser.add_argument("--brief-file", "-b", help="Existing brief file (skip Phase 1)")
    parser.add_argument("--email", "-e", help="Email for Phase 6 delivery")
    parser.add_argument("--api-key", "-k", help="CUA API key")
    parser.add_argument("--verbose", "-v", action="store_true")
    parser.add_argument("--pair", action="store_true", help="First-time login setup")
    parser.add_argument("--resume", "-r", help="Resume from a previous queue directory (name or full path)")
    parser.add_argument("--serve", action="store_true", help="Start web app API server")
    parser.add_argument("--port", type=int, default=None,
        help="Server port. Default: 8000 for worker 1, 8000+(worker_id-1) for worker N. "
             "Pass explicitly only for non-default port mappings (testing / port collision recovery).")
    parser.add_argument("--worker-id", type=int, default=1, dest="worker_id",
        help="Worker slot index (1-based). Worker N uses _profile_dir(N) for its browser "
             "and binds port 8000+N-1 (unless --port overrides). Workers ≥2 are spawned by "
             "daemon-loop when research_config.json's workerCount > 1; set up via pair Stage 4's "
             "multi-profile loop. Default: 1 (single-worker, backward compat).")
    parser.add_argument("--resurrect", action="store_true",
        help="Enable On Startup: auto-start the backend at login and keep it running in the background")
    parser.add_argument("--retire", action="store_true",
        help="Disable On Startup: remove the auto-start scheduled task and stop the background backend")
    parser.add_argument("--unpair", action="store_true",
        help="Fully disconnect this machine from Super Research (inverse of --pair): deletes token + device doc + local config")
    parser.add_argument("--deep", action="store_true",
        help="With --unpair: also wipe ALL Playwright browser profiles under ~/.super-research/browser-profile*/ "
             "(clears ChatGPT/Gemini/Claude/NotebookLM logins across profile-1 and any profile-N set up via pair "
             "Stage 4 multi-profile loop). Also resets workerCount to 1 and wipes pair-time API keys "
             "(ANTHROPIC_API_KEY/GEMINI_API_KEY, plus retired legacy aliases CUA_API_KEY/GOOGLE_API_KEY) from Windows User-scope env or "
             ".dg-supervisor.env so the next --pair Stage 3 re-prompts and re-verifies. Useful when re-pairing "
             "to a different account or when the F4 cookie check refuses pair due to stale Google auth. "
             "Default: preserve profiles + keys.")
    parser.add_argument("--daemon-loop", action="store_true",
        help="Internal: wrapper that keeps --serve alive by relaunching it on any exit. Used by the On Startup scheduled task.")
    parser.add_argument("--env-file", default=None,
        help=f"Path to KEY=value env file. Default: <script_dir>/.dg-supervisor.env (silently skipped if missing).")
    parser.add_argument("--commands", action="store_true",
        help="Print a branded reference card of every Super Research CLI command, grouped by use-case. "
             "Lighter-weight than --help; designed for at-a-glance recall.")
    parser.add_argument("--doctor", action="store_true",
        help="Diagnose + auto-repair common Super Research issues (pair state / Firebase / "
             "Chromium binary / supervisor unit / port 8000 / Linux DISPLAY propagation). "
             "First thing to run when something feels wrong. Non-destructive — never unpairs or deletes user data.")
    args = parser.parse_args()

    # Load .dg-supervisor.env BEFORE subcommand dispatch so every subcommand
    # (--serve, --daemon-loop, --resurrect, etc.) inherits the same values.
    # `os.environ.setdefault` semantics — existing process env wins, which
    # preserves Windows user-scope env priority for `resolve_api_key` callers.
    if args.env_file:
        _load_env_file(args.env_file)
    elif _SUPERVISOR_ENV_FILE_DEFAULT_PATH.exists():
        # Silently auto-load if default file exists. No WARN on first-run
        # where the user hasn't created it yet (the path-exists check here
        # sidesteps `_load_env_file`'s missing-file WARN).
        _load_env_file(_SUPERVISOR_ENV_FILE_DEFAULT_PATH)

    # One-shot upgrade for pre-2026-05-23 machines that paired before the
    # CUA_API_KEY → ANTHROPIC_API_KEY + GOOGLE_API_KEY → GEMINI_API_KEY
    # rename. Runs after env-file load (so POSIX picks up env-file legacy
    # values) and before subcommand dispatch (so resolvers see canonical
    # names everywhere). Cached via `~/.super-research/env-migrated-v1`
    # sentinel — subsequent process starts skip the work.
    _migrate_legacy_api_keys()

    if args.commands:
        run_commands_help()
        return

    if args.doctor:
        run_doctor()
        return

    if args.resurrect:
        run_resurrect()
        return

    if args.retire:
        run_retire()
        return

    if args.unpair:
        run_unpair(deep=bool(args.deep))
        return

    # Resolve worker_id + port. Port defaults to 8000+(worker_id-1) so the
    # daemon-loop's N children each bind a distinct port without each spawn
    # needing to know the global mapping. Stamp WORKER_ID module-global so
    # downstream code (pipeline launcher, pending-queue path, listener
    # claim, w1-only gates) can read it without plumbing.
    global WORKER_ID
    WORKER_ID = max(1, int(args.worker_id or 1))
    _resolved_port = args.port if args.port is not None else (8000 + WORKER_ID - 1)

    if args.daemon_loop:
        run_daemon_loop(_resolved_port)
        return

    if args.pair:
        asyncio.run(cmd_pair_v2(str(PROFILE_DIR)))
        return

    if args.serve:
        asyncio.run(run_server(_resolved_port))
        return

    if args.resume:
        resume_path = Path(args.resume)
        if not resume_path.is_absolute():
            resume_path = Path(__file__).parent / "queues" / args.resume
        log(f"Resuming from: {resume_path}")
        global _cli_mode
        _cli_mode = True
        asyncio.run(run_pipeline(
            topic=args.topic or "", resume_dir=str(resume_path),
            verbose=args.verbose, api_key=args.api_key, email=args.email,
        ))
        return

    if not args.topic:
        parser.error('Provide topic: python research.py "Your topic"')

    log(f"Topic: {args.topic}")
    if args.brief_file:
        log(f"Brief: {args.brief_file} (skipping Phase 1)")
    if args.pdf:
        log(f"PDFs: {[Path(p).name for p in args.pdf]}")

    _cli_mode = True
    asyncio.run(run_pipeline(
        topic=args.topic, pdf_paths=args.pdf,
        brief_file=args.brief_file, verbose=args.verbose,
        api_key=args.api_key, email=args.email,
    ))


if __name__ == "__main__":
    # F11 of the CLI audit — wrap the dispatcher in a single clean
    # KeyboardInterrupt catch so Ctrl+C anywhere in any subcommand
    # (--pair, --unpair, --retire, --resurrect, --doctor, --serve) exits
    # with a calm message + Unix convention exit code 130 instead of a
    # noisy traceback. Subcommands that need to do their own cleanup
    # before bailing can still catch KeyboardInterrupt locally; if they
    # re-raise it lands here.
    try:
        main()
    except KeyboardInterrupt:
        print()
        print(f"  {_c(_DIM, 'Cancelled.')}  {_c(_DIM, 'Re-run when ready.')}")
        sys.exit(130)
